//! Type checker и effect inference.
//!
//! Минимальная реализация: проверяем имена типов, выводим типы локальных
//! переменных, выводим эффекты для private функций (D28). Generic-параметры
//! проверяются как abstract names — мономорфизация делается при
//! интерпретации (treewalk не требует всего).

use crate::ast::*;
use crate::diag::{Diagnostic, FileId, MAIN_FILE_ID, Span};
use crate::parser::{impl_spec_base_name, impl_spec_args_text};
use std::collections::{HashMap, HashSet};

// Plan 172.1 U.5.4: the lossy bootstrap `Ty` enum (+ `ty_of_ref`) was DELETED — its int
// collapse + single `Ptr`/`TypedPtr` modelling is fully subsumed by the lossless
// `ResolvedType` (defined below), the single type representation the checker uses.

/// Plan 172.1 U.5.1 ([M-172.1-U5-structured-type]): single LOSSLESS structured
/// type carrier — replaces the lossy `Ty`/`TyCat` int-collapse (both map every int
/// width to ONE `Int` variant). Int-family carries EXACT `(width, signed)`; the L3
/// pointee modifier is carried via `TypedPtr` (mirrors `Ty::TypedPtr`). L2 view
/// (`ro`/`mut`) is transparent here — matching the `is_int_narrowing`/`int_width_rank`
/// unwrap (D227/D54); full L2 carriage is deferred to U.5.2 if the `assignable`
/// rewire needs it (`[M-172.1-U5-l2-view-deferred]`).
///
/// §2 exception: the primitive width/sign table (`int`≡`i64`=(64,signed),
/// `uint`≡`u64`=(64,unsigned), …) is the sanctioned hardcode (also pinned by the
/// `int`≡`i64` D-block).
///
/// U.5.2 amend: `Scalar` also carries `wide_default` — `true` ONLY for `int`/`uint`,
/// `false` for the explicit sized names (`i8`..`i64` / `u8`..`u64`). `int`≡`i64` and
/// `uint`≡`u64` stay equal on `(width, signed)` (arithmetic / `would_narrow_into`
/// read only those), but DIFFER on `wide_default`: the wide defaults skip the literal
/// range-check (D227 Rule 1), the sized names are range-checked. This is the one bit
/// the lossy `Ty`/`TyCat` could not express and the reason `sized_int_name` needs the
/// structured carrier (`int`/`uint` → `None`; `i64`/`u64` → checked).
#[derive(Debug, Clone, PartialEq)]
pub enum ResolvedType {
    /// Int-family with EXACT bit-width + signedness (lossless replacement for
    /// `Ty::Int` / `TyCat::Int`). `wide_default`: `true` for `int`/`uint` only
    /// (D227 Rule 1 — no literal range-check), `false` for sized `i8..u64`.
    Scalar { width: u8, signed: bool, wide_default: bool },
    /// Float-family with EXACT bit-width (`f32`=32, `f64`=64) — lossless like `Scalar`
    /// (U.5.3): `cat_compatible` is permissive on width (assignability), but the
    /// generic-arg type-identity check needs `f32`≠`f64`.
    Float { width: u8 },
    Str,
    Bool,
    Unit,
    Never,
    /// Plan 115 D214 opaque `ptr`.
    Ptr,
    Any,
    /// L3 typed pointer: pointee modifier + inner (mirrors `Ty::TypedPtr`).
    TypedPtr(crate::ast::PointerModifier, Box<ResolvedType>),
    /// Named record/sum/newtype/alias/`char` WITH its generic type-arguments (U.5.3:
    /// `args` preserves `Stack[int]`≠`Stack[u32]` for the type-identity check; empty for
    /// non-generic names). `cat_compatible` compares the NAME only (args ignored —
    /// permissive assignability), the generic-arg check compares args exactly.
    ///
    /// U.5.5(a) — `module`: the qualifier path segments BEFORE the name (the syntactic
    /// `TypeRef::Named.path` minus its last segment); `[]` for a bare name. Makes the
    /// carrier LOSSLESS for the C mangle (D315): `type_ref_to_c` mangles a user type from
    /// `path.join("_")` → `Nova_<module…>_<name>*`, so the pre-U.5.5 `path.last()` dropped
    /// the module and mis-mangled `Nova_mymod_Foo*` as `Nova_Foo*`. Populated ONLY by
    /// `from_type_ref` (the direct C-lowering producer); `resolved_cat_of` and the literal
    /// producer leave it `[]` — they key category/identity on `name` alone, so the field is
    /// invisible to `cat_compatible_rt`/`distinct_mono` (both read `name`, not the struct).
    /// Full path for the future `resolved_type_to_c` lowering = `module ++ [name]`.
    Named { name: String, module: Vec<String>, args: Vec<ResolvedType> },
    Array(Box<ResolvedType>),
    Tuple(Vec<ResolvedType>),
    Func { params: Vec<ResolvedType>, ret: Box<ResolvedType>, effects: Vec<String> },
}

impl ResolvedType {
    /// `(width, signed, wide_default)` `Scalar` for a bare int-family primitive NAME
    /// (`i8`..`i64` / `u8`..`u64` / `int` / `uint`), else `None`. THE single primitive
    /// width/sign table (`[M-172.1-U5-structured-type]` §2 exception) — shared by
    /// `from_type_ref` (empty-generics guarded) and `resolved_cat_of` (unguarded,
    /// mirroring `cat_of`'s name match) so the width/sign/wide-default mapping lives in
    /// ONE place (no drift, §2/§0).
    fn scalar_from_int_name(name: &str) -> Option<ResolvedType> {
        use ResolvedType as R;
        Some(match name {
            "i8" => R::Scalar { width: 8, signed: true, wide_default: false },
            "i16" => R::Scalar { width: 16, signed: true, wide_default: false },
            "i32" => R::Scalar { width: 32, signed: true, wide_default: false },
            "i64" => R::Scalar { width: 64, signed: true, wide_default: false },
            "int" => R::Scalar { width: 64, signed: true, wide_default: true },
            "u8" => R::Scalar { width: 8, signed: false, wide_default: false },
            "u16" => R::Scalar { width: 16, signed: false, wide_default: false },
            "u32" => R::Scalar { width: 32, signed: false, wide_default: false },
            "u64" => R::Scalar { width: 64, signed: false, wide_default: false },
            "uint" => R::Scalar { width: 64, signed: false, wide_default: true },
            _ => return None,
        })
    }

    /// Total conversion from a `TypeRef`, mirroring `ty_of_ref`'s collapse rules
    /// (`Pointer`/`Mut(Pointer)`/`Unsafe(Pointer)` → `TypedPtr`; `Readonly` /
    /// `Mut(non-ptr)` / `Unsafe(non-ptr)` transparent) but LOSSLESS for int
    /// width/sign. Int-family resolves only with EMPTY type-args (mirrors
    /// `int_width_rank`'s generics-guard, so `int[X]` — an arity error caught
    /// elsewhere — is `Named`, never a bogus scalar).
    pub fn from_type_ref(tr: &TypeRef) -> ResolvedType {
        use ResolvedType as R;
        match tr {
            TypeRef::Named { path, generics, .. } => {
                let name = path.last().map(|s| s.as_str());
                // Int-family only with EMPTY type-args (generics-guard mirrors
                // `int_width_rank`/`ty_of_ref`, so `int[X]` — arity error caught
                // elsewhere — is `Named`, never a bogus scalar). Category resolution
                // (`resolved_cat_of`) drops this guard to mirror `cat_of`.
                if generics.is_empty() {
                    if let Some(s) = name.and_then(ResolvedType::scalar_from_int_name) {
                        return s;
                    }
                }
                match name {
                    Some("f32") => R::Float { width: 32 },
                    Some("f64") => R::Float { width: 64 },
                    Some("str") => R::Str,
                    Some("bool") => R::Bool,
                    Some("never") => R::Never,
                    // (legacy bare `ptr` name arm removed, U.5.4 — `ptr` is no longer a
                    // type, Plan 134; it now falls through to `Named` like any unknown
                    // name. `ResolvedType::Ptr` stays for typed pointers `*T`/`*()`.)
                    Some(n) => R::Named {
                        name: n.to_string(),
                        // U.5.5(a): carry the qualifier prefix (path minus the name
                        // segment) so the C mangle keeps the full identity, not just
                        // `path.last()`. `Some(n)` ⇒ `path` non-empty ⇒ no underflow.
                        module: path[..path.len() - 1].to_vec(),
                        args: generics.iter().map(R::from_type_ref).collect(),
                    },
                    None => R::Any,
                }
            }
            TypeRef::Array(inner, _) | TypeRef::FixedArray(_, inner, _) => {
                R::Array(Box::new(R::from_type_ref(inner)))
            }
            TypeRef::Tuple(elems, _) => R::Tuple(elems.iter().map(R::from_type_ref).collect()),
            TypeRef::Func { params, return_type, effects, .. } => R::Func {
                params: params.iter().map(R::from_type_ref).collect(),
                ret: Box::new(return_type.as_ref().map(|t| R::from_type_ref(t)).unwrap_or(R::Unit)),
                effects: effects
                    .iter()
                    .filter_map(|e| match e {
                        TypeRef::Named { path, .. } => path.last().cloned(),
                        _ => None,
                    })
                    .collect(),
            },
            TypeRef::Protocol { .. } => R::Any,
            TypeRef::Unit(_) => R::Unit,
            TypeRef::Readonly(inner, _) => R::from_type_ref(inner),
            // U.5.5(a): `*mut T` / `*unsafe T` pointee-modifier fidelity. The canonical
            // mutable pointer is `Pointer(Mut(T))` / `Pointer(Unsafe(T))` (Nova V2 syntax,
            // Plan 131/118.5); the pre-U.5.5 arm collapsed BOTH spellings to
            // `TypedPtr(Ro, …)`, losing the modifier (so the C mangle would emit `const T*`
            // instead of `T*`). Mirror `type_ref_to_c`'s `(is_mutable_ptr, base_inner)`
            // split — strip a `Mut`/`Unsafe` wrapper for the modifier — so `Pointer(Mut(T))`
            // ≡ `Mut(Pointer(T))` → `TypedPtr(Mut, T)` (the `Mut(Pointer)`/`Unsafe(Pointer)`
            // spellings below already did this; this closes the divergent `Pointer(Mut)`).
            TypeRef::Pointer(inner, _) => {
                let (modifier, base) = match inner.as_ref() {
                    TypeRef::Mut(ti, _) => (crate::ast::PointerModifier::Mut, ti.as_ref()),
                    TypeRef::Unsafe(ti, _) => (crate::ast::PointerModifier::Unsafe, ti.as_ref()),
                    _ => (crate::ast::PointerModifier::Ro, inner.as_ref()),
                };
                R::TypedPtr(modifier, Box::new(R::from_type_ref(base)))
            }
            TypeRef::Mut(inner, _) => match inner.as_ref() {
                TypeRef::Pointer(p, _) => {
                    R::TypedPtr(crate::ast::PointerModifier::Mut, Box::new(R::from_type_ref(p)))
                }
                _ => R::from_type_ref(inner),
            },
            TypeRef::Unsafe(inner, _) => match inner.as_ref() {
                TypeRef::Pointer(p, _) => {
                    R::TypedPtr(crate::ast::PointerModifier::Unsafe, Box::new(R::from_type_ref(p)))
                }
                _ => R::from_type_ref(inner),
            },
        }
    }

    /// `(width, signed)` if int-family, else `None`. Single source for the width/sign
    /// that `int_width_rank` recovers separately today (folded by U.5.2).
    pub fn int_width_sign(&self) -> Option<(u8, bool)> {
        match self {
            ResolvedType::Scalar { width, signed, .. } => Some((*width, *signed)),
            _ => None,
        }
    }

    /// Signedness if int-family.
    pub fn is_signed(&self) -> Option<bool> {
        self.int_width_sign().map(|(_, s)| s)
    }

    /// Canonical primitive NAME of an int-family scalar — `i8`..`i64`/`int`,
    /// `u8`..`u64`/`uint` — reconstructed from `(width, signed, wide_default)`, the
    /// inverse of `scalar_from_int_name` (THE single §2-sanctioned primitive table).
    /// `None` for non-int. Used for the diagnostic name in BOTH the sized range-check
    /// and the D227 unsigned-floor (where wide `uint` has no `sized_int_name`).
    pub fn int_name(&self) -> Option<&'static str> {
        let ResolvedType::Scalar { width, signed, wide_default } = self else {
            return None;
        };
        Some(match (*width, *signed, *wide_default) {
            (64, true, true) => "int",
            (64, false, true) => "uint",
            (8, true, _) => "i8",
            (16, true, _) => "i16",
            (32, true, _) => "i32",
            (64, true, _) => "i64",
            (8, false, _) => "u8",
            (16, false, _) => "u16",
            (32, false, _) => "u32",
            (64, false, _) => "u64",
            _ => return None,
        })
    }

    /// Sized-int name (`i8`..`i64` / `u8`..`u64`) for the literal range-check —
    /// `int_name` gated to the SIZED types: `None` for the wide defaults (`int`/`uint`,
    /// D227 Rule 1: a bare literal in `int`/`uint` context is not range-checked for the
    /// UPPER bound) and for non-int. (The unsigned FLOOR — negative into any unsigned,
    /// incl `uint` — is enforced separately, D227 amend.) Byte-identical to the deleted
    /// standalone `sized_int_name(&TypeRef)` when called on `from_type_ref(tr)`.
    pub fn sized_int_name(&self) -> Option<String> {
        match self {
            ResolvedType::Scalar { wide_default: true, .. } => None,
            _ => self.int_name().map(str::to_string),
        }
    }

    /// Would coercing a non-literal value of `self` into `target` LOSE range — i.e.
    /// a narrowing / value-range-unsafe int conversion requiring explicit `as`?
    /// Mirrors `is_int_narrowing` EXACTLY (single source for U.5.2). Non-int on
    /// either side ⇒ `false` (permissive, D54).
    pub fn would_narrow_into(&self, target: &ResolvedType) -> bool {
        let (Some((fw, fs)), Some((ew, es))) =
            (self.int_width_sign(), target.int_width_sign())
        else {
            return false;
        };
        if fw == ew && fs == es {
            return false; // identity widening (int≡i64, uint≡u64, Tn→Tn)
        }
        let safe_widening = match (fs, es) {
            (true, true) => ew > fw,   // signed → wider signed
            (false, false) => ew > fw, // unsigned → wider unsigned
            (false, true) => ew > fw,  // unsigned → strictly wider signed (range fits)
            (true, false) => false,    // signed → unsigned: never implicit
        };
        !safe_widening
    }
}

#[cfg(test)]
mod resolved_type_tests {
    use super::*;
    use crate::diag::Span;

    fn r(name: &str) -> ResolvedType {
        ResolvedType::from_type_ref(&prim_ref(name, Span::dummy()))
    }

    #[test]
    fn primitives_lossless_width_sign() {
        // `int`≡`i64` and `uint`≡`u64` on (width, signed) — the arithmetic /
        // narrowing axis — but DIFFER on `wide_default` (the D227 range-check axis).
        assert_eq!(r("int"), ResolvedType::Scalar { width: 64, signed: true, wide_default: true });
        assert_eq!(r("i64"), ResolvedType::Scalar { width: 64, signed: true, wide_default: false });
        assert_eq!(r("uint"), ResolvedType::Scalar { width: 64, signed: false, wide_default: true });
        assert_eq!(r("u64"), ResolvedType::Scalar { width: 64, signed: false, wide_default: false });
        // representation identical (int ≡ i64): same width/sign ⇒ no narrowing between them.
        assert_eq!(r("int").int_width_sign(), r("i64").int_width_sign());
        assert_eq!(r("uint").int_width_sign(), r("u64").int_width_sign());
        assert_eq!(r("i8"), ResolvedType::Scalar { width: 8, signed: true, wide_default: false });
        assert_eq!(r("u32"), ResolvedType::Scalar { width: 32, signed: false, wide_default: false });
        assert_eq!(r("f64"), ResolvedType::Float { width: 64 });
        assert_eq!(r("f32"), ResolvedType::Float { width: 32 });
        assert_eq!(r("str"), ResolvedType::Str);
        assert_eq!(r("bool"), ResolvedType::Bool);
        assert_eq!(r("never"), ResolvedType::Never);
        // `char` has no `Ty` primitive → `Named` (mirrors ty_of_ref).
        assert_eq!(r("char"), ResolvedType::Named { name: "char".to_string(), module: vec![], args: vec![] });
        assert_eq!(r("Foo"), ResolvedType::Named { name: "Foo".to_string(), module: vec![], args: vec![] });
    }

    #[test]
    fn l2_view_transparent_for_int() {
        let int = || prim_ref("int", Span::dummy());
        assert_eq!(
            ResolvedType::from_type_ref(&TypeRef::Readonly(Box::new(int()), Span::dummy())),
            ResolvedType::Scalar { width: 64, signed: true, wide_default: true }
        );
        assert_eq!(
            ResolvedType::from_type_ref(&TypeRef::Mut(Box::new(int()), Span::dummy())),
            ResolvedType::Scalar { width: 64, signed: true, wide_default: true }
        );
    }

    #[test]
    fn l3_typed_pointer_modifier_preserved() {
        use crate::ast::PointerModifier;
        let int = || prim_ref("int", Span::dummy());
        let ptr = |inner| TypeRef::Pointer(Box::new(inner), Span::dummy());
        let scal = || ResolvedType::Scalar { width: 64, signed: true, wide_default: true };
        assert_eq!(
            ResolvedType::from_type_ref(&ptr(int())),
            ResolvedType::TypedPtr(PointerModifier::Ro, Box::new(scal()))
        );
        assert_eq!(
            ResolvedType::from_type_ref(&TypeRef::Mut(Box::new(ptr(int())), Span::dummy())),
            ResolvedType::TypedPtr(PointerModifier::Mut, Box::new(scal()))
        );
        assert_eq!(
            ResolvedType::from_type_ref(&TypeRef::Unsafe(Box::new(ptr(int())), Span::dummy())),
            ResolvedType::TypedPtr(PointerModifier::Unsafe, Box::new(scal()))
        );
        // U.5.5(a) fidelity: the CANONICAL `*mut T` / `*unsafe T` spelling
        // `Pointer(Mut(T))` / `Pointer(Unsafe(T))` (Plan 131) — pre-U.5.5 these collapsed
        // to `TypedPtr(Ro)` (modifier lost → `const T*`). They now carry the modifier AND
        // agree with the `Mut(Pointer)` / `Unsafe(Pointer)` spelling above (no divergence).
        let mutw = |inner| TypeRef::Mut(Box::new(inner), Span::dummy());
        let unsw = |inner| TypeRef::Unsafe(Box::new(inner), Span::dummy());
        assert_eq!(
            ResolvedType::from_type_ref(&ptr(mutw(int()))),
            ResolvedType::TypedPtr(PointerModifier::Mut, Box::new(scal()))
        );
        assert_eq!(
            ResolvedType::from_type_ref(&ptr(unsw(int()))),
            ResolvedType::TypedPtr(PointerModifier::Unsafe, Box::new(scal()))
        );
        assert_eq!(
            ResolvedType::from_type_ref(&ptr(mutw(int()))),
            ResolvedType::from_type_ref(&mutw(ptr(int())))
        );
    }

    #[test]
    fn array_element_lossless() {
        let arr = TypeRef::Array(Box::new(prim_ref("u32", Span::dummy())), Span::dummy());
        assert_eq!(
            ResolvedType::from_type_ref(&arr),
            ResolvedType::Array(Box::new(ResolvedType::Scalar { width: 32, signed: false, wide_default: false }))
        );
    }

    #[test]
    fn int_with_type_args_is_named_not_scalar() {
        // `int[X]` (arity error elsewhere) must NOT become a bogus scalar —
        // mirrors int_width_rank's generics-guard.
        let int_x = TypeRef::Named {
            path: vec!["int".to_string()],
            generics: vec![prim_ref("X", Span::dummy())],
            span: Span::dummy(),
        };
        // `int[X]` → `Named { "int", [X] }` (NOT a bogus scalar — generics-guard).
        assert!(matches!(
            ResolvedType::from_type_ref(&int_x),
            ResolvedType::Named { name, .. } if name == "int"
        ));
    }

    #[test]
    fn named_carries_module_identity_lossless() {
        // U.5.5(a): the carrier keeps the FULL syntactic identity — the qualifier prefix
        // (`module`) plus the `name` — so the C mangle reconstructs `path.join("_")`
        // (`Nova_<module…>_<name>*`) instead of dropping the module (the pre-U.5.5
        // `path.last()` mis-mangled `Nova_mymod_Foo*` as `Nova_Foo*`).
        let named = |segs: &[&str], gen: Vec<TypeRef>| TypeRef::Named {
            path: segs.iter().map(|s| s.to_string()).collect(),
            generics: gen,
            span: Span::dummy(),
        };
        // bare name → empty module.
        assert_eq!(
            ResolvedType::from_type_ref(&named(&["Foo"], vec![])),
            ResolvedType::Named { name: "Foo".into(), module: vec![], args: vec![] }
        );
        // single-segment qualifier preserved.
        assert_eq!(
            ResolvedType::from_type_ref(&named(&["mymod", "Foo"], vec![])),
            ResolvedType::Named { name: "Foo".into(), module: vec!["mymod".into()], args: vec![] }
        );
        // multi-segment qualifier preserved in order (full path = module ++ [name]).
        assert_eq!(
            ResolvedType::from_type_ref(&named(&["std", "collections", "Map"], vec![])),
            ResolvedType::Named {
                name: "Map".into(),
                module: vec!["std".into(), "collections".into()],
                args: vec![],
            }
        );
        // generics recurse and carry their own identity; outer module preserved.
        assert_eq!(
            ResolvedType::from_type_ref(&named(&["mymod", "Box"], vec![prim_ref("int", Span::dummy())])),
            ResolvedType::Named {
                name: "Box".into(),
                module: vec!["mymod".into()],
                args: vec![ResolvedType::Scalar { width: 64, signed: true, wide_default: true }],
            }
        );
        // CALIBRATION (byte-identical gate): `module` is invisible to category/identity
        // comparison — `cat_compatible_rt`/`distinct_mono` read `name` only, so a
        // module-qualified and a bare same-name type stay category-compatible and are NOT
        // a distinct-mono mismatch (the enrichment cannot shift any existing decision).
        let qual = ResolvedType::from_type_ref(&named(&["mymod", "Foo"], vec![]));
        let bare = ResolvedType::from_type_ref(&named(&["Foo"], vec![]));
        assert!(cat_compatible_rt(&qual, &bare));
        assert!(!distinct_mono(&qual, &bare));
    }

    #[test]
    fn would_narrow_into_int_semantics() {
        // narrowing reads only (width, signed) — `wide_default` is irrelevant here.
        let s = |w, sg| ResolvedType::Scalar { width: w, signed: sg, wide_default: false };
        // narrowing / value-range-unsafe:
        assert!(s(32, false).would_narrow_into(&s(32, true))); // u32 → i32
        assert!(s(64, false).would_narrow_into(&s(64, true))); // u64 → int(i64)
        assert!(s(32, true).would_narrow_into(&s(32, false))); // i32 → u32 (signed→unsigned)
        assert!(s(64, true).would_narrow_into(&s(8, true)));   // i64 → i8
        // safe widening / identity:
        assert!(!s(8, false).would_narrow_into(&s(64, true)));  // u8 → int (range fits)
        assert!(!s(64, true).would_narrow_into(&s(64, true)));  // int ≡ i64 identity
        assert!(!s(8, true).would_narrow_into(&s(16, true)));   // i8 → i16
        assert!(!s(8, false).would_narrow_into(&s(16, false))); // u8 → u16
        // over real TypeRefs (the narrowing surface `assignable` exercises) — these are
        // the exact pairs the deleted `is_int_narrowing` decided; pinned to the SAME
        // verdicts (the U.5.2 fold is byte-identical, also gated by the corpus run).
        let tr = |n| prim_ref(n, Span::dummy());
        for (f, e, expect) in [
            ("u32", "i32", true),  // narrowing (same width, sign flip)
            ("u8", "int", false),  // safe widening (range fits)
            ("i32", "u32", true),  // signed → unsigned
            ("int", "i64", false), // int ≡ i64 identity
            ("u64", "int", true),  // u64 → i64 narrowing
            ("u8", "u16", false),  // safe widening
            ("i64", "i8", true),   // narrowing
        ] {
            assert_eq!(
                ResolvedType::from_type_ref(&tr(f))
                    .would_narrow_into(&ResolvedType::from_type_ref(&tr(e))),
                expect,
                "would_narrow_into({f} → {e})"
            );
        }
    }

    #[test]
    fn sized_int_name_distinguishes_wide_default() {
        let tr = |n| prim_ref(n, Span::dummy());
        // The whole reason for `wide_default`: `int`/`uint` skip the range-check
        // (D227 Rule 1), the sized names are checked — a distinction `Scalar{w,s}`
        // alone could NOT express (`uint`≡`u64`≡(64,false)). Replaces the deleted
        // standalone `sized_int_name(&TypeRef)` — same verdicts, pinned directly.
        assert_eq!(r("int").sized_int_name(), None);
        assert_eq!(r("uint").sized_int_name(), None);
        assert_eq!(r("i64").sized_int_name(), Some("i64".to_string()));
        assert_eq!(r("u64").sized_int_name(), Some("u64".to_string()));
        assert_eq!(r("u8").sized_int_name(), Some("u8".to_string()));
        assert_eq!(r("i8").sized_int_name(), Some("i8".to_string()));
        assert_eq!(r("i16").sized_int_name(), Some("i16".to_string()));
        assert_eq!(r("i32").sized_int_name(), Some("i32".to_string()));
        assert_eq!(r("u16").sized_int_name(), Some("u16".to_string()));
        assert_eq!(r("u32").sized_int_name(), Some("u32".to_string()));
        assert_eq!(r("str").sized_int_name(), None);
        assert_eq!(r("bool").sized_int_name(), None);
        assert_eq!(r("Foo").sized_int_name(), None);
        // L2 view (ro/mut/unsafe) transparent — `from_type_ref` unwraps, so the method
        // sees the inner sized int (same as the deleted fn's unwrap).
        let ro_u8 = TypeRef::Readonly(Box::new(tr("u8")), Span::dummy());
        assert_eq!(
            ResolvedType::from_type_ref(&ro_u8).sized_int_name(),
            Some("u8".to_string())
        );
    }

    #[test]
    fn int_name_full_table_incl_wide_defaults() {
        // int_name covers ALL int spellings (incl wide int/uint) — the name source for
        // the D227 unsigned-floor where sized_int_name(uint) is None.
        assert_eq!(r("int").int_name(), Some("int"));
        assert_eq!(r("uint").int_name(), Some("uint"));
        assert_eq!(r("i64").int_name(), Some("i64"));
        assert_eq!(r("u64").int_name(), Some("u64"));
        assert_eq!(r("i8").int_name(), Some("i8"));
        assert_eq!(r("u32").int_name(), Some("u32"));
        assert_eq!(r("str").int_name(), None);
        assert_eq!(r("Foo").int_name(), None);
        // round-trips through scalar_from_int_name (the single primitive table):
        for n in ["i8", "i16", "i32", "i64", "int", "u8", "u16", "u32", "u64", "uint"] {
            assert_eq!(r(n).int_name(), Some(n));
        }
    }

    #[test]
    fn cat_compatible_rt_mirrors_legacy_arms() {
        use ResolvedType as R;
        let sc = |w, s| R::Scalar { width: w, signed: s, wide_default: false };
        let nm = |n: &str| R::Named { name: n.to_string(), module: vec![], args: vec![] };
        let f = |w| R::Float { width: w };
        // `Any` permissive (= old `Other`):
        assert!(cat_compatible_rt(&R::Any, &R::Str));
        assert!(cat_compatible_rt(&R::Bool, &R::Any));
        // Scalar/Float permissive on width+sign (= old (Int,Int)/(Int,Float)) — narrowing
        // is decided SEPARATELY by `would_narrow_into`, not here:
        assert!(cat_compatible_rt(&sc(8, false), &sc(64, true)));
        assert!(cat_compatible_rt(&sc(64, false), &sc(8, true)));
        assert!(cat_compatible_rt(&sc(32, true), &f(64)));
        assert!(cat_compatible_rt(&f(32), &sc(16, false)));
        assert!(cat_compatible_rt(&f(32), &f(64))); // float width permissive here
        // same-kind primitives:
        assert!(cat_compatible_rt(&R::Bool, &R::Bool));
        assert!(cat_compatible_rt(&R::Str, &R::Str));
        assert!(cat_compatible_rt(&R::Unit, &R::Unit));
        assert!(cat_compatible_rt(&R::Ptr, &R::Ptr));
        // Named by name (incl. `char` riding as `Named { "char", .. }` = old `(Char,Char)`);
        // generic args ignored here (permissive) — exactness is the type-identity check:
        assert!(cat_compatible_rt(&nm("char"), &nm("char")));
        assert!(cat_compatible_rt(&nm("Foo"), &nm("Foo")));
        assert!(cat_compatible_rt(
            &R::Named { name: "Box".into(), module: vec![], args: vec![sc(64, true)] },
            &R::Named { name: "Box".into(), module: vec![], args: vec![sc(32, false)] }
        )); // same NAME, different args → still compatible at this layer
        assert!(!cat_compatible_rt(&nm("Foo"), &nm("Bar")));
        assert!(!cat_compatible_rt(&nm("char"), &R::Str));
        // Array recurses on element:
        assert!(cat_compatible_rt(
            &R::Array(Box::new(sc(8, false))),
            &R::Array(Box::new(sc(64, true)))
        ));
        assert!(!cat_compatible_rt(
            &R::Array(Box::new(R::Bool)),
            &R::Array(Box::new(R::Str))
        ));
        // mismatched kinds → false:
        assert!(!cat_compatible_rt(&R::Bool, &R::Str));
        assert!(!cat_compatible_rt(&sc(8, true), &R::Bool));
    }
}

/// Результат проверки модуля — карта имён top-level → тип.
///
/// **D84 overloading:** `fns` хранит **Vec** для каждого имени, потому
/// что одно имя может иметь несколько перегрузок (методы с одним именем
/// на одном receiver-type, free-functions с разными signatures, разные
/// `From[X]`). Резолв на call-site по argument-types — ответственность
/// codegen / bound-checker.
#[derive(Debug, Default)]
pub struct ModuleEnv {
    pub types: HashMap<String, TypeDecl>,
    pub fns: HashMap<String, Vec<FnDecl>>,
    pub consts: HashMap<String, ConstDecl>,
    /// Plan 33.1 Ф.3: список доказанных (fn_name, contract span) контрактов.
    /// Codegen в release-сборке стирает соответствующие runtime-checks
    /// (zero-cost guarantee). В debug — checks всегда emit'ятся.
    pub proven_contracts: Vec<(String, Span)>,
    /// Plan 140.2 Part B (D257 / B.4): spans Index-сайтов, доказанных из LOOP/CODE
    /// (без contract-requires). Codegen элидит ВСЕГДА.
    pub proven_index_sites: Vec<Span>,
    /// Plan 140.2 followup §2: Index-сайты, доказанные ТОЛЬКО с fn-`requires`.
    /// Codegen элидит ТОЛЬКО при включённых контрактах (не `--contracts=off`).
    pub proven_index_sites_contract: Vec<Span>,
    /// Plan 140.4 ([M-opt-elide-proven-overflow-checks]): spans `int` `+`/`-`/`*`,
    /// доказанных в диапазоне i64 из LOOP/CODE. Codegen элидит `nova_int_checked_*`
    /// ВСЕГДА (safe даже под `--contracts=off`).
    pub proven_overflow_sites: Vec<Span>,
    /// Plan 140.4: `int`-арифм. сайты, доказанные ТОЛЬКО с fn-`requires`. Codegen
    /// элидит ТОЛЬКО при включённых контрактах (не `--contracts=off`).
    pub proven_overflow_sites_contract: Vec<Span>,
    /// Plan 172.1 U.4.1: per-Expr resolved-type annotations (ExprId → ResolvedType)
    /// from the semantic pass — codegen reads them instead of re-deriving
    /// (`infer_expr_c_type`, §0/§1). Part 2 seeds LITERALS via `number_exprs`; the
    /// checker annotates the rest in U.4.2+.
    pub resolved_types: HashMap<crate::ast::ExprId, ResolvedType>,
}

/// Минимальная проверка модуля. Регистрирует имена и базовую структуру —
/// для bootstrap'а этого достаточно: интерпретатор ловит ошибки типов в
/// runtime через match-mismatch и method-not-found.
pub fn check_module(module: &Module) -> Result<ModuleEnv, Vec<Diagnostic>> {
    check_module_impl(module, None)
}

/// Internal implementation shared by [`check_module`] and
/// [`check_module_with_sig_table`].  `sig_table` is `None` in the
/// default (no-I/O) path and `Some(table)` when the caller has
/// already collected cross-module signatures.
///
/// Plan 162.1 Step 3: the `sig_table` is threaded into:
/// - `TypeCheckCtx::build_with_sig_table` → `is_known_type` /
///   `is_known_fn` used in `verify_impl_protocols` to suppress false
///   `E_UNKNOWN_PROTOCOL` when the protocol is from a transitively
///   imported module not yet inline-merged.
/// - `check_protocol_embeds` → suppresses `E_PROTOCOL_EMBED_UNKNOWN`.
/// - `check_generic_bound_declarations` → suppresses `E_BOUND_UNKNOWN`.
fn check_module_impl(
    module: &Module,
    sig_table: Option<&crate::imports::ModuleSigTable>,
) -> Result<ModuleEnv, Vec<Diagnostic>> {
    let mut env = ModuleEnv::default();
    let mut errors = Vec::new();
    let mut names: HashSet<String> = HashSet::new();

    // D82: `external fn` whitelisted только в `std/runtime/*.nv`. User-код
    // не должен использовать external — это keyword для документирования
    // stdlib runtime-функций, реализованных в nova_rt/*.h. Будущий
    // `extern("C")` для FFI к сторонним libs — отдельный keyword.
    //
    // Plan 42 Sub-plan 42.6: detect runtime module по обоих declaration
    // форматов (rev-1 legacy + rev-3 parent.X). Logic — в manifest helper.
    //
    // Plan 62.A: also whitelist `std.prelude.*` submodules. Prelude
    // sub-modules (`std/prelude/core.nv`, etc.) declare types/methods
    // implemented by codegen helpers in `nova_rt/*.h` — same pattern
    // as `std.runtime.*` (declaration-only, no Nova body).
    //
    // Plan 62.A (2026-05-18): check only items DECLARED HERE (in entry
    // peers' `items_here`), not items merged from imports. Otherwise
    // `external fn`-карта prelude'а проседает на каждом user-модуле:
    // user `module foo` импортирует `std.prelude` → prelude.core external
    // fns merge'нутся в `module.items` → check fires на foo. Items
    // источника prelude.core валидируются при компиляции САМОГО
    // prelude.core (отдельный `check_module` invocation на std).
    let is_runtime_module = crate::manifest::is_stdlib_runtime_module(&module.name)
        || crate::manifest::is_prelude_self_module(&module.name);
    if !is_runtime_module {
        // Collect entry peers' items_here (items declared в этом модуле
        // самим, не pulled через imports). Fallback на module.items если
        // peer_files пуст (legacy single-file).
        let entry_items: Vec<&Item> = if module.peer_files.is_empty() {
            module.items.iter().collect()
        } else {
            module.peer_files
                .iter()
                .filter(|pf| pf.is_entry_module)
                .flat_map(|pf| pf.items_here.iter())
                .collect()
        };
        for item in entry_items {
            if let Item::Fn(fd) = item {
                if fd.is_external {
                    // Plan 91.10 (D163 retracted): `needs <Cap>` clause удалён.
                    //
                    // Plan 115 D214 amend D82 (2026-05-31): D82 restriction
                    // "external fn only allowed in std.runtime.*" SNYATA.
                    // Foundational FFI требует user-level `external fn` для
                    // bindings к третьесторонним C libraries (libsqlite, libpng,
                    // libcurl, etc) без участия compiler-team. User несёт
                    // ответственность за:
                    //   - правильную C shim implementation (Layer 4),
                    //   - safe memory ownership (consume close() pattern),
                    //   - link-time provision shim object files (`nova build
                    //     --c-shim path/to/shim.c`).
                    //
                    // Verification: D214 §«Layered FFI pattern». Future
                    // `[M-115-ffi-build-pipeline]` formalizes shim linking
                    // CLI.
                    // Plan 118 (D216 §20): `external fn ... Fail -> ...` —
                    // E_EXTERNAL_FN_FAIL_EFFECT. C ABI не propagates Nova
                    // exception machinery; Fail effect crossing FFI boundary
                    // = undefined behavior (no DWARF unwinder hookup). User
                    // должен catch внутри callback / wrapper, return sentinel.
                    // V1 enforcement: rejected on declaration. Future
                    // `extern "C-unwind"` (Rust 2024 model) — V2 research
                    // [M-118-extern-c-unwind].
                    for eff in &fd.effects {
                        if let TypeRef::Named { path, .. } = eff {
                            if path.last().map_or(false, |n| n == "Fail") {
                                errors.push(Diagnostic::new(
                                    format!(
                                        "[E_EXTERNAL_FN_FAIL_EFFECT] `external fn {}` declares `Fail` effect — \
                                         not allowed на Nova→C FFI boundary (D216 §20). C runtime не propagates \
                                         Nova exception machinery; throwing across C ABI = undefined behavior. \
                                         Workaround: catch внутри wrapper, return sentinel value (e.g. negative \
                                         error code) — let Nova-side caller convert sentinel к Fail. Future \
                                         `extern \"C-unwind\"` (Rust 2024 model) — `[M-118-extern-c-unwind]`.",
                                        fd.name,
                                    ),
                                    eff.span(),
                                ));
                            }
                        }
                    }
                }
            }
            // D126 (Plan 62.D.bis) + D163 (Plan 100.5) both fully retracted:
            //   - `external type X` — RETRACTED (E_EXTERNAL_TYPE_RETRACTED). Migration: `type X(ptr)`.
            //   - `external type X consume` — RETRACTED (D163 removed). Migration: `type X value { priv handle int }`.
            //   - `external fn` — RETRACTED (E_EXTERNAL_FN_RETRACTED) in parser. Use `extern "nova" fn`.
            if let Item::Type(td) = item {
                if matches!(td.kind, TypeDeclKind::Opaque) {
                    let hint = if td.consume {
                        format!(
                            "[E_EXTERNAL_TYPE_RETRACTED] `external type {name} consume` (D163) retracted. \
                             Use: `type {name} consume value {{ priv handle int }}` (D241 canonical order: consume value priv). \
                             Add cleanup method: `fn {name} consume @close() -> () {{ ... }}`.",
                            name = td.name
                        )
                    } else {
                        format!(
                            "[E_EXTERNAL_TYPE_RETRACTED] `external type {name}` (D126) retracted. \
                             Use tuple-newtype: `type {name}(ptr)` (Plan 115 D214). \
                             Migration guide: docs/migration/d126-to-tuple-newtype.md.",
                            name = td.name
                        )
                    };
                    errors.push(Diagnostic::new(hint, td.span));
                }
            }
        }
    }

    // Plan 163 Ф.1 (D282): E_REEXPORT_GLOB — запрет whole-module re-export.
    // `export import m` без `.{}` селектора = неконтролируемый barrel-реэкспорт;
    // гигиена поверхности имён требует явного именованного списка.
    // Разрешены: `export import m.{a, b}` (named). Forbidden: `export import m`.
    // Нулевая миграция: все 39 существующих `export import` уже именованные.
    //
    // Plan 163 Ф.2 (D282): E_IMPORT_GLOB — запрет whole-module import без alias.
    // `import m` без `.{}` селектора и без `as alias` = неконтролируемый glob;
    // загрязняет пространство имён неизвестным набором bare-имён.
    // Разрешены: `import m.{a, b}` (named), `import m as m` (qualified namespace).
    // Forbidden: `import m` (без selectors и без alias).
    // Exemption: prelude auto-imports (`std.prelude.*`) — служебный путь компилятора.
    //
    // Источник импортов: если peer_files заполнен (после resolve_imports_inline),
    // используем pf.imports каждого peer'а — они охватывают и entry и siblings.
    // Fallback на module.imports если peer_files пуст (legacy single-file без resolve).
    {
        let peer_imports_iter: Box<dyn Iterator<Item = &Import>> =
            if module.peer_files.is_empty() {
                Box::new(module.imports.iter())
            } else {
                Box::new(module.peer_files.iter().flat_map(|pf| pf.imports.iter()))
            };
        for imp in peer_imports_iter {
            if imp.is_export && imp.items.is_none() && imp.alias.is_none() {
                errors.push(Diagnostic::new(
                    format!(
                        "[E_REEXPORT_GLOB] `export import {}` re-exports the entire module \
                         without a name selector — this is a barrel re-export (Plan 163 / D282). \
                         Hint: use `export import {}.{{name1, name2}}` to re-export specific names.",
                        imp.path.join("."),
                        imp.path.join("."),
                    ),
                    imp.span,
                ));
            }
            // D289 amend: `import m` without `.{}` or `as` is legal — last segment
            // becomes the qualified namespace name (import vec_iter → vec_iter.Foo).
            // imported_modules already inserts path.last() unconditionally (Plan 81 Ф.2).
            // E_IMPORT_GLOB removed; only E_REEXPORT_GLOB (export form) remains.
            //
            // E_REDUNDANT_IMPORT_ALIAS: `import a.b.YYY as YYY` is forbidden —
            // alias equals last segment, which is the default; just write `import a.b.YYY`.
            if let Some(alias) = &imp.alias {
                if imp.items.is_none() {
                    if let Some(last) = imp.path.last() {
                        if alias == last {
                            errors.push(Diagnostic::new(
                                format!(
                                    "[E_REDUNDANT_IMPORT_ALIAS] `import {} as {}` — alias \
                                     matches the last path segment, which is the default. \
                                     Write `import {}` instead.",
                                    imp.path.join("."),
                                    alias,
                                    imp.path.join("."),
                                ),
                                imp.span,
                            ));
                        }
                    }
                }
            }
        }
    }

    // Plan 62.D bis-1 (2026-05-18, D29 W_PRELUDE_SHADOW basic):
    // Determine which items in `module.items` came from imports (vs the
    // user's own entry file) — these are conflict candidates for D29 lint
    // and for the "codegen-completeness invisible merge" detection.
    //
    // The merge logic in `imports.rs` is two-phase:
    //   - `merged_items` (→ `module.items`): ALL items from imported peer
    //     modules are pulled in for codegen completeness (e.g. typedef'ы
    //     should be available even if not selectively imported). This
    //     causes apparent name conflicts when the user re-declares a name
    //     that's in a merged-but-not-visible item.
    //   - `imported_item_names` (per-peer): names actually VISIBLE to the
    //     user via explicit imports + selective re-exports. This is the
    //     proper "what does user see" set.
    //
    // D29 rule (W_PRELUDE_SHADOW basic): user declarations that conflict
    // with names brought in via prelude auto-import → warning (not error).
    // User declarations that conflict with codegen-only merged items (not
    // user-visible) → silently accept user's declaration.
    //
    // We collect entry-visible names via prelude into `prelude_visible_names`;
    // items in `module.items` NOT in this set AND NOT in user's own
    // `items_here` are codegen-only merges — silently allowed to be
    // shadowed by user code.
    //
    // Detection of "prelude-brought-in":
    //   Pass 1: names declared directly in `std/prelude/*` or
    //   `std/prelude.nv` peer files (items_here of those peers).
    //   Pass 2: names re-exported through prelude facade via selective
    //   `export import X.{A, B}` lists in prelude peer imports. The
    //   re-exported alias (if any) is the visible name.
    //
    // Without this fix, enabling `export import
    // std.collections.range.{Range, RangeIter}` in `std/prelude.nv` broke
    // `nova_tests/syntax/for_in_range_iter.nv` (which locally declares
    // `type Range` and `type StepRangeIter`).
    //
    // Plan 62.F.bis Ф.2 (2026-05-18): visibility computation вынесена в
    // `lints::collect_prelude_visibility`. types::check_module использует
    // её для silent classify duplicate'ов (user-decl wins); structured
    // W_PRELUDE_SHADOW warning эмитится через `lints::lint_prelude_shadow`
    // — отдельно, в pipeline после check_module. Раньше eprintln здесь
    // дублировал диагностику; теперь silent — warnings приходят как
    // structured LintWarning через `cmd_check` warnings field.
    let prelude_vis = crate::lints::collect_prelude_visibility(module);

    // Classify a duplicate top-level name:
    //   - `Some(true)` → name is visible via prelude → user-decl wins,
    //     structured warning emitted by `lints::lint_prelude_shadow`
    //   - `Some(false)` → name is merged-from-imports (codegen-only, not
    //     user-visible) → silent (user wins)
    //   - `None` → genuine duplicate (e.g. user code declared same name twice)
    //     → error
    let classify_dup = |name: &str| -> Option<bool> {
        if prelude_vis.visible.contains(name) { Some(true) }
        else if prelude_vis.merged_from_imports.contains(name) { Some(false) }
        else { None }
    };

    // Plan 154 [M-method-override-silent-noop]: типы, объявленные ЛОКАЛЬНО в
    // user-коде (entry peers). Если пользователь сам (пере)объявил `type Range`,
    // то `fn Range @step_by` — метод на ЕГО типе (legit shadow всего типа,
    // Plan 62 user-wins), а не silent-override prelude/built-in метода. Ошибку
    // E_METHOD_REDEFINITION шлём ТОЛЬКО для методов на типах, которые юзер НЕ
    // объявлял локально (str/Vec/… из prelude — footgun, см. ниже).
    let user_declared_types: std::collections::HashSet<String> = module
        .peer_files
        .iter()
        .filter(|pf| pf.is_entry_module)
        .flat_map(|pf| pf.items_here.iter())
        .filter_map(|it| if let Item::Type(td) = it { Some(td.name.clone()) } else { None })
        .collect();

    // Plan 170 (D307): file-private dedup support. Two `priv(file)` symbols
    // with the SAME name in DIFFERENT peer files are NOT a conflict — they
    // occupy disjoint file-scopes. Collect, per top-level name, the set of
    // file_ids in which a `priv(file)` symbol of that name is declared. A
    // name-collision is тогда suppressed iff EVERY declaration carrying that
    // name (existing + new) is file-private AND they live in distinct files.
    // Module-private / export collisions remain errors as before (D281/D29).
    let mut file_priv_decl_files: std::collections::HashMap<String, std::collections::HashSet<FileId>>
        = std::collections::HashMap::new();
    // Count of NON-file-private (module-default / export) decls per name —
    // if any exists, the name lives in the shared module namespace and a
    // collision is a genuine duplicate even if other copies are file-private.
    let mut non_file_priv_names: std::collections::HashSet<String>
        = std::collections::HashSet::new();
    {
        let mut record = |name: &str, fp: bool, fid: FileId| {
            if fp {
                file_priv_decl_files.entry(name.to_string()).or_default().insert(fid);
            } else {
                non_file_priv_names.insert(name.to_string());
            }
        };
        for item in &module.items {
            match item {
                Item::Type(td) => record(&td.name, td.file_private, td.span.file_id),
                Item::Const(cd) => record(&cd.name, cd.file_private, cd.span.file_id),
                Item::Fn(fd) if fd.receiver.is_none() => {
                    record(&fd.name, fd.file_private, fd.span.file_id);
                }
                _ => {}
            }
        }
    }
    // A name's collision is suppressible (file-private dedup) iff there is NO
    // non-file-private decl of that name AND it is file-private in ≥2 files.
    let is_file_priv_dedup = |name: &str| -> bool {
        !non_file_priv_names.contains(name)
            && file_priv_decl_files.get(name).map_or(false, |s| s.len() >= 2)
    };

    for item in &module.items {
        match item {
            Item::Type(td) => {
                if !names.insert(td.name.clone()) {
                    // Plan 170 (D307): file-private dedup — two `priv(file)`
                    // types with the same name in different peer files are NOT
                    // a conflict (disjoint file-scopes). Silently keep the
                    // first registered (env.types is name-keyed; both share an
                    // identical user-visible signature within their own file).
                    if is_file_priv_dedup(&td.name) {
                        continue;
                    }
                    // Plan 62.D bis-1: classify the duplicate per D29.
                    match classify_dup(&td.name) {
                        Some(true) => {
                            // Visible via prelude → user-declaration wins
                            // silently here; structured W_PRELUDE_SHADOW
                            // warning emitted by `lints::lint_prelude_shadow`
                            // (Plan 62.F.bis Ф.2 — see warnings field в
                            // cmd_check для surface). User-decl still wins;
                            // qualify as `std.prelude.<sub>.<name>` для
                            // прямого доступа к prelude version.
                            env.types.insert(td.name.clone(), td.clone());
                            continue;
                        }
                        Some(false) => {
                            // Codegen-only merge (not user-visible). User's
                            // declaration silently wins.
                            env.types.insert(td.name.clone(), td.clone());
                            continue;
                        }
                        None => {
                            errors.push(Diagnostic::new(
                                format!("duplicate top-level name `{}`", td.name),
                                td.span,
                            ));
                        }
                    }
                }
                env.types.insert(td.name.clone(), td.clone());
            }
            Item::Fn(fd) => {
                let key = match &fd.receiver {
                    Some(r) => format!("{}.{}", r.type_name, fd.name),
                    None => fd.name.clone(),
                };
                // D84: overload по любой из четырёх осей (receiver-type,
                // arg-types, result-type, arity). Под одним именем может
                // быть несколько overloads, различающихся sig'ами; codegen
                // и bound-checker резолвят call-site по argument-types.
                //
                // Запрещено только **точное дублирование signature**
                // (одинаковые arity + одинаковые arg-types) — это была бы
                // ambiguity без возможности резолва. Проверка ниже.
                names.insert(key.clone()); // names — для конфликтов с типами/const'ами
                let entry = env.fns.entry(key.clone()).or_default();
                // D84: overload-disambiguation по любой из четырёх осей.
                // Точное дублирование запрещено — это требует одновременного
                // совпадения **arity + arg-types + return-type** (плюс
                // receiver-type, который уже включён в `key`). Если хоть одна
                // ось различается — overload валиден.
                let new_arg_tys: Vec<&TypeRef> = fd.params.iter().map(|p| &p.ty).collect();
                // Plan 135: receiver-mutability is a valid overload axis.
                // `fn T @m()` and `fn T mut @m()` are distinct overloads.
                let new_recv_mut = fd.receiver.as_ref().map(|r| r.mutable).unwrap_or(false);
                let dup_existing = entry.iter().find(|existing| {
                    // Plan 135: if receiver-mutability differs, NOT a duplicate.
                    let existing_recv_mut = existing.receiver.as_ref().map(|r| r.mutable).unwrap_or(false);
                    if existing_recv_mut != new_recv_mut { return false; }
                    // Arity + arg-types одинаковы?
                    let args_equal = existing.params.len() == fd.params.len()
                        && existing.params.iter().zip(new_arg_tys.iter())
                            .all(|(p, new_ty)| typeref_equal(&p.ty, new_ty));
                    if !args_equal { return false; }
                    // Return-type одинаков? (None / None или Some/Some equal).
                    match (&existing.return_type, &fd.return_type) {
                        (None, None) => true,
                        (Some(a), Some(b)) => typeref_equal(a, b),
                        _ => false,
                    }
                });
                if dup_existing.is_some() {
                    // Plan 62.D bis-1: D29 — duplicate fn signature shadowing
                    // a prelude-imported definition → warning (not error).
                    // E.g. `fn Range @step_by(int) -> StepRangeIter` declared
                    // in both user file and the merged-via-prelude
                    // std/collections/range.nv. User wins.
                    let dup_pos = entry.iter().position(|existing| {
                        let existing_recv_mut = existing.receiver.as_ref().map(|r| r.mutable).unwrap_or(false);
                        if existing_recv_mut != new_recv_mut { return false; }
                        let args_equal = existing.params.len() == fd.params.len()
                            && existing.params.iter().zip(new_arg_tys.iter())
                                .all(|(p, new_ty)| typeref_equal(&p.ty, new_ty));
                        if !args_equal { return false; }
                        match (&existing.return_type, &fd.return_type) {
                            (None, None) => true,
                            (Some(a), Some(b)) => typeref_equal(a, b),
                            _ => false,
                        }
                    });
                    // Plan 154 [M-method-override-silent-noop]: переопределение
                    // **метода** (receiver present) с той же сигнатурой, что у
                    // метода из std/prelude/импортированного модуля — это SILENT
                    // NO-OP: codegen `method_overloads` резолвит call-site
                    // first-match, а prelude/std prepend'ится первым → выигрывает
                    // существующее определение, тело пользователя НИКОГДА не
                    // вызывается (проверено: `fn str @to_lower` → "ABC".to_lower()
                    // печатает "abc", std-версия). Раньше — молча принималось
                    // (Some(_) → user-wins в env.fns, но codegen игнорирует) → нет
                    // диагностики. Теперь — ошибка: extension-метод должен иметь
                    // другое имя ИЛИ отличаться сигнатурой (overload, D84); для
                    // смены поведения типа — newtype + own-method (02-types §override
                    // через own-methods). Type/const/free-fn shadowing — без изменений
                    // (Plan 62 prelude-shadow: user-wins + W_PRELUDE_SHADOW).
                    //
                    // ИСКЛЮЧЕНИЕ (Plan 62): если receiver-тип объявлен ЛОКАЛЬНО юзером
                    // (`user_declared_types`) — это методы на ЕГО (пере)объявленном
                    // типе (shadow всего типа), не override чужого метода → НЕ ошибка
                    // (напр. nova_tests/syntax/for_in_range_iter.nv: локальные
                    // `type Range`+`fn Range @step_by`).
                    // Two IDENTICAL `extern` declarations (same signature, same
                    // C symbol) across peer files of one folder-module are NOT a
                    // conflict — they are repeated forward-declarations of a
                    // single external symbol. Codegen emits one prototype; the
                    // duplicate is harmless. Silent-merge (keep one) instead of
                    // erroring. Fires e.g. when two plan139 t4_* peers both
                    // declare `extern "nova" fn p139_make_str() -> str`.
                    let both_external = fd.is_external
                        && dup_existing.map(|e| e.is_external).unwrap_or(false);
                    if both_external {
                        continue;
                    }
                    // Plan 170 (D307): file-private dedup — two `priv(file)`
                    // free functions with the same name in different peer files
                    // are NOT a conflict. Applies only to free fns (`key` ==
                    // bare name); methods carry a receiver-qualified key and are
                    // out of scope for file-private. Codegen gives them distinct
                    // C symbols (file-discriminator), so no link collision; the
                    // first-registered overload is kept for type-checking.
                    if fd.receiver.is_none() && is_file_priv_dedup(&key) {
                        continue;
                    }
                    let is_method = fd.receiver.is_some();
                    let recv_user_local = fd.receiver.as_ref()
                        .map(|r| user_declared_types.contains(&r.type_name))
                        .unwrap_or(false);
                    match classify_dup(&key) {
                        Some(_) if is_method && !recv_user_local => {
                            errors.push(Diagnostic::new(
                                format!(
                                    "[E_METHOD_REDEFINITION] метод `{}` уже определён \
                                     (std/prelude или импортированный модуль); \
                                     переопределение с той же сигнатурой молча игнорируется \
                                     кодогеном (выигрывает существующее определение, тело \
                                     не вызывается). Используй extension-метод с ДРУГИМ именем \
                                     или overload с отличающейся сигнатурой (D84); для смены \
                                     поведения типа — newtype + own-method.",
                                    key
                                ),
                                fd.span,
                            ));
                            continue;
                        }
                        Some(true) => {
                            // Plan 62.F.bis Ф.2: silent user-wins; structured
                            // W_PRELUDE_SHADOW warning эмитится через
                            // `lints::lint_prelude_shadow`. (free-fn/type/const)
                            if let Some(pos) = dup_pos {
                                entry[pos] = fd.clone();
                            }
                            continue;
                        }
                        Some(false) => {
                            // Codegen-only merge — silent shadow. (free-fn/type/const)
                            if let Some(pos) = dup_pos {
                                entry[pos] = fd.clone();
                            }
                            continue;
                        }
                        None => {
                            errors.push(Diagnostic::new(
                                format!(
                                    "duplicate definition `{}` with same signature \
                                     (overload requires distinct param types, arity, или return type — \
                                     см. D84); previous definition has identical params and return type",
                                    key
                                ),
                                fd.span,
                            ));
                        }
                    }
                } else {
                    entry.push(fd.clone());
                }
            }
            Item::Const(cd) => {
                if !names.insert(cd.name.clone()) {
                    // Plan 170 (D307): file-private dedup — two `priv(file)`
                    // consts with the same name in different peer files are NOT
                    // a conflict (disjoint file-scopes). Keep first registered.
                    if is_file_priv_dedup(&cd.name) {
                        continue;
                    }
                    // Plan 62.D bis-1: same prelude-shadow rule as for types.
                    match classify_dup(&cd.name) {
                        Some(true) => {
                            // Plan 62.F.bis Ф.2: silent user-wins; structured
                            // W_PRELUDE_SHADOW warning эмитится через
                            // `lints::lint_prelude_shadow`.
                            env.consts.insert(cd.name.clone(), cd.clone());
                            continue;
                        }
                        Some(false) => {
                            env.consts.insert(cd.name.clone(), cd.clone());
                            continue;
                        }
                        None => {
                            errors.push(Diagnostic::new(
                                format!("duplicate top-level name `{}`", cd.name),
                                cd.span,
                            ));
                        }
                    }
                }
                env.consts.insert(cd.name.clone(), cd.clone());
            }
            Item::Let(ld) => {
                // Plan 152.4 (D199 ro-runtime side): a module-level `ro NAME = EXPR`
                // is a lazy-static global. The strict const/ro partition
                // (`check_ro_module_partition`) forces a constexpr-eligible RHS to
                // `const`; a genuinely runtime RHS (call/effect/alloc) stays `ro`
                // and reaches here. Register it like a const so USES resolve with
                // the right type (incl. method receivers, e.g. `tbl.get(k)`). The
                // constexpr-check pass iterates only `Item::Const`, so a runtime
                // RHS registered here is not rejected. Single named binding only
                // (Ident / single-segment unit Variant for UPPER_CASE), non-ghost.
                if !ld.is_ghost {
                    let name = match &ld.pattern {
                        crate::ast::Pattern::Ident { name, .. } => Some(name.clone()),
                        crate::ast::Pattern::Variant {
                            path,
                            kind: crate::ast::VariantPatternKind::Unit,
                            ..
                        } if path.len() == 1 => Some(path[0].clone()),
                        _ => None,
                    };
                    if let Some(name) = name {
                        names.insert(name.clone());
                        env.consts.insert(
                            name.clone(),
                            crate::ast::ConstDecl {
                                doc: None,
                                doc_attrs: Vec::new(),
                                is_export: false,
                                name,
                                ty: ld.ty.clone(),
                                value: ld.value.clone(),
                                span: ld.span,
                                file_private: false,
                            },
                        );
                    }
                }
            }
            Item::Test(_) | Item::Bench(_) | Item::Lemma(_) => {
                // test/bench — регистрируются отдельно (имя — string-literal, не
                // идентификатор), конфликта по имени быть не может.
                // Ф.4.1: lemma — ghost, только для proof; не регистрируется в env.
            }
        }
    }

    // (typeref_equal — helper для D84 duplicate-signature detection,
    // определён в конце файла.)

    // Plan 15 (D72): generic bounds enforcement.
    //
    // Собираем protocol_specs (методы каждого protocol-типа) и
    // method_table (методы каждого concrete-типа). Затем ходим по
    // всем call-сайтам в bodies, для generic-вызовов с bounds
    // проверяем satisfaction concrete-аргументов.
    // Plan 101.4 (D145 Ред. 5): protocol-composition validation —
    // embed target существует и есть protocol; нет cycle; нет duplicate
    // signature collision при flatten'е. Запускается ДО BoundCtx::build
    // чтобы errors на cycle не превращались в infinite recursion внутри
    // flatten_dfs (хотя у flatten_dfs есть `seen`-guard — safety belt).
    check_protocol_embeds(module, sig_table, &mut errors);

    // Plan 101.3 (D145 Ред. 5): generic-bound declaration validation —
    // каждое имя bound'а в `[T A + B]` должно быть объявленным protocol'ом
    // (или well-known stdlib alias типа Hashable/Eq/Ord/Display). Раньше
    // bound-resolve был permissive (silent skip unknown) — Plan 101 делает
    // strict. Pre-Plan 101 tests, ссылающиеся на неизвестные bound'ы,
    // должны их объявить или удалить.
    check_generic_bound_declarations(module, sig_table, &mut errors);

    // Plan 172.1 U.2.3.2: ONE base signature registry, built once and shared by
    // BoundCtx / CapabilityCtx (and TypeCheckCtx, U.2.3.3) — replaces the three
    // duplicated `fn_decls`/`method_table` build loops (§0 single source). BASE
    // ONLY: synthesized auto-derive methods are a TypeCheckCtx-private overlay (F2),
    // so this shared registry is byte-identical to what Bound/Cap built themselves.
    let sig = crate::sig_registry::SigRegistry::build_base(module);

    let bound_ctx = BoundCtx::build(module, &sig);
    bound_ctx.check_module(module, &mut errors);

    // Plan 16 (D63 forbid + D64 realtime): capability enforcement.
    //
    // Walk fn bodies + tests, отслеживая forbidden-effects стек +
    // realtime-флаг. На каждом Call-сайте — проверка intersect'а
    // callee.effects с forbidden-set; в realtime — Net/Fs/Db/Time
    // suspend-effects запрещены; в `realtime nogc` — alloc-fn'ы
    // запрещены. Установка handler'а для forbidden-эффекта внутри
    // forbid-блока — error.
    let cap_ctx = CapabilityCtx::build(module, &sig);
    cap_ctx.check_module(module, &mut errors);

    // D90 Plan 20 Ф.3: defer/errdefer body constraints.
    //
    // Body запрещает:
    //  - exit-control (return/throw/break/continue) — нельзя hijack
    //    exit семантику scope'а.
    //  - Fail-эффект (?/!!/throw) — double-throw невозможно сделать
    //    корректно. throw обнаруживается через AST-walk; ?/!! — в codegen
    //    они desugar'ятся в throw, поэтому достаточно catch throw.
    //  - suspend-операции (Net.*, Fs.*, Db.*, Time.sleep, parallel for,
    //    spawn, supervised, select) — defer должен быть быстрым cleanup.
    //
    // Walks по всем bodies всех функций. Spec — D90.
    check_defer_bodies(module, &mut errors);

    // D61 §1430-1434 / D90 Ф.8 (1): handler-method для эффект-операции
    // с return type `never` ОБЯЗАН закончиться exit-control'ом
    // (`interrupt v` или `throw err` / `panic` / `exit`). Рначе нет
    // значения типа never для возврата — handler не может законно
    // завершиться normally.
    //
    // Применяется к: Fail.fail (built-in, return never), любым
    // user-defined effect-operations с return type never.
    //
    // Walks все handler-литералы в module, проверяет для каждого
    // method'а, является ли соответствующая operation never-возврат-
    // ной, и если да — body должен diverge (static analysis).
    check_handler_never_ops(module, &mut errors);

    // Plan 77 (D132): `-> @` fluent-return — тело метода обязано
    // вернуть `@`. Делает гарантию проверяемой для consume-checker.
    check_fluent_return(module, &mut errors);

    // Plan 128 Ф.3: `fn <primitive> mut @method(...)` — E_PRIMITIVE_MUT_METHOD.
    // Primitive types (int/str/bool/f64/...) — immutable by design
    // (Plan 91 §«Nova-first»: scalars copy-by-value, no in-place
    // mutation through receiver). Plan 134: ptr removed; *() = TypeRef::Pointer. Parser permits the form syntactically but
    // codegen silently no-ops the mutation — caller sees no change. This
    // pass rejects such declarations at type-check time so the misleading
    // pattern fails fast.
    check_primitive_mut_method(module, &mut errors);

    // Plan 73 (D131): consume-qualifier flow-sensitive check. Use-after-
    // consume и maybe-consumed (consume на части веток) → compile error.
    check_consume(module, &mut errors);

    // Plan 127 Ф.4 (D228 amend): E_VALUE_RECORD_ESCAPE_AFTER_CONSUME —
    // hard error для `&v` после consume value-record local. Detects
    // syntactic pattern: a `consume v = ...` LetDecl (or method-call
    // consume of binding) followed by `&v` usage в той же fn-scope. More
    // specific message than generic D131 use-after-consume — helps user
    // понять value-record semantics.
    check_value_record_escape_after_consume(module, &mut errors);

    // Plan 91.10 (D163 retracted, 2026-05-30): check_external_fn_needs_caps
    // удалён. Capability tracking via отдельный syntax — redundant с effect
    // system. См. docs/plans/91.10-d163-retract-capability-syntax.md.

    // Plan 33.3 Ф.9 (D24): validate axiom-bodies в effect-блоках.
    // Каждый axiom должен ссылаться только на binders + pure_view-ops
    // **того же эффекта** + литералы + boolean/arith operators. Любой
    // другой identifier (включая non-pure_view ops) → error. Это
    // фундамент SMT encoding (UF mapping в Ф.9.4).
    check_effect_axioms(module, &mut errors);

    // Plan 33.3 Ф.9.6: handler verification gate.
    // Если эффект имеет pure_view-ops, любая `with E = handler` для
    // этого эффекта обязана быть помечена `#verify_handler` или
    // `#trusted_handler`. Без атрибута — compile error.
    check_handler_verification_gate(module, &mut errors);

    // Name-resolution фаза: статический поиск undefined идентификаторов
    // в expr-position. Запускается ПОСЛЕ BoundCtx/CapabilityCtx, чтобы
    // более фундаментальные ошибки (signatures/effects) приходили первыми.
    //
    // Без этой фазы код вроде `let r = 1 | undefined_var` проходил
    // typecheck и падал только на cc-этапе с малочитаемой ошибкой
    // "необъявленный идентификатор". См. NameResCtx ниже.
    let name_res = NameResCtx::build(module);
    name_res.check_module(module, &mut errors);

    // Plan 33.1 Ф.2 (D24): contract checking + purity inference.
    // Минимальный pass: проверка базовых правил для контрактов:
    // - `result` запрещён в `requires`;
    // - `old(...)` запрещён в `requires`;
    // - composition (вызов другой fn в контракте) запрещён в 33.1
    //   (будет разрешён для #pure в 33.2).
    let contract_ctx = ContractCtx::build(module);
    contract_ctx.check_module(module, &mut errors);

    // Plan 33.3 Ф.9.7 (D24): ghost-var usage check.
    // Non-ghost код не может читать ghost-var (Verus/Dafny semantics).
    // До этого: catch'илось на C-level через «undeclared identifier»;
    // теперь — proper compile-error с понятным сообщением.
    check_ghost_usage(module, &mut errors);

    // Plan 52 Ф.2 (D108): map-литерал `[k: v]` type-checking.
    //
    // Focused expected-type проход: обходит fn-bodies/tests/consts,
    // протаскивая ожидаемый тип в let-аннотацию / return / argument-
    // позицию. На каждом `MapLit` — вывод `HashMap[K, V]` из ключей/
    // значений (или из ожидаемого типа), enforce `K: Hashable`,
    // унификация ключей и значений. Пустой `[]` в позиции, ожидающей
    // `HashMap` — валиден; неоднозначный `[]` без типа — error.
    // Не заменяет существующие walk'и — отдельный проход (как
    // NameResCtx / ContractCtx), минимум регрессий.
    let map_lit_ctx = MapLitCtx::build(module);
    map_lit_ctx.check_module(module, &mut errors);

    // Plan 79: type-checker hardening — «no silent fallback» на уровне
    // типов. Отдельный проход (паттерн NameResCtx / MapLitCtx): доводит
    // type-checker до типовой полноты. Ф.2 — арность type-аргументов.
    // Plan 126.2 Ф.1: arena for synthesized auto-derive FnDecls. Created here
    // (in the caller) so it outlives `TypeCheckCtx`, allowing synthesized
    // methods to be registered in `method_table` as `&'a FnDecl`.
    let synth_arena = FnDeclArena::new();
    // Plan 162.1 Step 3: when a sig_table is available, use
    // build_with_sig_table so that is_known_type / is_known_fn
    // can consult cross-module signatures during type-checking.
    let type_check_ctx = match sig_table {
        Some(st) => TypeCheckCtx::build_with_sig_table(module, &synth_arena, st.clone(), &sig),
        None => TypeCheckCtx::build(module, &synth_arena, &sig),
    };
    type_check_ctx.check_module(module, &mut errors);

    // **Plan 118.5 V3 Ф.2 / D216 V3 §V3.1 (2026-06-04):** ro+mut conflict
    // check (storage-class-aware). Walks all param types, return types,
    // and field types для each Fn/TypeDecl item; emits
    // E_MUTABILITY_CONFLICT_VALUE_TYPE для value-T cases.
    //
    // Reuses TypeCheckCtx's `types` registry для storage-class detection.
    for item in &module.items {
        match item {
            Item::Fn(fd) => {
                for p in &fd.params {
                    check_v3_ro_mut_conflict(
                        &p.ty, &type_check_ctx.types, true, &mut errors);
                }
                if let Some(rt) = &fd.return_type {
                    check_v3_ro_mut_conflict(
                        rt, &type_check_ctx.types, true, &mut errors);
                }
            }
            Item::Type(td) => {
                if let crate::ast::TypeDeclKind::Record(fields) = &td.kind {
                    for f in fields {
                        check_v3_ro_mut_conflict(
                            &f.ty, &type_check_ctx.types, true, &mut errors);
                    }
                }
                if let crate::ast::TypeDeclKind::NamedTuple(fields) = &td.kind {
                    for f in fields {
                        check_v3_ro_mut_conflict(
                            &f.ty, &type_check_ctx.types, true, &mut errors);
                    }
                }
            }
            _ => {}
        }
    }

    // Plan 114.4.2 (D199) Ф.1 const fn body check pass.
    // 1) Collect const fn names. 2) Validate each const fn body против
    // V1 whitelist (literals/arithmetic/casts/refs to params/locals/const
    // fn calls). 3) Build call-graph and detect cycles (mutual recursion).
    {
        use std::collections::{HashMap as Map, HashSet as Set};
        // Plan 114.4.3 Ф.3 (V2 mixed-args): два set'а —
        //  * const_fn_names: ВСЕ fn с const-surface (any const param OR const
        //    return) — для call-site arg validation. Includes mixed fns.
        //  * fully_const_fn_names: ВСЕ params const AND return const —
        //    evaluator-inlined + dropped из codegen. V2 body whitelist
        //    applied только к этим (mixed fns — runtime body, normal rules).
        let mut const_fn_names: Set<String> = Set::new();
        let mut fully_const_fn_names: Set<String> = Set::new();
        let mut fully_const_fns: Vec<&FnDecl> = Vec::new();
        for item in &module.items {
            if let Item::Fn(fd) = item {
                let any_const = fd.return_is_const || fd.params.iter().any(|p| p.is_const);
                let all_const_params = !fd.params.is_empty()
                    && fd.params.iter().all(|p| p.is_const);
                let is_fully_const = (all_const_params || fd.params.is_empty())
                    && fd.return_is_const;
                if any_const {
                    const_fn_names.insert(fd.name.clone());
                }
                if is_fully_const {
                    fully_const_fn_names.insert(fd.name.clone());
                    fully_const_fns.push(fd);
                }
            }
        }
        let mut call_graph: Map<String, Set<String>> = Map::new();
        for fd in &fully_const_fns {
            let mut targets: Set<String> = Set::new();
            // Body checker against fully-const fn set (для transitivity:
            // fully-const fn calling mixed fn = forbidden, runtime escapes).
            if let Err(d) = check_const_fn_decl(fd, &fully_const_fn_names, &mut targets) {
                errors.push(d);
            }
            call_graph.insert(fd.name.clone(), targets);
        }
        // Cycle detection: DFS с three-color marker (WHITE/GRAY/BLACK).
        // GRAY → ребро в текущий путь → cycle.
        #[derive(Clone, Copy, PartialEq)]
        enum C { White, Gray, Black }
        let mut color: Map<String, C> = Map::new();
        for k in const_fn_names.iter() { color.insert(k.clone(), C::White); }
        fn visit(
            node: &str,
            graph: &Map<String, Set<String>>,
            color: &mut Map<String, C>,
        ) -> Option<Vec<String>> {
            color.insert(node.to_string(), C::Gray);
            if let Some(neigh) = graph.get(node) {
                for n in neigh {
                    match color.get(n).copied().unwrap_or(C::White) {
                        C::Gray => return Some(vec![node.to_string(), n.clone()]),
                        C::White => {
                            if let Some(mut path) = visit(n, graph, color) {
                                path.insert(0, node.to_string());
                                return Some(path);
                            }
                        }
                        C::Black => {}
                    }
                }
            }
            color.insert(node.to_string(), C::Black);
            None
        }
        // Plan 114.4.3 Ф.2 (V2): recursion (direct + mutual) allowed.
        // Cycle detection retained but downgraded — no error fired.
        // Evaluator enforces depth-limit + memoization runtime safety.
        let mut reported: Set<String> = Set::new();
        for fd in &fully_const_fns {
            if matches!(color.get(&fd.name), Some(C::White)) {
                if let Some(cycle) = visit(&fd.name, &call_graph, &mut color) {
                    let key = {
                        let mut v = cycle.clone();
                        v.sort();
                        v.join("→")
                    };
                    // V2: cycle reported only once per cycle (dedup),
                    // no error emitted — evaluator depth-limit enforces.
                    let _ = reported.insert(key);
                    let _ = cycle;
                    if false {
                        errors.push(Diagnostic::new(
                            format!(
                                "[E_CONST_FN_RECURSION] cycle detection: {}",
                                fd.name
                            ),
                            fd.span,
                        ));
                    }
                }
            }
        }
    }

    // Plan 33.1 Ф.3 (D24): SMT verification.
    // TrivialBackend по умолчанию (Z3 — отдельная feature в будущем).
    // Доказанные контракты записываются в env для zero-cost release.
    // `#must_verify` errors / counterexample warnings — попадают в errors.
    if errors.is_empty() {
        // Verify только если предыдущие фазы прошли (иначе encode на
        // невалидном AST может крашнуть).
        let report = crate::verify::verify_module(module);
        env.proven_contracts = report.proven;
        env.proven_index_sites = report.proven_index_sites;
        env.proven_index_sites_contract = report.proven_index_sites_contract;
        env.proven_overflow_sites = report.proven_overflow_sites;
        env.proven_overflow_sites_contract = report.proven_overflow_sites_contract;
        for e in report.errors { errors.push(e); }
        // warnings пока silent — добавим warning infrastructure
        // в Plan 36 production hardening.
        // Note: counterexample-warnings (без #must_verify) бэк-port'ятся
        // в errors временно, чтобы в 33.1 negative-тесты могли их детектить.
        // Это будет уточнено когда добавится warning severity (Plan 36).
        let _ = report.warnings; // intentionally silent
    }

    // Plan 118 D216 §8 (Ф.3.5): enforce E_UNSAFE_REQUIRED — `&value` /
    // `*expr` pointer ops require unsafe context (block.is_unsafe = true
    // OR enclosing #unsafe fn). Walks fn bodies + test bodies, maintains
    // depth counter, emits diagnostic при depth == 0.
    check_unsafe_context_in_module(module, &mut errors);

    if errors.is_empty() {
        Ok(env)
    } else {
        Err(errors)
    }
}

// Plan 162.1 Step 3: public entry-point that feeds a pre-built
// `ModuleSigTable` into the type-checker.  Callers that have already
// run `crate::imports::collect_all_signatures` can pass the resulting
// table here so that cross-module symbol lookups in the type-checker
// use the sig-table instead of only consulting `module.items`.
//
// Concretely, the sig_table suppresses false-positive
// `E_UNKNOWN_PROTOCOL` / `E_PROTOCOL_EMBED_UNKNOWN` / `E_BOUND_UNKNOWN`
// errors when the referenced type is declared in a transitively
// imported module that has been captured in the signature pre-pass
// but whose items may not yet be inline-merged into `module.items`
// (the lazy-resolution scenario described in Plan 162.1 Step 3).
//
// The existing `check_module` is kept as the zero-arg entry-point
// (backward-compatible); it uses an empty sig_table so that all
// existing checks fire normally.
pub fn check_module_with_sig_table(
    module: &Module,
    sig_table: crate::imports::ModuleSigTable,
) -> Result<ModuleEnv, Vec<Diagnostic>> {
    check_module_impl(module, Some(&sig_table))
}

// ─── internal shared core ────────────────────────────────────────────────────

// ============================================================================
// Plan 79: type-checker hardening — «no silent fallback» на уровне типов.
//
// Type-checker bootstrap'а проверяет имена/структуру/эффекты/контракты, но НЕ
// базовую совместимость типов. Plan 79 доводит его до типовой полноты: каждое
// использование типа проверяется, несовместимость → compile-error (серия
// E73xx) вместо silent miscompilation или поздней CC-FAIL.
//
//   Ф.2 — арность type-аргументов (`Result[int]` → E7310).   [реализовано]
//   Ф.1 — assignability arg↔param и annotation↔RHS.          [pending]
//   Ф.3 — существование поля / варианта.                      [pending]
//   Ф.4 — type-vs-value.                                      [pending]
//
// Отдельный проход `TypeCheckCtx` (паттерн NameResCtx / ContractCtx /
// MapLitCtx) — растёт по фазам, минимум регрессий к существующим walk'ам.
// ============================================================================

/// Объявленная арность generic-типа.
struct ArityInfo {
    /// Число объявленных generic-параметров.
    count: usize,
    /// Span объявления `type` — для note «declared here». `None` у
    /// built-in типов (Option/Result/примитивы), чьё объявление не
    /// находится в текущем модуле.
    decl_span: Option<Span>,
}

/// Plan 114.4 Ф.1: constexpr-eligibility check для `const X = expr`.
///
/// Проверяет рекурсивно что RHS — literal-eligible: literals + арифметика
/// над constexpr operands + record/tuple/array literals из constexpr-полей +
/// references на другие top-level `const`.
///
/// Возвращает `Err(Diagnostic)` если non-constexpr:
/// - `E_CONST_NOT_CONSTEXPR` — generic non-constexpr expr.
/// - `E_CONST_REFERS_NON_CONSTEXPR` — Ident на non-const binding.
/// - `E_CONST_EFFECT_IN_INIT` — runtime call / effect / allocation.
///
/// `known_consts` — set имен top-level `const` (для Ident-резолва).
fn check_const_constexpr(
    expr: &crate::ast::Expr,
    known_consts: &HashSet<String>,
) -> Result<(), Diagnostic> {
    let empty: HashSet<String> = HashSet::new();
    check_const_constexpr_ex(expr, known_consts, &empty, &empty)
}

/// Plan 114.4.2 (D199): extended constexpr validator с awareness of
/// const fn names. Used by check_module's scope-local const validation
/// + module-level const validation when const fn registry уже built.
/// `const_fn_names` — set of all const fn names в module (если empty —
/// backward-compatible с original check_const_constexpr behavior).
/// `named_tuple_names` — set of named tuple type names; their constructors
/// are constexpr (D215 amend: pure value construction, no side effects).
fn check_const_constexpr_ex(
    expr: &crate::ast::Expr,
    known_consts: &HashSet<String>,
    const_fn_names: &HashSet<String>,
    named_tuple_names: &HashSet<String>,
) -> Result<(), Diagnostic> {
    use crate::ast::ExprKind as E;
    match &expr.kind {
        // Literals — всегда constexpr.
        E::IntLit(_) | E::FloatLit(_) | E::StrLit(_) | E::BoolLit(_)
        | E::CharLit(_) | E::UnitLit => Ok(()),
        // Unary над constexpr operand.
        E::Unary { operand, .. } => check_const_constexpr_ex(operand, known_consts, const_fn_names, named_tuple_names),
        // Binary над constexpr operands.
        E::Binary { left, right, .. } => {
            check_const_constexpr_ex(left, known_consts, const_fn_names, named_tuple_names)?;
            check_const_constexpr_ex(right, known_consts, const_fn_names, named_tuple_names)
        }
        // Plan 114.4.2 D199: `as`-cast — constexpr if inner is constexpr.
        E::As(inner, _) => check_const_constexpr_ex(inner, known_consts, const_fn_names, named_tuple_names),
        // Tuple-литерал — каждый элемент constexpr.
        E::TupleLit(elems) => {
            for e in elems {
                check_const_constexpr_ex(e, known_consts, const_fn_names, named_tuple_names)?;
            }
            Ok(())
        }
        // Array-литерал (без spread) — каждый элемент constexpr.
        E::ArrayLit(elems) => {
            for el in elems {
                match el {
                    crate::ast::ArrayElem::Item(e) => check_const_constexpr_ex(e, known_consts, const_fn_names, named_tuple_names)?,
                    crate::ast::ArrayElem::Spread(_) => {
                        return Err(Diagnostic::new(
                            "[E_CONST_NOT_CONSTEXPR] spread `...` not allowed \
                             в const initialiser — runtime operation. Inline \
                             literals или use `ro X = …` for runtime value \
                             (Plan 114.4 Ф.1 D199).".to_string(),
                            expr.span,
                        ));
                    }
                }
            }
            Ok(())
        }
        // Record-литерал — каждое поле constexpr.
        E::RecordLit { fields, .. } => {
            for f in fields {
                if f.is_spread {
                    return Err(Diagnostic::new(
                        "[E_CONST_NOT_CONSTEXPR] spread `...` not allowed в \
                         const-record initialiser (Plan 114.4 Ф.1).".to_string(),
                        expr.span,
                    ));
                }
                match &f.value {
                    Some(v) => check_const_constexpr_ex(v, known_consts, const_fn_names, named_tuple_names)?,
                    None => {
                        // Shorthand `{ name }` — refers binding called `name`.
                        if !known_consts.contains(&f.name) {
                            return Err(Diagnostic::new(
                                format!(
                                    "[E_CONST_REFERS_NON_CONSTEXPR] field shorthand `{}` \
                                     в const-record refers binding which is not a \
                                     top-level const. Use explicit `{}: <literal>` либо \
                                     declare referenced `const {}` (Plan 114.4 Ф.1).",
                                    f.name, f.name, f.name
                                ),
                                expr.span,
                            ));
                        }
                    }
                }
            }
            Ok(())
        }
        // Ident — должен ссылаться на другой known top-level `const`
        // ИЛИ const fn (Plan 114.4.3 Ф.5 V2: first-class alias).
        E::Ident(name) => {
            if known_consts.contains(name) || const_fn_names.contains(name) {
                Ok(())
            } else {
                Err(Diagnostic::new(
                    format!(
                        "[E_CONST_REFERS_NON_CONSTEXPR] `const` initialiser \
                         refers `{}` which is not a top-level `const` or `const fn`. \
                         Only literals + arithmetic on literals + record/tuple/array \
                         literals из constexpr fields + references to other \
                         `const` / `const fn` are allowed. For runtime / lazy-init \
                         use `ro {} = …` (Plan 114.4 Ф.1 / D199).",
                        name, name
                    ),
                    expr.span,
                ))
            }
        }
        // Path (e.g. `Module.NAME` cross-module const, или `LOCAL.field`
        // member-access на local-const). V1 conservative: запрещаем все
        // Path формы в const-RHS (cross-module — followup
        // [M-114.4-cross-module-const-ref]; field-access на local-const —
        // runtime-only, эквивалент `ro X = LOCAL.field`).
        E::Path(_) => Err(Diagnostic::new(
            "[E_CONST_NOT_CONSTEXPR] path expression (Module.NAME / Type.field) \
             not allowed в `const` initialiser в V1. Cross-module const refs — \
             followup [M-114.4-cross-module-const-ref]. Field access на local \
             const → use `ro X = …` (runtime ok) (Plan 114.4 Ф.1).".to_string(),
            expr.span,
        )),
        // Plan 114.4.2 D199 / Plan 114.4.3 Ф.4 V2: Call к const fn — constexpr,
        // если callee = Ident (или TurboFish<Ident, ...> для generic const fn)
        // и зарегистрирован как const fn, и каждый arg constexpr.
        // D215 amend: named tuple constructors `T(...)` are also constexpr
        // (pure value construction, no side effects — same as record literals).
        E::Call { func, args, trailing: None } => {
            // Unwrap TurboFish to get underlying Ident name (generic const fn).
            let callee_name_opt: Option<&String> = match &func.kind {
                E::Ident(n) => Some(n),
                E::TurboFish { base, .. } => match &base.kind {
                    E::Ident(n) => Some(n),
                    _ => None,
                },
                _ => None,
            };
            if let Some(name) = callee_name_opt {
                // Plan 114.4.4 Ф.5 V4: size_of/align_of intrinsics accepted
                // на module-level const RHS (`const SIZE = size_of[int]()`).
                if name == "size_of" || name == "align_of" {
                    return Ok(());
                }
                // D215 amend: named tuple constructor — each arg must be constexpr.
                if named_tuple_names.contains(name) {
                    for a in args {
                        let arg_expr = match a {
                            crate::ast::CallArg::Item(e) => e,
                            crate::ast::CallArg::Named { value, .. } => value,
                            crate::ast::CallArg::Spread(e) => e,
                        };
                        check_const_constexpr_ex(arg_expr, known_consts, const_fn_names, named_tuple_names)?;
                    }
                    return Ok(());
                }
                if const_fn_names.contains(name) {
                    for a in args {
                        match a {
                            crate::ast::CallArg::Item(e) => {
                                // Arg recursion должен пройти как constexpr;
                                // если нет — переэмитим с E_CONST_FN_NON_CONST_ARG
                                // (per-D199 более информативный код для caller'а).
                                if let Err(_inner) = check_const_constexpr_ex(
                                    e, known_consts, const_fn_names, named_tuple_names,
                                ) {
                                    return Err(Diagnostic::new(
                                        format!(
                                            "[E_CONST_FN_NON_CONST_ARG] call to \
                                             const fn `{}` has non-constexpr \
                                             argument — all args must be literals, \
                                             arithmetic on literals, references to \
                                             top-level const, or other const fn \
                                             calls with constexpr args (D199).",
                                            name
                                        ),
                                        e.span,
                                    ));
                                }
                            }
                            _ => {
                                return Err(Diagnostic::new(
                                    "[E_CONST_FN_NON_CONST_ARG] only positional \
                                     constexpr args allowed when calling const fn \
                                     в const initialiser (D199).".to_string(),
                                    expr.span,
                                ));
                            }
                        }
                    }
                    return Ok(());
                }
            }
            Err(Diagnostic::new(
                "[E_CONST_NOT_CONSTEXPR] non-const-fn call в `const` initialiser \
                 — only literals, arithmetic, `as`-casts, record/tuple/array \
                 literals, named-tuple constructors, references to top-level consts, \
                 и calls to other `const fn` are allowed. Use `ro X = …` для \
                 runtime / lazy-init, либо declare `fn ... const param ... -> const T` \
                 (D199).".to_string(),
                expr.span,
            ))
        }
        // Member access / Index / InterpolatedStr / MapLit / call с trailing —
        // runtime.
        E::Call { .. } | E::Member { .. } | E::Index { .. }
        | E::InterpolatedStr { .. } | E::MapLit { .. } => Err(Diagnostic::new(
            "[E_CONST_NOT_CONSTEXPR] non-constexpr expression в `const` \
             initialiser (member/index/interpolation/map/call-with-trailing). \
             Use `ro X = …` для runtime / lazy-init value (D199).".to_string(),
            expr.span,
        )),
        // Любые другие конструкции (if, match, blocks, closures, etc.) — runtime.
        _ => Err(Diagnostic::new(
            "[E_CONST_NOT_CONSTEXPR] non-constexpr expression в `const` \
             initialiser (control flow / closures / blocks not allowed). \
             Use `ro X = …` для runtime / lazy-init value (Plan 114.4 Ф.1).".to_string(),
            expr.span,
        )),
    }
}

/// Plan 148 Ф.3 ([M-114.4-strict-partition]): forward direction of the
/// strict module-level `const`/`ro` partition (spec D199 / 03-syntax
/// «Strict module-level partition»).
///
/// `E_CONST_NOT_CONSTEXPR` (reverse direction) already rejects a module-level
/// `const X = …` whose RHS is *not* constexpr-eligible. This helper is the
/// forward direction: a module-level `ro X = …` whose RHS *is* fully
/// constexpr-eligible must instead be declared `const` — the keyword is not
/// a user choice, it follows the RHS. Such a binding is flagged with
/// `E_RO_FOR_CONSTEXPR_PREFER_CONST`.
///
/// Scope is deliberately narrow — this matches the spec, which restricts the
/// strict partition to **module-level** bindings only (scope-local `ro x = 5`
/// and `const x = 5` are both valid, with different guarantees):
///   - Only module-level `Item::Let` (which, post-D184, can only originate
///     from the `ro` keyword — `let`/`mut`/`consume` are rejected at module
///     level by the parser).
///   - Only a single named binding (`Pattern::Ident`, or — for the usual
///     UPPER_CASE constant name — a single-segment unit `Pattern::Variant`,
///     see the NB in the body); `const` has no destructuring form, so
///     `ro (a, b) = …` is never convertible and is left alone.
///   - `ghost` bindings are spec-only and never emitted — left alone.
///   - The RHS must be *fully* constexpr-eligible per the very same
///     `check_const_constexpr_ex` predicate that drives `E_CONST_NOT_CONSTEXPR`,
///     so the two directions can never disagree about what «constexpr» means.
///
/// Returns `Some(diagnostic)` when the binding should be `const`, else `None`.
fn check_ro_module_partition(
    decl: &crate::ast::LetDecl,
    known_consts: &HashSet<String>,
    const_fn_names: &HashSet<String>,
    named_tuple_names: &HashSet<String>,
) -> Option<Diagnostic> {
    // `ghost ro X = …` — spec-only binding, not subject to the partition.
    if decl.is_ghost {
        return None;
    }
    // `const` only supports a single named binding; non-binding patterns
    // (tuple / record / wildcard / multi-segment or sub-pattern variant) have
    // no `const` equivalent → leave alone.
    //
    // NB: a module-level constant is conventionally UPPER_CASE / PascalCase, so
    // `ro MAX = …` parses its binder as `Pattern::Variant { path: ["MAX"],
    // kind: Unit }` (the parser cannot tell a fresh binder from a unit-variant
    // match at parse time). A *single-segment unit* variant pattern in binding
    // position is always a fresh name (there is nothing to match against in a
    // `ro X = …` declaration), so it is the UPPER_CASE binding form. A
    // multi-segment path (`Mod.Variant`) or a variant with sub-patterns is a
    // genuine destructuring pattern, which has no `const` equivalent.
    let name = match &decl.pattern {
        crate::ast::Pattern::Ident { name, .. } => name.as_str(),
        crate::ast::Pattern::Variant {
            path,
            kind: crate::ast::VariantPatternKind::Unit,
            ..
        } if path.len() == 1 => path[0].as_str(),
        _ => return None,
    };
    // Fire only when the RHS is *fully* constexpr-eligible (same predicate
    // as `E_CONST_NOT_CONSTEXPR`). A runtime call / effect / allocation /
    // reference to another `ro` makes the binding genuinely runtime → `ro`
    // is correct and we stay silent.
    if check_const_constexpr_ex(&decl.value, known_consts, const_fn_names, named_tuple_names).is_err() {
        return None;
    }
    Some(Diagnostic::new(
        format!(
            "[E_RO_FOR_CONSTEXPR_PREFER_CONST] module-level `ro {name} = …` has a \
             constexpr-eligible initialiser (literal / arithmetic on literals / \
             record/tuple/array literal of constexpr fields / reference to another \
             `const` / `const fn` call). The module-level `const`/`ro` partition is \
             strict: a constexpr-eligible RHS must be declared `const {name} = …`, \
             not `ro {name} = …`. Use `const` here, or keep `ro` only for a runtime \
             value (Plan 114.4 / D199, spec 03-syntax «Strict module-level partition»). \
             Scope-local `ro`/`const` are both fine — this rule applies at module level."
        ),
        decl.span,
    ))
}

/// Plan 114.4.2 (D199) Ф.1 body checker: validate const fn body against
/// V1 whitelist (literals + arithmetic + as-cast + ident refs to const
/// params/locals + local const + final expr + calls to other const fn).
///
/// Returns Err on first violation with appropriate error code.
/// `param_consts` — set of const param names visible в body.
/// `const_fn_names` — set of all const fn names (для call validation).
/// `local_consts` — mutable set extended при встрече Stmt::Const.
/// `current_fn` — for self-recursion detection.
/// `call_targets` — mutable set — populated с именами callee const fn
/// (для post-pass cycle detection).
fn check_const_fn_expr(
    expr: &crate::ast::Expr,
    param_consts: &std::collections::HashSet<String>,
    const_fn_names: &std::collections::HashSet<String>,
    local_consts: &std::collections::HashSet<String>,
    current_fn: &str,
    call_targets: &mut std::collections::HashSet<String>,
) -> Result<(), Diagnostic> {
    use crate::ast::ExprKind as E;
    match &expr.kind {
        E::IntLit(_) | E::FloatLit(_) | E::StrLit(_) | E::BoolLit(_)
        | E::CharLit(_) | E::UnitLit => Ok(()),
        E::Unary { operand, .. } => check_const_fn_expr(
            operand, param_consts, const_fn_names, local_consts, current_fn, call_targets,
        ),
        E::Binary { left, right, .. } => {
            check_const_fn_expr(left, param_consts, const_fn_names, local_consts, current_fn, call_targets)?;
            check_const_fn_expr(right, param_consts, const_fn_names, local_consts, current_fn, call_targets)
        }
        E::As(inner, _) => check_const_fn_expr(
            inner, param_consts, const_fn_names, local_consts, current_fn, call_targets,
        ),
        // Plan 114.4.4 Ф.3 V3: Range expr — recurse on start/end.
        E::Range { start, end, .. } => {
            if let Some(s) = start {
                check_const_fn_expr(s, param_consts, const_fn_names, local_consts, current_fn, call_targets)?;
            }
            if let Some(e) = end {
                check_const_fn_expr(e, param_consts, const_fn_names, local_consts, current_fn, call_targets)?;
            }
            Ok(())
        }
        E::Ident(name) => {
            if param_consts.contains(name) || local_consts.contains(name) {
                Ok(())
            } else if const_fn_names.contains(name) {
                Err(Diagnostic::new(
                    format!(
                        "[E_CONST_FN_FIRST_CLASS] const fn `{}` used as first-class \
                         value в body — not supported в V1 (D199). Followup \
                         `[M-114.4.2-first-class]`. Direct call `{}(arg)` instead.",
                        name, name
                    ),
                    expr.span,
                ))
            } else {
                Err(Diagnostic::new(
                    format!(
                        "[E_CONST_FN_REF_NON_CONST] const fn body refers `{}` which \
                         is not a const param, local const, or const fn (D199). \
                         Only const params/locals/literals allowed в const fn V1 body.",
                        name
                    ),
                    expr.span,
                ))
            }
        }
        E::Call { func, args, trailing } => {
            if trailing.is_some() {
                return Err(Diagnostic::new(
                    "[E_CONST_FN_CONTROL_FLOW] trailing-block calls (DSL syntax) \
                     not allowed в const fn body (D199): require runtime closure / \
                     control-flow. Use const-eligible call syntax."
                        .to_string(),
                    expr.span,
                ));
            }
            // Callee должен быть Ident (или TurboFish<Ident> для generic
            // const fn / size_of/align_of intrinsics).
            let callee_name = match &func.kind {
                E::Ident(n) => n.clone(),
                E::TurboFish { base, .. } => match &base.kind {
                    E::Ident(n) => n.clone(),
                    _ => {
                        return Err(Diagnostic::new(
                            "[E_CONST_FN_EFFECT_IN_BODY] non-ident turbofish base \
                             (D199).".to_string(),
                            expr.span,
                        ));
                    }
                }
                _ => {
                    return Err(Diagnostic::new(
                        "[E_CONST_FN_EFFECT_IN_BODY] indirect / method / path calls \
                         not allowed в const fn body (D199). Use direct const fn \
                         call by name."
                            .to_string(),
                        expr.span,
                    ));
                }
            };
            // Plan 114.4.4 Ф.4 V4: variant constructor heuristic —
            // Call(Ident(Name), args) где Name начинается с uppercase
            // letter и НЕ const fn — treat as variant constructor
            // (e.g. `Some(5)`, `Ok(v)`, `Err(e)`, `Cons(h, t)`).
            let is_variant_constructor = !const_fn_names.contains(&callee_name)
                && callee_name.chars().next().map_or(false, |c| c.is_uppercase());
            // Plan 114.4.4 Ф.5 V4: t-reflection intrinsics — sizeof / align_of.
            // Recognized как built-in const fn без registration.
            let is_t_reflection = callee_name == "size_of" || callee_name == "align_of";
            if !const_fn_names.contains(&callee_name) && !is_variant_constructor && !is_t_reflection {
                return Err(Diagnostic::new(
                    format!(
                        "[E_CONST_FN_EFFECT_IN_BODY] call `{}(...)` from const fn \
                         body — `{}` is not a `const fn` или variant constructor \
                         (D199). Only calls к другим const fn или Variant constructors \
                         (TitleCase names) allowed. Use runtime fn if needed.",
                        callee_name, callee_name
                    ),
                    expr.span,
                ));
            }
            // Plan 114.4.3 Ф.2 (V2): direct self-recursion allowed.
            // Evaluator enforces depth limit + memoization.
            let _self_call = callee_name == current_fn;
            if !is_variant_constructor {
                call_targets.insert(callee_name);
            }
            // Args также constexpr-eligible — recurse.
            for a in args {
                match a {
                    crate::ast::CallArg::Item(e) => check_const_fn_expr(
                        e, param_consts, const_fn_names, local_consts, current_fn, call_targets,
                    )?,
                    crate::ast::CallArg::Spread(_) => {
                        return Err(Diagnostic::new(
                            "[E_CONST_FN_EFFECT_IN_BODY] spread args `...` not allowed \
                             в const fn body (D199): runtime collection operation."
                                .to_string(),
                            expr.span,
                        ));
                    }
                    _ => {
                        return Err(Diagnostic::new(
                            "[E_CONST_FN_EFFECT_IN_BODY] named / non-positional args \
                             not supported в const fn body (D199 V1)."
                                .to_string(),
                            expr.span,
                        ));
                    }
                }
            }
            Ok(())
        }
        // Block expression — recurse через statements.
        E::Block(block) => {
            check_const_fn_block(
                block, param_consts, const_fn_names, local_consts, current_fn, call_targets,
            )
        }
        // Plan 114.4.3 Ф.1 (D199 V2): `if`/`else` allowed — recurse
        // on cond + each branch. Все sub-expressions должны быть constexpr.
        E::If { cond, then, else_ } => {
            check_const_fn_expr(
                cond, param_consts, const_fn_names, local_consts, current_fn, call_targets,
            )?;
            check_const_fn_block(
                then, param_consts, const_fn_names, local_consts, current_fn, call_targets,
            )?;
            if let Some(eb) = else_ {
                match eb {
                    crate::ast::ElseBranch::Block(b) => check_const_fn_block(
                        b, param_consts, const_fn_names, local_consts, current_fn, call_targets,
                    )?,
                    crate::ast::ElseBranch::If(ie) => check_const_fn_expr(
                        ie, param_consts, const_fn_names, local_consts, current_fn, call_targets,
                    )?,
                }
            }
            // Plan 114.4.4 Ф.3 V3: if без else allowed как side-effect
            // statement (для loops с conditional continue/break). Evaluator
            // skips body если cond=false, returns Unit.
            Ok(())
        }
        // Plan 114.4.3 Ф.1 (D199 V2): `match` allowed — recurse on scrutinee +
        // каждый arm body. Pattern V2.0 subset: literal + wildcard + ident bind.
        E::Match { scrutinee, arms } => {
            check_const_fn_expr(
                scrutinee, param_consts, const_fn_names, local_consts, current_fn, call_targets,
            )?;
            for arm in arms {
                check_const_fn_pattern(&arm.pattern, expr.span)?;
                // Plan 114.4.4 Ф.4 V4: bindings из pattern добавляются в
                // arm-local scope для body/guard validation.
                let mut arm_locals = local_consts.clone();
                collect_const_fn_pattern_bindings(&arm.pattern, &mut arm_locals);
                if let Some(g) = &arm.guard {
                    check_const_fn_expr(
                        g, param_consts, const_fn_names, &arm_locals, current_fn, call_targets,
                    )?;
                }
                match &arm.body {
                    crate::ast::MatchArmBody::Expr(e) => check_const_fn_expr(
                        e, param_consts, const_fn_names, &arm_locals, current_fn, call_targets,
                    )?,
                    crate::ast::MatchArmBody::Block(b) => check_const_fn_block(
                        b, param_consts, const_fn_names, &arm_locals, current_fn, call_targets,
                    )?,
                }
            }
            Ok(())
        }
        // IfLet — V2.1 deferred (pattern-bind complexity).
        E::IfLet { .. } => Err(Diagnostic::new(
            "[E_CONST_FN_CONTROL_FLOW] `if let` pattern-bind в const fn body \
             не allowed в V2.0 (D199). Followup `[M-114.4.3-pattern-record-sum]`. \
             Use `if cond { ... } else { ... }` с literal comparison."
                .to_string(),
            expr.span,
        )),
        // Plan 114.4.4 Ф.3 (D199 V3): for/while/loop allowed —
        // evaluator enforces termination через MAX_LOOP_ITERATIONS.
        E::For { pattern, iter, body, .. } => {
            check_const_fn_expr(iter, param_consts, const_fn_names,
                local_consts, current_fn, call_targets)?;
            // Pattern var добавляется в locals для body validation.
            let mut body_locals = local_consts.clone();
            if let crate::ast::Pattern::Ident { name, .. } = pattern {
                body_locals.insert(name.clone());
            }
            check_const_fn_block(body, param_consts, const_fn_names,
                &body_locals, current_fn, call_targets)
        }
        E::While { cond, body, .. } => {
            check_const_fn_expr(cond, param_consts, const_fn_names,
                local_consts, current_fn, call_targets)?;
            check_const_fn_block(body, param_consts, const_fn_names,
                local_consts, current_fn, call_targets)
        }
        E::Loop { body, .. } => check_const_fn_block(body, param_consts,
            const_fn_names, local_consts, current_fn, call_targets),
        // ParallelFor + WhileLet остаются rejected.
        E::ParallelFor { .. } | E::WhileLet { .. } => Err(Diagnostic::new(
            "[E_CONST_FN_CONTROL_FLOW] `parallel for` / `while let` не \
             разрешены в const fn body (D199). Use plain `for`/`while`."
                .to_string(),
            expr.span,
        )),
        // Try/Bang — effect propagation.
        E::Try(_) | E::Bang(_) => Err(Diagnostic::new(
            "[E_CONST_FN_EFFECT_IN_BODY] Try / Bang (?/!!) propagate effects — \
             const fn body должен быть pure (D199)."
                .to_string(),
            expr.span,
        )),
        // Allocations / collection literals.
        E::ArrayLit(_) | E::MapLit { .. } | E::InterpolatedStr { .. } => Err(Diagnostic::new(
            "[E_CONST_FN_ALLOCATION] allocations (arrays/maps/string interp) \
             not allowed в const fn body V1 (D199)."
                .to_string(),
            expr.span,
        )),
        // Plan 114.4.4 Ф.4 V4: tuple literals — recursive sub-validation.
        // ConstValue::Tuple supports structured comptime data.
        E::TupleLit(elems) => {
            for e in elems {
                check_const_fn_expr(
                    e, param_consts, const_fn_names, local_consts, current_fn, call_targets,
                )?;
            }
            Ok(())
        }
        // Plan 114.4.4 Ф.4 V4: record literals — recursive sub-validation
        // на каждое field value. ConstValue::Record supports structured
        // comptime data.
        E::RecordLit { fields, .. } => {
            for f in fields {
                if f.is_spread {
                    return Err(Diagnostic::new(
                        "[E_CONST_FN_ALLOCATION] spread `...` в record literal не \
                         разрешён в const fn body (D199).".to_string(),
                        expr.span,
                    ));
                }
                if let Some(v) = &f.value {
                    check_const_fn_expr(
                        v, param_consts, const_fn_names, local_consts, current_fn, call_targets,
                    )?;
                }
            }
            Ok(())
        }
        // Member/Index/Path — runtime access.
        E::Member { .. } | E::Index { .. } | E::Path(_) | E::TurboFish { .. }
        | E::SelfAccess => Err(Diagnostic::new(
            "[E_CONST_FN_EFFECT_IN_BODY] member/index/path access — runtime \
             operations, not allowed в const fn body V1 (D199)."
                .to_string(),
            expr.span,
        )),
        // Coalesce/Is — runtime checks.
        E::Coalesce(_, _) | E::Is(_, _) => Err(Diagnostic::new(
            "[E_CONST_FN_EFFECT_IN_BODY] coalesce (??) / type-check (is) — \
             runtime semantics, not allowed в const fn body V1 (D199)."
                .to_string(),
            expr.span,
        )),
        // Прочее (closures / lambda / spawn / supervised / handler etc.) — reject.
        _ => Err(Diagnostic::new(
            "[E_CONST_FN_EFFECT_IN_BODY] expression form not allowed в const fn \
             body V1 (closures/spawn/handler/etc) (D199)."
                .to_string(),
            expr.span,
        )),
    }
}

/// Plan 114.4.3 Ф.1 (D199 V2): pattern V2.0 subset для match arm validation.
/// Allowed: literal (Int/Bool/Char/Str/Unit), wildcard (_), single Ident
/// bind (which binds a fresh local — caller responsibility to register).
/// Rejected V2.0: record/sum/tuple destructuring patterns.
fn check_const_fn_pattern(
    pat: &crate::ast::Pattern,
    span: Span,
) -> Result<(), Diagnostic> {
    use crate::ast::{Pattern, VariantPatternKind};
    match pat {
        Pattern::Wildcard(_) => Ok(()),
        Pattern::Ident { is_mut: false, .. } => Ok(()),
        Pattern::Ident { is_mut: true, .. } => Err(Diagnostic::new(
            "[E_CONST_FN_PATTERN_NOT_SUPPORTED] `mut` pattern в const fn match \
             arm not allowed (D199 V4). Remove `mut`."
                .to_string(),
            span,
        )),
        Pattern::Literal(_, _) => Ok(()),
        Pattern::Or { alternatives, .. } => {
            for alt in alternatives {
                check_const_fn_pattern(alt, span)?;
            }
            Ok(())
        }
        // Plan 114.4.4 Ф.4 V4: tuple destructuring pattern.
        Pattern::Tuple(pats, _) => {
            for p in pats { check_const_fn_pattern(p, span)?; }
            Ok(())
        }
        // Plan 114.4.4 Ф.4 V4: variant destructuring pattern.
        Pattern::Variant { kind, .. } => {
            match kind {
                VariantPatternKind::Unit => Ok(()),
                VariantPatternKind::Tuple { patterns, .. } => {
                    for p in patterns { check_const_fn_pattern(p, span)?; }
                    Ok(())
                }
            }
        }
        // Plan 114.4.4 Ф.4 V4: record destructuring pattern.
        Pattern::Record { fields, .. } => {
            for f in fields {
                if let Some(p) = &f.pattern {
                    check_const_fn_pattern(p, span)?;
                }
            }
            Ok(())
        }
        Pattern::Binding { inner, .. } => check_const_fn_pattern(inner, span),
        _ => Err(Diagnostic::new(
            "[E_CONST_FN_PATTERN_NOT_SUPPORTED] pattern form not supported в \
             const fn match arm (D199). Allowed: literal patterns, wildcard `_`, \
             ident bind, `|` alternation, tuple `(a, b)`, variant `Name(args)`, \
             record `{ field: pat }`."
                .to_string(),
            span,
        )),
    }
}

/// Plan 114.4.4 Ф.4 V4: collect bindings from match arm pattern.
/// Used при validating arm body — bindings из pattern visible.
fn collect_const_fn_pattern_bindings(
    pat: &crate::ast::Pattern,
    locals: &mut std::collections::HashSet<String>,
) {
    use crate::ast::{Pattern, VariantPatternKind};
    match pat {
        Pattern::Wildcard(_) | Pattern::Literal(_, _) => {}
        Pattern::Ident { name, .. } => { locals.insert(name.clone()); }
        Pattern::Tuple(pats, _) => {
            for p in pats { collect_const_fn_pattern_bindings(p, locals); }
        }
        Pattern::Variant { kind, .. } => match kind {
            VariantPatternKind::Unit => {}
            VariantPatternKind::Tuple { patterns, .. } => {
                for p in patterns { collect_const_fn_pattern_bindings(p, locals); }
            }
        }
        Pattern::Record { fields, .. } => {
            for f in fields {
                match &f.pattern {
                    Some(p) => collect_const_fn_pattern_bindings(p, locals),
                    None => { locals.insert(f.name.clone()); }
                }
            }
        }
        Pattern::Or { alternatives, .. } => {
            if let Some(first) = alternatives.first() {
                collect_const_fn_pattern_bindings(first, locals);
            }
        }
        Pattern::Binding { name, inner, .. } => {
            locals.insert(name.clone());
            collect_const_fn_pattern_bindings(inner, locals);
        }
        _ => {}
    }
}

/// Plan 114.4.4 Ф.3 V3: collect bindings from `let` pattern in const fn body.
/// V3.0 supports only single Ident patterns. Record/tuple destructuring —
/// V3.1 followup `[M-114.4.4-let-destructure]`.
fn collect_pattern_bindings_const_fn(
    pat: &crate::ast::Pattern,
    locals: &mut std::collections::HashSet<String>,
    span: Span,
) -> Result<(), Diagnostic> {
    use crate::ast::Pattern;
    match pat {
        Pattern::Ident { name, .. } => {
            locals.insert(name.clone());
            Ok(())
        }
        Pattern::Wildcard(_) => Ok(()),
        _ => Err(Diagnostic::new(
            "[E_CONST_FN_PATTERN_NOT_SUPPORTED] only single ident / wildcard \
             pattern allowed в `let` binding в const fn body V3.0 (D199). \
             Record/tuple destructure — followup `[M-114.4.4-let-destructure]`."
                .to_string(),
            span,
        )),
    }
}

fn check_const_fn_block(
    block: &crate::ast::Block,
    param_consts: &std::collections::HashSet<String>,
    const_fn_names: &std::collections::HashSet<String>,
    local_consts: &std::collections::HashSet<String>,
    current_fn: &str,
    call_targets: &mut std::collections::HashSet<String>,
) -> Result<(), Diagnostic> {
    use crate::ast::Stmt;
    let mut locals = local_consts.clone();
    // Block has stmts (non-final) + optional trailing expr (final value).
    // Если trailing нет — последний stmt из stmts становится final.
    let n = block.stmts.len();
    let has_trailing = block.trailing.is_some();
    for (idx, st) in block.stmts.iter().enumerate() {
        let is_last = !has_trailing && idx == n - 1;
        match st {
            Stmt::Const(cd) => {
                // Validate RHS as const-fn expression (allowed const fn calls).
                check_const_fn_expr(
                    &cd.value, param_consts, const_fn_names, &locals, current_fn, call_targets,
                )?;
                locals.insert(cd.name.clone());
            }
            Stmt::Expr(e) => {
                // Plan 114.4.4 Ф.3 V3: intermediate Stmt::Expr accepted —
                // body может содержать loops / if-without-else / etc. как
                // statements. Value extraction handled by caller (trailing
                // expr или final Stmt::Expr становится return value).
                let _ = is_last;
                check_const_fn_expr(
                    e, param_consts, const_fn_names, &locals, current_fn, call_targets,
                )?;
            }
            // Plan 114.4.4 Ф.3 V3: mut let bindings allowed для loops.
            // Stmt::Let добавляет name в locals. mut OK; ro/plain let
            // тоже OK — body checker treats them uniformly.
            Stmt::Let(ld) => {
                check_const_fn_expr(
                    &ld.value, param_consts, const_fn_names, &locals, current_fn, call_targets,
                )?;
                // Collect bindings from pattern. Только Ident patterns
                // supported в V3.0 const fn body. Record/tuple destructure
                // — V3.1 followup.
                collect_pattern_bindings_const_fn(&ld.pattern, &mut locals, ld.span)?;
            }
            // Plan 114.4.4 Ф.3 V3: assignment к mut local allowed.
            Stmt::Assign { target, value, .. } => {
                check_const_fn_expr(
                    target, param_consts, const_fn_names, &locals, current_fn, call_targets,
                )?;
                check_const_fn_expr(
                    value, param_consts, const_fn_names, &locals, current_fn, call_targets,
                )?;
            }
            Stmt::Return { value, span } => {
                if !is_last {
                    return Err(Diagnostic::new(
                        "[E_CONST_FN_CONTROL_FLOW] `return` must be terminal в \
                         const fn body V1 (D199)."
                            .to_string(),
                        *span,
                    ));
                }
                if let Some(v) = value {
                    check_const_fn_expr(
                        v, param_consts, const_fn_names, &locals, current_fn, call_targets,
                    )?;
                }
            }
            Stmt::Throw { span, .. } => {
                return Err(Diagnostic::new(
                    "[E_CONST_FN_EFFECT_IN_BODY] `throw` not allowed в const fn \
                     body (D199): effect propagation."
                        .to_string(),
                    *span,
                ));
            }
            Stmt::Defer { span, .. } | Stmt::ErrDefer { span, .. }
            | Stmt::OkDefer { span, .. } | Stmt::DeferWithResult { span, .. }
            | Stmt::ConsumeScope { span, .. } => {
                return Err(Diagnostic::new(
                    "[E_CONST_FN_EFFECT_IN_BODY] defer / consume-scope не разрешены \
                     в const fn body (D199): cleanup-семантика — runtime."
                        .to_string(),
                    *span,
                ));
            }
            // Plan 114.4.4 Ф.3 V3: break/continue allowed внутри loops.
            // Checker не отслеживает context — evaluator catches stray
            // break/continue outside loop scope at runtime через
            // ControlFlow propagation.
            Stmt::Break(_) | Stmt::Continue(_) => {}
            // Ghost statements (assume/assert_static/apply/calc/reveal) — reject
            // в const fn V1 как unsupported.
            Stmt::AssertStatic { span, .. } | Stmt::Assume { span, .. }
            | Stmt::Apply { span, .. } | Stmt::Calc { span, .. }
            | Stmt::Reveal { span, .. } => {
                return Err(Diagnostic::new(
                    "[E_CONST_FN_EFFECT_IN_BODY] ghost statements (assume/assert_static/\
                     apply/calc/reveal) not allowed в const fn body V1 (D199)."
                        .to_string(),
                    *span,
                ));
            }
            // Plan 136: tuple destructuring assignment — not supported in const fn V1.
            Stmt::TupleAssign { span, .. } => {
                return Err(Diagnostic::new(
                    "[E_CONST_FN_EFFECT_IN_BODY] tuple destructuring assignment not \
                     supported in const fn body V1 (Plan 136 followup)."
                        .to_string(),
                    *span,
                ));
            }
        }
    }
    // Trailing expression — финальное значение блока.
    if let Some(trail) = &block.trailing {
        check_const_fn_expr(
            trail, param_consts, const_fn_names, &locals, current_fn, call_targets,
        )?;
    }
    Ok(())
}

/// Top-level entrypoint: validate const fn `fd` body.
/// Returns Err on first violation; updates `call_targets` для cycle detection.
fn check_const_fn_decl(
    fd: &FnDecl,
    const_fn_names: &std::collections::HashSet<String>,
    call_targets: &mut std::collections::HashSet<String>,
) -> Result<(), Diagnostic> {
    let mut param_consts = std::collections::HashSet::new();
    for p in &fd.params {
        param_consts.insert(p.name.clone());
    }
    let local_consts = std::collections::HashSet::new();
    // Plan 114.4.4.4 V4.3: closure-returning const fn — body is single
    // closure literal at top level. Allow it и validate closure body
    // с extended scope (const params + closure params).
    if let crate::ast::FnBody::Expr(e) = &fd.body {
        if let Some(extra) = closure_param_names(e) {
            let mut extended = param_consts.clone();
            for n in &extra { extended.insert(n.clone()); }
            return validate_const_fn_closure_body(
                e, &extended, const_fn_names, &local_consts, &fd.name, call_targets,
            );
        }
    }
    // Plan 114.4.4 V4.4 Ф.2 [M-114.4.4-closure-captures-outer]: Block body
    // where stmts = all Stmt::Const + trailing = closure literal. Each
    // const RHS validated с regular const fn rules (scope = host const
    // params + prior outer consts); closure body validated с extended
    // scope (host params + outer consts + closure params).
    if let crate::ast::FnBody::Block(b) = &fd.body {
        let stmts_all_const = !b.stmts.is_empty()
            && b.stmts.iter().all(|s| matches!(s, crate::ast::Stmt::Const(_)));
        let trailing_closure = b.trailing.as_ref()
            .and_then(|t| closure_param_names(t).map(|p| (t.as_ref(), p)));
        if stmts_all_const {
            if let Some((closure_expr, closure_params)) = trailing_closure {
                let mut outer_consts: std::collections::HashSet<String> = local_consts.clone();
                for s in &b.stmts {
                    if let crate::ast::Stmt::Const(cd) = s {
                        // Each outer const RHS uses host const params + prior
                        // outer consts. Validator treats them all uniformly через
                        // param_consts + accumulated local_consts.
                        check_const_fn_expr(
                            &cd.value, &param_consts, const_fn_names,
                            &outer_consts, &fd.name, call_targets,
                        )?;
                        outer_consts.insert(cd.name.clone());
                    }
                }
                let mut extended = param_consts.clone();
                for n in &outer_consts { extended.insert(n.clone()); }
                for n in &closure_params { extended.insert(n.clone()); }
                return validate_const_fn_closure_body(
                    closure_expr, &extended, const_fn_names, &local_consts,
                    &fd.name, call_targets,
                );
            }
        }
    }
    match &fd.body {
        crate::ast::FnBody::Expr(e) => check_const_fn_expr(
            e, &param_consts, const_fn_names, &local_consts, &fd.name, call_targets,
        ),
        crate::ast::FnBody::Block(b) => check_const_fn_block(
            b, &param_consts, const_fn_names, &local_consts, &fd.name, call_targets,
        ),
        crate::ast::FnBody::External => Err(Diagnostic::new(
            "[E_CONST_FN_EXTERNAL] external fn не может быть const fn (D199)."
                .to_string(),
            fd.span,
        )),
    }
}

/// Plan 114.4.4.4 V4.3: if `e` is closure literal at top level — return
/// its parameter names. Otherwise None.
fn closure_param_names(e: &crate::ast::Expr) -> Option<Vec<String>> {
    use crate::ast::ExprKind as E;
    match &e.kind {
        E::Lambda { params, .. } => {
            Some(params.iter().map(|p| p.name.clone()).collect())
        }
        E::ClosureLight { params, .. } => {
            Some(params.iter().map(|p| p.name.clone()).collect())
        }
        E::ClosureFull(sb) => {
            Some(sb.params.iter().map(|p| p.name.clone()).collect())
        }
        _ => None,
    }
}

/// Plan 114.4.4.4 V4.3: validate closure body of closure-returning const
/// fn. Closure body может использовать host fn's const params + closure's
/// own params как identifier sources. Other constructs validated по
/// regular V1 const fn body rules.
fn validate_const_fn_closure_body(
    closure_expr: &crate::ast::Expr,
    extended_params: &std::collections::HashSet<String>,
    const_fn_names: &std::collections::HashSet<String>,
    local_consts: &std::collections::HashSet<String>,
    current_fn: &str,
    call_targets: &mut std::collections::HashSet<String>,
) -> Result<(), Diagnostic> {
    use crate::ast::{ExprKind as E, FnBody, ClosureBody};
    match &closure_expr.kind {
        E::Lambda { body, .. } => check_const_fn_expr(
            body, extended_params, const_fn_names, local_consts, current_fn, call_targets,
        ),
        E::ClosureLight { body, .. } => match body {
            ClosureBody::Expr(e) => check_const_fn_expr(
                e, extended_params, const_fn_names, local_consts, current_fn, call_targets,
            ),
            ClosureBody::Block(b) => check_const_fn_block(
                b, extended_params, const_fn_names, local_consts, current_fn, call_targets,
            ),
        },
        E::ClosureFull(sb) => match &sb.body {
            FnBody::Expr(e) => check_const_fn_expr(
                e, extended_params, const_fn_names, local_consts, current_fn, call_targets,
            ),
            FnBody::Block(b) => check_const_fn_block(
                b, extended_params, const_fn_names, local_consts, current_fn, call_targets,
            ),
            FnBody::External => Err(Diagnostic::new(
                "[E_CONST_FN_CLOSURE_EXTERNAL] closure-returning const fn body \
                 cannot be external (D199 V4.3).".to_string(),
                closure_expr.span,
            )),
        },
        _ => Err(Diagnostic::new(
            "[E_CONST_FN_CLOSURE_BODY] expected closure literal в \
             closure-returning const fn body (D199 V4.3).".to_string(),
            closure_expr.span,
        )),
    }
}

/// **Plan 118.5 V3 §V3.1 (D216 V3 amend, 2026-06-04):** detect value-type
/// classification of a TypeRef для storage-class-aware ro+mut conflict check.
///
/// Value types: primitives (int/uint as aliases для isize/usize, all sized
/// ints + floats, bool/char/byte/str/ptr), value records (Plan 124.8 D228
/// `type X value { ... }`), named tuples (Plan 120 D215), anonymous tuples,
/// unit.
///
/// Reference types: heap records, arrays, pointers, func, protocol.
fn is_value_type_for_v3(
    ty: &TypeRef,
    types: &HashMap<String, &TypeDecl>,
) -> bool {
    use TypeRef::*;
    match ty {
        Named { path, .. } if path.len() == 1 => {
            let name = path[0].as_str();
            // Primitives per V3.1 + Plan 133 (int=intptr_t, uint=uintptr_t; usize/isize removed).
            // Plan 134: `ptr` removed; *() = TypeRef::Pointer(Unit) is handled below.
            if matches!(name,
                "int" | "uint"
                | "i8" | "i16" | "i32" | "i64"
                | "u8" | "u16" | "u32" | "u64"
                | "f32" | "f64"
                | "bool" | "char" | "byte" | "str"
            ) {
                return true;
            }
            // User type: value record OR named tuple.
            if let Some(td) = types.get(name) {
                let is_value_record = matches!(
                    td.kind,
                    crate::ast::TypeDeclKind::Record(_)
                ) && td.allocation == crate::ast::AllocKind::Value;
                let is_named_tuple = matches!(
                    td.kind,
                    crate::ast::TypeDeclKind::NamedTuple(_)
                );
                return is_value_record || is_named_tuple;
            }
            false
        }
        Tuple(..) => true,        // anonymous tuples = value
        Unit(..) => true,
        FixedArray(..) => false,  // [N]T heap-tracked
        Array(..) => false,       // []T heap
        Pointer(..) => false,
        Func { .. } => false,
        Protocol { .. } => false,
        Readonly(inner, _) | Mut(inner, _) | Unsafe(inner, _) => {
            is_value_type_for_v3(inner, types)
        }
        // Module-qualified Named (path.len() > 1) — out-of-module type;
        // assume reference (conservative — won't break value semantic для
        // local types; cross-module value records require explicit detection
        // в future V3.1.1 followup).
        Named { .. } => false,
    }
}

/// **Plan 118.5 V3 §V3.1 (2026-06-04):** check binding type for ro+mut
/// conflict. Emits `E_MUTABILITY_CONFLICT_VALUE_TYPE` для:
/// - Readonly(Mut(T)) или Mut(Readonly(T)) AST shape WHEN
///   T (innermost after strip) is value-type
/// - Pure-type-level Readonly(Mut(T)) inside Pointer/Array constructor —
///   value-T → error
///
/// For reference-type T at outermost binding position, the combination
/// is allowed per §V3.1 («binding ro + content mut» semantics).
fn check_v3_ro_mut_conflict(
    ty: &TypeRef,
    types: &HashMap<String, &TypeDecl>,
    at_binding_top: bool,
    errors: &mut Vec<Diagnostic>,
) {
    use TypeRef::*;
    match ty {
        Readonly(inner, span) => {
            if let Mut(_, _) = inner.as_ref() {
                let inner_strip = inner.strip_modifiers();
                let is_value = is_value_type_for_v3(inner_strip, types);
                if is_value || !at_binding_top {
                    let ctx = if is_value { "value-type T" } else { "nested-type context" };
                    errors.push(Diagnostic::new(
                        format!(
                            "[E_MUTABILITY_CONFLICT_VALUE_TYPE] `ro` and `mut` \
                             modifiers conflict on {} (Plan 118.5 V3 / D216 V3 \
                             §V3.1). `ro` (cannot mutate / cannot rebind value) \
                             contradicts `mut` (mutable). For value-type T, \
                             storage IS value — combination not meaningful. \
                             For reference-type T at binding top-level, the \
                             combination expresses «ro binding к mut content» \
                             but in nested constructor position there's no \
                             binding context к disambiguate.",
                            ctx,
                        ),
                        *span,
                    ));
                }
            }
            check_v3_ro_mut_conflict(inner, types, false, errors);
        }
        Mut(inner, span) => {
            if let Readonly(_, _) = inner.as_ref() {
                let inner_strip = inner.strip_modifiers();
                let is_value = is_value_type_for_v3(inner_strip, types);
                if is_value || !at_binding_top {
                    let ctx = if is_value { "value-type T" } else { "nested-type context" };
                    errors.push(Diagnostic::new(
                        format!(
                            "[E_MUTABILITY_CONFLICT_VALUE_TYPE] `mut` and `ro` \
                             modifiers conflict on {} (Plan 118.5 V3 / D216 V3 \
                             §V3.1). `mut` (mutable / can rebind) contradicts \
                             `ro` (immutable). For value-type T, storage IS \
                             value — combination not meaningful. For reference-\
                             type T at binding top-level, the combination \
                             expresses «mut binding к ro content» but in nested \
                             constructor position there's no binding context.",
                            ctx,
                        ),
                        *span,
                    ));
                }
            }
            check_v3_ro_mut_conflict(inner, types, false, errors);
        }
        Unsafe(inner, _) => check_v3_ro_mut_conflict(inner, types, at_binding_top, errors),
        Pointer(inner, _) => check_v3_ro_mut_conflict(inner, types, false, errors),
        Array(inner, _) | FixedArray(_, inner, _) => {
            check_v3_ro_mut_conflict(inner, types, false, errors);
        }
        Tuple(elems, _) => {
            for e in elems { check_v3_ro_mut_conflict(e, types, false, errors); }
        }
        Func { params, return_type, .. } => {
            for p in params { check_v3_ro_mut_conflict(p, types, false, errors); }
            if let Some(rt) = return_type {
                check_v3_ro_mut_conflict(rt, types, false, errors);
            }
        }
        Named { generics, .. } => {
            for g in generics { check_v3_ro_mut_conflict(g, types, false, errors); }
        }
        Protocol { .. } | Unit(_) => {}
    }
}

/// Plan 126.2 Ф.1: owned arena для synthesized auto-derive `FnDecl`s.
///
/// Проблема: `TypeCheckCtx.method_table` хранит `&'a FnDecl` — заимствования
/// из AST модуля. Synthesized auto-derive методы (Plan 126 V1
/// `auto_derive::synthesize_method`) — **owned** `FnDecl`, их негде заимствовать
/// в исходном AST. Чтобы зарегистрировать их в `method_table` тем же путём,
/// что и user-методы, нужен arena, который живёт не меньше `'a`.
///
/// Реализация без внешних зависимостей (bootstrap-ethos — пустой lockfile):
/// каждый `FnDecl` лежит в собственном `Box`, а боксы складываются в `Vec`.
/// Содержимое `Box` стабильно по адресу: рост `Vec` перемещает только
/// box-указатели, heap-аллокация самого `FnDecl` не двигается. Поэтому
/// `&'arena FnDecl`, полученный из `&**boxed`, остаётся валидным даже после
/// последующих `alloc`. Это стандартный safe-by-invariant arena-паттерн
/// (тот же, что внутри `typed-arena`).
#[derive(Default)]
pub(crate) struct FnDeclArena {
    items: std::cell::RefCell<Vec<Box<FnDecl>>>,
}

impl FnDeclArena {
    fn new() -> Self {
        FnDeclArena { items: std::cell::RefCell::new(Vec::new()) }
    }

    /// Аллоцирует `fd` в arena, возвращает стабильную ссылку с lifetime arena.
    ///
    /// SAFETY: `fd` помещается в `Box`, чей heap-storage неподвижен на всё
    /// время жизни arena. Мы храним `Box` в `Vec` (под `RefCell`) — arena
    /// никогда не освобождает и не перемещает содержимое `Box` до своего
    /// собственного drop'а. Возвращаемая ссылка живёт `'arena` (привязана к
    /// `&'arena self`), что не дольше времени жизни arena. Aliasing: мы
    /// раздаём только shared (`&`) ссылки, мутаций содержимого нет.
    fn alloc<'arena>(&'arena self, fd: FnDecl) -> &'arena FnDecl {
        let boxed = Box::new(fd);
        let ptr: *const FnDecl = &*boxed;
        self.items.borrow_mut().push(boxed);
        unsafe { &*ptr }
    }
}

/// Plan 79: проход типовой полноты type-checker'а.
struct TypeCheckCtx<'a> {
    /// Ф.2: имя типа → объявленная арность.
    arity: HashMap<String, ArityInfo>,
    /// Plan 172.1 U.2.3.3: shared base signature registry (free fns + base methods,
    /// §0 single source) — replaces the local `fn_decls`/`method_table` build loop.
    /// Read via `self.sig.fn_decls` / `self.sig.method_table`, or the synth-aware
    /// helpers `method_overloads` / `t_provides_method` / `find_method_decl`.
    sig: &'a crate::sig_registry::SigRegistry<'a>,
    /// Plan 172.1 U.2.3.3 (F2, [M-172.1-U2.3-synth-overlay]): synthesized auto-derive
    /// methods (Plan 126) — a TypeCheckCtx-PRIVATE overlay on top of `sig.method_table`.
    /// NOT in the shared registry: Bound/Cap must not see synth (their resolution is
    /// base-only). Keyed `type → method → overloads`; for a given (type, method)
    /// overloads come from EITHER base OR synth, never both (synth is registered only
    /// when base lacks the method — see `register_synthesized_methods`).
    synth_methods: HashMap<String, HashMap<String, Vec<&'a FnDecl>>>,
    /// Ф.1: объявления типов — для разворачивания alias/newtype при
    /// категоризации (assignability сравнивает категории, не имена).
    types: HashMap<String, &'a TypeDecl>,
    /// Plan 81 Ф.2: префиксы импортированных модулей (alias + последний
    /// сегмент пути import'а) — для резолва module-qualified вызовов
    /// `alias.func(...)`.
    imported_modules: HashSet<String>,
    /// Plan 162 Ф.5: last-segments/aliases of modules imported DIRECTLY by
    /// entry-module peer files (is_entry_module = true). Excludes transitive
    /// imports from imported-module peers. Used for extension method policy:
    /// an extension method is accessible iff its declaring module's last-segment
    /// or alias is in this set.
    entry_imported_modules: HashSet<String>,
    /// Plan 114.4.2 (D199): const fn names в текущем модуле — для
    /// scope-local Stmt::Const RHS validation (calls к const fn разрешены).
    const_fn_names: HashSet<String>,
    /// Plan 114.4.2 (D199): flag — we are inside const fn body. Scope-local
    /// const validation skipped (body checker `check_const_fn_decl` covers
    /// param/local awareness more precisely).
    in_const_fn: std::cell::Cell<bool>,
    /// Plan 124 (D220): current receiver type — set перед walking method body
    /// в check_fn; cleared on exit. `None` если мы НЕ внутри type-method
    /// (free fn, top-level expr). f3_check_member использует для priv field
    /// access check: если field.priv_field И current_recv_type != obj's type
    /// → emit E_PRIV_FIELD_READ.
    current_recv_type: std::cell::RefCell<Option<String>>,
    /// Plan 124.6 (D225): current fn's `#test_access(TypeA, TypeB, ...)` list.
    /// Если non-empty, current fn body получает priv-field access ко всем
    /// перечисленным types (escape hatch для unit tests + sibling helper
    /// fns). Cleared on fn exit. Combines с current_recv_type для allow-list.
    current_fn_test_access: std::cell::RefCell<Vec<String>>,
    /// Plan 124.8 (D175 amend): set of `ro`-bound identifier names в текущем
    /// scope. Когда target assignment пути starts с Ident name ∈ этого
    /// set'а — binding dominates даже над `mut field` markers.
    /// Закрывает D175 §«binding dominates» — Rust-style rule.
    /// Tracks через f1_stmt Stmt::Let; cleared on scope exit (block end).
    ro_binding_names: std::cell::RefCell<std::collections::HashSet<String>>,
    /// Plan 138.2 Ф.0c (D29 method-level shadow): names of generic types
    /// imported into the merged module that the user has REDECLARED in
    /// entry-peer-files with a DIFFERENT arity (e.g. user `type Vec { x, y }`
    /// = arity 0 shadowing imported `type Vec[T]` = arity 1). The user
    /// declaration wins **entirely** (D29 full-shadow): the imported generic
    /// type's merged methods (`Vec[T] @push`, …) carry `Vec[T]` type-refs that
    /// would arity-check (E7310) against the user's non-generic `Vec`. We skip
    /// arity-checking those merged methods so they do not leak onto the
    /// user-shadowed receiver. Built in `build`. Empty in the common (no-shadow)
    /// case → zero overhead. Maps the shadowed name → the user's declared
    /// arity (so a merged method whose receiver carries a DIFFERENT carrier
    /// arity is recognised as the import's method and skipped, while a method
    /// the user wrote on their own redeclared type — matching carrier arity —
    /// is kept).
    user_shadowed_generic_types: HashMap<String, usize>,
    /// Plan 160 (D281) Ф.2: type name → declaring module name segments.
    /// Built from `module.peer_files.items_here` in `build`. Used by
    /// `module_priv_access_allowed` to compare with `current_module`.
    /// Types imported from other modules retain the module name from which
    /// they came (their type decl's module_name). Empty for types with
    /// unknown origin (imported without peer_files → conservative = deny).
    type_defining_modules: HashMap<String, Vec<String>>,
    /// Plan 160 (D281) Ф.2: module name of the code currently being
    /// checked — set to `module.name` at the start of `check_module`.
    /// Used together with `type_defining_modules` for module-boundary
    /// enforcement. Empty = no current module (conservative = deny).
    current_module: std::cell::RefCell<Vec<String>>,
    /// Plan 162 Ф.3: global TypeMethodMap — type_name → method_name →
    /// list of module_names (Vec<String>) that declared this method.
    /// Built from `module.peer_files[*].items_here` in `build`.
    /// Inherent method: method declared in the SAME module as its type T
    ///   (type_method_map[T][m] ∩ type_defining_modules[T] ≠ ∅).
    /// Extension method: method declared in a DIFFERENT module from T.
    /// Used by `is_inherent_method` to decide resolution priority.
    type_method_map: HashMap<String, HashMap<String, Vec<Vec<String>>>>,
    /// Plan 162 Ф.5: FileIds of entry-module peer files (is_entry_module=true).
    /// Extension method policy only fires for call sites in entry-module files.
    /// Prevents false positives from type-checking imported stdlib method bodies.
    entry_file_ids: HashSet<crate::diag::FileId>,
    /// Plan 124.6 (D224 §4): true when the checker is inside a `test "…" { }`
    /// block body. Controls rule-2 (implicit test grant — same-module access)
    /// and rule-3 (explicit `test_access` list check on the TestDecl itself).
    /// Set/cleared via `TestBlockGuard` RAII on `Item::Test` entry/exit.
    in_test_block: std::cell::Cell<bool>,
    /// Plan 124.6 (D224 §4): the `test_access` list from the *current* test
    /// block (populated from `TestDecl.test_access`). Non-empty only when
    /// `in_test_block` is true. Cleared on exit via `TestBlockGuard`.
    test_block_test_access: std::cell::RefCell<Vec<String>>,
    /// Plan 124.6 (D224 §4 rule-4): type name → pub_to friend list.
    /// Built in `build` from `TypeDecl.pub_to`. A `current_recv_type` that
    /// appears in `type_pub_to[tname]` gets priv-field access to `tname`.
    type_pub_to: HashMap<String, Vec<String>>,
    /// Plan 162.1 Step 2: cross-module signature table — maps declared module
    /// name to the set of type names and fn names it exports. Built lazily by
    /// `build_with_sig_table`; empty in the default `build` path (no I/O at
    /// type-check time). Used by `is_known_type` / `is_known_fn` to answer
    /// "does any imported module define symbol X?" without a full resolve.
    sig_table: crate::imports::ModuleSigTable,
}

/// Plan 114.4.2 D199: RAII guard для in_const_fn flag.
/// Restoring previous value on drop — works regardless of error path.
struct ConstFnFlagGuard<'a, 'b> {
    ctx: &'b TypeCheckCtx<'a>,
    prev: bool,
}
impl<'a, 'b> Drop for ConstFnFlagGuard<'a, 'b> {
    fn drop(&mut self) {
        self.ctx.in_const_fn.set(self.prev);
    }
}

/// Plan 124 (D220): RAII guard для current_recv_type field в TypeCheckCtx.
/// Restoring previous value on drop — works regardless of error path.
struct PrivRecvGuard<'a, 'b> {
    ctx: &'b TypeCheckCtx<'a>,
    prev: Option<String>,
}
impl<'a, 'b> Drop for PrivRecvGuard<'a, 'b> {
    fn drop(&mut self) {
        *self.ctx.current_recv_type.borrow_mut() = self.prev.take();
    }
}

/// Plan 124.6 (D225): RAII guard для current_fn_test_access vec в TypeCheckCtx.
struct PrivTestAccessGuard<'a, 'b> {
    ctx: &'b TypeCheckCtx<'a>,
    prev: Vec<String>,
}
impl<'a, 'b> Drop for PrivTestAccessGuard<'a, 'b> {
    fn drop(&mut self) {
        *self.ctx.current_fn_test_access.borrow_mut() = std::mem::take(&mut self.prev);
    }
}

/// Plan 160 (D281) Ф.2: RAII guard для current_module в TypeCheckCtx.
/// Restores previous module name on drop.
struct CurrentModuleGuard<'a, 'b> {
    ctx: &'b TypeCheckCtx<'a>,
    prev: Vec<String>,
}
impl<'a, 'b> CurrentModuleGuard<'a, 'b> {
    fn set(ctx: &'b TypeCheckCtx<'a>, module: Vec<String>) -> Self {
        let prev = std::mem::replace(&mut *ctx.current_module.borrow_mut(), module);
        CurrentModuleGuard { ctx, prev }
    }
}
impl<'a, 'b> Drop for CurrentModuleGuard<'a, 'b> {
    fn drop(&mut self) {
        *self.ctx.current_module.borrow_mut() = std::mem::take(&mut self.prev);
    }
}

/// Plan 124.6 (D224 §4): RAII guard для in_test_block + test_block_test_access
/// в TypeCheckCtx. Set to (true, access_list) on entry; restored on drop.
struct TestBlockGuard<'a, 'b> {
    ctx: &'b TypeCheckCtx<'a>,
    prev_in_test: bool,
    prev_access: Vec<String>,
}
impl<'a, 'b> TestBlockGuard<'a, 'b> {
    fn enter(ctx: &'b TypeCheckCtx<'a>, access: Vec<String>) -> Self {
        let prev_in_test = ctx.in_test_block.get();
        ctx.in_test_block.set(true);
        let prev_access = std::mem::replace(&mut *ctx.test_block_test_access.borrow_mut(), access);
        TestBlockGuard { ctx, prev_in_test, prev_access }
    }
}
impl<'a, 'b> Drop for TestBlockGuard<'a, 'b> {
    fn drop(&mut self) {
        self.ctx.in_test_block.set(self.prev_in_test);
        *self.ctx.test_block_test_access.borrow_mut() = std::mem::take(&mut self.prev_access);
    }
}

/// `true` для имён, у которых arity **не** проверяется: referential-типы
/// и эффекты с sugar/гибкой арностью.
fn arity_exempt(name: &str) -> bool {
    matches!(
        name,
        // referential / top / bottom
        "Self" | "any" | "never" | "Never"
        // Fail[E] ≡ bare Fail (D65); Effect[E] ≡ Effect[E, never] (D88)
        // Plan 97 Ф.3 (D142): `Handler` → `Effect`.
        | "Fail" | "Effect"
        // built-in эффекты с параметрами — не объявлены как Item::Type,
        // в таблицу не попадут; перечислены явно для ясности
        | "Ask" | "Alloc"
    )
}

/// Plan 126 (D230) Ф.4: bridge между TypeCheckCtx и auto_derive::DeriveQuery.
///
/// Owns shared reference к TypeCheckCtx, exposes lookup_type / has-method
/// queries по API contract auto_derive::DeriveQuery. Без этой обёртки
/// auto_derive вынужден был бы знать про полный TypeCheckCtx (cycle через
/// `types` модуль).
pub(crate) struct AutoDeriveQueryBridge<'a> {
    ctx: &'a TypeCheckCtx<'a>,
}

/// Plan 126.2 Ф.1: build-time `DeriveQuery` над уже-построенными `types` +
/// `method_table` (до конструирования `TypeCheckCtx`). Используется
/// `register_synthesized_methods` для синтеза auto-derive методов на этапе
/// `build`.
pub(crate) struct BuildTimeDeriveQuery<'a, 'b> {
    types: &'b HashMap<String, &'a TypeDecl>,
    method_table: &'b HashMap<String, HashMap<String, Vec<&'a FnDecl>>>,
}

impl<'a, 'b> crate::protocols::auto_derive::DeriveQuery for BuildTimeDeriveQuery<'a, 'b> {
    fn lookup_type(&self, name: &str) -> Option<&TypeDecl> {
        self.types.get(name).copied()
    }

    fn type_provides_method(&self, t: &str, method_name: &str) -> bool {
        self.method_table.get(t).map_or(false, |m| {
            m.keys().any(|k| k.trim_start_matches('@') == method_name)
        })
    }
}

impl<'a> crate::protocols::auto_derive::DeriveQuery for AutoDeriveQueryBridge<'a> {
    fn lookup_type(&self, name: &str) -> Option<&TypeDecl> {
        // TypeCheckCtx.types: HashMap<String, &'a TypeDecl>. Dereferences
        // outer reference twice (Option<&&'a TypeDecl> → Option<&TypeDecl>).
        self.ctx.types.get(name).copied()
    }

    fn type_provides_method(&self, t: &str, method_name: &str) -> bool {
        self.ctx.t_provides_method(t, method_name)
    }
}

impl<'a> TypeCheckCtx<'a> {
    fn build(
        module: &'a Module,
        synth_arena: &'a FnDeclArena,
        sig: &'a crate::sig_registry::SigRegistry<'a>,
    ) -> Self {
        let mut arity: HashMap<String, ArityInfo> = HashMap::new();
        // U.2.3.3: fn_decls/method_table read from `sig` (shared base registry);
        // only `types` is still collected here (needed locally below).
        let mut types: HashMap<String, &'a TypeDecl> = HashMap::new();
        for item in &module.items {
            if let Item::Type(td) = item {
                types.insert(td.name.clone(), td);
            }
        }
        // Все типы (пользовательские + merged-from-imports) — для подсчёта
        // арности; неверная арность на импортированном типе тоже ловится.
        // `decl_span: None` — у импортированных/prelude-типов объявление
        // не в текущем файле, note «declared here» был бы с чужим/битым
        // span'ом (см. Plan 81 Ф.8 file_id-утечки).
        for item in &module.items {
            if let Item::Type(td) = item {
                arity.insert(
                    td.name.clone(),
                    ArityInfo { count: td.generics.len(), decl_span: None },
                );
            }
        }
        // Типы, объявленные в самом компилируемом модуле (entry peers'
        // `items_here`) — для них note «declared here» указывает на
        // реальный исходник пользователя.
        let own_items: Vec<&Item> = if module.peer_files.is_empty() {
            module.items.iter().collect()
        } else {
            module
                .peer_files
                .iter()
                .filter(|pf| pf.is_entry_module)
                .flat_map(|pf| pf.items_here.iter())
                .collect()
        };
        for item in own_items {
            if let Item::Type(td) = item {
                arity.insert(
                    td.name.clone(),
                    ArityInfo { count: td.generics.len(), decl_span: Some(td.span) },
                );
            }
        }
        // Prelude-типы обычно приходят как Item::Type через auto-import;
        // fallback на известную арность для модулей без prelude.
        arity.entry("Option".to_string())
            .or_insert(ArityInfo { count: 1, decl_span: None });
        arity.entry("Result".to_string())
            .or_insert(ArityInfo { count: 2, decl_span: None });
        // Примитивы — арность 0 (`int[X]` / `bool[T]` — ошибка).
        for prim in [
            "int", "i8", "i16", "i32", "i64", "u8", "u16", "u32", "u64",
            "uint", "f32", "f64", "str", "bool", "char",
        ] {
            arity.entry(prim.to_string())
                .or_insert(ArityInfo { count: 0, decl_span: None });
        }
        // Plan 81 Ф.2: префиксы импортированных модулей.
        let mut imported_modules: HashSet<String> = HashSet::new();
        let mut collect = |imports: &[Import]| {
            for imp in imports {
                if let Some(a) = &imp.alias {
                    imported_modules.insert(a.clone());
                }
                if let Some(last) = imp.path.last() {
                    imported_modules.insert(last.clone());
                }
            }
        };
        collect(&module.imports);
        for pf in &module.peer_files {
            collect(&pf.imports);
        }
        drop(collect);

        // Plan 162 Ф.5: entry_imported_modules — last-segments/aliases of
        // modules imported DIRECTLY by entry-module peer files only.
        // Excludes transitive imports from imported-module peers, so that
        // extension method policy can distinguish "explicitly imported" from
        // "transitively pulled in".
        let mut entry_imported_modules: HashSet<String> = HashSet::new();
        // Plan 162 Ф.5: entry_file_ids — FileIds of entry-module peer files.
        // Extension method policy only fires for call sites in these files.
        let mut entry_file_ids: HashSet<crate::diag::FileId> = HashSet::new();
        {
            let mut collect_entry = |imports: &[Import]| {
                for imp in imports {
                    if let Some(a) = &imp.alias {
                        entry_imported_modules.insert(a.clone());
                    }
                    if let Some(last) = imp.path.last() {
                        entry_imported_modules.insert(last.clone());
                    }
                }
            };
            collect_entry(&module.imports);
            for pf in &module.peer_files {
                if pf.is_entry_module {
                    collect_entry(&pf.imports);
                    entry_file_ids.insert(pf.file_id);
                }
            }
        }

        // Plan 114.4.2 D199 + Plan 114.4.3 Ф.5 V2: precompute const fn names
        // для scope-local const validation. Includes const fn declarations
        // AND const fn aliases (`const ALIAS = const_fn_name` form).
        let mut const_fn_names: HashSet<String> = module.items.iter()
            .filter_map(|it| match it {
                Item::Fn(fd) => {
                    let is_const = fd.return_is_const
                        || fd.params.iter().any(|p| p.is_const);
                    if is_const { Some(fd.name.clone()) } else { None }
                }
                _ => None,
            })
            .collect();
        // Pass 2: include aliases (Ident RHS resolving to const fn name).
        // Iterative — alias-to-alias chains supported up to depth=10.
        for _ in 0..10 {
            let mut added = false;
            for item in &module.items {
                if let Item::Const(c) = item {
                    if let crate::ast::ExprKind::Ident(target) = &c.value.kind {
                        if const_fn_names.contains(target)
                            && !const_fn_names.contains(&c.name)
                        {
                            const_fn_names.insert(c.name.clone());
                            added = true;
                        }
                    }
                }
            }
            if !added { break; }
        }
        // Plan 126.2 Ф.1: register synthesized auto-derive methods into
        // `method_table` alongside user-written methods, so codegen
        // method-dispatch (and the type-checker's own resolution) finds them.
        //
        // For each type T с `#impl(P1 + P2 + ...)`, for each built-in
        // auto-derivable protocol P, if T does NOT already provide the
        // protocol's method explicitly, synthesize the FnDecl и insert
        // `&'a FnDecl` (allocated in `synth_arena`) into
        // `method_table[T][@method]`. Synthesis failures (ineligible fields,
        // unsupported kind, cycles) are silently skipped here — the dedicated
        // `verify_impl_protocols` pass re-runs synthesis и emits the
        // E_AUTO_DERIVE_* / E_IMPL_MISSING_METHODS diagnostics. This pass is
        // registration-only.
        // U.2.3.3 (F2): synth goes into a TypeCheckCtx-private overlay (NOT the shared
        // base registry). DeriveQuery reads base (`sig.method_table`) for user-method
        // coverage — synth is registered only where the user did not provide the method.
        let mut synth_methods: HashMap<String, HashMap<String, Vec<&'a FnDecl>>> =
            HashMap::new();
        Self::register_synthesized_methods(
            module, synth_arena, &types, &sig.method_table, &mut synth_methods,
        );

        // Plan 138.2 Ф.0c (D29 method-level shadow): detect generic types that
        // the user redeclared in entry-peer-files with a DIFFERENT arity than a
        // merged-from-import declaration of the same name. Such a name is a
        // genuine generic-type shadow (user `type Vec { x, y }` over imported
        // `type Vec[T]`). The merged generic type's methods reference `Name[T]`
        // and would arity-check (E7310) against the user's non-generic decl —
        // we record the name here so `check_module` skips those merged methods
        // (user wins entirely per D29). Mitigation RC: we record ONLY names the
        // user declared in entry-peers AND that also exist merged with a
        // different arity — a legitimate `import …Vec` *without* a user-side
        // `type Vec` redeclaration leaves this set empty, so dispatch is
        // untouched.
        let mut user_shadowed_generic_types: HashMap<String, usize> = HashMap::new();
        {
            // Per-name max arity seen across the WHOLE merged module
            // (`module.items`) — captures the imported generic decl.
            let mut merged_arity: HashMap<String, usize> = HashMap::new();
            for item in &module.items {
                if let Item::Type(td) = item {
                    let e = merged_arity.entry(td.name.clone()).or_insert(0);
                    *e = (*e).max(td.generics.len());
                }
            }
            // User-declared types in entry-peer-files only.
            let user_own: Vec<&Item> = if module.peer_files.is_empty() {
                module.items.iter().collect()
            } else {
                module
                    .peer_files
                    .iter()
                    .filter(|pf| pf.is_entry_module)
                    .flat_map(|pf| pf.items_here.iter())
                    .collect()
            };
            for item in user_own {
                if let Item::Type(td) = item {
                    if let Some(&m) = merged_arity.get(&td.name) {
                        if m != td.generics.len() {
                            // Same name, different arity, merged-vs-user →
                            // genuine generic shadow. User wins entirely.
                            user_shadowed_generic_types
                                .insert(td.name.clone(), td.generics.len());
                        }
                    }
                }
            }
        }

        // Plan 160 (D281) Ф.2: build type_defining_modules — maps type name
        // → the module_name of the peer_file that declared it. Used for
        // module-boundary enforcement of `priv` (module-private) types.
        // Only entry-peer-files contribute (imported modules bring in their
        // types with a different module_name = their own path, which is the
        // desired behaviour: cross-module access to those types is denied).
        let mut type_defining_modules: HashMap<String, Vec<String>> = HashMap::new();
        if module.peer_files.is_empty() {
            // Single-file module: all items in module.items belong to module.name.
            for item in &module.items {
                if let Item::Type(td) = item {
                    type_defining_modules
                        .entry(td.name.clone())
                        .or_insert_with(|| module.name.clone());
                }
            }
        } else {
            for pf in &module.peer_files {
                for item in &pf.items_here {
                    if let Item::Type(td) = item {
                        // Record the module_name of the peer that owns this type.
                        type_defining_modules
                            .entry(td.name.clone())
                            .or_insert_with(|| pf.module_name.clone());
                    }
                }
            }
        }

        // Plan 162 Ф.3: build type_method_map — maps
        // type_name → method_name → Vec<module_name> (all modules
        // that declare this method on this receiver type).
        //
        // Scans all peer_files (both entry-peers and imported-module
        // peers) to attribute each @method declaration to its source
        // module. When peer_files is empty (legacy/fallback case),
        // scans module.items and attributes everything to module.name.
        //
        // Together with type_defining_modules this enables:
        //   is_inherent = type_method_map[T][m] ∩ {type_defining_modules[T]} ≠ ∅
        let mut type_method_map: HashMap<String, HashMap<String, Vec<Vec<String>>>> =
            HashMap::new();
        if module.peer_files.is_empty() {
            // Single-file / no peer attribution: attribute all @methods
            // to module.name (the entry module). This is conservative:
            // inherent == all methods when there's only one module.
            for item in &module.items {
                if let Item::Fn(f) = item {
                    if let Some(recv) = &f.receiver {
                        type_method_map
                            .entry(recv.type_name.clone())
                            .or_default()
                            .entry(f.name.clone())
                            .or_default()
                            .push(module.name.clone());
                    }
                }
            }
        } else {
            for pf in &module.peer_files {
                for item in &pf.items_here {
                    if let Item::Fn(f) = item {
                        if let Some(recv) = &f.receiver {
                            let module_list = type_method_map
                                .entry(recv.type_name.clone())
                                .or_default()
                                .entry(f.name.clone())
                                .or_default();
                            // Only push if this module isn't already in the list
                            // (avoids duplicate entries from sibling peers of
                            // the same module that share module_name).
                            if !module_list.contains(&pf.module_name) {
                                module_list.push(pf.module_name.clone());
                            }
                        }
                    }
                }
            }
        }

        // Plan 124.6 (D224 §4 rule-4): build type_pub_to — maps type name
        // → its `pub_to` friend list (from TypeDecl.pub_to). A type that
        // appears as a receiver (current_recv_type) and is in the list gets
        // priv-field access. Merges across all items (single- + multi-file).
        let mut type_pub_to: HashMap<String, Vec<String>> = HashMap::new();
        for item in &module.items {
            if let Item::Type(td) = item {
                if !td.pub_to.is_empty() {
                    type_pub_to
                        .entry(td.name.clone())
                        .or_default()
                        .extend(td.pub_to.iter().cloned());
                }
            }
        }

        TypeCheckCtx { arity, sig, synth_methods, types, imported_modules,
            entry_imported_modules,
            entry_file_ids,
            const_fn_names,
            in_const_fn: std::cell::Cell::new(false),
            current_recv_type: std::cell::RefCell::new(None),
            current_fn_test_access: std::cell::RefCell::new(Vec::new()),
            ro_binding_names: std::cell::RefCell::new(std::collections::HashSet::new()),
            user_shadowed_generic_types,
            type_defining_modules,
            current_module: std::cell::RefCell::new(Vec::new()),
            type_method_map,
            in_test_block: std::cell::Cell::new(false),
            test_block_test_access: std::cell::RefCell::new(Vec::new()),
            type_pub_to,
            // Plan 162.1 Step 2: default build uses empty sig_table; callers
            // that need cross-module symbol lookup call build_with_sig_table.
            sig_table: crate::imports::ModuleSigTable::new(),
        }
    }

    /// Plan 162.1 Step 2: variant of `build` that pre-populates the
    /// cross-module signature table. Callers that have already run
    /// `collect_all_signatures` pass the resulting `ModuleSigTable` here so
    /// that `is_known_type` / `is_known_fn` can answer cross-module questions
    /// during type-checking without additional I/O.
    fn build_with_sig_table(
        module: &'a Module,
        synth_arena: &'a FnDeclArena,
        sig_table: crate::imports::ModuleSigTable,
        sig: &'a crate::sig_registry::SigRegistry<'a>,
    ) -> Self {
        let mut ctx = Self::build(module, synth_arena, sig);
        ctx.sig_table = sig_table;
        ctx
    }

    /// Plan 162.1 Step 2: returns `true` if `name` is a known type in either:
    /// (a) the merged `module.items` (types already resolved into this module),
    /// or (b) any module in the cross-module `sig_table`.
    /// Used for disambiguation before full resolution (Step 3).
    fn is_known_type(&self, name: &str) -> bool {
        self.types.contains_key(name)
            || !self.sig_table.find_type_modules(name).is_empty()
    }

    /// Plan 162.1 Step 2: returns `true` if `name` is a known free function in
    /// either:
    /// (a) `fn_decls` (free functions already merged into this module),
    /// or (b) any module in the cross-module `sig_table`.
    /// Used for disambiguation before full resolution.
    fn is_known_fn(&self, name: &str) -> bool {
        self.sig.fn_decls.contains_key(name)
            || !self.sig_table.find_fn_modules(name).is_empty()
    }

    /// U.2.3.3: overload set for `(type, method)`, base (`sig`) ∪ synth overlay.
    /// For any (type, method) the overloads live in EXACTLY ONE source (synth is
    /// registered only when base lacks the method), so synth-first ∥ base is
    /// collision-free; both Vecs preserve declaration order.
    fn method_overloads(&self, type_name: &str, method: &str) -> Option<&Vec<&'a FnDecl>> {
        self.synth_methods
            .get(type_name)
            .and_then(|m| m.get(method))
            .or_else(|| self.sig.method_overloads(type_name, method))
    }

    /// U.2.3.3: whether any method (any name) is declared on `type_name`,
    /// base (`sig`) ∪ synth overlay (legacy `method_table.contains_key`).
    fn type_has_any_method(&self, type_name: &str) -> bool {
        self.sig.has_type(type_name) || self.synth_methods.contains_key(type_name)
    }

    /// Plan 126.2 Ф.1: synthesize + register auto-derive methods into
    /// `method_table`. See call site in `build` for rationale.
    ///
    /// Idempotent w.r.t. user methods: a protocol method that T already
    /// provides explicitly (present in `method_table`) is never synthesized
    /// (user code wins). Synthesized `FnDecl`s carry `compiler_generated = true`
    /// (set by `auto_derive::make_synth_method`) so downstream passes can
    /// distinguish them.
    fn register_synthesized_methods(
        module: &'a Module,
        synth_arena: &'a FnDeclArena,
        types: &HashMap<String, &'a TypeDecl>,
        base_methods: &HashMap<String, HashMap<String, Vec<&'a FnDecl>>>,
        synth_methods: &mut HashMap<String, HashMap<String, Vec<&'a FnDecl>>>,
    ) {
        use crate::protocols::auto_derive::DeriveQuery as _;
        // Two-phase: phase 1 synthesizes against the immutable BASE methods
        // (`base_methods` = `sig.method_table`; DeriveQuery reads it for field
        // eligibility + user-method coverage — user wins); phase 2 inserts the
        // resulting `&'a FnDecl`s into the `synth_methods` overlay (U.2.3.3 F2).
        let mut pending: Vec<(String, &'a FnDecl)> = Vec::new();
        {
            // Local DeriveQuery over the already-built `types` + BASE `method_table`.
            // Decouples synthesis from the not-yet-constructed `TypeCheckCtx`.
            let query = BuildTimeDeriveQuery { types, method_table: base_methods };
            for item in &module.items {
                let Item::Type(td) = item else { continue; };
                if td.impl_protocols.is_empty() { continue; }
                for proto_name in &td.impl_protocols {
                    if !crate::protocols::auto_derive::is_builtin_protocol(proto_name) {
                        continue;
                    }
                    let Some(method_name) =
                        crate::protocols::auto_derive::builtin_protocol_method(proto_name)
                    else { continue; };
                    // User wins: skip if T already provides method explicitly.
                    if query.type_provides_method(&td.name, method_name) {
                        continue;
                    }
                    let mut derive_ctx =
                        crate::protocols::auto_derive::AutoDeriveCtx::new(&query);
                    let synthesized = match crate::protocols::auto_derive::synthesize_method(
                        &mut derive_ctx, td, proto_name,
                    ) {
                        Ok(fd) => fd,
                        // Registration-only: diagnostics emitted by
                        // verify_impl_protocols. Skip failures silently.
                        Err(_) => continue,
                    };
                    let fd_ref: &'a FnDecl = synth_arena.alloc(synthesized);
                    pending.push((td.name.clone(), fd_ref));
                }
            }
        }
        // Phase 2: insert into the synth overlay. Same key convention as user
        // instance methods: f.name (the protocol method bare name, e.g. "equal"/"hash").
        for (type_name, fd_ref) in pending {
            let entry = synth_methods
                .entry(type_name)
                .or_default()
                .entry(fd_ref.name.clone())
                .or_default();
            // Guard против дубля: не вставляем второй synthesized FnDecl
            // с тем же именем.
            let already = entry.iter().any(|f| {
                f.compiler_generated && f.name == fd_ref.name
            });
            if !already {
                entry.push(fd_ref);
            }
        }
    }

    /// Plan 138.2 Ф.0c (D29 method-level shadow): is `fd` a method that came
    /// from an imported generic type the user has shadowed with a different
    /// arity? Such methods carry the import's carrier arity (`Vec[T]` →
    /// receiver.generics.len() == 1) which differs from the user's redeclared
    /// arity (`type Vec { x, y }` → 0). A method the user wrote on their own
    /// redeclared type would carry the matching carrier arity and is kept.
    fn is_shadowed_import_method(&self, fd: &FnDecl) -> bool {
        if self.user_shadowed_generic_types.is_empty() {
            return false;
        }
        let Some(recv) = &fd.receiver else { return false; };
        match self.user_shadowed_generic_types.get(&recv.type_name) {
            Some(&user_arity) => recv.generics.len() != user_arity,
            None => false,
        }
    }

    fn check_module(&self, module: &Module, errors: &mut Vec<Diagnostic>) {
        // Plan 160 (D281) Ф.2: set current_module for module-boundary checks.
        // Restored to empty Vec on scope exit via CurrentModuleGuard RAII.
        let _module_guard = CurrentModuleGuard::set(self, module.name.clone());

        // Plan 91.9 (D186): verify `#impl(P1 + P2 + ...)` annotations.
        // Для каждого type T с impl_protocols, проверяем что:
        // 1. Каждый P в списке действительно protocol-тип (E_UNKNOWN_PROTOCOL).
        // 2. T provides каждый метод P либо напрямую (explicit `fn T @method`),
        //    либо синтезируемо через P's default body (`default_body_calls_satisfy_for`).
        // Missing methods → E_IMPL_MISSING_METHODS со списком и hint'ом.
        for item in &module.items {
            if let Item::Type(td) = item {
                if td.impl_protocols.is_empty() { continue; }
                self.verify_impl_protocols(td, errors);
            }
        }

        // Plan 154.1 (D268): verify method-level `#impl(P1 + P2 + ...)` annotations
        // (`#impl(Debug)` directly before a `fn T @m`). Opt-in: a method without
        // `#impl` is unaffected (structural conformance unchanged). See
        // `verify_method_impl_protocols` for the 3 error codes.
        for item in &module.items {
            if let Item::Fn(fd) = item {
                if fd.impl_protocols.is_empty() { continue; }
                self.verify_method_impl_protocols(fd, errors);
            }
        }

        // Plan 91.8a.2 part 3 (D183 amendment, Q4 strict): E_BLANKET_IDENTITY_OVERRIDE.
        // Identity From blanket `fn[T] T.from(t T) -> T => t` declared в prelude.
        // Override запрещён: попытка явно объявить `fn TypeName.from(t TypeName) -> TypeName`
        // (identity case на конкретном типе) — error.
        for item in &module.items {
            if let Item::Fn(fd) = item {
                if let Some(recv) = &fd.receiver {
                    if matches!(recv.kind, ReceiverKind::Static)
                        && fd.name == "from"
                        && fd.params.len() == 1
                        && fd.generics.is_empty()
                    {
                        let recv_type = &recv.type_name;
                        // Param type matches receiver type? (identity signature)
                        let param_is_recv = matches!(
                            &fd.params[0].ty,
                            TypeRef::Named { path, .. }
                                if path.len() == 1 && path[0] == *recv_type
                        );
                        let return_is_recv = matches!(
                            &fd.return_type,
                            Some(TypeRef::Named { path, .. })
                                if path.len() == 1 && (path[0] == *recv_type || path[0] == "Self")
                        );
                        if param_is_recv && return_is_recv {
                            errors.push(Diagnostic::new(
                                format!(
                                    "[E_BLANKET_IDENTITY_OVERRIDE] cannot override identity \
                                     `fn[T] T.from(t T) -> T => t` blanket for type `{}`. \
                                     Identity is identity (D183 amendment Q4 strict, \
                                     D9 single canonical path). Remove this declaration; \
                                     `{0}.from({0})` works automatically via blanket.",
                                    recv_type
                                ),
                                fd.span,
                            ));
                        }
                    }
                }
            }
        }
        // Plan 114.4 / D199 + Plan 148 Ф.3: constexpr-eligibility sets, shared
        // by the `const` enforcement (`E_CONST_NOT_CONSTEXPR`, reverse) and the
        // `ro` partition enforcement (`E_RO_FOR_CONSTEXPR_PREFER_CONST`, forward).
        // Both directions MUST use the same predicate so they can never
        // disagree about what «constexpr» means.
        let partition_known_consts: HashSet<String> = module
            .items
            .iter()
            .filter_map(|it| match it {
                Item::Const(c) => Some(c.name.clone()),
                _ => None,
            })
            .collect();
        // Plan 114.4.2 D199 + 114.4.3 Ф.5 V2: const fn names
        // (including aliases — `const ALIAS = const_fn`).
        let partition_const_fn_names: HashSet<String> = {
            let mut s: HashSet<String> = module
                .items
                .iter()
                .filter_map(|it| match it {
                    Item::Fn(fd) => {
                        let is_const = fd.return_is_const
                            || fd.params.iter().any(|p| p.is_const);
                        if is_const { Some(fd.name.clone()) } else { None }
                    }
                    _ => None,
                })
                .collect();
            for _ in 0..10 {
                let mut added = false;
                for it in &module.items {
                    if let Item::Const(c) = it {
                        if let crate::ast::ExprKind::Ident(target) = &c.value.kind {
                            if s.contains(target) && !s.contains(&c.name) {
                                s.insert(c.name.clone());
                                added = true;
                            }
                        }
                    }
                }
                if !added { break; }
            }
            s
        };
        // D215 amend: named tuple constructor names for constexpr recognition.
        let partition_named_tuple_names: HashSet<String> = module
            .items
            .iter()
            .filter_map(|it| match it {
                Item::Type(td) => {
                    if matches!(td.kind, crate::ast::TypeDeclKind::NamedTuple(_)) {
                        Some(td.name.clone())
                    } else {
                        None
                    }
                }
                _ => None,
            })
            .collect();
        for item in &module.items {
            match item {
                Item::Fn(fd) => {
                    // Plan 138.2 Ф.0c (D29 method-level shadow): when the user
                    // redeclared a generic type with a different arity (e.g.
                    // `type Vec { x, y }` over imported `type Vec[T]`), the
                    // import's merged methods carry `Vec[T]` type-refs that
                    // arity-check (E7310) against the user's non-generic decl.
                    // Skip those merged methods — user wins entirely (D29).
                    if self.is_shadowed_import_method(fd) {
                        continue;
                    }
                    self.check_fn(fd, errors)
                }
                Item::Type(td) => self.check_type_decl(td, errors),
                Item::Const(cd) => {
                    let empty = HashSet::new();
                    if let Some(t) = &cd.ty {
                        self.walk_typeref(t, &empty, errors);
                    }
                    self.walk_expr(&cd.value, &empty, errors);
                    // Plan 114.4 Ф.1: strict constexpr-only enforcement.
                    // `const X = expr` принимает только literal-eligible
                    // RHS — арифметику над literals, record-literal из
                    // constexpr-fields, references на другие const.
                    // Runtime calls / effects / allocations / non-const
                    // refs → E_CONST_NOT_CONSTEXPR.
                    if let Err(d) = check_const_constexpr_ex(
                        &cd.value, &partition_known_consts, &partition_const_fn_names,
                        &partition_named_tuple_names,
                    ) {
                        errors.push(d);
                    }
                }
                Item::Test(t) => {
                    // Plan 124.6 (D224 §4): set test-block context so that
                    // priv_access_allowed_base applies rules 2 + 3 (same-module
                    // implicit grant + explicit test_access list). Guard
                    // restores previous state on drop.
                    let _tb_guard = TestBlockGuard::enter(self, t.test_access.clone());
                    let empty = HashSet::new();
                    self.walk_block(&t.body, &empty, errors);
                }
                // Plan 148 Ф.3 ([M-114.4-strict-partition]): module-level `ro`
                // bindings are subject to the strict partition forward direction.
                // A constexpr-eligible `ro X = …` must instead be `const X = …`.
                Item::Let(ld) => {
                    if let Some(d) = check_ro_module_partition(
                        ld, &partition_known_consts, &partition_const_fn_names,
                        &partition_named_tuple_names,
                    ) {
                        errors.push(d);
                    }
                }
                Item::Bench(_) | Item::Lemma(_) => {}
            }
        }
        // Ф.1: assignability — отдельный scope-aware проход по телам
        // (var-типы локальных переменных нужны только здесь).
        for item in &module.items {
            match item {
                Item::Fn(fd) => {
                    // Plan 138.2 Ф.0c: same method-level shadow-skip as the
                    // arity pass above — merged methods of a user-shadowed
                    // generic type are not the user's, skip body-checking them.
                    if self.is_shadowed_import_method(fd) {
                        continue;
                    }
                    self.f1_check_fn(fd, errors)
                }
                Item::Test(t) => {
                    // Plan 124.6 (D224 §4): propagate test-block context into
                    // the f1 assignability pass too (handles priv record-init
                    // and write checks that fire from f1_check_assign_let).
                    let _tb_guard = TestBlockGuard::enter(self, t.test_access.clone());
                    let gs: HashSet<String> = HashSet::new();
                    let mut scope: HashMap<String, TypeRef> = HashMap::new();
                    self.f1_block(&t.body, &gs, &mut scope, errors);
                }
                Item::Const(cd) => {
                    let gs: HashSet<String> = HashSet::new();
                    let mut scope: HashMap<String, TypeRef> = HashMap::new();
                    if let Some(ann) = &cd.ty {
                        // A `const` binding is immutable (ro content-view).
                        self.f1_check_assign_let(
                            &cd.value, ann, &cd.name, false, &gs, &scope, errors,
                        );
                    }
                    self.f1_expr(&cd.value, &gs, &mut scope, errors);
                }
                _ => {}
            }
        }

        // Plan 110.1.2 (D188 / D196): Consumable[E] protocol satisfaction check.
        // Для каждого `Stmt::ConsumeScope { init, body, .. }` проверяем что
        // init expr resolves к типу с `on_exit` method. Если нет — emit
        // [D188-not-consumable] error. Полный D196 (Result/Option unwrap,
        // conditional, method chain — non-trivial type inference) — staged
        // delivery: дополнительные формы validated в Plan 110.1.3 / 110.1.4.
        for item in &module.items {
            match item {
                Item::Fn(fd) => {
                    match &fd.body {
                        FnBody::Block(b) => self.check_consume_scopes_in_block(b, errors),
                        FnBody::Expr(e) => self.check_consume_scopes_in_expr(e, errors),
                        FnBody::External => {}
                    }
                }
                Item::Test(t) => self.check_consume_scopes_in_block(&t.body, errors),
                Item::Bench(b) => {
                    for s in &b.setup { self.check_consume_scopes_in_stmt(s, errors); }
                    self.check_consume_scopes_in_block(&b.measure_body, errors);
                    for s in &b.teardown { self.check_consume_scopes_in_stmt(s, errors); }
                }
                _ => {}
            }
        }
    }

    /// Plan 110.1.2 (D188): recursive walk через Block для ConsumeScope check.
    fn check_consume_scopes_in_block(&self, b: &Block, errors: &mut Vec<Diagnostic>) {
        for s in &b.stmts {
            self.check_consume_scopes_in_stmt(s, errors);
        }
        if let Some(t) = &b.trailing {
            self.check_consume_scopes_in_expr(t, errors);
        }
    }

    /// Plan 110.1.2 (D188): walk Stmt looking for ConsumeScope, recurse into children.
    fn check_consume_scopes_in_stmt(&self, s: &Stmt, errors: &mut Vec<Diagnostic>) {
        match s {
            Stmt::ConsumeScope { binding, init, body, .. } => {
                self.validate_consume_scope_init(init, errors);
                // Plan 110.1.5 (D188 R2 enforcement at compile time):
                // detect manual `binding.on_exit(...)` calls в body.
                // Runtime exactly-once guard prevents double dispatch;
                // здесь — compile-time gate чтобы избегать runtime panic.
                self.check_no_manual_on_exit_call_in_block(binding, body, errors);
                self.check_consume_scopes_in_expr(init, errors);
                self.check_consume_scopes_in_block(body, errors);
            }
            Stmt::Let(d) => self.check_consume_scopes_in_expr(&d.value, errors),
            // Plan 114.4 Ф.2: scope-local const — walk value for nested ConsumeScope.
            Stmt::Const(d) => self.check_consume_scopes_in_expr(&d.value, errors),
            Stmt::Expr(e) => self.check_consume_scopes_in_expr(e, errors),
            Stmt::Assign { target, value, .. } => {
                self.check_consume_scopes_in_expr(target, errors);
                self.check_consume_scopes_in_expr(value, errors);
            }
            Stmt::Return { value, .. } => {
                if let Some(v) = value { self.check_consume_scopes_in_expr(v, errors); }
            }
            Stmt::Throw { value, .. } => self.check_consume_scopes_in_expr(value, errors),
            Stmt::Defer { body, .. } | Stmt::ErrDefer { body, .. }
            | Stmt::OkDefer { body, .. } | Stmt::DeferWithResult { body, .. } => {
                self.check_consume_scopes_in_expr(body, errors);
            }
            Stmt::AssertStatic { expr, .. } | Stmt::Assume { expr, .. } => {
                self.check_consume_scopes_in_expr(expr, errors);
            }
            Stmt::Break(_) | Stmt::Continue(_) | Stmt::Reveal { .. }
            | Stmt::Apply { .. } | Stmt::Calc { .. } => {}
            // Plan 136: tuple destructuring assignment.
            Stmt::TupleAssign { lhs, rhs, .. } => {
                for e in lhs { self.check_consume_scopes_in_expr(e, errors); }
                for e in rhs { self.check_consume_scopes_in_expr(e, errors); }
            }
        }
    }

    /// Plan 110.1.2 (D188): walk Expr looking for nested ConsumeScope in
    /// bodies (lambdas, blocks, if-then-else, match arms, etc).
    fn check_consume_scopes_in_expr(&self, e: &Expr, errors: &mut Vec<Diagnostic>) {
        use crate::ast::ExprKind;
        match &e.kind {
            ExprKind::Block(b) => self.check_consume_scopes_in_block(b, errors),
            ExprKind::If { cond, then, else_, .. } => {
                self.check_consume_scopes_in_expr(cond, errors);
                self.check_consume_scopes_in_block(then, errors);
                if let Some(eb) = else_ {
                    match eb {
                        crate::ast::ElseBranch::Block(b) => self.check_consume_scopes_in_block(b, errors),
                        crate::ast::ElseBranch::If(ei) => self.check_consume_scopes_in_expr(ei, errors),
                    }
                }
            }
            ExprKind::While { cond, body, .. } => {
                self.check_consume_scopes_in_expr(cond, errors);
                self.check_consume_scopes_in_block(body, errors);
            }
            ExprKind::For { iter, body, .. } => {
                self.check_consume_scopes_in_expr(iter, errors);
                self.check_consume_scopes_in_block(body, errors);
            }
            ExprKind::Loop { body, .. } => self.check_consume_scopes_in_block(body, errors),
            ExprKind::Call { func, args, .. } => {
                self.check_consume_scopes_in_expr(func, errors);
                for a in args {
                    match a {
                        crate::ast::CallArg::Item(e) | crate::ast::CallArg::Spread(e) => {
                            self.check_consume_scopes_in_expr(e, errors);
                        }
                        _ => {}
                    }
                }
            }
            ExprKind::Try(e) | ExprKind::Bang(e) => self.check_consume_scopes_in_expr(e, errors),
            ExprKind::Coalesce(a, b) => {
                self.check_consume_scopes_in_expr(a, errors);
                self.check_consume_scopes_in_expr(b, errors);
            }
            ExprKind::Binary { left, right, .. } => {
                self.check_consume_scopes_in_expr(left, errors);
                self.check_consume_scopes_in_expr(right, errors);
            }
            ExprKind::Unary { operand, .. } => self.check_consume_scopes_in_expr(operand, errors),
            ExprKind::Member { obj, .. } => self.check_consume_scopes_in_expr(obj, errors),
            // Lambda / closure bodies — separate scopes; walk their bodies too.
            ExprKind::Lambda { body, .. } => self.check_consume_scopes_in_expr(body, errors),
            _ => {}
        }
    }

    /// Plan 110.1.2 (D188 / D196): validate init expression's type implements
    /// Consumable. Uses простой heuristic для type inference (Type.method() →
    /// return type; record literal → type; ?/!! → recurse). Полный inference
    /// (method chain, conditional, generic) — staged delivery 110.1.3+.
    fn validate_consume_scope_init(&self, init: &Expr, errors: &mut Vec<Diagnostic>) {
        // Plan 110.1.3 (D196 form 5 — wrapped без unwrap): detect raw
        // Option[T] / Result[T,_] returning expressions WITHOUT ?/!!
        // unwrap. Emit specific D196-wrapped-init-needs-unwrap hint.
        if let Some(wrapped) = self.detect_wrapped_init_typeref(init) {
            errors.push(Diagnostic::new(
                format!(
                    "[D196-wrapped-init-needs-unwrap] `consume X = expr {{ body }}` \
                     init expr returns `{wrapped}[T, ...]` без unwrap. Required: \
                     either `consume X = expr!! {{ body }}` (Option unwrap), \
                     `consume X = expr? {{ body }}` (Result unwrap with Fail \
                     propagation), or distinguish None case explicitly через \
                     `if Some(X) = maybe_X() {{ consume X = X {{ ... }} }}`.",
                    wrapped = wrapped
                ),
                init.span,
            ));
            return;
        }
        // Plan 110.1.3 (D196 form 3 — divergent conditional): if/match init
        // with branches returning incompatible Consumable types.
        if let Some((t1, t2)) = self.detect_divergent_consumable(init) {
            errors.push(Diagnostic::new(
                format!(
                    "[D196-divergent-consumable] `consume X = if cond {{ ... }} \
                     else {{ ... }} {{ body }}` branches return divergent \
                     Consumable types: `{t1}` vs `{t2}`. Branches must return \
                     compatible type. Extract в polymorphic wrapper type \
                     или unify branches.",
                    t1 = t1, t2 = t2
                ),
                init.span,
            ));
            return;
        }
        let Some(type_name) = self.infer_consume_init_type(init) else {
            // Тип не выводится простыми heuristic'ами — staged delivery
            // через codegen-gate D188-codegen-not-yet-implemented. Полное
            // покрытие в Plan 110.1.4 / 110.1.3.
            return;
        };
        // Special case: `never` (bottom-тип) — никогда не resolved init
        // type, skip без ошибки.
        if type_name == "never" || type_name == "Never" {
            return;
        }
        // Look up on_exit method on the type.
        let has_on_exit = self.method_overloads(&type_name, "on_exit").is_some();
        if !has_on_exit {
            // Тип known? Если не known — это либо primitive (`int`/`str`)
            // либо unresolved (caught by name resolution). Skip primitive
            // случаи silently.
            let is_known_type = self.types.contains_key(&type_name)
                || self.type_has_any_method(&type_name);
            // Even for primitive types like `int`/`str` — нет on_exit → error.
            // Но diagnostic должен быть полезный (suggest implement).
            if is_known_type || self.type_has_any_method(&type_name) {
                let diag = Diagnostic::new(
                    format!(
                        "[D188-not-consumable] type `{name}` does not implement `Consumable[E]` \
                         (method `on_exit` missing). \
                         To use `consume X = expr {{ body }}` scope-block, type must declare:\n  \
                         `fn {name} consume @on_exit(outcome ScopeOutcome) Fail[E] -> () => {{ ... }}`\n\
                         where `E` is the cleanup-error type (or `never` for infallible — D194).\n\
                         Alternative: use raw `consume X = expr` (D180 linear binding) without block.",
                        name = type_name
                    ),
                    init.span,
                ).with_note(format!(
                    "Plan 110.6.1: see docs/idiom/consume-scope-cleanup.md \
                     Q-consumable-protocol for decision tree + implementation template. \
                     For infallible cleanup (Mutex/Sem/Lock) use `Consumable[never]` — \
                     no Fail[E] effect (D194 hot-path eligible)."
                ));
                errors.push(diag);
            }
        } else {
            // on_exit existsует — validate signature (Plan 110.1.2 §D188-malformed-on-exit).
            // Минимальная проверка: первый param должен быть ScopeOutcome.
            // Глубокая validation (Fail[E] check, return type ()) — 110.1.3.
            self.validate_on_exit_signature(&type_name, init.span, errors);
        }
    }

    /// Plan 110.1.2 / refine (D188-malformed-on-exit) + 110.9.5 V1.1 strict:
    /// on_exit signature check.
    /// Verifies:
    /// - Param[0] is `outcome ScopeOutcome`.
    /// - Exactly 1 param (D188 protocol contract).
    /// - Return type is `()` or absent (D188 protocol contract).
    /// - Effects are either empty (Consumable[never]) or `Fail[E]` only
    ///   (no other effects).
    /// - No generic parameters (cleanup methods on concrete types).
    fn validate_on_exit_signature(&self, type_name: &str, init_span: Span, errors: &mut Vec<Diagnostic>) {
        let Some(decls) = self.method_overloads(type_name, "on_exit") else { return; };
        for decl in decls {
            // Param[0] must be `outcome ScopeOutcome`.
            let first_param_ok = decl.params.first()
                .map(|p| matches!(&p.ty, TypeRef::Named { path, .. }
                    if path.last().map_or(false, |s| s == "ScopeOutcome")))
                .unwrap_or(false);
            if !first_param_ok {
                errors.push(Diagnostic::new(
                    format!(
                        "[D188-malformed-on-exit] `fn {tn} @on_exit(...)` signature invalid: \
                         first parameter must be `outcome ScopeOutcome` (D188 protocol contract). \
                         Correct form: \
                         `fn {tn} consume @on_exit(outcome ScopeOutcome) Fail[E] -> () => {{ ... }}`. \
                         (Diagnostic emitted at `consume {{}}` use-site for context.)",
                        tn = type_name
                    ),
                    init_span,
                ));
                continue;
            }

            // Exactly 1 param (D188 protocol contract).
            if decl.params.len() != 1 {
                errors.push(Diagnostic::new(
                    format!(
                        "[D188-malformed-on-exit] `fn {tn} @on_exit(...)` has {n} params; \
                         protocol requires exactly 1 (`outcome ScopeOutcome`). \
                         Remove extra parameters; resource state available via `@`.",
                        tn = type_name, n = decl.params.len()
                    ),
                    init_span,
                ));
                continue;
            }

            // Plan 110.9.5 V1.1 [M-110.9.5-on-exit-strict-signature] +
            // Plan 110.9.5.a (2026-06-05): canonical strict check.
            //
            // **Pre-110.9.5.a state:** pragmatic accept-both allowed Tuple([]),
            // Named("unit"), and TypeRef::Unit equivalents. Documented as
            // "backward-compat без parser canonicalization".
            //
            // **110.9.5.a finding:** Recon (Workflow `wf_ccdccc85-007`)
            // confirmed parser ALREADY canonicalizes `()` к `TypeRef::Unit(Span)`
            // (parser/mod.rs line 5031). NO Tuple([]) или Named("unit")
            // construction sites в parser. The pragmatic accept-both was
            // defensive code for a non-existent variance. Removing accept-both
            // aligns with peer is_unit_or_none() at line 9137+ which already
            // checks ONLY TypeRef::Unit.
            //
            // Strict checks (unchanged from V1.1):
            //   (a) Return type must be TypeRef::Unit (canonical form).
            //   (b) Effects must be subset of `{ Fail[E] }`.
            //   (c) No generic params allowed.
            //
            // Permitted forms: TypeRef::Unit и TypeRef::Readonly(Unit) — последний
            // transparent wrapper (readonly modifier shouldn't change semantic equality).
            fn is_unit_tr(t: &TypeRef) -> bool {
                match t {
                    TypeRef::Unit(_) => true,
                    TypeRef::Readonly(inner, _) => is_unit_tr(inner),
                    _ => false,
                }
            }
            let ret_ok = match &decl.return_type {
                None => true, // implicit Unit → OK.
                Some(rt) => is_unit_tr(rt),
            };
            if !ret_ok {
                errors.push(Diagnostic::new(
                    format!(
                        "[D188-malformed-on-exit] `fn {tn} @on_exit(...)` return type \
                         invalid (Plan 110.9.5 V1.1): protocol requires `()` (Unit) return. \
                         Got `{rt}`. Correct: `fn {tn} consume @on_exit(outcome ScopeOutcome) \
                         Fail[E] -> () => {{ ... }}` (or omit `-> ()`).",
                        tn = type_name,
                        rt = decl.return_type.as_ref()
                            .map(|t| format!("{:?}", t))
                            .unwrap_or_else(|| "<missing>".to_string()),
                    ),
                    init_span,
                ));
                continue;
            }
            // 2. Effects must contain at most Fail[E].
            let effects_ok = decl.effects.iter().all(|eff| {
                matches!(
                    eff,
                    TypeRef::Named { path, .. }
                        if path.last().map_or(false, |s| s == "Fail")
                )
            });
            if !effects_ok {
                errors.push(Diagnostic::new(
                    format!(
                        "[D188-malformed-on-exit] `fn {tn} @on_exit(...)` effects list \
                         invalid (Plan 110.9.5 V1.1): protocol allows only `Fail[E]` effect \
                         (or no effects). Other effects (handler invocations, `parks`/`wakes`, \
                         capability requirements) violate cleanup contract. Got: {effs:?}.",
                        tn = type_name,
                        effs = decl.effects
                    ),
                    init_span,
                ));
                continue;
            }
            // 3. No generic params (would imply per-call mono за scope of cleanup).
            if !decl.generics.is_empty() {
                errors.push(Diagnostic::new(
                    format!(
                        "[D188-malformed-on-exit] `fn {tn} @on_exit(...)` declares generic \
                         params `[{gens}]` (Plan 110.9.5 V1.1): protocol forbids generics \
                         on cleanup methods — resource-state types already concrete by \
                         construction.",
                        tn = type_name,
                        gens = decl.generics.iter().map(|g| g.name.clone()).collect::<Vec<_>>().join(", ")
                    ),
                    init_span,
                ));
                continue;
            }
        }
    }

    /// Plan 110.1.5 (D188 R2): detect manual `binding.on_exit(...)` calls
    /// в ConsumeScope body. Auto on_exit dispatch happens at scope-exit;
    /// manual call → double invocation → runtime panic (R2 exactly-once
    /// violation). Compile-time gate preferred to runtime panic.
    fn check_no_manual_on_exit_call_in_block(&self, binding: &str, b: &Block, errors: &mut Vec<Diagnostic>) {
        for s in &b.stmts {
            self.check_no_manual_on_exit_call_in_stmt(binding, s, errors);
        }
        if let Some(t) = &b.trailing {
            self.check_no_manual_on_exit_call_in_expr(binding, t, errors);
        }
    }

    fn check_no_manual_on_exit_call_in_stmt(&self, binding: &str, s: &Stmt, errors: &mut Vec<Diagnostic>) {
        match s {
            Stmt::Let(d) => self.check_no_manual_on_exit_call_in_expr(binding, &d.value, errors),
            Stmt::Expr(e) => self.check_no_manual_on_exit_call_in_expr(binding, e, errors),
            Stmt::Assign { target, value, .. } => {
                self.check_no_manual_on_exit_call_in_expr(binding, target, errors);
                self.check_no_manual_on_exit_call_in_expr(binding, value, errors);
            }
            Stmt::Return { value, .. } => {
                if let Some(v) = value { self.check_no_manual_on_exit_call_in_expr(binding, v, errors); }
            }
            Stmt::Throw { value, .. } => self.check_no_manual_on_exit_call_in_expr(binding, value, errors),
            Stmt::Defer { body, .. } | Stmt::ErrDefer { body, .. }
            | Stmt::OkDefer { body, .. } | Stmt::DeferWithResult { body, .. } => {
                self.check_no_manual_on_exit_call_in_expr(binding, body, errors);
            }
            Stmt::ConsumeScope { init, body, binding: inner_binding, .. } => {
                self.check_no_manual_on_exit_call_in_expr(binding, init, errors);
                // Nested consume scope с inner binding NEW — outer `binding`
                // check still applies inside (если inner body references
                // outer's binding manually — same violation).
                self.check_no_manual_on_exit_call_in_block(binding, body, errors);
                // Дополнительно: recurse с inner binding (D197 re-entrance).
                self.check_no_manual_on_exit_call_in_block(inner_binding, body, errors);
            }
            Stmt::AssertStatic { expr, .. } | Stmt::Assume { expr, .. } => {
                self.check_no_manual_on_exit_call_in_expr(binding, expr, errors);
            }
            _ => {}
        }
    }

    fn check_no_manual_on_exit_call_in_expr(&self, binding: &str, e: &Expr, errors: &mut Vec<Diagnostic>) {
        use crate::ast::ExprKind;
        // Detect `binding.on_exit(...)` call: Call { func: Member { obj: Ident(binding), name: "on_exit" }, ... }
        if let ExprKind::Call { func, .. } = &e.kind {
            if let ExprKind::Member { obj, name, .. } = &func.kind {
                if name == "on_exit" {
                    if let ExprKind::Ident(obj_name) = &obj.kind {
                        if obj_name == binding {
                            errors.push(Diagnostic::new(
                                format!(
                                    "[D188-r2-manual-on-exit] `{binding}.on_exit(...)` cannot be \
                                     called manually from inside `consume {binding} = ... {{ body }}` \
                                     scope-block body. Auto on_exit dispatch на scope exit \
                                     гарантирует exactly-once invariant (D188 R2). Manual call \
                                     → double invocation → runtime panic. \
                                     Remove the explicit call; scope-exit will dispatch on_exit \
                                     с appropriate ScopeOutcome value.",
                                    binding = binding
                                ),
                                e.span,
                            ));
                        }
                    }
                }
            }
        }
        // Recurse into children regardless.
        self.check_no_manual_on_exit_recurse(binding, e, errors);
    }

    fn check_no_manual_on_exit_recurse(&self, binding: &str, e: &Expr, errors: &mut Vec<Diagnostic>) {
        use crate::ast::ExprKind;
        match &e.kind {
            ExprKind::Block(b) => self.check_no_manual_on_exit_call_in_block(binding, b, errors),
            ExprKind::Call { func, args, .. } => {
                self.check_no_manual_on_exit_call_in_expr(binding, func, errors);
                for a in args {
                    match a {
                        crate::ast::CallArg::Item(ae) | crate::ast::CallArg::Spread(ae) => {
                            self.check_no_manual_on_exit_call_in_expr(binding, ae, errors);
                        }
                        _ => {}
                    }
                }
            }
            ExprKind::If { cond, then, else_, .. } => {
                self.check_no_manual_on_exit_call_in_expr(binding, cond, errors);
                self.check_no_manual_on_exit_call_in_block(binding, then, errors);
                if let Some(eb) = else_ {
                    match eb {
                        crate::ast::ElseBranch::Block(b) => self.check_no_manual_on_exit_call_in_block(binding, b, errors),
                        crate::ast::ElseBranch::If(ei) => self.check_no_manual_on_exit_call_in_expr(binding, ei, errors),
                    }
                }
            }
            ExprKind::While { cond, body, .. } => {
                self.check_no_manual_on_exit_call_in_expr(binding, cond, errors);
                self.check_no_manual_on_exit_call_in_block(binding, body, errors);
            }
            ExprKind::For { iter, body, .. } => {
                self.check_no_manual_on_exit_call_in_expr(binding, iter, errors);
                self.check_no_manual_on_exit_call_in_block(binding, body, errors);
            }
            ExprKind::Try(inner) | ExprKind::Bang(inner) => self.check_no_manual_on_exit_call_in_expr(binding, inner, errors),
            ExprKind::Coalesce(a, b) => {
                self.check_no_manual_on_exit_call_in_expr(binding, a, errors);
                self.check_no_manual_on_exit_call_in_expr(binding, b, errors);
            }
            ExprKind::Binary { left, right, .. } => {
                self.check_no_manual_on_exit_call_in_expr(binding, left, errors);
                self.check_no_manual_on_exit_call_in_expr(binding, right, errors);
            }
            ExprKind::Unary { operand, .. } => self.check_no_manual_on_exit_call_in_expr(binding, operand, errors),
            ExprKind::Member { obj, .. } => self.check_no_manual_on_exit_call_in_expr(binding, obj, errors),
            _ => {}
        }
    }

    /// Plan 110.1.2 / 110.1.3 (D196): infer the resulting type name from
    /// `consume X = INIT { body }` init expression. Heuristics:
    /// - `Type.method(args)` → look up method's return type via method_table.
    /// - `Type { fields }` → type name directly.
    /// - `expr?` / `expr!!` → если inner returns `Result[T,E]` / `Option[T]`,
    ///   unwrap до T (D196 form 2: Result/Option unwrap).
    /// - `expr as Type` → cast target.
    /// - Other forms → None (staged delivery — full inference 110.1.4).
    fn infer_consume_init_type(&self, e: &Expr) -> Option<String> {
        self.infer_consume_init_typeref(e)
            .as_ref()
            .and_then(Self::typeref_to_name)
    }

    /// Extract final type name from TypeRef::Named (last path segment).
    fn typeref_to_name(t: &TypeRef) -> Option<String> {
        if let TypeRef::Named { path, .. } = t {
            path.last().cloned()
        } else {
            None
        }
    }

    /// Plan 110.1.3 (D196 form 5): detect if init returns raw `Option[T]`
    /// or `Result[T,_]` без unwrap operator. Returns wrapper name если
    /// detected, None если init is direct (unwrapped) or non-wrapped type.
    fn detect_wrapped_init_typeref(&self, init: &Expr) -> Option<String> {
        use crate::ast::ExprKind;
        // `?` and `!!` are unwrap operators — they're EXPLICITLY safe.
        if matches!(init.kind, ExprKind::Try(_) | ExprKind::Bang(_)) {
            return None;
        }
        // For direct Call (e.g., `try_new()` without `?`), inspect return type.
        if let ExprKind::Call { func, .. } = &init.kind {
            if let ExprKind::Path(parts) = &func.kind {
                if parts.len() >= 2 {
                    let type_name = &parts[parts.len() - 2];
                    let method_name = &parts[parts.len() - 1];
                    if let Some(decls) = self.method_overloads(type_name, method_name) {
                        if let Some(decl) = decls.first() {
                            if let Some(TypeRef::Named { path, .. }) = &decl.return_type {
                                if let Some(outer) = path.last() {
                                    if outer == "Option" || outer == "Result" {
                                        return Some(outer.clone());
                                    }
                                }
                            }
                        }
                    }
                }
            }
        }
        None
    }

    /// Plan 110.1.3 (D196 form 3): detect if/match init with branches
    /// returning incompatible Consumable types. Returns (t1, t2) pair если
    /// detected.
    fn detect_divergent_consumable(&self, init: &Expr) -> Option<(String, String)> {
        use crate::ast::ExprKind;
        if let ExprKind::If { then, else_, .. } = &init.kind {
            // Plan 125.1 D196 amend: divergent branch (`never` через любой
            // путь — trailing throw/interrupt/panic, stmt-position
            // throw/return, divergent call) не участвует в conflict-check —
            // bottom type subtype of any. Используем `block_diverges`
            // (полный stmts+trailing walk) вместо trailing-only check, и
            // SKIP (continue к following branch / return None) вместо
            // `?`-propagation abort.
            let then_diverges = block_diverges(then);
            let else_b = else_.as_ref()?;
            let else_diverges = match else_b {
                crate::ast::ElseBranch::Block(b) => block_diverges(b),
                crate::ast::ElseBranch::If(ei) => expr_diverges(ei),
            };
            // Если ЛЮБАЯ ветка diverges — пары для conflict-check нет.
            if then_diverges || else_diverges {
                return None;
            }
            // Both branches must end в expression returning Consumable.
            let then_ty = self.infer_block_trailing_typeref(then)?;
            let else_ty = match else_b {
                crate::ast::ElseBranch::Block(b) => self.infer_block_trailing_typeref(b)?,
                crate::ast::ElseBranch::If(ei) => self.infer_consume_init_typeref(ei)?,
            };
            let then_name = Self::typeref_to_name(&then_ty)?;
            let else_name = Self::typeref_to_name(&else_ty)?;
            // Plan 125.1 (Ф.3): defensive — Ф.3 уже фильтрует trailing-
            // divergent в "never" name, оставляем guard для symmetry.
            if then_name == "never" || else_name == "never" {
                return None;
            }
            if then_name != else_name {
                return Some((then_name, else_name));
            }
        }
        None
    }

    fn infer_block_trailing_typeref(&self, b: &crate::ast::Block) -> Option<TypeRef> {
        if let Some(t) = &b.trailing {
            // Plan 125.1 (Ф.3): trailing-divergence detection. По спеке D25
            // bottom-тип `never` propagates как тип блока, когда trailing
            // expression diverges (throw / interrupt / never-returning call).
            // Conservative: НЕ ходим по preceding stmts (только trailing).
            // Hookpoint feeds assignable() never-subtype branch из Ф.1.
            if Self::expr_diverges_at_top(t) {
                return Some(prim_ref("never", t.span));
            }
            self.infer_consume_init_typeref(t)
        } else {
            None
        }
    }

    /// Plan 125.1 (Ф.3): top-level divergence check для trailing expression.
    /// Возвращает true, если expression имеет тип `never` (D25 bottom):
    /// `throw e`, `interrupt v?`, или call к never-returning builtin
    /// (panic/exit/abort/unreachable). Conservative — не walks вложенные
    /// statements, только распознаёт top-level shape. Mirrors detection
    /// logic из `infer_expr_type` Ф.2 (без scope-зависимости).
    fn expr_diverges_at_top(e: &Expr) -> bool {
        use crate::ast::ExprKind;
        match &e.kind {
            ExprKind::Throw(_) | ExprKind::Interrupt(_) => true,
            ExprKind::Call { func, .. } => {
                if let ExprKind::Ident(name) = &func.kind {
                    matches!(name.as_str(), "panic" | "exit" | "abort" | "unreachable")
                } else {
                    false
                }
            }
            _ => false,
        }
    }

    /// Plan 110.1.3 (D196): infer full TypeRef для init expression. Используется
    /// для Result/Option unwrap (D196 form 2) — нужен дополнительный slot
    /// для unwrap'нутого T type-ref'а.
    fn infer_consume_init_typeref(&self, e: &Expr) -> Option<TypeRef> {
        use crate::ast::ExprKind;
        match &e.kind {
            ExprKind::Call { func, .. } => {
                match &func.kind {
                    ExprKind::Path(parts) if parts.len() >= 2 => {
                        let type_name = &parts[parts.len() - 2];
                        let method_name = &parts[parts.len() - 1];
                        let decls = self.method_overloads(type_name, method_name)?;
                        let decl = decls.first()?;
                        let rt = decl.return_type.as_ref()?;
                        // Self → receiver type substitution.
                        if let TypeRef::Named { path, .. } = rt {
                            if path.last().map_or(false, |s| s == "Self") {
                                return Some(TypeRef::Named {
                                    path: vec![type_name.clone()],
                                    generics: Vec::new(),
                                    span: e.span,
                                });
                            }
                        }
                        Some(rt.clone())
                    }
                    _ => None,
                }
            }
            ExprKind::RecordLit { type_name: Some(name), .. } => {
                Some(TypeRef::Named {
                    path: name.clone(),
                    generics: Vec::new(),
                    span: e.span,
                })
            }
            ExprKind::Try(inner) => {
                // D196 form 2 (?): unwrap Result[T, E] → T.
                let inner_ty = self.infer_consume_init_typeref(inner)?;
                if let TypeRef::Named { path, generics, .. } = &inner_ty {
                    if path.last().map_or(false, |s| s == "Result") && !generics.is_empty() {
                        return Some(generics[0].clone());
                    }
                    // Option[T] через ? тоже разворачивается (R/E aware).
                    if path.last().map_or(false, |s| s == "Option") && !generics.is_empty() {
                        return Some(generics[0].clone());
                    }
                }
                Some(inner_ty)
            }
            ExprKind::Bang(inner) => {
                // D196 form 2 (!!): unwrap Option[T] → T или Result[T,_] → T.
                let inner_ty = self.infer_consume_init_typeref(inner)?;
                if let TypeRef::Named { path, generics, .. } = &inner_ty {
                    if path.last().map_or(false, |s| s == "Option" || s == "Result") && !generics.is_empty() {
                        return Some(generics[0].clone());
                    }
                }
                Some(inner_ty)
            }
            ExprKind::As(_, ty) => Some(ty.clone()),
            ExprKind::Ident(_) | ExprKind::Path(_) => None,
            _ => None,
        }
    }

    // --- Ф.2: walk сигнатур ---------------------------------------------

    fn check_fn(&self, fd: &FnDecl, errors: &mut Vec<Diagnostic>) {
        // Plan 114.4.2 (D199): set flag для scope-local const skip
        // когда мы внутри const fn body. Body checker
        // (check_const_fn_decl) точнее покрывает validation.
        let is_const_fn = fd.return_is_const || fd.params.iter().any(|p| p.is_const);
        let prev_in_const_fn = self.in_const_fn.get();
        self.in_const_fn.set(is_const_fn);
        let _guard = ConstFnFlagGuard { ctx: self, prev: prev_in_const_fn };

        // Plan 124 (D220): set current_recv_type для priv field access scope
        // tracking. Instance + Static methods обa get receiver's type_name;
        // priv field access разрешён в both contexts.
        let prev_recv = self.current_recv_type.borrow().clone();
        let new_recv = fd.receiver.as_ref().map(|r| r.type_name.clone());
        *self.current_recv_type.borrow_mut() = new_recv;
        let _recv_guard = PrivRecvGuard { ctx: self, prev: prev_recv };
        // Plan 124.6 (D225): set current_fn_test_access — fn body gets priv
        // access к listed types (escape hatch для tests + helper fns).
        let prev_ta = std::mem::take(&mut *self.current_fn_test_access.borrow_mut());
        *self.current_fn_test_access.borrow_mut() = fd.test_access_for.clone();
        let _ta_guard = PrivTestAccessGuard { ctx: self, prev: prev_ta };
        // Generic-scope функции: её собственные generic-параметры +
        // generic-параметры receiver-типа (`fn Box[T] @get() -> T`).
        let mut gs: HashSet<String> = HashSet::new();
        for g in &fd.generics {
            gs.insert(g.name.clone());
        }
        if let Some(r) = &fd.receiver {
            for tr in &r.generics {
                if let TypeRef::Named { path, .. } = tr {
                    if path.len() == 1 {
                        gs.insert(path[0].clone());
                    }
                }
            }
            // Plan 153.5 (D263) / [M-153.5-flatten-nested-receiver]: a NESTED
            // CARRIER receiver (`Vec[Vec[T]]`) declares its typevars in the
            // carrier brackets; they land in `r.generics` (as `Named{T}`) and so
            // are already in scope via the loop above. A NESTED SLICE receiver
            // (`fn[T] [][]T`) declares `T` via the `fn[T]` prefix (already in
            // `fd.generics` → `gs`). The structured `r.receiver_ty` is therefore
            // NOT used to seed `gs`: doing so would mask the
            // `E_UNDECLARED_TYPEVAR_IN_RECEIVER` diagnostic for an UNdeclared
            // slice typevar (`fn []T @m` without a `fn[T]` prefix), which is the
            // whole point of that check.
        }
        // Plan 101.1 B1 (Ф.2 E_UNDECLARED_TYPEVAR_IN_RECEIVER):
        // Detect `fn []T @method` где T — single-uppercase letter без
        // `fn[T]` префикса (не в gs). Это silent miscompile в old codegen
        // (defaults T=nova_int). Loud error suggests `fn[T]` prefix fix.
        if let Some(r) = &fd.receiver {
            if r.type_name.starts_with("[]") {
                let elem = &r.type_name[2..];
                let is_single_upper = elem.len() <= 2
                    && elem.chars().all(|c| c.is_ascii_uppercase());
                if is_single_upper && !gs.contains(elem) {
                    errors.push(Diagnostic::new(
                        format!(
                            "[E_UNDECLARED_TYPEVAR_IN_RECEIVER] `fn []{elem} @{m}` — \
                             typevar `{elem}` не объявлен. Добавьте `fn[{elem}]` префикс \
                             (Plan 101.1 / D145):\n  \
                             fn[{elem}] []{elem} @{m}(...) -> ...",
                            elem = elem, m = fd.name
                        ),
                        r.span,
                    ));
                }
            }
            // Plan 101.1 B2 (Ф.2 E_BARE_TYPEVAR_NEEDS_PREFIX):
            // Detect `fn T @method` где T — bare single-uppercase letter
            // (not array, not other shape) без `fn[T]` prefix. Allowed only
            // если T in gs (declared via prefix) OR T — named type (но
            // type-check error elsewhere). Distinct from B1 (which targets `[]T`).
            let tn = r.type_name.as_str();
            if tn.len() <= 2 && tn.chars().all(|c| c.is_ascii_uppercase()) {
                if !gs.contains(tn) && !self.types.contains_key(tn) {
                    errors.push(Diagnostic::new(
                        format!(
                            "[E_BARE_TYPEVAR_NEEDS_PREFIX] `fn {tn} @{m}` — \
                             bare typevar `{tn}` receiver требует `fn[{tn}]` префикс \
                             (Plan 101.1 / D145):\n  \
                             fn[{tn}] {tn} @{m}(...) -> ...\n  \
                             OR declare `type {tn} {{ ... }}` если intended named type.",
                            tn = tn, m = fd.name
                        ),
                        r.span,
                    ));
                }
            }
            // Plan 101.1 C8 (Ф.2 E_UNUSED_PREFIX_TYPEVAR):
            // Каждый prefix-generic должен использоваться в receiver/params/return.
            // Если объявлен но не используется — error.
            {
                let mut referenced: HashSet<String> = HashSet::new();
                // Collect from receiver type-name (bare T case).
                let tn_rec = r.type_name.as_str();
                if tn_rec.len() <= 2 && tn_rec.chars().all(|c| c.is_ascii_uppercase()) {
                    referenced.insert(tn_rec.to_string());
                }
                // Collect from receiver type generics (`[]T`, Option[T], etc.).
                for tr in &r.generics {
                    Self::collect_named_idents(tr, &mut referenced);
                }
                // Array element if receiver is []T.
                if let Some(elem) = r.type_name.strip_prefix("[]") {
                    if elem.len() <= 2 && elem.chars().all(|c| c.is_ascii_uppercase()) {
                        referenced.insert(elem.to_string());
                    }
                }
                // Plan 153.5 (D263) / [M-153.5-flatten-nested-receiver]: a NESTED
                // receiver (`[][]T`, `Vec[Vec[T]]`) references its typevars only
                // through the structured `receiver_ty` — collect them so a
                // legitimately-used nested typevar is not flagged unused.
                if let Some(rty) = &r.receiver_ty {
                    Self::collect_named_idents(rty, &mut referenced);
                }
                // Collect from params.
                for p in &fd.params {
                    Self::collect_named_idents(&p.ty, &mut referenced);
                }
                // Collect from return type.
                if let Some(rt) = &fd.return_type {
                    Self::collect_named_idents(rt, &mut referenced);
                }
                // Check each fd.generics — must be referenced.
                for g in &fd.generics {
                    if !referenced.contains(&g.name) {
                        errors.push(Diagnostic::new(
                            format!(
                                "[E_UNUSED_PREFIX_TYPEVAR] generic `{name}` declared в \
                                 `fn[…]` prefix но не используется в receiver, params, \
                                 или return type (Plan 101.1 / D145). Удалите из prefix.",
                                name = g.name
                            ),
                            r.span,
                        ));
                    }
                }
            }
            // Plan 101.1 B4 (Ф.2 E_PREFIX_SHADOWS_NAMED_TYPE):
            // Detect `fn[T] T @method` + `type T { ... }` в scope. fn-prefix
            // shadows named type — ambiguous. Loud error suggests rename.
            for g in &fd.generics {
                if self.types.contains_key(&g.name) {
                    errors.push(Diagnostic::new(
                        format!(
                            "[E_PREFIX_SHADOWS_NAMED_TYPE] `fn[{tn}] ...` — \
                             generic `{tn}` shadows named type `{tn}` in scope \
                             (Plan 101.1 / D145). Rename one:\n  \
                             - rename prefix generic: `fn[T2] {tn} @{m}(...)` (use named T)\n  \
                             - rename named type: `type {tn}_New {{ ... }}` (free up T)",
                            tn = g.name, m = fd.name
                        ),
                        r.span,
                    ));
                }
            }
            // Plan 101.1 B3 (Ф.2 E_DUPLICATE_GENERIC_DECL):
            // Detect `fn[K, V] HashMap[K, V] @method` — generics в `fn[…]`
            // дублируют carrier-brackets `Name[K, V]`. Удалите fn-prefix
            // OR удалите из carrier.
            //
            // Collect carrier-declared generics (single-upper names from
            // receiver.generics) and check if any fn-prefix-generic
            // (fd.generics from prefix) duplicates them.
            let carrier_decls: HashSet<String> = r.generics.iter()
                .filter_map(|tr| {
                    if let TypeRef::Named { path, .. } = tr {
                        if path.len() == 1 {
                            let n = &path[0];
                            if n.len() <= 2 && n.chars().all(|c| c.is_ascii_uppercase()) {
                                return Some(n.clone());
                            }
                        }
                    }
                    None
                })
                .collect();
            for g in &fd.generics {
                if carrier_decls.contains(&g.name) {
                    errors.push(Diagnostic::new(
                        format!(
                            "[E_DUPLICATE_GENERIC_DECL] generic `{tn}` уже введён через \
                             receiver `{rn}[{ts}]` — удалите из `fn[…]` префикса \
                             (Plan 101.1 / D145):\n  \
                             fn {rn}[{ts}] @{m}(...)  // без fn[{tn}]",
                            tn = g.name, rn = r.type_name, ts = r.generics.iter().map(|t| format!("{:?}", t)).collect::<Vec<_>>().join(", "), m = fd.name
                        ),
                        r.span,
                    ));
                }
            }
        }
        // Bounds и defaults generic-параметров.
        for g in &fd.generics {
            for b in &g.bounds {
                self.walk_typeref(b, &gs, errors);
            }
            if let Some(d) = &g.default {
                self.walk_typeref(d, &gs, errors);
            }
        }
        // Параметры, return, эффекты.
        for p in &fd.params {
            self.walk_typeref(&p.ty, &gs, errors);
            if let Some(dv) = &p.default {
                self.walk_expr(dv, &gs, errors);
            }
        }
        if let Some(rt) = &fd.return_type {
            self.walk_typeref(rt, &gs, errors);
        }
        for e in &fd.effects {
            self.walk_typeref(e, &gs, errors);
        }
        for c in &fd.contracts {
            self.walk_expr(&c.expr, &gs, errors);
        }
        if let Some(d) = &fd.decreases {
            self.walk_expr(d, &gs, errors);
        }
        // Тело.
        match &fd.body {
            FnBody::Expr(e) => self.walk_expr(e, &gs, errors),
            FnBody::Block(b) => self.walk_block(b, &gs, errors),
            FnBody::External => {}
        }
    }

    fn check_type_decl(&self, td: &TypeDecl, errors: &mut Vec<Diagnostic>) {
        // Plan 167: single-letter type names forbidden (D30 amend).
        // Generic parameters are conventionally single-letter (T, S, K, V) — naming
        // conflict with type S causes E_PREFIX_SHADOWS_NAMED_TYPE. Ban type names
        // of length 1 to make the namespaces non-overlapping.
        if td.name.chars().count() == 1 {
            errors.push(Diagnostic::new(
                format!(
                    "[E_TYPE_NAME_TOO_SHORT] type name `{name}` is a single character — \
                     must be at least 2 characters (Plan 167, D30 §naming). \
                     Rename to a descriptive PascalCase name, e.g. `{name}Val`, \
                     `{name}Node`, `{name}Item`. \
                     Single-letter names conflict with generic parameters by convention.",
                    name = td.name
                ),
                td.span,
            ));
        }
        let mut gs: HashSet<String> = HashSet::new();
        for g in &td.generics {
            gs.insert(g.name.clone());
        }
        for g in &td.generics {
            for b in &g.bounds {
                self.walk_typeref(b, &gs, errors);
            }
            if let Some(d) = &g.default {
                self.walk_typeref(d, &gs, errors);
            }
        }
        match &td.kind {
            TypeDeclKind::Record(fields) => {
                for f in fields {
                    self.walk_typeref(&f.ty, &gs, errors);
                }
            }
            TypeDeclKind::Sum(variants) => {
                for v in variants {
                    match &v.kind {
                        SumVariantKind::Unit => {}
                        SumVariantKind::Tuple(tys) => {
                            for t in tys {
                                self.walk_typeref(t, &gs, errors);
                            }
                        }
                        SumVariantKind::Record(fields) => {
                            for f in fields {
                                self.walk_typeref(&f.ty, &gs, errors);
                            }
                        }
                    }
                }
            }
            TypeDeclKind::Effect(methods) => {
                for m in methods {
                    let mut ms = gs.clone();
                    for g in &m.generics {
                        ms.insert(g.name.clone());
                    }
                    for p in &m.params {
                        self.walk_typeref(&p.ty, &ms, errors);
                    }
                    if let Some(rt) = &m.return_type {
                        self.walk_typeref(rt, &ms, errors);
                    }
                    for e in &m.effects {
                        self.walk_typeref(e, &ms, errors);
                    }
                }
            }
            TypeDeclKind::Protocol { methods, embeds } => {
                for m in methods {
                    let mut ms = gs.clone();
                    for g in &m.generics {
                        ms.insert(g.name.clone());
                    }
                    for p in &m.params {
                        self.walk_typeref(&p.ty, &ms, errors);
                    }
                    if let Some(rt) = &m.return_type {
                        self.walk_typeref(rt, &ms, errors);
                    }
                    for e in &m.effects {
                        self.walk_typeref(e, &ms, errors);
                    }
                }
                // Plan 101.4: validate embedded protocol type references.
                for e in embeds {
                    self.walk_typeref(e, &gs, errors);
                }
            }
            // Plan 120 (D215): walk field types in named tuple declarations.
            TypeDeclKind::NamedTuple(fields) => {
                for f in fields {
                    self.walk_typeref(&f.ty, &gs, errors);
                }
            }
            TypeDeclKind::Newtype(tr) => {
                self.walk_typeref(tr, &gs, errors);
                // Plan 91.12 V2 followup [M-91.12-generic-newtype-non-ptr-inner]
                // (2026-06-02): generic newtype `type X[T](INNER)` где INNER
                // использует generic param T (e.g. `type Wrap[T](T)`) НЕ
                // поддерживается. Causes: codegen emit'ит `typedef Nova_T
                // Nova_Wrap;` где `Nova_T` — type-param placeholder, не
                // resolved C type → C compile error.
                //
                // Semantically tuple newtype = transparent typedef (Plan 115
                // D214); same C ABI shared across mono'd instances. Per-T
                // storage variance (sizeof(T) differs) — это record-semantics,
                // не newtype. User should migrate к record form:
                //   type Wrap[T] { value T }   ← properly mono'd per T
                if !td.generics.is_empty() {
                    let type_params: HashSet<String> = td.generics.iter()
                        .map(|g| g.name.clone())
                        .collect();
                    if Self::typeref_uses_param(tr, &type_params) {
                        let inner_span = match tr {
                            TypeRef::Named { span, .. } => *span,
                            TypeRef::Array(_, span) => *span,
                            TypeRef::FixedArray(_, _, span) => *span,
                            TypeRef::Tuple(_, span) => *span,
                            TypeRef::Func { span, .. } => *span,
                            TypeRef::Protocol { span, .. } => *span,
                            TypeRef::Unit(span) => *span,
                            TypeRef::Readonly(_, span) => *span,
                            _ => td.span,
                        };
                        errors.push(Diagnostic::new(
                            format!(
                                "[E_GENERIC_NEWTYPE_INNER_USES_PARAM] generic newtype \
                                 `type {}[..](..)` cannot use type-parameter \
                                 in inner position — newtype = transparent typedef \
                                 (Plan 115 D214), shared C ABI across all T's. \
                                 Per-T storage requires record-semantics: replace \
                                 with `type {} {{ value T }}` (record form, properly \
                                 mono'd per T).",
                                td.name, td.name
                            ),
                            inner_span,
                        ));
                    }
                }
            }
            TypeDeclKind::Alias(tr) => self.walk_typeref(tr, &gs, errors),
            TypeDeclKind::Opaque => {}
        }
        // Plan 124.8 [M-124.8-zero-on-move] (2026-06-03): validation —
        // `#zero_on_move` применим только к Record (heap + value), NamedTuple,
        // Newtype. Не применим к Effect/Protocol (нет storage), Sum (variant
        // storage non-trivial; V2 followup), Alias/Opaque (нет own layout).
        if td.zero_on_move {
            let kind_ok = matches!(
                &td.kind,
                TypeDeclKind::Record(_) | TypeDeclKind::NamedTuple(_) | TypeDeclKind::Newtype(_)
            );
            if !kind_ok {
                let kind_str = match &td.kind {
                    TypeDeclKind::Record(_) => "record",
                    TypeDeclKind::Sum(_) => "sum",
                    TypeDeclKind::Effect(_) => "effect",
                    TypeDeclKind::Protocol { .. } => "protocol",
                    TypeDeclKind::Alias(_) => "alias",
                    TypeDeclKind::Opaque => "external opaque",
                    TypeDeclKind::NamedTuple(_) => "named tuple",
                    TypeDeclKind::Newtype(_) => "newtype",
                };
                errors.push(Diagnostic::new(
                    format!(
                        "[E_ZERO_ON_MOVE_INVALID_KIND] `#zero_on_move` cannot be \
                         applied to `{}` ({}). Allowed kinds: record \
                         (heap + value), named tuple, newtype. Plan 124.8 \
                         [M-124.8-zero-on-move].",
                        td.name, kind_str
                    ),
                    td.span,
                ));
            }
        }
        // Q-infinite-value-type (D280 §4): genuinely-infinite VALUE types —
        // a value record / named-tuple / newtype / alias whose layout transitively
        // contains ITSELF through INLINE edges only (no pointer/heap/slice/Option
        // indirection). Such a type has no finite object layout. The const_fn_eval
        // size walk degrades gracefully (depth-guard → None, surfaced only when
        // `size_of` forces it); this dedicated check reports it at type-check time.
        self.check_infinite_type(td, errors);
    }

    /// Q-infinite-value-type (D280 §4): report an `E_INFINITE_TYPE` diagnostic
    /// when this value type's layout transitively embeds itself through INLINE
    /// edges only — i.e. there is a value-containment cycle with no
    /// pointer/heap/slice/Option indirection to break it.
    ///
    /// The INLINE-vs-INDIRECTION classification MIRRORS
    /// `const_fn_eval::type_size_or_align_resolved_d` (post-D280):
    ///   - INLINE (recurse, can carry a cycle): a field whose named type is a
    ///     VALUE record / named-tuple / newtype / alias-to-value; tuples;
    ///     fixed-arrays of inline types; transparent `ro`/`mut`/`unsafe`
    ///     wrappers over an inline type.
    ///   - INDIRECTION (STOP — finite, breaks the cycle): a HEAP type (Sum is
    ///     ALWAYS heap; a Record with `td.allocation.is_heap()`), a pointer
    ///     `*T`, a slice `[]T`/Array, `str`, any generics-carrying Named
    ///     (`Option[..]`/`Vec[..]`/`Wrapper[..]` — they box / are not inlined
    ///     by the size walk), primitives, `Unit`, `Func`, `Protocol`.
    ///
    /// Detect with a DFS over the inline-containment graph keyed by type name,
    /// with an on-path set (mirrors `type_is_consume_v`'s visited-set, except we
    /// only follow inline edges and report on a back-edge into a node already on
    /// the current path). Catches direct self-cycles (`type N value { next N }`)
    /// and mutual cycles (`type A value { b B }` + `type B value { a A }`).
    ///
    /// Only types DECLARED in entry-peer files (the user's own source) are
    /// reported — a cycle is reported once, on the decl currently being checked,
    /// when the DFS starting at `td` revisits `td` itself. Reporting on the
    /// entry node (rather than every node on the cycle) keeps the diagnostic
    /// stable and avoids duplicate errors for mutual cycles (each peer reports
    /// its own self-reaching path).
    fn check_infinite_type(&self, td: &TypeDecl, errors: &mut Vec<Diagnostic>) {
        // Only value records / named-tuples / newtypes / aliases can be the
        // *subject* of a value-containment cycle. A heap record / sum boxes to a
        // pointer and is never inlined into a field, so it can never close a
        // cycle (it is an INDIRECTION boundary). Skip everything else fast.
        let subject_inlineable = match &td.kind {
            TypeDeclKind::Record(_) => !td.allocation.is_heap(),
            TypeDeclKind::NamedTuple(_) | TypeDeclKind::Newtype(_) | TypeDeclKind::Alias(_) => true,
            _ => false,
        };
        if !subject_inlineable {
            return;
        }
        // Generic params of the decl under check — a bare param `T` is not a
        // user type and cannot close a value cycle (mirrors the size walk, which
        // has no entry for an unresolved param → None).
        let mut gs: HashSet<String> = HashSet::new();
        for g in &td.generics {
            gs.insert(g.name.clone());
        }
        // DFS over the inline-containment graph starting at `td.name`. `on_path`
        // is the set of type names currently on the DFS stack; a back-edge into
        // a node on the path is a cycle. We only care whether the cycle passes
        // through `td.name` (the subject) — if so, `td` is infinite.
        let mut on_path: HashSet<String> = HashSet::new();
        // The field whose type carries the back-edge to `td` — captured for the
        // diagnostic span + message. `(field_label, field_ty)`.
        let root = td.name.clone();
        on_path.insert(root.clone());
        for (label, field_ty, _path_segs) in Self::inline_fields_of(td) {
            if let Some(offender_span) =
                self.infinite_dfs(field_ty, &root, &mut on_path, &gs)
            {
                // Found a value-containment cycle reaching `td` through INLINE
                // edges only. Report once, on the offending field of `td`.
                let field_ty_str = Self::typeref_display(field_ty);
                errors.push(Diagnostic::new(
                    format!(
                        "[E_INFINITE_TYPE] value type `{name}` has infinite size: \
                         field `{label}` of type `{fty}` contains `{name}` by value \
                         (no pointer/heap indirection), so the layout recurses without \
                         bound. Break the cycle with indirection: box it behind a sum \
                         variant (sums are always heap), wrap the field in `Option[{fty}]`, \
                         use a pointer `*{fty}`, or a slice `[]{fty}`.",
                        name = td.name,
                        label = label,
                        fty = field_ty_str,
                    ),
                    offender_span,
                ));
                // One diagnostic per offending decl is enough — the first inline
                // field that closes a cycle is the actionable site. (A type with
                // several independent cyclic fields still gets reported via the
                // first; fixing it re-runs the check.)
                break;
            }
        }
    }

    /// Q-infinite-value-type: the INLINE-edge field list of a value-carrying
    /// `TypeDecl` — the contained types that participate in the value layout.
    /// Returns `(field_label, &TypeRef, ())` for each inline edge. Heap records
    /// and sums are NOT subjects here (handled by the caller's gate), so this
    /// only enumerates value Record / NamedTuple / Newtype / Alias contents.
    fn inline_fields_of(td: &TypeDecl) -> Vec<(String, &TypeRef, ())> {
        match &td.kind {
            TypeDeclKind::Record(fields) => fields
                .iter()
                .map(|f| (f.name.clone(), &f.ty, ()))
                .collect(),
            TypeDeclKind::NamedTuple(fields) => fields
                .iter()
                .map(|f| (f.name.clone(), &f.ty, ()))
                .collect(),
            TypeDeclKind::Newtype(inner) => vec![("(0)".to_string(), inner, ())],
            TypeDeclKind::Alias(inner) => vec![("(alias)".to_string(), inner, ())],
            _ => Vec::new(),
        }
    }

    /// Q-infinite-value-type: DFS over the inline-containment graph from a single
    /// field `TypeRef`. Returns `Some(span)` of the offending TypeRef if a value
    /// cycle reaching `root` (through INLINE edges only) is found, else `None`.
    /// `on_path` holds the type names currently on the DFS stack. `gs` is the set
    /// of generic-param names of the root decl (bare params are STOP leaves).
    ///
    /// Classification mirrors `type_size_or_align_resolved_d` exactly: see the
    /// per-`TypeRef` arms below. STOP arms return `None` (finite, breaks cycle);
    /// INLINE arms recurse; reaching a Named that resolves to `root` (or any node
    /// already on `on_path`, which transitively reaches `root`) is the cycle.
    fn infinite_dfs(
        &self,
        t: &TypeRef,
        root: &str,
        on_path: &mut HashSet<String>,
        gs: &HashSet<String>,
    ) -> Option<Span> {
        match t {
            TypeRef::Named { path, generics, span } => {
                // Mirror the size walk's inline Named arm gate exactly:
                // ONLY `path.len() == 1 && generics.is_empty()` is inlined.
                // A module-qualified path (len > 1) OR any non-empty generics
                // (Option[..]/Vec[..]/Wrapper[..]) falls to the size walk's
                // `_ => None` → INDIRECTION/finite here. STOP.
                if path.len() != 1 || !generics.is_empty() {
                    return None;
                }
                let name = &path[0];
                // Bare generic-param of the root decl — not a user type. STOP.
                if gs.contains(name) {
                    return None;
                }
                // Primitives are finite leaves (and are NOT in self.types). STOP.
                if Self::is_primitive_type_name(name) {
                    return None;
                }
                // A back-edge into a node already on the DFS path → cycle. Every
                // node on `on_path` transitively reaches `root` (the path was
                // grown from `root`), so reaching any of them means `root` is on
                // an inline cycle. Report at this field's span.
                if on_path.contains(name) {
                    return Some(*span);
                }
                // Resolve the named TypeDecl. Unresolvable → STOP (the size walk
                // returns None there; a false positive would violate the
                // zero-false-positive gate).
                let td = match self.types.get(name).copied() {
                    Some(td) => td,
                    None => return None,
                };
                // BOXING short-circuit — the load-bearing branch. A Sum is ALWAYS
                // heap; a Record is indirection iff `td.allocation.is_heap()`.
                // Either way the reference is an 8-byte pointer leaf → finite,
                // BREAKS the cycle. STOP. (Mirrors size walk lines 1147-1152.)
                let boxed_to_pointer = matches!(&td.kind, TypeDeclKind::Sum(_))
                    || (matches!(&td.kind, TypeDeclKind::Record(_)) && td.allocation.is_heap());
                if boxed_to_pointer {
                    return None;
                }
                // INLINE: value Record / NamedTuple / Newtype / Alias. Recurse
                // into its contained types, with `name` pushed on the path.
                on_path.insert(name.clone());
                let mut found = None;
                for (_label, field_ty, _seg) in Self::inline_fields_of(td) {
                    if let Some(s) = self.infinite_dfs(field_ty, root, on_path, gs) {
                        found = Some(s);
                        break;
                    }
                }
                on_path.remove(name);
                found
            }
            // Tuples: INLINE of each element (size walk recurses each elem).
            TypeRef::Tuple(elems, _) => {
                for e in elems {
                    if let Some(s) = self.infinite_dfs(e, root, on_path, gs) {
                        return Some(s);
                    }
                }
                None
            }
            // Fixed array `[n]T`: n inline copies of T → INLINE-recurse the elem
            // regardless of n (even one inline copy closes a cycle).
            TypeRef::FixedArray(_, elem, _) => self.infinite_dfs(elem, root, on_path, gs),
            // Transparent wrappers — recurse inner, preserve its inline/indirection
            // nature (`ro T`/`mut T`/`unsafe T`). The OUTER Pointer of `*ro T`
            // etc. has already stopped before reaching these.
            TypeRef::Readonly(inner, _)
            | TypeRef::Mut(inner, _)
            | TypeRef::Unsafe(inner, _) => self.infinite_dfs(inner, root, on_path, gs),
            // Pointer `*T` (any pointee) — always 8 bytes. INDIRECTION. STOP.
            TypeRef::Pointer(_, _) => None,
            // Slice `[]T` — 16-byte {ptr,len}. INDIRECTION. STOP.
            TypeRef::Array(_, _) => None,
            // Unit / Func / Protocol — finite leaves / existentials. STOP.
            TypeRef::Unit(_) | TypeRef::Func { .. } | TypeRef::Protocol { .. } => None,
        }
    }

    /// Q-infinite-value-type: primitive type names that are finite leaves and
    /// are NOT present in `self.types` (mirrors the size walk's primitive table).
    #[inline]
    fn is_primitive_type_name(name: &str) -> bool {
        matches!(
            name,
            "int" | "i64" | "u64" | "f64" | "i32" | "u32" | "f32" | "i16" | "u16"
                | "i8" | "u8" | "uint" | "bool" | "char" | "str"
        )
    }

    /// Q-infinite-value-type: compact display of a `TypeRef` for the diagnostic
    /// message (`Option[Node]`, `*Node`, `[]Node`, `Node`). Best-effort — only
    /// the common shapes; falls back to the leading segment name.
    fn typeref_display(t: &TypeRef) -> String {
        match t {
            TypeRef::Named { path, generics, .. } => {
                let base = path.join(".");
                if generics.is_empty() {
                    base
                } else {
                    let args: Vec<String> = generics.iter().map(Self::typeref_display).collect();
                    format!("{}[{}]", base, args.join(", "))
                }
            }
            TypeRef::Array(inner, _) => format!("[]{}", Self::typeref_display(inner)),
            TypeRef::FixedArray(n, inner, _) => format!("[{}]{}", n, Self::typeref_display(inner)),
            TypeRef::Pointer(inner, _) => format!("*{}", Self::typeref_display(inner)),
            TypeRef::Readonly(inner, _) => format!("ro {}", Self::typeref_display(inner)),
            TypeRef::Mut(inner, _) => format!("mut {}", Self::typeref_display(inner)),
            TypeRef::Unsafe(inner, _) => format!("unsafe {}", Self::typeref_display(inner)),
            TypeRef::Tuple(elems, _) => {
                let parts: Vec<String> = elems.iter().map(Self::typeref_display).collect();
                format!("({})", parts.join(", "))
            }
            TypeRef::Unit(_) => "()".to_string(),
            TypeRef::Func { .. } => "fn(..)".to_string(),
            TypeRef::Protocol { .. } => "<protocol>".to_string(),
        }
    }

    /// Plan 91.12 V2 followup #3 (2026-06-02): thin wrapper над
    /// `TypeRef::uses_any_type_param` (ast::mod.rs) — extracted common
    /// helper, removed duplication с codegen's parallel impl (emit_c.rs).
    #[inline]
    fn typeref_uses_param(tr: &TypeRef, params: &HashSet<String>) -> bool {
        tr.uses_any_type_param(params)
    }

    /// Ф.2: рекурсивная проверка арности одного TypeRef-дерева.
    fn walk_typeref(
        &self,
        tr: &TypeRef,
        gs: &HashSet<String>,
        errors: &mut Vec<Diagnostic>,
    ) {
        match tr {
            TypeRef::Named { path, generics, span } => {
                for g in generics {
                    self.walk_typeref(g, gs, errors);
                }
                let Some(name) = path.last() else { return; };
                // Plan 118 Ф.5 A22 (D216 §7): W_OPTION_DOUBLE_NESTED warning
                // для `Option[Option[*T]]` — V2 follow-on. Requires lint
                // framework integration (LintWarning через lints.rs), so что
                // diagnostic emits as warning not hard error. V1 detection
                // path documented здесь для future implementation:
                //   if name == "Option" && generics.len() == 1 &&
                //      inner is Named["Option"] with pointer-typed payload
                //   → emit W_OPTION_DOUBLE_NESTED via lint framework.
                // Currently не fires — nested Option[Option[*T]] codegen
                // falls back в tagged form automatically (inner c_ty =
                // NovaOpt_X struct, не pointer).
                // generic-параметр в scope — абстрактное имя, не тип.
                if gs.contains(name) {
                    return;
                }
                // Plan 134: встроенный тип `ptr` (и его C-имя `nova_ptr`) удалён.
                // `*()` (pointer-to-unit → `void*`) — канонический opaque-pointer.
                // Ловим использование на этапе `nova check` (не откладываем до
                // codegen): даём понятную миграционную ошибку с подсказкой.
                // A-134.a / Plan 134 Ф.1.7.
                if name == "ptr" || name == "nova_ptr" {
                    errors.push(Diagnostic::new(
                        format!(
                            "[E_TYPE_UNKNOWN] type `{name}` is removed — use `*()` \
                             (pointer-to-unit = `void*`) instead (Plan 134). \
                             For a short alias write `type ptr = *()` in your own code.",
                        ),
                        *span,
                    ));
                    return;
                }
                if arity_exempt(name) {
                    return;
                }
                // Неизвестное имя — не наша забота (name-resolution).
                let Some(info) = self.arity.get(name) else { return; };
                let actual = generics.len();
                // `actual == 0` — type-аргументы опущены и выводятся из
                // контекста (`fn f() -> Result { Ok(1) }`, `let x Option`).
                // Это легальный idiom Nova — не arity-ошибка. Ошибка только
                // когда аргументы УКАЗАНЫ, но их число неверно.
                if actual > 0 && actual != info.count {
                    errors.push(arity_diag(name, info, actual, *span));
                }
            }
            TypeRef::Array(inner, _) | TypeRef::FixedArray(_, inner, _) => {
                self.walk_typeref(inner, gs, errors);
            }
            TypeRef::Tuple(items, _) => {
                for it in items {
                    self.walk_typeref(it, gs, errors);
                }
            }
            TypeRef::Func { params, effects, return_type, .. } => {
                for p in params {
                    self.walk_typeref(p, gs, errors);
                }
                for e in effects {
                    self.walk_typeref(e, gs, errors);
                }
                if let Some(rt) = return_type {
                    self.walk_typeref(rt, gs, errors);
                }
            }
            // Plan 97 Ф.2 (D142): анонимный protocol-тип — рекурсивно
            // walk через сигнатуры методов; arity-checking применяется к
            // ссылкам внутри param-/return-/effect-типов.
            TypeRef::Protocol { methods, .. } => {
                for m in methods {
                    for p in &m.params {
                        self.walk_typeref(&p.ty, gs, errors);
                    }
                    for e in &m.effects {
                        self.walk_typeref(e, gs, errors);
                    }
                    if let Some(rt) = &m.return_type {
                        self.walk_typeref(rt, gs, errors);
                    }
                }
            }
            TypeRef::Unit(_) => {}
            // D176 (Plan 108): readonly T — transparent, walk inner.
            TypeRef::Readonly(inner, _) => self.walk_typeref(inner, gs, errors),
            // Plan 118 D216 + Plan 118.5: typed pointer `*T` family
            // (Pointer/Mut/Unsafe) — all transparent, walk inner for arity checks.
            TypeRef::Pointer(inner, _)
            | TypeRef::Mut(inner, _)
            | TypeRef::Unsafe(inner, _) => self.walk_typeref(inner, gs, errors),
        }
    }

    /// Plan 101.1 C8: collect all Named-type identifiers referenced
    /// anywhere в typeref recursively. Used для unused-prefix-generic
    /// detection (compare against fd.generics names).
    fn collect_named_idents(tr: &TypeRef, out: &mut HashSet<String>) {
        match tr {
            TypeRef::Named { path, generics, .. } => {
                if let Some(name) = path.last() {
                    out.insert(name.clone());
                }
                for g in generics {
                    Self::collect_named_idents(g, out);
                }
            }
            TypeRef::Array(inner, _) => Self::collect_named_idents(inner, out),
            TypeRef::FixedArray(_, inner, _) => Self::collect_named_idents(inner, out),
            TypeRef::Tuple(items, _) => {
                for it in items {
                    Self::collect_named_idents(it, out);
                }
            }
            TypeRef::Func { params, return_type, .. } => {
                for p in params {
                    Self::collect_named_idents(p, out);
                }
                if let Some(rt) = return_type {
                    Self::collect_named_idents(rt, out);
                }
            }
            TypeRef::Protocol { methods: _, .. } => {}
            TypeRef::Unit(_) => {}
            // D176 (Plan 108): readonly T — transparent.
            TypeRef::Readonly(inner, _) => Self::collect_named_idents(inner, out),
            // Plan 118 D216 + Plan 118.5: typed pointer `*T` family
            // (Pointer/Mut/Unsafe) — all transparent, recurse on inner.
            TypeRef::Pointer(inner, _)
            | TypeRef::Mut(inner, _)
            | TypeRef::Unsafe(inner, _) => Self::collect_named_idents(inner, out),
        }
    }

    // --- Ф.2: walk тел (turbofish / as / is / let-аннотации) ------------

    fn walk_block(
        &self,
        b: &Block,
        gs: &HashSet<String>,
        errors: &mut Vec<Diagnostic>,
    ) {
        for s in &b.stmts {
            self.walk_stmt(s, gs, errors);
        }
        if let Some(t) = &b.trailing {
            self.walk_expr(t, gs, errors);
        }
    }

    fn walk_stmt(
        &self,
        s: &Stmt,
        gs: &HashSet<String>,
        errors: &mut Vec<Diagnostic>,
    ) {
        match s {
            Stmt::Expr(e) => self.walk_expr(e, gs, errors),
            Stmt::Let(d) => {
                if let Some(t) = &d.ty {
                    self.walk_typeref(t, gs, errors);
                }
                self.walk_expr(&d.value, gs, errors);
            }
            // Plan 114.4 Ф.2: scope-local const — strict constexpr enforce.
            // Same eligibility rule as module-level const (check_const_constexpr).
            // known_consts здесь conservatively empty (referencing другие
            // scope-locals — followup [M-114.4-scope-const-chain]).
            Stmt::Const(d) => {
                if let Some(t) = &d.ty {
                    self.walk_typeref(t, gs, errors);
                }
                self.walk_expr(&d.value, gs, errors);
                // Plan 114.4.2 D199: внутри const fn body — scope-local
                // const validated by check_const_fn_decl (param/local
                // awareness). Здесь skip избегаем false-positives на
                // const param refs (e.g. `const c = b as int` где
                // `b` — const param).
                if !self.in_const_fn.get() {
                    let empty_consts: HashSet<String> = HashSet::new();
                    let empty_nt: HashSet<String> = HashSet::new();
                    if let Err(diag) = check_const_constexpr_ex(
                        &d.value, &empty_consts, &self.const_fn_names, &empty_nt,
                    ) {
                        errors.push(diag);
                    }
                }
            }
            Stmt::Assign { target, value, .. } => {
                self.walk_expr(target, gs, errors);
                self.walk_expr(value, gs, errors);
            }
            Stmt::Return { value, .. } => {
                if let Some(v) = value {
                    self.walk_expr(v, gs, errors);
                }
            }
            Stmt::Throw { value, .. } => self.walk_expr(value, gs, errors),
            Stmt::Break(_) | Stmt::Continue(_) | Stmt::Reveal { .. } => {}
            Stmt::Defer { body, .. } | Stmt::ErrDefer { body, .. }
            | Stmt::OkDefer { body, .. } | Stmt::DeferWithResult { body, .. } => {
                self.walk_expr(body, gs, errors);
            }
            // Plan 110 D188: walk init + body.
            Stmt::ConsumeScope { type_annot, init, body, .. } => {
                if let Some(t) = type_annot {
                    self.walk_typeref(t, gs, errors);
                }
                self.walk_expr(init, gs, errors);
                for stmt in &body.stmts {
                    self.walk_stmt(stmt, gs, errors);
                }
                if let Some(t) = &body.trailing {
                    self.walk_expr(t, gs, errors);
                }
            }
            Stmt::AssertStatic { expr, .. } | Stmt::Assume { expr, .. } => {
                self.walk_expr(expr, gs, errors);
            }
            Stmt::Apply { args, .. } => {
                for a in args {
                    self.walk_expr(a, gs, errors);
                }
            }
            Stmt::Calc { steps, .. } => {
                for step in steps {
                    self.walk_expr(&step.expr, gs, errors);
                }
            }
            // Plan 136: tuple destructuring assignment.
            Stmt::TupleAssign { lhs, rhs, .. } => {
                for e in lhs { self.walk_expr(e, gs, errors); }
                for e in rhs { self.walk_expr(e, gs, errors); }
            }
        }
    }

    fn walk_expr(
        &self,
        e: &Expr,
        gs: &HashSet<String>,
        errors: &mut Vec<Diagnostic>,
    ) {
        match &e.kind {
            ExprKind::TurboFish { base, type_args } => {
                for t in type_args {
                    self.walk_typeref(t, gs, errors);
                }
                // Если turbofish целится в известный тип — проверить
                // арность самого turbofish'а (`HashMap[str].new()`).
                // Generic-функции (`parse[int]`) в `arity` не попадают —
                // их арность с D88-дефолтами проверяется отдельно (не Ф.2).
                let target: Option<&String> = match &base.kind {
                    ExprKind::Ident(n) => Some(n),
                    ExprKind::Path(parts) => parts.last(),
                    _ => None,
                };
                if let Some(name) = target {
                    if !gs.contains(name) && !arity_exempt(name) {
                        if let Some(info) = self.arity.get(name) {
                            // turbofish всегда указывает аргументы явно —
                            // пустой `[]` не парсится; проверяем как есть.
                            if !type_args.is_empty()
                                && type_args.len() != info.count
                            {
                                errors.push(arity_diag(
                                    name, info, type_args.len(), e.span,
                                ));
                            }
                        }
                    }
                }
                self.walk_expr(base, gs, errors);
            }
            ExprKind::As(inner, ty) | ExprKind::Is(inner, ty) => {
                self.walk_expr(inner, gs, errors);
                self.walk_typeref(ty, gs, errors);
            }
            ExprKind::Call { func, args, trailing } => {
                self.walk_expr(func, gs, errors);
                for a in args {
                    self.walk_expr(a.expr(), gs, errors);
                }
                if let Some(t) = trailing {
                    match t {
                        Trailing::Block(b) => self.walk_block(b, gs, errors),
                        Trailing::LegacyBlockWithParams(tb) => {
                            self.walk_block(&tb.body, gs, errors)
                        }
                        Trailing::Fn(sb) => self.walk_fn_sig_body(sb, gs, errors),
                    }
                }
            }
            ExprKind::Binary { left, right, .. } => {
                self.walk_expr(left, gs, errors);
                self.walk_expr(right, gs, errors);
            }
            ExprKind::Unary { operand, .. } => self.walk_expr(operand, gs, errors),
            ExprKind::Try(inner) | ExprKind::Bang(inner) => {
                self.walk_expr(inner, gs, errors)
            }
            ExprKind::Coalesce(a, b) => {
                self.walk_expr(a, gs, errors);
                self.walk_expr(b, gs, errors);
            }
            ExprKind::Member { obj, .. } => self.walk_expr(obj, gs, errors),
            ExprKind::Index { obj, index } => {
                self.walk_expr(obj, gs, errors);
                self.walk_expr(index, gs, errors);
            }
            ExprKind::If { cond, then, else_ } => {
                self.walk_expr(cond, gs, errors);
                self.walk_block(then, gs, errors);
                if let Some(eb) = else_ {
                    self.walk_else(eb, gs, errors);
                }
            }
            ExprKind::IfLet { scrutinee, then, else_, .. } => {
                self.walk_expr(scrutinee, gs, errors);
                self.walk_block(then, gs, errors);
                if let Some(eb) = else_ {
                    self.walk_else(eb, gs, errors);
                }
            }
            ExprKind::Match { scrutinee, arms } => {
                self.walk_expr(scrutinee, gs, errors);
                for arm in arms {
                    if let Some(g) = &arm.guard {
                        self.walk_expr(g, gs, errors);
                    }
                    match &arm.body {
                        MatchArmBody::Expr(e) => self.walk_expr(e, gs, errors),
                        MatchArmBody::Block(b) => self.walk_block(b, gs, errors),
                    }
                }
            }
            ExprKind::Block(b) => self.walk_block(b, gs, errors),
            ExprKind::ArrayLit(elems) => {
                for el in elems {
                    match el {
                        ArrayElem::Item(e) | ArrayElem::Spread(e) => {
                            self.walk_expr(e, gs, errors)
                        }
                    }
                }
            }
            ExprKind::MapLit { elems, .. } => {
                for (k, v) in crate::ast::MapElem::cloned_pairs(elems).iter() {
                    self.walk_expr(k, gs, errors);
                    self.walk_expr(v, gs, errors);
                }
            }
            ExprKind::TupleLit(elems) => {
                for e in elems {
                    self.walk_expr(e, gs, errors);
                }
            }
            ExprKind::RecordLit { type_name, fields, .. } => {
                // Plan 114.4.1 (D200): reject field shorthand / pair refering
                // assoc const — assoc consts live на type-level, не указываются
                // в record literal.
                if let Some(tn) = type_name {
                    if let Some(last) = tn.last() {
                        if let Some(td) = self.types.get(last) {
                            for f in fields {
                                if f.is_spread { continue; }
                                if td.assoc_consts.iter().any(|ac| ac.name == f.name) {
                                    errors.push(Diagnostic::new(
                                        format!(
                                            "[E_CONST_FIELD_IN_LITERAL] field `{}` \
                                             в record literal `{}{{ … }}` — это \
                                             associated constant (zero-storage, \
                                             namespace access `{}.{}`); НЕ указывается \
                                             и НЕ инициализируется в record literal \
                                             (Plan 114.4.1 D200).",
                                            f.name, last, last, f.name,
                                        ),
                                        f.span,
                                    ));
                                }
                            }
                            // Plan 124 (D220/D221) + 124.6 (D225): priv field INIT
                            // check — record literal outside type-method scope cannot
                            // init priv fields (unless #test_access).
                            if let TypeDeclKind::Record(rec_fields) = &td.kind {
                                let base_allowed = self.priv_access_allowed_base(last.as_str());
                                if !base_allowed {
                                    let has_priv = rec_fields.iter().any(|fd| fd.priv_field);
                                    // Plan 160 (D281) Ф.2: module access context.
                                    let module_allowed = self.module_priv_access_allowed(last.as_str());
                                    let has_type_priv = rec_fields.iter().any(|fd| fd.priv_field && !fd.priv_module_field);
                                    for f in fields {
                                        // Plan 124.2 (D221 §5): spread `...other` outside
                                        // type-method scope on a type WITH priv fields
                                        // — implicitly initializes priv via copy → emit
                                        // E_PRIV_FIELD_INIT_SPREAD.
                                        if f.is_spread {
                                            if has_priv {
                                                // Plan 160 Ф.2: spread allowed within same
                                                // module for module-priv-only types.
                                                let has_module_priv_only = has_priv && !has_type_priv;
                                                let spread_ok = has_module_priv_only && module_allowed;
                                                if !spread_ok {
                                                    errors.push(Diagnostic::new(
                                                        format!(
                                                            "[E_PRIV_FIELD_INIT_SPREAD] cannot use \
                                                             spread `...` in record literal of `{}` \
                                                             outside type-method scope: type has \
                                                             private fields which would be \
                                                             implicitly initialized via copy \
                                                             (Plan 124 / D221 §5). Hint: use \
                                                             factory method `{}.new(...)` or list \
                                                             each public field explicitly.",
                                                            last, last,
                                                        ),
                                                        f.span,
                                                    ));
                                                }
                                            }
                                            continue;
                                        }
                                        if let Some(fdecl) = rec_fields.iter().find(|fd| fd.name == f.name) {
                                            if fdecl.priv_field
                                                && !self.priv_field_access_allowed(last.as_str(), &fdecl.visible_to)
                                            {
                                                // Plan 160 (D281) Ф.2: module-private init.
                                                if fdecl.priv_module_field {
                                                    if !self.module_priv_access_allowed(last.as_str()) {
                                                        errors.push(Diagnostic::new(
                                                            format!(
                                                                "[E_FIELD_MODULE_PRIVATE] cannot \
                                                                 initialize module-private field \
                                                                 `{}.{}` via record literal from \
                                                                 outside its module. Type declared \
                                                                 with bare `priv` (Plan 160 / \
                                                                 D281). Hint: use factory method \
                                                                 `{}.new(...)`.",
                                                                last, f.name, last,
                                                            ),
                                                            f.span,
                                                        ));
                                                    }
                                                } else {
                                                    errors.push(Diagnostic::new(
                                                        format!(
                                                            "[E_PRIV_FIELD_INIT] cannot \
                                                             initialize private field `{}.{}` \
                                                             via record literal outside type-\
                                                             method scope. Field marked `priv` \
                                                             (Plan 124 / D220). Hint: use \
                                                             factory method like `{}.new(...)`, \
                                                             or use `#test_access({})` on test fn.",
                                                            last, f.name, last, last,
                                                        ),
                                                        f.span,
                                                    ));
                                                }
                                            }
                                        }
                                    }
                                }
                            }
                        }
                    }
                }
                for f in fields {
                    if let Some(v) = &f.value {
                        self.walk_expr(v, gs, errors);
                    }
                }
            }
            ExprKind::TaggedTemplate { tag, args, .. } => {
                self.walk_expr(tag, gs, errors);
                for a in args {
                    self.walk_expr(a, gs, errors);
                }
            }
            ExprKind::InterpolatedStr { parts } => {
                for p in parts {
                    if let InterpStrPart::Expr { expr: e, spec: _ } = p {
                        self.walk_expr(e, gs, errors);
                    }
                }
            }
            ExprKind::Lambda { body, .. } => self.walk_expr(body, gs, errors),
            ExprKind::ClosureLight { body, .. } => match body {
                ClosureBody::Expr(e) => self.walk_expr(e, gs, errors),
                ClosureBody::Block(b) => self.walk_block(b, gs, errors),
            },
            ExprKind::ClosureFull(sb) => self.walk_fn_sig_body(sb, gs, errors),
            ExprKind::Spawn(body) => self.walk_expr(body, gs, errors),
            ExprKind::Detach(body) | ExprKind::Blocking(body) => self.walk_block(body, gs, errors),
            ExprKind::Supervised { body, cancel } => {
                if let Some(c) = cancel {
                    self.walk_expr(c, gs, errors);
                }
                self.walk_block(body, gs, errors);
            }
            ExprKind::Forbid { body, .. } => self.walk_block(body, gs, errors),
            ExprKind::Realtime { body, .. } => self.walk_block(body, gs, errors),
            ExprKind::ParallelFor { iter, body, .. } => {
                self.walk_expr(iter, gs, errors);
                self.walk_block(body, gs, errors);
            }
            ExprKind::For { iter, body, .. } => {
                self.walk_expr(iter, gs, errors);
                self.walk_block(body, gs, errors);
            }
            ExprKind::While { cond, body, .. } => {
                self.walk_expr(cond, gs, errors);
                self.walk_block(body, gs, errors);
            }
            ExprKind::WhileLet { scrutinee, body, .. } => {
                self.walk_expr(scrutinee, gs, errors);
                self.walk_block(body, gs, errors);
            }
            ExprKind::Loop { body, .. } => self.walk_block(body, gs, errors),
            ExprKind::Select { arms } => {
                for arm in arms {
                    match &arm.op {
                        SelectOp::Recv { chan, .. } => {
                            self.walk_expr(chan, gs, errors)
                        }
                        SelectOp::Send { chan, value } => {
                            self.walk_expr(chan, gs, errors);
                            self.walk_expr(value, gs, errors);
                        }
                        SelectOp::Default => {}
                    }
                    if let Some(g) = &arm.guard {
                        self.walk_expr(g, gs, errors);
                    }
                    self.walk_block(&arm.body, gs, errors);
                }
            }
            ExprKind::Range { start, end, .. } => {
                if let Some(s) = start { self.walk_expr(s, gs, errors); }
                if let Some(e) = end { self.walk_expr(e, gs, errors); }
            }
            ExprKind::Throw(inner) => self.walk_expr(inner, gs, errors),
            ExprKind::Interrupt(opt) => {
                if let Some(e) = opt {
                    self.walk_expr(e, gs, errors);
                }
            }
            ExprKind::With { body, .. } => self.walk_block(body, gs, errors),
            ExprKind::Forall { range, body, .. }
            | ExprKind::Exists { range, body, .. } => {
                self.walk_expr(range, gs, errors);
                self.walk_expr(body, gs, errors);
            }
            // Plan 97 Ф.4 (D142): protocol-литерал — walk идентичен.
            ExprKind::HandlerLit { methods, .. } | ExprKind::ProtocolLit { methods, .. } => {
                for m in methods {
                    match &m.body {
                        HandlerMethodBody::Expr(e) => self.walk_expr(e, gs, errors),
                        HandlerMethodBody::Block(b) => self.walk_block(b, gs, errors),
                    }
                }
            }
            ExprKind::IntLit(_) | ExprKind::FloatLit(_) | ExprKind::BoolLit(_)
            | ExprKind::StrLit(_) | ExprKind::CharLit(_) | ExprKind::UnitLit
            | ExprKind::NullPtrLit
            | ExprKind::Ident(_) | ExprKind::Path(_) | ExprKind::SelfAccess => {}
        }
    }

    fn walk_else(
        &self,
        eb: &ElseBranch,
        gs: &HashSet<String>,
        errors: &mut Vec<Diagnostic>,
    ) {
        match eb {
            ElseBranch::Block(b) => self.walk_block(b, gs, errors),
            ElseBranch::If(e) => self.walk_expr(e, gs, errors),
        }
    }

    fn walk_fn_sig_body(
        &self,
        sb: &FnSigBody,
        gs: &HashSet<String>,
        errors: &mut Vec<Diagnostic>,
    ) {
        for p in &sb.params {
            self.walk_typeref(&p.ty, gs, errors);
        }
        for e in &sb.effects {
            self.walk_typeref(e, gs, errors);
        }
        if let Some(rt) = &sb.return_type {
            self.walk_typeref(rt, gs, errors);
        }
        match &sb.body {
            FnBody::Expr(e) => self.walk_expr(e, gs, errors),
            FnBody::Block(b) => self.walk_block(b, gs, errors),
            FnBody::External => {}
        }
    }

    // ================================================================
    // Ф.1 — assignability: arg↔param и annotation↔RHS.
    //
    // Scope-aware проход: трекает типы локальных переменных, на каждом
    // call-site и `let`-аннотации сверяет совместимость. Числовые
    // литералы полиморфны по контексту (D44: `let x u8 = 200` валиден),
    // поэтому проверка literal-aware. Несовместимость → E7301.
    //
    // Резолвятся только однозначные callee (free fn / static-метод,
    // ровно один overload): instance-методы требуют receiver-type
    // inference, ненадёжной в bootstrap — их резолвит codegen.
    // ================================================================

    fn f1_check_fn(&self, fd: &FnDecl, errors: &mut Vec<Diagnostic>) {
        // Plan 124 (D220): set current_recv_type для priv field access scope
        // tracking. Instance + Static methods обa get receiver's type_name.
        let prev_recv = self.current_recv_type.borrow().clone();
        let new_recv = fd.receiver.as_ref().map(|r| r.type_name.clone());
        *self.current_recv_type.borrow_mut() = new_recv;
        let _recv_guard = PrivRecvGuard { ctx: self, prev: prev_recv };
        // Plan 124.6 (D225): set current_fn_test_access — fn body gets priv
        // access к listed types.
        let prev_ta = std::mem::take(&mut *self.current_fn_test_access.borrow_mut());
        *self.current_fn_test_access.borrow_mut() = fd.test_access_for.clone();
        let _ta_guard = PrivTestAccessGuard { ctx: self, prev: prev_ta };

        let gs = fn_generic_scope(fd);
        let mut scope: HashMap<String, TypeRef> = HashMap::new();
        for p in &fd.params {
            scope.insert(p.name.clone(), p.ty.clone());
        }
        // D175 (Plan 108): inject receiver type as "@" in scope so that
        // `check_target_readonly` can resolve @.field type for self-assignments.
        if let Some(recv) = &fd.receiver {
            if matches!(recv.kind, ReceiverKind::Instance) {
                scope.insert("@".to_string(), TypeRef::Named {
                    path: vec![recv.type_name.clone()],
                    generics: recv.generics.clone(),
                    span: recv.span,
                });
            }
        }
        // Plan 147 Ф.7 [M-147-param-index-freeze]: non-mut params are ro by
        // default (D176 §«Параметры функций»). Register them in ro_binding_names
        // so that check_target_readonly's is_through_ro_binding covers index
        // writes `arr[i] = x` on ro params, mirroring the Member-field check.
        //
        // Guard: only apply to functions defined in entry-module files (i.e.
        // the user's own code). Imported functions from std/prelude have already
        // been checked when their source was type-checked; re-enforcing here
        // would fire false positives on std library bodies that intentionally
        // write through array params.
        //
        // When the module has peer files (multi-file module), `entry_file_ids`
        // contains the FileIds of entry-module peers. When testing a single file
        // (no peer files), `entry_file_ids` is empty; in that case we use
        // file_id == 0 (the initial parse file) as the entry-module heuristic —
        // inline-merged imports are parsed as separate source strings with
        // file_id > 0, so this correctly skips them.
        //
        // Note: `ro b []int` (prefix synonym, valid per D176) and `b ro []int`
        // (type-position ro) produce the same AST (Readonly([]int), is_mut=false)
        // so no redundancy check is added here — the prefix synonym form is
        // explicitly documented as valid. The parser already catches `ro x ro T`
        // and `mut x mut T` for let-bindings (lines 5198-5215 in parser/mod.rs).
        let is_entry_fn = if self.entry_file_ids.is_empty() {
            fd.span.file_id == 0
        } else {
            self.entry_file_ids.contains(&fd.span.file_id)
        };
        let ro_snap_fn: std::collections::HashSet<String> =
            self.ro_binding_names.borrow().clone();
        if is_entry_fn {
            for p in &fd.params {
                // Add non-mut, non-consume params to ro_binding_names so
                // is_through_ro_binding fires on index writes `arr[i] = x` (P7
                // freeze, D246).  `mut` params and `consume` params may mutate.
                if !p.is_mut && !p.consume {
                    self.ro_binding_names.borrow_mut().insert(p.name.clone());
                }
            }
        }
        match &fd.body {
            FnBody::Expr(e) => {
                self.f1_expr(e, &gs, &mut scope, errors);
                self.f4_check_value(e, &scope, errors);
            }
            FnBody::Block(b) => self.f1_block(b, &gs, &mut scope, errors),
            FnBody::External => {}
        }
        // Restore ro_binding_names to the state before this fn's params were
        // added — function scopes are independent; param names from one fn
        // must not bleed into the next fn's checks.
        *self.ro_binding_names.borrow_mut() = ro_snap_fn;
    }

    fn f1_block(
        &self,
        b: &Block,
        gs: &HashSet<String>,
        scope: &mut HashMap<String, TypeRef>,
        errors: &mut Vec<Diagnostic>,
    ) {
        // Snapshot let-имён этого блока — восстановить scope на выходе
        // (block-out shadowing, как BoundCtx::walk_block).
        let mut snapshot: Vec<(String, Option<TypeRef>)> = Vec::new();
        for s in &b.stmts {
            if let Stmt::Let(d) = s {
                if let Some(name) = pattern_simple_name(&d.pattern) {
                    snapshot.push((name.clone(), scope.get(&name).cloned()));
                }
            }
        }
        // Plan 124.8 [M-124.8-ro-binding-scope] fix (2026-06-03):
        // snapshot `ro_binding_names` at block entry, restore at exit.
        // Without restore, `ro x = ...` inside ANY block leaks `x` into the
        // global ctx state — survives even cross-module type-check passes
        // (e.g., stdlib sha1.nv `ro v = ...` polluted user fixtures that
        // later used `mut v = ...`). Each block now properly cleans up the
        // entries it added. Outer scopes are preserved (transitivity D175).
        let ro_snapshot: std::collections::HashSet<String> =
            self.ro_binding_names.borrow().clone();
        for s in &b.stmts {
            self.f1_stmt(s, gs, scope, errors);
        }
        if let Some(t) = &b.trailing {
            self.f1_expr(t, gs, scope, errors);
            self.f4_check_value(t, scope, errors);
        }
        for (n, prev) in snapshot {
            match prev {
                Some(t) => { scope.insert(n, t); }
                None => { scope.remove(&n); }
            }
        }
        *self.ro_binding_names.borrow_mut() = ro_snapshot;
    }

    fn f1_stmt(
        &self,
        s: &Stmt,
        gs: &HashSet<String>,
        scope: &mut HashMap<String, TypeRef>,
        errors: &mut Vec<Diagnostic>,
    ) {
        match s {
            Stmt::Expr(e) => self.f1_expr(e, gs, scope, errors),
            Stmt::Let(d) => {
                self.f1_expr(&d.value, gs, scope, errors);
                self.f4_check_value(&d.value, scope, errors);
                // Plan 124 (D220/D221): priv field PATTERN check — recursive,
                // covers nested destructure через sub-field types.
                let scrut_ty = self.infer_expr_type(&d.value, scope);
                self.check_priv_pattern_recursive(&d.pattern, scrut_ty.as_ref(), errors);
                // Plan 124.8 (D175 amend): track ro-binding names. `ro x = expr`
                // делает binding immutable — даже `mut field` через `x.f = ...`
                // блокируется (Rust-style binding dominates).
                // Cleared on enclosing block exit via f1_block snapshot/restore
                // (fixed 2026-06-03 — [M-124.8-ro-binding-scope] closed).
                //
                // Shadow semantics: at each let, replace the prior entry (if
                // any) — `ro x; { mut x; x.field = ... }` works because the
                // inner `mut x` removes `x` from ro_binding_names. Outer
                // state restored by enclosing f1_block snapshot/restore.
                if let Some(name) = pattern_simple_name(&d.pattern) {
                    let mut set = self.ro_binding_names.borrow_mut();
                    set.remove(&name);
                    if !d.mutable {
                        set.insert(name);
                    }
                }
                // Ф.1: annotation ↔ RHS.
                if let (Some(ann), Some(name)) =
                    (&d.ty, pattern_simple_name(&d.pattern))
                {
                    // Plan 147 (D246): pass the binding's L1 mutability so the
                    // E_READONLY_COERCE content-view check honours P7 (bare
                    // `ro x` = freeze) — a ro source into `ro a T` is OK, into
                    // `mut a T` is a coercion error.
                    self.f1_check_assign_let(
                        &d.value, ann, &name, d.mutable, gs, scope, errors,
                    );
                }
                // Регистрируем переменную в scope: тип = аннотация, иначе
                // inferred из RHS.
                if let Some(name) = pattern_simple_name(&d.pattern) {
                    match d.ty.clone()
                        .or_else(|| self.infer_expr_type(&d.value, scope))
                    {
                        Some(t) => { scope.insert(name, t); }
                        None => { scope.remove(&name); }
                    }
                }
            }
            // Plan 114.4 Ф.2: scope-local const — pass-through (no-op for now).
            Stmt::Const(_) => {}
            Stmt::Assign { target, value, .. } => {
                self.f1_expr(target, gs, scope, errors);
                self.f1_expr(value, gs, scope, errors);
                // D175/D176 (Plan 108): check that we're not assigning to a
                // readonly field or through a readonly index.
                self.check_target_readonly(target, scope, errors);
                // **Plan 147 Ф.3 (D246, L1 binding):** reassigning the NAME
                // (`x = v` where target is a plain Ident) requires a `mut`
                // binding. A `ro`-bound local is fixed (L1) — even an explicit
                // `mut T` content-view does NOT make the name reassignable
                // (R2-split: `ro r mut Point` → `r.x` ✅ / `r = X` ❌). This
                // closes the latent reassignment hole in D36 (previously only
                // mut-method / index-write were enforced, plain rebind slipped
                // through).
                if let ExprKind::Ident(name) = &target.kind {
                    if self.ro_binding_names.borrow().contains(name) {
                        errors.push(Diagnostic::new(
                            format!(
                                "[E_LOCAL_NOT_MUT] local-binding `{}` не помечен `mut`, \
                                 но переприсваивается (`{} = ...`). `ro`-binding фиксирует \
                                 имя (L1 — Plan 147 / D246); для переприсваивания используй \
                                 `mut {} = ...`. (Явный `mut T` content-view не делает имя \
                                 переприсваиваемым — это R2-split: `ro r mut T` разрешает \
                                 `r.field = v`, но не `r = X`.)",
                                name, name, name),
                            target.span,
                        ));
                    }
                }
                // [M-scalar-nonliteral-narrowing-not-enforced] (D54): reassignment
                // `a = c` where a non-literal wider int narrows into `a`'s declared
                // int type needs an explicit `as`. Reassignment has no general
                // `assignable()` check, so do a focused narrowing-only compare here.
                // Literals coerce by context (skip); `as`-casts infer as their
                // target width (no narrowing seen). Only fires int→int narrowing.
                if let ExprKind::Ident(name) = &target.kind {
                    let is_num_lit = matches!(
                        value.kind,
                        ExprKind::IntLit(_) | ExprKind::FloatLit(_)
                    ) || matches!(&value.kind,
                        ExprKind::Unary { op: UnOp::Neg, operand }
                        if matches!(operand.kind, ExprKind::IntLit(_) | ExprKind::FloatLit(_)));
                    if !is_num_lit {
                        if let (Some(target_ty), Some(value_ty)) =
                            (scope.get(name).cloned(), self.infer_expr_type(value, scope))
                        {
                            // U.5.2: single-source narrowing via `would_narrow_into`
                            // on DIRECT types (folds the legacy `is_int_narrowing`).
                            if ResolvedType::from_type_ref(&value_ty)
                                .would_narrow_into(&ResolvedType::from_type_ref(&target_ty))
                            {
                                errors.push(Diagnostic::new(
                                    format!(
                                        "[E_IMPLICIT_NARROWING] cannot assign value of \
                                         type `{}` to `{}` of narrower type `{}` — \
                                         implicit int narrowing loses range; use an \
                                         explicit `... as {}` cast (D54)",
                                        typeref_display(&value_ty),
                                        name,
                                        typeref_display(&target_ty),
                                        typeref_display(&target_ty),
                                    ),
                                    value.span,
                                ));
                            }
                        }
                    }
                }
            }
            Stmt::Return { value, .. } => {
                if let Some(v) = value {
                    self.f1_expr(v, gs, scope, errors);
                    self.f4_check_value(v, scope, errors);
                }
            }
            Stmt::Throw { value, .. } => {
                self.f1_expr(value, gs, scope, errors);
                self.f4_check_value(value, scope, errors);
            }
            Stmt::Break(_) | Stmt::Continue(_) | Stmt::Reveal { .. } => {}
            Stmt::Defer { body, .. } | Stmt::ErrDefer { body, .. }
            | Stmt::OkDefer { body, .. } | Stmt::DeferWithResult { body, .. } => {
                self.f1_expr(body, gs, scope, errors);
            }
            // Plan 110 D188: walk init + body (full D188 R1-R6 check лежит
            // в Plan 110.1.2/110.1.3 — здесь scaffold walking).
            Stmt::ConsumeScope { init, body, .. } => {
                self.f1_expr(init, gs, scope, errors);
                self.f4_check_value(init, scope, errors);
                for s in &body.stmts {
                    self.f1_stmt(s, gs, scope, errors);
                }
                if let Some(t) = &body.trailing {
                    self.f1_expr(t, gs, scope, errors);
                }
            }
            Stmt::AssertStatic { expr, .. } | Stmt::Assume { expr, .. } => {
                self.f1_expr(expr, gs, scope, errors);
            }
            Stmt::Apply { args, .. } => {
                for a in args {
                    self.f1_expr(a, gs, scope, errors);
                }
            }
            Stmt::Calc { steps, .. } => {
                for step in steps {
                    self.f1_expr(&step.expr, gs, scope, errors);
                }
            }
            // Plan 136: tuple destructuring assignment.
            Stmt::TupleAssign { lhs, rhs, .. } => {
                for e in lhs { self.f1_expr(e, gs, scope, errors); }
                for e in rhs { self.f1_expr(e, gs, scope, errors); }
            }
        }
    }

    /// Plan 152.1 Ф.1: strip `ro`/`mut`/`unsafe` wrappers and return the base
    /// `Named` type's last path segment (e.g. `"str"`, `"Range"`, `"CharsIter"`),
    /// or `None` for non-Named types.
    fn typeref_named_base(t: &TypeRef) -> Option<&str> {
        match t {
            TypeRef::Named { path, .. } => path.last().map(|s| s.as_str()),
            TypeRef::Readonly(inner, _)
            | TypeRef::Mut(inner, _)
            | TypeRef::Unsafe(inner, _) => Self::typeref_named_base(inner),
            _ => None,
        }
    }

    fn f1_expr(
        &self,
        e: &Expr,
        gs: &HashSet<String>,
        scope: &mut HashMap<String, TypeRef>,
        errors: &mut Vec<Diagnostic>,
    ) {
        match &e.kind {
            ExprKind::Call { func, args, trailing } => {
                self.f1_expr(func, gs, scope, errors);
                for a in args {
                    self.f1_expr(a.expr(), gs, scope, errors);
                    self.f4_check_value(a.expr(), scope, errors);
                }
                if let Some(t) = trailing {
                    match t {
                        Trailing::Block(b) => self.f1_block(b, gs, scope, errors),
                        Trailing::LegacyBlockWithParams(tb) => {
                            self.f1_block(&tb.body, gs, scope, errors)
                        }
                        Trailing::Fn(sb) => {
                            self.f1_fn_sig_body(sb, gs, scope, errors)
                        }
                    }
                }
                self.f1_check_call(
                    func, args, trailing.is_some(), gs, scope, errors,
                );
                self.f5_check_tuple_construct(func, args, e.span, scope, errors);
            }
            ExprKind::TurboFish { base, .. } => {
                self.f1_expr(base, gs, scope, errors)
            }
            ExprKind::As(inner, _) | ExprKind::Is(inner, _) => {
                self.f1_expr(inner, gs, scope, errors)
            }
            ExprKind::Binary { left, right, .. } => {
                self.f1_expr(left, gs, scope, errors);
                self.f1_expr(right, gs, scope, errors);
                self.f4_check_value(left, scope, errors);
                self.f4_check_value(right, scope, errors);
            }
            ExprKind::Unary { operand, .. } => {
                self.f1_expr(operand, gs, scope, errors);
                self.f4_check_value(operand, scope, errors);
            }
            ExprKind::Try(inner) | ExprKind::Bang(inner) => {
                self.f1_expr(inner, gs, scope, errors)
            }
            ExprKind::Coalesce(a, b) => {
                self.f1_expr(a, gs, scope, errors);
                self.f1_expr(b, gs, scope, errors);
            }
            ExprKind::Member { obj, name } => {
                self.f1_expr(obj, gs, scope, errors);
                self.f3_check_member(obj, name, e.span, scope, errors);
            }
            ExprKind::Index { obj, index } => {
                self.f1_expr(obj, gs, scope, errors);
                self.f1_expr(index, gs, scope, errors);
                // Plan 152.1 Ф.1 (D249): `str` is NOT integer-indexable — codepoint
                // indexing a UTF-8 string is O(n) hiding behind `[i]`. Only the
                // byte-range slice `str[a..b]` (Range index) is valid. Discriminate
                // by the INDEX TYPE (not just a literal `a..b`) so `let r = 2..5;
                // s[r]` is also accepted. Element access goes through a lens.
                let index_is_range = matches!(index.kind, ExprKind::Range { .. })
                    || self.infer_expr_type(index, scope).as_ref()
                        .and_then(Self::typeref_named_base) == Some("Range");
                if !index_is_range {
                    if let Some(obj_tr) = self.infer_expr_type(obj, scope) {
                        if Self::typeref_named_base(&obj_tr) == Some("str") {
                            errors.push(Diagnostic::new(
                                "[E_STR_NO_INT_INDEX] `str` cannot be indexed by an integer — \
                                 codepoint indexing a UTF-8 string is O(n) masquerading as O(1) \
                                 (D249). Use a lens: byte `s.as_bytes()[i]` (O(1)), codepoint \
                                 `s.as_chars().nth(i)` (O(n)); the only `str[..]` form is the \
                                 byte-range slice `s[a..b]`.".to_string(),
                                e.span,
                            ));
                        }
                    }
                }
            }
            ExprKind::If { cond, then, else_ } => {
                self.f1_expr(cond, gs, scope, errors);
                self.f1_block(then, gs, scope, errors);
                if let Some(eb) = else_ {
                    self.f1_else(eb, gs, scope, errors);
                }
            }
            ExprKind::IfLet { pattern, scrutinee, then, else_, .. } => {
                self.f1_expr(scrutinee, gs, scope, errors);
                // Plan 124.2 (D221): pattern destructure priv-field check.
                let scrut_ty = self.infer_expr_type(scrutinee, scope);
                self.check_priv_pattern_recursive(pattern, scrut_ty.as_ref(), errors);
                self.f1_block(then, gs, scope, errors);
                if let Some(eb) = else_ {
                    self.f1_else(eb, gs, scope, errors);
                }
            }
            ExprKind::Match { scrutinee, arms } => {
                self.f1_expr(scrutinee, gs, scope, errors);
                // Plan 124.2 (D221): each arm's pattern checked vs scrutinee type.
                let scrut_ty = self.infer_expr_type(scrutinee, scope);
                for arm in arms {
                    self.check_priv_pattern_recursive(&arm.pattern, scrut_ty.as_ref(), errors);
                    if let Some(g) = &arm.guard {
                        self.f1_expr(g, gs, scope, errors);
                    }
                    match &arm.body {
                        MatchArmBody::Expr(e) => {
                            self.f1_expr(e, gs, scope, errors)
                        }
                        MatchArmBody::Block(b) => {
                            self.f1_block(b, gs, scope, errors)
                        }
                    }
                }
            }
            ExprKind::Block(b) => self.f1_block(b, gs, scope, errors),
            ExprKind::ArrayLit(elems) => {
                for el in elems {
                    match el {
                        ArrayElem::Item(e) | ArrayElem::Spread(e) => {
                            self.f1_expr(e, gs, scope, errors)
                        }
                    }
                }
            }
            ExprKind::MapLit { elems, .. } => {
                for (k, v) in crate::ast::MapElem::cloned_pairs(elems).iter() {
                    self.f1_expr(k, gs, scope, errors);
                    self.f1_expr(v, gs, scope, errors);
                }
            }
            ExprKind::TupleLit(elems) => {
                for e in elems {
                    self.f1_expr(e, gs, scope, errors);
                }
            }
            ExprKind::RecordLit { fields, .. } => {
                for f in fields {
                    if let Some(v) = &f.value {
                        self.f1_expr(v, gs, scope, errors);
                    }
                }
            }
            ExprKind::TaggedTemplate { tag, args, .. } => {
                self.f1_expr(tag, gs, scope, errors);
                for a in args {
                    self.f1_expr(a, gs, scope, errors);
                }
            }
            ExprKind::InterpolatedStr { parts } => {
                for p in parts {
                    if let InterpStrPart::Expr { expr: e, spec: _ } = p {
                        self.f1_expr(e, gs, scope, errors);
                    }
                }
            }
            ExprKind::Lambda { body, .. } => {
                self.f1_expr(body, gs, scope, errors)
            }
            ExprKind::ClosureLight { body, .. } => match body {
                ClosureBody::Expr(e) => self.f1_expr(e, gs, scope, errors),
                ClosureBody::Block(b) => self.f1_block(b, gs, scope, errors),
            },
            ExprKind::ClosureFull(sb) => {
                self.f1_fn_sig_body(sb, gs, scope, errors)
            }
            ExprKind::Spawn(body) => self.f1_expr(body, gs, scope, errors),
            ExprKind::Detach(body) | ExprKind::Blocking(body) => self.f1_block(body, gs, scope, errors),
            ExprKind::Supervised { body, cancel } => {
                if let Some(c) = cancel {
                    self.f1_expr(c, gs, scope, errors);
                }
                self.f1_block(body, gs, scope, errors);
            }
            ExprKind::Forbid { body, .. } => {
                self.f1_block(body, gs, scope, errors)
            }
            ExprKind::Realtime { body, .. } => {
                self.f1_block(body, gs, scope, errors)
            }
            ExprKind::ParallelFor { pattern, iter, body, elem_type } => {
                self.f1_expr(iter, gs, scope, errors);
                if let Some(ann) = elem_type {
                    self.f1_check_for_elem(iter, ann, gs, scope, errors);
                }
                // Plan 124.2 (D221): destructure pattern in parallel-for.
                let elem_ty = elem_type.clone()
                    .or_else(|| self.infer_iter_elem_type(iter, scope));
                self.check_priv_pattern_recursive(pattern, elem_ty.as_ref(), errors);
                self.f1_for_body(elem_type, pattern, body, gs, scope, errors);
            }
            ExprKind::For { pattern, iter, body, elem_type, .. } => {
                self.f1_expr(iter, gs, scope, errors);
                // Plan 87 Ф.3: явная аннотация типа элемента — checked
                // assertion против фактического типа элемента итератора.
                if let Some(ann) = elem_type {
                    self.f1_check_for_elem(iter, ann, gs, scope, errors);
                }
                // Plan 124.2 (D221): destructure pattern in for-in loop.
                let elem_ty = elem_type.clone()
                    .or_else(|| self.infer_iter_elem_type(iter, scope));
                self.check_priv_pattern_recursive(pattern, elem_ty.as_ref(), errors);
                self.f1_for_body(elem_type, pattern, body, gs, scope, errors);
            }
            ExprKind::While { cond, body, .. } => {
                self.f1_expr(cond, gs, scope, errors);
                self.f1_block(body, gs, scope, errors);
            }
            ExprKind::WhileLet { pattern, scrutinee, body, .. } => {
                self.f1_expr(scrutinee, gs, scope, errors);
                // Plan 124.2 (D221): destructure pattern in while-let.
                let scrut_ty = self.infer_expr_type(scrutinee, scope);
                self.check_priv_pattern_recursive(pattern, scrut_ty.as_ref(), errors);
                self.f1_block(body, gs, scope, errors);
            }
            ExprKind::Loop { body, .. } => {
                self.f1_block(body, gs, scope, errors)
            }
            ExprKind::Select { arms } => {
                for arm in arms {
                    match &arm.op {
                        SelectOp::Recv { chan, .. } => {
                            self.f1_expr(chan, gs, scope, errors)
                        }
                        SelectOp::Send { chan, value } => {
                            self.f1_expr(chan, gs, scope, errors);
                            self.f1_expr(value, gs, scope, errors);
                        }
                        SelectOp::Default => {}
                    }
                    if let Some(g) = &arm.guard {
                        self.f1_expr(g, gs, scope, errors);
                    }
                    self.f1_block(&arm.body, gs, scope, errors);
                }
            }
            ExprKind::Range { start, end, .. } => {
                if let Some(s) = start { self.f1_expr(s, gs, scope, errors); }
                if let Some(e) = end { self.f1_expr(e, gs, scope, errors); }
            }
            ExprKind::Throw(inner) => self.f1_expr(inner, gs, scope, errors),
            ExprKind::Interrupt(opt) => {
                if let Some(e) = opt {
                    self.f1_expr(e, gs, scope, errors);
                }
            }
            ExprKind::With { body, .. } => {
                self.f1_block(body, gs, scope, errors)
            }
            ExprKind::Forall { range, body, .. }
            | ExprKind::Exists { range, body, .. } => {
                self.f1_expr(range, gs, scope, errors);
                self.f1_expr(body, gs, scope, errors);
            }
            // Plan 97 Ф.4 (D142): protocol-литерал — f1_expr walk
            // идентичен.
            ExprKind::HandlerLit { methods, .. } | ExprKind::ProtocolLit { methods, .. } => {
                for m in methods {
                    match &m.body {
                        HandlerMethodBody::Expr(e) => {
                            self.f1_expr(e, gs, scope, errors)
                        }
                        HandlerMethodBody::Block(b) => {
                            self.f1_block(b, gs, scope, errors)
                        }
                    }
                }
            }
            ExprKind::IntLit(_) | ExprKind::FloatLit(_) | ExprKind::BoolLit(_)
            | ExprKind::StrLit(_) | ExprKind::CharLit(_) | ExprKind::UnitLit
            | ExprKind::NullPtrLit
            | ExprKind::Ident(_) | ExprKind::Path(_) | ExprKind::SelfAccess => {}
        }
    }

    fn f1_else(
        &self,
        eb: &ElseBranch,
        gs: &HashSet<String>,
        scope: &mut HashMap<String, TypeRef>,
        errors: &mut Vec<Diagnostic>,
    ) {
        match eb {
            ElseBranch::Block(b) => self.f1_block(b, gs, scope, errors),
            ElseBranch::If(e) => self.f1_expr(e, gs, scope, errors),
        }
    }

    fn f1_fn_sig_body(
        &self,
        sb: &FnSigBody,
        gs: &HashSet<String>,
        scope: &mut HashMap<String, TypeRef>,
        errors: &mut Vec<Diagnostic>,
    ) {
        match &sb.body {
            FnBody::Expr(e) => {
                self.f1_expr(e, gs, scope, errors);
                self.f4_check_value(e, scope, errors);
            }
            FnBody::Block(b) => self.f1_block(b, gs, scope, errors),
            FnBody::External => {}
        }
    }

    /// Ф.1: проверить `let <name> <ann> = <value>` на совместимость.
    fn f1_check_assign_let(
        &self,
        value: &Expr,
        ann: &TypeRef,
        name: &str,
        binding_mut: bool,
        gs: &HashSet<String>,
        scope: &HashMap<String, TypeRef>,
        errors: &mut Vec<Diagnostic>,
    ) {
        match self.assignable(value, ann, gs, gs, scope) {
            Compat::Bad { found } => {
                errors.push(
                    Diagnostic::new(
                        format!(
                            "[E7301] cannot assign value of type `{}` to `{}` \
                             declared as `{}`",
                            found, name, typeref_display(ann),
                        ),
                        value.span,
                    )
                    .with_note_at(
                        "type expected because of this annotation".to_string(),
                        ann.span(),
                    ),
                );
            }
            // Plan 142 (D227): целочисленный литерал вне диапазона sized-типа.
            Compat::OutOfRange { msg } => {
                errors.push(
                    Diagnostic::new(
                        format!("[E_LIT_OUT_OF_RANGE] {msg}"),
                        value.span,
                    )
                    .with_note_at(
                        "type expected because of this annotation".to_string(),
                        ann.span(),
                    ),
                );
            }
            // [M-scalar-nonliteral-narrowing-not-enforced] (D54).
            Compat::Narrowing { from, to } => {
                errors.push(
                    Diagnostic::new(
                        format!(
                            "[E_IMPLICIT_NARROWING] cannot assign value of type `{}` \
                             to `{}` of narrower type `{}` — implicit int narrowing \
                             loses range; use an explicit `... as {}` cast (D54)",
                            from, name, to, to,
                        ),
                        value.span,
                    )
                    .with_note_at(
                        "type expected because of this annotation".to_string(),
                        ann.span(),
                    ),
                );
            }
            Compat::Ok | Compat::Unknown => {}
        }
        // D176 (Plan 108): `readonly T → T` is forbidden (E_READONLY_COERCE).
        // `T → readonly T` is allowed (auto-coerce, narrowing rights).
        //
        // **Plan 147 Ф.3 (D246):** coercion is decided by the target's L2
        // *content-view*, which combines the explicit type modifier (L2) with
        // the binding (L1, P7 «bare `ro x` = freeze»):
        //   - explicit `ro T` annotation        → ro content-view (freeze)
        //   - explicit `mut T` annotation        → mut content-view
        //   - bare `T` under a `ro` binding      → ro content-view (P7 freeze)
        //   - bare `T` under a `mut` binding      → mut content-view
        // A ro source coerced into a mut content-view is `E_READONLY_COERCE`;
        // into a ro content-view it is OK. This makes the oracle row-D split
        // work: `-> ro Value` then `ro a Value = f()` ✅ (target frozen by the
        // `ro` binding) vs `mut a Value = f()` ❌ (mut content-view).
        let target_content_is_mut = if ann.is_readonly() {
            false
        } else if ann.is_mut() {
            true
        } else {
            // bare value/record type — content-view follows the binding (P7).
            binding_mut
        };
        if target_content_is_mut {
            if let Some(value_ty) = self.infer_expr_type(value, scope) {
                if value_ty.is_readonly() {
                    errors.push(Diagnostic::new(
                        format!(
                            "[E_READONLY_COERCE] cannot coerce `readonly {}` to `{}`: \
                             removing readonly is not allowed. Use `.to_owned()` to \
                             get a mutable copy.",
                            typeref_display(value_ty.strip_readonly()),
                            typeref_display(ann),
                        ),
                        value.span,
                    ));
                }
            }
        }
    }

    // ── Plan 124.2 (D221): pattern destructure priv-field check ───────────
    //
    // Helper recursively walks a Pattern; when it encounters Pattern::Record
    // on a type with priv fields AND outside type-method scope, emits
    // E_PRIV_FIELD_PATTERN per priv field. Recurses into sub-patterns
    // (nested destructure) using the corresponding RecordField type.
    //
    /// Plan 124.6 (D224 §4): unified priv access predicate. Returns true if
    /// current fn body has priv access to `tname` (i.e. may read/write/
    /// init/destructure priv-marked fields of that type).
    ///
    /// D224 §4 combined predicate — allowed when ANY of:
    /// 1. current_recv_type == tname  — canonical type-method scope (D220).
    /// 2. in_test_block && same_module(current_module, type_defining_modules[tname])
    ///    — implicit test grant: any test block in the same module may access
    ///    priv fields of types declared in that module (D224 §4 rule-2).
    /// 3. in_test_block && tname ∈ test_block_test_access
    ///    — explicit `test "…" #test_access(T) { }` grant (D224 §4 rule-3).
    /// 4. current_recv_type ∈ type_pub_to[tname]
    ///    — type-level friend via `#pub_to(FriendType)` on the type decl
    ///    (D224 §4 rule-4). Per-field visible_to (rule for individual fields)
    ///    is handled at call sites via `priv_field_access_allowed`.
    ///
    /// Legacy fn-level escape hatch (`#test_access(T)` on an `fn` decl,
    /// from current_fn_test_access) is also preserved as a sub-case of
    /// rule-3 for backward compat with D225.
    fn priv_access_allowed_base(&self, tname: &str) -> bool {
        // Rule 1: inside the type's own method body.
        let current_recv = self.current_recv_type.borrow();
        if current_recv.as_deref() == Some(tname) {
            return true;
        }

        // Rule 2 + 3 (test-block rules).
        if self.in_test_block.get() {
            // Rule 2: implicit same-module grant inside a test block.
            let current_mod = self.current_module.borrow();
            if !current_mod.is_empty() {
                if let Some(def_mod) = self.type_defining_modules.get(tname) {
                    if def_mod.as_slice() == current_mod.as_slice() {
                        return true;
                    }
                }
            }
            // Rule 3a: explicit test_access list on the TestDecl itself.
            if self.test_block_test_access.borrow().iter().any(|t| t == tname) {
                return true;
            }
        }

        // Rule 3b (legacy): fn-level #test_access(T) escape hatch (D225).
        if self.current_fn_test_access.borrow().iter().any(|t| t == tname) {
            return true;
        }

        // Rule 4: type-level friend (`#pub_to(FriendType)` on tname's TypeDecl).
        if let Some(cur) = current_recv.as_deref() {
            if let Some(pub_to) = self.type_pub_to.get(tname) {
                if pub_to.iter().any(|f| f == cur) {
                    return true;
                }
            }
        }

        false
    }

    /// Plan 160 (D281) Ф.2: true when the caller is in the SAME module as
    /// the type `tname` was declared in. Used for `priv` (module-private) boundary:
    /// fields with `priv_module_field=true` are allowed within the module.
    ///
    /// Conservative (deny) when:
    /// - `type_defining_modules` has no entry for `tname` (unknown origin),
    /// - `current_module` is empty (no module context set),
    /// - the modules differ.
    fn module_priv_access_allowed(&self, tname: &str) -> bool {
        let current = self.current_module.borrow();
        if current.is_empty() {
            return false;
        }
        match self.type_defining_modules.get(tname) {
            Some(def_mod) => def_mod.as_slice() == current.as_slice(),
            None => false,
        }
    }

    /// Plan 162 Ф.3: returns true iff `method_name` on type `type_name` is an
    /// **inherent** method — i.e. declared in the SAME module as `type_name`.
    ///
    /// Inherent: `type_method_map[type_name][method_name]` contains at least
    /// one module_name equal to `type_defining_modules[type_name]`.
    ///
    /// Extension: method declared in a DIFFERENT module (no overlap).
    ///
    /// Returns false (treated as extension / unknown) when:
    /// - type_name not in type_defining_modules (unknown origin),
    /// - method_name not in type_method_map[type_name],
    /// - no module_name in the method list matches the type's defining module.
    fn is_inherent_method(&self, type_name: &str, method_name: &str) -> bool {
        let Some(type_module) = self.type_defining_modules.get(type_name) else {
            return false;
        };
        let Some(type_methods) = self.type_method_map.get(type_name) else {
            return false;
        };
        let Some(method_modules) = type_methods.get(method_name) else {
            return false;
        };
        method_modules.iter().any(|m| m == type_module)
    }

    /// Plan 162 Ф.5: extension method policy enforcement.
    ///
    /// Called when a method `method_name` IS found in `method_table` for type
    /// `type_name`. Emits:
    ///   - `[E_EXTENSION_METHOD_NEEDS_IMPORT]` if the method is a pure extension
    ///     (declared in a DIFFERENT module than the type) and no declaring module
    ///     is imported in the current file.
    ///   - `[E_METHOD_AMBIGUOUS]` if two or more extension modules providing this
    ///     method are both imported.
    ///
    /// Conservative (no error) when:
    ///   - `type_defining_modules` has no entry for the type (unknown origin),
    ///   - `type_method_map` has no entry for the method (synthetic / no attribution),
    ///   - at least one declaring module equals the type's defining module (inherent),
    ///   - exactly one extension module is imported.
    fn check_extension_method_policy(
        &self,
        type_name: &str,
        method_name: &str,
        span: Span,
        errors: &mut Vec<Diagnostic>,
    ) {
        // Extension method policy only fires for call sites in ENTRY-MODULE
        // peer files. Checking imported module bodies (stdlib methods calling
        // other stdlib methods) would cause false positives because transitive
        // method bodies are not "user code" — their imports are not in scope.
        // Conservative: if entry_file_ids is empty (single-file legacy, no
        // peer_files), skip.
        if !self.entry_file_ids.is_empty() && !self.entry_file_ids.contains(&span.file_id) {
            return;
        }
        // Conservative: if we can't determine the type's defining module, allow.
        let Some(type_module) = self.type_defining_modules.get(type_name) else {
            return;
        };
        // Extension method policy only applies to USER-DEFINED types.
        // Stdlib types (str, int, bool, Option, etc.) have methods spread
        // across multiple prelude/runtime modules — these are all part of the
        // standard library and implicitly available without explicit import.
        // Skip the check if the type's defining module starts with "std",
        // "prelude", or "runtime" (all stdlib conventional prefixes).
        // Additionally treat any method whose declaring module also starts
        // with "std"/"prelude"/"runtime" as inherent (see partition below).
        let is_stdlib_module = |m: &Vec<String>| {
            matches!(m.first().map(|s| s.as_str()), Some("std") | Some("prelude") | Some("runtime"))
        };
        if is_stdlib_module(type_module) {
            return;
        }
        let Some(type_methods) = self.type_method_map.get(type_name) else {
            return; // no method attribution — could be synthetic; allow
        };
        // Methods are stored in type_method_map with their original AST name,
        // which includes the leading '@' for instance methods (e.g. "@doubled").
        // The call-site `method_name` arrives WITHOUT '@' (plain "doubled").
        // Try both the bare name and the '@'-prefixed form.
        let bare_name = method_name.trim_start_matches('@');
        let at_name = format!("@{bare_name}");
        let method_modules = type_methods
            .get(bare_name)
            .or_else(|| type_methods.get(at_name.as_str()));
        let Some(method_modules) = method_modules else {
            return; // method not in type_method_map — synthetic or compiler-generated; allow
        };

        // Partition into inherent (same module as type) and extension (different).
        // A method whose declaring module equals the type's defining module is
        // INHERENT. A method from a DIFFERENT module is EXTENSION.
        // Additional rule: a method from ANY stdlib module ("std", "prelude",
        // "runtime" first-segment) is treated as inherent regardless of exact
        // module match — stdlib methods are always implicitly available.
        let mut extension_modules: Vec<&Vec<String>> = Vec::new();
        let mut has_inherent = false;
        for mod_name in method_modules {
            if mod_name == type_module || is_stdlib_module(mod_name) {
                has_inherent = true;
            } else {
                extension_modules.push(mod_name);
            }
        }

        // Inherent methods are always accessible when the type is in scope.
        if has_inherent {
            return;
        }

        // Pure extension: check which extension modules are imported.
        if extension_modules.is_empty() {
            return; // no attribution — allow
        }

        // Check import status by last segment of module path (or alias).
        // Use entry_imported_modules (direct imports of entry-module files only)
        // to exclude transitive imports from non-entry peers.
        let imported_ext: Vec<&Vec<String>> = extension_modules
            .iter()
            .filter(|m| {
                m.last().map_or(false, |last| self.entry_imported_modules.contains(last.as_str()))
            })
            .cloned()
            .collect();

        if imported_ext.is_empty() {
            // No extension module imported — require explicit import.
            let hint = extension_modules[0].last().map(|s| s.as_str()).unwrap_or("?");
            errors.push(Diagnostic::new(
                format!(
                    "[E_EXTENSION_METHOD_NEEDS_IMPORT] extension method `{}.{}()` \
                     requires the defining module to be imported. \
                     Hint: add `import ...{{{}}}` or import the module \
                     that declares this extension method.",
                    type_name, bare_name, hint,
                ),
                span,
            ));
        } else if imported_ext.len() > 1 {
            // Multiple extension modules imported — ambiguous.
            let mod_names: Vec<String> = imported_ext
                .iter()
                .map(|m| m.join("."))
                .collect();
            errors.push(Diagnostic::new(
                format!(
                    "[E_METHOD_AMBIGUOUS] extension method `{}.{}()` is ambiguous: \
                     defined in multiple imported modules ({}). \
                     Hint: import only one extension module that provides this method.",
                    type_name, bare_name, mod_names.join(", "),
                ),
                span,
            ));
        }
        // Exactly one extension module imported — OK, no error.
    }

    /// Combines `priv_access_allowed_base(tname)` с per-field visible_to:
    /// true if access allowed, considering field's friend list.
    fn priv_field_access_allowed(&self, tname: &str, visible_to: &[String]) -> bool {
        if self.priv_access_allowed_base(tname) {
            return true;
        }
        let current_recv = self.current_recv_type.borrow();
        if let Some(cur) = current_recv.as_deref() {
            if visible_to.iter().any(|t| t == cur) {
                return true;
            }
        }
        false
    }

    // Pattern::Or → recurses into all alternatives (same scrutinee_ty).
    // Pattern::Binding → recurses into inner.
    // Pattern::Tuple — Plan 124.4 covers tuple priv; here no-op (no type
    // info per-position without a concrete TupleType for ad-hoc tuples).
    // Pattern::Variant — sum-variant pattern; field privacy is encoded
    // inside variant ctor (out of scope V1).
    //
    // The `rest: bool` flag on Pattern::Record marks `..` syntactic
    // presence; it does NOT bind anything, so does NOT leak priv (D221 §3).
    fn check_priv_pattern_recursive(
        &self,
        pattern: &Pattern,
        scrutinee_ty: Option<&TypeRef>,
        errors: &mut Vec<Diagnostic>,
    ) {
        match pattern {
            Pattern::Record { type_path, fields, span, .. } => {
                let tname_opt: Option<String> = type_path
                    .as_ref()
                    .and_then(|p| p.last().cloned())
                    .or_else(|| match scrutinee_ty {
                        Some(TypeRef::Named { path, .. }) => path.last().cloned(),
                        Some(TypeRef::Readonly(inner, _)) => match inner.as_ref() {
                            TypeRef::Named { path, .. } => path.last().cloned(),
                            _ => None,
                        },
                        _ => None,
                    });
                let Some(tname) = tname_opt else { return };
                let Some(td) = self.types.get(tname.as_str()) else { return };
                // Plan 124.2 + 124.4 + 124.6 (D221+D222+D224): unified priv
                // check (Record + NamedTuple). Per-field visible_to taken into
                // account (Plan 124.6).
                // Plan 160 (D281) Ф.2: priv_module_field added for module-boundary.
                struct FieldMeta { name: String, priv_field: bool, priv_module_field: bool, visible_to: Vec<String>, ty: TypeRef }
                let metas: Vec<FieldMeta> = match &td.kind {
                    TypeDeclKind::Record(rec_fields) => rec_fields.iter().map(|f| FieldMeta {
                        name: f.name.clone(),
                        priv_field: f.priv_field,
                        priv_module_field: f.priv_module_field,
                        visible_to: f.visible_to.clone(),
                        ty: f.ty.clone(),
                    }).collect(),
                    TypeDeclKind::NamedTuple(nt_fields) => nt_fields.iter().map(|f| FieldMeta {
                        name: f.name.clone(),
                        priv_field: f.priv_field,
                        priv_module_field: f.priv_module_field,
                        visible_to: f.visible_to.clone(),
                        ty: f.ty.clone(),
                    }).collect(),
                    _ => return,
                };
                let base_allowed = self.priv_access_allowed_base(tname.as_str());
                if !base_allowed {
                    for pf in fields {
                        if let Some(meta) = metas.iter().find(|m| m.name == pf.name) {
                            if meta.priv_field
                                && !self.priv_field_access_allowed(tname.as_str(), &meta.visible_to)
                            {
                                // Plan 160 (D281) Ф.2: module-private pattern check.
                                if meta.priv_module_field {
                                    if !self.module_priv_access_allowed(tname.as_str()) {
                                        errors.push(Diagnostic::new(
                                            format!(
                                                "[E_FIELD_MODULE_PRIVATE] cannot destructure \
                                                 module-private field `{}.{}` in pattern from \
                                                 outside its module. Type declared with \
                                                 bare `priv` (Plan 160 / D281). Hint: use \
                                                 public accessor methods of `{}`.",
                                                tname, pf.name, tname,
                                            ),
                                            pf.span,
                                        ));
                                    }
                                } else {
                                    errors.push(Diagnostic::new(
                                        format!(
                                            "[E_PRIV_FIELD_PATTERN] cannot destructure \
                                             private field `{}.{}` в pattern outside type-\
                                             method scope. Field marked `priv` (Plan 124 / \
                                             D220/D221/D222). Hint: bind the value to a variable \
                                             and access via public methods of `{}`, move \
                                             destructure into a method of `{}`, or use \
                                             `#test_access({})` (D225).",
                                            tname, pf.name, tname, tname, tname,
                                        ),
                                        pf.span,
                                    ));
                                }
                            }
                        }
                    }
                }
                // Recurse into sub-patterns with resolved sub-field type.
                let _ = span;
                for pf in fields {
                    if let Some(sub) = &pf.pattern {
                        let sub_ty = metas.iter()
                            .find(|m| m.name == pf.name)
                            .map(|m| m.ty.clone());
                        self.check_priv_pattern_recursive(sub, sub_ty.as_ref(), errors);
                    }
                }
            }
            Pattern::Or { alternatives, .. } => {
                for alt in alternatives {
                    self.check_priv_pattern_recursive(alt, scrutinee_ty, errors);
                }
            }
            Pattern::Binding { inner, .. } => {
                self.check_priv_pattern_recursive(inner, scrutinee_ty, errors);
            }
            // Variant/Tuple/Array/Wildcard/Ident/Literal — no priv-record
            // semantics at this level (handled in Plan 124.4 для tuple form).
            _ => {}
        }
    }

    /// Plan 87 Ф.2.2: пройти тело for-in. При заданной аннотации типа
    /// элемента (`for x TYPE in`) loop-переменная-`Ident` получает этот
    /// тип в scope тела (save/restore — for-body не утекает в окружающий
    /// scope). Без аннотации scope не трогаем — поведение 1:1 до Plan 87.
    fn f1_for_body(
        &self,
        elem_type: &Option<TypeRef>,
        pattern: &Pattern,
        body: &Block,
        gs: &HashSet<String>,
        scope: &mut HashMap<String, TypeRef>,
        errors: &mut Vec<Diagnostic>,
    ) {
        match (elem_type, pattern) {
            (Some(ann), Pattern::Ident { name, .. }) => {
                let saved = scope.insert(name.clone(), ann.clone());
                self.f1_block(body, gs, scope, errors);
                match saved {
                    Some(prev) => { scope.insert(name.clone(), prev); }
                    None => { scope.remove(name); }
                }
            }
            _ => self.f1_block(body, gs, scope, errors),
        }
    }

    /// Plan 87 Ф.3: проверить, что аннотация типа loop-переменной
    /// (`for x TYPE in iter`) совместима с фактическим типом элемента
    /// итератора. Несовпадение → E7340. Если тип элемента уверенно
    /// вывести не удалось — проверка пропускается (Compat::Unknown-
    /// философия Plan 79: никаких ложных срабатываний).
    fn f1_check_for_elem(
        &self,
        iter: &Expr,
        ann: &TypeRef,
        gs: &HashSet<String>,
        scope: &HashMap<String, TypeRef>,
        errors: &mut Vec<Diagnostic>,
    ) {
        let Some(elem_tr) = self.infer_iter_elem_type(iter, scope) else {
            return;
        };
        // U.5.2: structured category (`resolved_cat_of` + `cat_compatible_rt`),
        // mirroring `assignable`. Permissive на `Any` (generic-параметр /
        // неизвестное / protocol). Транзитный parity-ассерт снимается в Phase B.
        let ann_rt = self.resolved_cat_of(ann, gs);
        let elem_rt = self.resolved_cat_of(&elem_tr, gs);
        if !cat_compatible_rt(&elem_rt, &ann_rt) {
            errors.push(
                Diagnostic::new(
                    format!(
                        "[E7340] for-in loop variable annotated as `{}`, \
                         but the iterator yields elements of type `{}`",
                        typeref_display(ann),
                        typeref_display(&elem_tr),
                    ),
                    ann.span(),
                )
                .with_note_at(
                    "iterator element type comes from here".to_string(),
                    iter.span,
                ),
            );
        }
    }

    /// Plan 87 Ф.3: best-effort вывод типа элемента for-in итератора.
    /// `None` — вывести не удалось (проверка аннотации пропускается).
    fn infer_iter_elem_type(
        &self,
        iter: &Expr,
        scope: &HashMap<String, TypeRef>,
    ) -> Option<TypeRef> {
        match &iter.kind {
            // `a..b` / `a..=b` — элементы int.
            ExprKind::Range { .. } => Some(prim_ref("int", iter.span)),
            // Литерал массива — тип из первого выводимого не-spread элемента.
            ExprKind::ArrayLit(elems) => {
                for el in elems {
                    if let ArrayElem::Item(e) = el {
                        if let Some(t) = self.infer_expr_type(e, scope) {
                            return Some(t);
                        }
                    }
                }
                None
            }
            // Прочее: если выражение имеет тип `[]T` / `[N]T` — элемент `T`.
            // D176 (Plan 108): `readonly []T` → elements are `T` (primitive copy).
            _ => match self.infer_expr_type(iter, scope)? {
                TypeRef::Array(inner, _)
                | TypeRef::FixedArray(_, inner, _) => Some(*inner),
                TypeRef::Readonly(inner, _) => match *inner {
                    TypeRef::Array(elem, _) | TypeRef::FixedArray(_, elem, _) => Some(*elem),
                    _ => None,
                },
                _ => None,
            },
        }
    }

    /// Ф.1: проверить типы аргументов call-site против параметров callee.
    /// Plan 172.1 U.3.1: ARITY-AWARE compatibility probe for ONE overload.
    ///
    /// - `None` — the overload is not even ARITY-applicable (`bind_call_args`
    ///   fails: wrong number of positional args, bad named arg, etc.). That is a
    ///   wrong-arity / non-call situation reported elsewhere (BoundCtx), NOT a
    ///   "no matching overload by type" — the caller must EXCLUDE it from the
    ///   no-match decision (else a 0-arg / wrong-arity reference to a multi-overload
    ///   fn would falsely fire E_NO_MATCHING_OVERLOAD).
    /// - `Some(true)` — binds AND every arg is category-compatible (no `Compat::Bad`).
    /// - `Some(false)` — binds but some arg is a category mismatch (the str↔int leak).
    ///
    /// Permissive by design — Narrowing/OutOfRange/Unknown/Ok all count as
    /// compatible, because codegen still performs the FINAL exact-C-type selection
    /// (U.3.4). The checker only enforces that AT LEAST ONE arity-applicable overload
    /// is category-compatible. Pure: emits no diagnostics.
    fn overload_applicability(
        &self,
        callee: &FnDecl,
        args: &[CallArg],
        gs: &HashSet<String>,
        scope: &HashMap<String, TypeRef>,
    ) -> Option<bool> {
        let bindings = crate::argbind::bind_call_args(&callee.params, args).ok()?;
        let callee_gs = fn_generic_scope(callee);
        for (pi, binding) in bindings.iter().enumerate() {
            let ai = match binding {
                crate::argbind::ArgBinding::Positional(i)
                | crate::argbind::ArgBinding::Named(i) => *i,
                _ => continue,
            };
            let Some(param) = callee.params.get(pi) else { continue; };
            if param.is_variadic {
                continue;
            }
            let Some(arg) = args.get(ai) else { continue; };
            if matches!(
                self.assignable(arg.expr(), &param.ty, gs, &callee_gs, scope),
                Compat::Bad { .. }
            ) {
                return Some(false);
            }
        }
        Some(true)
    }

    fn f1_check_call(
        &self,
        func: &Expr,
        args: &[CallArg],
        trailing_present: bool,
        gs: &HashSet<String>,
        scope: &HashMap<String, TypeRef>,
        errors: &mut Vec<Diagnostic>,
    ) {
        // Trailing-форма перепривязывает последний param — пропускаем
        // (редко, и codegen всё равно проверяет).
        if trailing_present {
            return;
        }
        let base: &Expr = match &func.kind {
            ExprKind::TurboFish { base, .. } => base.as_ref(),
            _ => func,
        };
        // Резолвим callee только однозначно (ровно один overload).
        let callee: &FnDecl = match &base.kind {
            ExprKind::Ident(n) => {
                match self.sig.fn_decls.get(n).map(|v| v.as_slice()) {
                    Some([single]) => single,
                    Some(multi) => {
                        // Plan 172.1 U.3.1: resolve free-fn overloads in the
                        // CHECKER (§0/§1). Consider ONLY arity-applicable overloads
                        // (`overload_applicability` → Some(_)); if at least one
                        // binds by arity but NONE is category-compatible, the call
                        // is a type error that previously leaked to codegen/C
                        // ("no matching overload" / CC-FAIL) — now a clean Nova
                        // diagnostic. If NO overload binds by arity (wrong-arity
                        // call or a non-call reference to the name), defer: that
                        // arity error is reported by BoundCtx, not here. If ≥1
                        // overload is type-compatible, defer FINAL selection to
                        // codegen's exact-C-type match (that move is U.3.4).
                        let applicable: Vec<bool> = multi.iter()
                            .filter_map(|c| self.overload_applicability(c, args, gs, scope))
                            .collect();
                        if !applicable.is_empty() && !applicable.iter().any(|&ok| ok) {
                            errors.push(Diagnostic::new(
                                format!(
                                    "[E_NO_MATCHING_OVERLOAD] no overload of `{}` \
                                     matches the given argument types",
                                    n,
                                ),
                                base.span,
                            ));
                        }
                        return;
                    }
                    None => return,
                }
            }
            ExprKind::Path(parts) if parts.len() == 2 => {
                let overloads = self
                    .method_overloads(&parts[0], &parts[1])
                    .map(|v| v.as_slice());
                // Plan 91.8a.2 followup 2026-05-29: для receiver-types,
                // у которых ЧАСТЬ overload'ов лежит вне method_table
                // (external fn в другом stdlib-модуле, codegen builtins,
                // hidden D73 auto-derive paths) — single-overload arg-check
                // даёт ложные positives. Symptom: `let fill_s = str.from(fill)`
                // в std/runtime/string.nv падает с E7301 "cannot pass char as bool"
                // когда пользователь добавил `fn str.from(b bool) -> str` —
                // type-checker видит ЕДИНСТВЕННЫЙ overload (bool) и ругается
                // на arg типа char, не зная про external `str.from(c char)`.
                //
                // Фикс: для primitive-receiver'ов (str/int/char/bool/f*/u*/i*/uint)
                // **никогда** не делать arg-check на single-overload в Path-форме.
                // Codegen overload resolution в `external_registry` +
                // `method_overloads` корректно резолвит за нас.
                let is_primitive_recv = matches!(
                    parts[0].as_str(),
                    "str" | "int" | "char" | "bool" | "f32" | "f64"
                    | "u8" | "u16" | "u32" | "u64" | "uint"
                    | "i8" | "i16" | "i32" | "i64"
                );
                if is_primitive_recv {
                    return;
                }
                match overloads {
                    Some([single]) => single,
                    Some(multi) => {
                        // Plan 172.1 U.3.3: arity-aware overload resolution in the
                        // CHECKER for non-primitive `Type.method(args)` calls —
                        // same rule as U.3.1 (free-fn). Fire E_NO_MATCHING_OVERLOAD
                        // only when ≥1 overload binds by arity but NONE is
                        // category-compatible (previously leaked to codegen/C).
                        // Final exact-C-type selection stays in codegen (U.3.4).
                        // (primitive-receiver bailed above — U.3.2 closes that via
                        // ExternalRegistry.) Method params exclude the receiver
                        // (`f.receiver`), so they align 1:1 with call args exactly
                        // like the single-overload path below.
                        let applicable: Vec<bool> = multi.iter()
                            .filter_map(|c| self.overload_applicability(c, args, gs, scope))
                            .collect();
                        if !applicable.is_empty() && !applicable.iter().any(|&ok| ok) {
                            errors.push(Diagnostic::new(
                                format!(
                                    "[E_NO_MATCHING_OVERLOAD] no overload of `{}.{}` \
                                     matches the given argument types",
                                    parts[0], parts[1],
                                ),
                                base.span,
                            ));
                        }
                        return;
                    }
                    None => return,
                }
            }
            // Plan 81 Ф.2: module-qualified вызов `alias.func(...)` /
            // `mod.func(...)`. `obj` — alias/имя импортированного модуля,
            // `name` — свободная функция этого модуля. Раньше неизвестная
            // функция давала link-error (EXPECT_COMPILE_ERROR не ловил —
            // Plan 70.1 known-limitation); теперь — compile-error E7401.
            ExprKind::Member { obj, name } => {
                let ExprKind::Ident(prefix) = &obj.kind else { return; };
                // Локальная переменная перекрывает имя → это instance-
                // метод на значении, не module-call.
                if scope.contains_key(prefix) {
                    return;
                }
                // Не импортированный модуль → instance-метод (codegen).
                if !self.imported_modules.contains(prefix) {
                    return;
                }
                // Intrinsic namespace (gc / Time / Channel / ...) —
                // спец-dispatch в codegen, не обычная free fn.
                if is_intrinsic_namespace(prefix) {
                    return;
                }
                match self.sig.fn_decls.get(name) {
                    Some(overloads) => match overloads.as_slice() {
                        [single] => single,
                        // 0 (никогда) или overload — пропускаем arg-check.
                        _ => return,
                    },
                    None => {
                        // Plan 162.2 Ф.3: cross-module fn known via sig_table —
                        // suppress false-positive E7401 for functions that live in
                        // a transitively imported module captured during the
                        // signature pre-pass but not yet merged into fn_decls.
                        if self.is_known_fn(name) {
                            return;
                        }
                        errors.push(Diagnostic::new(
                            format!(
                                "[E7401] no function `{}` in module `{}`",
                                name, prefix,
                            ),
                            base.span,
                        ));
                        return;
                    }
                }
            }
            // прочие instance-методы (`obj.method` на значении) —
            // receiver-type inference ненадёжна в bootstrap; codegen
            // резолвит по type-info.
            _ => return,
        };
        let Ok(bindings) =
            crate::argbind::bind_call_args(&callee.params, args)
        else {
            // BindError уже репортит BoundCtx::check_call_argbind.
            return;
        };
        let callee_gs = fn_generic_scope(callee);
        for (pi, binding) in bindings.iter().enumerate() {
            let ai = match binding {
                crate::argbind::ArgBinding::Positional(i)
                | crate::argbind::ArgBinding::Named(i) => *i,
                // Variadic собирается в []T, Default — нет arg-выражения.
                _ => continue,
            };
            let Some(param) = callee.params.get(pi) else { continue; };
            if param.is_variadic {
                continue;
            }
            let Some(arg) = args.get(ai) else { continue; };
            match self.assignable(arg.expr(), &param.ty, gs, &callee_gs, scope)
            {
                Compat::Bad { found } => {
                    errors.push(
                        Diagnostic::new(
                            format!(
                                "[E7301] cannot pass `{}` as argument `{}` \
                                 of type `{}`",
                                found, param.name, typeref_display(&param.ty),
                            ),
                            arg.expr().span,
                        )
                        .with_note_at(
                            format!("parameter `{}` declared here", param.name),
                            param.span,
                        ),
                    );
                }
                // Plan 142 (D227): литерал-аргумент вне диапазона sized-param.
                Compat::OutOfRange { msg } => {
                    errors.push(
                        Diagnostic::new(
                            format!("[E_LIT_OUT_OF_RANGE] {msg}"),
                            arg.expr().span,
                        )
                        .with_note_at(
                            format!("parameter `{}` declared here", param.name),
                            param.span,
                        ),
                    );
                }
                Compat::Narrowing { from, to } => {
                    errors.push(
                        Diagnostic::new(
                            format!(
                                "[E_IMPLICIT_NARROWING] cannot pass `{}` as argument \
                                 `{}` of narrower type `{}` — implicit int narrowing \
                                 loses range; use an explicit `{} as {}` cast (D54)",
                                from, param.name, to, "<value>", to,
                            ),
                            arg.expr().span,
                        )
                        .with_note_at(
                            format!("parameter `{}` declared here", param.name),
                            param.span,
                        ),
                    );
                }
                Compat::Ok | Compat::Unknown => {
                    // [M-generic-arg-type-mismatch-silent] The Ty/TyCat lowering
                    // folds every int width into one `TyCat::Int` and drops a
                    // named type's generic arguments, so a generic value passed
                    // with a different concrete primitive type-argument (e.g.
                    // `Vec[int]`→`Vec[u32]`, or a user `Stack[int]`→`Stack[u32]`)
                    // slips past `assignable`. That is a pointer reinterpretation —
                    // a generic instantiation is a distinct monomorphized struct
                    // (`Nova_Vec____nova_int*` 8-byte slots vs
                    // `Nova_Vec____uint32_t*` 4-byte slots), so reading one as the
                    // other misreads element width/stride and yields garbage like
                    // `(hi<<32)|lo`. NOT Vec-specific — fires for ANY generic type whose
                    // base name + arity match but a concrete type-argument differs.
                    // Scalar coercion (`int`→`u32` OUTSIDE a generic, e.g. `push(int)`
                    // into a `Vec[u32]`) is a value-level truncation and is intentionally
                    // NOT flagged. U.5.3: the mismatch DECISION is now made on the
                    // lossless structured `ResolvedType` (`distinct_mono`); `generic_args`
                    // is kept only to iterate the arg pairs + display their `TypeRef`s in
                    // the message (a thin accessor, not a parallel type engine).
                    if let (Some((base_p, args_p)), Some(arg_tr)) = (
                        generic_args(&param.ty),
                        self.infer_expr_type(arg.expr(), scope),
                    ) {
                        if let Some((base_a, args_a)) = generic_args(&arg_tr) {
                            // Same generic type (base name + arity) — compare each
                            // type-argument; flag the first definite mismatch.
                            if base_p == base_a && args_p.len() == args_a.len() {
                                for (pa, aa) in args_p.iter().zip(args_a.iter()) {
                                    if distinct_mono(
                                        &self.resolved_cat_of(pa, &callee_gs),
                                        &self.resolved_cat_of(aa, gs),
                                    ) {
                                        errors.push(
                                            Diagnostic::new(
                                                format!(
                                                    "[E_ARG_ELEM_TYPE_MISMATCH] cannot \
                                                     pass `{}` as argument `{}` of type \
                                                     `{}` — generic type argument \
                                                     differs (`{}` vs `{}`); a generic \
                                                     instantiation is a distinct \
                                                     monomorphized type, so this would \
                                                     reinterpret its contents",
                                                    typeref_display(&arg_tr),
                                                    param.name,
                                                    typeref_display(&param.ty),
                                                    typeref_display(aa),
                                                    typeref_display(pa),
                                                ),
                                                arg.expr().span,
                                            )
                                            .with_note_at(
                                                format!(
                                                    "parameter `{}` declared here",
                                                    param.name,
                                                ),
                                                param.span,
                                            ),
                                        );
                                        break;
                                    }
                                }
                            }
                        }
                    }
                }
            }
        }
    }

    /// Ф.3: проверить существование поля/метода `name` у `obj`.
    ///
    /// Консервативно: проверяется только когда тип `obj` уверенно
    /// резолвится в concrete record **без embed'ов** (`use`-поля
    /// проксируют члены — резолв слишком сложен). Метод ИЛИ поле —
    /// обе формы валидны (`obj.field`, `obj.method`, `obj.method()`).
    fn f3_check_member(
        &self,
        obj: &Expr,
        name: &str,
        span: Span,
        scope: &HashMap<String, TypeRef>,
        errors: &mut Vec<Diagnostic>,
    ) {
        // Plan 132 Ф.1: bound method value `obj.@method` removed (D-block Plan 11).
        // `Type.@method` (unbound fn-pointer) is still allowed.
        // Heuristic identical to emit_c.rs emit_method_value_typed: a bare Ident
        // that starts with uppercase OR is a primitive type name = unbound (keep).
        // Everything else = bound (E_BOUND_METHOD_REMOVED).
        if name.starts_with('@') {
            let is_type_name = match &obj.kind {
                ExprKind::Ident(n) => {
                    n.chars().next().map(|c| c.is_ascii_uppercase()).unwrap_or(false)
                        || matches!(
                            n.as_str(),
                            "int" | "i8" | "i16" | "i32" | "i64"
                                | "u8" | "u16" | "u32" | "u64"
                                | "f32" | "f64" | "bool" | "char" | "str"
                        )
                }
                ExprKind::Path(parts) if parts.len() == 1 => true,
                _ => false,
            };
            if !is_type_name {
                errors.push(Diagnostic::new(
                    format!(
                        "[E_BOUND_METHOD_REMOVED] bound method value `obj.{}` \
                         removed (Plan 132). Bound method values that capture \
                         receiver were removed because they conflicted with \
                         field/method same-name design. Migration: \
                         use a lambda `|| obj.{}(...)` for a captured call, \
                         or use unbound `Type.{}` for an fn-pointer.",
                        name,
                        &name[1..], // strip leading @
                        name,
                    ),
                    span,
                ));
                return;
            }
            // Unbound Type.@method — fall through, normal checks apply.
            return;
        }
        let Some(obj_tr) = self.infer_expr_type(obj, scope) else { return; };
        // Plan 118 D216 §5: auto-deref one level для typed pointer `*T` —
        // permissive в type-checker (skip f3 not-found error so codegen может
        // attempt arrow `p->field`). Full proper auto-deref resolution
        // с codegen integration (emit `p->field` C consistently для both
        // record and primitive pointee) — Ф.4 followup work. V1: skip check
        // для pointer types — permissive (codegen may produce CC-FAIL if
        // arrow codegen path не handles *T properly yet).
        // Plan 118.5: pointer-like = Pointer | Mut | Unsafe (all auto-deref candidates).
        if matches!(
            obj_tr,
            TypeRef::Pointer(_, _) | TypeRef::Mut(_, _) | TypeRef::Unsafe(_, _)
        ) {
            return; // permissive — defer to codegen + Ф.4 full integration
        }
        let TypeRef::Named { path, .. } = &obj_tr else { return; };
        let Some(tname) = path.last() else { return; };
        // Plan 152.1 Ф.4 (D249): str's bare length / codepoint-access / byte-access
        // accessors are retired for the lens model. Targeted error (fires BEFORE the
        // priv-field-read path below — `str` has a priv `len` FIELD — and before the
        // generic "no method" error) guiding to the lens replacement. `@byte_len()`
        // (O(1) byte-length shortcut) stays. EXEMPTION: a bare self-access `@len`
        // (obj == SelfAccess) is the legitimate backing-field read inside str's own
        // `@byte_len() => @len` (D117 carve-out) — only NON-self receivers (external
        // `s.len()` / `s.char_at(i)` / …) are diagnosed.
        if tname == "str" && !matches!(obj.kind, ExprKind::SelfAccess) {
            // NB: `get` is NOT listed — `str @get(r Range) -> Option[str]` is the
            // valid safe-slice accessor (slice.nv). The retired `get(int)` simply
            // fails arg-resolution against `get(Range)` (no `str.get(int)` sites remain).
            let hint = match name {
                "len"      => Some("`byte_len()` (byte length, O(1)) or `as_chars().count()` (codepoint count, O(n))"),
                "char_len" => Some("`as_chars().count()` (codepoint count, O(n))"),
                "char_at"  => Some("`as_chars().nth(i)` (i-th codepoint, O(n))"),
                "byte_at"  => Some("`as_bytes()[i]` (i-th byte, O(1), bounds-checked)"),
                _ => None,
            };
            if let Some(hint) = hint {
                errors.push(Diagnostic::new(
                    format!(
                        "[E_STR_NO_LEN] `str.{}()` was retired (D249 lens model): a `str` \
                         has three diverging lengths, so length / element access goes through \
                         a representation lens — use {}.",
                        name, hint
                    ),
                    span,
                ));
                return;
            }
        }
        let Some(td) = self.types.get(tname) else { return; };
        match &td.kind {
            TypeDeclKind::Record(fields) => {
                // embed (`use`) проксирует поля/методы вложенного типа — резолв
                // слишком сложен для надёжной проверки, пропускаем такой тип.
                if fields.iter().any(|f| f.is_embed) {
                    return;
                }
                // Plan 139.1 (lang-item str): same-name field/method resolution.
                // `str` has BOTH a priv field `len` AND a method `@len()`. A
                // member access `s.len(...)` is a METHOD call, not a priv-field
                // read — codegen resolves it to the method. If a method with this
                // name exists on the type, prefer it (return) BEFORE the priv-field
                // check, so `s.len()` is not mis-flagged E_PRIV_FIELD_READ. A bare
                // field read like `s.ptr` (no method `ptr`) still falls through to
                // the field block below and fires privacy correctly. This matches
                // the documented field/method same-name design (see E_BOUND_METHOD
                // heuristic above) и поведение codegen method-resolution.
                let has_same_name_method = self.t_provides_method(tname, name);
                if has_same_name_method {
                    // Plan 162 Ф.5: extension method policy — check even for
                    // method/field same-name early return (e.g. str.len() case).
                    self.check_extension_method_policy(tname, name, span, errors);
                    return;
                }
                if let Some(field) = fields.iter().find(|f| f.name == name) {
                    // Plan 124 (D220) + 124.6 (D225): priv field READ access check.
                    // Allowed: own type-method, или fn с #test_access(tname),
                    // или current_recv ∈ field.visible_to (friend).
                    if field.priv_field
                        && !self.priv_field_access_allowed(tname.as_str(), &field.visible_to)
                    {
                        // Plan 160 (D281) Ф.2: distinguish module-private from
                        // type-private. priv_module_field=true → Module default;
                        // allow if same module, otherwise E_FIELD_MODULE_PRIVATE.
                        if field.priv_module_field {
                            if !self.module_priv_access_allowed(tname.as_str()) {
                                errors.push(Diagnostic::new(
                                    format!(
                                        "[E_FIELD_MODULE_PRIVATE] cannot read \
                                         module-private field `{}.{}` from \
                                         outside its module. Type declared with \
                                         bare `priv` (Plan 160 / D281). \
                                         Hint: add a public accessor method on \
                                         `{}`, or move the caller into the same \
                                         module.",
                                        tname, name, tname,
                                    ),
                                    span,
                                ));
                            }
                        } else {
                            errors.push(Diagnostic::new(
                                format!(
                                    "[E_PRIV_FIELD_READ] cannot read private field \
                                     `{}.{}` outside type-method scope. Field marked \
                                     `priv` (Plan 124 / D220). Hint: add public \
                                     getter method on `{}`, or move accessing code \
                                     into a method of `{}`, or use `#test_access({})` \
                                     на test fn (escape hatch — D224).",
                                    tname, name, tname, tname, tname,
                                ),
                                span,
                            ));
                        }
                    }
                    return;
                }
                // Метод? Имена операторных методов могут храниться с ведущим `@`.
                let has_method = self.t_provides_method(tname, name);
                if has_method {
                    // Plan 162 Ф.5: extension method policy.
                    self.check_extension_method_policy(tname, name, span, errors);
                    return;
                }
                // `into` / `try_into` синтексируются компилятором из `From` /
                // `TryFrom` (D73/D77) — их нет в method_table, но они валидны
                // для любого типа-источника конверсии.
                if matches!(name, "into" | "try_into") {
                    return;
                }
                // Plan 91.8a.2 [M-91.8a.2-default-body-general] 2026-05-29:
                // generalized protocol default-body satisfiability. Replaces prior
                // hardcoded equals/fmt MVP. Walks ALL protocols, finds methods named
                // `name` with `default_body`, and for each checks whether the body's
                // top-level method/free-fn calls resolve for T (i.e. T provides every
                // method/overload referenced by the body). If at least one protocol
                // is satisfied → accept the bare call; codegen general synthesizer
                // emits the concrete Nova_<T>_method_<name> on first use.
                if self.protocol_method_satisfiable_for(tname, name) {
                    return;
                }
                // Plan 114.4.1 (D200): assoc const detection — если `name` matches
                // одну из assoc consts типа, hint user про namespace access.
                let is_assoc_const = self.types.get(tname)
                    .map(|td| td.assoc_consts.iter().any(|ac| ac.name == name))
                    .unwrap_or(false);
                if is_assoc_const {
                    errors.push(Diagnostic::new(
                        format!(
                            "[E_CONST_INSTANCE_ACCESS] cannot access associated \
                             constant `{}.{}` через instance — assoc constants \
                             live на type-level (zero storage в instance). \
                             Use `{}.{}` namespace access instead (Plan 114.4.1 D200).",
                            tname, name, tname, name,
                        ),
                        span,
                    ));
                    return;
                }
                let avail: Vec<&str> =
                    fields.iter().map(|f| f.name.as_str()).collect();
                let mut diag = Diagnostic::new(
                    format!(
                        "[E7320] no field or method `{}` on type `{}`",
                        name, tname,
                    ),
                    span,
                );
                if !avail.is_empty() {
                    diag = diag.with_note(format!(
                        "`{}` has field{}: {}",
                        tname,
                        if avail.len() == 1 { "" } else { "s" },
                        avail.join(", "),
                    ));
                }
                errors.push(diag);
            }
            TypeDeclKind::NamedTuple(fields) => {
                // Plan 120 (D215): named tuple — named access only (Q120-positional-access-on-named Option B)
                if name.chars().all(|c| c.is_ascii_digit()) {
                    errors.push(Diagnostic::new(
                        format!(
                            "[E_TUPLE_POSITIONAL_ACCESS_ON_NAMED] \
                             named tuple `{}` does not support positional field access `.{}`; \
                             use named access `.field_name` instead",
                            tname, name
                        ),
                        span,
                    ));
                    return;
                }
                if let Some(field) = fields.iter().find(|f| f.name == name) {
                    // Plan 124.4 (D222) + 124.6 (D225): priv field READ check
                    // для named tuple — uniform allowance с Record.
                    if field.priv_field
                        && !self.priv_field_access_allowed(tname.as_str(), &field.visible_to)
                    {
                        // Plan 160 (D281) Ф.2: module-private vs type-private.
                        if field.priv_module_field {
                            if !self.module_priv_access_allowed(tname.as_str()) {
                                errors.push(Diagnostic::new(
                                    format!(
                                        "[E_FIELD_MODULE_PRIVATE] cannot read \
                                         module-private field `{}.{}` from \
                                         outside its module. Named-tuple type \
                                         declared with bare `priv` (Plan 160 / \
                                         D281). Hint: add a public accessor \
                                         method on `{}`.",
                                        tname, name, tname,
                                    ),
                                    span,
                                ));
                            }
                        } else {
                            errors.push(Diagnostic::new(
                                format!(
                                    "[E_PRIV_FIELD_READ] cannot read private field \
                                     `{}.{}` outside type-method scope. Named-tuple \
                                     field marked `priv` (Plan 124 / D220 / D222). \
                                     Hint: add public getter method on `{}`, move \
                                     accessing code into a method of `{}`, или use \
                                     `#test_access({})` на test fn (D225).",
                                    tname, name, tname, tname, tname,
                                ),
                                span,
                            ));
                        }
                    }
                    return;
                }
                let has_method = self.t_provides_method(tname, name);
                if has_method {
                    // Plan 162 Ф.5: extension method policy.
                    self.check_extension_method_policy(tname, name, span, errors);
                    return;
                }
                if matches!(name, "into" | "try_into") {
                    return;
                }
                if self.protocol_method_satisfiable_for(tname, name) {
                    return;
                }
                let avail: Vec<&str> = fields.iter().map(|f| f.name.as_str()).collect();
                let mut diag = Diagnostic::new(
                    format!(
                        "[E7320] no field or method `{}` on named tuple `{}`",
                        name, tname,
                    ),
                    span,
                );
                if !avail.is_empty() {
                    diag = diag.with_note(format!(
                        "`{}` has field{}: {}",
                        tname,
                        if avail.len() == 1 { "" } else { "s" },
                        avail.join(", "),
                    ));
                }
                errors.push(diag);
            }
            TypeDeclKind::Newtype(TypeRef::Tuple(_, _)) => {
                // Positional tuple: named field access (`.x`) is invalid
                if !name.chars().all(|c| c.is_ascii_digit()) {
                    let has_method = self.t_provides_method(tname, name);
                    if has_method {
                        // Plan 162 Ф.5: extension method policy.
                        self.check_extension_method_policy(tname, name, span, errors);
                        return;
                    }
                    if matches!(name, "into" | "try_into") {
                        return;
                    }
                    errors.push(Diagnostic::new(
                        format!(
                            "[E_TUPLE_NAMED_ACCESS_ON_POSITIONAL] \
                             positional tuple `{}` does not have named fields; \
                             use positional access `.0`, `.1`, … instead",
                            tname
                        ),
                        span,
                    ));
                }
            }
            _ => {} // Sum, Effect, Protocol, Alias, Opaque, etc. — conservative, skip
        }
    }

    /// Plan 120 (D215): validate tuple construction calls.
    /// Checks direct construction `TypeName(args...)` where TypeName is a
    /// known named or positional tuple type.  Conservative: skips if callee is
    /// not a plain Ident or if the name is shadowed by a local variable.
    fn f5_check_tuple_construct(
        &self,
        func: &Expr,
        args: &[CallArg],
        span: Span,
        scope: &HashMap<String, TypeRef>,
        errors: &mut Vec<Diagnostic>,
    ) {
        let ExprKind::Ident(name) = &func.kind else { return; };
        if scope.contains_key(name.as_str()) { return; }
        let Some(td) = self.types.get(name.as_str()) else { return; };
        match &td.kind {
            TypeDeclKind::NamedTuple(fields) => {
                // Plan 124.4 (D222) + 124.6 (D225): if any priv field exists,
                // for each named-arg targeting priv field check access allowance.
                let has_priv = fields.iter().any(|f| f.priv_field);
                let base_allowed = self.priv_access_allowed_base(name.as_str());
                for arg in args {
                    if let CallArg::Named { name: field_name, value: arg_value } = arg {
                        if !fields.iter().any(|f| &f.name == field_name) {
                            let avail: Vec<&str> =
                                fields.iter().map(|f| f.name.as_str()).collect();
                            let mut diag = Diagnostic::new(
                                format!(
                                    "[E_TUPLE_UNKNOWN_FIELD] named tuple `{}` has no field `{}`",
                                    name, field_name,
                                ),
                                span,
                            );
                            if !avail.is_empty() {
                                diag = diag.with_note(format!(
                                    "`{}` has field{}: {}",
                                    name,
                                    if avail.len() == 1 { "" } else { "s" },
                                    avail.join(", "),
                                ));
                            }
                            errors.push(diag);
                        }
                        if has_priv && !base_allowed {
                            if let Some(fd) = fields.iter().find(|f| &f.name == field_name) {
                                if fd.priv_field
                                    && !self.priv_field_access_allowed(name.as_str(), &fd.visible_to)
                                {
                                    // Plan 160 (D281) Ф.2: module-private init.
                                    if fd.priv_module_field {
                                        if !self.module_priv_access_allowed(name.as_str()) {
                                            errors.push(Diagnostic::new(
                                                format!(
                                                    "[E_FIELD_MODULE_PRIVATE] cannot initialize \
                                                     module-private field `{}.{}` via named-tuple \
                                                     constructor from outside its module. Type \
                                                     declared with bare `priv` (Plan 160 / D281). \
                                                     Hint: use factory method `{}.new(...)`.",
                                                    name, field_name, name,
                                                ),
                                                arg_value.span,
                                            ));
                                        }
                                    } else {
                                        errors.push(Diagnostic::new(
                                            format!(
                                                "[E_PRIV_FIELD_INIT] cannot initialize private \
                                                 field `{}.{}` via named-tuple constructor outside \
                                                 type-method scope. Field marked `priv` (Plan 124 / \
                                                 D220 / D222). Hint: use factory method like \
                                                 `{}.new(...)`, or use `#test_access({})` on test fn.",
                                                name, field_name, name, name,
                                            ),
                                            arg_value.span,
                                        ));
                                    }
                                }
                            }
                        }
                    }
                }
                // D215 amend: fields with defaults are optional at call site.
                let required = fields.iter().filter(|f| f.default.is_none()).count();
                let total = fields.len();
                if args.len() < required || args.len() > total {
                    let range_desc = if required == total {
                        format!("exactly {} argument{}", total, if total == 1 { "" } else { "s" })
                    } else {
                        format!("{}-{} arguments", required, total)
                    };
                    errors.push(Diagnostic::new(
                        format!(
                            "[E_TUPLE_CONSTRUCT_ARITY_MISMATCH] named tuple `{}` expects \
                             {} but {} {} provided",
                            name,
                            range_desc,
                            args.len(),
                            if args.len() == 1 { "was" } else { "were" },
                        ),
                        span,
                    ));
                }
            }
            TypeDeclKind::Newtype(TypeRef::Tuple(elem_types, _)) => {
                if args.iter().any(|a| matches!(a, CallArg::Named { .. })) {
                    errors.push(Diagnostic::new(
                        format!(
                            "[E_TUPLE_CONSTRUCT_NAMED_ON_POSITIONAL] \
                             positional tuple `{}` does not accept named arguments; \
                             pass values by position instead",
                            name,
                        ),
                        span,
                    ));
                }
                if args.len() != elem_types.len() {
                    errors.push(Diagnostic::new(
                        format!(
                            "[E_TUPLE_CONSTRUCT_ARITY_MISMATCH] positional tuple `{}` expects \
                             {} argument{} but {} {} provided",
                            name,
                            elem_types.len(),
                            if elem_types.len() == 1 { "" } else { "s" },
                            args.len(),
                            if args.len() == 1 { "was" } else { "were" },
                        ),
                        span,
                    ));
                }
            }
            _ => {}
        }
    }

    /// Ф.4: имя типа в value-позиции (`let c = Foo`, `Foo + 1`) → E7330.
    ///
    /// Флагится только bare `Ident`, разрешающийся в **непустой**
    /// Plan 91.8a.2 [M-91.8a.2-default-body-general] 2026-05-29.
    ///
    /// Generalized check: does type `tname` satisfy SOME protocol's method
    /// named `method_name` through its `default_body`? Walks ALL protocols
    /// in `self.types`, finds methods of that name with default_body, and
    /// for each tries to verify body's referenced calls resolve for T.
    ///
    /// Implementation: a small AST visitor (`default_body_calls_satisfy_for`)
    /// recursively walks the body and checks each `obj.method(...)` /
    /// `Type.method(...)` call that depends on Self or @ — verifies T
    /// provides a matching method or overload.
    ///
    /// Returns true if at least one protocol satisfies. False if no protocol
    /// has a matching default body OR every candidate has unsatisfiable
    /// dependencies.
    /// Plan 91.9 (D186): verify that type T satisfies every protocol listed
    /// в its `#impl(P1 + P2 + ...)` annotation. For each P:
    /// 1. P must be a known protocol (else E_UNKNOWN_PROTOCOL).
    /// 2. T must provide every required method of P:
    ///    - Either explicit `fn T @method(...)` declaration (in method_table), OR
    ///    - P's method has a `default_body` whose calls resolve for T
    ///      (`default_body_calls_satisfy_for` walker — same checker used
    ///      для bare-call satisfiability).
    /// Missing methods → E_IMPL_MISSING_METHODS со списком и hint'ом
    /// (как реализовать).
    /// Plan 126 (D230) Ф.4: bridge TypeCheckCtx → auto_derive::DeriveQuery.
    /// Allows synthesize_method to query type registry and method coverage
    /// without coupling auto_derive module к full type-checker structure.
    fn as_derive_query(&'a self) -> AutoDeriveQueryBridge<'a> {
        AutoDeriveQueryBridge { ctx: self }
    }

    /// Plan 137 (D237): protocols renamed; emit helpful E_PROTOCOL_RENAMED.
    const RENAMED_PROTOCOLS: &'static [(&'static str, &'static str)] = &[
        ("Hashable",       "Hash"),
        ("Equatable",      "Equal"),
        ("Comparable",     "Compare"),
        ("Cloneable",      "Clone"),
        ("Printable",      "Display"),
        ("DebugPrintable", "Debug"),
    ];

    fn verify_impl_protocols(&self, td: &TypeDecl, errors: &mut Vec<Diagnostic>) {
        for proto_name in &td.impl_protocols {
            // Plan 164 Ф.1: proto_name may be "Next[T]" — extract bare name for lookups.
            let proto_base = impl_spec_base_name(proto_name);
            // Plan 137 (D237): check for renamed protocols first, emit helpful message.
            if let Some((_, new_name)) = Self::RENAMED_PROTOCOLS.iter()
                .find(|(old, _)| *old == proto_base)
            {
                errors.push(Diagnostic::new(
                    format!(
                        "[E_PROTOCOL_RENAMED] protocol `{}` was renamed to `{}` (D237). \
                         Use `#impl({})` instead.",
                        proto_name, new_name, new_name,
                    ),
                    td.span,
                ));
                continue;
            }
            let proto_decl = match self.types.get(proto_base) {
                Some(td) => td,
                None => {
                    // Plan 162.1 Step 3: suppress E_UNKNOWN_PROTOCOL when the
                    // protocol is known via the cross-module sig_table.  In the
                    // lazy-resolution scenario the protocol may be from a
                    // transitively-imported module not yet inline-merged into
                    // module.items.  is_known_type checks both self.types (local)
                    // and self.sig_table (cross-module).
                    if self.is_known_type(proto_base) {
                        // Known via sig_table — skip full verification for now.
                        // (Full check would require fetching the protocol decl
                        // from the sig_table, which is a Step 4 / lazy-body task.)
                        continue;
                    }
                    errors.push(Diagnostic::new(
                        format!(
                            "[E_UNKNOWN_PROTOCOL] type `{}` has `#impl({})` but \
                             `{}` is not a known type. Did you forget to import \
                             it, or misspell the protocol name?",
                            td.name, proto_name, proto_name,
                        ),
                        td.span,
                    ));
                    continue;
                }
            };
            let proto_methods = match &proto_decl.kind {
                TypeDeclKind::Protocol { methods, .. } => methods,
                _ => {
                    errors.push(Diagnostic::new(
                        format!(
                            "[E_IMPL_NOT_PROTOCOL] type `{}` has `#impl({})` but \
                             `{}` is not a protocol — it's a different kind of type. \
                             `#impl(...)` only accepts protocol names.",
                            td.name, proto_name, proto_name,
                        ),
                        td.span,
                    ));
                    continue;
                }
            };
            // Per-method check: T provides explicit method OR synthesizable from default body.
            // Plan 91.9 also enforces signature match для explicit methods —
            // E_IMPL_WRONG_SIGNATURE если T provides method с wrong arity /
            // param types / return type vs protocol declaration.
            let mut missing: Vec<String> = Vec::new();
            let mut wrong_sig: Vec<(String, String, String)> = Vec::new();
            // Plan 108.4 Ф.2: receiver mutability mismatch errors.
            // Each entry: (method_name, error_code, proto_qualifier, fix_hint).
            let mut wrong_recv: Vec<(String, &'static str, String, String)> = Vec::new();
            // Plan 126 (D230) Ф.4: built-in protocol auto-derive eligibility.
            // Если protocol auto-derive-able AND user не предоставил explicit
            // method AND нет default body — пытаемся synthesize. Synth-success
            // → method считается satisfied (не добавляется в `missing`).
            // Synth-error → emit E_AUTO_DERIVE_* diagnostic.
            // Plan 164 Ф.1: build a generic substitution map from the impl-spec
            // args, e.g. "Next[U]" → {"T": "U"} (proto param → impl arg).
            // Used in check_signature_match_with_subst below.
            let proto_arg_subst: Vec<(String, String)> = {
                let args_text = impl_spec_args_text(proto_name);
                if args_text.is_empty() || proto_decl.generics.is_empty() {
                    vec![]
                } else {
                    // Strip outer `[` and `]` and split by `,` at depth 0.
                    let inner = &args_text[1..args_text.len().saturating_sub(1)];
                    let mut parts: Vec<String> = Vec::new();
                    let mut depth = 0usize;
                    let mut cur = String::new();
                    for ch in inner.chars() {
                        match ch {
                            '[' | '(' => { depth += 1; cur.push(ch); }
                            ']' | ')' => { depth -= 1; cur.push(ch); }
                            ',' if depth == 0 => {
                                parts.push(cur.trim().to_string());
                                cur = String::new();
                            }
                            _ => { cur.push(ch); }
                        }
                    }
                    if !cur.trim().is_empty() { parts.push(cur.trim().to_string()); }
                    proto_decl.generics.iter()
                        .zip(parts.iter())
                        .map(|(gp, arg)| (gp.name.clone(), arg.clone()))
                        .collect()
                }
            };
            let is_auto_derivable =
                crate::protocols::auto_derive::is_builtin_protocol(proto_base);
            let mut auto_derive_errors: Vec<crate::protocols::auto_derive::DeriveError> = Vec::new();
            for m in proto_methods {
                let has_explicit = self.t_provides_method(&td.name, &m.name);
                let has_default = if let Some(body) = &m.default_body {
                    self.default_body_calls_satisfy_for(body, &td.name)
                } else {
                    false
                };
                if has_explicit {
                    // Compare signature. Find T's fn for method name.
                    if let Some(t_method) = self.find_method_decl(&td.name, &m.name) {
                        if let Some(reason) = check_signature_match_with_subst(t_method, m, &proto_arg_subst) {
                            wrong_sig.push((
                                m.name.clone(),
                                render_method_sig(&m.name, &m.params, &m.return_type),
                                reason,
                            ));
                        }
                        // Plan 108.4 Ф.2: receiver mutability match check.
                        if let Some(recv_err) = check_receiver_mut_match(t_method, m, proto_base, &td.name) {
                            wrong_recv.push(recv_err);
                        }
                    }
                } else if !has_default {
                    // Plan 126 Ф.4: попытка auto-derive перед reporting missing.
                    let mut synthesized_ok = false;
                    if is_auto_derivable {
                        // Match method name к protocol's expected method.
                        let expected_method =
                            crate::protocols::auto_derive::builtin_protocol_method(proto_base);
                        if expected_method.map_or(false, |em| em == m.name.as_str()) {
                            let bridge = self.as_derive_query();
                            let mut derive_ctx =
                                crate::protocols::auto_derive::AutoDeriveCtx::new(&bridge);
                            match crate::protocols::auto_derive::synthesize_method(
                                &mut derive_ctx, td, proto_base,
                            ) {
                                Ok(_fn_decl) => {
                                    // Synthesis succeeded — method satisfied via auto-derive.
                                    // V1: synthesized FnDecl не register'ится в method_table
                                    // immediately — Plan 126 Ф.5+ extension покрывает codegen
                                    // integration. Здесь только suppress'им E_IMPL_MISSING_METHODS,
                                    // подтверждая что фактическая synthesis возможна.
                                    synthesized_ok = true;
                                }
                                Err(derive_err) => {
                                    auto_derive_errors.push(derive_err);
                                }
                            }
                        }
                    }
                    if !synthesized_ok {
                        missing.push(render_method_sig(&m.name, &m.params, &m.return_type));
                    }
                }
            }
            // Plan 126 Ф.4: emit auto-derive diagnostics (E_AUTO_DERIVE_*).
            for derive_err in &auto_derive_errors {
                errors.push(Diagnostic::new(
                    derive_err.diagnostic_message(),
                    td.span,
                ));
            }
            for (name, expected, reason) in &wrong_sig {
                errors.push(Diagnostic::new(
                    format!(
                        "[E_IMPL_WRONG_SIGNATURE] type `{}` has method `{}` but its \
                         signature does not match the requirement from `#impl({})`. \
                         Expected: `{}`. {}\n  \
                         note: protocol method signatures must match exactly \
                         (arity, param types, return type — modulo Self ↔ {}).",
                        td.name, name, proto_name, expected, reason, td.name,
                    ),
                    td.span,
                ));
            }
            // Plan 108.4 Ф.2: emit receiver-mutability mismatch errors.
            for (mname, error_code, proto_qual, fix_hint) in &wrong_recv {
                errors.push(Diagnostic::new(
                    format!(
                        "[{}] type `{}` implements `{}` but method `{}` has wrong \
                         receiver mutability. Protocol `{}` declares `{} @{}(...)`. \
                         {}",
                        error_code, td.name, proto_name, mname,
                        proto_name, proto_qual, mname, fix_hint,
                    ),
                    td.span,
                ));
            }
            if !missing.is_empty() {
                let hint = missing.iter()
                    .map(|s| format!("  - {}", s))
                    .collect::<Vec<_>>()
                    .join("\n");
                errors.push(Diagnostic::new(
                    format!(
                        "[E_IMPL_MISSING_METHODS] type `{}` claims `#impl({})` but \
                         is missing required method(s):\n{}\n  \
                         note: implement these directly, e.g. `fn {} @<method>(...) -> ... => ...`, \
                         or ensure dependencies for a default body (e.g. `@compare` enables \
                         Equatable.equals via default).",
                        td.name, proto_name, hint, td.name,
                    ),
                    td.span,
                ));
            }
        }
    }

    /// Plan 154.1 (D268): verify a METHOD-level `#impl(P1 + P2 + ...)` annotation
    /// on `fn T @m(...)`. Unlike the type-level pass (`verify_impl_protocols`,
    /// which checks T provides ALL of P's methods), this checks that THIS method
    /// `@m` legitimately implements a method OF P:
    ///   1. P is a known protocol type            → else E_IMPL_UNKNOWN_PROTOCOL
    ///   2. `@m` ∈ P's declared methods            → else E_IMPL_NOT_A_PROTOCOL_METHOD
    ///   3. signature (params + return + receiver  → else E_IMPL_SIGNATURE_MISMATCH
    ///      mutability) matches P's `@m`, modulo `Self` ↔ T
    ///
    /// Opt-in: the binding `type_impl_protocols[T] += P` happens in codegen
    /// (emit_c.rs ~2063, mirrored for method-level `#impl`). Absence of `#impl`
    /// is never an error — structural conformance still satisfies `[T P]` bounds.
    fn verify_method_impl_protocols(&self, fd: &FnDecl, errors: &mut Vec<Diagnostic>) {
        // `#impl` on a function requires a receiver — a protocol method is always
        // a method on a type. A free function can never BE a protocol method.
        let recv = match &fd.receiver {
            Some(r) => r,
            None => {
                errors.push(Diagnostic::new(
                    format!(
                        "[E_IMPL_NOT_A_PROTOCOL_METHOD] free function `{}` has `#impl(...)` \
                         but `#impl` on a `fn` requires a receiver (`fn T @{}(...)`). \
                         Protocol methods are always methods on a type.",
                        fd.name, fd.name,
                    ),
                    fd.span,
                ));
                return;
            }
        };
        for proto_name in &fd.impl_protocols {
            // Plan 164 Ф.1: proto_name may be "Next[U]" — extract bare name for lookups.
            let proto_base = impl_spec_base_name(proto_name);
            // Plan 137 (D237): renamed protocols — helpful redirect.
            if let Some((_, new_name)) = Self::RENAMED_PROTOCOLS.iter()
                .find(|(old, _)| *old == proto_base)
            {
                errors.push(Diagnostic::new(
                    format!(
                        "[E_PROTOCOL_RENAMED] protocol `{}` was renamed to `{}` (D237). \
                         Use `#impl({})` instead.",
                        proto_name, new_name, new_name,
                    ),
                    fd.span,
                ));
                continue;
            }
            let proto_decl = match self.types.get(proto_base) {
                Some(td) => td,
                None => {
                    errors.push(Diagnostic::new(
                        format!(
                            "[E_IMPL_UNKNOWN_PROTOCOL] method `{} @{}` has `#impl({})` but \
                             `{}` is not a known type. Did you forget to import it, or \
                             misspell the protocol name?",
                            recv.type_name, fd.name, proto_name, proto_base,
                        ),
                        fd.span,
                    ));
                    continue;
                }
            };
            let proto_methods = match &proto_decl.kind {
                TypeDeclKind::Protocol { methods, .. } => methods,
                _ => {
                    errors.push(Diagnostic::new(
                        format!(
                            "[E_IMPL_UNKNOWN_PROTOCOL] method `{} @{}` has `#impl({})` but \
                             `{}` is not a protocol — it's a different kind of type. \
                             `#impl(...)` only accepts protocol names.",
                            recv.type_name, fd.name, proto_name, proto_base,
                        ),
                        fd.span,
                    ));
                    continue;
                }
            };
            // Plan 164 Ф.1: build a generic substitution map from the impl-spec args,
            // e.g. "Next[U]" → {"T": "U"} (proto generic param → impl type arg name).
            let proto_arg_subst: Vec<(String, String)> = {
                let args_text = impl_spec_args_text(proto_name);
                if args_text.is_empty() || proto_decl.generics.is_empty() {
                    vec![]
                } else {
                    let inner = &args_text[1..args_text.len().saturating_sub(1)];
                    let mut parts: Vec<String> = Vec::new();
                    let mut depth = 0usize;
                    let mut cur = String::new();
                    for ch in inner.chars() {
                        match ch {
                            '[' | '(' => { depth += 1; cur.push(ch); }
                            ']' | ')' => { depth -= 1; cur.push(ch); }
                            ',' if depth == 0 => {
                                parts.push(cur.trim().to_string());
                                cur = String::new();
                            }
                            _ => { cur.push(ch); }
                        }
                    }
                    if !cur.trim().is_empty() { parts.push(cur.trim().to_string()); }
                    proto_decl.generics.iter()
                        .zip(parts.iter())
                        .map(|(gp, arg)| (gp.name.clone(), arg.clone()))
                        .collect()
                }
            };
            // `@m` must be one of P's declared methods.
            let proto_method = match proto_methods.iter().find(|m| m.name == fd.name) {
                Some(m) => m,
                None => {
                    let avail = proto_methods.iter()
                        .map(|m| format!("`@{}`", m.name))
                        .collect::<Vec<_>>()
                        .join(", ");
                    errors.push(Diagnostic::new(
                        format!(
                            "[E_IMPL_NOT_A_PROTOCOL_METHOD] method `@{}` is not declared by \
                             protocol `{}`. `{}` declares: {}. Did you mean one of those, \
                             or a different protocol in `#impl(...)`?",
                            fd.name, proto_base, proto_base, avail,
                        ),
                        fd.span,
                    ));
                    continue;
                }
            };
            // Signature: params + return type, modulo `Self` ↔ T and generic subst.
            if let Some(reason) = check_signature_match_with_subst(fd, proto_method, &proto_arg_subst) {
                errors.push(Diagnostic::new(
                    format!(
                        "[E_IMPL_SIGNATURE_MISMATCH] method `{} @{}` has `#impl({})` but its \
                         signature does not match protocol `{}`'s `@{}`. Expected: `{}`. {}\n  \
                         note: protocol method signatures must match exactly (arity, param \
                         types, return type — modulo Self ↔ {}).",
                        recv.type_name, fd.name, proto_name, proto_base, fd.name,
                        render_method_sig(&proto_method.name, &proto_method.params, &proto_method.return_type),
                        reason, recv.type_name,
                    ),
                    fd.span,
                ));
                continue;
            }
            // Receiver mutability (ro / mut / consume) must match P's `@m`.
            if let Some((_, code, proto_qual, fix)) =
                check_receiver_mut_match(fd, proto_method, proto_base, &recv.type_name)
            {
                errors.push(Diagnostic::new(
                    format!(
                        "[E_IMPL_SIGNATURE_MISMATCH] method `{} @{}` has `#impl({})` but its \
                         receiver mutability does not match protocol `{}`'s `{} @{}(...)`. {} \
                         (detail: {})",
                        recv.type_name, fd.name, proto_name, proto_name, proto_qual,
                        fd.name, fix, code,
                    ),
                    fd.span,
                ));
                continue;
            }
        }
    }

    fn protocol_method_satisfiable_for(&self, tname: &str, method_name: &str) -> bool {
        // Plan 91.9 (D186) gate: bare-call satisfiability требует `#impl(P)`
        // opt-in. Only protocols в T's impl_protocols list considered.
        // Без `#impl` — bare call к default-body-synthesized method даёт
        // E7320 normally (opt-in nominal layer над structural protocols).
        // Plan 164 Ф.1: impl_protocols may contain "Next[U]" — extract bare names
        // for the opted_in set which is compared against self.types keys (bare names).
        let opted_in: HashSet<&str> = self.types.get(tname)
            .map(|td| td.impl_protocols.iter().map(|s| impl_spec_base_name(s)).collect())
            .unwrap_or_default();
        for (proto_name, td) in &self.types {
            if !opted_in.contains(proto_name.as_str()) {
                continue;
            }
            if let TypeDeclKind::Protocol { methods, .. } = &td.kind {
                for m in methods {
                    if m.name == method_name && m.default_body.is_some() {
                        let body = m.default_body.as_ref().unwrap();
                        if self.default_body_calls_satisfy_for(body, tname) {
                            return true;
                        }
                    }
                }
            }
        }
        false
    }

    /// Recursively walks `body` (a protocol default_body Block) and checks
    /// whether every method reference / free-fn call on Self/@ resolves
    /// to a method available on `tname` (directly or via well-known
    /// auto-derive: `str.from(T)` overload OR `T.@into() -> str`).
    ///
    /// Conservative: unknown patterns return `true` (assume satisfiable).
    /// Codegen general synthesizer does the precise check at emission.
    fn default_body_calls_satisfy_for(&self, body: &Block, tname: &str) -> bool {
        let mut ok = true;
        self.walk_default_body_block(body, tname, &mut ok);
        ok
    }

    fn walk_default_body_block(&self, b: &Block, tname: &str, ok: &mut bool) {
        for s in &b.stmts {
            self.walk_default_body_stmt(s, tname, ok);
            if !*ok { return; }
        }
        if let Some(t) = &b.trailing {
            self.walk_default_body_expr(t, tname, ok);
        }
    }

    fn walk_default_body_stmt(&self, s: &Stmt, tname: &str, ok: &mut bool) {
        match s {
            Stmt::Expr(e) => self.walk_default_body_expr(e, tname, ok),
            Stmt::Return { value: Some(e), .. } => self.walk_default_body_expr(e, tname, ok),
            Stmt::Let(d) => self.walk_default_body_expr(&d.value, tname, ok),
            Stmt::Const(_) => {}
            Stmt::Assign { target, value, .. } => {
                self.walk_default_body_expr(target, tname, ok);
                self.walk_default_body_expr(value, tname, ok);
            }
            _ => {}
        }
    }

    fn walk_default_body_expr(&self, e: &Expr, tname: &str, ok: &mut bool) {
        if !*ok { return; }
        match &e.kind {
            ExprKind::Call { func, args, .. } => {
                // Check the call target. Two patterns matter:
                // 1. Member call `obj.method(...)` where `obj` is `@` (SelfAccess)
                //    → require T provides the method.
                // 2. Path call `Type.method(arg)` where one arg is `@` → handle
                //    well-known auto-derive: `str.from(@)` accepts if T has
                //    `str.from(T)` overload OR `T.@into() -> str`.
                if let ExprKind::Member { obj, name } = &func.kind {
                    if matches!(obj.kind, ExprKind::SelfAccess) {
                        if !self.t_provides_method(tname, name) {
                            *ok = false;
                            return;
                        }
                    }
                } else if let ExprKind::Path(parts) = &func.kind {
                    if parts.len() == 2 && parts[0] == "str" && parts[1] == "from" {
                        if args.iter().any(|a| matches!(a.expr().kind, ExprKind::SelfAccess))
                            && !self.t_satisfies_str_from(tname)
                        {
                            *ok = false;
                            return;
                        }
                    }
                }
                self.walk_default_body_expr(func, tname, ok);
                for a in args { self.walk_default_body_expr(a.expr(), tname, ok); }
            }
            ExprKind::Member { obj, name } => {
                if matches!(obj.kind, ExprKind::SelfAccess) {
                    // Bare access `@method` (method-value, not call) — require T provides.
                    if !self.t_provides_method(tname, name)
                        && !self.t_provides_field(tname, name)
                    {
                        *ok = false;
                        return;
                    }
                }
                self.walk_default_body_expr(obj, tname, ok);
            }
            ExprKind::Binary { left, right, .. } => {
                self.walk_default_body_expr(left, tname, ok);
                self.walk_default_body_expr(right, tname, ok);
            }
            ExprKind::Unary { operand, .. } => self.walk_default_body_expr(operand, tname, ok),
            ExprKind::Try(inner) | ExprKind::Bang(inner) => self.walk_default_body_expr(inner, tname, ok),
            ExprKind::Coalesce(a, b) => {
                self.walk_default_body_expr(a, tname, ok);
                self.walk_default_body_expr(b, tname, ok);
            }
            ExprKind::As(inner, _) | ExprKind::Is(inner, _) => {
                self.walk_default_body_expr(inner, tname, ok);
            }
            ExprKind::If { cond, then, else_ } => {
                self.walk_default_body_expr(cond, tname, ok);
                self.walk_default_body_block(then, tname, ok);
                if let Some(eb) = else_ {
                    match eb {
                        crate::ast::ElseBranch::Block(b) => self.walk_default_body_block(b, tname, ok),
                        crate::ast::ElseBranch::If(i) => self.walk_default_body_expr(i, tname, ok),
                    }
                }
            }
            ExprKind::Block(b) => self.walk_default_body_block(b, tname, ok),
            _ => {}
        }
    }

    /// T has method `name` (instance or static, with-or-without `@` prefix).
    fn t_provides_method(&self, tname: &str, name: &str) -> bool {
        // U.2.3.3: base (sig) ∪ synth overlay (this is the F1 helper that collapses
        // the inline `method_table.get(t).keys().any(trim @)` sites).
        let has = |tbl: Option<&HashMap<String, Vec<&'a FnDecl>>>| {
            tbl.map_or(false, |m| m.keys().any(|k| k.trim_start_matches('@') == name))
        };
        has(self.sig.methods_of(tname)) || has(self.synth_methods.get(tname))
    }

    /// Find the FnDecl of T's method with given name. Returns first match
    /// (overloads not typical для protocol methods — strict 1-to-1 match).
    fn find_method_decl(&self, tname: &str, name: &str) -> Option<&FnDecl> {
        // U.2.3.3: search base (sig) then synth overlay.
        let search = |tbl: Option<&HashMap<String, Vec<&'a FnDecl>>>| -> Option<&'a FnDecl> {
            let methods = tbl?;
            for (k, fns) in methods.iter() {
                if k.trim_start_matches('@') == name {
                    return fns.first().copied();
                }
            }
            None
        };
        search(self.sig.methods_of(tname)).or_else(|| search(self.synth_methods.get(tname)))
    }

    fn t_provides_field(&self, tname: &str, name: &str) -> bool {
        if let Some(td) = self.types.get(tname) {
            if let TypeDeclKind::Record(fields) = &td.kind {
                return fields.iter().any(|f| f.name == name);
            }
        }
        false
    }

    /// `str.from(T)` satisfied if T has either:
    /// - `fn str.from(T) -> str` overload registered, OR
    /// - `fn T @into() -> str` (D73 chain).
    fn t_satisfies_str_from(&self, tname: &str) -> bool {
        // Path 1: explicit `fn str.from(T) -> str` overload.
        let str_from = self.method_overloads("str", "from")
            .map_or(false, |fns| fns.iter().any(|f| {
                f.params.len() == 1
                    && matches!(&f.params[0].ty, TypeRef::Named { path, .. }
                        if path.last().map_or(false, |s| s == tname))
            }));
        if str_from { return true; }
        // Path 2: T has `@into() -> str`.
        self.method_overloads(tname, "into")
            .or_else(|| self.method_overloads(tname, "@into"))
            .map_or(false, |fns| fns.iter().any(|f| {
                matches!(&f.return_type, Some(TypeRef::Named { path, .. })
                    if path.len() == 1 && path[0] == "str")
            }))
    }

    /// record/sum-тип. Пустые типы (unit), эффекты (handler — значение),
    /// протоколы/newtype/alias/opaque, а также имена, перекрытые
    /// локальной переменной — пропускаются (валидно либо неоднозначно).
    fn f4_check_value(
        &self,
        expr: &Expr,
        scope: &HashMap<String, TypeRef>,
        errors: &mut Vec<Diagnostic>,
    ) {
        let ExprKind::Ident(name) = &expr.kind else { return; };
        // Локальная переменная / параметр перекрывает имя типа.
        if scope.contains_key(name) {
            return;
        }
        let Some(td) = self.types.get(name) else { return; };
        let kind = match &td.kind {
            TypeDeclKind::Record(fields) if !fields.is_empty() => "record type",
            TypeDeclKind::Sum(variants) if !variants.is_empty() => "sum type",
            // empty record/sum (unit), effect/protocol/newtype/alias/opaque —
            // не value-misuse (либо валидно как значение, либо неоднозначно).
            _ => return,
        };
        let hint = match &td.kind {
            TypeDeclKind::Record(_) => format!(
                "construct a value: `{} {{ ... }}` or a constructor `{}.new(...)`",
                name, name,
            ),
            TypeDeclKind::Sum(_) => {
                format!("use one of `{}`'s variants", name)
            }
            _ => String::new(),
        };
        errors.push(
            Diagnostic::new(
                format!("[E7330] `{}` is a {}, not a value", name, kind),
                expr.span,
            )
            .with_note(hint),
        );
    }

    /// Ф.1: совместимо ли `expr` с типом `expected`?
    ///
    /// `expr_gs` — generic-scope места, где написан `expr`; `exp_gs` —
    /// generic-scope, в котором объявлен `expected` (для arg↔param это
    /// разные scope: caller vs callee). Числовые литералы полиморфны
    /// (D44): целый литерал совместим с любым числовым типом.
    fn assignable(
        &self,
        expr: &Expr,
        expected: &TypeRef,
        expr_gs: &HashSet<String>,
        exp_gs: &HashSet<String>,
        scope: &HashMap<String, TypeRef>,
    ) -> Compat {
        // U.5.2: category через структурный `ResolvedType` (lossless width/sign) —
        // `resolved_cat_of` зеркалит `cat_of` (alias/Vec/Named/Any), но int-семья несёт
        // точные (width, signed) вместо `TyCat::Int`-коллапса.
        let exp_rt = self.resolved_cat_of(expected, exp_gs);
        // Generic-параметр / any / func / tuple — проверить нельзя.
        if matches!(exp_rt, ResolvedType::Any) {
            return Compat::Ok;
        }
        // Литералы: тип адаптируется к контексту (D44).
        match &expr.kind {
            ExprKind::IntLit(v) => {
                return match &exp_rt {
                    ResolvedType::Scalar { .. } => {
                        // Plan 142 (D227 Rule 3): context-coercion целого
                        // литерала к sized-типу — hard range-check. Default
                        // `int`/`uint` (wide) → sized_int_name = None → Ok.
                        // Имя для range-check берём из DIRECT-типа
                        // (`from_type_ref`, БЕЗ alias-резолва) — byte-identical
                        // c legacy `sized_int_name(expected)` (alias → None,
                        // `uint` ≠ `u64`; `wide_default` несёт это различие).
                        if let Some(name) =
                            ResolvedType::from_type_ref(expected).sized_int_name()
                        {
                            // Hex literals > i64::MAX are stored as wrapping
                            // i64 by the lexer (spec: bit-identical). For
                            // unsigned target types, reinterpret as u64 so
                            // 0xCBF29CE484222325 (FNV offset etc.) is valid.
                            let v128 = if matches!(name.as_str(), "u8"|"u16"|"u32"|"u64") && *v < 0 {
                                (*v as u64) as i128
                            } else {
                                *v as i128
                            };
                            if let Some(msg) = lit_range_check(v128, &name) {
                                return Compat::OutOfRange { msg };
                            }
                        }
                        Compat::Ok
                    }
                    ResolvedType::Float { .. } => Compat::Ok,
                    _ => Compat::Bad { found: "int".to_string() },
                };
            }
            // Plan 142 (D227 Rule 6): unary-minus над целым литералом —
            // `-1`, `-200` etc. `-1` это Unary{Neg, IntLit(1)}, не часть
            // литерала, поэтому проверяем здесь (negative-in-unsigned →
            // hard error; negative вне i-диапазона → тоже range-check).
            ExprKind::Unary { op: UnOp::Neg, operand }
                if matches!(operand.kind, ExprKind::IntLit(_)) =>
            {
                let ExprKind::IntLit(v) = operand.kind else {
                    unreachable!()
                };
                return match &exp_rt {
                    ResolvedType::Scalar { .. } => {
                        let exp_direct = ResolvedType::from_type_ref(expected);
                        // i128 negation — без overflow даже для i64::MIN.
                        let neg = -(v as i128);
                        // D227 amend (Rule 6, fixed 2026-06-20; spec 03-syntax.md; regress
                        // detect172/d227): a NEGATIVE literal into ANY unsigned target is a
                        // sign-domain error. The wide-default skip (D227 Rule 1) relaxes only
                        // the UPPER bound — never the floor 0. Keyed on the GENERAL
                        // `signed == false` property (not a `uint` special-case), this closed
                        // the `uint = -1` hole vs `u64 = -1`; byte-identical for sized unsigned
                        // (same `< T.MIN (0)` message). NOT an open marker — bug is fixed.
                        if matches!(exp_direct, ResolvedType::Scalar { signed: false, .. })
                            && neg < 0
                        {
                            if let Some(name) = exp_direct.int_name() {
                                return Compat::OutOfRange {
                                    msg: format!("{neg} < {name}.MIN (0)"),
                                };
                            }
                        }
                        if let Some(name) = exp_direct.sized_int_name() {
                            if let Some(msg) = lit_range_check(neg, &name) {
                                return Compat::OutOfRange { msg };
                            }
                        }
                        Compat::Ok
                    }
                    ResolvedType::Float { .. } => Compat::Ok,
                    _ => Compat::Bad { found: "int".to_string() },
                };
            }
            ExprKind::FloatLit(_) => {
                return match &exp_rt {
                    ResolvedType::Float { .. } => Compat::Ok,
                    _ => Compat::Bad { found: "f64".to_string() },
                };
            }
            ExprKind::BoolLit(_) => {
                return if matches!(exp_rt, ResolvedType::Bool) {
                    Compat::Ok
                } else {
                    Compat::Bad { found: "bool".to_string() }
                };
            }
            ExprKind::StrLit(_) | ExprKind::InterpolatedStr { .. } => {
                return if matches!(exp_rt, ResolvedType::Str) {
                    Compat::Ok
                } else {
                    Compat::Bad { found: "str".to_string() }
                };
            }
            ExprKind::CharLit(_) => {
                // `char` riding as `Named { name: "char", .. }` — mirrors legacy `TyCat::Char`.
                return if matches!(&exp_rt, ResolvedType::Named { name, .. } if name == "char") {
                    Compat::Ok
                } else {
                    Compat::Bad { found: "char".to_string() }
                };
            }
            ExprKind::UnitLit => {
                return if matches!(exp_rt, ResolvedType::Unit) {
                    Compat::Ok
                } else {
                    Compat::Bad { found: "()".to_string() }
                };
            }
            // Plan 134: null ptr literal — only assignable к *() or pointer types
            // (ResolvedType::Ptr). Mismatch flagged as *()-not-X.
            ExprKind::NullPtrLit => {
                return if matches!(exp_rt, ResolvedType::Ptr) {
                    Compat::Ok
                } else {
                    Compat::Bad { found: "*()".to_string() }
                };
            }
            _ => {}
        }
        // Не-литерал: вывести тип; не вышло → Unknown (skip, не ошибка).
        let Some(found_tr) = self.infer_expr_type(expr, scope) else {
            return Compat::Unknown;
        };
        // Plan 125.1 (Ф.1) — never-subtype-of-T per spec D25: `never` assignable
        // to any expected type (bottom type). `from_type_ref` mirrors `ty_of_ref`
        // (both map `never` → `Never`, neither resolves aliases).
        if matches!(ResolvedType::from_type_ref(&found_tr), ResolvedType::Never) {
            return Compat::Ok;
        }
        let found_rt = self.resolved_cat_of(&found_tr, expr_gs);
        // [M-scalar-nonliteral-narrowing-not-enforced] (D54): a NON-LITERAL int
        // value coerced into a narrower / value-range-unsafe int position must
        // use an explicit `as`. U.5.2: narrowing decided on the DIRECT
        // (`from_type_ref`) types via `would_narrow_into` — the SINGLE source that
        // folds the former raw-TypeRef `is_int_narrowing` second pass. Direct-only
        // width (no alias resolve) preserves the legacy `int_width_rank` semantics
        // byte-identically; widening stays implicit.
        if ResolvedType::from_type_ref(&found_tr)
            .would_narrow_into(&ResolvedType::from_type_ref(expected))
        {
            return Compat::Narrowing {
                from: typeref_display(&found_tr),
                to: typeref_display(expected),
            };
        }
        if cat_compatible_rt(&found_rt, &exp_rt) {
            Compat::Ok
        } else {
            Compat::Bad { found: typeref_display(&found_tr) }
        }
    }

    /// Ф.1: best-effort вывод типа выражения (для не-литералов).
    fn infer_expr_type(
        &self,
        expr: &Expr,
        scope: &HashMap<String, TypeRef>,
    ) -> Option<TypeRef> {
        match &expr.kind {
            ExprKind::Ident(name) => scope.get(name).cloned(),
            ExprKind::RecordLit { type_name: Some(name), .. } => {
                Some(TypeRef::Named {
                    path: name.clone(),
                    generics: Vec::new(),
                    span: expr.span,
                })
            }
            ExprKind::As(_, ty) => Some(ty.clone()),
            ExprKind::IntLit(_) => Some(prim_ref("int", expr.span)),
            ExprKind::FloatLit(_) => Some(prim_ref("f64", expr.span)),
            ExprKind::BoolLit(_) => Some(prim_ref("bool", expr.span)),
            ExprKind::StrLit(_) | ExprKind::InterpolatedStr { .. } => {
                Some(prim_ref("str", expr.span))
            }
            ExprKind::CharLit(_) => Some(prim_ref("char", expr.span)),
            // Plan 134: null ptr literal → *() = TypeRef::Pointer(TypeRef::Unit).
            ExprKind::NullPtrLit => Some(TypeRef::Pointer(
                Box::new(TypeRef::Unit(expr.span)),
                expr.span,
            )),
            // D176 (Plan 108): SelfAccess → look up "@" in scope (injected by f1_check_fn).
            ExprKind::SelfAccess => scope.get("@").cloned(),
            // Plan 125.1 (Ф.2): `throw expr` — divergent expression. По спеке
            // D25 throw имеет тип `never` (bottom). Без этого `let x = throw e`
            // / `f(throw e)` падают в Compat::Unknown даже при наличии
            // never-subtype hookpoint'а из Ф.1.
            ExprKind::Throw(_) => Some(prim_ref("never", expr.span)),
            // Plan 125.1 (Ф.2): `interrupt v?` — D61 досрочное завершение
            // with-блока, тип позиции = `never` (control-flow leaves enclosing
            // expression context). Аналогично Throw — divergent.
            ExprKind::Interrupt(_) => Some(prim_ref("never", expr.span)),
            // Plan 115 D214 [M-115-newtype-constructor]: `Type(value)` call where
            // Type is a known Newtype/Alias → infer as Named(Type). Without
            // this, `ro h = SqHandle(raw)` binds `h` без типа в scope, и
            // assignable() для `close_sqlite(h)` падает в Compat::Unknown
            // (E7301 не fires при passing PngHandle к fn(SqHandle)).
            //
            // Plan 125.1 (Ф.2): never-returning builtins + user fns whose
            // return_type resolves to `Ty::Never` → propagate `never`.
            ExprKind::Call { func, .. } => {
                // [M-vec-elem-type-mismatch-silent] generic constructor:
                // `Type[T..].new(...)` / `.with_capacity` / `.from` / `.default`
                // / `.filled` → `Named{Type, generics:[T..]}`. Preserves the
                // element type (unlike `infer_value_type`, which collapses to the
                // bare name) so an inferred `mut v = Vec[int].with_capacity(n)`
                // binds `v: Vec[int]` in scope — letting the container
                // element-mismatch arg-check fire on inferred bindings, not only
                // explicitly-annotated ones. AST shape: Call{ func: Member{ obj:
                // TurboFish{ base: Ident(Type), type_args }, name: ctor } }.
                if let ExprKind::Member { obj, name: ctor } = &func.kind {
                    if let ExprKind::TurboFish { base, type_args } = &obj.kind {
                        if let ExprKind::Ident(tyname) = &base.kind {
                            if matches!(
                                ctor.as_str(),
                                "new" | "with_capacity" | "from" | "default" | "filled"
                            ) {
                                return Some(TypeRef::Named {
                                    path: vec![tyname.clone()],
                                    generics: type_args.clone(),
                                    span: expr.span,
                                });
                            }
                        }
                    }
                }
                if let ExprKind::Ident(name) = &func.kind {
                    if let Some(td) = self.types.get(name) {
                        // Plan 128.1 Ф.2 — D215 NamedTuple constructor (`Vec3(1,2,3)`)
                        // is type-producing наряду с Newtype/Alias. Без этого
                        // assignable() для NamedTuple bindings (e.g. `let v Vec3 = Vec3(...)`)
                        // падает в default-int fallback, ломая infer элемента в
                        // array-literals `[Vec3(1,2,3), Vec3(4,5,6)]`.
                        //
                        // Sum-variant constructors `Red(1)` НЕ попадают в этот arm:
                        // sum variants хранятся внутри TypeDeclKind::Sum(...) (см.
                        // walk_typeref @ 3082), а не как top-level types — поэтому
                        // `self.types.get("Red")` → None, fallthrough preserved.
                        if matches!(
                            td.kind,
                            TypeDeclKind::Newtype(_)
                                | TypeDeclKind::Alias(_)
                                | TypeDeclKind::NamedTuple(_)
                        ) {
                            return Some(TypeRef::Named {
                                path: vec![name.clone()],
                                generics: Vec::new(),
                                span: expr.span,
                            });
                        }
                    }
                    // Plan 125.1 (Ф.2): never-returning builtins (D13).
                    // Same set as `expr_diverges` ниже + `unreachable`.
                    if matches!(name.as_str(), "panic" | "exit" | "abort" | "unreachable") {
                        return Some(prim_ref("never", expr.span));
                    }
                    // Plan 125.1 (Ф.2): propagate `never` для user fns whose
                    // declared return_type resolves к `never`. Requires ВСЕ
                    // overloads divergent — иначе ambiguous (call resolution
                    // ещё не выполнена на этом этапе, безопаснее fallback к
                    // `None` чем выбрать random overload). U.5.4: `from_type_ref`
                    // mirrors the deleted `ty_of_ref` for the `never` check.
                    if let Some(decls) = self.sig.fn_decls.get(name) {
                        if !decls.is_empty()
                            && decls.iter().all(|d| {
                                d.return_type.as_ref().map_or(false, |tr| {
                                    matches!(ResolvedType::from_type_ref(tr), ResolvedType::Never)
                                })
                            })
                        {
                            return Some(prim_ref("never", expr.span));
                        }
                        // **Plan 147 Ф.3 (D246, oracle row D):** propagate a
                        // `ro`-wrapped RETURN type (`-> ro Value`) so the
                        // E_READONLY_COERCE content-view check can reject
                        // `mut a Value = f()` while accepting `ro a Value =
                        // f()`. Requires ALL overloads to declare a `Readonly`
                        // return (call resolution is not yet done here, so a
                        // mixed set is ambiguous → fall through to None). The
                        // returned `ro` type drives only the readonly-coerce
                        // gate; it is intentionally NOT a general return-type
                        // inference (no monomorphization here).
                        if !decls.is_empty()
                            && decls.iter().all(|d| {
                                d.return_type.as_ref().map_or(false, |tr| tr.is_readonly())
                            })
                        {
                            // Safe: the `all` guard proved the first decl has a
                            // readonly return_type.
                            if let Some(rt) = decls[0].return_type.as_ref() {
                                return Some(rt.clone());
                            }
                        }
                        // **Plan 147 Ф.3 (D246, L3, oracle row D):** propagate a
                        // POINTER return type (`-> *T` / `-> *mut T`) so the
                        // E_POINTER_RO_ASSIGN check on `*a = v` (where
                        // `a = f()`) can read the pointee capability from the
                        // type. Requires ALL overloads to agree on a pointer
                        // return shape (else ambiguous → None). Only the FIRST
                        // matching decl's type is returned — its pointee L3 is
                        // what the deref-write gate consults; this is not a
                        // general return-type inference.
                        if !decls.is_empty()
                            && decls.iter().all(|d| {
                                d.return_type
                                    .as_ref()
                                    .map_or(false, |tr| tr.is_pointer_or_wraps_pointer())
                            })
                        {
                            if let Some(rt) = decls[0].return_type.as_ref() {
                                return Some(rt.clone());
                            }
                        }
                    }
                }
                None
            }
            _ => None,
        }
    }

    // ── D175/D176 (Plan 108): readonly enforcement helpers ─────────────────

    /// Resolve record fields for a type name. Returns None if not a Record type.
    fn record_fields_for<'t>(&'t self, type_name: &str) -> Option<&'t Vec<RecordField>> {
        match self.types.get(type_name)?.kind {
            TypeDeclKind::Record(ref fields) => Some(fields),
            _ => None,
        }
    }

    /// Returns `true` if `expr` is an access path that goes through a readonly field,
    /// meaning any mutation through this path is forbidden (D175 transitivity).
    /// Plan 124.8 (D175 amend): returns true if `expr` is a path rooted at
    /// an Ident that is `ro`-bound. Walks through Member/Index chains к
    /// корневому Ident.
    fn is_through_ro_binding(&self, expr: &Expr) -> bool {
        match &expr.kind {
            ExprKind::Ident(name) => self.ro_binding_names.borrow().contains(name),
            ExprKind::Member { obj, .. } => self.is_through_ro_binding(obj),
            ExprKind::Index { obj, .. } => self.is_through_ro_binding(obj),
            _ => false,
        }
    }

    /// **Plan 147 Ф.3 (D246):** walk a `.field`/`[i]` access path down to its
    /// root `Ident` name, used to look up the binding's declared L2
    /// content-view type for the R2-split override (`ro r mut Point` →
    /// content-writable). Returns `None` for non-Ident roots (deref / self /
    /// call results), which carry no simple binding to consult.
    fn assign_root_ident(expr: &Expr) -> Option<&str> {
        match &expr.kind {
            ExprKind::Ident(name) => Some(name.as_str()),
            ExprKind::Member { obj, .. } => Self::assign_root_ident(obj),
            ExprKind::Index { obj, .. } => Self::assign_root_ident(obj),
            _ => None,
        }
    }

    fn is_readonly_path(&self, expr: &Expr, scope: &HashMap<String, TypeRef>) -> bool {
        match &expr.kind {
            ExprKind::Member { obj, name: field_name } => {
                // Check if this field is readonly on obj's type.
                let obj_ty = self.infer_expr_type(obj, scope);
                if let Some(tr) = obj_ty {
                    let type_name = match tr.strip_readonly() {
                        TypeRef::Named { path, .. } => path.last().map(|s| s.as_str()),
                        _ => None,
                    };
                    if let Some(tname) = type_name {
                        if let Some(fields) = self.record_fields_for(tname) {
                            if fields.iter().any(|f| f.name == *field_name && f.readonly) {
                                return true;
                            }
                        }
                    }
                }
                // Transitivity: if the path to obj is itself readonly, propagate.
                self.is_readonly_path(obj, scope)
            }
            _ => false,
        }
    }

    /// Check if an assignment target is readonly and emit an error if so.
    /// Handles D175 (readonly fields) and D176 (readonly T index writes).
    fn check_target_readonly(
        &self,
        target: &Expr,
        scope: &HashMap<String, TypeRef>,
        errors: &mut Vec<Diagnostic>,
    ) {
        match &target.kind {
            ExprKind::Member { obj, name: field_name } => {
                // **Plan 147 Ф.3 (D246, R2-split):** an EXPLICIT `mut T`
                // content-view (L2) on the binding overrides the bare-ro
                // freeze — `ro r mut Point` permits `r.x = v` (content ✅)
                // while `r = X` stays forbidden (reassign ❌, handled by D36).
                // This is the deliberate split of the two axes (L1 binding vs
                // L2 content-view); the bare-`ro r` freeze (P7) below only
                // applies when the binding does NOT carry an explicit `mut`
                // content-view.
                let root_view_is_mut_type = Self::assign_root_ident(obj)
                    .and_then(|root| scope.get(root))
                    .map_or(false, |t| t.is_mut());
                // **Plan 147 Ф.3 (D246, R2-split MIRROR):** an EXPLICIT `ro T`
                // content-view (L2) on the binding FREEZES the owned-graph even
                // under a `mut` L1 binding — `mut r ro Point` permits `r = X`
                // (reassign ✅, L1) but forbids `r.x = v` (content ❌, L2). This
                // is the symmetric counterpart of `root_view_is_mut_type`:
                // L2 content-view dominates field-writes independently of L1.
                // The freeze is along the owned-graph only — a `*` deref is a
                // separate target arm (L3 `pointee_is_writable`), so the L2
                // wall-at-`*` (P4) is respected. The bare `ro r` freeze (P7) is
                // handled by `is_through_ro_binding` below; this catches the
                // mut-binding-with-ro-type-view case it cannot see.
                let root_view_is_ro_type = Self::assign_root_ident(obj)
                    .and_then(|root| scope.get(root))
                    .map_or(false, |t| t.is_readonly());
                if root_view_is_ro_type {
                    errors.push(Diagnostic::new(
                        format!(
                            "[E_READONLY_FIELD] cannot mutate `{}` through a `ro` \
                             content-view binding (L2 freeze — `ro T` type-view \
                             dominates field-writes even under a `mut` binding; \
                             Plan 147 / D246 R2-split). Hint: drop the `ro` type \
                             modifier (`mut name Point`) if content-mutation is needed.",
                            field_name
                        ),
                        target.span,
                    ));
                    return;
                }
                // Plan 124.8 (D175 amend): binding dominates — если корень
                // path = Ident бинд'енный через `ro`, любой write блокируется
                // даже если field имеет `mut` модификатор. Rust-style правило:
                // `let x = ...; x.field = ...` ❌ vs `let mut x = ...; x.field = ...` ✅.
                if !root_view_is_mut_type && self.is_through_ro_binding(obj) {
                    errors.push(Diagnostic::new(
                        format!(
                            "[E_READONLY_FIELD] cannot mutate `{}` через `ro`-binding \
                             (binding dominates даже над `mut field` markers — Plan \
                             124.8 / D175 amend). Hint: используй `mut binding-name = ...` \
                             если нужна мутация.",
                            field_name
                        ),
                        target.span,
                    ));
                    return;
                }
                // Transitivity check: mutation through a ro field (Plan 114 D184).
                if self.is_readonly_path(obj, scope) {
                    errors.push(Diagnostic::new(
                        format!(
                            "[E_READONLY_FIELD] cannot mutate `{}` through a `ro` field path",
                            field_name
                        ),
                        target.span,
                    ));
                    return;
                }
                // Direct check: is this specific field readonly?
                let obj_ty = self.infer_expr_type(obj, scope);
                if let Some(tr) = obj_ty {
                    let type_name = match tr.strip_readonly() {
                        TypeRef::Named { path, .. } => path.last().map(|s| s.as_str()),
                        _ => None,
                    };
                    if let Some(tname) = type_name {
                        if let Some(fields) = self.record_fields_for(tname) {
                            if let Some(f) = fields.iter().find(|f| f.name == *field_name) {
                                if f.readonly {
                                    errors.push(Diagnostic::new(
                                        format!(
                                            "[E_READONLY_FIELD] cannot assign to `ro` field `{}` of type `{}`",
                                            field_name, tname
                                        ),
                                        target.span,
                                    ));
                                }
                                // Plan 124 (D220) + 124.6 (D225): priv field WRITE check.
                                // Plan 160 (D281) Ф.2: module-private write.
                                if f.priv_field
                                    && !self.priv_field_access_allowed(tname, &f.visible_to)
                                {
                                    if f.priv_module_field {
                                        if !self.module_priv_access_allowed(tname) {
                                            errors.push(Diagnostic::new(
                                                format!(
                                                    "[E_FIELD_MODULE_PRIVATE] cannot write to \
                                                     module-private field `{}.{}` from outside \
                                                     its module. Type declared with bare `priv` \
                                                     (Plan 160 / D281). Hint: add a public mutator \
                                                     method on `{}`.",
                                                    tname, field_name, tname,
                                                ),
                                                target.span,
                                            ));
                                        }
                                    } else {
                                        errors.push(Diagnostic::new(
                                            format!(
                                                "[E_PRIV_FIELD_WRITE] cannot write to private \
                                                 field `{}.{}` outside type-method scope. \
                                                 Field marked `priv` (Plan 124 / D220). \
                                                 Hint: add public mutator method on `{}` \
                                                 (e.g. `export fn {} mut @set_{}(v T)`), \
                                                 move accessing code into a method of `{}`, \
                                                 or use `#test_access({})` (D225).",
                                                tname, field_name, tname, tname, field_name, tname, tname,
                                            ),
                                            target.span,
                                        ));
                                    }
                                }
                            }
                        }
                    }
                }
            }
            // D176 / Plan 114 D184: index write `arr[i] = x` — forbid if arr has `ro` type.
            ExprKind::Index { obj, .. } => {
                let obj_ty = self.infer_expr_type(obj, scope);
                if let Some(tr) = &obj_ty {
                    if tr.is_readonly() {
                        errors.push(Diagnostic::new(
                            "[E_READONLY_CONTENT] cannot write through index on `ro` array".to_string(),
                            target.span,
                        ));
                        return;
                    }
                }
                // Plan 147 Ф.7 [M-147-ro-binding-index-freeze] + [M-147-param-index-freeze]:
                // L1/L2 freeze (D246 P7): a `ro`-bound local or a non-mut param is frozen —
                // even an explicitly-`mut`-typed content view does NOT allow index writes if
                // the ROOT binding is ro.  Mirror the Member-field check above (line ~7878).
                //
                // `ro r mut []int` → `r[0] = x` ❌ (binding ro dominates; L1 freeze)
                // but `ro r mut Point` → `r.field = v` ✅ was already the Member rule.
                // The only carve-out: explicit `mut` content-view type on the object
                // (TypeRef::Mut) allows content writes regardless of binding (R2-split P6).
                // We check: if root is ro-bound AND the *declared type* is NOT TypeRef::Mut
                // (explicit mut content-view) → fire.
                // Plan 147 Ф.7: only enforce the ro-binding freeze for
                // assignments in user's own code (entry-module file_id). Imported
                // prelude / std functions may legitimately use `ro buf = ...` locals
                // that they then write through (e.g. WriteBuffer internals). Their
                // correctness is established when their own module is compiled; we
                // must not re-check them here against the user module's entry guard.
                let is_target_in_entry = if self.entry_file_ids.is_empty() {
                    target.span.file_id == 0
                } else {
                    self.entry_file_ids.contains(&target.span.file_id)
                };
                if is_target_in_entry && self.is_through_ro_binding(obj) {
                    let explicit_mut_view = obj_ty.map_or(false, |t| t.is_mut());
                    if !explicit_mut_view {
                        errors.push(Diagnostic::new(
                            "[E_READONLY_CONTENT] cannot write through index on a `ro`-bound \
                             binding or non-mut param — L1/L2 freeze (Plan 147 / D246 P7). \
                             The binding is readonly; use `mut binding = ...` (local) or \
                             `mut param T` (param) to allow index writes. An explicit `mut T` \
                             content-view type (`ro r mut []int`) would also permit it \
                             (R2-split, P6)."
                                .to_string(),
                            target.span,
                        ));
                    }
                }
            }
            // **Plan 147 Ф.3 (D246, L3 pointee-capability):** `*p = v` — a
            // write THROUGH a pointer. The pointee-mutability is read FROM THE
            // TYPE (L3), position- and binding-independent: `*mut T` (=
            // `Pointer(Mut(T))`) is writable; a bare `*T ≡ *ro T` (=
            // `Pointer(T)`) is a readonly pointee → `E_POINTER_RO_ASSIGN`.
            // The binding (L1: `ro p` / `mut p`) controls reassignment of `p`
            // itself, NOT the pointee — so even `ro p *mut T` allows `*p = v`
            // (oracle row C), and `mut p *T` forbids it. We therefore inspect
            // `p`'s *type* and ignore the binding here.
            ExprKind::Unary { op: UnOp::Deref, operand } => {
                if let Some(ty) = self.infer_expr_type(operand, scope) {
                    if let Some(writable) = pointee_is_writable(&ty) {
                        if !writable {
                            errors.push(Diagnostic::new(
                                "[E_POINTER_RO_ASSIGN] cannot write through a \
                                 readonly pointer — `*T` is a readonly pointee \
                                 (the L3 default is `ro`: `*T ≡ *ro T`, Plan \
                                 147 / D246). A writable pointee requires the \
                                 `*mut T` opt-in; pointer reassignability \
                                 (`mut p`) does NOT make the pointee writable."
                                    .to_string(),
                                target.span,
                            ));
                        }
                    }
                }
            }
            _ => {}
        }
    }

    // ── End D175/D176 helpers ──────────────────────────────────────────────

    /// Plan 172.1 U.5.4: the SOLE structured category resolver — the LOSSLESS replacement
    /// of the deleted lossy `cat_of`/`cat_of_depth`/`TyCat` parallel engine. SAME
    /// resolution as the old `cat_of` (alias-transparent, `Vec[T]`→`Array`,
    /// newtype/record/sum/named-tuple→`Named` + generic args, unknown/protocol/effect/
    /// `any`/`never`/generic-param→`Any`, `char`→`Named { "char" }`) but int-family
    /// carries EXACT `(width, signed, wide_default)`, float carries width, and `Named`
    /// carries generic args — instead of the `TyCat`-collapse. Feeds `cat_compatible_rt`
    /// (`assignable`/`f1_check_for_elem`) and `distinct_mono` (generic-arg identity).
    ///
    /// Like the old `cat_of` (and UNLIKE `from_type_ref`), int-family names resolve to
    /// `Scalar` REGARDLESS of generics (`int[X]`→`Scalar`) — name match, not
    /// `ty_of_ref`'s generics-guard.
    fn resolved_cat_of(&self, tr: &TypeRef, gs: &HashSet<String>) -> ResolvedType {
        self.resolved_cat_of_depth(tr, gs, 0)
    }

    fn resolved_cat_of_depth(
        &self,
        tr: &TypeRef,
        gs: &HashSet<String>,
        depth: u32,
    ) -> ResolvedType {
        use ResolvedType as R;
        if depth > 16 {
            return R::Any; // mirrors cat_of_depth depth-guard → Other
        }
        match tr {
            TypeRef::Named { path, generics, .. } => {
                let Some(name) = path.last() else { return R::Any; };
                if gs.contains(name) {
                    return R::Any; // generic type-param → permissive
                }
                // Int-family — UNGUARDED on generics (mirrors cat_of, not from_type_ref).
                if let Some(s) = ResolvedType::scalar_from_int_name(name) {
                    return s;
                }
                // Generic type-arguments (lossless, U.5.3) — recursed for the nominal
                // arms below so `Stack[int]` ≠ `Stack[u32]` in the type-identity check.
                let rt_args = || -> Vec<R> {
                    generics
                        .iter()
                        .map(|g| self.resolved_cat_of_depth(g, gs, depth + 1))
                        .collect()
                };
                // [M-172.1-U5-nv-type-name-hardcode] §3 DEBT (carried from legacy
                // `cat_of`, NOT introduced here): `str` (Plan 139 lang-item
                // `type str value {...}` in core.nv) and `Vec` (vec_seq.nv / D239) ARE
                // `.nv`-DECLARED types, so name-keying their category here violates §3
                // ("resolve from the declaration, not a Rust name-match"). The principled
                // fix derives their category from the import-resolved registry / lang-item
                // (U.1/U.6), NOT a wider `ResolvedType` change — U.5 only collapses the
                // REPRESENTATION (Ty+TyCat→ResolvedType), carrying this debt byte-identically.
                // `char`/`f32`/`f64`/`bool` are genuine compiler PRIMITIVES (NO `.nv` type
                // decl — `char.nv` declares only METHODS on the primitive, like `int`) →
                // sanctioned §3 exception, same class as `scalar_from_int_name`.
                match name.as_str() {
                    "f32" => R::Float { width: 32 },
                    "f64" => R::Float { width: 64 },
                    "bool" => R::Bool,
                    "str" => R::Str,
                    // U.5.5(a): category resolver — keyed on `name` only, so `module`
                    // stays `[]` (the C-lowering identity comes from `from_type_ref`).
                    "char" => R::Named { name: "char".to_string(), module: Vec::new(), args: Vec::new() },
                    // D239 `Vec[T] ≡ []T` — same `Array(elem)` category as the sugar.
                    "Vec" if generics.len() == 1 => {
                        R::Array(Box::new(self.resolved_cat_of_depth(&generics[0], gs, depth + 1)))
                    }
                    // (legacy bare `ptr` name arm removed, U.5.4 — Plan 134; `ptr` now
                    // resolves as an unknown name → `Any` via the `other` arm below.
                    // `TypeRef::Pointer` (typed `*T`) still → `Ptr` further down.)
                    "any" | "never" | "Self" => R::Any,
                    other => match self.types.get(other) {
                        Some(td) => match &td.kind {
                            // Alias transparent (D52); newtype/record/sum/named-tuple
                            // nominal by name (+ generic args); protocol/effect/opaque permissive.
                            TypeDeclKind::Alias(inner) => {
                                self.resolved_cat_of_depth(inner, gs, depth + 1)
                            }
                            TypeDeclKind::Newtype(_)
                            | TypeDeclKind::Record(_)
                            | TypeDeclKind::Sum(_)
                            | TypeDeclKind::NamedTuple(_) => {
                                R::Named { name: other.to_string(), module: Vec::new(), args: rt_args() }
                            }
                            TypeDeclKind::Protocol { .. }
                            | TypeDeclKind::Effect(_)
                            | TypeDeclKind::Opaque => R::Any,
                        },
                        None => R::Any, // unknown name → permissive
                    },
                }
            }
            TypeRef::Array(inner, _) | TypeRef::FixedArray(_, inner, _) => {
                R::Array(Box::new(self.resolved_cat_of_depth(inner, gs, depth + 1)))
            }
            TypeRef::Tuple(_, _) | TypeRef::Func { .. } => R::Any,
            TypeRef::Protocol { .. } => R::Any,
            TypeRef::Unit(_) => R::Unit,
            TypeRef::Readonly(inner, _) => self.resolved_cat_of_depth(inner, gs, depth + 1),
            TypeRef::Pointer(_, _) => R::Ptr,
            TypeRef::Mut(inner, _) | TypeRef::Unsafe(inner, _) => {
                self.resolved_cat_of_depth(inner, gs, depth + 1)
            }
        }
    }

    // [M-generic-arg-type-mismatch-silent] U.5.3: the raw-TypeRef
    // `generic_arg_mismatch` (+ `concrete_primitive_name` / `is_type_param_name`) was
    // folded into the structured `distinct_mono` over the lossless `ResolvedType` and
    // deleted. `generic_args` (a thin TypeRef accessor) is retained for the f1_check_call
    // arg-pair iteration + message display. This removed the LAST `cat_of` consumer.
}

/// Ф.1: результат проверки совместимости.
enum Compat {
    /// Совместимо.
    Ok,
    /// Тип выражения не выводится — проверку пропускаем (не ошибка).
    Unknown,
    /// Несовместимо; `found` — отображение типа выражения.
    Bad { found: String },
    /// Plan 142 (D227): целочисленный литерал вне диапазона sized-типа.
    /// `msg` — готовый суффикс диагностики, e.g. «300 > u8.MAX (255)».
    OutOfRange { msg: String },
    /// [M-scalar-nonliteral-narrowing-not-enforced] (D54): неявное сужение
    /// НЕ-литерала из более широкого int-типа в более узкий (или
    /// value-range-unsafe sign-flip / cross). Требует явного `as`. `from`/`to` —
    /// отображения исходного и целевого типов для диагностики.
    Narrowing { from: String, to: String },
}

/// Plan 142 (D227 Rule 3/6): диапазон `[min, max]` для sized-int типа.
/// Возвращает `None` для не-sized-типов (`int`/`uint` — wide defaults
/// per D227 Rule 1, диапазон не проверяется; всё остальное — не int).
/// Используется `i128`, чтобы корректно сравнить `u64::MAX` и негативные
/// значения с границами (литерал хранится как `i64`).
fn sized_int_bounds(name: &str) -> Option<(i128, i128)> {
    let (min, max): (i128, i128) = match name {
        "u8" => (0, u8::MAX as i128),
        "u16" => (0, u16::MAX as i128),
        "u32" => (0, u32::MAX as i128),
        "u64" => (0, u64::MAX as i128),
        "i8" => (i8::MIN as i128, i8::MAX as i128),
        "i16" => (i16::MIN as i128, i16::MAX as i128),
        "i32" => (i32::MIN as i128, i32::MAX as i128),
        "i64" => (i64::MIN as i128, i64::MAX as i128),
        // `int` (= i64) и `uint` (= u64) — wide defaults (D227 Rule 1):
        // голый литерал держится без range-check. Не-числовые имена —
        // тоже None (сюда не дойдём: проверяем только TyCat::Int).
        _ => return None,
    };
    Some((min, max))
}

/// Plan 172.1 U.5.2: the former `sized_int_name(&TypeRef)`, `int_width_rank` and
/// `is_int_narrowing` standalone helpers were folded into `ResolvedType`
/// (`sized_int_name()` method + `would_narrow_into`, the single narrowing source) and
/// deleted here — the raw-TypeRef second pass over `assignable` is gone.
///
/// Plan 142 (D227 Rule 3/6): диапазон-проверка значения `val` (i128)
/// против sized-типа `name`. `Some(msg)` — литерал вне диапазона,
/// `msg` — суффикс диагностики; `None` — в пределах (или не sized).
fn lit_range_check(val: i128, name: &str) -> Option<String> {
    let (min, max) = sized_int_bounds(name)?;
    if val > max {
        Some(format!("{val} > {name}.MAX ({max})"))
    } else if val < min {
        Some(format!("{val} < {name}.MIN ({min})"))
    } else {
        None
    }
}

// Plan 172.1 U.5.4: the lossy `TyCat` category enum (and `cat_of`/`cat_of_depth`/
// `cat_compatible`) was deleted — `ResolvedType` + `resolved_cat_of` + `cat_compatible_rt`
// are the single lossless category representation. (`Ty`/`ty_of_ref` remain pending the
// U.5.4 never-check migration.)

/// Plan 172.1 U.5.2: structured mirror of `cat_compatible` over `ResolvedType`
/// (replaces the `TyCat` version for the `assignable` / `f1_check_for_elem` category
/// gate). Permissive on `Any` (= old `Other`) and — exactly like the old `(Int,Int)` —
/// on int WIDTH/SIGN: `(Scalar,Scalar)` is ALWAYS compatible here. Narrowing is decided
/// SEPARATELY by `would_narrow_into` on the DIRECT (`from_type_ref`) types BEFORE this
/// call, preserving the `int_width_rank`-vs-`cat_of` alias asymmetry byte-identically
/// (an alias-to-int must NOT be flagged as narrowing — `int_width_rank` does not resolve
/// aliases, so the width gate stays direct-only). `char` rides as `Named("char")`, so the
/// old `(Char,Char)` case is covered by the `(Named,Named)` arm.
fn cat_compatible_rt(found: &ResolvedType, expected: &ResolvedType) -> bool {
    use ResolvedType as R;
    match (found, expected) {
        (R::Any, _) | (_, R::Any) => true,
        // Permissive on int width/sign AND float width (assignability) — the
        // generic-arg type-identity check is what compares those exactly (U.5.3).
        (R::Scalar { .. }, R::Scalar { .. })
        | (R::Float { .. }, R::Float { .. })
        | (R::Scalar { .. }, R::Float { .. })
        | (R::Float { .. }, R::Scalar { .. }) => true,
        (R::Bool, R::Bool) | (R::Str, R::Str) | (R::Unit, R::Unit) | (R::Ptr, R::Ptr) => true,
        // NAME only — generic args ignored here (permissive); `char` rides as `Named`.
        (R::Named { name: a, .. }, R::Named { name: b, .. }) => a == b,
        (R::Array(a), R::Array(b)) => cat_compatible_rt(a, b),
        _ => false,
    }
}

/// U.5.3 ([M-generic-arg-type-mismatch-silent], structured): `char` rides as
/// `Named { name: "char", .. }`, so it must be treated as a primitive LEAF here, not a
/// nominal record (mirrors the legacy `concrete_primitive_name` which lists `char`).
fn is_char_rt(t: &ResolvedType) -> bool {
    matches!(t, ResolvedType::Named { name, .. } if name == "char")
}

/// U.5.3 — is `t` a concrete builtin scalar primitive leaf (the
/// `concrete_primitive_name` set: int-family, `f32`/`f64`, `char`, `bool`, `str`)? Used
/// by `distinct_mono` to decide where width/sign/float-width must match EXACTLY.
fn is_prim_leaf_rt(t: &ResolvedType) -> bool {
    use ResolvedType as R;
    matches!(t, R::Scalar { .. } | R::Float { .. } | R::Bool | R::Str) || is_char_rt(t)
}

/// U.5.3 — structured replacement of `generic_arg_mismatch`: are two `ResolvedType`
/// type-arguments of the SAME generic a DEFINITE mismatch (two distinct
/// monomorphizations, a pointer-reinterpretation footgun)? Conservative — `true` ONLY
/// when confident, mirroring the legacy raw-TypeRef rules on the now-lossless type:
///   1. `Any` (generic-param / unknown / protocol) either side → permissive (`false`);
///   2. both concrete primitives → mismatch iff NOT structurally equal (int names via
///      `wide_default`, `f32`≠`f64` via width, `char`≠`int`, …);
///   3. both same-base generic (`Array`/`[]`, or a user `Named { args }`) → recurse on
///      each nested type-argument; mismatch if any nested pair is;
///   4. both concrete NAMED records (alias-resolved via `resolved_cat_of`) with
///      different names → mismatch;
///   5. a primitive vs a record (or `ptr`/`unit`/mixed) → permissive (`false`).
fn distinct_mono(p: &ResolvedType, a: &ResolvedType) -> bool {
    use ResolvedType as R;
    match (p, a) {
        (R::Any, _) | (_, R::Any) => false, // (1)
        (R::Array(x), R::Array(y)) => distinct_mono(x, y), // (3) Vec/[]T
        // (4) both nominal records (NOT `char`, which is a primitive leaf) → name +
        // recurse args.
        (R::Named { name: np, args: ap, .. }, R::Named { name: na, args: aa, .. })
            if !is_char_rt(p) && !is_char_rt(a) =>
        {
            np != na
                || ap.len() != aa.len()
                || ap.iter().zip(aa.iter()).any(|(x, y)| distinct_mono(x, y))
        }
        // (2) both concrete primitives → exact structural identity.
        _ if is_prim_leaf_rt(p) && is_prim_leaf_rt(a) => p != a,
        // (5) primitive vs record / ptr / unit / mixed → permissive.
        _ => false,
    }
}

/// Ф.1: generic-scope функции — её параметры + generics receiver-типа.
fn fn_generic_scope(fd: &FnDecl) -> HashSet<String> {
    let mut gs: HashSet<String> = HashSet::new();
    for g in &fd.generics {
        gs.insert(g.name.clone());
    }
    if let Some(r) = &fd.receiver {
        for tr in &r.generics {
            if let TypeRef::Named { path, .. } = tr {
                if path.len() == 1 {
                    gs.insert(path[0].clone());
                }
            }
        }
    }
    gs
}

/// Plan 81 Ф.2: имена-namespace со специальным dispatch в codegen
/// (`gc.collect()`, `Time.sleep()`, ...) — не обычные module-qualified
/// вызовы свободных функций. Совпадает со списком guard'а в
/// `emit_c.rs` (Member-rewrite Plan 70.1).
// Plan 172.1 U.1.4: делегирует в ЕДИНЫЙ `crate::is_intrinsic_namespace`
// (раньше список был захардкожен здесь И в codegen emit_c.rs — hand-synced;
// теперь один источник). Тонкий wrapper сохранён, чтобы не трогать call-sites.
fn is_intrinsic_namespace(name: &str) -> bool {
    crate::is_intrinsic_namespace(name)
}

/// Ф.1: syntactic ptr-detection для arithmetic-ban check в
/// BoundCtx::walk_expr (где нет full type-inference). Покрывает literal
/// (`null ptr`), explicit cast (`x as *()` or `x as ptr` legacy),
/// scope-binding с typed ptr.
/// Plan 134: `*()` = TypeRef::Pointer(TypeRef::Unit); legacy "ptr" Named still
/// matched for transition period until all call-sites migrated.
/// Recursion в Ident lookup безопасна — scope содержит resolved TypeRef'ы.
fn expr_is_ptr_typed(e: &Expr, scope: &HashMap<String, TypeRef>) -> bool {
    fn typeref_is_ptr(ty: &TypeRef) -> bool {
        match ty {
            // Plan 134: *() = TypeRef::Pointer(TypeRef::Unit) = void*.
            TypeRef::Pointer(inner, _) => matches!(inner.as_ref(), TypeRef::Unit(_)),
            // Legacy "ptr" named type (transition period).
            TypeRef::Named { path, .. } => path.last().map_or(false, |s| s == "ptr"),
            _ => false,
        }
    }
    match &e.kind {
        ExprKind::NullPtrLit => true,
        ExprKind::As(_, ty) => typeref_is_ptr(ty),
        ExprKind::Ident(name) => scope.get(name).map_or(false, typeref_is_ptr),
        ExprKind::SelfAccess => scope.get("@").map_or(false, typeref_is_ptr),
        _ => false,
    }
}

/// **Plan 150 / D248:** is this type definitively `bool` or `unit`? Relational
/// operators (`<` `<=` `>` `>=`) require an ORDERED operand category; `bool`
/// ordering is method-only via `@compare` (D183), and `unit` has no order at
/// all. Transparent over L1/L2 modifier wrappers (`ro bool` is still bool).
/// Conservative: callers pass a definitively-inferred type (from
/// `infer_arg_ty`) and treat `None`/other as permissive (don't fire).
fn typeref_is_bool_or_unit(ty: &TypeRef) -> bool {
    match ty {
        TypeRef::Unit(_) => true,
        TypeRef::Named { path, .. } => path.last().map_or(false, |s| s == "bool"),
        TypeRef::Readonly(inner, _) | TypeRef::Mut(inner, _) => typeref_is_bool_or_unit(inner),
        _ => false,
    }
}

fn prim_ref(name: &str, span: Span) -> TypeRef {
    TypeRef::Named {
        path: vec![name.to_string()],
        generics: Vec::new(),
        span,
    }
}

/// **Plan 147 Ф.3 (D246, L3 pointee-capability):** given the type of a
/// pointer-valued expression `p`, determine whether writing through it
/// (`*p = v`) is allowed by the pointee capability (L3) — read FROM THE TYPE,
/// independent of the binding (L1).
///
/// Returns:
/// - `Some(true)`  — pointee is writable (`*mut T` = `Pointer(Mut(..))`, or
///   `*unsafe T` = `Pointer(Unsafe(..))` which is a writable raw pointee).
/// - `Some(false)` — pointee is readonly (a bare `*T ≡ *ro T` = `Pointer(T)`
///   over a non-Mut/Unsafe pointee).
/// - `None`        — `p` is not a pointer type (no L3 capability to enforce;
///   non-pointer deref is handled elsewhere / a no-op here).
///
/// Outer binding-level / value-level modifier wrappers (`Readonly` / `Mut` /
/// `Unsafe`) around the WHOLE type are transparent — they belong to L1/L2 (the
/// name/value view), not to L3 (the pointee). A `*()` (void pointer, opaque
/// pointee) carries no writable element, so it is treated as readonly.
fn pointee_is_writable(ty: &TypeRef) -> Option<bool> {
    match ty {
        // Transparent over outer L1/L2 modifier wrappers — the pointee
        // capability lives on the inner Pointer, not on these wrappers.
        TypeRef::Readonly(inner, _)
        | TypeRef::Mut(inner, _)
        | TypeRef::Unsafe(inner, _) => pointee_is_writable(inner),
        TypeRef::Pointer(pointee, _) => Some(match pointee.as_ref() {
            // `*mut T` / `*unsafe T` → writable pointee (L3 opt-in).
            TypeRef::Mut(..) | TypeRef::Unsafe(..) => true,
            // `*()` = void pointer — opaque, no writable element.
            TypeRef::Unit(_) => false,
            // Bare `*T ≡ *ro T` → readonly pointee (L3 default).
            _ => false,
        }),
        _ => None,
    }
}

/// Ф.1: человекочитаемое отображение TypeRef для диагностик.
pub(crate) fn typeref_display(tr: &TypeRef) -> String {
    match tr {
        TypeRef::Named { path, generics, .. } => {
            let base = path.join(".");
            if generics.is_empty() {
                base
            } else {
                let inner: Vec<String> =
                    generics.iter().map(typeref_display).collect();
                format!("{}[{}]", base, inner.join(", "))
            }
        }
        TypeRef::Array(inner, _) => format!("[]{}", typeref_display(inner)),
        TypeRef::FixedArray(n, inner, _) => {
            format!("[{}]{}", n, typeref_display(inner))
        }
        TypeRef::Tuple(elems, _) => {
            let inner: Vec<String> =
                elems.iter().map(typeref_display).collect();
            format!("({})", inner.join(", "))
        }
        TypeRef::Func { params, return_type, .. } => {
            let ps: Vec<String> =
                params.iter().map(typeref_display).collect();
            let rt = return_type
                .as_ref()
                .map(|t| typeref_display(t))
                .unwrap_or_else(|| "()".to_string());
            format!("fn({}) -> {}", ps.join(", "), rt)
        }
        // Plan 97 Ф.2 (D142): анонимный protocol — компактное отображение
        // через сигнатуры. В диагностике пользователю важно отличить
        // anon-protocol от других видов типа.
        TypeRef::Protocol { methods, .. } => {
            let sigs: Vec<String> = methods
                .iter()
                .map(|m| {
                    let prefix = if m.is_static { "." } else { "" };
                    let ps: Vec<String> = m
                        .params
                        .iter()
                        .map(|p| typeref_display(&p.ty))
                        .collect();
                    let rt = m
                        .return_type
                        .as_ref()
                        .map(|t| format!(" -> {}", typeref_display(t)))
                        .unwrap_or_default();
                    format!("{}{}({}){}", prefix, m.name, ps.join(", "), rt)
                })
                .collect();
            format!("protocol {{ {} }}", sigs.join("; "))
        }
        TypeRef::Unit(_) => "()".to_string(),
        // D176 (Plan 108): readonly T — display as "readonly T"
        TypeRef::Readonly(inner, _) => format!("ro {}", typeref_display(inner)),
        // Plan 118 D216 §1 + Plan 118.5: typed pointer `*T` family — new
        // canonical syntax with each modifier as its own variant. Pointer is
        // the only sigil-introducing variant; Mut/Unsafe are pre-modifiers
        // that wrap an inner (typically `Pointer(T)`, producing `mut *T`/
        // `unsafe *T`). Display recursively to preserve nesting (e.g.
        // `Mut(Pointer(Readonly(Pointer(T))))` → `mut *ro *T`).
        TypeRef::Pointer(inner, _) => format!("*{}", typeref_display(inner)),
        TypeRef::Mut(inner, _) => format!("mut {}", typeref_display(inner)),
        TypeRef::Unsafe(inner, _) => format!("unsafe {}", typeref_display(inner)),
    }
}

/// Ф.2: построить диагностику E7310 о неверной арности type-аргументов.
/// Вызывается только когда аргументы УКАЗАНЫ (`actual > 0`) — опущенные
/// аргументы легальны (выводятся из контекста), это не arity-ошибка.
fn arity_diag(name: &str, info: &ArityInfo, actual: usize, span: Span) -> Diagnostic {
    let plural = |n: usize| if n == 1 { "" } else { "s" };
    let werewas = |n: usize| if n == 1 { "was" } else { "were" };
    let msg = if info.count == 0 {
        format!(
            "[E7310] type `{}` is not generic — it takes no type arguments, \
             but {} {} provided",
            name, actual, werewas(actual),
        )
    } else {
        format!(
            "[E7310] type `{}` expects {} type argument{}, but {} {} provided",
            name, info.count, plural(info.count), actual, werewas(actual),
        )
    };
    let diag = Diagnostic::new(msg, span);
    match info.decl_span {
        Some(ds) => diag.with_note_at(format!("type `{}` declared here", name), ds),
        None => diag,
    }
}

/// Plan 101.4 (D145 Ред. 5): protocol composition validation.
///
/// Проверяет три инварианта на `type X protocol { use Y  use Z  ... }`:
///   1. **E_PROTOCOL_EMBED_NOT_PROTOCOL** — target типа `use TypeName`
///      объявлен, но это НЕ `TypeDeclKind::Protocol` (effect/record/sum/
///      alias/newtype). Embed работает только между protocol'ами.
///   2. **E_PROTOCOL_EMBED_UNKNOWN** — target не объявлен ни как protocol,
///      ни как любой другой тип (typo / forgotten import).
///   3. **E_PROTOCOL_EMBED_CYCLE** — `A use B use C use A` — циклическая
///      композиция. Detect через DFS.
///   4. **E_PROTOCOL_EMBED_DUPLICATE** — после flatten'а ≥2 метода с
///      одинаковым (name, arity) сигнатурой пришли из разных embed-путей
///      (или direct + embedded). Разрешено если строго совпадают; иначе
///      ambiguity, должна быть resolved direct-override'ом (V1 — error;
///      override-механизм — V2/D145 Ред. 6).
/// `sig_table` — optional cross-module signature table (Plan 162.1 Step 3).
/// When present, `E_PROTOCOL_EMBED_UNKNOWN` is suppressed for type names that
/// are declared in a transitively-imported module captured in the sig_table.
fn check_protocol_embeds(
    module: &Module,
    sig_table: Option<&crate::imports::ModuleSigTable>,
    errors: &mut Vec<Diagnostic>,
) {
    use std::collections::{HashMap, HashSet};
    // Collect protocol declarations + map of all type names → kind hint.
    let mut proto_map: HashMap<String, (&Vec<EffectMethod>, &Vec<TypeRef>, Span)> = HashMap::new();
    let mut type_kinds: HashMap<String, &'static str> = HashMap::new();
    for item in &module.items {
        if let Item::Type(t) = item {
            let kind_name = match &t.kind {
                TypeDeclKind::Protocol { .. } => "protocol",
                TypeDeclKind::Effect(_) => "effect",
                TypeDeclKind::Record(_) => "record",
                TypeDeclKind::Sum(_) => "sum",
                TypeDeclKind::Alias(_) => "alias",
                TypeDeclKind::Newtype(_) => "newtype",
                TypeDeclKind::Opaque => "opaque",
                TypeDeclKind::NamedTuple(_) => "named_tuple",
            };
            type_kinds.insert(t.name.clone(), kind_name);
            if let TypeDeclKind::Protocol { methods, embeds } = &t.kind {
                proto_map.insert(t.name.clone(), (methods, embeds, t.span));
            }
        }
    }
    // 1+2: validate each embed reference.
    for (proto_name, (_methods, embeds, _span)) in &proto_map {
        for emb in embeds.iter() {
            let TypeRef::Named { path, span: emb_span, .. } = emb else {
                errors.push(Diagnostic::new(
                    format!(
                        "[E_PROTOCOL_EMBED_NOT_NAMED] `use` in protocol `{}` body \
                         requires a named protocol type (e.g. `use Reader`); \
                         complex type expressions are not allowed here",
                        proto_name
                    ),
                    emb.span(),
                ));
                continue;
            };
            let Some(emb_name) = path.last() else { continue };
            // Self-embed `use Self` или `use <SelfName>` — circular trivially.
            if emb_name == proto_name {
                errors.push(Diagnostic::new(
                    format!(
                        "[E_PROTOCOL_EMBED_CYCLE] protocol `{}` cannot embed itself \
                         (`use {}`)",
                        proto_name, emb_name
                    ),
                    *emb_span,
                ));
                continue;
            }
            match type_kinds.get(emb_name) {
                None => {
                    // Plan 162.1 Step 3: suppress E_PROTOCOL_EMBED_UNKNOWN
                    // when the type is known via the cross-module sig_table.
                    // This handles the lazy-resolution scenario where a
                    // transitively imported module's types are not yet
                    // inline-merged into module.items.
                    let known_via_sig_table = sig_table
                        .map(|st| !st.find_type_modules(emb_name).is_empty())
                        .unwrap_or(false);
                    if !known_via_sig_table {
                        errors.push(Diagnostic::new(
                            format!(
                                "[E_PROTOCOL_EMBED_UNKNOWN] unknown type `{}` in \
                                 `use {}` (protocol `{}` body) — type not declared \
                                 in module or via import",
                                emb_name, emb_name, proto_name
                            ),
                            *emb_span,
                        ));
                    }
                }
                Some(&"protocol") => { /* OK */ }
                Some(other) => {
                    errors.push(Diagnostic::new(
                        format!(
                            "[E_PROTOCOL_EMBED_NOT_PROTOCOL] `use {}` in protocol \
                             `{}` body — `{}` is a {}, not a protocol. Protocol \
                             composition (D145 Ред. 5) requires `use <Protocol>`",
                            emb_name, proto_name, emb_name, other
                        ),
                        *emb_span,
                    ));
                }
            }
        }
    }
    // 3: cycle detection via DFS coloring (white/gray/black).
    #[derive(Clone, Copy, PartialEq)]
    enum Color { White, Gray, Black }
    let mut color: HashMap<String, Color> = proto_map.keys()
        .map(|n| (n.clone(), Color::White)).collect();
    fn dfs_cycle(
        node: &str,
        proto_map: &HashMap<String, (&Vec<EffectMethod>, &Vec<TypeRef>, Span)>,
        color: &mut HashMap<String, Color>,
        path: &mut Vec<String>,
        errors: &mut Vec<Diagnostic>,
    ) {
        let cur = *color.get(node).unwrap_or(&Color::White);
        if cur == Color::Black { return; }
        if cur == Color::Gray {
            // Cycle: path contains `node` earlier.
            let cycle_start = path.iter().position(|n| n == node).unwrap_or(0);
            let cycle_names: Vec<String> = path[cycle_start..].to_vec();
            let cycle_str = format!("{} → {}", cycle_names.join(" → "), node);
            // Use embed-span of first protocol in cycle if available.
            let span = proto_map.get(&cycle_names[0])
                .map(|(_, _, s)| *s).unwrap_or_default();
            errors.push(Diagnostic::new(
                format!(
                    "[E_PROTOCOL_EMBED_CYCLE] cyclic protocol composition: {}",
                    cycle_str
                ),
                span,
            ));
            return;
        }
        color.insert(node.to_string(), Color::Gray);
        path.push(node.to_string());
        if let Some((_, embeds, _)) = proto_map.get(node) {
            for emb in embeds.iter() {
                if let TypeRef::Named { path: p, .. } = emb {
                    if let Some(n) = p.last() {
                        if proto_map.contains_key(n) {
                            dfs_cycle(n, proto_map, color, path, errors);
                        }
                    }
                }
            }
        }
        path.pop();
        color.insert(node.to_string(), Color::Black);
    }
    // Iterate sorted for deterministic diagnostic order.
    let mut names: Vec<String> = proto_map.keys().cloned().collect();
    names.sort();
    for name in &names {
        if *color.get(name).unwrap_or(&Color::White) == Color::White {
            let mut path = Vec::new();
            dfs_cycle(name, &proto_map, &mut color, &mut path, errors);
        }
    }
    // 4: duplicate-method detection after flatten.
    // Flatten без cycle (cycle уже reported) — guard через max-depth.
    fn flatten_with_origin(
        name: &str,
        proto_map: &HashMap<String, (&Vec<EffectMethod>, &Vec<TypeRef>, Span)>,
        seen: &mut HashSet<String>,
        out: &mut Vec<(String, String, usize)>, // (origin_proto, method_name, arity)
        origin: &str,
    ) {
        if !seen.insert(name.to_string()) { return; }
        let Some((methods, embeds, _)) = proto_map.get(name) else { return; };
        for m in methods.iter() {
            out.push((origin.to_string(), m.name.clone(), m.params.len()));
        }
        for emb in embeds.iter() {
            if let TypeRef::Named { path: p, .. } = emb {
                if let Some(n) = p.last() {
                    flatten_with_origin(n, proto_map, seen, out, n);
                }
            }
        }
    }
    for (proto_name, (local_methods, _, span)) in &proto_map {
        let mut entries = Vec::new();
        let mut seen = HashSet::new();
        flatten_with_origin(proto_name, &proto_map, &mut seen, &mut entries, proto_name);
        // Group by (name, arity). >1 distinct origins → duplicate.
        let mut sig_origins: HashMap<(String, usize), Vec<String>> = HashMap::new();
        for (orig, mname, arity) in entries {
            sig_origins.entry((mname, arity)).or_default().push(orig);
        }
        // Plan 91.8a (D183): local override allowed — если метод есть и
        // локально в proto_name, и из embed'ов, локальная декларация
        // считается override embedded-default'а (НЕ duplicate). Это
        // используется напр. в `Comparable.equals` default body для
        // embedded `Equatable.equals`.
        let local_sigs: HashSet<(String, usize)> = local_methods.iter()
            .map(|m| (m.name.clone(), m.params.len()))
            .collect();
        for ((mname, arity), origins) in sig_origins {
            // Уникальные источники (один и тот же origin >1 раз не считается).
            let unique: HashSet<String> = origins.iter().cloned().collect();
            if unique.len() > 1 {
                // Override-by-local case: если метод объявлен локально И
                // также приходит из embed'а — local wins, skip duplicate.
                if local_sigs.contains(&(mname.clone(), arity)) {
                    continue;
                }
                let mut sources: Vec<String> = unique.into_iter().collect();
                sources.sort();
                errors.push(Diagnostic::new(
                    format!(
                        "[E_PROTOCOL_EMBED_DUPLICATE] method `{}/{}` in protocol \
                         `{}` is provided by multiple embedded protocols: {}. \
                         Protocol composition (D145 Ред. 5) does not yet support \
                         override; remove one embed or define the method directly \
                         (Plan 91.8a D183: declaring the method locally в `{}` \
                         overrides embedded default).",
                        mname, arity, proto_name, sources.join(", "), proto_name
                    ),
                    *span,
                ));
            }
        }
    }
}

/// Plan 101.3 (D145 Ред. 5): валидация bound-имён в declaration
/// generic-параметров. Для каждого `[T A + B + C]` проверяем, что
/// каждое имя bound'а — это объявленный protocol, либо well-known
/// stdlib-alias (Hashable/Eq/Ord/Display/Equatable/Comparable/ToStr/
/// TryFrom/TryInto), либо primitive-имя (Q-representation-bound future).
/// Если имя — record/sum/effect → error E_BOUND_NOT_PROTOCOL.
/// Если имя вообще unknown → error E_BOUND_UNKNOWN.
///
/// `sig_table` — optional cross-module signature table (Plan 162.1 Step 3).
/// When present, `E_BOUND_UNKNOWN` is suppressed for type names that are
/// declared in a transitively-imported module captured in the sig_table.
fn check_generic_bound_declarations(
    module: &Module,
    sig_table: Option<&crate::imports::ModuleSigTable>,
    errors: &mut Vec<Diagnostic>,
) {
    use std::collections::HashMap;
    // Карта известных type-имён → kind hint.
    let mut type_kinds: HashMap<String, &'static str> = HashMap::new();
    for item in &module.items {
        if let Item::Type(t) = item {
            let kind_name = match &t.kind {
                TypeDeclKind::Protocol { .. } => "protocol",
                TypeDeclKind::Effect(_) => "effect",
                TypeDeclKind::Record(_) => "record",
                TypeDeclKind::Sum(_) => "sum",
                TypeDeclKind::Alias(_) => "alias",
                TypeDeclKind::Newtype(_) => "newtype",
                TypeDeclKind::Opaque => "opaque",
                TypeDeclKind::NamedTuple(_) => "named_tuple",
            };
            type_kinds.insert(t.name.clone(), kind_name);
        }
    }
    // Well-known stdlib alias names (D237: renamed + new protocols).
    // D237: Hashable→Hash, Equatable→Equal, Comparable→Compare, Cloneable→Clone,
    //       Printable→Display, DebugPrintable→Debug.
    let stdlib_aliases: &[&str] = &[
        "Ord", "Eq", "ToStr", "TryFrom", "TryInto",
        "Hash", "Display", "Equal", "Compare", "Clone", "Debug",
        "Iterable", "From", "Into",
    ];
    // Primitive-имена (Q-representation-bound future):
    let primitives: &[&str] = &[
        "int", "i8", "i16", "i32", "i64",
        "u8", "u16", "u32", "u64", "uint",
        "f32", "f64", "bool", "char", "str", "any", "never",
    ];
    let check_bound = |b: &TypeRef, errors: &mut Vec<Diagnostic>| {
        let TypeRef::Named { path, span, .. } = b else { return; };
        let Some(name) = path.last() else { return; };
        // Если у имени префикс (`std.collections.Iter`), берём последний.
        // Allowed: protocol, alias, primitive.
        if stdlib_aliases.contains(&name.as_str()) { return; }
        if primitives.contains(&name.as_str()) { return; }
        match type_kinds.get(name) {
            Some(&"protocol") => { /* OK */ }
            Some(&kind) => {
                errors.push(Diagnostic::new(
                    format!(
                        "[E_BOUND_NOT_PROTOCOL] `{}` is a {}, not a protocol — \
                         generic bounds must be protocol-types (D72). Consider \
                         declaring `type {} protocol {{ ... }}` if structural \
                         contract is intended.",
                        name, kind, name
                    ),
                    *span,
                ));
            }
            None => {
                // Plan 162.1 Step 3: suppress E_BOUND_UNKNOWN when the type
                // is known via the cross-module sig_table (lazy resolution).
                let known_via_sig_table = sig_table
                    .map(|st| !st.find_type_modules(name).is_empty())
                    .unwrap_or(false);
                if !known_via_sig_table {
                    errors.push(Diagnostic::new(
                        format!(
                            "[E_BOUND_UNKNOWN] unknown type `{}` used as generic bound — \
                             not a declared protocol, stdlib alias, or primitive. \
                             Did you forget to declare/import it?",
                            name
                        ),
                        *span,
                    ));
                }
            }
        }
    };
    for item in &module.items {
        match item {
            Item::Fn(f) => {
                for g in &f.generics {
                    for b in &g.bounds {
                        check_bound(b, errors);
                    }
                }
            }
            Item::Type(t) => {
                for g in &t.generics {
                    for b in &g.bounds {
                        check_bound(b, errors);
                    }
                }
            }
            _ => {}
        }
    }
}

/// Plan 15 (D72): registry для bound enforcement.
///
/// `protocol_specs`: для каждого `type Foo protocol { ... }` — список
/// required methods (TypeDeclKind::Effect; в Nova protocol/effect единая
/// форма по D62).
///
/// `fn_decls`: top-level fn-декларации (для resolve вызова по имени).
///
/// `method_table`: для каждого concrete-типа — методы (по имени), для
/// проверки "type T satisfies protocol P".
struct BoundCtx<'a> {
    /// Plan 15 D53 strict: только protocol-kind типов. Effect-kind
    /// сюда не попадает — effects не разрешены как D72 bounds.
    ///
    /// Plan 101.4 (D145 Ред. 5): значение — **flattened** список методов:
    /// direct + recursive embedded protocol methods. Поэтому owned `Vec`,
    /// а не borrow в AST (синтетическая копия после embed-expansion).
    /// Flatten построен в `BoundCtx::build` через DFS с cycle-protection.
    protocol_specs: HashMap<String, Vec<EffectMethod>>,
    /// Plan 15 D53 strict: effect-kind типы. Рспользуется для
    /// дифференциированного error-сообщения, если их пытаются
    /// использовать как bound («`Db` is an effect, not a protocol»).
    effect_decls: HashMap<String, &'a TypeDecl>,
    /// Plan 172.1 U.2.3.2: shared base signature registry — replaces the local
    /// `fn_decls`/`method_table` build loop (§0 single source). Read via
    /// `self.sig.fn_decls` / `self.sig.method_table` (same nested shapes, base only).
    /// D84 overload semantics unchanged: `Vec<&FnDecl>` per name; bound-checker
    /// filters by arity, codegen does full type-based resolve.
    sig: &'a crate::sig_registry::SigRegistry<'a>,
    /// Plan 53: имена sum-variant'ов (для refutability check let-pattern).
    /// `type Color | Red | Green` → {"Red", "Green"}. Рспользуется чтобы
    /// отличить `let Color.Red { x } = obj` (refutable, error) от
    /// `let Pair { x, y } = p` (irrefutable record).
    sum_variant_names: std::collections::HashSet<String>,
    /// Plan 162 Ф.3: type name -> declaring module name segments.
    /// Mirrors TypeCheckCtx.type_defining_modules; built from peer_files.
    type_defining_modules: HashMap<String, Vec<String>>,
    /// Plan 162 Ф.3: TypeMethodMap - type_name -> method_name ->
    /// list of module_names that declared this method.
    type_method_map: HashMap<String, HashMap<String, Vec<Vec<String>>>>,
}

impl<'a> BoundCtx<'a> {
    fn build(module: &'a Module, sig: &'a crate::sig_registry::SigRegistry<'a>) -> Self {
        // Plan 101.4: direct = name → (own methods, embed-typerefs).
        // Используется для flatten DFS ниже.
        let mut direct: HashMap<String, (Vec<EffectMethod>, Vec<TypeRef>)> = HashMap::new();
        // U.2.3.2: fn_decls/method_table no longer built here — read from `sig`.
        let mut sum_variant_names: std::collections::HashSet<String> = std::collections::HashSet::new();

        let mut effect_decls: HashMap<String, &TypeDecl> = HashMap::new();
        for item in &module.items {
            match item {
                Item::Type(t) => {
                    // Plan 15 D53 strict: protocol-kind → eligible как
                    // bound (D72); effect-kind → отдельный registry для
                    // диагностики «used as bound but it's an effect».
                    match &t.kind {
                        TypeDeclKind::Protocol { methods, embeds } => {
                            direct.insert(
                                t.name.clone(),
                                (methods.clone(), embeds.clone()),
                            );
                        }
                        TypeDeclKind::Effect(_) => {
                            effect_decls.insert(t.name.clone(), t);
                        }
                        // Plan 53: sum-variants для refutability check.
                        TypeDeclKind::Sum(variants) => {
                            for v in variants {
                                sum_variant_names.insert(v.name.clone());
                            }
                        }
                        _ => {}
                    }
                }
                _ => {}
            }
        }

        // Plan 101.4 flatten: для каждого protocol'а собираем полный
        // список методов = direct ∪ recursively-embedded. Cycle-protection
        // через `seen` — если протокол повторно встречается в DFS, его
        // методы НЕ добавляются повторно (silent skip; error diagnostic —
        // в `check_protocol_embeds` отдельно). Duplicate-method конфликты
        // тоже только в check_protocol_embeds; здесь — bag-union.
        fn flatten_dfs(
            name: &str,
            direct: &HashMap<String, (Vec<EffectMethod>, Vec<TypeRef>)>,
            seen: &mut std::collections::HashSet<String>,
            out: &mut Vec<EffectMethod>,
        ) {
            if !seen.insert(name.to_string()) {
                return;
            }
            let Some((methods, embeds)) = direct.get(name) else { return; };
            for m in methods {
                out.push(m.clone());
            }
            for e in embeds {
                if let TypeRef::Named { path, .. } = e {
                    if let Some(emb_name) = path.last() {
                        flatten_dfs(emb_name, direct, seen, out);
                    }
                }
            }
        }
        let mut protocol_specs: HashMap<String, Vec<EffectMethod>> = HashMap::new();
        for name in direct.keys() {
            let mut out = Vec::new();
            let mut seen = std::collections::HashSet::new();
            flatten_dfs(name, &direct, &mut seen, &mut out);
            protocol_specs.insert(name.clone(), out);
        }

        // Plan 162 Ф.3: build type_defining_modules and type_method_map for BoundCtx.
        // Same logic as TypeCheckCtx.build; BoundCtx needs them for is_inherent_method
        // used in resolve_instance_method.
        let mut type_defining_modules: HashMap<String, Vec<String>> = HashMap::new();
        let mut type_method_map: HashMap<String, HashMap<String, Vec<Vec<String>>>> = HashMap::new();
        if module.peer_files.is_empty() {
            for item in &module.items {
                match item {
                    Item::Type(td) => {
                        type_defining_modules.entry(td.name.clone()).or_insert_with(|| module.name.clone());
                    }
                    Item::Fn(f) => {
                        if let Some(recv) = &f.receiver {
                            let module_list = type_method_map.entry(recv.type_name.clone()).or_default().entry(f.name.clone()).or_default();
                            if !module_list.contains(&module.name) { module_list.push(module.name.clone()); }
                        }
                    }
                    _ => {}
                }
            }
        } else {
            for pf in &module.peer_files {
                for item in &pf.items_here {
                    match item {
                        Item::Type(td) => {
                            type_defining_modules.entry(td.name.clone()).or_insert_with(|| pf.module_name.clone());
                        }
                        Item::Fn(f) => {
                            if let Some(recv) = &f.receiver {
                                let module_list = type_method_map.entry(recv.type_name.clone()).or_default().entry(f.name.clone()).or_default();
                                if !module_list.contains(&pf.module_name) { module_list.push(pf.module_name.clone()); }
                            }
                        }
                        _ => {}
                    }
                }
            }
        }

        BoundCtx { protocol_specs, effect_decls, sig, sum_variant_names, type_defining_modules, type_method_map }
    }

    /// Plan 162 Ф.3: returns true iff method_name on type type_name is inherent
    /// (declared in the same module as the type).
    fn is_inherent_method(&self, type_name: &str, method_name: &str) -> bool {
        let Some(type_module) = self.type_defining_modules.get(type_name) else {
            return false;
        };
        let Some(type_methods) = self.type_method_map.get(type_name) else {
            return false;
        };
        let Some(method_modules) = type_methods.get(method_name) else {
            return false;
        };
        method_modules.iter().any(|m| m == type_module)
    }

    fn check_module(&self, module: &Module, errors: &mut Vec<Diagnostic>) {
        // Plan 56 Ф.2.7 reverted (2026-05-20, D122 amended): эффекты в
        // protocol-методах РАЗРЕШЕНЫ. Под mono-dispatch (bootstrap) эффект
        // protocol-метода пробрасывается как у любой effectful-функции;
        // прежний запрет касался только true-vtable dispatch (Plan 03 —
        // там effectful-protocol bounds обязаны mono-dispatch'иться).
        // Пример: `type TryFrom[T,E] protocol { try_from(t T) Fail[E] -> Self }`.
        for item in &module.items {
            match item {
                Item::Fn(f) => {
                    let mut scope: HashMap<String, TypeRef> = HashMap::new();
                    // Регистрируем параметры функции с их типами.
                    for p in &f.params {
                        scope.insert(p.name.clone(), p.ty.clone());
                    }
                    self.walk_fn_body(f, &mut scope, errors);
                }
                Item::Test(t) => {
                    // Plan 15: тесты тоже могут содержать generic-вызовы
                    // c bounds — обходим их body со свежим scope.
                    let mut scope: HashMap<String, TypeRef> = HashMap::new();
                    self.walk_block(&t.body, &mut scope, errors);
                }
                _ => {}
            }
        }
    }

    fn walk_fn_body(&self, f: &FnDecl, scope: &mut HashMap<String, TypeRef>, errors: &mut Vec<Diagnostic>) {
        match &f.body {
            FnBody::Expr(e) => self.walk_expr(e, scope, errors),
            FnBody::Block(b) => self.walk_block(b, scope, errors),
            FnBody::External => {}
        }
    }

    fn walk_block(&self, b: &Block, scope: &mut HashMap<String, TypeRef>, errors: &mut Vec<Diagnostic>) {
        // Сохраняем snapshot для bindings которые let'аются в этом блоке —
        // чтобы вернуть scope после блока (block-out shadowing semantics).
        let mut snapshot: Vec<(String, Option<TypeRef>)> = Vec::new();
        for s in &b.stmts {
            if let Stmt::Let(d) = s {
                if let Some(name) = pattern_simple_name(&d.pattern) {
                    snapshot.push((name.clone(), scope.get(&name).cloned()));
                }
            }
        }
        for s in &b.stmts {
            self.walk_stmt(s, scope, errors);
        }
        if let Some(t) = &b.trailing {
            self.walk_expr(t, scope, errors);
        }
        // Восстановим shadowed bindings (block-out).
        for (n, prev) in snapshot {
            match prev {
                Some(t) => { scope.insert(n, t); }
                None => { scope.remove(&n); }
            }
        }
    }

    fn walk_stmt(&self, s: &Stmt, scope: &mut HashMap<String, TypeRef>, errors: &mut Vec<Diagnostic>) {
        match s {
            Stmt::Expr(e) => self.walk_expr(e, scope, errors),
            Stmt::Let(d) => {
                self.walk_expr(&d.value, scope, errors);
                // Plan 53: refutable pattern в `let` — compile error.
                // Допустимы только irrefutable patterns (Ident, Wildcard,
                // Tuple, plain-Record). Refutable (Literal, Variant, Or,
                // Array, Record-к-sum-variant) ловим здесь — codegen и
                // interp ассамят irrefutable.
                self.check_let_pattern_irrefutable(&d.pattern, errors);
                // Регистрируем simple-Ident pattern с inferred типом.
                if let Some(name) = pattern_simple_name(&d.pattern) {
                    let inferred = d.ty.clone()
                        .or_else(|| Self::infer_arg_ty(&d.value, scope));
                    if let Some(t) = inferred {
                        scope.insert(name, t);
                    }
                }
            }
            // Plan 114.4 Ф.2: scope-local const — pass-through (no-op for now).
            Stmt::Const(_) => {}
            Stmt::Assign { target, value, .. } => {
                self.walk_expr(target, scope, errors);
                self.walk_expr(value, scope, errors);
            }
            Stmt::Return { value, .. } => {
                if let Some(v) = value { self.walk_expr(v, scope, errors); }
            }
            Stmt::Throw { value, .. } => self.walk_expr(value, scope, errors),
            Stmt::Break(_) | Stmt::Continue(_) => {}
            // D90 Plan 20 Ф.2: body парсится, walk'аем — bound-checker
            // получит call'ы внутри body. Body-constraint проверки
            // (no Fail, no suspend, no exit-control) добавляются в Ф.3.
            Stmt::Defer { body, .. } | Stmt::ErrDefer { body, .. }
            | Stmt::OkDefer { body, .. } | Stmt::DeferWithResult { body, .. } => {
                self.walk_expr(body, scope, errors);
            }
            // Plan 110 D188: walk init + body (scaffold).
            Stmt::ConsumeScope { init, body, .. } => {
                self.walk_expr(init, scope, errors);
                for s in &body.stmts {
                    self.walk_stmt(s, scope, errors);
                }
                if let Some(t) = &body.trailing {
                    self.walk_expr(t, scope, errors);
                }
            }
            // Plan 33.2 Ф.8: assert_static — walk expr.
            Stmt::AssertStatic { expr, .. } | Stmt::Assume { expr, .. } => self.walk_expr(expr, scope, errors),
            // Ф.4.1: apply — ghost statement, args walk'аем (для name resolution).
            Stmt::Apply { args, .. } => {
                for a in args { self.walk_expr(a, scope, errors); }
            }
            // Ф.4.2: calc — ghost, шаги walk'аем.
            Stmt::Calc { steps, .. } => {
                for step in steps { self.walk_expr(&step.expr, scope, errors); }
            }
            // Plan 33.9 Ф.2: reveal — ghost, name resolution в pipeline.
            Stmt::Reveal { .. } => {}
            // Plan 136: tuple destructuring assignment.
            Stmt::TupleAssign { lhs, rhs, .. } => {
                for e in lhs { self.walk_expr(e, scope, errors); }
                for e in rhs { self.walk_expr(e, scope, errors); }
            }
        }
    }

    fn walk_expr(&self, e: &Expr, scope: &mut HashMap<String, TypeRef>, errors: &mut Vec<Diagnostic>) {
        // Проверяем сам call перед рекурсией в args (порядок не важен).
        self.check_call_bounds(e, scope, errors);
        // Plan 46 (D102): argument binding diagnostics.
        self.check_call_argbind(e, scope, errors);
        // Plan 97.1 hardening: `box.method()` для protocol-typed var —
        // method обязан быть в protocol_specs[<Proto>].
        self.check_protocol_method_call(e, scope, errors);
        match &e.kind {
            ExprKind::Call { func, args, trailing } => {
                self.walk_expr(func, scope, errors);
                for a in args {
                    self.walk_expr(a.expr(), scope, errors);
                }
                if let Some(t) = trailing {
                    match t {
                        crate::ast::Trailing::Block(b) => self.walk_block(b, scope, errors),
                        crate::ast::Trailing::LegacyBlockWithParams(tb) => {
                            self.walk_block(&tb.body, scope, errors)
                        }
                        crate::ast::Trailing::Fn(sb) => {
                            // Trailing-fn body: Expr или Block.
                            match &sb.body {
                                FnBody::Expr(e) => self.walk_expr(e, scope, errors),
                                FnBody::Block(b) => self.walk_block(b, scope, errors),
                                FnBody::External => {}
                            }
                        }
                    }
                }
            }
            ExprKind::TurboFish { base, .. } => self.walk_expr(base, scope, errors),
            ExprKind::Binary { left, right, op } => {
                // Plan 115 D214: ptr arithmetic banned (E_PTR_ARITHMETIC_BANNED).
                // V1: only comparison (Eq/Neq) и cast (handled separately)
                // разрешены на ptr. Все остальные binary ops — forbidden.
                let is_arith_or_rel = !matches!(op, BinOp::Eq | BinOp::Neq);
                if is_arith_or_rel {
                    let l_is_ptr = expr_is_ptr_typed(left, scope);
                    let r_is_ptr = expr_is_ptr_typed(right, scope);
                    if l_is_ptr || r_is_ptr {
                        errors.push(Diagnostic::new(
                            format!(
                                "[E_PTR_ARITHMETIC_BANNED] арифметика и сравнения \
                                 порядка на `ptr` запрещены (Plan 115 D214 V1): \
                                 опаковый pointer не поддерживает `{:?}`. \
                                 Используйте `==` / `!=` для null-check'ов; для integer-\
                                 арифметики сделайте `(p as u64) <op> ...`.",
                                op
                            ),
                            e.span,
                        ));
                    }
                }
                // Plan 150 / D248: relational operators require an ORDERED operand
                // type. `bool` / `unit` are not ordered (bool ordering is
                // method-only via `@compare`, D183) — `flag < 5` / `true < false`
                // is the silent-coercion footgun. `==`/`!=` on bool/unit stay legal
                // (not relational, hence excluded here). Conservative: fires only
                // when an operand type is definitively known to be bool/unit
                // (permissive on unknown/generic — does not break inference).
                if matches!(op, BinOp::Lt | BinOp::Le | BinOp::Gt | BinOp::Ge) {
                    let is_bool_unit = |x: &Expr| {
                        Self::infer_arg_ty(x, scope)
                            .map_or(false, |t| typeref_is_bool_or_unit(&t))
                    };
                    if is_bool_unit(left) || is_bool_unit(right) {
                        errors.push(Diagnostic::new(
                            "[E_RELATIONAL_OPERAND_NOT_ORDERED] `bool` / `unit` is not \
                             an ordered type — the relational operators `<` `<=` `>` \
                             `>=` require operands of an ordered category (int, float, \
                             str, char, or a type carrying `@compare`). Boolean ordering \
                             is method-only via `@compare` (D183 / Plan 150 D248), not \
                             the `<` operator. Use `==` / `!=` for boolean equality."
                                .to_string(),
                            e.span,
                        ));
                    }
                }
                self.walk_expr(left, scope, errors);
                self.walk_expr(right, scope, errors);
            }
            ExprKind::Unary { operand, .. } => self.walk_expr(operand, scope, errors),
            ExprKind::Try(inner) | ExprKind::Bang(inner) => self.walk_expr(inner, scope, errors),
            ExprKind::Coalesce(a, b) => {
                self.walk_expr(a, scope, errors);
                self.walk_expr(b, scope, errors);
            }
            ExprKind::As(e, _) => self.walk_expr(e, scope, errors),
            ExprKind::Is(e, _) => self.walk_expr(e, scope, errors),
            ExprKind::Member { obj, .. } => self.walk_expr(obj, scope, errors),
            ExprKind::Index { obj, index } => {
                self.walk_expr(obj, scope, errors);
                self.walk_expr(index, scope, errors);
            }
            ExprKind::If { cond, then, else_ } => {
                self.walk_expr(cond, scope, errors);
                self.walk_block(then, scope, errors);
                if let Some(eb) = else_ {
                    match eb {
                        ElseBranch::Block(b) => self.walk_block(b, scope, errors),
                        ElseBranch::If(e) => self.walk_expr(e, scope, errors),
                    }
                }
            }
            ExprKind::IfLet { scrutinee, then, else_, .. } => {
                self.walk_expr(scrutinee, scope, errors);
                self.walk_block(then, scope, errors);
                if let Some(eb) = else_ {
                    match eb {
                        ElseBranch::Block(b) => self.walk_block(b, scope, errors),
                        ElseBranch::If(e) => self.walk_expr(e, scope, errors),
                    }
                }
            }
            ExprKind::Match { scrutinee, arms } => {
                self.walk_expr(scrutinee, scope, errors);
                for arm in arms {
                    if let Some(g) = &arm.guard { self.walk_expr(g, scope, errors); }
                    match &arm.body {
                        MatchArmBody::Expr(e) => self.walk_expr(e, scope, errors),
                        MatchArmBody::Block(b) => self.walk_block(b, scope, errors),
                    }
                }
            }
            ExprKind::Block(b) => self.walk_block(b, scope, errors),
            ExprKind::ArrayLit(elems) => {
                for el in elems {
                    match el {
                        ArrayElem::Item(e) | ArrayElem::Spread(e) => self.walk_expr(e, scope, errors),
                    }
                }
            }
            ExprKind::MapLit { elems, .. } => {
                let pairs = crate::ast::MapElem::cloned_pairs(&elems);
                for (k, v) in pairs.iter() {
                    self.walk_expr(k, scope, errors);
                    self.walk_expr(v, scope, errors);
                }
            }
            ExprKind::TupleLit(elems) => {
                for e in elems { self.walk_expr(e, scope, errors); }
            }
            ExprKind::RecordLit { fields, .. } => {
                for f in fields {
                    if let Some(v) = &f.value { self.walk_expr(v, scope, errors); }
                }
            }
            ExprKind::TaggedTemplate { tag, args, .. } => {
                self.walk_expr(tag, scope, errors);
                for a in args { self.walk_expr(a, scope, errors); }
            }
            ExprKind::InterpolatedStr { parts } => {
                for p in parts {
                    if let InterpStrPart::Expr { expr: e, spec: _ } = p {
                        self.walk_expr(e, scope, errors);
                    }
                }
            }
            ExprKind::Lambda { body, .. } => self.walk_expr(body, scope, errors),
            // Plan 19, C5: BoundCtx обходит тело closure-light /
            // closure-full для генерик-bound проверок. Полный
            // bidirectional inference — фаза C6; здесь — только walk.
            ExprKind::ClosureLight { body, .. } => match body {
                crate::ast::ClosureBody::Expr(e) => self.walk_expr(e, scope, errors),
                crate::ast::ClosureBody::Block(b) => self.walk_block(b, scope, errors),
            },
            ExprKind::ClosureFull(sb) => match &sb.body {
                FnBody::Expr(e) => self.walk_expr(e, scope, errors),
                FnBody::Block(b) => self.walk_block(b, scope, errors),
                FnBody::External => {}
            },
            ExprKind::Spawn(body) => self.walk_expr(body, scope, errors),
            ExprKind::Detach(body) | ExprKind::Blocking(body) => self.walk_block(body, scope, errors),
            ExprKind::Supervised { body, cancel } => {
                if let Some(c) = cancel { self.walk_expr(c, scope, errors); }
                self.walk_block(body, scope, errors);
            }
            ExprKind::Forbid { body, .. } => self.walk_block(body, scope, errors),
            ExprKind::Realtime { body, .. } => self.walk_block(body, scope, errors),
            ExprKind::ParallelFor { iter, body, .. } => {
                self.walk_expr(iter, scope, errors);
                self.walk_block(body, scope, errors);
            }
            ExprKind::For { iter, body, .. } => {
                self.walk_expr(iter, scope, errors);
                self.walk_block(body, scope, errors);
            }
            ExprKind::While { cond, body, .. } => {
                self.walk_expr(cond, scope, errors);
                self.walk_block(body, scope, errors);
            }
            ExprKind::WhileLet { scrutinee, body, .. } => {
                self.walk_expr(scrutinee, scope, errors);
                self.walk_block(body, scope, errors);
            }
            ExprKind::Loop { body, .. } => self.walk_block(body, scope, errors),
            ExprKind::Select { arms } => {
                for arm in arms {
                    match &arm.op {
                        SelectOp::Recv { chan, .. } => self.walk_expr(chan, scope, errors),
                        SelectOp::Send { chan, value } => {
                            self.walk_expr(chan, scope, errors);
                            self.walk_expr(value, scope, errors);
                        }
                        SelectOp::Default => {}
                    }
                    if let Some(g) = &arm.guard { self.walk_expr(g, scope, errors); }
                    self.walk_block(&arm.body, scope, errors);
                }
            }
            ExprKind::Range { start, end, .. } => {
                if let Some(s) = start { self.walk_expr(s, scope, errors); }
                if let Some(e) = end { self.walk_expr(e, scope, errors); }
            }
            ExprKind::Throw(e) => self.walk_expr(e, scope, errors),
            ExprKind::Interrupt(opt) => {
                if let Some(e) = opt { self.walk_expr(e, scope, errors); }
            }
            ExprKind::With { body, .. } => self.walk_block(body, scope, errors),
            // D.1.3: квантор — только в контрактах; обходим range и body.
            ExprKind::Forall { range, body, .. } | ExprKind::Exists { range, body, .. } => {
                self.walk_expr(range, scope, errors);
                self.walk_expr(body, scope, errors);
            }
            // Plan 97 Ф.4 (D142): protocol-литерал — structural-check
            // относительно объявленного протокола (instance-only).
            ExprKind::ProtocolLit { proto_name, methods } => {
                self.check_protocol_lit(proto_name, methods, e.span, errors);
            }
            // Литералы / ident'ы / handler-литералы — без рекурсии в bound-проверке.
            ExprKind::IntLit(_) | ExprKind::FloatLit(_) | ExprKind::BoolLit(_)
            | ExprKind::StrLit(_) | ExprKind::CharLit(_) | ExprKind::UnitLit
            | ExprKind::NullPtrLit
            | ExprKind::Ident(_) | ExprKind::Path(_) | ExprKind::SelfAccess
            | ExprKind::HandlerLit { .. } => {}
        }
    }

    /// Plan 97 Ф.4 (D142): структурная проверка protocol-литерала.
    ///
    /// 1. Resolve `proto_name` в registered protocol через `protocol_specs`.
    ///    Если не найден — error (unknown protocol).
    /// 2. Каждый impl-метод должен соответствовать **instance**-методу
    ///    протокола (по имени + arity). Реализация **static**-метода
    ///    (декларированного с `.method`) в protocol-литерале запрещена
    ///    (static — `Type.method` D35, у литерала нет «своего типа»).
    /// 3. Каждый instance-метод протокола должен быть реализован — иначе
    ///    «missing method» error.
    fn check_protocol_lit(
        &self,
        proto_name: &[String],
        methods: &[HandlerMethod],
        span: Span,
        errors: &mut Vec<Diagnostic>,
    ) {
        let name = match proto_name.last() {
            Some(n) => n.clone(),
            None => return,
        };
        let Some(spec_methods) = self.protocol_specs.get(&name) else {
            // Unknown protocol — diagnostic с hint'ом про D142.
            // Permissive если effect (effect-литерал, не protocol-литерал).
            if !self.effect_decls.contains_key(&name) {
                errors.push(Diagnostic::new(
                    format!(
                        "unknown protocol `{}` in protocol-literal — must be a declared \
                         `type {} protocol {{ ... }}` (D142 / Plan 97 Ф.4). \
                         If you meant an effect-literal, use `effect {} {{ ... }}` instead.",
                        name, name, name),
                    span,
                ));
            }
            return;
        };
        // Static-method-impl rejection (Ф.4.3).
        for spec_m in spec_methods.iter() {
            if spec_m.is_static {
                // Если literal реализует static-метод (по имени), diagnostic.
                if methods.iter().any(|im| im.name == spec_m.name) {
                    errors.push(Diagnostic::new(
                        format!(
                            "static method `.{}` cannot be implemented in protocol-literal \
                             — static methods belong to a type (D35: `fn Type.{}(...)`), \
                             not to an instance. Declare a named `type Impl {{ ... }}` with \
                             `fn Impl.{}(...)` and pass an instance of `Impl` instead.",
                            spec_m.name, spec_m.name, spec_m.name),
                        span,
                    ));
                }
            }
        }
        // Structural-match: каждый instance-метод протокола должен быть реализован.
        let mut missing: Vec<String> = Vec::new();
        for spec_m in spec_methods.iter() {
            if spec_m.is_static {
                continue;
            }
            let found = methods.iter().any(|im|
                im.name == spec_m.name && im.params.len() == spec_m.params.len());
            if !found {
                missing.push(format!(
                    "{}({})",
                    spec_m.name,
                    spec_m.params.iter().map(|p| p.name.clone()).collect::<Vec<_>>().join(", ")));
            }
        }
        if !missing.is_empty() {
            errors.push(Diagnostic::new(
                format!(
                    "protocol-literal `protocol {} {{ ... }}` is missing required instance methods: {}. \
                     The protocol contract declared `{}` requires every instance method to be \
                     implemented (D142 / Plan 97 Ф.4 structural conformance).",
                    name, missing.join(", "), name),
                span,
            ));
        }
        // Extra-method warning: реализация unknown-имени.
        for im in methods {
            let in_proto = spec_methods.iter().any(|s| s.name == im.name);
            if !in_proto {
                errors.push(Diagnostic::new(
                    format!(
                        "protocol-literal implements method `{}` not declared in protocol `{}` \
                         (D142 / Plan 97 Ф.4). Method names must match the contract.",
                        im.name, name),
                    im.span,
                ));
            }
        }
    }

    /// Plan 97.1 hardening (D142): Nova-side enforcement для
    /// `obj.method(args)` где `obj` — переменная типа named protocol.
    /// Метод должен быть в `protocol_specs[<Proto>]`; иначе compile error
    /// (раньше эта ошибка ловилась только на C-side как
    /// `no member named 'X' in struct NovaVtable_<Proto>`).
    ///
    /// Закрывает silent miscompile риск для пользовательской опечатки
    /// `l.nonexistent()` на protocol-typed value.
    fn check_protocol_method_call(
        &self,
        e: &Expr,
        scope: &HashMap<String, TypeRef>,
        errors: &mut Vec<Diagnostic>,
    ) {
        let ExprKind::Call { func, .. } = &e.kind else { return; };
        // Снять turbofish если есть.
        let func = match &func.kind {
            ExprKind::TurboFish { base, .. } => base.as_ref(),
            _ => func.as_ref(),
        };
        let (obj, method_name, member_span) = match &func.kind {
            ExprKind::Member { obj, name } => (obj.as_ref(), name.clone(), func.span),
            _ => return,
        };
        // Resolve obj-тип через scope (только для простых Ident'ов; deeper
        // resolution — это задача codegen-уровня inference).
        let obj_ty = match &obj.kind {
            ExprKind::Ident(n) => match scope.get(n) {
                Some(t) => t.clone(),
                None => return,
            },
            _ => return,
        };
        // Extract protocol-name (named type, не generic-bound here).
        let proto_name = match &obj_ty {
            TypeRef::Named { path, generics, .. }
                if generics.is_empty() && path.len() == 1 =>
            {
                path[0].clone()
            }
            _ => return,
        };
        // Skip non-protocol type bindings.
        let Some(spec_methods) = self.protocol_specs.get(&proto_name) else { return; };
        // Method обязан быть в protocol-spec.
        let known: bool = spec_methods.iter().any(|m| m.name == method_name);
        if known { return; }
        // Compose listing of known methods для R5.3 hint.
        let known_methods: Vec<String> = spec_methods.iter().map(|m| m.name.clone()).collect();
        let listing = if known_methods.is_empty() {
            "<no methods>".to_string()
        } else {
            known_methods.join(", ")
        };
        errors.push(Diagnostic::new(
            format!(
                "unknown method `.{}()` on protocol-typed value (declared protocol `{}` \
                 has no such method). Declared methods: [{}].\n  \
                 fix: rename call to one of the declared methods, or add `{}` to the protocol \
                 declaration (`type {} protocol {{ ... }}`).\n  \
                 (Plan 97.1 hardening — D142 / [M-protocol-method-name-shadowing] enforcement.)",
                method_name, proto_name, listing, method_name, proto_name),
            member_span,
        ));
    }

    /// Plan 15 Ф.3: проверить bound'ы на конкретном call-site.
    ///
    /// Если callee — top-level fn с generics+bounds, и есть turbofish
    /// type_args (или возможна простая inference из args) — проверить
    /// что concrete-T удовлетворяет bound'у.
    fn check_call_bounds(
        &self,
        e: &Expr,
        scope: &HashMap<String, TypeRef>,
        errors: &mut Vec<Diagnostic>,
    ) {
        let ExprKind::Call { func, args, .. } = &e.kind else { return; };
        // Распакуем turbofish, чтобы добраться до базового идентификатора.
        let (base, type_args): (&Expr, &[TypeRef]) = match &func.kind {
            ExprKind::TurboFish { base, type_args } => (base, type_args.as_slice()),
            _ => (func.as_ref(), &[][..]),
        };
        // Plan 101.2 (D145 Ред. 5): method-call bound enforcement.
        // `xs.desc()` где xs : []NoShow, desc объявлен как
        // `fn[T Showable_] []T @desc`. Подставить T = NoShow,
        // проверить satisfaction. Раньше check_call_bounds работал
        // только для free-fn call'ов — method-dispatch with bounded
        // receiver-generic не enforce'ился.
        if let ExprKind::Member { obj, name: method_name } = &base.kind {
            self.check_method_call_bounds(obj, method_name, e.span, scope, errors);
            return;
        }
        let fn_name = match &base.kind {
            ExprKind::Ident(n) => n.clone(),
            _ => return,
        };
        // D84: fn_decls — Vec<&FnDecl>. Резолв overload по arity (то, что
        // bound-checker может определить без full type-inference).
        // Если несколько overloads подходят по arity — bound-checker не
        // делает разрешение (это работа codegen, у которого есть type-info).
        // Bound-проверка пропускается; codegen ловит ambiguity на своём
        // уровне.
        let Some(overloads) = self.sig.fn_decls.get(&fn_name) else { return; };
        let arity_matches: Vec<&&FnDecl> = overloads.iter()
            .filter(|f| f.params.len() == args.len())
            .collect();
        let callee: &FnDecl = match arity_matches.as_slice() {
            [single] => *single,
            _ => return, // нет однозначной overload по arity — пропускаем
        };
        // Bounds присутствуют?
        let has_bounds = callee.generics.iter().any(|g| !g.bounds.is_empty());
        if !has_bounds { return; }
        // Сматчим concrete T. Стратегия:
        //   - turbofish — explicit type_args[i] для callee.generics[i].
        //   - иначе simple inference: для каждого param с TypeRef::Named{path:[T]}
        //     где T — generic-param, тип arg'а на той же позиции = concrete T.
        let mut bindings: HashMap<String, TypeRef> = HashMap::new();
        if !type_args.is_empty() {
            for (i, gp) in callee.generics.iter().enumerate() {
                if let Some(t) = type_args.get(i) {
                    bindings.insert(gp.name.clone(), t.clone());
                }
            }
        } else {
            // Simple inference из позиционных args.
            for (i, param) in callee.params.iter().enumerate() {
                let Some(call_arg) = args.get(i) else { continue; };
                let arg_expr = call_arg.expr();
                if let Some(t_name) = Self::param_generic_name(&param.ty, &callee.generics) {
                    if let Some(arg_ty) = Self::infer_arg_ty(arg_expr, scope) {
                        bindings.entry(t_name).or_insert(arg_ty);
                    }
                }
            }
        }
        // Для каждого bounded generic — проверить.
        // Plan 101.3: multi-bound `[T A + B]` — ALL bounds должны быть
        // satisfied (conjunction). check_satisfaction вызывается на
        // каждом bound отдельно — каждый missing-метод выдаст diagnostic.
        for gp in &callee.generics {
            if gp.bounds.is_empty() { continue; }
            let Some(concrete) = bindings.get(&gp.name) else {
                // Inference не удалась — пропускаем (best-effort).
                // Strict-mode мог бы требовать explicit turbofish.
                continue;
            };
            for bound in &gp.bounds {
                self.check_satisfaction(
                    concrete, bound, &gp.name, &fn_name, e.span, errors,
                );
            }
        }
    }

    /// Plan 101.2 (D145 Ред. 5): bound enforcement для method-call
    /// `obj.method(args)` где method объявлен с receiver-generic prefix
    /// `fn[T Bound] []T @method` (или `fn[T Bound] T @method`). Inferим
    /// concrete T из obj-type, для каждого bound checking satisfaction.
    ///
    /// **Surface**: только `fn[T] []T @method` (array-receiver) и
    /// `fn[T] T @method` (bare-T receiver) — Plan 101.1 формы.
    /// Tuple/Func/Map receivers — followup (V2 если нужно).
    ///
    /// **Best-effort**: если obj-type не resolvable или method
    /// неоднозначен по arity — skip (silent, как и check_call_bounds
    /// для free-fn'ов; codegen/runtime поймает на своём уровне).
    fn check_method_call_bounds(
        &self,
        obj: &Expr,
        method_name: &str,
        span: Span,
        scope: &HashMap<String, TypeRef>,
        errors: &mut Vec<Diagnostic>,
    ) {
        // Inferим obj-type.
        let Some(obj_ty) = Self::infer_arg_ty(obj, scope) else { return; };
        // Определяем receiver-key и concrete substitution для T.
        // Plan 101 surface:
        //   []T  → key = "[]T", T = element type.
        //   T    → key = "T",   T = obj-type whole (bare-receiver).
        let (recv_key, concrete_t): (&str, TypeRef) = match &obj_ty {
            TypeRef::Array(inner, _) => ("[]T", (**inner).clone()),
            TypeRef::Named { path, .. } if path.last().map(|s| s.len()).unwrap_or(0) == 1 => {
                // Bare-T receiver `fn[T] T @method` — но obj должен быть
                // конкретным single-name type. Слишком permissive — skip
                // если просто `[T]` без method_table-entry. Лучше: дождаться
                // method-table lookup и если нашлось — substitute.
                ("T", obj_ty.clone())
            }
            _ => return, // Non-array, non-single-name — skip.
        };
        // Lookup methods под этим receiver-key.
        let Some(methods_for_recv) = self.sig.method_table.get(recv_key) else { return; };
        let Some(overloads) = methods_for_recv.get(method_name) else { return; };
        // Take single match (skip if multiple overloads — codegen разрулит).
        let callee: &FnDecl = match overloads.as_slice() {
            [single] => single,
            _ => return,
        };
        // Bounded generic-параметры?
        if !callee.generics.iter().any(|g| !g.bounds.is_empty()) { return; }
        // Substitution: для каждого generic-param с тем же именем что
        // в receiver-type (T в []T или T в bare-T) — concrete_t. Для
        // method-level generics (U, V, ...) — skip (нужен type-inference
        // из args, что выходит за scope этого smoke check'а).
        for gp in &callee.generics {
            if gp.bounds.is_empty() { continue; }
            // Только T matches receiver-substitution.
            // Для recv_key="[]T" мы знаем что receiver-T это первый
            // generic prefix (parser кладёт его первым). Для bare-T
            // тоже первый. Substitute concrete_t для gp.name если он
            // первый prefix-generic; для остальных — skip.
            if callee.generics.first().map(|g| &g.name) != Some(&gp.name) {
                continue;
            }
            for bound in &gp.bounds {
                self.check_satisfaction(
                    &concrete_t, bound, &gp.name, method_name, span, errors,
                );
            }
        }
    }

    /// Plan 46 (D102): проверить argument binding на call-site.
    /// Резолвит callee (free fn / static-method по Path), сопоставляет
    /// позиционные + именованные аргументы с параметрами через
    /// `argbind::bind_call_args`, эмитит diagnostics.
    ///
    /// Резолв best-effort: если callee неоднозначен (overload по arity)
    /// или не резолвится (instance-method через Member — нужен тип obj) —
    /// проверка пропускается (codegen поймает на своём уровне).
    fn check_call_argbind(
        &self,
        e: &Expr,
        scope: &HashMap<String, TypeRef>,
        errors: &mut Vec<Diagnostic>,
    ) {
        let ExprKind::Call { func, args, trailing } = &e.kind else { return; };
        // Распакуем turbofish до базового func-expr.
        let base: &Expr = match &func.kind {
            ExprKind::TurboFish { base, .. } => base,
            _ => func.as_ref(),
        };
        // Резолвим callee → список параметров.
        let callee_params: &[Param] = match &base.kind {
            ExprKind::Ident(name) => {
                // Plan 153 fix (regression from vec `resize_with`/`fill_with`,
                // 2026-06-14): a LOCAL binding named `name` — in particular a
                // closure parameter like `f fn() -> T` — SHADOWS a module-level
                // free function of the same name. Without this guard, `f()`
                // inside such a method resolved to a free `fn f(x int)` from the
                // *entry* module (e.g. a `contracts` test that happens to define
                // `fn f`), and arg-checking the closure call against the free
                // fn's params raised a spurious `обязательный параметр не передан`.
                // The closure call is validated via the var's fn-type / codegen,
                // so skip the free-fn arg-check entirely when shadowed.
                if scope.contains_key(name) { return; }
                let Some(overloads) = self.sig.fn_decls.get(name) else { return; };
                match overloads.as_slice() {
                    [single] => &single.params,
                    _ => return, // overload — пропускаем (D102: нет overload,
                                 // но bootstrap fn_decls может иметь несколько).
                }
            }
            ExprKind::Path(parts) if parts.len() == 2 => {
                // `Type.method` — static-method резолв.
                let Some(methods) = self.sig.method_table.get(&parts[0]) else { return; };
                let Some(overloads) = methods.get(&parts[1]) else { return; };
                match overloads.as_slice() {
                    [single] => &single.params,
                    _ => return,
                }
            }
            // Plan 46 Ф.3 + Plan 50 follow-up: instance-method `obj.method(...)`.
            // Первая попытка — receiver-type inference (best-effort через
            // `infer_arg_ty`): если тип `obj` известен (Ident в scope,
            // record-литерал, литерал-примитив) — точный резолв
            // `method_table[type][method]`. Закрывает gap при collision
            // имён методов: `Box.scaled` vs `Cube.scaled` с дефолтами
            // больше не пропускает keyword-only диагностику.
            // Fallback — name-only резолв (как было в Plan 46): уникальное
            // имя метода через все типы. Для остальных случаев codegen
            // резолвит через type-info.
            ExprKind::Member { obj, name: method_name } => {
                let resolved = self.resolve_instance_method(obj, method_name, scope, args.len());
                match resolved {
                    Some(f) => &f.params,
                    None => return,
                }
            }
            _ => return,
        };
        // Plan 46 Ф.3: trailing-форма (D43) связывает ПОСЛЕДНРЙ
        // функциональный параметр. Bind'аем против params без него.
        // Также: если named-arg назван как trailing-bound param — это
        // double-bind (ловится ниже отдельно).
        let trailing_present = trailing.is_some();
        let effective_params: &[Param] = if trailing_present && !callee_params.is_empty() {
            // Проверка: named-arg для trailing-bound параметра — error.
            let last = &callee_params[callee_params.len() - 1];
            for a in args.iter() {
                if a.arg_name() == Some(last.name.as_str()) {
                    errors.push(Diagnostic::new(
                        format!(
                            "параметр `{}` связан и trailing-формой, и именованным \
                             аргументом (D102)",
                            last.name
                        ),
                        a.expr().span,
                    ));
                    return;
                }
            }
            &callee_params[..callee_params.len() - 1]
        } else {
            callee_params
        };
        // Запускаем binding. Ошибка → diagnostic.
        //
        // Precedence (Plan 50): структурные ошибки argbind — арность,
        // неизвестное имя, двойная привязка, позиционный-после-именованного
        // — fail-fast в `bind_call_args` и эмитятся первыми. Правило
        // keyword-only (Plan 50, D102 №1) проверяется ТОЛЬКО когда
        // структура валидна (`Ok(bindings)`) — оно последнее в порядке
        // диагностик.
        match crate::argbind::bind_call_args(effective_params, args) {
            Err(err) => {
                let span = {
                    let s = err.span();
                    if s == crate::diag::Span::dummy() { e.span } else { s }
                };
                errors.push(Diagnostic::new(err.message(), span));
            }
            Ok(bindings) => {
                // Plan 50 (D102 ревизия): параметр с дефолтом — keyword-only.
                // Позиционная привязка к дефолтному параметру — ошибка.
                // Trailing-форма исключена структурно: trailing-bound
                // параметр уже снят из `effective_params` выше, поэтому
                // в `bindings` его нет — заполнение дефолтного последнего
                // параметра trailing-формой не считается нарушением.
                //
                // Отдельная диагностика на КАЖДЫЙ нарушающий аргумент
                // (не «первый и стоп») — error recovery без каскада:
                // просто продолжаем цикл.
                self.check_keyword_only(effective_params, args, &bindings, errors);
            }
        }
    }

    /// Plan 50 (D102 №1): после успешного argbind — найти позиционные
    /// аргументы, легшие на параметры с дефолтом, и эмитить production-grade
    /// диагностику на каждый (имя параметра, `note: declared here`,
    /// machine-applicable structured suggestion `name: <expr>`).
    fn check_keyword_only(
        &self,
        effective_params: &[Param],
        args: &[CallArg],
        bindings: &[crate::argbind::ArgBinding],
        errors: &mut Vec<Diagnostic>,
    ) {
        use crate::argbind::ArgBinding;
        use crate::diag::{Applicability, Span, Suggestion};
        for (pi, binding) in bindings.iter().enumerate() {
            let ArgBinding::Positional(ai) = binding else { continue; };
            let param = &effective_params[pi];
            if param.default.is_none() {
                continue;
            }
            // Нарушение: позиционный аргумент `args[*ai]` лёг на
            // дефолтный параметр `param`.
            let arg_span = args[*ai].expr().span;
            // Structured suggestion — чистая ВСТАВКА `<name>: ` в начале
            // выражения-аргумента (span нулевой ширины). Source-независимо:
            // producer не читает исходник. Machine-applicable — edit
            // корректен и авто-применим (`nova fix` / LSP code-action).
            let insert_at = Span::with_file(arg_span.start, arg_span.start, arg_span.file_id);
            let suggestion = Suggestion {
                message: format!("pass `{}` by name", param.name),
                span: insert_at,
                replacement: format!("{}: ", param.name),
                applicability: Applicability::MachineApplicable,
            };
            let diag = Diagnostic::new(
                format!(
                    "параметр `{}` имеет значение по умолчанию — \
                     передаётся только по имени (D102)",
                    param.name,
                ),
                arg_span,
            )
            .with_note_at(
                format!("параметр `{}` объявлен здесь", param.name),
                param.span,
            )
            .with_note(
                "параметры с дефолтом — keyword-only: обязательный — \
                 позиционно, опциональный — по имени",
            )
            .with_suggestion(suggestion);
            errors.push(diag);
        }
    }

    /// Plan 53: refutability check для `let`-pattern. Допустимы только
    /// irrefutable patterns:
    /// - `Ident`, `Wildcard`
    /// - `Tuple(pats)` — рекурсивно irrefutable
    /// - `Record` без type_path РЛР с type_path к record-типу (не
    ///   sum-variant) — рекурсивно irrefutable для под-pattern'ов
    /// - `Binding { inner, .. }` — inner irrefutable
    ///
    /// Refutable (compile error):
    /// - `Literal`, `Variant`, `Or`, `Array` (всегда refutable)
    /// - `Record` с type_path к sum-variant (нужен tag-check в runtime)
    ///
    /// Production-grade diagnostic: тип нарушения + подсказка `if let
    /// <pat> = <expr> { ... }` / `match`.
    fn check_let_pattern_irrefutable(&self, pat: &Pattern, errors: &mut Vec<Diagnostic>) {
        match pat {
            Pattern::Ident { .. } | Pattern::Wildcard(_) => {}
            Pattern::Tuple(pats, _) => {
                for p in pats {
                    self.check_let_pattern_irrefutable(p, errors);
                }
            }
            Pattern::Record { type_path, fields, span, .. } => {
                // Sum-variant in type_path — refutable.
                if let Some(path) = type_path {
                    if let Some(last) = path.last() {
                        if self.sum_variant_names.contains(last) {
                            let path_str = path.join(".");
                            errors.push(
                                Diagnostic::new(
                                    format!(
                                        "refutable pattern in `let`: `{}` is a sum-variant — \
                                         match is not statically guaranteed (D52). Use \
                                         `if let` or `match` instead.",
                                        path_str,
                                    ),
                                    *span,
                                )
                                .with_note(
                                    "Plan 53: `let` accepts only irrefutable patterns (Ident, \
                                     Wildcard, Tuple, plain-Record). Sum-variants need a \
                                     runtime tag-check — `let` cannot perform it.",
                                )
                                .with_note(
                                    format!(
                                        "example: `if let {} {{ ... }} = <expr> {{ ... }}`",
                                        path_str,
                                    ),
                                ),
                            );
                            return;
                        }
                    }
                }
                // Recurse into sub-patterns of fields.
                for f in fields {
                    if let Some(sub) = &f.pattern {
                        self.check_let_pattern_irrefutable(sub, errors);
                    }
                }
            }
            Pattern::Binding { inner, .. } => {
                self.check_let_pattern_irrefutable(inner, errors);
            }
            Pattern::Literal(_, span) => {
                errors.push(
                    Diagnostic::new(
                        "refutable pattern in `let`: literal match is not statically \
                         guaranteed. Use `if let` / `match`, or a plain \
                         `let x = ...; if x == ...`",
                        *span,
                    )
                    .with_note(
                        "example: `if let 42 = n { ... }` or `let x = n; if x == 42 { ... }`",
                    ),
                );
            }
            Pattern::Variant { path, span, .. } => {
                let path_str = path.join(".");
                errors.push(
                    Diagnostic::new(
                        format!(
                            "refutable pattern in `let`: `{}` is a variant-pattern — \
                             match is not statically guaranteed (D52/D59). Use `if let` \
                             or `match` instead.",
                            path_str,
                        ),
                        *span,
                    )
                    .with_note(
                        "Plan 53: variant-patterns need a runtime tag-check — `let` \
                         guarantees binding, not a fallible match.",
                    )
                    .with_note(
                        format!(
                            "example: `if let {}(..) = <expr> {{ ... }}`",
                            path_str,
                        ),
                    ),
                );
            }
            Pattern::Or { span, .. } => {
                errors.push(
                    Diagnostic::new(
                        "refutable pattern in `let`: alternation `|` is not statically \
                         guaranteed to match. Use `if let` / `match`.",
                        *span,
                    )
                    .with_note(
                        "example: `match x { A | B => ..., _ => ... }`",
                    ),
                );
            }
            Pattern::Array { span, .. } => {
                errors.push(
                    Diagnostic::new(
                        "refutable pattern in `let`: array length is not statically \
                         guaranteed. Use `if let` / `match`, or index/length checks \
                         like `xs[0]`, `xs.len`.",
                        *span,
                    )
                    .with_note(
                        "example: `if let [a, b, c] = xs { ... } else { /* handle */ }` \
                         or `match xs { [a, b, c] => ..., _ => ... }`",
                    )
                    .with_note(
                        "Plan 53: array-length is checked at runtime — `let` accepts \
                         only statically-guaranteed patterns.",
                    ),
                );
            }
        }
    }

    /// Plan 50 follow-up: резолв `obj.method` для argbind-диагностик.
    ///
    /// Сначала best-effort receiver-type inference через `infer_arg_ty`
    /// — если тип `obj` известен (Ident в scope / record-литерал /
    /// литерал-примитив), точный резолв через `method_table[type][name]`.
    /// Это закрывает gap при коллизии имён методов между типами
    /// (`Box.scaled` vs `Cube.scaled` с дефолтами): без inference оба
    /// попадали в name-only поиск, тот видел >1 sig → ambiguous → skip,
    /// keyword-only диагностика терялась.
    ///
    /// Fallback — name-only через все типы (поведение Plan 46): подходит
    /// когда тип receiver'а не выводим (сложное выражение / generic).
    /// Уникальное имя метода → один тип → один sig → используем его.
    /// Рначе — пропускаем, codegen резолвит через type-info.
    fn resolve_instance_method(
        &self,
        obj: &Expr,
        method_name: &str,
        scope: &HashMap<String, TypeRef>,
        arg_count_hint: usize,
    ) -> Option<&FnDecl> {
        // Попытка 1: receiver-type inference.
        // Plan 162 Ф.3: когда тип receiver'а известен, сначала проверяем
        // наследуемые (inherent) методы — методы, объявленные в том же модуле
        // что и тип T. Inherent методы доступны без явного import модуля-метода:
        // при импорте типа T все его inherent методы автоматически доступны
        // (они слиты в merged module.items). Это позволяет вызывать foo.greet()
        // даже если пользователь импортировал только тип Foo, а не модуль методов.
        if let Some(recv_ty) = Self::infer_arg_ty(obj, scope) {
            if let TypeRef::Named { path, .. } = &recv_ty {
                if path.len() == 1 {
                    let type_name = &path[0];
                    if let Some(methods) = self.sig.method_table.get(type_name) {
                        if let Some(overloads) = methods.get(method_name) {
                            // Plan 162 Ф.3: prefer inherent overloads over
                            // extension overloads when receiver type is known.
                            // Inherent = declared in same module as the type.
                            let inherent: Vec<&&FnDecl> = overloads
                                .iter()
                                .filter(|f| {
                                    self.is_inherent_method(type_name, &f.name)
                                })
                                .collect();
                            let candidates = if !inherent.is_empty() {
                                &inherent[..] as &[&&FnDecl]
                            } else {
                                // All overloads (extension or unknown origin).
                                // Wrap to match type; use slice of all overloads.
                                // SAFETY: overloads is Vec<&FnDecl>; inherent is
                                // empty so fall back to non-inherent branch below.
                                &[][..]
                            };
                            if let [single] = candidates {
                                return Some(single);
                            }
                            // Either 0 inherent (all extension) or >1 inherent
                            // (overloaded inherent). Fall through to non-inherent
                            // single-overload path.
                            if let [single] = overloads.as_slice() {
                                return Some(single);
                            }
                        }
                    }
                }
            }
        }
        // Попытка 2: name-only fallback. Уникальное имя метода через
        // все типы → один sig, используем.
        // Plan 109: фильтр по arity предотвращает ложные "expected 0, got N"
        // когда builtin-метод ([]T::push и т.п.) отсутствует в method_table,
        // но пользовательский тип случайно имеет метод с тем же именем.
        // Plan 162 Ф.3: в name-only поиске inherent-методы приоритетны при
        // неоднозначности (два типа → один inherent → один extension).
        let mut found_inherent: Option<&FnDecl> = None;
        let mut found: Option<&FnDecl> = None;
        let mut ambiguous_inherent = false;
        let mut ambiguous = false;
        for (type_name, methods) in &self.sig.method_table {
            if let Some(overloads) = methods.get(method_name) {
                for f in overloads {
                    if f.params.len() != arg_count_hint { continue; }
                    let inherent = self.is_inherent_method(type_name, &f.name);
                    if inherent {
                        if found_inherent.is_some() {
                            ambiguous_inherent = true;
                        }
                        found_inherent = Some(f);
                    } else {
                        if found.is_some() {
                            ambiguous = true;
                        }
                        found = Some(f);
                    }
                }
            }
        }
        // Return inherent if unambiguous; otherwise fall back to extension if
        // unambiguous; otherwise return None (ambiguous → codegen resolves).
        if !ambiguous_inherent {
            if let Some(f) = found_inherent {
                return Some(f);
            }
        }
        if ambiguous { return None; }
        found
    }

    /// Если param's TypeRef — простой `Named{path: [T]}` где T в
    /// списке generics, вернуть имя T. Рначе None.
    fn param_generic_name(ty: &TypeRef, generics: &[GenericParam]) -> Option<String> {
        let TypeRef::Named { path, generics: g, .. } = ty else { return None; };
        if path.len() != 1 || !g.is_empty() { return None; }
        if generics.iter().any(|gp| gp.name == path[0]) {
            Some(path[0].clone())
        } else {
            None
        }
    }

    /// Минимальная inference типа argument'а — best-effort на основе
    /// синтаксической формы и текущего scope (let-bindings).
    fn infer_arg_ty(e: &Expr, scope: &HashMap<String, TypeRef>) -> Option<TypeRef> {
        match &e.kind {
            ExprKind::Ident(name) => scope.get(name).cloned(),
            // Plan 97.1 hardening (D142): protocol-литерал имеет тип
            // именованного protocol'а — это позволяет let-binding
            // получить корректный тип в scope (для последующего
            // check_protocol_method_call enforcement'а).
            ExprKind::ProtocolLit { proto_name, .. } => Some(TypeRef::Named {
                path: proto_name.clone(),
                generics: Vec::new(),
                span: e.span,
            }),
            ExprKind::RecordLit { type_name: Some(name), .. } => Some(TypeRef::Named {
                path: name.clone(),
                generics: Vec::new(),
                span: e.span,
            }),
            ExprKind::ArrayLit(elems) => {
                // []T — element type from first element.
                let inner = elems.iter().find_map(|el| match el {
                    ArrayElem::Item(it) | ArrayElem::Spread(it) => Self::infer_arg_ty(it, scope),
                });
                inner.map(|t| TypeRef::Array(Box::new(t), e.span))
            }
            ExprKind::IntLit(_) => Some(TypeRef::Named {
                path: vec!["int".to_string()], generics: vec![], span: e.span }),
            ExprKind::FloatLit(_) => Some(TypeRef::Named {
                path: vec!["f64".to_string()], generics: vec![], span: e.span }),
            ExprKind::BoolLit(_) => Some(TypeRef::Named {
                path: vec!["bool".to_string()], generics: vec![], span: e.span }),
            ExprKind::StrLit(_) | ExprKind::InterpolatedStr { .. } => Some(TypeRef::Named {
                path: vec!["str".to_string()], generics: vec![], span: e.span }),
            ExprKind::CharLit(_) => Some(TypeRef::Named {
                path: vec!["char".to_string()], generics: vec![], span: e.span }),
            _ => None,
        }
    }

    /// Plan 15 Ф.3: проверить, что concrete-тип удовлетворяет bound'у
    /// (protocol-типу). При несоответствии — R5.3 diagnostic.
    ///
    /// Plan 97 Ф.2 (D142): bound может быть **анонимным** inline-protocol
    /// (`[T protocol { method-sig* }]`) — методы проверяются «по месту»
    /// без регистрации в `protocol_specs`. Закрывает Plan 15
    /// `[P-15-anon-protocol-bound]`.
    fn check_satisfaction(
        &self,
        concrete: &TypeRef,
        bound: &TypeRef,
        type_param_name: &str,
        fn_name: &str,
        span: Span,
        errors: &mut Vec<Diagnostic>,
    ) {
        // Plan 97 Ф.2: inline-protocol bound — методы прямо в TypeRef.
        if let TypeRef::Protocol { methods, .. } = bound {
            self.check_satisfaction_against_methods(
                concrete,
                methods,
                None, // anon — нет имени
                type_param_name,
                fn_name,
                span,
                errors,
            );
            return;
        }
        let bound_name = match bound {
            TypeRef::Named { path, .. } if path.len() == 1 => path[0].clone(),
            _ => return, // complex bounds (Hashable[K], etc.) — отдельная задача
        };
        // Plan 15 D53 strict: bound должен быть protocol-kind. Если
        // имя зарегистрировано как effect-kind — это spec violation
        // (D72: bounds require protocols). R5.3-style diagnostic.
        if let Some(eff_decl) = self.effect_decls.get(&bound_name) {
            let _ = eff_decl;
            errors.push(Diagnostic::new(
                format!(
                    "type `{}` is an effect, not a protocol — generic bounds \
                     require protocol-types (D72/D53). Hint: declare `{}` as \
                     `type {} protocol {{ ... }}` if structural-contract semantics \
                     is intended; effects are runtime-dispatched capabilities and \
                     can only appear in effect-rows `(...) {} -> ...`, not as \
                     `[T {}]` bounds.",
                    bound_name, bound_name, bound_name, bound_name, bound_name,
                ),
                span,
            ));
            return;
        }
        let concrete_name = match concrete {
            TypeRef::Named { path, .. } if path.len() == 1 => path[0].clone(),
            // Plan 138.1 Ф.1 (D239): `[]T` ≡ `Vec[T]` — align the array
            // receiver with the Vec named type so bound-resolution checks
            // Vec's method_table (iter/next/len/...). Without this, `[]T`
            // passed where an `Iter`-bound type-param is expected would be
            // silently skipped; now it genuinely satisfies via Vec's methods.
            TypeRef::Array(_, _) => "Vec".to_string(),
            // Tuple/Func — пока пропускаем (не обрабатываем составные T).
            _ => return,
        };
        // Built-in primitives автоматически удовлетворяют ничему — у нас
        // нет registry их методов в method_table. Skip (best-effort).
        if matches!(concrete_name.as_str(),
            "int" | "i8" | "i16" | "i32" | "i64"
            | "u8" | "u16" | "u32" | "u64"
            | "f32" | "f64" | "bool" | "char"
            // Plan 76: `never` — bottom-тип, vacuously удовлетворяет любому bound.
            | "str" | "any" | "never") {
            return;
        }
        let Some(spec_methods) = self.protocol_specs.get(&bound_name) else {
            // Bound — не зарегистрирован ни как protocol, ни как effect.
            // Может быть type alias / record / unknown. Пока пропускаем —
            // formal check'а не делаем (best-effort permissive).
            return;
        };
        // Plan 97 Ф.2: shared satisfaction-логика с anon-вариантом.
        self.check_satisfaction_against_methods(
            concrete,
            spec_methods.as_slice(),
            Some(&bound_name),
            type_param_name,
            fn_name,
            span,
            errors,
        );
    }

    /// Plan 97 Ф.2 (D142): общая satisfaction-логика для named и anonymous
    /// protocol-bound'ов. `bound_name = Some(...)` — named (показывается
    /// в diagnostic); `None` — inline `[T protocol { ... }]`, рендерим
    /// как `protocol{...}`.
    fn check_satisfaction_against_methods(
        &self,
        concrete: &TypeRef,
        required: &[EffectMethod],
        bound_name: Option<&str>,
        type_param_name: &str,
        fn_name: &str,
        span: Span,
        errors: &mut Vec<Diagnostic>,
    ) {
        let concrete_name = match concrete {
            TypeRef::Named { path, .. } if path.len() == 1 => path[0].clone(),
            // Plan 138.1 Ф.1 (D239): `[]T` ≡ `Vec[T]` — see check_satisfaction.
            TypeRef::Array(_, _) => "Vec".to_string(),
            _ => return,
        };
        if matches!(concrete_name.as_str(),
            "int" | "i8" | "i16" | "i32" | "i64"
            | "u8" | "u16" | "u32" | "u64"
            | "f32" | "f64" | "bool" | "char"
            | "str" | "any" | "never") {
            return;
        }
        let empty: HashMap<String, Vec<&FnDecl>> = HashMap::new();
        let concrete_methods = self.sig.method_table.get(&concrete_name).unwrap_or(&empty);
        let mut missing: Vec<String> = Vec::new();
        for req in required {
            let found = concrete_methods.get(&req.name).map(|fns| {
                fns.iter().any(|f| f.params.len() == req.params.len())
            }).unwrap_or(false);
            if !found {
                // Plan 91.8a.2 part 2 (D183 amendment): default body fallback.
                // Если protocol method имеет default body — type can satisfy via
                // codegen synthesis. Assumption: synthesis will lower default body
                // calls correctly или error там. Здесь — accept satisfaction.
                if req.default_body.is_some() {
                    continue;
                }
                let sig = render_method_sig(&req.name, &req.params, &req.return_type);
                let prefix = if req.is_static { "." } else { "" };
                missing.push(format!("{}{}", prefix, sig));
            }
        }
        if missing.is_empty() {
            return;
        }
        let bound_display = bound_name
            .map(|n| n.to_string())
            .unwrap_or_else(|| "<anonymous protocol>".to_string());
        let mut msg = format!(
            "type `{}` does not satisfy `{}` bound (in call to `{}[{} {}]`).\n\n  `{}` requires:\n",
            concrete_name, bound_display, fn_name, type_param_name, bound_display, bound_display);
        for req in required {
            let prefix = if req.is_static { "." } else { "" };
            msg.push_str(&format!(
                "    {}{}\n",
                prefix,
                render_method_sig(&req.name, &req.params, &req.return_type)));
        }
        msg.push_str(&format!("\n  `{}` is missing: {}\n", concrete_name, missing.join(", ")));
        msg.push_str(&format!(
            "\n  fix: добавить недостающие методы для типа `{}`. \
             См. spec/decisions/02-types.md#d72 и #d142 (anonymous protocol).",
            concrete_name));
        errors.push(Diagnostic::new(msg, span));
    }
}

/// Plan 15: extract simple identifier-name из Pattern. Рспользуется
/// для регистрации let-bindings в scope (только Pattern::Ident; complex
/// patterns — tuple/variant — пропускаются).
fn pattern_simple_name(p: &Pattern) -> Option<String> {
    match p {
        Pattern::Ident { name, .. } => Some(name.clone()),
        _ => None,
    }
}

// ============================================================================
// Plan 16 (D63 forbid + D64 realtime): capability enforcement.
// ============================================================================

/// Plan 16: набор "suspend"-эффектов которые нельзя использовать внутри
/// `realtime { ... }` блоков (D64). Эти эффекты по семантике могут
/// приостановить fiber'а в production-runtime'е.
fn realtime_suspend_effect(name: &str) -> bool {
    matches!(name, "Net" | "Fs" | "Db" | "Time")
}

/// Plan 83.3 Ф.6: эффекты, запрещённые в теле `blocking { }`. Тело
/// исполняется на libuv-threadpool-потоке без fiber/event-loop-
/// контекста — async-I/O-эффекты (Net/Fs/Db/Time) там сломаны.
/// `Blocking` сюда НЕ входит: вложенный `blocking` на threadpool-
/// потоке исполняется inline (`mco_running()` == false) — безвреден.
fn blocking_body_forbidden_effect(name: &str) -> bool {
    matches!(name, "Net" | "Fs" | "Db" | "Time")
}

/// Plan 16: hardcoded whitelist callee-name'ов, которые **аллоцируют**
/// в managed heap (и потому запрещены в `realtime nogc { ... }`).
/// Рдентификация по mangled C-name pattern + по высокоуровневым
/// `Type.method` (e.g. `[]int.new`, `StringBuilder.new`).
///
/// **Не покрывается** этим whitelist'ом:
/// - User-defined record-конструкторы `Foo.new()` если они alloc'ят
///   через nova_alloc — codegen всегда heap-боксит record-литералы,
///   так что фактически любой record-литерал «аллоцирующий». Но
///   detection требует bigger inference. Conservative — флагуем
///   только статические fabric-методы.
/// - `str.from(non-str)` если требует concat'а — пока считаем
///   все `str.from`-вызовы "alloc'ирующими".
fn nogc_blacklisted_call(callee_path: &[String]) -> bool {
    if callee_path.len() != 2 { return false; }
    let ty = callee_path[0].as_str();
    let m = callee_path[1].as_str();
    // Array constructors: `[]T.new` / `[]T.with_capacity`.
    if ty.starts_with("[]") && matches!(m, "new" | "with_capacity") { return true; }
    // Builder/buffer constructors.
    if matches!(ty, "StringBuilder" | "WriteBuffer" | "ReadBuffer")
        && matches!(m, "new" | "with_capacity" | "from") { return true; }
    // D91 (Plan 21): Channel.new allocates Nova_ChannelState + Sender + Receiver + buf.
    if ty == "Channel" && matches!(m, "new" | "with_capacity") { return true; }
    // Map/Set/Vec/Deque etc.
    if matches!(ty, "HashMap" | "Set" | "Vec" | "Deque" | "LinkedList" | "Lru" | "BloomFilter")
        && matches!(m, "new" | "with_capacity") { return true; }
    // str.from: format/conversion может alloc'ать.
    if ty == "str" && m == "from" { return true; }
    false
}

/// Plan 16: registry для capability enforcement.
struct CapabilityCtx<'a> {
    /// Plan 172.1 U.2.3.2: shared base signature registry — replaces the local
    /// `fn_decls`/`method_table` build (§0 single source). Read via
    /// `self.sig.fn_decls` / `self.sig.method_table` (base only). D84 overload
    /// semantics unchanged (capability check walks all overloads).
    sig: &'a crate::sig_registry::SigRegistry<'a>,
    /// Effect-type name registry (для distinguish'а effect-call vs ordinary).
    effect_decls: HashMap<String, &'a TypeDecl>,
}

/// Plan 16: capability state передаётся через walk как mutable.
/// Push/pop при входе/выходе из forbid/realtime блоков.
#[derive(Default, Clone)]
struct CapState {
    /// Stack forbidden-effects-set'ов от вложенных `forbid` блоков.
    /// Effect разрешён если он не в **union'е** этих set'ов.
    /// (Forbid внутри forbid — union, см. D63.)
    forbidden_stack: Vec<HashSet<String>>,
    /// True если мы внутри `realtime { ... }` (или `realtime nogc`).
    /// Suspend-effects (Net/Fs/Db/Time/Blocking) запрещены.
    realtime_active: bool,
    /// True если мы внутри `realtime nogc { ... }`. Дополнительно к
    /// realtime_active запрещены alloc-вызовы.
    realtime_nogc: bool,
    /// Stack handlers, установленных через `with X = ... { ... }`.
    /// Рспользуется для D63 forbid-handler-ban: `with X` внутри
    /// `forbid X` — compile error.
    with_handler_stack: Vec<String>,
    /// Plan 83.3 (D50): имена эффектов, объявленных в сигнатуре
    /// enclosing-функции. `blocking { }` требует наличия `Blocking`
    /// в этом наборе. Заполняется один раз при входе в `walk_fn_body`;
    /// у `test`-блоков остаётся пустым (нет сигнатуры).
    declared_effects: HashSet<String>,
    /// Plan 83.3 Ф.6 (D50): True внутри тела `blocking { }`. Тело
    /// исполняется на libuv-threadpool-потоке без fiber-контекста и
    /// без GC-регистрации — поэтому проверяется как `nogc`
    /// (`realtime_nogc` тоже выставляется) + бан suspend-эффектов
    /// Net/Fs/Db/Time (V1 leaf-контракт). Отдельный флаг, НЕ
    /// `realtime_active` — иначе вложенный `blocking` отвергался бы
    /// как «`blocking` внутри `realtime`».
    blocking_body_active: bool,
}

impl CapState {
    /// Union forbidden-set'ов всех уровней стека.
    fn union_forbidden(&self) -> HashSet<String> {
        let mut out = HashSet::new();
        for s in &self.forbidden_stack { out.extend(s.iter().cloned()); }
        out
    }
}

impl<'a> CapabilityCtx<'a> {
    fn build(module: &'a Module, sig: &'a crate::sig_registry::SigRegistry<'a>) -> Self {
        // U.2.3.2: fn_decls/method_table read from `sig` (shared base registry).
        let mut effect_decls: HashMap<String, &TypeDecl> = HashMap::new();
        for item in &module.items {
            if let Item::Type(t) = item {
                if matches!(t.kind, TypeDeclKind::Effect(_)) {
                    effect_decls.insert(t.name.clone(), t);
                }
            }
        }
        CapabilityCtx { sig, effect_decls }
    }

    fn check_module(&self, module: &Module, errors: &mut Vec<Diagnostic>) {
        // Plan 42 Sub-plan 42.A: file-level #forbid declarations.
        // Initial forbidden set из module.attrs (per-file scope).
        // Все functions в этом file получают эти effects forbidden.
        let mut file_forbidden: HashSet<String> = HashSet::new();
        for attr in &module.attrs {
            if matches!(attr.kind, crate::ast::ModuleAttrKind::Forbid) {
                for e in &attr.effects {
                    file_forbidden.insert(e.clone());
                }
            }
        }
        for item in &module.items {
            match item {
                Item::Fn(f) => {
                    let mut state = CapState::default();
                    // Plan 42 Sub-plan 42.A: file-level #forbid initial frame.
                    if !file_forbidden.is_empty() {
                        state.forbidden_stack.push(file_forbidden.clone());
                    }
                    // Plan 16 Ф.5: @realtime атрибут оборачивает body
                    // в realtime[+nogc] контекст.
                    match f.realtime_attr {
                        RealtimeAttr::None => {}
                        RealtimeAttr::Realtime => state.realtime_active = true,
                        RealtimeAttr::RealtimeNogc => {
                            state.realtime_active = true;
                            state.realtime_nogc = true;
                        }
                    }
                    self.walk_fn_body(f, &mut state, errors);
                }
                Item::Test(t) => {
                    let mut state = CapState::default();
                    if !file_forbidden.is_empty() {
                        state.forbidden_stack.push(file_forbidden.clone());
                    }
                    self.walk_block(&t.body, &mut state, errors);
                }
                _ => {}
            }
        }
    }

    fn walk_fn_body(&self, f: &FnDecl, state: &mut CapState, errors: &mut Vec<Diagnostic>) {
        // Plan 83.3 (D50): зафиксировать объявленные эффекты сигнатуры —
        // `blocking { }` в теле требует среди них `Blocking`. Имя эффекта —
        // последний segment Named-path (`std.io.Blocking` → `Blocking`).
        for ef in &f.effects {
            if let TypeRef::Named { path, .. } = ef {
                if let Some(last) = path.last() {
                    state.declared_effects.insert(last.clone());
                }
            }
        }
        match &f.body {
            FnBody::Expr(e) => self.walk_expr(e, state, errors),
            FnBody::Block(b) => self.walk_block(b, state, errors),
            FnBody::External => {}
        }
    }

    fn walk_block(&self, b: &Block, state: &mut CapState, errors: &mut Vec<Diagnostic>) {
        for s in &b.stmts {
            self.walk_stmt(s, state, errors);
        }
        if let Some(t) = &b.trailing {
            self.walk_expr(t, state, errors);
        }
    }

    fn walk_stmt(&self, s: &Stmt, state: &mut CapState, errors: &mut Vec<Diagnostic>) {
        match s {
            Stmt::Expr(e) => self.walk_expr(e, state, errors),
            Stmt::Let(d) => self.walk_expr(&d.value, state, errors),
            Stmt::Const(_) => {}
            Stmt::Assign { target, value, .. } => {
                self.walk_expr(target, state, errors);
                self.walk_expr(value, state, errors);
            }
            Stmt::Return { value, .. } => {
                if let Some(v) = value { self.walk_expr(v, state, errors); }
            }
            Stmt::Throw { value, .. } => self.walk_expr(value, state, errors),
            Stmt::Break(_) | Stmt::Continue(_) => {}
            // D90 Plan 20 Ф.2: проверяем capability'и внутри body
            // defer'а. Полные constraints (no Fail/suspend/exit-control)
            // — Ф.3.
            Stmt::Defer { body, .. } | Stmt::ErrDefer { body, .. }
            | Stmt::OkDefer { body, .. } | Stmt::DeferWithResult { body, .. } => {
                self.walk_expr(body, state, errors);
            }
            // Plan 110 D188: walk init + body (scaffold).
            Stmt::ConsumeScope { init, body, .. } => {
                self.walk_expr(init, state, errors);
                for s in &body.stmts {
                    self.walk_stmt(s, state, errors);
                }
                if let Some(t) = &body.trailing {
                    self.walk_expr(t, state, errors);
                }
            }
            // Plan 33.2 Ф.8: assert_static — walk expr.
            Stmt::AssertStatic { expr, .. } | Stmt::Assume { expr, .. } => self.walk_expr(expr, state, errors),
            // Ф.4.1: apply — ghost, нет capability-эффектов.
            Stmt::Apply { .. } => {}
            // Ф.4.2: calc — ghost, нет capability-эффектов.
            Stmt::Calc { .. } => {}
            // Plan 33.9 Ф.2: reveal — ghost, нет capability-эффектов.
            Stmt::Reveal { .. } => {}
            // Plan 136: tuple destructuring assignment.
            Stmt::TupleAssign { lhs, rhs, .. } => {
                for e in lhs { self.walk_expr(e, state, errors); }
                for e in rhs { self.walk_expr(e, state, errors); }
            }
        }
    }

    fn walk_expr(&self, e: &Expr, state: &mut CapState, errors: &mut Vec<Diagnostic>) {
        // Сначала проверяем сам узел (call-bound checks), потом
        // погружаемся внутрь с обновлённым state'ом для блочных
        // конструкций (forbid/realtime/with).
        self.check_capabilities_at(e, state, errors);
        match &e.kind {
            ExprKind::Forbid { effects, body } => {
                // Push forbidden-set, walk, pop.
                let names: HashSet<String> = effects.iter()
                    .filter_map(|t| match t {
                        TypeRef::Named { path, .. } if path.len() == 1 => Some(path[0].clone()),
                        _ => None,
                    })
                    .collect();
                state.forbidden_stack.push(names);
                self.walk_block(body, state, errors);
                state.forbidden_stack.pop();
            }
            ExprKind::Realtime { nogc, body } => {
                let prev_active = state.realtime_active;
                let prev_nogc = state.realtime_nogc;
                state.realtime_active = true;
                state.realtime_nogc = state.realtime_nogc || *nogc;
                self.walk_block(body, state, errors);
                state.realtime_active = prev_active;
                state.realtime_nogc = prev_nogc;
            }
            ExprKind::With { bindings, body } => {
                // Plan 16 D63: установка handler'а для forbidden-эффекта
                // внутри forbid-блока — compile error.
                //
                // WithBinding.effect: TypeRef. Для названия эффекта
                // берём последний segment Named-path (e.g. `std.io.Net`
                // → "Net"). Non-Named TypeRefs (Array/Tuple/Func/etc.) —
                // невалидны для эффект-handler'ов, пропускаем.
                let pushed: Vec<String> = bindings.iter()
                    .filter_map(|b| match &b.effect {
                        TypeRef::Named { path, .. } if !path.is_empty() => path.last().cloned(),
                        _ => None,
                    })
                    .collect();
                let forbidden = state.union_forbidden();
                for n in &pushed {
                    if forbidden.contains(n) {
                        errors.push(Diagnostic::new(
                            format!(
                                "cannot install handler for `{}` inside `forbid {}` block (D63): \
                                 forbid is impenetrable — code in body cannot escape sandbox \
                                 via `with X = …`.",
                                n, n
                            ),
                            e.span,
                        ));
                    }
                    state.with_handler_stack.push(n.clone());
                }
                self.walk_block(body, state, errors);
                for _ in &pushed { state.with_handler_stack.pop(); }
            }
            ExprKind::Call { func, args, trailing } => {
                self.walk_expr(func, state, errors);
                for a in args { self.walk_expr(a.expr(), state, errors); }
                if let Some(t) = trailing {
                    match t {
                        crate::ast::Trailing::Block(b) => self.walk_block(b, state, errors),
                        crate::ast::Trailing::LegacyBlockWithParams(tb) => {
                            self.walk_block(&tb.body, state, errors)
                        }
                        crate::ast::Trailing::Fn(sb) => match &sb.body {
                            FnBody::Expr(e) => self.walk_expr(e, state, errors),
                            FnBody::Block(b) => self.walk_block(b, state, errors),
                            FnBody::External => {}
                        },
                    }
                }
            }
            ExprKind::TurboFish { base, .. } => self.walk_expr(base, state, errors),
            ExprKind::Binary { left, right, .. } => {
                self.walk_expr(left, state, errors);
                self.walk_expr(right, state, errors);
            }
            ExprKind::Unary { operand, .. } => self.walk_expr(operand, state, errors),
            ExprKind::Try(inner) | ExprKind::Bang(inner) => self.walk_expr(inner, state, errors),
            ExprKind::Coalesce(a, b) => {
                self.walk_expr(a, state, errors);
                self.walk_expr(b, state, errors);
            }
            ExprKind::As(e, _) => self.walk_expr(e, state, errors),
            ExprKind::Is(e, _) => self.walk_expr(e, state, errors),
            ExprKind::Member { obj, .. } => self.walk_expr(obj, state, errors),
            ExprKind::Index { obj, index } => {
                self.walk_expr(obj, state, errors);
                self.walk_expr(index, state, errors);
            }
            ExprKind::If { cond, then, else_ } => {
                self.walk_expr(cond, state, errors);
                self.walk_block(then, state, errors);
                if let Some(eb) = else_ {
                    match eb {
                        ElseBranch::Block(b) => self.walk_block(b, state, errors),
                        ElseBranch::If(e) => self.walk_expr(e, state, errors),
                    }
                }
            }
            ExprKind::IfLet { scrutinee, then, else_, .. } => {
                self.walk_expr(scrutinee, state, errors);
                self.walk_block(then, state, errors);
                if let Some(eb) = else_ {
                    match eb {
                        ElseBranch::Block(b) => self.walk_block(b, state, errors),
                        ElseBranch::If(e) => self.walk_expr(e, state, errors),
                    }
                }
            }
            ExprKind::Match { scrutinee, arms } => {
                self.walk_expr(scrutinee, state, errors);
                for arm in arms {
                    if let Some(g) = &arm.guard { self.walk_expr(g, state, errors); }
                    match &arm.body {
                        MatchArmBody::Expr(e) => self.walk_expr(e, state, errors),
                        MatchArmBody::Block(b) => self.walk_block(b, state, errors),
                    }
                }
            }
            ExprKind::Block(b) => self.walk_block(b, state, errors),
            ExprKind::ArrayLit(elems) => {
                for el in elems {
                    match el {
                        ArrayElem::Item(e) | ArrayElem::Spread(e) => self.walk_expr(e, state, errors),
                    }
                }
            }
            ExprKind::MapLit { elems, .. } => {
                let pairs = crate::ast::MapElem::cloned_pairs(&elems);
                for (k, v) in pairs.iter() {
                    self.walk_expr(k, state, errors);
                    self.walk_expr(v, state, errors);
                }
            }
            ExprKind::TupleLit(elems) => {
                for e in elems { self.walk_expr(e, state, errors); }
            }
            ExprKind::RecordLit { fields, .. } => {
                for f in fields {
                    if let Some(v) = &f.value { self.walk_expr(v, state, errors); }
                }
            }
            ExprKind::TaggedTemplate { tag, args, .. } => {
                self.walk_expr(tag, state, errors);
                for a in args { self.walk_expr(a, state, errors); }
            }
            ExprKind::InterpolatedStr { parts } => {
                for p in parts {
                    if let InterpStrPart::Expr { expr: e, spec: _ } = p {
                        self.walk_expr(e, state, errors);
                    }
                }
            }
            ExprKind::Lambda { body, .. } => self.walk_expr(body, state, errors),
            // Plan 19, C5: CapabilityCtx обходит тело closure для
            // forbid/realtime проверок (D63/D64). Closure-light и
            // closure-full одинаково — walk by body kind.
            ExprKind::ClosureLight { body, .. } => match body {
                crate::ast::ClosureBody::Expr(e) => self.walk_expr(e, state, errors),
                crate::ast::ClosureBody::Block(b) => self.walk_block(b, state, errors),
            },
            ExprKind::ClosureFull(sb) => match &sb.body {
                FnBody::Expr(e) => self.walk_expr(e, state, errors),
                FnBody::Block(b) => self.walk_block(b, state, errors),
                FnBody::External => {}
            },
            ExprKind::Spawn(body) => self.walk_expr(body, state, errors),
            ExprKind::Detach(body) => self.walk_block(body, state, errors),
            ExprKind::Blocking(body) => {
                // Plan 91.15 (D172): the `blocking { }` block-form was retracted
                // by Plan 113. The parser now rejects `blocking { ... }` outright
                // (parser::parse_blocking → `[D172-block-form-removed]`), so this
                // AST arm is unreachable in practice. The variant is retained only
                // to keep the AST enum stable; walk the body defensively without
                // requiring the removed `Blocking` effect.
                self.walk_block(body, state, errors);
            }
            ExprKind::Supervised { body, cancel } => {
                if let Some(c) = cancel { self.walk_expr(c, state, errors); }
                self.walk_block(body, state, errors);
            }
            ExprKind::ParallelFor { iter, body, .. } => {
                self.walk_expr(iter, state, errors);
                self.walk_block(body, state, errors);
            }
            ExprKind::For { iter, body, .. } => {
                self.walk_expr(iter, state, errors);
                self.walk_block(body, state, errors);
            }
            ExprKind::While { cond, body, .. } => {
                self.walk_expr(cond, state, errors);
                self.walk_block(body, state, errors);
            }
            ExprKind::WhileLet { scrutinee, body, .. } => {
                self.walk_expr(scrutinee, state, errors);
                self.walk_block(body, state, errors);
            }
            ExprKind::Loop { body, .. } => self.walk_block(body, state, errors),
            ExprKind::Select { arms } => {
                for arm in arms {
                    match &arm.op {
                        SelectOp::Recv { chan, .. } => self.walk_expr(chan, state, errors),
                        SelectOp::Send { chan, value } => {
                            self.walk_expr(chan, state, errors);
                            self.walk_expr(value, state, errors);
                        }
                        SelectOp::Default => {}
                    }
                    if let Some(g) = &arm.guard { self.walk_expr(g, state, errors); }
                    self.walk_block(&arm.body, state, errors);
                }
            }
            ExprKind::Range { start, end, .. } => {
                if let Some(s) = start { self.walk_expr(s, state, errors); }
                if let Some(e) = end { self.walk_expr(e, state, errors); }
            }
            ExprKind::Throw(e) => self.walk_expr(e, state, errors),
            ExprKind::Interrupt(opt) => {
                if let Some(e) = opt { self.walk_expr(e, state, errors); }
            }
            // D.1.3: квантор — только в контрактах; обходим range и body.
            ExprKind::Forall { range, body, .. } | ExprKind::Exists { range, body, .. } => {
                self.walk_expr(range, state, errors);
                self.walk_expr(body, state, errors);
            }
            // Литералы / ident'ы / handler-литералы — без рекурсии.
            ExprKind::IntLit(_) | ExprKind::FloatLit(_) | ExprKind::BoolLit(_)
            | ExprKind::StrLit(_) | ExprKind::CharLit(_) | ExprKind::UnitLit
            | ExprKind::NullPtrLit
            | ExprKind::Ident(_) | ExprKind::Path(_) | ExprKind::SelfAccess
            | ExprKind::HandlerLit { .. }
            | ExprKind::ProtocolLit { .. } => {}
        }
    }

    /// Plan 16 Ф.2-Ф.4: проверка capability-rules на конкретном узле.
    /// Сейчас — только для Call'ов; forbid/realtime/with управляют
    /// state'ом, не вызывая check'ов на собственном узле.
    fn check_capabilities_at(&self, e: &Expr, state: &CapState, errors: &mut Vec<Diagnostic>) {
        let ExprKind::Call { func, .. } = &e.kind else { return; };
        // Path-form: `Type.method`, `Effect.op` или `[]T.method`.
        // Для `[]T.method()` парсер строит Member{obj: Path(["__array", T]), name}.
        let path: Vec<String> = match &func.kind {
            ExprKind::Path(parts) => parts.clone(),
            ExprKind::Member { obj, name } => {
                match &obj.kind {
                    ExprKind::Ident(n) => vec![n.clone(), name.clone()],
                    // `[]T.method`: Path(["__array","T"]) → ["[]T", method].
                    ExprKind::Path(parts) if parts.len() == 2 && parts[0] == "__array" => {
                        vec![format!("[]{}", parts[1]), name.clone()]
                    }
                    ExprKind::Path(parts) => {
                        let mut v = parts.clone();
                        v.push(name.clone());
                        v
                    }
                    _ => return, // dynamic member-call; не resolve'им
                }
            }
            ExprKind::Ident(n) => vec![n.clone()],
            _ => return,
        };
        // 1. Effect-op call: `Effect.op(...)` где Effect — registered effect-type.
        if path.len() == 2 {
            let head = &path[0];
            if self.effect_decls.contains_key(head) {
                self.check_forbid_intersection(head, state, e.span, errors);
                if state.realtime_active && realtime_suspend_effect(head) {
                    errors.push(Diagnostic::new(
                        format!(
                            "cannot use suspend-effect `{}` inside `realtime` block (D64): \
                             {}.{} may suspend the fiber. Hint: extract the effectful work \
                             out of `realtime` block, or use non-blocking alternative \
                             (e.g. `Channel.try_recv` instead of `Channel.recv`).",
                            head, head, &path[1]
                        ),
                        e.span,
                    ));
                }
                // Plan 83.3 Ф.6: тело `blocking { }` идёт на threadpool-потоке
                // без fiber/event-loop — async-I/O-эффекты там сломаны.
                if state.blocking_body_active && blocking_body_forbidden_effect(head) {
                    errors.push(Diagnostic::new(
                        format!(
                            "cannot use suspend-effect `{}` inside `blocking {{ ... }}` body \
                             (Plan 83.3 V1 leaf-contract, D50 §4): {}.{} needs the \
                             fiber/event-loop context, which the libuv threadpool thread \
                             does not have. Hint: `blocking` is for genuinely-blocking C \
                             calls — do async I/O outside the `blocking` block.",
                            head, head, &path[1]
                        ),
                        e.span,
                    ));
                }
            }
        }
        // 2. Free-fn call: lookup callee.effects.
        // D84: fn_decls — Vec<&FnDecl>. Без полного type-resolve в
        // bound-checker'е невозможно выбрать конкретную overload —
        // проверяем эффекты у **всех** overloads (consistent с тем что
        // делает method_table-ветка ниже). False-positive если разные
        // overloads имеют разные эффекты — в реальных API маловероятно
        // (overloads обычно отличаются типом аргумента, не эффектами),
        // но если случится — программист дисамбигуирует через cast.
        if path.len() == 1 {
            if let Some(overloads) = self.sig.fn_decls.get(&path[0]) {
                for callee in overloads.iter() {
                    self.check_callee_effects(callee, &path[0], state, e.span, errors);
                }
            }
        }
        // 3. Method call: `Type.method` или `obj.method` — lookup в method_table.
        // (Только receiver-Path формы; instance-method через obj.method
        // требует type-инференции, отложен.)
        if path.len() == 2 {
            if let Some(methods) = self.sig.method_table.get(&path[0]) {
                if let Some(fns) = methods.get(&path[1]) {
                    for callee in fns {
                        self.check_callee_effects(callee, &format!("{}.{}", path[0], path[1]), state, e.span, errors);
                    }
                }
            }
        }
        // 4. Plan 16 Ф.4: nogc alloc-fn check.
        //    Plan 83.3 Ф.6: тело `blocking { }` тоже nogc (threadpool-поток
        //    не GC-registered) — context-aware сообщение.
        if state.realtime_nogc && nogc_blacklisted_call(&path) {
            if state.blocking_body_active && !state.realtime_active {
                errors.push(Diagnostic::new(
                    format!(
                        "cannot allocate inside `blocking {{ ... }}` body (Plan 83.3 \
                         V1 leaf-contract, D50 §4): `{}` allocates on the managed heap, \
                         but the body runs on a libuv threadpool thread that is not \
                         GC-registered. Hint: move the allocation outside the \
                         `blocking` block.",
                        path.join(".")
                    ),
                    e.span,
                ));
            } else {
                errors.push(Diagnostic::new(
                    format!(
                        "cannot allocate inside `realtime nogc` block (D64): `{}` allocates \
                         on managed heap. Hint: use `region {{ ... }}` for arena-allocations, \
                         or move the allocation outside the `realtime nogc` block.",
                        path.join(".")
                    ),
                    e.span,
                ));
            }
        }
    }

    /// Plan 16 Ф.2: проверка пересечения callee.effects с union forbidden-стека.
    fn check_callee_effects(
        &self,
        callee: &FnDecl,
        callee_label: &str,
        state: &CapState,
        span: Span,
        errors: &mut Vec<Diagnostic>,
    ) {
        // Pure — всегда OK.
        if callee.effects.is_empty() && state.forbidden_stack.is_empty() && !state.realtime_active {
            return;
        }
        let forbidden = state.union_forbidden();
        for eff in &callee.effects {
            let TypeRef::Named { path, .. } = eff else { continue; };
            if path.is_empty() { continue; }
            let name = &path[0];
            // Forbid check.
            if forbidden.contains(name) {
                errors.push(Diagnostic::new(
                    format!(
                        "function `{}` requires effect `{}`, forbidden by enclosing \
                         `forbid {}` block (D63). Hint: pure code inside `forbid` is OK; \
                         to use `{}`, restructure to compute effect-free results inside \
                         and apply effects outside the sandbox.",
                        callee_label, name, name, name
                    ),
                    span,
                ));
            }
            // Realtime check.
            if state.realtime_active && realtime_suspend_effect(name) {
                errors.push(Diagnostic::new(
                    format!(
                        "function `{}` requires suspend-effect `{}`, cannot be called \
                         inside `realtime` block (D64). Hint: realtime guarantees \
                         no fiber-suspension; effects {} block.",
                        callee_label, name,
                        "Net/Fs/Db/Time/Blocking suspend the fiber and are forbidden inside realtime"
                    ),
                    span,
                ));
            }
            // Plan 83.3 Ф.6: тело `blocking { }` идёт на threadpool-потоке
            // без fiber/event-loop-контекста — async-I/O-эффекты сломаны.
            if state.blocking_body_active && blocking_body_forbidden_effect(name) {
                errors.push(Diagnostic::new(
                    format!(
                        "function `{}` requires suspend-effect `{}`, cannot be called \
                         inside `blocking {{ ... }}` body (Plan 83.3 V1 leaf-contract, \
                         D50 §4): the libuv threadpool thread has no fiber/event-loop \
                         context for `{}`. Hint: `blocking` is for genuinely-blocking \
                         C calls — do async I/O outside it.",
                        callee_label, name, name
                    ),
                    span,
                ));
            }
        }
    }

    /// Plan 16 D63: единичная проверка effect'a против forbidden-стека.
    fn check_forbid_intersection(
        &self,
        eff_name: &str,
        state: &CapState,
        span: Span,
        errors: &mut Vec<Diagnostic>,
    ) {
        let forbidden = state.union_forbidden();
        if forbidden.contains(eff_name) {
            errors.push(Diagnostic::new(
                format!(
                    "use of effect `{}` is forbidden by enclosing `forbid {}` block (D63).",
                    eff_name, eff_name
                ),
                span,
            ));
        }
    }
}

// ============================================================================
// Name-resolution фаза.
//
// Pre-collects top-level имена (fns/types/consts/variants/built-ins) +
// walk fn/test bodies со scope-стеком. На `ExprKind::Ident(name)`
// проверяет, что `name` в (текущий scope ∪ top-level ∪ built-ins).
// Рначе — diagnostic «undefined identifier`.
//
// **Конкервативная стратегия**: лучше пропустить undefined чем
// false-positive. Случаи, где не проверяем:
//   - `obj.method(args)` / `Type.method(args)` — method-имена resolve'ятся
//     через method_table (могут быть на любом типе).
//   - `obj.field` / `Record { field: val }` — поля, не идентификаторы.
//   - Path-сегменты `mod1::mod2::name` (intermediate — модули, не expr).
//   - Tagged-template tags.
//   - Generic-params в TypeRef (это типы, не expressions).
//   - Sum-variant tag в pattern (`Some(x)` — constructor name, не expr).
// ============================================================================

/// Plan 19+: статическая проверка undefined идентификаторов.
struct NameResCtx {
    /// Plan 42.15: per-group shared declarations (Rule C). Key = file_id
    /// peer'а. Value = declarations всех peers ЕГО module-group (folder-
    /// module с общим parent dir). Peers одной группы делят namespace;
    /// между группами — НЕ делят (imported folder-module's decls не
    /// протекают).
    group_decls: HashMap<FileId, HashSet<String>>,
    /// Plan 42.15: fallback для legacy/single-file (peer_files пуст) —
    /// flat все module.items. Рспользуется когда file_id не в group_decls.
    shared_decls: HashSet<String>,
    /// Plan 42.15: union ВСЕХ declarations (все группы + imported). НЕ
    /// для name-resolution enforcement (это нарушило бы Rule C) —
    /// используется ТОЛЬКО как эвристика в `collect_pattern_bindings`
    /// (отличить pattern-binding `let x` от variant-pattern `Some`).
    all_decls: HashSet<String>,
    /// Plan 42.15: per-peer imported item names — items ставшие
    /// видимыми в peer'е через его прямые `import` (после rename +
    /// selective filter). Rule C: imports НЕ shared между peers.
    peer_imported_names: HashMap<FileId, HashSet<String>>,
    /// Built-in имена, доступные в любом scope без объявления:
    /// primitive types, prelude variants (None/Some/Ok/Err), bool
    /// литералы (true/false), builtin functions (assert/print/...),
    /// special idents (Self).
    builtins: HashSet<String>,
    /// Per-peer import namespace (Plan 42.4 Rule C).
    /// Key = file_id of peer file (MAIN_FILE_ID for entry).
    /// Value = set of module/alias names visible in that peer.
    peer_module_names: HashMap<FileId, HashSet<String>>,
    /// Plan 170 (D307): per-file file-private leak table. Key = file_id of a
    /// peer F. Value = map `name → owner_path` for every `priv(file)` symbol
    /// declared in ANOTHER peer file of F's module-group. When F references
    /// such a name and it is otherwise unresolved, the resolver emits the
    /// specific `E_FILE_PRIV_LEAK` diagnostic (instead of generic «undefined
    /// identifier»). The symbol is intentionally NOT in `group_decls[F]`.
    file_priv_leak: HashMap<FileId, HashMap<String, String>>,
}

impl NameResCtx {
    fn build(module: &Module) -> Self {
        // Plan 42.15: per-group shared declarations (Rule C).
        //
        // **Module-group** = набор peer-файлов одного folder-module
        // (имеют общий parent dir). Внутри группы peers делят
        // declarations namespace (Rule C: «peers share declarations»).
        // МЕЖДУ группами — НЕ делят (imported folder-module's decls не
        // протекают в entry's namespace).
        //
        // `group_decls`: HashMap<FileId, HashSet<String>> — для каждого
        // peer'а (по file_id) → declarations всех peers его группы.
        let mut group_decls: HashMap<FileId, HashSet<String>> = HashMap::new();
        // Fallback для legacy/single-file (peer_files пуст).
        let mut shared_decls: HashSet<String> = HashSet::new();

        fn collect_decl_names(items: &[Item], out: &mut HashSet<String>) {
            for item in items {
                match item {
                    Item::Fn(fd) => {
                        // free-functions (без receiver) валидны как
                        // bare-ident `foo()`. Методы — через obj.method.
                        if fd.receiver.is_none() {
                            out.insert(fd.name.clone());
                        }
                    }
                    Item::Type(td) => {
                        out.insert(td.name.clone());
                        // Variant-имена sum-типов: `Some(x)`, `Red`, etc.
                        if let TypeDeclKind::Sum(variants) = &td.kind {
                            for v in variants {
                                out.insert(v.name.clone());
                            }
                        }
                    }
                    Item::Const(cd) => {
                        out.insert(cd.name.clone());
                    }
                    // Plan 152.4 (D199 ro-runtime side): a module-level
                    // `ro NAME = EXPR` is a lazy-static global (genuinely
                    // runtime RHS — call/effect/alloc; the strict const/ro
                    // partition forces a constexpr RHS to `const`). Its binder
                    // is a resolvable top-level name, exactly like a `const`, so
                    // collect it for name-resolution — otherwise USES
                    // (`tbl.get(k)`) would be flagged «undefined identifier».
                    // Single named binder only (Ident, or single-segment unit
                    // Variant for the UPPER_CASE form), non-ghost. Mirrors the
                    // env.consts registration in `check_module`.
                    Item::Let(ld) if !ld.is_ghost => {
                        match &ld.pattern {
                            crate::ast::Pattern::Ident { name, .. } => {
                                out.insert(name.clone());
                            }
                            crate::ast::Pattern::Variant {
                                path,
                                kind: crate::ast::VariantPatternKind::Unit,
                                ..
                            } if path.len() == 1 => {
                                out.insert(path[0].clone());
                            }
                            _ => {}
                        }
                    }
                    // Plan 57: bench — top-level item но имя — string-literal,
                    // не идентификатор; в name resolution не участвует. ghost
                    // `let` — spec-only, не резолвится.
                    Item::Let(_) | Item::Test(_) | Item::Bench(_) | Item::Lemma(_) => {}
                }
            }
        }

        // Plan 170 (D307): file-private leak table — per-file map of names that
        // are `priv(file)` in another peer file of the same module-group.
        let mut file_priv_leak: HashMap<FileId, HashMap<String, String>> = HashMap::new();

        // Plan 170 (D307): collect a peer's `priv(file)` top-level names — these
        // are visible ONLY inside their own file and must NOT enter the shared
        // group namespace. Free fns / types (+ sum variants) / consts.
        fn collect_file_private_names(items: &[Item], out: &mut HashSet<String>) {
            for item in items {
                match item {
                    Item::Fn(fd) if fd.receiver.is_none() && fd.file_private => {
                        out.insert(fd.name.clone());
                    }
                    Item::Type(td) if td.file_private => {
                        out.insert(td.name.clone());
                        if let TypeDeclKind::Sum(variants) = &td.kind {
                            for v in variants { out.insert(v.name.clone()); }
                        }
                    }
                    Item::Const(cd) if cd.file_private => {
                        out.insert(cd.name.clone());
                    }
                    _ => {}
                }
            }
        }

        if module.peer_files.is_empty() {
            // Legacy/single-file: flat — все module.items. A lone file has no
            // peers, so file-private symbols are trivially visible in it.
            collect_decl_names(&module.items, &mut shared_decls);
        } else {
            // Группируем peers по parent dir пути. Все peers одной
            // папки = одна module-group, делят declarations.
            //
            // Plan 170 (D307): the SHARED group namespace excludes each peer's
            // `priv(file)` names. Per peer F the visible set is then
            // `shared_group ∪ F's own file-private names` — so a sibling never
            // resolves another file's private symbol.
            let mut groups: HashMap<(std::path::PathBuf, Vec<String>), HashSet<String>> = HashMap::new();
            let mut peer_group_key: HashMap<FileId, (std::path::PathBuf, Vec<String>)> = HashMap::new();
            // Per file: its OWN file-private names (re-added to its own scope).
            let mut own_file_private: HashMap<FileId, HashSet<String>> = HashMap::new();
            // Per group: file-private name → owner file path (for leak diag).
            let mut group_file_private: HashMap<
                (std::path::PathBuf, Vec<String>),
                HashMap<String, (FileId, String)>,
            > = HashMap::new();
            for pf in &module.peer_files {
                let dir_key = pf.path.parent()
                    .map(|p| p.to_path_buf())
                    .unwrap_or_else(|| pf.path.clone());
                // Plan 81 F.1: group by (dir, module_name).
                let group_key = (dir_key, pf.module_name.clone());
                peer_group_key.insert(pf.file_id, group_key.clone());
                // Collect ALL decl names, then subtract this file's privates so
                // the shared group set has only module-default / export names.
                let mut all_here: HashSet<String> = HashSet::new();
                collect_decl_names(&pf.items_here, &mut all_here);
                let mut fp_here: HashSet<String> = HashSet::new();
                collect_file_private_names(&pf.items_here, &mut fp_here);
                let entry = groups.entry(group_key.clone()).or_default();
                for n in all_here.difference(&fp_here) {
                    entry.insert(n.clone());
                }
                let path_str = pf.path.to_string_lossy().to_string();
                let gfp = group_file_private.entry(group_key).or_default();
                for n in &fp_here {
                    gfp.entry(n.clone()).or_insert((pf.file_id, path_str.clone()));
                }
                own_file_private.insert(pf.file_id, fp_here);
            }
            // Разворачиваем: для каждого peer'а — shared group decls ∪ его own
            // file-private. Также строим leak-table: file-private имена,
            // объявленные в ДРУГИХ файлах группы.
            for pf in &module.peer_files {
                if let Some(gk) = peer_group_key.get(&pf.file_id) {
                    if let Some(decls) = groups.get(gk) {
                        let mut visible = decls.clone();
                        if let Some(own) = own_file_private.get(&pf.file_id) {
                            for n in own { visible.insert(n.clone()); }
                        }
                        group_decls.insert(pf.file_id, visible);
                    }
                    if let Some(gfp) = group_file_private.get(gk) {
                        let mut leak: HashMap<String, String> = HashMap::new();
                        for (name, (owner_fid, owner_path)) in gfp {
                            if *owner_fid != pf.file_id {
                                leak.insert(name.clone(), owner_path.clone());
                            }
                        }
                        if !leak.is_empty() {
                            file_priv_leak.insert(pf.file_id, leak);
                        }
                    }
                }
            }
        }

        let builtins: HashSet<String> = [
            // Numeric primitives.
            "int", "i8", "i16", "i32", "i64",
            "u8", "u16", "u32", "u64",
            "f32", "f64", "uint", "size",
            // Other primitives.
            "bool", "str", "char", "unit", "any",
            // Plan 76: `never` — bottom-тип (uninhabited, 0 значений),
            // строчный встроенный примитив. Subtype любого `T`. Как и
            // остальные примитивы (`int`/`bool`/...) — НЕ объявляется в
            // prelude, известен компилятору напрямую.
            "never",
            // Boolean literals (parsed как Ident в bool-context кое-где).
            "true", "false",
            // Special idents.
            "Self", "self",
            // Plan 62.A: `Option`/`Result`/`Some`/`None`/`Ok`/`Err`/`Error`/
            // `Ordering`/`Less`/`Equal`/`Greater` (11 names) перенесены в
            // std/prelude/core.nv. Type-checker теперь resolves их через
            // cross-file resolve (R27 auto-import). См. docs/plans/
            // 62-prelude-hardcode-migration.md §62.A.
            //
            // Plan 62.C: `RuntimeError` + 6 variants (`DivByZero`,
            // `Overflow`, `IndexOutOfBounds`, `TypeMismatch`, `AssertFailed`,
            // `NoHandler`) перенесены в std/prelude/errors.nv. Аналогично
            // `ReadBufferError` + `UnexpectedEnd` (не были в этом HashSet'е,
            // но добавлены в registry через init_prelude_decls_from_items
            // — см. sum_schema_registry.rs::register_prelude_sum_from_decl).
            // Type-checker теперь resolves их через cross-file resolve.
            // Pre-populated `sum_schemas["RuntimeError"]` (emit_c.rs:1029-1048)
            // оставлен как ABI-compat fallback baseline per 62.A.bis
            // architecture (HardcodedBaseline остаётся, lookup precedence
            // DeclaredFromPrelude > HardcodedBaseline).
            //
            // `RuntimeNoneError` НЕ перенесён — bootstrap parser не
            // поддерживает empty-body sum syntax. Остаётся as
            // string-payload throw в nova_rt/effects.h.
            // Plan 62.B: `panic`/`exit`/`assert`/`debug_assert` (4 names)
            // перенесены в std/prelude/runtime.nv (file-based external fn
            // declarations). Type-checker теперь resolves их через
            // cross-file resolve (R27 auto-import + R26 re-export через
            // std/prelude.nv facade). Codegen special-cases в emit_c.rs
            // (~11086-11136) остаются:
            //   - panic/exit нужны для comma-expression обёртки
            //     `(nv_panic(msg), (nova_int)0LL)` в expression-position
            //     (?? coalesce, if-else branches).
            //   - assert/debug_assert: D89 expression-context + Plan 11
            //     auto-derived cond_text (msg arg silently ignored).
            // См. docs/plans/62-prelude-hardcode-migration.md §62.B.
            //
            // Plan 62.B.bis (2026-05-18) closure: `print` / `println`
            // больше не hardcoded — formally declared в
            // std/prelude/runtime.nv через D69 variadic + `[]any`
            // (canonical D26 signature). Cross-file resolve через R27
            // auto-import + R26 facade re-export находит declarations.
            // Codegen special-case (emit_c.rs:11270, Ф.1 reorder) fires
            // ДО variadic routing — preserves per-arg type info,
            // synthesized `[]any` array никогда не строится; per-arg
            // `nova_print_<type>` dispatch через infer_print_helper
            // (Ф.0 Plan 67 absorption — unified через infer_expr_c_type).
            // См. docs/plans/62.B.bis-print-println-migration.md.
            // Plan 32: GC introspection namespace (std.runtime.gc).
            // Рспользуется как `gc.heap_size()`, `gc.collect()` и т.д.
            // Source of truth для signatures: std/runtime/gc.nv (external fn).
            // Codegen dispatch: emit_c.rs:7155 special-case на name == "gc".
            // Builtin запись нужна потому что cross-file bare-name resolve
            // не работает (Plan 35 Ф.1).
            "gc",
            // Plan 57: bench DSL builtins namespace (std.bench).
            // `bench.opaque(v)`, `bench.iterations()`, `bench.reset_timer()`,
            // `bench.bytes(n)`, `bench.elements(n)`, `bench.allocs()`,
            // `bench.now_ns()`. Source of truth: std/bench.nv. Codegen
            // dispatch: emit_c.rs special-case на `name == "bench"`.
            "bench",
            // Plan 44.2 Этап 3: fiber arena introspection namespace
            // (std.runtime.fibers). `fibers.slot_count()`, etc.
            // Source of truth: std/runtime/fibers.nv. Codegen dispatch:
            // emit_c.rs `name == "fibers"`.
            "fibers",
            // Plan 44 Этап 0: M:N runtime control namespace
            // (std.runtime.runtime). `runtime.init(n)`, `runtime.shutdown()`.
            "runtime",
            // Default Fail-effect type (D65 placeholder).
            "Fail",
            // Detach effect-type для detach {} expression (D50).
            "Detach",
            // CancelToken — caller-owned cancellation handle (D75 revised,
            // Plan 47). Builtin type: `CancelToken.new()` конструктор +
            // тип параметра `cancel CancelToken`. Методы (cancel/is_cancelled/
            // bind) — built-in dispatch в codegen на receiver NovaCancelToken*.
            "CancelToken",
            // Plan 62.D.bis (2026-05-18): StringBuilder / WriteBuffer /
            // ReadBuffer объявлены в std/prelude/collections.nv через
            // `external type` (D126). **Не были** в этом HashSet'е изначально
            // (verified via grep на baseline) — cross-file resolve работает
            // через std/runtime/<name>.nv external fn декларации + теперь
            // через std/prelude/collections.nv type-decl (TypeDeclKind::Opaque).
            // `nogc_blacklisted_call` (types/mod.rs:1454) сохраняет
            // name-matches как capability data — не builtins source,
            // не conflicts.
            //
            // Plan 103.1 Ф.6: `fence` — memory fence free function
            // (std/runtime/sync.nv). Lowercase free fn → нужен в builtins
            // иначе type-checker флагает «undefined identifier» для тестов
            // без `import std.runtime.sync`. Dispatch: ExternalRegistry
            // → nova_fn_fence (free_fn_c_name ExternalRegistry-first path).
            "fence",
        ]
        .iter()
        .map(|s| s.to_string())
        .collect();

        // Plan 42.4 Rule C: per-peer import namespace isolation.
        // Build a map from file_id → visible module names for that peer.
        // If peer_files is empty (legacy/single-file), fall back to entry.
        let mut peer_module_names: HashMap<FileId, HashSet<String>> = HashMap::new();

        let build_import_names = |imports: &[Import], module_name: &[String]| -> HashSet<String> {
            let mut names: HashSet<String> = HashSet::new();
            for imp in imports {
                if let Some(alias) = &imp.alias {
                    names.insert(alias.clone());
                }
                if let Some(last) = imp.path.last() {
                    names.insert(last.clone());
                }
                if let Some(head) = imp.path.first() {
                    names.insert(head.clone());
                }
            }
            // Own module name (last + first segment) for self-reference.
            if let Some(head) = module_name.first() { names.insert(head.clone()); }
            if let Some(last) = module_name.last() { names.insert(last.clone()); }
            names
        };

        if module.peer_files.is_empty() {
            // Legacy/single-file: entry imports under MAIN_FILE_ID.
            peer_module_names.insert(
                MAIN_FILE_ID,
                build_import_names(&module.imports, &module.name),
            );
        } else {
            for pf in &module.peer_files {
                peer_module_names.insert(
                    pf.file_id,
                    build_import_names(&pf.imports, &module.name),
                );
            }
        }

        // Plan 42.15: per-peer imported item names. Resolver наполнил
        // `PeerFile.imported_item_names` (items притащенные прямыми
        // imports этого peer'а). Rule C: imports не shared между peers.
        let mut peer_imported_names: HashMap<FileId, HashSet<String>> = HashMap::new();
        for pf in &module.peer_files {
            peer_imported_names.insert(pf.file_id, pf.imported_item_names.clone());
        }

        // Plan 42.15: all_decls — union ВСЕХ declarations (эвристика для
        // pattern-binding detection, НЕ для enforcement).
        let mut all_decls: HashSet<String> = shared_decls.clone();
        for gd in group_decls.values() {
            all_decls.extend(gd.iter().cloned());
        }
        // Также merged module.items (imported items для эвристики).
        collect_decl_names(&module.items, &mut all_decls);

        NameResCtx {
            group_decls, shared_decls, all_decls, builtins,
            peer_module_names, peer_imported_names, file_priv_leak,
        }
    }

    fn check_module(&self, module: &Module, errors: &mut Vec<Diagnostic>) {
        for item in &module.items {
            let file_id = match item {
                Item::Fn(f) => f.span.file_id,
                Item::Test(t) => t.span.file_id,
                Item::Bench(b) => b.span.file_id,
                Item::Const(c) => c.span.file_id,
                Item::Type(t) => t.span.file_id,
                Item::Let(l) => l.span.file_id,
                Item::Lemma(ld) => ld.span.file_id,
            };
            match item {
                Item::Fn(f) => self.walk_fn(f, file_id, errors),
                Item::Test(t) => {
                    let mut scope: Vec<HashSet<String>> = vec![HashSet::new()];
                    self.walk_block(&t.body, file_id, &mut scope, errors);
                }
                // Plan 57: bench body — name-resolution как у test (один
                // общий scope для setup → measure → teardown, потому что
                // setup-bindings видны в measure и teardown).
                Item::Bench(b) => {
                    let mut scope: Vec<HashSet<String>> = vec![HashSet::new()];
                    for s in &b.setup {
                        self.walk_stmt(s, file_id, &mut scope, errors);
                    }
                    self.walk_block(&b.measure_body, file_id, &mut scope, errors);
                    for s in &b.teardown {
                        self.walk_stmt(s, file_id, &mut scope, errors);
                    }
                }
                Item::Const(c) => {
                    let mut scope: Vec<HashSet<String>> = vec![HashSet::new()];
                    self.walk_expr(&c.value, file_id, &mut scope, errors);
                }
                _ => {}
            }
        }
    }

    fn walk_fn(&self, f: &FnDecl, file_id: FileId, errors: &mut Vec<Diagnostic>) {
        // External — нет тела.
        if matches!(f.body, FnBody::External) { return; }
        let mut scope: Vec<HashSet<String>> = vec![HashSet::new()];
        let mut frame: HashSet<String> = HashSet::new();
        // Receiver: self/Self доступны через builtins; нет нужды добавлять.
        if let Some(_recv) = &f.receiver {
            frame.insert("self".to_string());
        }
        for p in &f.params {
            frame.insert(p.name.clone());
        }
        // Generic-params могут использоваться в expr-position? — Нет
        // (по spec). Но безопасно их добавить чтобы не флагать False+
        // если parser/codegen где-то их так трактует.
        for g in &f.generics {
            frame.insert(g.name.clone());
        }
        scope.push(frame);
        match &f.body {
            FnBody::Expr(e) => self.walk_expr(e, file_id, &mut scope, errors),
            FnBody::Block(b) => self.walk_block(b, file_id, &mut scope, errors),
            FnBody::External => {}
        }
        scope.pop();
    }

    fn walk_block(
        &self,
        b: &Block,
        file_id: FileId,
        scope: &mut Vec<HashSet<String>>,
        errors: &mut Vec<Diagnostic>,
    ) {
        scope.push(HashSet::new());
        for s in &b.stmts {
            self.walk_stmt(s, file_id, scope, errors);
        }
        if let Some(t) = &b.trailing {
            self.walk_expr(t, file_id, scope, errors);
        }
        scope.pop();
    }

    fn walk_stmt(
        &self,
        s: &Stmt,
        file_id: FileId,
        scope: &mut Vec<HashSet<String>>,
        errors: &mut Vec<Diagnostic>,
    ) {
        match s {
            Stmt::Expr(e) => self.walk_expr(e, file_id, scope, errors),
            Stmt::Let(d) => {
                // Right-side вычисляется в текущем scope (let не
                // рекурсивный). Затем pattern-bindings добавляются в
                // текущий frame.
                self.walk_expr(&d.value, file_id, scope, errors);
                let mut bindings: HashSet<String> = HashSet::new();
                self.collect_pattern_bindings(&d.pattern, &mut bindings);
                if let Some(top) = scope.last_mut() {
                    for n in bindings { top.insert(n); }
                }
            }
            // Plan 114.4 Ф.2 / Plan 114.4.2 (D199): scope-local const — walk
            // RHS (may reference const fn calls) + bind name в текущий frame
            // так чтобы subsequent expressions могли его использовать.
            Stmt::Const(d) => {
                self.walk_expr(&d.value, file_id, scope, errors);
                if let Some(top) = scope.last_mut() {
                    top.insert(d.name.clone());
                }
            }
            Stmt::Assign { target, value, .. } => {
                self.walk_expr(target, file_id, scope, errors);
                self.walk_expr(value, file_id, scope, errors);
            }
            Stmt::Return { value, .. } => {
                if let Some(v) = value { self.walk_expr(v, file_id, scope, errors); }
            }
            Stmt::Throw { value, .. } => self.walk_expr(value, file_id, scope, errors),
            // D90 (Plan 20): defer/errdefer body — обычный expr в текущем
            // scope. Bindings внутри body локальны их собственным under-scope’ам;
            // на верхнем уровне defer не вводит новых имён.
            Stmt::Defer { body, .. } | Stmt::ErrDefer { body, .. }
            | Stmt::OkDefer { body, .. } | Stmt::DeferWithResult { body, .. } => {
                self.walk_expr(body, file_id, scope, errors);
            }
            // Plan 110 D188: walk init + push new scope frame с binding,
            // walk body, pop frame. Binding visible только внутри body
            // (D188 §«Syntax» single-name binding).
            Stmt::ConsumeScope { binding, init, body, .. } => {
                self.walk_expr(init, file_id, scope, errors);
                scope.push({
                    let mut frame = HashSet::new();
                    frame.insert(binding.clone());
                    frame
                });
                for s in &body.stmts {
                    self.walk_stmt(s, file_id, scope, errors);
                }
                if let Some(t) = &body.trailing {
                    self.walk_expr(t, file_id, scope, errors);
                }
                scope.pop();
            }
            // Plan 33.2 Ф.8: assert_static — walk expr.
            Stmt::AssertStatic { expr, .. } | Stmt::Assume { expr, .. } => self.walk_expr(expr, file_id, scope, errors),
            Stmt::Break(_) | Stmt::Continue(_) => {}
            // Ф.4.1: apply — ghost, args walk для name-resolution.
            Stmt::Apply { args, .. } => {
                for a in args { self.walk_expr(a, file_id, scope, errors); }
            }
            // Ф.4.2: calc — ghost, шаги walk для name-resolution.
            Stmt::Calc { steps, .. } => {
                for step in steps { self.walk_expr(&step.expr, file_id, scope, errors); }
            }
            // Plan 33.9 Ф.2: reveal — ghost, name resolution в pipeline.
            Stmt::Reveal { .. } => {}
            // Plan 136: tuple destructuring assignment.
            Stmt::TupleAssign { lhs, rhs, .. } => {
                for e in lhs { self.walk_expr(e, file_id, scope, errors); }
                for e in rhs { self.walk_expr(e, file_id, scope, errors); }
            }
        }
    }

    fn walk_expr(
        &self,
        e: &Expr,
        file_id: FileId,
        scope: &mut Vec<HashSet<String>>,
        errors: &mut Vec<Diagnostic>,
    ) {
        match &e.kind {
            ExprKind::Ident(name) => {
                if !self.is_known(name, file_id, scope) {
                    // Plan 170 (D307): if the name is file-private to ANOTHER
                    // peer of this module-group, emit the specific leak error.
                    if let Some(owner) = self.file_priv_leak
                        .get(&file_id)
                        .and_then(|m| m.get(name))
                    {
                        errors.push(Diagnostic::new(
                            format!(
                                "[E_FILE_PRIV_LEAK] `{}` is file-private to {}; not \
                                 visible from this file. Remove `priv(file)` from the \
                                 declaration (to make it module-private) or move the \
                                 symbol into this file (D307).",
                                name, owner,
                            ),
                            e.span,
                        ));
                    } else {
                        errors.push(Diagnostic::new(
                            format!("undefined identifier `{}`", name),
                            e.span,
                        ));
                    }
                }
            }
            // Path-form `Module.func` / `Type.method`: head — модуль или
            // type. Plan 42.15 Ф.3: head-segment check для lowercase
            // module-alias'ов (Rule C: peer видит только свои imports).
            //
            // Проверяем ТОЛЬКО lowercase head: Capitalized = тип/effect/
            // variant (cross-file, bootstrap-консервативно пропускаем).
            // lowercase head должен быть: builtin namespace (gc/fibers/
            // runtime) РЛР module-alias в peer's import scope. Если нет —
            // вероятно use чужого import'а (Rule C violation) или typo.
            ExprKind::Path(parts) => {
                if let Some(head) = parts.first() {
                    let is_lowercase = head.chars().next()
                        .map(|c| c.is_ascii_lowercase())
                        .unwrap_or(false);
                    if is_lowercase {
                        let in_builtins = self.builtins.contains(head);
                        let in_peer_modules = self.peer_module_names.get(&file_id)
                            .or_else(|| self.peer_module_names.get(&MAIN_FILE_ID))
                            .map_or(false, |s| s.contains(head));
                        // Также head может быть local binding (struct в
                        // scope) — тогда это фактически Member-access;
                        // парсер иногда эмитит Path. Проверяем scope.
                        let in_scope = scope.iter().rev()
                            .any(|frame| frame.contains(head));
                        if !in_builtins && !in_peer_modules && !in_scope {
                            errors.push(Diagnostic::new(
                                format!(
                                    "undefined module / name `{}` in path expression \
                                     (Rule C: peer sees only its own imports)",
                                    head),
                                e.span,
                            ));
                        }
                    }
                }
            }
            // SelfAccess — `@field` или `@method`. Не Ident.
            ExprKind::SelfAccess => {}

            // Литералы.
            ExprKind::IntLit(_) | ExprKind::FloatLit(_) | ExprKind::BoolLit(_)
            | ExprKind::StrLit(_) | ExprKind::CharLit(_) | ExprKind::UnitLit
            | ExprKind::NullPtrLit => {}

            ExprKind::InterpolatedStr { parts } => {
                for p in parts {
                    if let InterpStrPart::Expr { expr: e, spec: _ } = p {
                        self.walk_expr(e, file_id, scope, errors);
                    }
                }
            }

            ExprKind::Call { func, args, trailing } => {
                // Plan 118.6 Ф.3: addr_of/addr_of_mut removed — emit
                // E_ADDR_OF_REMOVED before undefined-identifier fires.
                if let ExprKind::Ident(n) = &func.kind {
                    if (n == "addr_of" || n == "addr_of_mut") && args.len() == 1 {
                        errors.push(Diagnostic::new(
                            format!(
                                "[E_ADDR_OF_REMOVED] `{}(x)` is removed (Plan 118.6, D216 §4). \
                                 Use `&x` instead.",
                                n,
                            ),
                            func.span,
                        ));
                        // Still walk the argument to catch errors inside it.
                        self.walk_expr(args[0].expr(), file_id, scope, errors);
                        if let Some(t) = trailing {
                            self.walk_trailing(t, file_id, scope, errors);
                        }
                        return;
                    }
                }
                // Special-case: если func — bare Ident, может быть
                // variant-constructor (`Square(5)`) — top_level.contains.
                // is_known покрывает оба варианта (fn + variant).
                self.walk_expr(func, file_id, scope, errors);
                for a in args {
                    self.walk_expr(a.expr(), file_id, scope, errors);
                }
                if let Some(t) = trailing {
                    self.walk_trailing(t, file_id, scope, errors);
                }
            }
            ExprKind::TurboFish { base, .. } => self.walk_expr(base, file_id, scope, errors),
            ExprKind::Try(inner) | ExprKind::Bang(inner) => {
                self.walk_expr(inner, file_id, scope, errors)
            }
            ExprKind::Coalesce(a, b) => {
                self.walk_expr(a, file_id, scope, errors);
                self.walk_expr(b, file_id, scope, errors);
            }
            ExprKind::As(e, _) | ExprKind::Is(e, _) => self.walk_expr(e, file_id, scope, errors),
            ExprKind::Binary { left, right, .. } => {
                self.walk_expr(left, file_id, scope, errors);
                self.walk_expr(right, file_id, scope, errors);
            }
            ExprKind::Unary { operand, .. } => self.walk_expr(operand, file_id, scope, errors),

            // Member-access: проверяем obj (это expr), но НЕ name (field/method).
            ExprKind::Member { obj, .. } => self.walk_expr(obj, file_id, scope, errors),
            ExprKind::Index { obj, index } => {
                self.walk_expr(obj, file_id, scope, errors);
                self.walk_expr(index, file_id, scope, errors);
            }

            ExprKind::If { cond, then, else_ } => {
                self.walk_expr(cond, file_id, scope, errors);
                self.walk_block(then, file_id, scope, errors);
                if let Some(eb) = else_ {
                    match eb {
                        ElseBranch::Block(b) => self.walk_block(b, file_id, scope, errors),
                        ElseBranch::If(e) => self.walk_expr(e, file_id, scope, errors),
                    }
                }
            }
            ExprKind::IfLet { pattern, scrutinee, guard, then, else_ } => {
                self.walk_expr(scrutinee, file_id, scope, errors);
                // Pattern-bindings — в scope для guard и then-branch.
                let mut bindings: HashSet<String> = HashSet::new();
                self.collect_pattern_bindings(pattern, &mut bindings);
                scope.push(bindings);
                if let Some(g) = guard {
                    self.walk_expr(g, file_id, scope, errors);
                }
                self.walk_block(then, file_id, scope, errors);
                scope.pop();
                if let Some(eb) = else_ {
                    match eb {
                        ElseBranch::Block(b) => self.walk_block(b, file_id, scope, errors),
                        ElseBranch::If(e) => self.walk_expr(e, file_id, scope, errors),
                    }
                }
            }
            ExprKind::Match { scrutinee, arms } => {
                self.walk_expr(scrutinee, file_id, scope, errors);
                for arm in arms {
                    let mut bindings: HashSet<String> = HashSet::new();
                    self.collect_pattern_bindings(&arm.pattern, &mut bindings);
                    scope.push(bindings);
                    if let Some(g) = &arm.guard {
                        self.walk_expr(g, file_id, scope, errors);
                    }
                    match &arm.body {
                        MatchArmBody::Expr(e) => self.walk_expr(e, file_id, scope, errors),
                        MatchArmBody::Block(b) => self.walk_block(b, file_id, scope, errors),
                    }
                    scope.pop();
                }
            }
            ExprKind::For { pattern, iter, body, .. } => {
                self.walk_expr(iter, file_id, scope, errors);
                let mut bindings: HashSet<String> = HashSet::new();
                self.collect_pattern_bindings(pattern, &mut bindings);
                scope.push(bindings);
                self.walk_block(body, file_id, scope, errors);
                scope.pop();
            }
            ExprKind::ParallelFor { pattern, iter, body, .. } => {
                self.walk_expr(iter, file_id, scope, errors);
                let mut bindings: HashSet<String> = HashSet::new();
                self.collect_pattern_bindings(pattern, &mut bindings);
                scope.push(bindings);
                self.walk_block(body, file_id, scope, errors);
                scope.pop();
            }
            ExprKind::While { cond, body, .. } => {
                self.walk_expr(cond, file_id, scope, errors);
                self.walk_block(body, file_id, scope, errors);
            }
            ExprKind::WhileLet { pattern, scrutinee, body, .. } => {
                self.walk_expr(scrutinee, file_id, scope, errors);
                let mut bindings: HashSet<String> = HashSet::new();
                self.collect_pattern_bindings(pattern, &mut bindings);
                scope.push(bindings);
                self.walk_block(body, file_id, scope, errors);
                scope.pop();
            }
            ExprKind::Loop { body, .. } => self.walk_block(body, file_id, scope, errors),
            ExprKind::Select { arms } => {
                for arm in arms {
                    match &arm.op {
                        SelectOp::Recv { binding, chan } => {
                            self.walk_expr(chan, file_id, scope, errors);
                            let mut bindings: HashSet<String> = HashSet::new();
                            if let Some(b) = binding { bindings.insert(b.clone()); }
                            scope.push(bindings);
                            if let Some(g) = &arm.guard { self.walk_expr(g, file_id, scope, errors); }
                            self.walk_block(&arm.body, file_id, scope, errors);
                            scope.pop();
                        }
                        SelectOp::Send { chan, value } => {
                            self.walk_expr(chan, file_id, scope, errors);
                            self.walk_expr(value, file_id, scope, errors);
                            if let Some(g) = &arm.guard { self.walk_expr(g, file_id, scope, errors); }
                            self.walk_block(&arm.body, file_id, scope, errors);
                        }
                        SelectOp::Default => {
                            if let Some(g) = &arm.guard { self.walk_expr(g, file_id, scope, errors); }
                            self.walk_block(&arm.body, file_id, scope, errors);
                        }
                    }
                }
            }

            ExprKind::Block(b) => self.walk_block(b, file_id, scope, errors),

            ExprKind::ArrayLit(elems) => {
                for el in elems {
                    match el {
                        ArrayElem::Item(e) | ArrayElem::Spread(e) => {
                            self.walk_expr(e, file_id, scope, errors);
                        }
                    }
                }
            }
            ExprKind::MapLit { elems, .. } => {
                let pairs = crate::ast::MapElem::cloned_pairs(&elems);
                for (k, v) in pairs.iter() {
                    self.walk_expr(k, file_id, scope, errors);
                    self.walk_expr(v, file_id, scope, errors);
                }
            }
            ExprKind::TupleLit(elems) => {
                for e in elems { self.walk_expr(e, file_id, scope, errors); }
            }
            ExprKind::RecordLit { fields, .. } => {
                for f in fields {
                    match &f.value {
                        Some(v) => {
                            // D52 §2 enforcement: redundant `{ name: name }` или
                            // `{ field: @field }` запрещены (shorthand mandatory
                            // когда имя поля совпадает с источником). Spec:
                            // spec/decisions/02-types.md D52 §2.
                            if !f.is_spread && !f.at_shorthand {
                                use crate::ast::ExprKind as EK;
                                let is_redundant_ident = matches!(&v.kind,
                                    EK::Ident(n) if n == &f.name);
                                let is_redundant_self_field = matches!(&v.kind,
                                    EK::Member { obj, name }
                                        if name == &f.name
                                        && matches!(obj.kind, EK::SelfAccess));
                                if is_redundant_ident {
                                    errors.push(Diagnostic::new(
                                        format!(
                                            "избыточная форма поля `{name}: {name}` — \
                                             D52 §2 требует shorthand `{name}` когда имя \
                                             поля совпадает с источником",
                                            name = f.name),
                                        f.span,
                                    ));
                                } else if is_redundant_self_field {
                                    errors.push(Diagnostic::new(
                                        format!(
                                            "избыточная форма поля `{name}: @{name}` — \
                                             D52 §2 требует shorthand `@{name}` когда имя \
                                             поля совпадает с self-полем",
                                            name = f.name),
                                        f.span,
                                    ));
                                }
                            }
                            self.walk_expr(v, file_id, scope, errors);
                        }
                        None => {
                            // Shorthand `{ name }` (D52 field punning):
                            // `name` — это ident, который должен быть
                            // в scope.
                            if !f.is_spread && !self.is_known(&f.name, file_id, scope) {
                                errors.push(Diagnostic::new(
                                    format!("undefined identifier `{}`", f.name),
                                    f.span,
                                ));
                            }
                        }
                    }
                }
            }

            // Tagged-template: tag — это специальный DSL-marker
            // (sql, json, html, ...). В bootstrap'е tag-функция
            // игнорируется (parts конкатенируются), но в production
            // tag — это runtime-функция/macro. Не проверяем tag как
            // Ident — это special-form syntax, не обычный expr-call.
            // Args (`${expr}` интерполяции) — обычные expressions.
            ExprKind::TaggedTemplate { args, .. } => {
                for a in args { self.walk_expr(a, file_id, scope, errors); }
            }

            // Lambda (legacy) / closure-light / closure-full — params
            // push'ятся как новый scope frame.
            ExprKind::Lambda { params, body, .. } => {
                let mut frame: HashSet<String> = HashSet::new();
                for p in params { frame.insert(p.name.clone()); }
                scope.push(frame);
                self.walk_expr(body, file_id, scope, errors);
                scope.pop();
            }
            ExprKind::ClosureLight { params, body } => {
                let mut frame: HashSet<String> = HashSet::new();
                for p in params {
                    if p.name != "_" { frame.insert(p.name.clone()); }
                }
                scope.push(frame);
                match body {
                    crate::ast::ClosureBody::Expr(e) => self.walk_expr(e, file_id, scope, errors),
                    crate::ast::ClosureBody::Block(b) => self.walk_block(b, file_id, scope, errors),
                }
                scope.pop();
            }
            ExprKind::ClosureFull(sb) => {
                let mut frame: HashSet<String> = HashSet::new();
                for p in &sb.params { frame.insert(p.name.clone()); }
                scope.push(frame);
                match &sb.body {
                    FnBody::Expr(e) => self.walk_expr(e, file_id, scope, errors),
                    FnBody::Block(b) => self.walk_block(b, file_id, scope, errors),
                    FnBody::External => {}
                }
                scope.pop();
            }

            ExprKind::With { bindings, body } => {
                // Effect-handler vals — обычные expressions.
                for b in bindings {
                    self.walk_expr(&b.handler, file_id, scope, errors);
                }
                self.walk_block(body, file_id, scope, errors);
            }
            // Plan 97 Ф.4 (D142): protocol-литерал — name-resolution
            // walk идентичен handler-литералу.
            ExprKind::HandlerLit { methods, .. } | ExprKind::ProtocolLit { methods, .. } => {
                // Каждый method — op с собственным scope params.
                for m in methods {
                    let mut frame: HashSet<String> = HashSet::new();
                    for p in &m.params { frame.insert(p.name.clone()); }
                    scope.push(frame);
                    match &m.body {
                        HandlerMethodBody::Expr(e) => self.walk_expr(e, file_id, scope, errors),
                        HandlerMethodBody::Block(b) => self.walk_block(b, file_id, scope, errors),
                    }
                    scope.pop();
                }
            }
            ExprKind::Interrupt(opt) => {
                if let Some(e) = opt { self.walk_expr(e, file_id, scope, errors); }
            }
            ExprKind::Forbid { body, .. } | ExprKind::Realtime { body, .. } => {
                self.walk_block(body, file_id, scope, errors);
            }
            ExprKind::Range { start, end, .. } => {
                if let Some(s) = start { self.walk_expr(s, file_id, scope, errors); }
                if let Some(e) = end { self.walk_expr(e, file_id, scope, errors); }
            }
            ExprKind::Spawn(body) => self.walk_expr(body, file_id, scope, errors),
            ExprKind::Detach(body) | ExprKind::Blocking(body) => {
                self.walk_block(body, file_id, scope, errors);
            }
            ExprKind::Supervised { body, cancel } => {
                // Plan 47: `cancel:` expr — обычное выражение scope'а
                // (типично `Ident` токена); резолвится в текущем scope'е,
                // никаких новых биндингов не вводит.
                if let Some(c) = cancel {
                    self.walk_expr(c, file_id, scope, errors);
                }
                self.walk_block(body, file_id, scope, errors);
            }
            ExprKind::Throw(inner) => self.walk_expr(inner, file_id, scope, errors),
            // D.1.3: квантор — bound variable вводится в scope для body.
            ExprKind::Forall { var, range, body } | ExprKind::Exists { var, range, body } => {
                self.walk_expr(range, file_id, scope, errors);
                let mut frame: HashSet<String> = HashSet::new();
                frame.insert(var.clone());
                scope.push(frame);
                self.walk_expr(body, file_id, scope, errors);
                scope.pop();
            }
        }
    }

    fn walk_trailing(
        &self,
        t: &crate::ast::Trailing,
        file_id: FileId,
        scope: &mut Vec<HashSet<String>>,
        errors: &mut Vec<Diagnostic>,
    ) {
        match t {
            crate::ast::Trailing::Block(b) => self.walk_block(b, file_id, scope, errors),
            crate::ast::Trailing::LegacyBlockWithParams(tb) => {
                let mut frame: HashSet<String> = HashSet::new();
                for p in &tb.params { frame.insert(p.name.clone()); }
                scope.push(frame);
                self.walk_block(&tb.body, file_id, scope, errors);
                scope.pop();
            }
            crate::ast::Trailing::Fn(sb) => {
                let mut frame: HashSet<String> = HashSet::new();
                for p in &sb.params { frame.insert(p.name.clone()); }
                scope.push(frame);
                match &sb.body {
                    FnBody::Expr(e) => self.walk_expr(e, file_id, scope, errors),
                    FnBody::Block(b) => self.walk_block(b, file_id, scope, errors),
                    FnBody::External => {}
                }
                scope.pop();
            }
        }
    }

    /// Собрать все bindings из pattern (только names, без проверки
    /// variant-tag'ов или field-name'ов — это constructor/field
    /// references, не expr-bindings).
    fn collect_pattern_bindings(&self, p: &Pattern, out: &mut HashSet<String>) {
        match p {
            Pattern::Wildcard(_) => {}
            Pattern::Literal(_, _) => {}
            Pattern::Ident { name, .. } => {
                // Edge-case: Pattern::Ident { name: "Some" } — это
                // unit-variant Some? Нет, парсер emit'ит Variant { path:
                // ["Some"], kind: Unit }. Здесь — настоящий binding.
                // Но если имя совпадает с известным variant — считаем
                // это variant-pattern, не binding (D52 семантика
                // pattern-matching). Также Capitalized-имена в bootstrap
                // — это всегда type/variant (cross-file), не binding.
                // Plan 55 fix: all_decls contains free function names (lowercase)
                // which must NOT block for-loop bindings like `for inner in @`.
                // Only treat as variant-like if it's a builtin OR capitalized
                // (Nova convention: variants/types are always PascalCase,
                // free functions are snake_case).
                let is_variant_like = self.builtins.contains(name)
                    || name.chars().next().map(|c| c.is_ascii_uppercase()).unwrap_or(false);
                if !is_variant_like {
                    out.insert(name.clone());
                }
            }
            Pattern::Variant { kind, .. } => {
                // path = variant-tag — не binding.
                match kind {
                    VariantPatternKind::Unit => {}
                    VariantPatternKind::Tuple { patterns, .. } => {
                        for sub in patterns {
                            self.collect_pattern_bindings(sub, out);
                        }
                    }
                }
            }
            Pattern::Record { fields, .. } => {
                for f in fields {
                    match &f.pattern {
                        Some(sub) => self.collect_pattern_bindings(sub, out),
                        // Shorthand `{ name }` — name — это binding
                        // (одновременно field-name и bound variable).
                        None => { out.insert(f.name.clone()); }
                    }
                }
            }
            Pattern::Array { elems, .. } => {
                for el in elems {
                    match el {
                        ArrayPatternElem::Item(sub) => self.collect_pattern_bindings(sub, out),
                        ArrayPatternElem::Rest => {}
                        ArrayPatternElem::RestBind(name) => { out.insert(name.clone()); }
                    }
                }
            }
            Pattern::Tuple(elems, _) => {
                for sub in elems { self.collect_pattern_bindings(sub, out); }
            }
            Pattern::Binding { name, inner, .. } => {
                out.insert(name.clone());
                self.collect_pattern_bindings(inner, out);
            }
            Pattern::Or { alternatives, .. } => {
                // По spec все alternatives имеют одинаковый набор
                // bindings; берём из первого. (Bootstrap-семантика — см.
                // ast::Pattern::Or doc.)
                if let Some(first) = alternatives.first() {
                    self.collect_pattern_bindings(first, out);
                }
            }
        }
    }

    fn is_known(&self, name: &str, file_id: FileId, scope: &[HashSet<String>]) -> bool {
        // Plan 114.4.4 Ф.5 V4: t-reflection intrinsics — built-in
        // const fn names recognized без registration. Replaced литералом
        // в rewriter pass (const_fn_eval.rs).
        if name == "size_of" || name == "align_of" { return true; }
        if self.builtins.contains(name) { return true; }
        // Plan 42.15 Rule C: declarations module-group этого peer'а
        // (peers одного folder-module делят declarations namespace).
        // Fallback на flat shared_decls для legacy/single-file.
        if let Some(gd) = self.group_decls.get(&file_id) {
            if gd.contains(name) { return true; }
        } else if self.shared_decls.contains(name) {
            return true;
        }
        // Plan 42.15: per-peer imported item names — items притащенные
        // прямыми imports РМЕННО этого peer'а. Rule C: imports НЕ shared.
        // Fallback на MAIN_FILE_ID если file_id не найден (legacy).
        let imported = self.peer_imported_names.get(&file_id)
            .or_else(|| self.peer_imported_names.get(&MAIN_FILE_ID));
        if imported.map_or(false, |s| s.contains(name)) { return true; }
        // Plan 42.4 Rule C: per-peer import namespace (module/alias names).
        let module_names = self.peer_module_names.get(&file_id)
            .or_else(|| self.peer_module_names.get(&MAIN_FILE_ID));
        if module_names.map_or(false, |s| s.contains(name)) { return true; }
        for frame in scope.iter().rev() {
            if frame.contains(name) { return true; }
        }
        // Bootstrap-консервативность: имена начинающиеся с заглавной
        // буквы по convention — типы / variants / модули. Bootstrap
        // не имеет cross-file name resolution, поэтому ident вроде
        // `HashMap` (из другого .nv файла) приходит сюда не задекларированным.
        // Чтобы не флагать такие cross-file типы как undefined,
        // пропускаем Capitalized-ident'ы. Опечатки в lowercase
        // именах (snake_case convention для vars/fns) — настоящие
        // undefined и будут ловиться.
        if let Some(c) = name.chars().next() {
            if c.is_ascii_uppercase() { return true; }
        }
        false
    }
}

/// Render method signature `name(p1 T1, p2 T2) -> Ret` — для diagnostic'а.
/// Plan 91.9 (D186): compare T's explicit method signature vs protocol's
/// method requirement. Returns Some(reason) если mismatch, None если ok.
///
/// Strict check:
/// - arity (param count) must match
/// - each param type must match (modulo Self ↔ T receiver-coercion)
/// - return type must match (modulo Self)
///
/// Self в protocol method ↔ T's own type name — допустимо. Generic params
/// в protocol — допустимо в принципе (treated as wildcards), но bootstrap
/// strict-match для simple cases.
fn check_signature_match(
    t_method: &FnDecl,
    proto_method: &crate::ast::EffectMethod,
) -> Option<String> {
    if t_method.params.len() != proto_method.params.len() {
        return Some(format!(
            "arity mismatch: T's `{}` has {} param(s), protocol expects {}",
            t_method.name, t_method.params.len(), proto_method.params.len(),
        ));
    }
    for (tp, pp) in t_method.params.iter().zip(proto_method.params.iter()) {
        let tt = &tp.ty;
        let pt = &pp.ty;
        if !type_refs_equiv_modulo_self(tt, pt, &t_method.receiver.as_ref()
            .map(|r| r.type_name.as_str())
            .unwrap_or(""))
        {
            return Some(format!(
                "param `{}`: T has `{}`, protocol expects `{}`",
                tp.name, render_type_ref(tt), render_type_ref(pt),
            ));
        }
    }
    let t_ret = t_method.return_type.as_ref();
    let p_ret = proto_method.return_type.as_ref();
    let recv_name = t_method.receiver.as_ref()
        .map(|r| r.type_name.as_str()).unwrap_or("");
    // None ↔ Unit equivalence: both forms `fn foo()` и `fn foo() -> ()`
    // declare unit-returning method. Treated identically.
    let is_unit_or_none = |r: Option<&TypeRef>| -> bool {
        match r {
            None => true,
            Some(TypeRef::Unit(_)) => true,
            _ => false,
        }
    };
    if is_unit_or_none(t_ret) && is_unit_or_none(p_ret) {
        return None;
    }
    match (t_ret, p_ret) {
        (Some(a), Some(b)) => {
            if !type_refs_equiv_modulo_self(a, b, recv_name) {
                return Some(format!(
                    "return type: T returns `{}`, protocol expects `{}`",
                    render_type_ref(a), render_type_ref(b),
                ));
            }
        }
        _ => return Some(format!(
            "return type: T returns `{}`, protocol expects `{}`",
            t_ret.map(render_type_ref).unwrap_or_else(|| "()".into()),
            p_ret.map(render_type_ref).unwrap_or_else(|| "()".into()),
        )),
    }
    None
}

/// Plan 164 Ф.1: apply a generic substitution map to a TypeRef string.
///
/// `subst` maps protocol generic param names to their impl counterparts,
/// e.g. [("T", "U")]. We operate on `render_type_ref` strings for simplicity:
/// replace whole-word occurrences of each proto param with the impl arg.
fn apply_subst_to_type_str(s: &str, subst: &[(String, String)]) -> String {
    let mut result = s.to_string();
    for (proto_param, impl_arg) in subst {
        // Replace whole-word occurrences: surrounded by non-ident chars.
        let mut out = String::new();
        let mut i = 0;
        let bytes = result.as_bytes();
        while i < bytes.len() {
            let is_ident_start = |b: u8| b.is_ascii_alphabetic() || b == b'_';
            if bytes[i..].starts_with(proto_param.as_bytes()) {
                let end = i + proto_param.len();
                let before_ok = i == 0 || !is_ident_start(bytes[i - 1]);
                let after_ok = end >= bytes.len() || !is_ident_start(bytes[end]);
                if before_ok && after_ok {
                    out.push_str(impl_arg);
                    i = end;
                    continue;
                }
            }
            out.push(bytes[i] as char);
            i += 1;
        }
        result = out;
    }
    result
}

/// Plan 164 Ф.1: normalize a rendered type string for whitespace-insensitive
/// comparison. Removes spaces immediately after `,`, `[`, `(` and before `]`,
/// `)` so that `render_type_ref`-produced `"(int, T)"` and the raw-source
/// `"(int,T)"` compare equal.
fn normalize_type_str(s: &str) -> String {
    // Replace all whitespace sequences with a single space, then strip spaces
    // adjacent to punctuation characters in type positions.
    let mut out = String::with_capacity(s.len());
    let mut prev_was_punct = false;
    for ch in s.chars() {
        if ch.is_whitespace() {
            // Suppress space if the previous non-space char was a punctuation
            // or if we haven't started yet; we'll decide once we see the next
            // non-space char.
            if !prev_was_punct && !out.is_empty() {
                out.push(' '); // tentative space
            }
            // Mark: the tentative space may get removed if next char is punct.
        } else {
            let is_punct = matches!(ch, '[' | ']' | '(' | ')' | ',');
            if is_punct {
                // Remove any trailing space we just added.
                if out.ends_with(' ') {
                    out.pop();
                }
                out.push(ch);
                prev_was_punct = true;
            } else {
                // If the previous char was a closing punct and we have a space,
                // the space is valid (e.g. "Option[T]" vs method names).
                prev_was_punct = false;
                out.push(ch);
            }
        }
    }
    // Trailing spaces.
    while out.ends_with(' ') { out.pop(); }
    out
}

/// Plan 164 Ф.1: signature match with optional generic substitution.
///
/// Like `check_signature_match` but applies `subst` to the protocol method's
/// types before comparison. If `subst` is empty, falls back to the original
/// behaviour (for backward compat with non-generic `#impl(Display)`).
fn check_signature_match_with_subst(
    t_method: &FnDecl,
    proto_method: &crate::ast::EffectMethod,
    subst: &[(String, String)],
) -> Option<String> {
    if subst.is_empty() {
        return check_signature_match(t_method, proto_method);
    }
    if t_method.params.len() != proto_method.params.len() {
        return Some(format!(
            "arity mismatch: T's `{}` has {} param(s), protocol expects {}",
            t_method.name, t_method.params.len(), proto_method.params.len(),
        ));
    }
    let recv_name = t_method.receiver.as_ref()
        .map(|r| r.type_name.as_str()).unwrap_or("");
    for (tp, pp) in t_method.params.iter().zip(proto_method.params.iter()) {
        let tt_str = render_type_ref(&tp.ty);
        let pt_str = apply_subst_to_type_str(&render_type_ref(&pp.ty), subst);
        // Plan 164 Ф.1: normalize whitespace before comparing — render produces
        // "( int, T )" with spaces; raw-source subst may produce "(int,T)".
        let tt_norm = normalize_type_str(&tt_str);
        let pt_norm = normalize_type_str(&pt_str);
        // Also accept Self ↔ recv_name equivalence.
        if tt_norm != pt_norm {
            let pt_self = pt_str == "Self" && tt_str == recv_name;
            let tt_self = tt_str == "Self" && pt_str == recv_name;
            if !pt_self && !tt_self {
                return Some(format!(
                    "param `{}`: T has `{}`, protocol expects `{}`",
                    tp.name, tt_str, pt_str,
                ));
            }
        }
    }
    let t_ret = t_method.return_type.as_ref();
    let p_ret = proto_method.return_type.as_ref();
    let is_unit_or_none = |r: Option<&TypeRef>| -> bool {
        matches!(r, None | Some(TypeRef::Unit(_)))
    };
    if is_unit_or_none(t_ret) && is_unit_or_none(p_ret) {
        return None;
    }
    match (t_ret, p_ret) {
        (Some(a), Some(b)) => {
            let a_str = render_type_ref(a);
            let b_str = apply_subst_to_type_str(&render_type_ref(b), subst);
            // Plan 164 Ф.1: normalize before comparison — tuple types with spaces.
            let a_norm = normalize_type_str(&a_str);
            let b_norm = normalize_type_str(&b_str);
            if a_norm != b_norm {
                let b_self = b_str == "Self" && a_str == recv_name;
                let a_self = a_str == "Self" && b_str == recv_name;
                if !b_self && !a_self {
                    return Some(format!(
                        "return type: T returns `{}`, protocol expects `{}`",
                        a_str, b_str,
                    ));
                }
            }
        }
        _ => return Some(format!(
            "return type: T returns `{}`, protocol expects `{}`",
            t_ret.map(render_type_ref).unwrap_or_else(|| "()".into()),
            p_ret.as_ref().map(|b| apply_subst_to_type_str(&render_type_ref(b), subst))
                .unwrap_or_else(|| "()".into()),
        )),
    }
    None
}

/// Plan 108.4 Ф.2: Check receiver-mutability match between T's implementation method
/// and the protocol's method declaration.
///
/// Returns Some((method_name, error_code, proto_qualifier, fix_hint)) on mismatch, None on match.
///
/// Match rules (proto → impl):
///   ro       (receiver_mut=false, receiver_consume=false) → impl ro   → OK
///   mut      (receiver_mut=true,  receiver_consume=false) → impl mut  → OK
///   consume  (receiver_mut=false, receiver_consume=true)  → impl consume → OK
///   All other combinations → mismatch → one of the 4 E_PROTO_IMPL_* errors.
fn check_receiver_mut_match(
    t_method: &FnDecl,
    proto_method: &crate::ast::EffectMethod,
    _proto_name: &str,
    _type_name: &str,
) -> Option<(String, &'static str, String, String)> {
    // Determine proto receiver qualifier.
    let proto_consume = proto_method.receiver_consume;
    let proto_mut     = proto_method.receiver_mut;
    // Determine impl receiver qualifier from FnDecl.receiver.
    let (impl_mut, impl_consume) = t_method.receiver.as_ref()
        .map(|r| (r.mutable, r.consume))
        .unwrap_or((false, false));
    // Build a string describing the protocol's declared qualifier (for messages).
    let proto_qual = if proto_consume {
        "consume".to_string()
    } else if proto_mut {
        "mut".to_string()
    } else {
        "ro".to_string()  // default (no prefix = ro)
    };
    // Match table:
    if proto_consume {
        // Protocol requires consume receiver.
        if impl_consume {
            return None; // OK
        }
        // impl is mut or ro — wrong; both cases use E_PROTO_IMPL_MUT_FOR_CONSUME
        // (plan: "protocol `consume @m()`, impl mut/ro" → same error code).
        let tname_c = t_method.receiver.as_ref().map(|r| r.type_name.as_str()).unwrap_or("T");
        let impl_qual = if impl_mut { "mut " } else { "" };
        let (code, fix) = (
            "E_PROTO_IMPL_MUT_FOR_CONSUME",
            format!("Change `fn {} {}@{}(...)` to `fn {} consume @{}(...)`.",
                    tname_c, impl_qual, t_method.name, tname_c, t_method.name),
        );
        return Some((t_method.name.clone(), code, proto_qual, fix));
    }
    if proto_mut {
        // Protocol requires mut receiver.
        if impl_mut {
            return None; // OK
        }
        // impl is consume → E_PROTO_IMPL_CONSUME_FOR_MUT
        // impl is ro      → E_PROTO_IMPL_RO_FOR_MUT
        let tname = t_method.receiver.as_ref().map(|r| r.type_name.as_str()).unwrap_or("T");
        let (code, fix) = if impl_consume {
            ("E_PROTO_IMPL_CONSUME_FOR_MUT",
             format!("Change `fn {} consume @{}(...)` to `fn {} mut @{}(...)`.",
                     tname, t_method.name, tname, t_method.name))
        } else {
            ("E_PROTO_IMPL_RO_FOR_MUT",
             format!("Change `fn {} @{}(...)` to `fn {} mut @{}(...)`.",
                     tname, t_method.name, tname, t_method.name))
        };
        return Some((t_method.name.clone(), code, proto_qual, fix));
    }
    // Protocol requires ro receiver (default).
    if !impl_mut && !impl_consume {
        return None; // OK — both ro
    }
    let tname = t_method.receiver.as_ref().map(|r| r.type_name.as_str()).unwrap_or("T");
    let (code, fix) = if impl_mut {
        ("E_PROTO_IMPL_MUT_FOR_RO",
         format!("Change `fn {} mut @{}(...)` to `fn {} @{}(...)`.",
                 tname, t_method.name, tname, t_method.name))
    } else {
        // impl_consume — protocol says ro but impl is consume; treat as MUT_FOR_RO variant
        ("E_PROTO_IMPL_MUT_FOR_RO",
         format!("Change `fn {} consume @{}(...)` to `fn {} @{}(...)`.",
                 tname, t_method.name, tname, t_method.name))
    };
    Some((t_method.name.clone(), code, proto_qual, fix))
}

/// Two TypeRefs are equivalent if textually equal, OR one is `Self`
/// and the other is `recv_name` (or vice versa).
fn type_refs_equiv_modulo_self(a: &TypeRef, b: &TypeRef, recv_name: &str) -> bool {
    let is_self = |t: &TypeRef| matches!(t, TypeRef::Named { path, .. }
        if path.len() == 1 && path[0] == "Self");
    let is_recv = |t: &TypeRef| matches!(t, TypeRef::Named { path, .. }
        if path.len() == 1 && path[0] == recv_name);
    if is_self(a) && (is_self(b) || is_recv(b)) { return true; }
    if is_self(b) && (is_self(a) || is_recv(a)) { return true; }
    render_type_ref(a) == render_type_ref(b)
}

fn render_method_sig(name: &str, params: &[Param], ret: &Option<TypeRef>) -> String {
    let p_strs: Vec<String> = params.iter().map(|p| {
        format!("{} {}", p.name, render_type_ref(&p.ty))
    }).collect();
    let r = ret.as_ref().map(|t| format!(" -> {}", render_type_ref(t))).unwrap_or_default();
    format!("{}({}){}", name, p_strs.join(", "), r)
}

fn render_type_ref(t: &TypeRef) -> String {
    match t {
        TypeRef::Named { path, generics, .. } => {
            if generics.is_empty() {
                path.join(".")
            } else {
                let g: Vec<String> = generics.iter().map(render_type_ref).collect();
                format!("{}[{}]", path.join("."), g.join(", "))
            }
        }
        TypeRef::Array(inner, _) => format!("[]{}", render_type_ref(inner)),
        TypeRef::FixedArray(n, inner, _) => format!("[{}]{}", n, render_type_ref(inner)),
        TypeRef::Tuple(items, _) => {
            let s: Vec<String> = items.iter().map(render_type_ref).collect();
            format!("({})", s.join(", "))
        }
        TypeRef::Func { params, return_type, .. } => {
            let p: Vec<String> = params.iter().map(render_type_ref).collect();
            let r = return_type.as_ref().map(|t| format!(" -> {}", render_type_ref(t))).unwrap_or_default();
            format!("fn({}){}", p.join(", "), r)
        }
        // Plan 97 Ф.2 (D142): анонимный protocol-тип — пишется через
        // render_method_sig, чтобы R5.3 diagnostic'и видели полную
        // сигнатуру inline-protocol bound'а.
        TypeRef::Protocol { methods, .. } => {
            let sigs: Vec<String> = methods
                .iter()
                .map(|m| {
                    let prefix = if m.is_static { "." } else { "" };
                    let full = render_method_sig(&m.name, &m.params, &m.return_type);
                    format!("{}{}", prefix, full)
                })
                .collect();
            format!("protocol {{ {} }}", sigs.join("; "))
        }
        TypeRef::Unit(_) => "()".to_string(),
        // D176 (Plan 108): readonly T — display as "readonly T"
        TypeRef::Readonly(inner, _) => format!("ro {}", render_type_ref(inner)),
        // Plan 118 D216 §1 / Plan 118.5 V2 (2026-06-04): typed pointer
        // `*T` family — split into three AST wrapper arms after V2 amend.
        //   - Pointer(T, _)    → `* T` (canonical readonly)
        //   - Mut(inner, _)    → `mut <inner>` (right-binding wrapper)
        //   - Unsafe(inner, _) → `unsafe <inner>` (right-binding wrapper)
        TypeRef::Pointer(inner, _) => format!("* {}", render_type_ref(inner)),
        TypeRef::Mut(inner, _) => format!("mut {}", render_type_ref(inner)),
        TypeRef::Unsafe(inner, _) => format!("unsafe {}", render_type_ref(inner)),
    }
}

/// D28 effect inference для private fn.
///
/// Walk модуль mutably: для каждой private (`!is_export`) fn,
/// если её тело использует `throw`, и в effect-row нет ни одного
/// `Fail`/`Fail[E]`/`Fail[any]` — добавляем `Fail` (placeholder).
///
/// Это упрощённая реализация D28 для bootstrap'а:
/// - Полная version выводила бы конкретный E из type-of(throw expr).
///   Bootstrap не имеет точного типизатора, поэтому выводит просто
///   `Fail` (placeholder, по D65 — inference placeholder).
/// - Для public fn ничего не делаем (D62: явная декларация обязательна).
/// - Транзитивная inference (callee имеет Fail → caller тоже) не
///   реализована; программист должен явно импортировать.
///
/// Эффекты типа Db/Net/Time/etc. **не** добавляются автоматически —
/// они resource-capability и должны быть видны в сигнатуре, программист
/// объявляет явно. Только Fail имеет особый placeholder-режим.
pub fn infer_effects(module: &mut Module) {
    for item in &mut module.items {
        if let Item::Fn(f) = item {
            if f.is_export {
                continue;
            }
            if has_throw_in_fn(f) && !has_fail_effect(&f.effects) {
                let span = f.span;
                f.effects.push(TypeRef::Named {
                    path: vec!["Fail".to_string()],
                    generics: vec![],
                    span,
                });
            }
        }
    }
}

/// Есть ли хотя бы один `Fail`/`Fail[...]` в effect-row.
fn has_fail_effect(effects: &[TypeRef]) -> bool {
    effects.iter().any(|e| {
        matches!(e, TypeRef::Named { path, .. } if path.len() == 1 && path[0] == "Fail")
    })
}

/// Содержит ли тело fn выражение `throw` (рекурсивно).
fn has_throw_in_fn(f: &FnDecl) -> bool {
    match &f.body {
        FnBody::Expr(e) => has_throw_in_expr(e),
        FnBody::Block(b) => has_throw_in_block(b),
        // D82: external fn — тела нет; throw'ы декларируются через
        // Fail[E] effect-аннотацию в сигнатуре, не в теле.
        FnBody::External => false,
    }
}

fn has_throw_in_block(b: &Block) -> bool {
    for s in &b.stmts {
        if has_throw_in_stmt(s) {
            return true;
        }
    }
    if let Some(t) = &b.trailing {
        if has_throw_in_expr(t) {
            return true;
        }
    }
    false
}

fn has_throw_in_stmt(s: &Stmt) -> bool {
    match s {
        Stmt::Expr(e) => has_throw_in_expr(e),
        Stmt::Let(decl) => has_throw_in_expr(&decl.value),
        Stmt::Const(_) => false,
        Stmt::Assign { target, value, .. } =>
            has_throw_in_expr(target) || has_throw_in_expr(value),
        Stmt::Return { value, .. } => value.as_ref().map_or(false, has_throw_in_expr),
        Stmt::Throw { value, .. } => {
            // Statement-level throw: явный сигнал, что Fail нужен.
            let _ = value;
            true
        }
        Stmt::Break(_) | Stmt::Continue(_) => false,
        // D90: defer/errdefer body **запрещают** throw внутри (Ф.3
        // body-constraint). Throw в body — compile error. Поэтому
        // body не считается throw-носителем — он отдельный scope с
        // ограничением. Если в body throw обнаружен — Ф.3 даст
        // отдельную compile error раньше этой проверки.
        Stmt::Defer { .. } | Stmt::ErrDefer { .. }
        | Stmt::OkDefer { .. } | Stmt::DeferWithResult { .. } => false,
        // Plan 110 D188: consume scope-block body может содержать throw —
        // D188 R3 cancel-shield масаит throw к caller'у после on_exit;
        // для has_throw analysis считаем body как throw-носитель.
        Stmt::ConsumeScope { init, body, .. } => {
            if has_throw_in_expr(init) { return true; }
            for s in &body.stmts {
                if has_throw_in_stmt(s) { return true; }
            }
            body.trailing.as_ref().map_or(false, |t| has_throw_in_expr(t))
        }
        // Plan 33.2 Ф.8: assert_static — bool expr, no throw inside.
        Stmt::AssertStatic { expr, .. } | Stmt::Assume { expr, .. } => has_throw_in_expr(expr),
        // Ф.4.1: apply — ghost, args могут содержать throw (теоретически нет, но проверяем).
        Stmt::Apply { args, .. } => args.iter().any(has_throw_in_expr),
        // Ф.4.2: calc — ghost, шаги могут содержать throw.
        Stmt::Calc { steps, .. } => steps.iter().any(|s| has_throw_in_expr(&s.expr)),
        // Plan 33.9 Ф.2: reveal — ghost, no throw inside.
        Stmt::Reveal { .. } => false,
        // Plan 136: tuple destructuring assignment — check all lhs + rhs.
        Stmt::TupleAssign { lhs, rhs, .. } => {
            lhs.iter().any(has_throw_in_expr) || rhs.iter().any(has_throw_in_expr)
        }
    }
}

fn has_throw_in_expr(e: &Expr) -> bool {
    match &e.kind {
        ExprKind::Throw(_) => true,
        ExprKind::Try(inner) => has_throw_in_expr(inner),
        // Plan 19, C7 (D85): `!!` тоже может бросить (`Err`/`None`).
        ExprKind::Bang(inner) => has_throw_in_expr(inner),
        ExprKind::Binary { left, right, .. } =>
            has_throw_in_expr(left) || has_throw_in_expr(right),
        ExprKind::Unary { operand, .. } => has_throw_in_expr(operand),
        ExprKind::Call { func, args, .. } =>
            has_throw_in_expr(func) || args.iter().any(|a| has_throw_in_expr(a.expr())),
        ExprKind::Member { obj, .. } => has_throw_in_expr(obj),
        ExprKind::Index { obj, index } =>
            has_throw_in_expr(obj) || has_throw_in_expr(index),
        ExprKind::If { cond, then, else_, .. } => {
            if has_throw_in_expr(cond) || has_throw_in_block(then) { return true; }
            match else_ {
                Some(ElseBranch::Block(b)) => has_throw_in_block(b),
                Some(ElseBranch::If(e)) => has_throw_in_expr(e),
                None => false,
            }
        }
        ExprKind::IfLet { scrutinee, then, else_, .. } => {
            if has_throw_in_expr(scrutinee) || has_throw_in_block(then) { return true; }
            match else_ {
                Some(ElseBranch::Block(b)) => has_throw_in_block(b),
                Some(ElseBranch::If(e)) => has_throw_in_expr(e),
                None => false,
            }
        }
        ExprKind::Match { scrutinee, arms } => {
            if has_throw_in_expr(scrutinee) { return true; }
            arms.iter().any(|arm| match &arm.body {
                MatchArmBody::Expr(e) => has_throw_in_expr(e),
                MatchArmBody::Block(b) => has_throw_in_block(b),
            })
        }
        ExprKind::While { cond, body, .. } => has_throw_in_expr(cond) || has_throw_in_block(body),
        ExprKind::WhileLet { scrutinee, body, .. } =>
            has_throw_in_expr(scrutinee) || has_throw_in_block(body),
        ExprKind::For { iter, body, .. } => has_throw_in_expr(iter) || has_throw_in_block(body),
        ExprKind::Loop { body, .. } => has_throw_in_block(body),
        ExprKind::Select { arms } => arms.iter().any(|a| {
            (match &a.op {
                SelectOp::Recv { chan, .. } => has_throw_in_expr(chan),
                SelectOp::Send { chan, value } => has_throw_in_expr(chan) || has_throw_in_expr(value),
                SelectOp::Default => false,
            }) || a.guard.as_ref().map_or(false, has_throw_in_expr)
              || has_throw_in_block(&a.body)
        }),
        ExprKind::Block(b) => has_throw_in_block(b),
        ExprKind::Lambda { .. } => false,
            // Lambda has its own scope; throw inside lambda — её эффекты, не текущей fn.
        ExprKind::Range { start, end, .. } =>
            start.as_deref().map_or(false, has_throw_in_expr)
                || end.as_deref().map_or(false, has_throw_in_expr),
        ExprKind::TupleLit(elems) => elems.iter().any(has_throw_in_expr),
        ExprKind::ArrayLit(elems) => elems.iter().any(|el| match el {
            ArrayElem::Item(e) => has_throw_in_expr(e),
            ArrayElem::Spread(e) => has_throw_in_expr(e),
        }),
        ExprKind::RecordLit { fields, .. } =>
            fields.iter().any(|f| f.value.as_ref().map_or(false, has_throw_in_expr)),
        ExprKind::With { bindings, body } => {
            if bindings.iter().any(|b| has_throw_in_expr(&b.handler)) { return true; }
            has_throw_in_block(body)
        }
        ExprKind::Spawn(e) => has_throw_in_expr(e),
        ExprKind::Supervised { body, cancel } => {
            has_throw_in_block(body)
                || cancel.as_ref().map_or(false, |c| has_throw_in_expr(c))
        }
        ExprKind::ParallelFor { iter, body, .. } =>
            has_throw_in_expr(iter) || has_throw_in_block(body),
        ExprKind::TurboFish { base, .. } => has_throw_in_expr(base),
        _ => false,
    }
}

// Plan 172.1 U.5.4: `ty_of_ref` (TypeRef → lossy `Ty`) was deleted — its sole consumer
// (the `never` propagation check) now uses `ResolvedType::from_type_ref` (which mirrors
// `ty_of_ref`'s `never`/collapse rules losslessly). `Ty` enum deleted with it.

/// D84: structural equality для TypeRef (игнорирует Span'ы).
///
/// Рспользуется для detection дублированных signatures свободных
/// функций — "точное совпадение" arity + arg-types запрещено как
/// ambiguous overload без возможности резолва.
///
/// Не использует PartialEq/Eq derive потому что TypeRef содержит
/// Span'ы (позиции в исходнике), которые отличаются у разных
/// определений того же типа.
fn typeref_equal(a: &TypeRef, b: &TypeRef) -> bool {
    match (a, b) {
        (
            TypeRef::Named { path: pa, generics: ga, .. },
            TypeRef::Named { path: pb, generics: gb, .. },
        ) => {
            pa == pb
                && ga.len() == gb.len()
                && ga.iter().zip(gb.iter()).all(|(x, y)| typeref_equal(x, y))
        }
        (TypeRef::Array(ia, _), TypeRef::Array(ib, _)) => typeref_equal(ia, ib),
        (TypeRef::FixedArray(na, ia, _), TypeRef::FixedArray(nb, ib, _)) => {
            na == nb && typeref_equal(ia, ib)
        }
        (TypeRef::Tuple(ea, _), TypeRef::Tuple(eb, _)) => {
            ea.len() == eb.len()
                && ea.iter().zip(eb.iter()).all(|(x, y)| typeref_equal(x, y))
        }
        (
            TypeRef::Func { params: pa, return_type: ra, effects: ea, .. },
            TypeRef::Func { params: pb, return_type: rb, effects: eb, .. },
        ) => {
            pa.len() == pb.len()
                && pa.iter().zip(pb.iter()).all(|(x, y)| typeref_equal(x, y))
                && match (ra.as_deref(), rb.as_deref()) {
                    (Some(x), Some(y)) => typeref_equal(x, y),
                    (None, None) => true,
                    _ => false,
                }
                && ea.len() == eb.len()
                && ea.iter().zip(eb.iter()).all(|(x, y)| typeref_equal(x, y))
        }
        (TypeRef::Unit(_), TypeRef::Unit(_)) => true,
        // D176 (Plan 108): readonly T == readonly T if inner equal.
        (TypeRef::Readonly(ia, _), TypeRef::Readonly(ib, _)) => typeref_equal(ia, ib),
        // Plan 118.1.6: V2 modifier wrappers — Pointer/Mut/Unsafe must compare
        // structurally with their inner types. Без этих арм две одинаковые
        // подписи с *T / mut T / unsafe T силкомо не считаются равными,
        // ломая duplicate-signature detection и breaking coercion checks
        // (E_UNSAFE_FN_PTR_COERCION ниже полагается на структурное сравнение
        // outer Unsafe wrapper).
        (TypeRef::Pointer(ia, _), TypeRef::Pointer(ib, _)) => typeref_equal(ia, ib),
        (TypeRef::Mut(ia, _), TypeRef::Mut(ib, _)) => typeref_equal(ia, ib),
        (TypeRef::Unsafe(ia, _), TypeRef::Unsafe(ib, _)) => typeref_equal(ia, ib),
        _ => false,
    }
}

/// [M-generic-arg-type-mismatch-silent] — extract `(base-name, type-arguments)`
/// from ANY generic type: a user `Stack[T]` / `Map[K,V]` / `Box[T]` as well as
/// the builtin `Vec[T]` and its `[]T` array sugar. Deliberately NOT Vec-specific:
/// the silent element-reinterpretation bug applies to every generic type — a
/// `Stack[int]` passed where `Stack[u32]` is expected is the same
/// pointer-reinterpretation footgun as `Vec[int]`→`Vec[u32]`.
///
/// The `[]T` array form normalizes to base `"Vec"` (D239: `[]T ≡ Vec[T]`) so the
/// two spellings of the one builtin compare equal. Peels `ro`/`mut` binding
/// wrappers. Returns `None` for non-generic types (bare names, primitives,
/// tuples, …) — the caller then skips the check.
fn generic_args(tr: &TypeRef) -> Option<(String, Vec<&TypeRef>)> {
    match tr {
        TypeRef::Readonly(inner, _) | TypeRef::Mut(inner, _) => generic_args(inner),
        TypeRef::Array(inner, _) => Some(("Vec".to_string(), vec![inner.as_ref()])),
        TypeRef::FixedArray(_, inner, _) => Some(("Vec".to_string(), vec![inner.as_ref()])),
        TypeRef::Named { path, generics, .. } if !generics.is_empty() => {
            Some((path.last()?.clone(), generics.iter().collect()))
        }
        _ => None,
    }
}

// [M-generic-arg-type-mismatch-silent] U.5.3: `is_type_param_name` (→ `Any` in
// `resolved_cat_of`) and `concrete_primitive_name` (→ structural eq of primitive
// `ResolvedType` leaves) were folded into `distinct_mono` and deleted.

// ============================================================================
// D90 Plan 20 Ф.3: defer/errdefer body constraints
// ============================================================================
//
// Body запрещает три категории конструкций:
//
// 1. **Exit-control:** `return`, `throw`, `break`, `continue` нельзя
//    использовать в defer body — defer часть exit-процесса, не может
//    hijack его. Compile error: «defer body cannot use ... — это
//    нарушит exit семантику scope'а».
//
// 2. **Fail-effect:** `?`, `!!`, `throw` desugar'ятся в throw через
//    эффект Fail. Defer body должно быть infallible — double-throw
//    невозможно сделать корректно. Detection через AST-walk
//    (ExprKind::Throw, ExprKind::Try, ExprKind::Bang).
//
// 3. **Suspend operations:** Net.*, Fs.*, Db.*, Time.sleep,
//    Channel.recv (blocking), parallel for, spawn, supervised, select.
//    Defer должен быть быстрым cleanup — suspend делает exit-семантику
//    непредсказуемой. Detection: AST-форма (ParallelFor, Spawn,
//    Supervised) + callee.effects intersect с SUSPEND_EFFECTS списком.

/// Эффекты, которые считаются suspend в контексте defer body.
/// Это approximation для bootstrap — D90 spec говорит «cleanup быстрый»,
/// безопаснее запретить целую группу чем пытаться различить
/// blocking vs non-blocking варианты для каждого эффекта.
const SUSPEND_EFFECT_NAMES: &[&str] = &[
    "Net", "Fs", "Db", "Time",
];

/// AST-формы которые сами по себе считаются suspend (даже если effects
/// не объявлены).
///
/// **Reserved**: текущая suspend-detection использует прямой
/// `matches!` inline в effect-inference path'е. Helper сохранён для
/// возможной consolidation если правил станет больше.
#[allow(dead_code)]
fn is_suspend_expr_kind(kind: &ExprKind) -> bool {
    matches!(kind,
        ExprKind::ParallelFor { .. }
        | ExprKind::Spawn(_)
        | ExprKind::Supervised { .. }
        | ExprKind::Detach(_)
        | ExprKind::Blocking(_)
    )
}

/// D90 Ф.8 (1): walk модуля, для каждого `HandlerLit { methods }`
/// проверяет, что methods обрабатывающие never-operations завершаются
/// exit-control'ом.
///
/// never-operation = operation, чей return type — `never`. Handler-method
/// для такой operation не может завершиться normally (нет значения типа
/// never). По D61 (стр. 1430-1434) body обязан `interrupt v`, `throw err`,
/// `panic(...)` или `exit(...)`.
///
/// Bootstrap-stage: знаем что built-in `Fail.fail(value) -> never` —
/// единственная never-operation в prelude. Hardcoded effect_name="Fail",
/// method_name="fail". User-defined effects с never-methods будут покрыты
/// общей effect-schema-аналитикой (Plan 25+).
fn check_handler_never_ops(module: &Module, errors: &mut Vec<Diagnostic>) {
    // Сбор: какие user-defined effect-methods имеют return type never.
    // Bootstrap: только Fail.fail — встроенный. User effects парсятся
    // через TypeDecl::Effect — анализируем их EffectMethod.return_type.
    let mut never_ops: HashSet<(String, String)> = HashSet::new();
    // Always-true: built-in Fail.fail.
    never_ops.insert(("Fail".to_string(), "fail".to_string()));
    // User-defined effects.
    for item in &module.items {
        if let Item::Type(td) = item {
            if let TypeDeclKind::Effect(methods) = &td.kind {
                for m in methods {
                    if let Some(rt) = &m.return_type {
                        if type_ref_is_never(rt) {
                            never_ops.insert((td.name.clone(), m.name.clone()));
                        }
                    }
                }
            }
        }
    }
    // Walk all expressions, найдём HandlerLit'ы.
    for item in &module.items {
        match item {
            Item::Fn(f) => {
                if let FnBody::Block(b) = &f.body {
                    walk_block_for_handler_lits(b, &never_ops, errors);
                } else if let FnBody::Expr(e) = &f.body {
                    walk_expr_for_handler_lits(e, &never_ops, errors);
                }
            }
            Item::Test(t) => walk_block_for_handler_lits(&t.body, &never_ops, errors),
            _ => {}
        }
    }
}

/// Plan 33.3 Ф.9.6 (D24): handler verification gate.
///
/// Если эффект имеет хотя бы одну `pure_view` op'у, любое использование
/// handler'а через `with E = h` обязано декларировать verification
/// статус через `#verify_handler` или `#trusted_handler`. Без атрибута —
/// compile error.
///
/// Семантика:
/// - `#verify_handler` — symbolic verification handler.action body
///   против axiom'ов эффекта (Ф.9.7). Bootstrap V1: атрибут принимается
///   но реальной верификации нет — placeholder для Ф.9.7.
/// - `#trusted_handler` — программист берёт ответственность.
/// - Default (Unverified) для эффектов с pure_views — **error**.
///
/// Эффекты БЕЗ pure_views — никаких ограничений (default = Unverified
/// допустим).
///
/// Эта проверка консервативна: даже если body не вызывает pure_view-
/// using функции, gate всё равно требует attribute для эффекта с
/// pure_views. Это упрощает V1 (нет cross-fn analysis); Ф.9.7
/// уточнит до actually-uses analysis.
fn check_handler_verification_gate(module: &Module, errors: &mut Vec<Diagnostic>) {
    // Шаг 1: какие эффекты имеют axioms?
    // Refactor: gate срабатывает только при axiom-присутствии — pure_view сам по
    // себе ничего не утверждает, утверждение делает axiom. Без axiom handler
    // верифицировать не на что.
    let mut effects_with_axioms: HashSet<String> = HashSet::new();
    for item in &module.items {
        let Item::Type(td) = item else { continue };
        if !matches!(&td.kind, TypeDeclKind::Effect(_)) { continue; }
        if !td.axioms.is_empty() {
            effects_with_axioms.insert(td.name.clone());
        }
    }
    if effects_with_axioms.is_empty() { return; }

    // Шаг 2: walk all expressions, найти WithBinding'и с такими эффектами.
    for item in &module.items {
        match item {
            Item::Fn(f) => match &f.body {
                FnBody::Block(b) => walk_block_for_with_gate(b, &effects_with_axioms, errors),
                FnBody::Expr(e) => walk_expr_for_with_gate(e, &effects_with_axioms, errors),
                FnBody::External => {}
            }
            Item::Test(t) => walk_block_for_with_gate(&t.body, &effects_with_axioms, errors),
            _ => {}
        }
    }
}

fn walk_block_for_with_gate(b: &Block, eff_pv: &HashSet<String>, errors: &mut Vec<Diagnostic>) {
    for s in &b.stmts {
        match s {
            Stmt::Expr(e) => walk_expr_for_with_gate(e, eff_pv, errors),
            Stmt::Let(LetDecl { value, .. }) => walk_expr_for_with_gate(value, eff_pv, errors),
            Stmt::Const(_) => {}
            Stmt::Assign { target, value, .. } => {
                walk_expr_for_with_gate(target, eff_pv, errors);
                walk_expr_for_with_gate(value, eff_pv, errors);
            }
            _ => {}
        }
    }
    if let Some(t) = &b.trailing { walk_expr_for_with_gate(t, eff_pv, errors); }
}

fn walk_expr_for_with_gate(e: &Expr, eff_pv: &HashSet<String>, errors: &mut Vec<Diagnostic>) {
    use crate::ast::ExprKind::*;
    match &e.kind {
        With { bindings, body } => {
            for b in bindings {
                let eff_name = match &b.effect {
                    TypeRef::Named { path, .. } => path.last().cloned().unwrap_or_default(),
                    _ => String::new(),
                };
                if !eff_pv.contains(&eff_name) { continue; }
                if matches!(b.verification, HandlerVerification::Unverified) {
                    errors.push(Diagnostic::new(
                        format!(
                            "handler for effect `{}` must be marked `#verify` \
                             or `#trusted` (effect has `axiom` declarations, so any \
                             handler must declare verification status). Examples:\n  \
                             with #trusted {0} = my_handler {{ ... }}\n  \
                             with #verify {0} = my_handler {{ ... }}",
                            eff_name,
                        ),
                        b.span,
                    ));
                }
                walk_expr_for_with_gate(&b.handler, eff_pv, errors);
            }
            walk_block_for_with_gate(body, eff_pv, errors);
        }
        Block(b) => walk_block_for_with_gate(b, eff_pv, errors),
        Call { func, args, .. } => {
            walk_expr_for_with_gate(func, eff_pv, errors);
            for a in args { walk_expr_for_with_gate(a.expr(), eff_pv, errors); }
        }
        Binary { left, right, .. } => {
            walk_expr_for_with_gate(left, eff_pv, errors);
            walk_expr_for_with_gate(right, eff_pv, errors);
        }
        Unary { operand, .. } => walk_expr_for_with_gate(operand, eff_pv, errors),
        Member { obj, .. } => walk_expr_for_with_gate(obj, eff_pv, errors),
        Index { obj, index } => {
            walk_expr_for_with_gate(obj, eff_pv, errors);
            walk_expr_for_with_gate(index, eff_pv, errors);
        }
        If { cond, then, else_ } => {
            walk_expr_for_with_gate(cond, eff_pv, errors);
            walk_block_for_with_gate(then, eff_pv, errors);
            match else_ {
                Some(crate::ast::ElseBranch::Block(b)) => walk_block_for_with_gate(b, eff_pv, errors),
                Some(crate::ast::ElseBranch::If(ie)) => walk_expr_for_with_gate(ie, eff_pv, errors),
                None => {}
            }
        }
        _ => {}
    }
}

fn type_ref_is_never(t: &TypeRef) -> bool {
    if let TypeRef::Named { path, .. } = t {
        if let Some(last) = path.last() {
            // Plan 76: bottom-тип — строчный `never`.
            return last == "never";
        }
    }
    false
}

/// Plan 33.3 Ф.9 (D24): валидация axiom-формул внутри effect-блоков.
///
/// Контракт: внутри `axiom name(binders) => formula` разрешены только:
///   - литералы (int/bool/str/unit);
///   - идентификаторы из `binders`;
///   - вызовы pure_view-ops **того же эффекта**: `balance(id) >= 0`;
///   - стандартные бинарные/унарные/comparison/boolean операторы;
///   - `if/else` без stmts.
///
/// Запрещены:
///   - non-pure_view operations (`SetBalance(...)`);
///   - вызовы любых других fn (включая built-ins за пределами разрешённых
///     операторов);
///   - record/sum constructors, member access, method calls.
///
/// Эти ограничения нужны для чистой SMT-кодировки (`pure_view` → UF,
/// axiom → assert) в Ф.9.4. Если разрешить произвольный код — SMT
/// encoding теряет soundness.
fn check_effect_axioms(module: &Module, errors: &mut Vec<Diagnostic>) {
    for item in &module.items {
        let Item::Type(td) = item else { continue };
        // Plan 33.3 Ф.9 (refactor): unique-name + axiom-formula checks
        // применяются и к effect, и к protocol (в обоих можно объявлять
        // #pure ops и axioms).
        let methods = match &td.kind {
            TypeDeclKind::Effect(m) => m,
            TypeDeclKind::Protocol { methods, .. } => methods,
            _ => continue,
        };

        // Plan 33.3 (refactor): unique-name checks внутри effect/protocol.
        //
        // Перегрузка op разрешена — уникальность по (name + param_types).
        // Axioms уникальны по имени (overloading axioms не поддерживается).
        // Axiom name не может совпадать с именем любого op (независимо от
        // типов параметров) — они в одном logical namespace.
        fn type_key(ty: &TypeRef) -> String {
            match ty {
                TypeRef::Named { path, generics, .. } => {
                    let base = path.join(".");
                    if generics.is_empty() {
                        base
                    } else {
                        let a: Vec<_> = generics.iter().map(type_key).collect();
                        format!("{}[{}]", base, a.join(","))
                    }
                }
                TypeRef::Tuple(ts, _) => {
                    let a: Vec<_> = ts.iter().map(type_key).collect();
                    format!("({})", a.join(","))
                }
                TypeRef::Func { params, return_type, .. } => {
                    let ps: Vec<_> = params.iter().map(type_key).collect();
                    let ret = return_type.as_deref().map(type_key).unwrap_or_default();
                    format!("fn({})->{}", ps.join(","), ret)
                }
                TypeRef::Array(t, _) => format!("[]{}", type_key(t)),
                TypeRef::FixedArray(n, t, _) => format!("[{}]{}", n, type_key(t)),
                // Plan 97 Ф.2 (D142): анонимный protocol — структурный
                // ключ через method-имена + аriт'и. Полная сигнатура с
                // type_key рекурсивно даёт стабильный ключ для overload
                // disambiguation.
                TypeRef::Protocol { methods, .. } => {
                    let ms: Vec<String> = methods
                        .iter()
                        .map(|m| {
                            let prefix = if m.is_static { "." } else { "" };
                            let ps: Vec<String> =
                                m.params.iter().map(|p| type_key(&p.ty)).collect();
                            let ret = m
                                .return_type
                                .as_ref()
                                .map(type_key)
                                .unwrap_or_default();
                            format!("{}{}({})->{}", prefix, m.name, ps.join(","), ret)
                        })
                        .collect();
                    format!("protocol{{{}}}", ms.join(";"))
                }
                TypeRef::Unit(_) => "()".to_string(),
                // D176 (Plan 108): readonly T — key as "readonly_<inner>"
                TypeRef::Readonly(inner, _) => format!("readonly_{}", type_key(inner)),
                // Plan 118 D216 §1 / Plan 118.5 V2 (2026-06-04): typed
                // pointer `*T` family — split into three arms по AST
                // wrappers. Keys distinct для overload disambiguation:
                //   - Pointer(T)             → "*ro_<inner>"
                //   - Mut(Pointer(T))        → "*mut_<inner>" (pointee)
                //   - Mut(non-Pointer)       → inner key (transparent)
                //   - Unsafe(Pointer(T))     → "*unsafe_<inner>" (pointee)
                //   - Unsafe(non-Pointer)    → inner key (transparent)
                TypeRef::Pointer(inner, _) => format!("*ro_{}", type_key(inner)),
                TypeRef::Mut(inner, _) => match inner.as_ref() {
                    TypeRef::Pointer(p_inner, _) => {
                        format!("*mut_{}", type_key(p_inner))
                    }
                    _ => type_key(inner),
                },
                TypeRef::Unsafe(inner, _) => match inner.as_ref() {
                    TypeRef::Pointer(p_inner, _) => {
                        format!("*unsafe_{}", type_key(p_inner))
                    }
                    _ => type_key(inner),
                },
            }
        }
        fn op_sig(m: &EffectMethod) -> String {
            let types: Vec<String> = m.params.iter()
                .map(|p| type_key(&p.ty))
                .collect();
            format!("{}({})", m.name, types.join(","))
        }
        let mut op_sigs: HashSet<String> = HashSet::new();
        // op_names_only: все имена operations (для проверки axiom↔op коллизии).
        let mut op_names_only: HashSet<&String> = HashSet::new();
        for m in methods {
            op_names_only.insert(&m.name);
            let sig = op_sig(m);
            if !op_sigs.insert(sig) {
                errors.push(Diagnostic::new(
                    format!("effect `{}`: duplicate operation `{}` \
                             (same name and parameter types)",
                        td.name, m.name),
                    m.span,
                ));
            }
        }
        let mut axiom_names: HashSet<&String> = HashSet::new();
        for ax in &td.axioms {
            if !axiom_names.insert(&ax.name) {
                errors.push(Diagnostic::new(
                    format!("effect `{}`: duplicate axiom `{}`",
                        td.name, ax.name),
                    ax.span,
                ));
            }
            if op_names_only.contains(&ax.name) {
                errors.push(Diagnostic::new(
                    format!("effect `{}`: axiom `{}` conflicts with operation \
                             of the same name (axiom names must be distinct \
                             from operations / `#pure` views)",
                        td.name, ax.name),
                    ax.span,
                ));
            }
        }

        if td.axioms.is_empty() { continue; }

        // Собираем pure_view-имена эффекта: имя → ожидаемая арность.
        let mut pure_views: HashMap<String, usize> = HashMap::new();
        for m in methods {
            if matches!(m.kind, EffectOpKind::PureView) {
                pure_views.insert(m.name.clone(), m.params.len());
            }
        }

        for ax in &td.axioms {
            // Duplicate-binder check.
            let mut seen: HashSet<&String> = HashSet::new();
            for bd in &ax.binders {
                if !seen.insert(&bd.name) {
                    errors.push(Diagnostic::new(
                        format!("axiom `{}.{}`: duplicate binder `{}`",
                            td.name, ax.name, bd.name),
                        ax.span,
                    ));
                }
            }
            let binders: HashSet<&String> = ax.binders.iter().map(|bd| &bd.name).collect();
            check_axiom_expr(&ax.formula, &td.name, &ax.name,
                             &binders, &pure_views, errors);
        }
    }
}

/// Walk `expr` в axiom-formula и пушит ошибки на запрещённые конструкции.
fn check_axiom_expr(
    e: &Expr,
    effect_name: &str,
    axiom_name: &str,
    binders: &HashSet<&String>,
    pure_views: &HashMap<String, usize>,
    errors: &mut Vec<Diagnostic>,
) {
    use crate::ast::ExprKind::*;
    match &e.kind {
        IntLit(_) | BoolLit(_) | StrLit(_) | CharLit(_) | UnitLit => {}
        Ident(n) => {
            if binders.contains(&n.to_string()) { return; }
            if pure_views.contains_key(n) {
                // Reference to pure_view без вызова — V1 запрещаем
                // (требуем `name(args)`-форму для arity-clarity).
                errors.push(Diagnostic::new(
                    format!(
                        "axiom `{}.{}`: pure_view `{}` must be called \
                         with arguments (e.g. `{}(...)`), not used as value",
                        effect_name, axiom_name, n, n,
                    ),
                    e.span,
                ));
                return;
            }
            errors.push(Diagnostic::new(
                format!(
                    "axiom `{}.{}`: unknown identifier `{}` (axiom-body \
                     may only reference binders {:?} or pure_view ops \
                     of effect `{}`)",
                    effect_name, axiom_name, n,
                    binders.iter().map(|s| s.as_str()).collect::<Vec<_>>(),
                    effect_name,
                ),
                e.span,
            ));
        }
        Binary { left, right, .. } => {
            check_axiom_expr(left, effect_name, axiom_name, binders, pure_views, errors);
            check_axiom_expr(right, effect_name, axiom_name, binders, pure_views, errors);
        }
        Unary { operand, .. } => {
            check_axiom_expr(operand, effect_name, axiom_name, binders, pure_views, errors);
        }
        If { cond, then, else_ } => {
            check_axiom_expr(cond, effect_name, axiom_name, binders, pure_views, errors);
            if !then.stmts.is_empty() {
                errors.push(Diagnostic::new(
                    format!("axiom `{}.{}`: if-branch must not contain statements",
                        effect_name, axiom_name),
                    e.span,
                ));
            }
            if let Some(trailing) = &then.trailing {
                check_axiom_expr(trailing, effect_name, axiom_name, binders, pure_views, errors);
            }
            match else_ {
                Some(crate::ast::ElseBranch::Block(b)) => {
                    if !b.stmts.is_empty() {
                        errors.push(Diagnostic::new(
                            format!("axiom `{}.{}`: else-branch must not contain statements",
                                effect_name, axiom_name),
                            e.span,
                        ));
                    }
                    if let Some(t) = &b.trailing {
                        check_axiom_expr(t, effect_name, axiom_name, binders, pure_views, errors);
                    }
                }
                Some(crate::ast::ElseBranch::If(ie)) => {
                    check_axiom_expr(ie, effect_name, axiom_name, binders, pure_views, errors);
                }
                None => {}
            }
        }
        Call { func, args, trailing } => {
            if trailing.is_some() {
                errors.push(Diagnostic::new(
                    format!(
                        "axiom `{}.{}`: trailing blocks not allowed in axiom-formulas",
                        effect_name, axiom_name,
                    ),
                    e.span,
                ));
                return;
            }
            // Plan 33.5 F.6: allow `post(ActionCall)(viewCall)` in axiom-formulas.
            // Shape: outer Call{ func: Call{ func: Ident("post"), args:[action_call] }, args:[view_call] }
            // Validate: action args and view args must only reference binders.
            // (Action and view names are validated at pipeline verify time, not here.)
            if let Call { func: inner_func, args: inner_args, .. } = &func.kind {
                if let Ident(n) = &inner_func.kind {
                    if n == "post" {
                        // post(ActionCall)(ViewCall): only validate binder references
                        // inside action args and view args; action/view names are
                        // validated by pipeline at verify time.
                        // inner_args[0] = ActionName(binder1, binder2, ...)
                        if let Some(action_call) = inner_args.first() {
                            if let Call { args: action_binder_args, .. } = &action_call.expr().kind {
                                for a in action_binder_args {
                                    check_axiom_expr(a.expr(), effect_name, axiom_name, binders, pure_views, errors);
                                }
                            }
                        }
                        // args[0] = ViewName(binder1, ...)
                        if let Some(view_call) = args.first() {
                            if let Call { args: view_binder_args, .. } = &view_call.expr().kind {
                                for a in view_binder_args {
                                    check_axiom_expr(a.expr(), effect_name, axiom_name, binders, pure_views, errors);
                                }
                            }
                        }
                        return;
                    }
                }
            }
            // V1: allowed form `<pure_view_name>(args)`.
            let pv_name = match &func.kind {
                Ident(n) => n.clone(),
                _ => {
                    errors.push(Diagnostic::new(
                        format!(
                            "axiom `{}.{}`: callee must be a pure_view of effect `{}`",
                            effect_name, axiom_name, effect_name,
                        ),
                        e.span,
                    ));
                    return;
                }
            };
            let Some(&expected) = pure_views.get(&pv_name) else {
                errors.push(Diagnostic::new(
                    format!(
                        "axiom `{}.{}`: `{}` is not a pure_view of effect `{}` \
                         (axioms may only reference pure_view ops)",
                        effect_name, axiom_name, pv_name, effect_name,
                    ),
                    e.span,
                ));
                return;
            };
            if args.len() != expected {
                errors.push(Diagnostic::new(
                    format!(
                        "axiom `{}.{}`: pure_view `{}` expects {} arg(s), got {}",
                        effect_name, axiom_name, pv_name, expected, args.len(),
                    ),
                    e.span,
                ));
            }
            for a in args {
                check_axiom_expr(a.expr(), effect_name, axiom_name, binders, pure_views, errors);
            }
        }
        _ => {
            errors.push(Diagnostic::new(
                format!(
                    "axiom `{}.{}`: this expression form is not allowed inside \
                     axiom-formula (only literals, binders, pure_view calls, \
                     arith/bool ops, and if/else)",
                    effect_name, axiom_name,
                ),
                e.span,
            ));
        }
    }
}

/// Walk block recursively: ищет HandlerLit, проверяет never-ops.
fn walk_block_for_handler_lits(b: &Block, never_ops: &HashSet<(String, String)>, errors: &mut Vec<Diagnostic>) {
    for s in &b.stmts {
        match s {
            Stmt::Let(decl) => walk_expr_for_handler_lits(&decl.value, never_ops, errors),
            Stmt::Const(_) => {}
            Stmt::Expr(e) => walk_expr_for_handler_lits(e, never_ops, errors),
            Stmt::Assign { target, value, .. } => {
                walk_expr_for_handler_lits(target, never_ops, errors);
                walk_expr_for_handler_lits(value, never_ops, errors);
            }
            Stmt::Return { value, .. } => {
                if let Some(v) = value { walk_expr_for_handler_lits(v, never_ops, errors); }
            }
            Stmt::Throw { value, .. } => walk_expr_for_handler_lits(value, never_ops, errors),
            Stmt::Defer { body, .. } | Stmt::ErrDefer { body, .. }
            | Stmt::OkDefer { body, .. } | Stmt::DeferWithResult { body, .. } => {
                walk_expr_for_handler_lits(body, never_ops, errors);
            }
            // Plan 110 D188: walk init + body block recursively.
            Stmt::ConsumeScope { init, body, .. } => {
                walk_expr_for_handler_lits(init, never_ops, errors);
                walk_block_for_handler_lits(body, never_ops, errors);
            }
            Stmt::AssertStatic { expr, .. } | Stmt::Assume { expr, .. } => walk_expr_for_handler_lits(expr, never_ops, errors),
            Stmt::Break(_) | Stmt::Continue(_) => {}
            Stmt::Apply { args, .. } => {
                for a in args { walk_expr_for_handler_lits(a, never_ops, errors); }
            }
            Stmt::Calc { steps, .. } => {
                for step in steps { walk_expr_for_handler_lits(&step.expr, never_ops, errors); }
            }
            Stmt::Reveal { .. } => {}
            // Plan 136: tuple destructuring assignment.
            Stmt::TupleAssign { lhs, rhs, .. } => {
                for e in lhs { walk_expr_for_handler_lits(e, never_ops, errors); }
                for e in rhs { walk_expr_for_handler_lits(e, never_ops, errors); }
            }
        }
    }
    if let Some(t) = &b.trailing { walk_expr_for_handler_lits(t, never_ops, errors); }
}

fn walk_expr_for_handler_lits(e: &Expr, never_ops: &HashSet<(String, String)>, errors: &mut Vec<Diagnostic>) {
    match &e.kind {
        // Plan 97 Ф.4 (D142): protocol-литерал — never-op check'и
        // на nor сейчас не специфицированы для protocol'ов (D61
        // §1430-1434 — только handler/effect-op'ы). Рекурсивно walk'аем
        // в bodies, но never-op assertion не применяется.
        ExprKind::ProtocolLit { methods, .. } => {
            for m in methods {
                match &m.body {
                    HandlerMethodBody::Expr(ex) => walk_expr_for_handler_lits(ex, never_ops, errors),
                    HandlerMethodBody::Block(b) => walk_block_for_handler_lits(b, never_ops, errors),
                }
            }
        }
        ExprKind::HandlerLit { effect_name, methods } => {
            // effect_name — Vec<String>, последний компонент = effect's last name.
            let eff_last = effect_name.last().cloned().unwrap_or_default();
            for m in methods {
                let key = (eff_last.clone(), m.name.clone());
                if never_ops.contains(&key) {
                    if !handler_body_diverges(&m.body) {
                        errors.push(Diagnostic::new(
                            format!(
                                "handler-method `{}.{}` обрабатывает операцию с возвращаемым типом `never` \
                                 (D61 §1430-1434, D65): body обязан завершиться через `interrupt v`, \
                                 `throw err`, `panic(...)` или `exit(...)`. Нельзя завершить handler-method \
                                 normally — нет значения типа `never` для return.",
                                eff_last, m.name
                            ),
                            m.span,
                        ));
                    }
                }
            }
            // Также recurse в bodies handler-методов (могут содержать nested
            // HandlerLit).
            for m in methods {
                match &m.body {
                    HandlerMethodBody::Expr(ex) => walk_expr_for_handler_lits(ex, never_ops, errors),
                    HandlerMethodBody::Block(b) => walk_block_for_handler_lits(b, never_ops, errors),
                }
            }
        }
        // Recurse в остальные expr-kinds (используем существующий walk
        // через ExprKind::Block + остальные expressions).
        ExprKind::Block(b) => walk_block_for_handler_lits(b, never_ops, errors),
        ExprKind::With { bindings, body } => {
            for bd in bindings { walk_expr_for_handler_lits(&bd.handler, never_ops, errors); }
            walk_block_for_handler_lits(body, never_ops, errors);
        }
        ExprKind::If { cond, then, else_ } => {
            walk_expr_for_handler_lits(cond, never_ops, errors);
            walk_block_for_handler_lits(then, never_ops, errors);
            match else_ {
                Some(ElseBranch::Block(b)) => walk_block_for_handler_lits(b, never_ops, errors),
                Some(ElseBranch::If(e2)) => walk_expr_for_handler_lits(e2, never_ops, errors),
                None => {}
            }
        }
        ExprKind::IfLet { scrutinee, then, else_, .. } => {
            walk_expr_for_handler_lits(scrutinee, never_ops, errors);
            walk_block_for_handler_lits(then, never_ops, errors);
            match else_ {
                Some(ElseBranch::Block(b)) => walk_block_for_handler_lits(b, never_ops, errors),
                Some(ElseBranch::If(e2)) => walk_expr_for_handler_lits(e2, never_ops, errors),
                None => {}
            }
        }
        ExprKind::Match { scrutinee, arms } => {
            walk_expr_for_handler_lits(scrutinee, never_ops, errors);
            for a in arms {
                match &a.body {
                    MatchArmBody::Expr(ex) => walk_expr_for_handler_lits(ex, never_ops, errors),
                    MatchArmBody::Block(b) => walk_block_for_handler_lits(b, never_ops, errors),
                }
                if let Some(g) = &a.guard { walk_expr_for_handler_lits(g, never_ops, errors); }
            }
        }
        ExprKind::For { iter, body, .. } => {
            walk_expr_for_handler_lits(iter, never_ops, errors);
            walk_block_for_handler_lits(body, never_ops, errors);
        }
        ExprKind::While { cond, body, .. } | ExprKind::WhileLet { scrutinee: cond, body, .. } => {
            walk_expr_for_handler_lits(cond, never_ops, errors);
            walk_block_for_handler_lits(body, never_ops, errors);
        }
        ExprKind::Loop { body, .. } => walk_block_for_handler_lits(body, never_ops, errors),
        ExprKind::Select { arms } => {
            for arm in arms {
                match &arm.op {
                    SelectOp::Recv { chan, .. } => walk_expr_for_handler_lits(chan, never_ops, errors),
                    SelectOp::Send { chan, value } => {
                        walk_expr_for_handler_lits(chan, never_ops, errors);
                        walk_expr_for_handler_lits(value, never_ops, errors);
                    }
                    SelectOp::Default => {}
                }
                if let Some(g) = &arm.guard { walk_expr_for_handler_lits(g, never_ops, errors); }
                walk_block_for_handler_lits(&arm.body, never_ops, errors);
            }
        }
        ExprKind::Forbid { body, .. } | ExprKind::Realtime { body, .. } => {
            walk_block_for_handler_lits(body, never_ops, errors);
        }
        ExprKind::Detach(b) | ExprKind::Blocking(b) => walk_block_for_handler_lits(b, never_ops, errors),
        ExprKind::Supervised { body, cancel } => {
            if let Some(c) = cancel { walk_expr_for_handler_lits(c, never_ops, errors); }
            walk_block_for_handler_lits(body, never_ops, errors);
        }
        ExprKind::Spawn(ex) => walk_expr_for_handler_lits(ex, never_ops, errors),
        ExprKind::ParallelFor { iter, body, .. } => {
            walk_expr_for_handler_lits(iter, never_ops, errors);
            walk_block_for_handler_lits(body, never_ops, errors);
        }
        ExprKind::Call { func, args, trailing } => {
            walk_expr_for_handler_lits(func, never_ops, errors);
            for a in args { walk_expr_for_handler_lits(a.expr(), never_ops, errors); }
            if let Some(tr) = trailing {
                match tr {
                    Trailing::Block(b) => walk_block_for_handler_lits(b, never_ops, errors),
                    Trailing::Fn(fsb) => match &fsb.body {
                        FnBody::Block(b) => walk_block_for_handler_lits(b, never_ops, errors),
                        FnBody::Expr(e2) => walk_expr_for_handler_lits(e2, never_ops, errors),
                        FnBody::External => {}
                    },
                    Trailing::LegacyBlockWithParams(tb) => walk_block_for_handler_lits(&tb.body, never_ops, errors),
                }
            }
        }
        ExprKind::Binary { left, right, .. } => {
            walk_expr_for_handler_lits(left, never_ops, errors);
            walk_expr_for_handler_lits(right, never_ops, errors);
        }
        ExprKind::Unary { operand, .. } => walk_expr_for_handler_lits(operand, never_ops, errors),
        ExprKind::Coalesce(a, b) => {
            walk_expr_for_handler_lits(a, never_ops, errors);
            walk_expr_for_handler_lits(b, never_ops, errors);
        }
        ExprKind::As(e2, _) | ExprKind::Is(e2, _) => walk_expr_for_handler_lits(e2, never_ops, errors),
        ExprKind::Member { obj, .. } | ExprKind::Index { obj, .. } | ExprKind::TurboFish { base: obj, .. } => {
            walk_expr_for_handler_lits(obj, never_ops, errors);
        }
        ExprKind::Range { start, end, .. } => {
            if let Some(s) = start { walk_expr_for_handler_lits(s, never_ops, errors); }
            if let Some(e) = end { walk_expr_for_handler_lits(e, never_ops, errors); }
        }
        ExprKind::ArrayLit(elems) => {
            for el in elems {
                match el {
                    ArrayElem::Item(e2) | ArrayElem::Spread(e2) => walk_expr_for_handler_lits(e2, never_ops, errors),
                }
            }
        }
        ExprKind::MapLit { elems, .. } => {
                let pairs = crate::ast::MapElem::cloned_pairs(&elems);
            for (k, v) in pairs.iter() {
                walk_expr_for_handler_lits(k, never_ops, errors);
                walk_expr_for_handler_lits(v, never_ops, errors);
            }
        }
        ExprKind::TupleLit(elems) => { for el in elems { walk_expr_for_handler_lits(el, never_ops, errors); } }
        ExprKind::RecordLit { fields, .. } => {
            for f in fields { if let Some(v) = &f.value { walk_expr_for_handler_lits(v, never_ops, errors); } }
        }
        ExprKind::Throw(v) | ExprKind::Try(v) | ExprKind::Bang(v) | ExprKind::Interrupt(Some(v)) => {
            walk_expr_for_handler_lits(v, never_ops, errors);
        }
        ExprKind::Interrupt(None) => {}
        ExprKind::Lambda { body, .. } => walk_expr_for_handler_lits(body, never_ops, errors),
        ExprKind::ClosureLight { body, .. } => match body {
            ClosureBody::Expr(e2) => walk_expr_for_handler_lits(e2, never_ops, errors),
            ClosureBody::Block(b) => walk_block_for_handler_lits(b, never_ops, errors),
        },
        ExprKind::ClosureFull(fsb) => match &fsb.body {
            FnBody::Block(b) => walk_block_for_handler_lits(b, never_ops, errors),
            FnBody::Expr(e2) => walk_expr_for_handler_lits(e2, never_ops, errors),
            FnBody::External => {}
        },
        // Interpolated string — recurse в её parts (могут содержать expressions).
        ExprKind::InterpolatedStr { parts } => {
            for p in parts {
                if let InterpStrPart::Expr { expr: e2, spec: _ } = p {
                    walk_expr_for_handler_lits(e2, never_ops, errors);
                }
            }
        }
        // TaggedTemplate имеет args со sub-expressions — но bootstrap-stage
        // редко используется; для completeness'а добавим shallow walk.
        ExprKind::TaggedTemplate { .. } => {}
        // D.1.3: квантор — только в контрактах; обходим range и body.
        ExprKind::Forall { range, body, .. } | ExprKind::Exists { range, body, .. } => {
            walk_expr_for_handler_lits(range, never_ops, errors);
            walk_expr_for_handler_lits(body, never_ops, errors);
        }
        // Leaf expressions — nothing to recurse into.
        ExprKind::IntLit(_) | ExprKind::FloatLit(_) | ExprKind::CharLit(_) | ExprKind::StrLit(_)
        | ExprKind::BoolLit(_) | ExprKind::Ident(_) | ExprKind::Path(_) | ExprKind::UnitLit
        | ExprKind::NullPtrLit
        | ExprKind::SelfAccess => {}
    }
}

/// Static analysis: завершается ли handler-method body через exit-control?
///
/// Exit-control = `interrupt`, `throw`, `panic(...)`, `exit(...)` —
/// expressions/stmts которые гарантированно НЕ возвращают control в
/// caller операции (never-returning).
///
/// Bootstrap conservative: проверяем самые частые паттерны:
///   - Expr body = exit-control expression.
///   - Block body = последний stmt/trailing — exit-control.
///   - Conditional structures (if/match) — ВСЕ ветки exit-control.
///
/// Если не уверены — возвращаем `false` (нечасто-используемый граничный
/// случай → программист обязан явно exit'нуть).
fn handler_body_diverges(body: &HandlerMethodBody) -> bool {
    match body {
        HandlerMethodBody::Expr(e) => expr_diverges(e),
        HandlerMethodBody::Block(b) => block_diverges(b),
    }
}

fn expr_diverges(e: &Expr) -> bool {
    match &e.kind {
        // Direct exit-control.
        ExprKind::Interrupt(_) | ExprKind::Throw(_) => true,
        // panic(...) / exit(...) — never-returning builtins (D13).
        ExprKind::Call { func, .. } => {
            if let ExprKind::Ident(name) = &func.kind {
                matches!(name.as_str(), "panic" | "exit")
            } else {
                false
            }
        }
        // Conditional: все ветки должны diverge.
        ExprKind::If { then, else_, .. } => {
            block_diverges(then)
                && match else_ {
                    Some(ElseBranch::Block(b)) => block_diverges(b),
                    Some(ElseBranch::If(e2)) => expr_diverges(e2),
                    None => false, // нет else — fall-through possible
                }
        }
        ExprKind::IfLet { then, else_, .. } => {
            block_diverges(then)
                && match else_ {
                    Some(ElseBranch::Block(b)) => block_diverges(b),
                    Some(ElseBranch::If(e2)) => expr_diverges(e2),
                    None => false,
                }
        }
        ExprKind::Match { arms, .. } => {
            !arms.is_empty()
                && arms.iter().all(|a| match &a.body {
                    MatchArmBody::Expr(ex) => expr_diverges(ex),
                    MatchArmBody::Block(b) => block_diverges(b),
                })
        }
        // Block-as-expr.
        ExprKind::Block(b) => block_diverges(b),
        // Loop без condition — diverges (если нет break).
        ExprKind::Loop { .. } => true,
        _ => false,
    }
}

fn block_diverges(b: &Block) -> bool {
    // Сначала проверим: есть ли в block.stmts unconditional throw/return/etc
    // на верхнем уровне? Это early-diverge.
    for s in &b.stmts {
        if stmt_diverges(s) {
            return true;
        }
    }
    // Рначе — проверка trailing expression.
    if let Some(t) = &b.trailing {
        return expr_diverges(t);
    }
    false
}

fn stmt_diverges(s: &Stmt) -> bool {
    match s {
        Stmt::Return { .. } | Stmt::Throw { .. } => true,
        Stmt::Expr(e) => expr_diverges(e),
        // Break/Continue exit'ят loop, не handler-fn — не diverge для
        // handler-purposes (handler body должен иметь exit к caller'у
        // операции, не к outer loop).
        Stmt::Break(_) | Stmt::Continue(_) => false,
        _ => false,
    }
}

/// Plan 100.7 (D165): Returns true if the block (or any nested block) contains
/// at least one explicit `throw` statement. Used by `check_d162_coverage` to
/// distinguish “consumed at exit via explicit error-branch handling” (D162 ok)
/// from “consumed at exit in a function with no explicit throw paths” (D162 lint).
fn block_has_throw(b: &Block) -> bool {
    for s in &b.stmts {
        if stmt_has_throw(s) { return true; }
    }
    if let Some(t) = &b.trailing {
        if expr_has_throw(t) { return true; }
    }
    false
}

fn stmt_has_throw(s: &Stmt) -> bool {
    match s {
        Stmt::Throw { .. } => true,
        Stmt::Expr(e) => expr_has_throw(e),
        Stmt::Let(d) => expr_has_throw(&d.value),
        Stmt::Const(_) => false,
        Stmt::Defer { body, .. } | Stmt::ErrDefer { body, .. } | Stmt::OkDefer { body, .. }
        | Stmt::DeferWithResult { body, .. }
            => expr_has_throw(body),
        _ => false,
    }
}

fn expr_has_throw(e: &crate::ast::Expr) -> bool {
    use crate::ast::ExprKind;
    match &e.kind {
        ExprKind::Throw(_) => true,
        ExprKind::Block(b) => block_has_throw(b),
        ExprKind::If { then, else_, .. } => {
            block_has_throw(then) || else_.as_ref().map(|el| match el {
                crate::ast::ElseBranch::Block(b) => block_has_throw(b),
                crate::ast::ElseBranch::If(e) => expr_has_throw(e),
            }).unwrap_or(false)
        }
        ExprKind::With { body, .. } => block_has_throw(body),
        _ => false,
    }
}

/// Walk модуля: для каждого defer/errdefer statement в bodies функций
/// и тестах — проверить body constraints.
// ─────────────────────────────────────────────────────────────────────
// Plan 73 (D131): consume-qualifier flow-sensitive check.
//
// `consume` помечает receiver / параметр, чьё значение логически
// забирается вызовом (`fn StringBuilder consume @into()`,
// `fn f(consume sb StringBuilder)`). После consume-вызова переменная-
// источник недоступна:
//   - повторное использование (use-after-consume) → compile error;
//   - использование на пути, где consume произошёл лишь на части веток
//     (maybe-consumed) → compile error.
//
// Анализ flow-sensitive: состояние `VarState` каждой переменной
// протягивается через statements, ветвится на if/match/coalesce и
// пессимистично обрабатывает циклы (consume в теле → переменная
// maybe-consumed на 2-й итерации). Это НЕ borrow checker — памятью
// управляет GC; проверяется только логический инвариант D131.
//
// Closure / handler / trailing тела walk'аются изолированно (могут
// исполняться 0+ раз): use-after-consume внутри них ловится, но их
// собственные consume наружу не протекают (conservative).
// ─────────────────────────────────────────────────────────────────────

/// Состояние логической линейности переменной (D131).
#[derive(Clone)]
enum VarState {
    /// Значение доступно.
    Live,
    /// Значение потреблено в указанной точке.
    Consumed(Span),
    /// Значение потреблено лишь на части путей выполнения.
    MaybeConsumed(Span),
}

/// Plan 100.1 (D133 / D6): registry consume-типов модуля. Заполняется
/// pre-pass'ом до `check_consume`. Используется `type_is_consume`
/// для рекурсивной классификации (record-field consume-types,
/// generic-wraps).
///
/// **НЕ путать с `ConsumeRegistry`** (Plan 73 D131 — registry consume-
/// методов и consume-параметров; flat-name based).
struct LinearityRegistry {
    /// Имена типов, объявленных `type X consume {...}`.
    consume_types: HashSet<String>,
    /// Consume-методы по типу: type_name → Vec<method_name>.
    consume_methods: HashMap<String, Vec<String>>,
    /// Все имена типов, объявленных ЛОКАЛЬНО в модуле (независимо от consume).
    /// Используется в W_CONSUME_KEYWORD_UNNECESSARY: предупреждать только
    /// для локальных типов — для внешних типов мы не знаем их consume-статус
    /// из module.items.
    local_type_names: HashSet<String>,
}

impl LinearityRegistry {
    fn build(module: &Module) -> Self {
        let mut consume_types = HashSet::new();
        let mut consume_methods: HashMap<String, Vec<String>> = HashMap::new();
        let mut local_type_names = HashSet::new();

        // 1. Local module: consume-types + consume-methods + all local type names.
        for item in &module.items {
            if let Item::Type(td) = item {
                local_type_names.insert(td.name.clone());
                if td.consume {
                    consume_types.insert(td.name.clone());
                }
            }
            if let Item::Fn(fd) = item {
                if let Some(recv) = &fd.receiver {
                    if recv.consume {
                        consume_methods
                            .entry(recv.type_name.clone())
                            .or_default()
                            .push(fd.name.clone());
                    }
                }
            }
        }

        LinearityRegistry { consume_types, consume_methods, local_type_names }
    }

    /// Plan 100.1 (D133 / D6): `type_is_consume(TypeRef)` — рекурсивно
    /// определяет, является ли тип consume через wrap-transitivity.
    /// Bootstrap: generic-param без bound → false (silent-ignore;
    /// 100.2 закроет через `[T consume]`).
    fn type_is_consume(&self, t: &TypeRef, module: &Module) -> bool {
        // [M-checker-recursive-type-overflow]: the field-walk below follows
        // named-type references, which form a CYCLE for a recursive type
        // (`type Tree | Leaf | Node(int, Tree, Tree)`, or an invalid value
        // self-cycle `type N value { next N }`). Without a guard the recursion
        // never terminates → stack overflow during `nova check`. Thread a
        // visited-set keyed by the named type currently being resolved; a
        // re-entry returns `false` (consume-ness cannot be "introduced" by a
        // back-edge — the field that closes the cycle is already being checked,
        // and a genuine consume field elsewhere is still discovered on its own
        // forward edge). Public signature unchanged.
        let mut visited: std::collections::HashSet<String> = std::collections::HashSet::new();
        self.type_is_consume_v(t, module, &mut visited)
    }

    fn type_is_consume_v(
        &self,
        t: &TypeRef,
        module: &Module,
        visited: &mut std::collections::HashSet<String>,
    ) -> bool {
        match t {
            TypeRef::Named { path, generics, .. } => {
                // Direct consume-type.
                let name = path.last().cloned().unwrap_or_default();
                if self.consume_types.contains(&name) {
                    return true;
                }
                // Generic wrap: Option[Transaction], Box[Tx], Wrapper[T].
                if generics.iter().any(|a| self.type_is_consume_v(a, module, visited)) {
                    return true;
                }
                // Record/sum lookup: own fields consume-typed? Guard against
                // recursive named-type cycles (see type_is_consume doc above).
                if !visited.insert(name.clone()) {
                    return false;
                }
                let result = (|| {
                    for item in &module.items {
                        if let Item::Type(td) = item {
                            if td.name == name {
                                return match &td.kind {
                                    TypeDeclKind::Record(fields) =>
                                        fields.iter().any(|f|
                                            f.consume || self.type_is_consume_v(&f.ty, module, visited)),
                                    TypeDeclKind::Sum(variants) =>
                                        variants.iter().any(|v|
                                            match &v.kind {
                                                SumVariantKind::Tuple(payloads) =>
                                                    payloads.iter().any(|p|
                                                        self.type_is_consume_v(p, module, visited)),
                                                SumVariantKind::Record(fields) =>
                                                    fields.iter().any(|f|
                                                        f.consume || self.type_is_consume_v(&f.ty, module, visited)),
                                                SumVariantKind::Unit => false,
                                            }),
                                    _ => false,
                                };
                            }
                        }
                    }
                    false
                })();
                visited.remove(&name);
                result
            }
            TypeRef::Tuple(elems, _) =>
                elems.iter().any(|e| self.type_is_consume_v(e, module, visited)),
            TypeRef::Array(inner, _) => self.type_is_consume_v(inner, module, visited),
            // Generic-param без bound — bootstrap silent-ignore.
            _ => false,
        }
    }

    /// Plan 100.1 (D133): список consume-методов для типа (для diagnostics).
    fn consume_methods_for(&self, type_name: &str) -> Vec<String> {
        self.consume_methods.get(type_name).cloned().unwrap_or_default()
    }
}

/// Plan 100.1 (D133 / D4): проверка согласованности consume-маркеров
/// на type-decl'ах и полях. Emit diagnostics:
/// - D133-field-marker-missing: field consume-типа без `consume`.
/// - D133-type-marker-missing: `consume field` в non-consume type.
/// - D133-empty-consume: `type X consume {}` без consume-полей и без
///   consume-методов.
/// - D133-marker-on-non-consume: `consume f int` (non-consume type).
// Plan 91.10 (D163 retracted, 2026-05-30): check_external_fn_needs_caps удалён.
// Capability tracking via отдельный syntax — redundant с effect system; см.
// docs/plans/91.10-d163-retract-capability-syntax.md для rationale.

fn check_linearity_markers(
    module: &Module,
    reg: &LinearityRegistry,
    errors: &mut Vec<Diagnostic>,
) {
    for item in &module.items {
        let Item::Type(td) = item else { continue; };

        // Sum-types — D4 covers fields-level only для record-variants;
        // skip for now (sum-variants могут содержать consume-payload —
        // type_is_consume их подхватит).
        let TypeDeclKind::Record(fields) = &td.kind else {
            continue;
        };

        for f in fields {
            let field_is_consume_type = reg.type_is_consume(&f.ty, module);

            // 1. D133-field-marker-missing: consume-field без `consume`-маркера.
            if field_is_consume_type && !f.consume {
                errors.push(Diagnostic::new(
                    format!(
                        "[D133-field-marker-missing] field `{}` имеет consume-тип \
                         но не помечен `consume`. Добавь `consume field {}` либо \
                         замени тип на non-consume.",
                        f.name, f.name),
                    f.span,
                ));
            }
            // 4. D133-marker-on-non-consume: `consume f int` где int не consume.
            if f.consume && !field_is_consume_type {
                errors.push(Diagnostic::new(
                    format!(
                        "[D133-marker-on-non-consume] поле `{}` помечено `consume` \
                         но его тип не consume — маркер не нужен. Удали `consume` \
                         перед полем `{}`.",
                        f.name, f.name),
                    f.span,
                ));
            }
        }

        // 2. D133-type-marker-missing: consume-field в non-consume type-decl.
        if !td.consume && fields.iter().any(|f| f.consume) {
            errors.push(Diagnostic::new(
                format!(
                    "[D133-type-marker-missing] type `{}` содержит consume-поле, \
                     но сам не помечен `consume`. Добавь `consume` после имени: \
                     `type {} consume {{ ... }}`.",
                    td.name, td.name),
                td.span,
            ));
        }

        // 3. D133-empty-consume: `type X consume {}` без consume-полей и методов.
        // Допускаем opaque consume-типы (StringBuilder pattern: consume-methods
        // через external-fn, без consume-fields). Heuristic: ищем хотя бы один
        // consume-method для этого типа.
        if td.consume && !fields.iter().any(|f| f.consume) {
            let has_consume_method = module.items.iter().any(|it| {
                if let Item::Fn(fd) = it {
                    fd.receiver.as_ref().map_or(false, |r|
                        r.type_name == td.name && r.consume)
                } else { false }
            });
            if !has_consume_method {
                errors.push(Diagnostic::new(
                    format!(
                        "[D133-empty-consume] type `{}` помечен `consume` но не \
                         имеет ни consume-полей, ни consume-методов — добавь \
                         хотя бы один consume-method (`fn {} consume @method() -> ()`) \
                         либо убери `consume` с type-decl.",
                        td.name, td.name),
                    td.span,
                ));
            }
        }
    }
}

/// Реестр consume-аннотаций: user-module + runtime-stdlib.
struct ConsumeRegistry {
    /// `(receiver_type, method_name)` — consume-методы.
    methods: HashSet<(String, String)>,
    /// free-fn name → индексы consume-параметров.
    fn_params: HashMap<String, Vec<usize>>,
    /// `(receiver_type, method_name)` → индексы consume-параметров.
    method_params: HashMap<(String, String), Vec<usize>>,
    /// Plan 73 followup: free-fn name → имя return-типа (Named, 1-seg).
    /// Для var-type инференса `let x = factory()` — расширяет резолв
    /// consume-метода за пределы очевидных конструкторов.
    fn_return_types: HashMap<String, String>,
    /// Plan 77 (D132): `(receiver_type, method)` — fluent-методы `-> @`,
    /// гарантированно возвращающие сам receiver. `let x = recv.method()`
    /// для такого метода → `x` алиас `recv`.
    recv_returning: HashSet<(String, String)>,
    /// Plan 100.3 (D157): free-fn name → indices of view-params
    /// (non-consume params of consume types). Used to detect
    /// D133-consume-rvalue-in-view: rvalue passed to view-param position.
    fn_view_params: HashMap<String, Vec<usize>>,
    /// Plan 103.9 (D174): `(receiver_type, method_name)` → return-type name
    /// (single-segment Named). Used for var-type inference of method calls:
    /// `consume g = mu.lock()` → g has type `MutexGuard`.
    method_return_types: HashMap<(String, String), String>,
    /// Plan 108.1 (D176 amend): `(receiver_type, method_name)` для всех
    /// методов с `mut`-receiver (`fn T mut @method(...)`).  Вызов такого
    /// метода на параметре без `mut` → E_PARAM_NOT_MUT.
    mut_methods: HashSet<(String, String)>,
    /// Plan 135: `(receiver_type, method_name)` для методов с ro-receiver
    /// (`fn T @method(...)`).  Если метод присутствует и в `mut_methods`,
    /// и в `ro_methods` — это recv-mut overload пара; вызов на ro-binding
    /// диспатчится на ro-overload → НЕ E_LOCAL_NOT_MUT/E_PARAM_NOT_MUT.
    ro_methods: HashSet<(String, String)>,
    /// Plan 108.1 followup ([M-108.1-readonly-to-explicit-mut-coerce]):
    /// free-fn name → indices of `mut`-params.  Используется при call
    /// site: если arg в этой позиции имеет тип `readonly T` (или
    /// помечен readonly в `readonly_locals`), → E_READONLY_COERCE.
    fn_mut_params: HashMap<String, Vec<usize>>,
    /// Plan 108.1 followup: `(receiver_type, method_name)` → indices of
    /// `mut`-params.  Parallel free-fn `fn_mut_params`.
    method_mut_params: HashMap<(String, String), Vec<usize>>,
    /// **Plan 118.5 V2 [M-118.5-arg-coerce-unsafe] (2026-06-04):** free-fn
    /// name → indices of params that are NOT `unsafe T` typed (their type
    /// has no outer Unsafe wrapper before any Pointer). Used at call sites:
    /// если arg в одной из этих позиций является unsafe-T binding (Ident
    /// in `unsafe_t_locals`), → E_UNSAFE_ARG_REQUIRES_WRAP. Passing unsafe-T
    /// arg к unsafe-T param does NOT error (matched contract).
    fn_non_unsafe_params: HashMap<String, Vec<usize>>,
    /// Plan 118.5 V2 [M-118.5-arg-coerce-unsafe]: `(receiver_type, method)`
    /// → indices of non-unsafe-T-typed params. Parallel free-fn
    /// `fn_non_unsafe_params`.
    method_non_unsafe_params: HashMap<(String, String), Vec<usize>>,
}

impl ConsumeRegistry {
    fn build(module: &Module) -> Self {
        let mut methods: HashSet<(String, String)> = HashSet::new();
        let mut fn_params: HashMap<String, Vec<usize>> = HashMap::new();
        let mut method_params: HashMap<(String, String), Vec<usize>> = HashMap::new();
        let mut fn_return_types: HashMap<String, String> = HashMap::new();
        let mut recv_returning: HashSet<(String, String)> = HashSet::new();
        let mut fn_view_params: HashMap<String, Vec<usize>> = HashMap::new();
        // Plan 103.9 (D174): method return-type map for var-type inference.
        let mut method_return_types: HashMap<(String, String), String> = HashMap::new();
        // Plan 108.1 (D176 amend): mut-receiver methods registry.
        let mut mut_methods: HashSet<(String, String)> = HashSet::new();
        // Plan 135: ro-receiver methods registry (for recv-mut overload pairs).
        let mut ro_methods: HashSet<(String, String)> = HashSet::new();
        // Plan 108.1 followup: mut-params indices for E_READONLY_COERCE.
        let mut fn_mut_params: HashMap<String, Vec<usize>> = HashMap::new();
        let mut method_mut_params: HashMap<(String, String), Vec<usize>> = HashMap::new();
        // Plan 118.5 V2 [M-118.5-arg-coerce-unsafe]: non-unsafe-T params
        // indices (positions where param's outer wrapper is NOT Unsafe).
        let mut fn_non_unsafe_params: HashMap<String, Vec<usize>> = HashMap::new();
        let mut method_non_unsafe_params: HashMap<(String, String), Vec<usize>> = HashMap::new();

        // Plan 100.3 (D157): collect consume-types for view-param detection.
        // Mirrors LinearityRegistry::build consume_types collection.
        let consume_type_names: HashSet<String> = module.items.iter()
            .filter_map(|it| {
                if let Item::Type(td) = it {
                    if td.consume { Some(td.name.clone()) } else { None }
                } else { None }
            })
            .collect();

        // 1. Runtime-stdlib consume-методы (`StringBuilder.into` и т.п.).
        //    Single source of truth — runtime_registry.rs (`is_consume`).
        for f in crate::codegen::runtime_registry::all() {
            if let Some(recv) = f.receiver {
                if f.is_consume {
                    methods.insert((recv.to_string(), f.name.to_string()));
                }
                // Plan 108.1 (D176 amend): mut-receiver methods registry.
                if !f.is_static && f.is_mut {
                    mut_methods.insert((recv.to_string(), f.name.to_string()));
                }
                // Plan 77 (D132): fluent builder-методы рендерятся `-> @`
                // (mirror `render_nv` is_fluent) — гарантированно
                // возвращают receiver.
                if !f.is_static && f.is_mut && f.return_ty == "Self"
                    && f.nova_body.is_none()
                {
                    recv_returning.insert((recv.to_string(), f.name.to_string()));
                }
            }
        }

        // 2. User-module: consume-receiver методы + consume-параметры.
        for item in &module.items {
            if let Item::Fn(fd) = item {
                let consume_idx: Vec<usize> = fd.params.iter().enumerate()
                    .filter(|(_, p)| p.consume)
                    .map(|(i, _)| i)
                    .collect();
                // Plan 108.1 followup: mut-params indices.
                let mut_idx: Vec<usize> = fd.params.iter().enumerate()
                    .filter(|(_, p)| p.is_mut)
                    .map(|(i, _)| i)
                    .collect();
                // Plan 118.5 V2 [M-118.5-arg-coerce-unsafe]: positions of
                // params whose declared type does NOT start with Unsafe
                // wrapper. Passing unsafe-T arg at any of these positions
                // outside unsafe block → E_UNSAFE_ARG_REQUIRES_WRAP.
                let non_unsafe_idx: Vec<usize> = fd.params.iter().enumerate()
                    .filter(|(_, p)| !p.ty.outer_unsafe_before_pointer())
                    .map(|(i, _)| i)
                    .collect();
                match &fd.receiver {
                    Some(r) => {
                        if r.consume {
                            methods.insert((r.type_name.clone(), fd.name.clone()));
                        }
                        // Plan 108.1 (D176 amend): mut-receiver methods registry.
                        if r.mutable {
                            mut_methods.insert((r.type_name.clone(), fd.name.clone()));
                        } else if matches!(r.kind, ReceiverKind::Instance) {
                            // Plan 135: track ro-receiver instance methods.
                            ro_methods.insert((r.type_name.clone(), fd.name.clone()));
                        }
                        if !mut_idx.is_empty() {
                            method_mut_params.insert(
                                (r.type_name.clone(), fd.name.clone()), mut_idx.clone());
                        }
                        // Plan 118.5 V2 [M-118.5-arg-coerce-unsafe].
                        if !non_unsafe_idx.is_empty() {
                            method_non_unsafe_params.insert(
                                (r.type_name.clone(), fd.name.clone()),
                                non_unsafe_idx.clone());
                        }
                        // Plan 103.9 (D174): track method return-type for inference.
                        // `fn Mutex mut @lock() -> MutexGuard consume` → ("Mutex","lock") → "MutexGuard".
                        // Resolve "Self" → receiver type so that `consume b = a.clone()`
                        // correctly infers b's type as the receiver type (e.g. "StringBuilder").
                        if let Some(TypeRef::Named { path, .. }) = &fd.return_type {
                            if path.len() == 1 {
                                let ret = if path[0] == "Self" {
                                    r.type_name.clone()
                                } else {
                                    path[0].clone()
                                };
                                method_return_types.insert(
                                    (r.type_name.clone(), fd.name.clone()),
                                    ret,
                                );
                            }
                        }
                        // Plan 77 (D132): `-> @` fluent-метод.
                        if fd.returns_receiver {
                            recv_returning
                                .insert((r.type_name.clone(), fd.name.clone()));
                        }
                        if !consume_idx.is_empty() {
                            method_params.insert(
                                (r.type_name.clone(), fd.name.clone()), consume_idx);
                        }
                    }
                    None => {
                        if !consume_idx.is_empty() {
                            fn_params.insert(fd.name.clone(), consume_idx);
                        }
                        // Plan 108.1 followup: mut-params indices.
                        if !mut_idx.is_empty() {
                            fn_mut_params.insert(fd.name.clone(), mut_idx);
                        }
                        // Plan 118.5 V2 [M-118.5-arg-coerce-unsafe].
                        if !non_unsafe_idx.is_empty() {
                            fn_non_unsafe_params.insert(fd.name.clone(), non_unsafe_idx);
                        }
                        // Plan 73 followup: return-тип свободной функции.
                        if let Some(TypeRef::Named { path, .. }) = &fd.return_type {
                            if path.len() == 1 {
                                fn_return_types
                                    .insert(fd.name.clone(), path[0].clone());
                            }
                        }
                        // Plan 100.3 (D157): collect view-params — non-consume params
                        // of consume types. Used for D133-consume-rvalue-in-view check.
                        let view_idx: Vec<usize> = fd.params.iter().enumerate()
                            .filter(|(_, p)| {
                                !p.consume && matches!(&p.ty,
                                    TypeRef::Named { path, .. }
                                    if path.len() == 1
                                        && consume_type_names.contains(&path[0]))
                            })
                            .map(|(i, _)| i)
                            .collect();
                        if !view_idx.is_empty() {
                            fn_view_params.insert(fd.name.clone(), view_idx);
                        }
                    }
                }
            }
        }

        ConsumeRegistry {
            methods, fn_params, method_params, fn_return_types, recv_returning,
            fn_view_params, method_return_types, mut_methods, ro_methods,
            fn_mut_params, method_mut_params,
            fn_non_unsafe_params, method_non_unsafe_params,
        }
    }
}

/// Имена, связываемые pattern'ом (best-effort: Ident / Tuple / Record /
/// Variant / Array / Or). Используется для регистрации новых live-vars.
fn consume_pattern_names(p: &Pattern, out: &mut Vec<String>) {
    match p {
        Pattern::Ident { name, .. } => out.push(name.clone()),
        Pattern::Binding { name, inner, .. } => {
            out.push(name.clone());
            consume_pattern_names(inner, out);
        }
        Pattern::Tuple(ps, _) => {
            for sp in ps { consume_pattern_names(sp, out); }
        }
        Pattern::Variant { kind, .. } => {
            if let VariantPatternKind::Tuple { patterns, .. } = kind {
                for sp in patterns { consume_pattern_names(sp, out); }
            }
        }
        Pattern::Record { fields, .. } => {
            for f in fields {
                match &f.pattern {
                    Some(sp) => consume_pattern_names(sp, out),
                    None => out.push(f.name.clone()), // shorthand `{ name }`
                }
            }
        }
        Pattern::Array { elems, .. } => {
            for el in elems {
                match el {
                    ArrayPatternElem::Item(sp) => consume_pattern_names(sp, out),
                    ArrayPatternElem::RestBind(n) => out.push(n.clone()),
                    ArrayPatternElem::Rest => {}
                }
            }
        }
        Pattern::Or { alternatives, .. } => {
            // Альтернативы связывают одинаковый набор имён — берём первую.
            if let Some(first) = alternatives.first() {
                consume_pattern_names(first, out);
            }
        }
        Pattern::Wildcard(_) | Pattern::Literal(..) => {}
    }
}

/// Plan 108.3 (D36 amend): аналог `consume_pattern_names` но возвращает
/// pairs `(name, is_mut)` для per-name mut в pattern.
/// `let (mut a, b) = ...` → `[("a", true), ("b", false)]`.
fn consume_pattern_names_with_mut(p: &Pattern, out: &mut Vec<(String, bool)>) {
    match p {
        Pattern::Ident { name, is_mut, .. } => out.push((name.clone(), *is_mut)),
        Pattern::Binding { name, inner, .. } => {
            out.push((name.clone(), false));
            consume_pattern_names_with_mut(inner, out);
        }
        Pattern::Tuple(ps, _) => {
            for sp in ps { consume_pattern_names_with_mut(sp, out); }
        }
        Pattern::Variant { kind, .. } => {
            if let VariantPatternKind::Tuple { patterns, .. } = kind {
                for sp in patterns { consume_pattern_names_with_mut(sp, out); }
            }
        }
        Pattern::Record { fields, .. } => {
            for f in fields {
                match &f.pattern {
                    Some(sp) => consume_pattern_names_with_mut(sp, out),
                    None => out.push((f.name.clone(), false)),
                }
            }
        }
        Pattern::Array { elems, .. } => {
            for el in elems {
                match el {
                    ArrayPatternElem::Item(sp) => consume_pattern_names_with_mut(sp, out),
                    ArrayPatternElem::RestBind(n) => out.push((n.clone(), false)),
                    ArrayPatternElem::Rest => {}
                }
            }
        }
        Pattern::Or { alternatives, .. } => {
            if let Some(first) = alternatives.first() {
                consume_pattern_names_with_mut(first, out);
            }
        }
        Pattern::Wildcard(_) | Pattern::Literal(..) => {}
    }
}

/// Flow-context consume-анализа одной функции / теста.
struct ConsumeCtx<'a> {
    reg: &'a ConsumeRegistry,
    /// Plan 100.1 (D133): LinearityRegistry для consume-типов и методов.
    lin_reg: &'a LinearityRegistry,
    /// Состояние линейности per-variable. Ключ — каноническое имя
    /// (alias-класс представлен своим каноническим членом).
    states: HashMap<String, VarState>,
    /// Best-effort тип переменной — для резолва consume-метода по
    /// receiver'у. Неизвестный тип → метод не трактуется как consuming
    /// (sound: false-negative, не false-positive).
    var_types: HashMap<String, String>,
    /// Plan 73 followup: alias-карта. `let a = b` -> `aliases[a] = b`
    /// (b — каноническое имя). Обе переменные ссылаются на ОДИН
    /// heap-объект; consume любой -> consume всего alias-класса.
    aliases: HashMap<String, String>,
    /// Plan 100.1 (D133 / D9): локальные переменные объявленные с
    /// `consume tx = ...` — обязаны быть Consumed до scope-exit.
    consume_obligations: HashSet<String>,
    /// Plan 100.8 (D166): accumulates ALL consume-binding names ever declared
    /// in this scope (never cleared, unlike `consume_obligations`).  Used by
    /// `check_d162_coverage` which runs AFTER `consume_walk_block` has already
    /// cleared `consume_obligations` for satisfied obligations.
    all_declared_consume: HashSet<String>,
    /// Plan 100.1 (D133 / D5): состояние consume-полей receiver'а.
    /// Ключ — имя поля (без "@."), значение — VarState.
    /// Для consume-методов: поля должны быть Consumed на exit'е.
    /// Для не-consume методов: consume-поля должны быть Live на exit'е.
    field_states: HashMap<String, VarState>,
    /// Plan 100.2 (D156): generic-параметры с `[T consume]` bound.
    /// Внутри тела функции, параметры с типами из этого набора
    /// трактуются как consume-obligations (strict-mode).
    consume_bound_generics: HashSet<String>,
    /// Plan 100.3 (D157): view-params — non-consume params of consume types.
    /// Calling consume-methods on view-params → D157-consume-via-view error.
    /// Returning a view-param → D157-view-escape-return error.
    view_params: HashSet<String>,
    /// Plan 100.3 (D157): consume-closures — closures that consume outer vars.
    /// closure_var_name → list of outer vars it consumes when invoked.
    /// When closure is invoked: mark those outer vars Consumed + closure Consumed.
    consume_closures: HashMap<String, Vec<String>>,
    /// Plan 103.9 (D174): тип receiver'а текущего метода. Используется для
    /// инференса типа при `consume g = self.method()` — `self` это SelfAccess.
    self_type: Option<String>,
    /// Plan 108.1 (D176 amend): параметры функции с `is_mut: bool`.
    /// HashMap<param_name, is_mut>.  Используется для проверки
    /// `param.mut_method(...)` → E_PARAM_NOT_MUT при is_mut=false.
    /// Заполняется при входе в функцию.  Includes consume-params
    /// (is_mut=true since consume implies ownership+mut).
    param_mut: HashMap<String, bool>,
    /// Plan 108.2 (D36 enforcement): local `let` bindings с `is_mut: bool`.
    /// HashMap<binding_name, is_mut>.  Используется для проверки
    /// `local.mut_method(...)` / `local.field = ...` / `local[i] = ...`
    /// → E_LOCAL_NOT_MUT при is_mut=false.
    /// `consume X = ...` неявно is_mut=true (ownership transfer).
    local_mut: HashMap<String, bool>,
    /// Plan 108.1 followup ([M-108.1-readonly-to-explicit-mut-coerce]):
    /// HashSet локальных binding'ов, объявленных как `readonly T`
    /// (explicit readonly annotation на let-binding или fn-param).
    /// Передача такого binding'а в `mut`-параметр → E_READONLY_COERCE.
    readonly_locals: HashSet<String>,
    /// **Plan 118.5 V2 [M-118.5-arg-coerce-unsafe] (2026-06-04):**
    /// HashSet локальных binding'ов/parameters объявленных с type `unsafe T`
    /// (outer Unsafe wrapper detected via `outer_unsafe_before_pointer()`).
    /// Передача такого binding'а в non-unsafe param outside unsafe context
    /// → E_UNSAFE_ARG_REQUIRES_WRAP.
    unsafe_t_locals: HashSet<String>,
}

impl<'a> ConsumeCtx<'a> {
    fn new(reg: &'a ConsumeRegistry, lin_reg: &'a LinearityRegistry) -> Self {
        ConsumeCtx {
            reg,
            lin_reg,
            states: HashMap::new(),
            var_types: HashMap::new(),
            aliases: HashMap::new(),
            consume_obligations: HashSet::new(),
            all_declared_consume: HashSet::new(),
            field_states: HashMap::new(),
            consume_bound_generics: HashSet::new(),
            view_params: HashSet::new(),
            consume_closures: HashMap::new(),
            self_type: None,
            param_mut: HashMap::new(),
            local_mut: HashMap::new(),
            readonly_locals: HashSet::new(),
            unsafe_t_locals: HashSet::new(),
        }
    }

    /// Каноническое имя alias-класса переменной (следует по цепочке
    /// `aliases`). Guard от циклов — теоретически невозможны (alias
    /// всегда на уже-существующее имя), но защищаемся.
    fn canonical(&self, name: &str) -> String {
        let mut cur = name.to_string();
        for _ in 0..64 {
            match self.aliases.get(&cur) {
                Some(next) if next != &cur => cur = next.clone(),
                _ => break,
            }
        }
        cur
    }

    /// Пометить alias-класс переменной потреблённым.
    fn mark_consumed(&mut self, name: &str, span: Span) {
        let canon = self.canonical(name);
        if self.states.contains_key(&canon) {
            self.states.insert(canon, VarState::Consumed(span));
        }
    }

    /// Зарегистрировать новую live-переменную (с опц. известным типом).
    fn declare(&mut self, name: &str, ty: Option<String>) {
        if name == "_" { return; }
        // Свежий binding — не алиас (рвём прежнюю alias-связь при shadow).
        self.aliases.remove(name);
        self.states.insert(name.to_string(), VarState::Live);
        match ty {
            Some(t) => { self.var_types.insert(name.to_string(), t); }
            None => { self.var_types.remove(name); }
        }
    }

    /// Зарегистрировать alias `name` -> `canon` (`let a = b`): обе
    /// переменные — один объект.
    fn declare_alias(&mut self, name: &str, canon: &str, ty: Option<String>) {
        if name == "_" { return; }
        self.states.remove(name);            // shadow: убрать прежнее состояние
        self.aliases.insert(name.to_string(), canon.to_string());
        match ty {
            Some(t) => { self.var_types.insert(name.to_string(), t); }
            None => { self.var_types.remove(name); }
        }
    }

    /// Развязать alias-класс переменной `name` перед её реассайном
    /// (`name = ...`). Каждый член класса становится независимой
    /// переменной с ТЕКУЩИМ состоянием класса (объект-то прежний,
    /// меняется только привязка `name`). Sound: исключает ложную
    /// propagation consume через устаревший alias после реассайна.
    fn dissolve_alias_class(&mut self, name: &str) {
        let canon = self.canonical(name);
        let class_state = self.states.get(&canon).cloned()
            .unwrap_or(VarState::Live);
        let all_aliased: Vec<String> = self.aliases.keys().cloned().collect();
        for m in all_aliased {
            if self.canonical(&m) == canon {
                self.aliases.remove(&m);
                // member продолжает ссылаться на прежний объект —
                // сохраняем его состояние как независимое.
                self.states.insert(m, class_state.clone());
            }
        }
        // `canon` сохраняет своё состояние в `states` (уже там).
    }

    /// Использование переменной — проверка use-after-consume.
    fn use_var(&self, name: &str, span: Span, errors: &mut Vec<Diagnostic>) {
        let canon = self.canonical(name);
        match self.states.get(&canon) {
            Some(VarState::Consumed(at)) => {
                errors.push(Diagnostic::new(
                    format!(
                        "использование потреблённой переменной `{}` (D131): \
                         её значение отдано consume-вызовом и больше недоступно",
                        name),
                    span,
                ).with_note_at("значение потреблено здесь".to_string(), *at));
            }
            Some(VarState::MaybeConsumed(at)) => {
                errors.push(Diagnostic::new(
                    format!(
                        "использование, возможно, потреблённой переменной `{}` \
                         (D131): значение потребляется не на всех путях \
                         выполнения — компилятор не может гарантировать, что \
                         оно ещё доступно",
                        name),
                    span,
                ).with_note_at(
                    "значение потенциально потреблено здесь".to_string(), *at));
            }
            _ => {}
        }
    }

    /// Вывести тип значения `let`-binding'а (best-effort).
    fn infer_let_type(&self, decl: &LetDecl) -> Option<String> {
        // Явная аннотация `let x T = ...`.
        if let Some(TypeRef::Named { path, .. }) = &decl.ty {
            if path.len() == 1 {
                return Some(path[0].clone());
            }
        }
        self.infer_value_type(&decl.value)
    }

    /// Best-effort тип выражения — только синтаксически очевидные формы.
    fn infer_value_type(&self, e: &Expr) -> Option<String> {
        match &e.kind {
            // Конструктор `Type.new(...)` / `.with_capacity` / `.from` и т.п.
            ExprKind::Call { func, .. } => {
                if let ExprKind::Path(parts) = &func.kind {
                    if parts.len() == 2 && matches!(parts[1].as_str(),
                        "new" | "with_capacity" | "from" | "default" | "filled")
                    {
                        return Some(parts[0].clone());
                    }
                }
                // Plan 73 followup: свободная функция с известным
                // return-типом (`let x = make_builder()`).
                if let ExprKind::Ident(fname) = &func.kind {
                    if let Some(rt) = self.reg.fn_return_types.get(fname) {
                        return Some(rt.clone());
                    }
                }
                // Plan 103.9 (D174): метод с известным return-типом.
                // `consume g = mu.lock()` → ("Mutex","lock") → "MutexGuard".
                // Handles: `recv.method()` (Ident), `self.method()` (Ident "self"),
                // `@method()` desugared to `SelfAccess.method()`.
                if let ExprKind::Member { obj, name: method } = &func.kind {
                    let recv_ty: Option<String> = match &obj.kind {
                        ExprKind::Ident(recv) if recv == "self" => {
                            // Nova `self.lock()` — receiver is implicit self.
                            self.self_type.clone()
                        }
                        ExprKind::Ident(recv) => {
                            let canon = self.canonical(recv);
                            self.var_types.get(&canon)
                                .or_else(|| self.var_types.get(recv.as_str()))
                                .cloned()
                        }
                        ExprKind::SelfAccess => self.self_type.clone(),
                        _ => None,
                    };
                    if let Some(rty) = recv_ty {
                        if let Some(ret) = self.reg.method_return_types
                            .get(&(rty, method.clone()))
                        {
                            return Some(ret.clone());
                        }
                    }
                }
                None
            }
            // Алиас `let y = x` — переносим известный тип `x`.
            ExprKind::Ident(n) => self.var_types.get(&self.canonical(n)).cloned(),
            // `User { ... }` record-литерал.
            ExprKind::RecordLit { type_name: Some(path), .. } if path.len() == 1 => {
                Some(path[0].clone())
            }
            _ => None,
        }
    }

    /// Имя consume-метода для receiver-типа? (тип берётся по
    /// каноническому имени alias-класса).
    fn is_consume_method(&self, recv_var: &str, method: &str) -> bool {
        self.var_types.get(&self.canonical(recv_var))
            .map(|ty| self.reg.methods.contains(&(ty.clone(), method.to_string())))
            .unwrap_or(false)
    }

    /// Пометить аргументы в consume-позициях как потреблённые.
    /// Аргументы уже walk'нуты вызывающим (use-after-consume проверен) —
    /// здесь только переход состояния alias-класса.
    fn consume_args(&mut self, args: &[CallArg], idxs: &[usize], span: Span) {
        for &i in idxs {
            if let Some(CallArg::Item(arg)) = args.get(i) {
                if let ExprKind::Ident(name) = &arg.kind {
                    self.mark_consumed(name, span);
                }
            }
        }
    }

    // ── Plan 100.1 (D133): consume-obligation methods ────────────────────

    /// Зарегистрировать `consume tx = ...` binding — tx обязан быть
    /// Consumed до scope-exit.
    fn declare_consume_binding(&mut self, name: &str, ty: Option<String>) {
        if name == "_" { return; }
        self.declare(name, ty);
        self.consume_obligations.insert(name.to_string());
        // Plan 100.8 (D166): also track in all_declared_consume (never cleared).
        self.all_declared_consume.insert(name.to_string());
    }

    // ── Plan 100.3 (D157): view-param and consume-closure helpers ─────────

    /// Зарегистрировать view-param (non-consume param of consume type).
    /// view-params — Live, но запрещено вызывать consume-методы или return.
    fn declare_view_param(&mut self, name: &str, ty: Option<String>) {
        if name == "_" { return; }
        self.declare(name, ty);
        self.view_params.insert(name.to_string());
    }

    /// Проверить, является ли переменная view-param (D157).
    fn is_view_param(&self, name: &str) -> bool {
        let canon = self.canonical(name);
        self.view_params.contains(&canon) || self.view_params.contains(name)
    }

    /// Зарегистрировать consume-closure binding (FnOnce-equivalent).
    /// closure_name — имя let-binding'а; captured — список outer vars
    /// которые closure потребляет при invoke.
    fn declare_consume_closure(&mut self, closure_name: &str, captured: Vec<String>) {
        if closure_name == "_" { return; }
        // Consume-closure само является consume-obligation: если не invoked
        // до scope-exit → D133-not-consumed error.
        self.declare_consume_binding(closure_name, Some("__consume_closure__".to_string()));
        self.consume_closures.insert(closure_name.to_string(), captured);
    }

    /// Проверить, является ли переменная consume-closure (D157).
    fn is_consume_closure(&self, name: &str) -> bool {
        let canon = self.canonical(name);
        self.consume_closures.contains_key(&canon)
            || self.consume_closures.contains_key(name)
    }

    /// Вызвать consume-closure: пометить closure Consumed + все captured outer vars.
    fn invoke_consume_closure(&mut self, name: &str, span: Span) {
        let captured = {
            let canon = self.canonical(name);
            self.consume_closures.get(&canon)
                .or_else(|| self.consume_closures.get(name))
                .cloned()
                .unwrap_or_default()
        };
        // Mark captured outer vars as Consumed (closure consumed them).
        for var in &captured {
            self.mark_consumed(var, span);
        }
        // Mark closure itself as Consumed (FnOnce).
        self.mark_consumed(name, span);
    }

    /// Проверить, что все consume-obligations Consumed на текущем exit.
    /// `exit_span` — span точки выхода (конец scope'а / return / panic).
    ///
    /// Plan 100.8 (D166): enhanced с machine-applicable `Suggestion` для
    /// LSP quick-fix integration (D166 §LSP quick fixes).
    fn check_obligations_at_exit(&self,
                                  exit_span: Span,
                                  errors: &mut Vec<Diagnostic>) {
        use crate::diag::{Applicability, Suggestion};
        for name in &self.consume_obligations {
            let canon = self.canonical(name);
            let state = self.states.get(&canon)
                .or_else(|| self.states.get(name));
            let ty = self.var_types.get(name)
                .or_else(|| self.var_types.get(&canon))
                .cloned()
                .unwrap_or_default();
            // Plan 100.2 (D156): если тип — generic из [T consume] bound,
            // используем D156-strict-forget вместо D133-not-consumed.
            let is_strict_generic = !ty.is_empty()
                && self.consume_bound_generics.contains(&ty);
            match state {
                Some(VarState::Live) => {
                    let methods = self.lin_reg.consume_methods_for(&ty);
                    // Plan 100.6 (D164 §5): cross-module hint — если тип не
                    // объявлен в текущем модуле, он из внешнего пакета.
                    // Используем другой hint, чтобы не вводить в заблуждение.
                    let is_external_type = !ty.is_empty()
                        && !self.lin_reg.consume_types.contains(&ty);
                    let hint = if methods.is_empty() {
                        if is_external_type {
                            format!(
                                "вызовите consume-метод типа `{}` \
                                 (тип из внешнего модуля/пакета)",
                                ty)
                        } else {
                            "объявите consume-метод для этого типа".to_string()
                        }
                    } else if methods.len() <= 4 {
                        methods.join(" / ")
                    } else {
                        format!("см. `nova doc {}`", ty)
                    };
                    // Plan 100.2 (D156): D156-strict-forget для generic [T consume] vars.
                    let code = if is_strict_generic { "D156-strict-forget" } else { "D133-not-consumed" };
                    // Plan 100.8 (D166): build machine-applicable suggestion
                    // for LSP quick-fix. Suggest errdefer + primary commit.
                    let suggestion_text = if methods.is_empty() {
                        format!(
                            "// TODO: add consume-method for `{}` then call it here",
                            ty)
                    } else {
                        // Primary method = first; secondary (cleanup) = last if different.
                        let primary = &methods[0];
                        let cleanup = if methods.len() > 1 { Some(&methods[methods.len()-1]) } else { None };
                        if let Some(cl) = cleanup {
                            format!(
                                "errdefer {{ {name}.{cl}() }}\n{name}.{primary}()",
                                name = name, cl = cl, primary = primary)
                        } else {
                            format!("{name}.{primary}()", name = name, primary = primary)
                        }
                    };
                    let suggestion = Suggestion {
                        message: format!(
                            "consume `{name}` via method ({code} quick fix)",
                            name = name, code = code),
                        span: exit_span,
                        replacement: suggestion_text,
                        applicability: Applicability::MaybeIncorrect,
                    };
                    errors.push(Diagnostic::new(
                        format!(
                            "[{}] переменная `{}` (тип `{}`) не \
                             consumed до scope-exit. Добавьте вызов одного из: {}, \
                             либо `return {}`, либо передайте в consume-param.",
                            code, name, ty, hint, name),
                        exit_span,
                    ).with_suggestion(suggestion));
                }
                Some(VarState::MaybeConsumed(at)) => {
                    let methods = self.lin_reg.consume_methods_for(&ty);
                    // Plan 100.6 (D164 §5): cross-module hint — тип из
                    // внешнего пакета (не в локальном LinearityRegistry).
                    let is_external_type = !ty.is_empty()
                        && !self.lin_reg.consume_types.contains(&ty);
                    let hint = if methods.is_empty() {
                        if is_external_type {
                            format!(
                                "вызовите consume-метод типа `{}` \
                                 (тип из внешнего модуля/пакета)",
                                ty)
                        } else {
                            "объявите consume-метод".to_string()
                        }
                    } else {
                        methods.join(" / ")
                    };
                    // Plan 100.2 (D156): D156-strict-forget для generic [T consume] vars.
                    let code = if is_strict_generic { "D156-strict-forget" } else { "D133-not-consumed" };
                    // Plan 100.8 (D166): multi-path suggestion — both errdefer + okdefer
                    // (D166 §LSP quick fixes — suggestion lists both errdefer + okdefer).
                    let suggestion_text = if methods.is_empty() {
                        format!("// TODO: consume `{}` on all code paths", name)
                    } else {
                        let primary = &methods[0];
                        let cleanup = if methods.len() > 1 { Some(&methods[methods.len()-1]) } else { None };
                        if let Some(cl) = cleanup {
                            format!(
                                "errdefer {{ {name}.{cl}() }}\nokdefer {{ {name}.{primary}() }}",
                                name = name, cl = cl, primary = primary)
                        } else {
                            format!(
                                "errdefer {{ {name}.{primary}() }}\nokdefer {{ {name}.{primary}() }}",
                                name = name, primary = primary)
                        }
                    };
                    let suggestion = Suggestion {
                        message: format!(
                            "cover `{name}` on all paths: errdefer + okdefer ({code} multi-path)",
                            name = name, code = code),
                        span: exit_span,
                        replacement: suggestion_text,
                        applicability: Applicability::MaybeIncorrect,
                    };
                    errors.push(Diagnostic::new(
                        format!(
                            "[{}] переменная `{}` (тип `{}`) \
                             consumed только на части путей выполнения. На всех \
                             путях до scope-exit должен быть вызов одного из: {}. \
                             suggestion: add errdefer + okdefer для полного покрытия.",
                            code, name, ty, hint),
                        exit_span,
                    ).with_note_at("частичный consume здесь".to_string(), *at)
                     .with_suggestion(suggestion));
                }
                Some(VarState::Consumed(_)) | None => {}
            }
        }
    }

    // ── Plan 100.1 (D133 / D5): field-state tracking ─────────────────────

    /// Инициализировать состояние consume-поля receiver'а как Live.
    fn init_field_live(&mut self, field_name: &str) {
        self.field_states.insert(field_name.to_string(), VarState::Live);
    }

    /// Пометить consume-поле как Consumed.
    fn mark_field_consumed(&mut self, field_name: &str, span: Span) {
        if self.field_states.contains_key(field_name) {
            self.field_states.insert(field_name.to_string(), VarState::Consumed(span));
        }
    }

    /// Пометить consume-поле как Live (после rebind через assign).
    fn mark_field_live(&mut self, field_name: &str) {
        if self.field_states.contains_key(field_name) {
            self.field_states.insert(field_name.to_string(), VarState::Live);
        }
    }

    /// Проверить exit-point инварианты для consume-полей:
    /// - consume-метод: все consume-поля должны быть Consumed.
    /// - non-consume метод: все consume-поля должны быть Live.
    fn check_fields_at_exit(&self,
                             receiver_type: &str,
                             is_consume_method: bool,
                             fn_name: &str,
                             exit_span: Span,
                             errors: &mut Vec<Diagnostic>) {
        for (field_name, state) in &self.field_states {
            match (is_consume_method, state) {
                (false, VarState::Consumed(at)) => {
                    // Non-consume метод потребил поле без rebind.
                    errors.push(Diagnostic::new(
                        format!(
                            "[D133-field-not-restored] метод `{}` consume'нул \
                             consume-поле `@.{}` (тип `{}`), но не восстановил \
                             его до выхода. Используйте pattern: \
                             `@{field} = новое_значение` после consume, либо \
                             объявите метод как `consume @{method}`.",
                            fn_name, field_name, receiver_type,
                            field = field_name, method = fn_name),
                        *at,
                    ));
                }
                (false, VarState::MaybeConsumed(at)) => {
                    errors.push(Diagnostic::new(
                        format!(
                            "[D133-field-not-restored] метод `{}` возможно \
                             consume'нул consume-поле `@.{}` на части путей. \
                             Обеспечьте rebind на всех путях.",
                            fn_name, field_name),
                        *at,
                    ));
                }
                (true, VarState::Live) => {
                    // consume-метод не потребил поле — разрешено (может не
                    // использовать поле). Но если поле существует и Live —
                    // это нормально (consume-method закрывает весь record).
                    // Ошибку не эмитим: record-consume = весь объект consumed.
                    let _ = exit_span; // avoid unused warning
                }
                _ => {}
            }
        }
    }
}

/// Plan 73 (D131): consume-check входная точка — walk всех function /
/// method / test bodies модуля.
/// Plan 77 (D132): `-> @` fluent-return — тело non-external метода
/// обязано завершаться выражением `@` (вернуть сам receiver). Делает
/// гарантию «возвращает receiver» проверяемой → consume-checker может
/// soundly трактовать `let x = recv.method()` как alias receiver'а.
fn check_fluent_return(module: &Module, errors: &mut Vec<Diagnostic>) {
    // Build set of (type_name, method_name) pairs that have `returns_receiver: true`
    // in this module. Used by both checks below.
    let fluent_methods: std::collections::HashSet<(String, String)> = module.items.iter()
        .filter_map(|it| {
            if let Item::Fn(f) = it {
                if f.returns_receiver {
                    if let Some(recv) = &f.receiver {
                        return Some((recv.type_name.clone(), f.name.clone()));
                    }
                }
            }
            None
        })
        .collect();

    // Returns true if `expr` can be statically determined to always yield the receiver.
    // Covers: bare `@`, call to a known `-> @` method on `@`, if/else where all
    // branches yield receiver. Conservative — returns false for anything complex.
    fn expr_always_returns_receiver(
        e: &Expr,
        fluent: &std::collections::HashSet<(String, String)>,
        recv_type: &str,
    ) -> bool {
        match &e.kind {
            ExprKind::SelfAccess => true,
            ExprKind::Call { func, .. } => {
                if let ExprKind::Member { obj, name } = &func.kind {
                    if matches!(obj.kind, ExprKind::SelfAccess) {
                        return fluent.contains(&(recv_type.to_string(), name.clone()));
                    }
                }
                false
            }
            ExprKind::If { then, else_: Some(else_branch), .. } => {
                let then_ok = then.trailing.as_ref()
                    .map(|t| expr_always_returns_receiver(t, fluent, recv_type))
                    .unwrap_or(false);
                if !then_ok { return false; }
                match else_branch {
                    ElseBranch::Block(b) => b.trailing.as_ref()
                        .map(|t| expr_always_returns_receiver(t, fluent, recv_type))
                        .unwrap_or(false),
                    ElseBranch::If(e2) => expr_always_returns_receiver(e2, fluent, recv_type),
                }
            }
            _ => false,
        }
    }

    // Returns true if a body can be statically determined to always yield the receiver.
    // External: C-runtime contract guarantees it. Block: checks trailing expression
    // + all Stmt::Return values.
    fn body_always_returns_receiver(
        body: &FnBody,
        fluent: &std::collections::HashSet<(String, String)>,
        recv_type: &str,
    ) -> bool {
        match body {
            // External — C-реализация (StringBuilder/WriteBuffer); C-функция
            // возвращает receiver-pointer по контракту runtime'а.
            FnBody::External => true,
            FnBody::Expr(e) => expr_always_returns_receiver(e, fluent, recv_type),
            FnBody::Block(b) => {
                // Trailing expression must return receiver.
                let trailing_ok = b.trailing.as_ref()
                    .map(|t| expr_always_returns_receiver(t, fluent, recv_type))
                    .unwrap_or(false);
                if !trailing_ok { return false; }
                // All explicit return statements must also return receiver.
                for stmt in &b.stmts {
                    if let Stmt::Return { value: Some(v), .. } = stmt {
                        if !expr_always_returns_receiver(v, fluent, recv_type) {
                            return false;
                        }
                    }
                    if let Stmt::Return { value: None, .. } = stmt {
                        return false; // bare `return` → returns unit, not receiver
                    }
                }
                true
            }
        }
    }

    for item in &module.items {
        if let Item::Fn(f) = item {
            let recv_type = f.receiver.as_ref().map(|r| r.type_name.as_str()).unwrap_or("");
            if f.returns_receiver {
                // Check 1: `-> @` body must always return receiver.
                // Accepted: bare `@`, call to another `-> @` method, if/else where
                // all branches yield receiver, external fn (C-contract).
                if !body_always_returns_receiver(&f.body, &fluent_methods, recv_type) {
                    let span = match &f.body {
                        FnBody::Block(b) => b.span,
                        FnBody::Expr(e) => e.span,
                        FnBody::External => f.span,
                    };
                    errors.push(Diagnostic::new(
                        format!(
                            "метод `{}` объявлен `-> @` (fluent-return, D132): его \
                             тело обязано завершаться выражением `@` (или вызовом \
                             другого `-> @` метода). Добавьте `@` последним \
                             выражением тела.",
                            f.name),
                        span,
                    ));
                }
            } else {
                // Check 2: `-> Self` method where all return paths yield `@`
                // must be declared `-> @` instead. Catches the accidental pattern
                //   `fn T mut @m(...) -> Self => @fluent_call(...)`.
                let is_self_return = matches!(&f.return_type,
                    Some(TypeRef::Named { path, .. })
                    if path.len() == 1 && path[0] == "Self");
                if !is_self_return { continue; }
                if !matches!(&f.receiver, Some(r) if r.kind == ReceiverKind::Instance) {
                    continue;
                }
                if body_always_returns_receiver(&f.body, &fluent_methods, recv_type) {
                    errors.push(Diagnostic::new(
                        format!(
                            "метод `{}` объявлен `-> Self`, но все пути возвращают \
                             сам receiver (`@`). Используйте `-> @` (fluent-return, D132) \
                             вместо `-> Self`.",
                            f.name),
                        f.span,
                    ));
                }
            }
        }
    }
}

/// Plan 128 Ф.3: returns `true` iff `name` is the canonical name of a
/// Nova primitive (leaf) type — one that cannot carry mut-receiver methods.
///
/// Coverage mirrors the prelude primitive set: integer family
/// (`int`, signed `i8..i64`, unsigned `u8..u64`, `uint`), floats (`f32`,
/// `f64`), `bool`, `char`, `str`, and unit (`()`, which appears as the
/// canonical name `Unit`).
///
/// Plan 134: `ptr` removed from primitives — use `*()` (TypeRef::Pointer(Unit)).
/// `*()` receivers are TypeRef::Pointer, not Named, so check_primitive_mut_method
/// handles them via the TypeRef::Pointer arm, not via this leaf check.
///
/// Used by `check_primitive_mut_method` to flag declarations like
/// `fn str mut @hack(...)` — the parser permits the form, but codegen
/// silently no-ops the mutation; receiver-as-value primitives have no
/// in-place semantics by D215/D226 design.
fn is_primitive_leaf(name: &str) -> bool {
    // Plan 133: usize/isize removed from primitives.
    // Plan 134: ptr/nova_ptr removed — *() is TypeRef::Pointer, not Named leaf.
    matches!(name,
        "int" | "uint"
        | "i8" | "i16" | "i32" | "i64"
        | "u8" | "u16" | "u32" | "u64"
        | "f32" | "f64"
        | "bool" | "char" | "str"
        | "Unit"
    )
}

/// Plan 128 Ф.3: reject `fn <primitive> mut @method(...)` declarations.
///
/// Primitives are immutable by design (Plan 91 §«Nova-first»). A receiver
/// of a primitive type is passed by value — the only place where `mut` on
/// such a receiver could have meaning is in-place mutation of the caller's
/// binding, which Nova does not support for scalars. The parser currently
/// accepts the syntax, and codegen silently drops the mutation, so the
/// method LOOKS like it works but produces no observable effect. This pass
/// turns the silent footgun into a type-check error:
///
///   * `fn str mut @hack() => @ = "x"`           → E_PRIMITIVE_MUT_METHOD
///   * `fn int mut @inc(by int) => @ = @ + by`   → E_PRIMITIVE_MUT_METHOD
///   * `fn bool mut @flip() => @ = !@`           → E_PRIMITIVE_MUT_METHOD
///
/// Accepted (NOT flagged here):
///
///   * `fn str @len() -> int`                    — read-only method, no `mut`.
///   * `fn UserType mut @method()`               — non-primitive receiver
///     (record/named-tuple) — D215/D226 path handles mut-receiver pointer ABI.
///
/// Suggestion in the error message points users to the canonical
/// alternative: write a pure function returning a new value
/// (`fn name(x T) -> T`).
fn check_primitive_mut_method(module: &Module, errors: &mut Vec<Diagnostic>) {
    for item in &module.items {
        let Item::Fn(f) = item else { continue; };
        let Some(recv) = &f.receiver else { continue; };
        // Only instance methods take `@`; static methods (`.`) can't carry
        // `mut` on the receiver in the first place. Guard anyway in case
        // future parser changes lift that restriction.
        if recv.kind != ReceiverKind::Instance { continue; }
        if !recv.mutable { continue; }
        if !is_primitive_leaf(&recv.type_name) { continue; }
        errors.push(Diagnostic::new(
            format!(
                "[E_PRIMITIVE_MUT_METHOD] primitive type `{ty}` cannot have \
                 mut-methods (`fn {ty} mut @{name}(...)`): primitives are \
                 immutable by design — receiver is passed by value, so \
                 in-place mutation through `@` has no observable effect \
                 on the caller. Use a pure function returning a new value \
                 instead, e.g. `fn {name}(x {ty}) -> {ty}` (or a method \
                 returning a new {ty}). See Plan 91 §«Nova-first», \
                 Plan 128 Ф.3.",
                ty = recv.type_name,
                name = f.name,
            ),
            recv.span,
        ));
    }
}

/// Plan 100.2 (D156): определяет, содержит ли тип параметра generic
/// с consume_bound. Используется для авто-обязательства при entry в
/// функцию с `[T consume]` bound.
fn typeref_contains_consume_generic(ty: &TypeRef, consume_generics: &HashSet<String>) -> bool {
    if consume_generics.is_empty() { return false; }
    match ty {
        TypeRef::Named { path, generics, .. } => {
            // Generic-param T в consume_generics → consume-обязательство.
            if path.len() == 1 && consume_generics.contains(&path[0]) {
                return true;
            }
            // Generic-wrap G[T] где T consume → G тоже consume.
            generics.iter().any(|g| typeref_contains_consume_generic(g, consume_generics))
        }
        TypeRef::Tuple(elems, _) => {
            elems.iter().any(|e| typeref_contains_consume_generic(e, consume_generics))
        }
        TypeRef::Array(inner, _) => typeref_contains_consume_generic(inner, consume_generics),
        _ => false,
    }
}

// ============================================================================
// Plan 127 Ф.4 (D228 amend): E_VALUE_RECORD_ESCAPE_AFTER_CONSUME.
//
// `&v` после consume value-record local — hard error (D162 violation
// специализированное под value-record semantics). Generic D131 use-after-
// consume catches the underlying state-error, но Plan 127 эмитит более
// targeted сообщение: «stack-allocated value-record's slot logically
// drained — taking address now is undefined» — direct guidance.
//
// Detection (V1 syntactic):
// 1. Collect value-record type names (TypeDecl.allocation == Value).
// 2. For each fn-body: walk statements maintaining set of bindings to
//    value-record locals.
// 3. If we see a `consume v = ...` LetDecl с value-record type — flag `v`
//    в consumed-set.
// 4. If we see `consume`-method call on value-record local (e.g.
//    `v.drain()` where drain has consume receiver) — flag `v`.
// 5. If subsequently within the same fn we encounter `&v` (UnOp::AddrOf
//    on Ident with same name + still in consumed-set) — emit error.
//
// V1 conservative: linear scan per fn (no path-sensitive). Misses cases
// где consume на одном пути и use на another (covered partially by D131).
// V2: path-sensitive с DFG = `[M-127-consume-escape-path-sensitive]`.
// ============================================================================

fn check_value_record_escape_after_consume(module: &Module, errors: &mut Vec<Diagnostic>) {
    use std::collections::HashSet;
    let mut value_record_types: HashSet<String> = HashSet::new();
    let mut collect_vrt = |items: &[Item], out: &mut HashSet<String>| {
        for it in items {
            if let Item::Type(td) = it {
                if matches!(td.kind, crate::ast::TypeDeclKind::Record(_))
                    && td.allocation == crate::ast::AllocKind::Value
                {
                    out.insert(td.name.clone());
                }
            }
        }
    };
    collect_vrt(&module.items, &mut value_record_types);
    for pf in &module.peer_files {
        collect_vrt(&pf.items_here, &mut value_record_types);
    }
    if value_record_types.is_empty() { return; }

    let visit_fn = |fd: &crate::ast::FnDecl, errors: &mut Vec<Diagnostic>| {
        if matches!(fd.body, crate::ast::FnBody::External) { return; }
        let mut ctx = VrEscapeCtx {
            value_records: &value_record_types,
            vr_locals: std::collections::HashMap::new(),
            consumed: HashSet::new(),
        };
        match &fd.body {
            crate::ast::FnBody::Block(b) => ctx.walk_block(b, errors),
            crate::ast::FnBody::Expr(e) => ctx.walk_expr(e, errors),
            crate::ast::FnBody::External => {}
        }
    };
    for item in &module.items {
        if let Item::Fn(fd) = item { visit_fn(fd, errors); }
    }
    for pf in &module.peer_files {
        for item in &pf.items_here {
            if let Item::Fn(fd) = item { visit_fn(fd, errors); }
        }
    }
}

struct VrEscapeCtx<'a> {
    value_records: &'a std::collections::HashSet<String>,
    vr_locals: std::collections::HashMap<String, String>, // binding → type-name
    consumed: std::collections::HashSet<String>,         // names already consumed
}

impl<'a> VrEscapeCtx<'a> {
    fn resolve_vrt(&self, t: &TypeRef) -> Option<String> {
        if let TypeRef::Named { path, .. } = t {
            if let Some(last) = path.last() {
                if self.value_records.contains(last) {
                    return Some(last.clone());
                }
            }
        }
        None
    }
    fn infer_vrt_from_expr(&self, e: &crate::ast::Expr) -> Option<String> {
        if let crate::ast::ExprKind::RecordLit { type_name: Some(path), .. } = &e.kind {
            if let Some(last) = path.last() {
                if self.value_records.contains(last) {
                    return Some(last.clone());
                }
            }
        }
        None
    }
    fn walk_block(&mut self, b: &crate::ast::Block, errors: &mut Vec<Diagnostic>) {
        for s in &b.stmts { self.walk_stmt(s, errors); }
        if let Some(t) = &b.trailing { self.walk_expr(t, errors); }
    }
    fn walk_stmt(&mut self, s: &crate::ast::Stmt, errors: &mut Vec<Diagnostic>) {
        match s {
            crate::ast::Stmt::Let(d) => {
                // First walk RHS — escape detection on RHS may flag prior consumed.
                self.walk_expr(&d.value, errors);
                if let crate::ast::Pattern::Ident { name, .. } = &d.pattern {
                    if let Some(vrt) = d.ty.as_ref().and_then(|t| self.resolve_vrt(t))
                        .or_else(|| self.infer_vrt_from_expr(&d.value))
                    {
                        self.vr_locals.insert(name.clone(), vrt);
                        if d.consume {
                            // `consume v = ...` value-record binding — consumed at bind site.
                            self.consumed.insert(name.clone());
                        }
                    }
                }
            }
            crate::ast::Stmt::Expr(e) => self.walk_expr(e, errors),
            crate::ast::Stmt::Assign { target, value, .. } => {
                self.walk_expr(target, errors);
                self.walk_expr(value, errors);
            }
            crate::ast::Stmt::Return { value: Some(v), .. } => self.walk_expr(v, errors),
            crate::ast::Stmt::Throw { value, .. } => self.walk_expr(value, errors),
            crate::ast::Stmt::Defer { body, .. }
            | crate::ast::Stmt::ErrDefer { body, .. }
            | crate::ast::Stmt::OkDefer { body, .. }
            | crate::ast::Stmt::DeferWithResult { body, .. } => self.walk_expr(body, errors),
            crate::ast::Stmt::ConsumeScope { init, body, .. } => {
                self.walk_expr(init, errors);
                self.walk_block(body, errors);
            }
            crate::ast::Stmt::AssertStatic { expr, .. } | crate::ast::Stmt::Assume { expr, .. } => {
                self.walk_expr(expr, errors);
            }
            _ => {}
        }
    }
    fn walk_expr(&mut self, e: &crate::ast::Expr, errors: &mut Vec<Diagnostic>) {
        use crate::ast::{ExprKind, UnOp};
        match &e.kind {
            ExprKind::Unary { op: UnOp::AddrOf, operand } => {
                // Plan 127 E_VALUE_RECORD_ESCAPE_AFTER_CONSUME check.
                if let ExprKind::Ident(name) = &operand.kind {
                    if self.vr_locals.contains_key(name) && self.consumed.contains(name) {
                        errors.push(Diagnostic::new(
                            format!(
                                "[E_VALUE_RECORD_ESCAPE_AFTER_CONSUME] `&{}` после \
                                 consume value-record `{}`: stack-allocated slot \
                                 логически drained — taking address invalid (D228 \
                                 §«escape & auto-promote»). Consume-методы / consume-\
                                 binding инвалидируют локал; subsequent `&v` создаёт \
                                 dangling-pointer семантику. Если address нужен — \
                                 take его BEFORE consume.",
                                name, name
                            ),
                            e.span,
                        ));
                    }
                }
                self.walk_expr(operand, errors);
            }
            ExprKind::Call { func, args, .. } => {
                // Method-call с consume receiver: receiver Ident → mark consumed.
                // Conservative detection: instance-method call `recv.m(...)` where
                // recv is value-record local; without method-registry lookup we
                // skip this — full integration с consume-registry в follow-up.
                self.walk_expr(func, errors);
                for a in args {
                    self.walk_expr(a.expr(), errors);
                }
            }
            ExprKind::Binary { left, right, .. } => {
                self.walk_expr(left, errors);
                self.walk_expr(right, errors);
            }
            ExprKind::Unary { operand, .. } => self.walk_expr(operand, errors),
            ExprKind::Block(b) => self.walk_block(b, errors),
            ExprKind::Member { obj, .. } => self.walk_expr(obj, errors),
            ExprKind::Index { obj, index } => {
                self.walk_expr(obj, errors);
                self.walk_expr(index, errors);
            }
            ExprKind::If { cond, then, else_ } => {
                self.walk_expr(cond, errors);
                self.walk_block(then, errors);
                if let Some(eb) = else_ {
                    match eb {
                        crate::ast::ElseBranch::Block(b) => self.walk_block(b, errors),
                        crate::ast::ElseBranch::If(ie) => self.walk_expr(ie, errors),
                    }
                }
            }
            ExprKind::Match { scrutinee, arms } => {
                self.walk_expr(scrutinee, errors);
                for arm in arms {
                    if let Some(g) = &arm.guard { self.walk_expr(g, errors); }
                    match &arm.body {
                        crate::ast::MatchArmBody::Expr(ex) => self.walk_expr(ex, errors),
                        crate::ast::MatchArmBody::Block(b) => self.walk_block(b, errors),
                    }
                }
            }
            ExprKind::Try(i) | ExprKind::Bang(i) => self.walk_expr(i, errors),
            ExprKind::Coalesce(a, b) => { self.walk_expr(a, errors); self.walk_expr(b, errors); }
            ExprKind::As(i, _) | ExprKind::Is(i, _) => self.walk_expr(i, errors),
            _ => {}
        }
    }
}

fn check_consume(module: &Module, errors: &mut Vec<Diagnostic>) {
    let reg = ConsumeRegistry::build(module);
    // Plan 100.1 (D133): LinearityRegistry + marker consistency.
    let lin_reg = LinearityRegistry::build(module);
    check_linearity_markers(module, &lin_reg, errors);

    for item in &module.items {
        match item {
            Item::Fn(f) => {
                let mut ctx = ConsumeCtx::new(&reg, &lin_reg);

                // Plan 100.2 (D156): collect `[T consume]` bound generics.
                // Внутри тела функции параметры с такими типами —
                // consume-obligations (strict-mode D156).
                let consume_bound_generics: HashSet<String> = f.generics.iter()
                    .filter(|g| g.consume_bound)
                    .map(|g| g.name.clone())
                    .collect();
                ctx.consume_bound_generics = consume_bound_generics.clone();

                // Параметры функции — live на входе.
                // Plan 100.2 (D156): если функция имеет `[T consume]` generics,
                // параметры с типом T (или содержащим T) — consume-obligations.
                for p in &f.params {
                    // Plan 108.1 (D176 amend): track param mutability.
                    // consume params получают неявно mut (по spec).
                    let effective_mut = p.is_mut || p.consume;
                    ctx.param_mut.insert(p.name.clone(), effective_mut);
                    // Plan 118.5 V2 [M-118.5-arg-coerce-unsafe]: track
                    // unsafe-T-annotated params (outer Unsafe wrapper detected
                    // before any Pointer wrapper).
                    if p.ty.outer_unsafe_before_pointer() {
                        ctx.unsafe_t_locals.insert(p.name.clone());
                    }
                    // Plan 108.1 followup: track readonly-annotated params.
                    if matches!(&p.ty, TypeRef::Readonly(..)) {
                        ctx.readonly_locals.insert(p.name.clone());
                    }
                    let pty = match &p.ty {
                        TypeRef::Named { path, .. } if path.len() == 1 =>
                            Some(path[0].clone()),
                        _ => None,
                    };
                    // Plan 100.2: param type contains consume-bound generic → obligation.
                    let is_consume_generic_param =
                        typeref_contains_consume_generic(&p.ty, &consume_bound_generics);
                    if is_consume_generic_param {
                        // Plan 100.2 (D156): if param type is not a simple Named
                        // (e.g. tuple `(T, T)`) but contains a consume-bound generic,
                        // store the generic name as the type so that D156-strict-forget
                        // is emitted (not D133) on obligation failure.
                        let pty = pty.or_else(|| {
                            consume_bound_generics.iter().find(|g| {
                                let g_set: HashSet<String> =
                                    std::iter::once((*g).clone()).collect();
                                typeref_contains_consume_generic(&p.ty, &g_set)
                            }).cloned()
                        });
                        ctx.declare_consume_binding(&p.name, pty);
                    } else if p.consume {
                        // Explicit `consume` param: consume-obligation.
                        ctx.declare_consume_binding(&p.name, pty);
                    } else {
                        // Plan 100.3 (D157): non-consume param of consume type
                        // → view-param. Can read fields, call non-consume methods,
                        // pass to other view-params. Cannot call consume-methods,
                        // cannot return.
                        let is_consume_type = pty.as_ref()
                            .map(|t| lin_reg.consume_types.contains(t))
                            .unwrap_or(false);
                        if is_consume_type {
                            ctx.declare_view_param(&p.name, pty);
                        } else {
                            ctx.declare(&p.name, pty);
                        }
                    }
                }
                // Plan 100.1 (D133 / D5): инициализация consume-полей receiver'а.
                if let Some(recv) = &f.receiver {
                    // Plan 103.9 (D174): track self-type for method call inference.
                    // `consume g = self.lock()` needs to know `self` is `Mutex`.
                    ctx.self_type = Some(recv.type_name.clone());
                    for it in &module.items {
                        if let Item::Type(td) = it {
                            if td.name == recv.type_name {
                                if let TypeDeclKind::Record(fields) = &td.kind {
                                    for field in fields {
                                        if field.consume {
                                            ctx.init_field_live(&field.name);
                                        }
                                    }
                                }
                                break;
                            }
                        }
                    }
                }
                match &f.body {
                    FnBody::Block(b) => {
                        // Plan 73.1 V3 [M-73.1-fluent-return-implicit-consume]:
                        // FnBody-level trailing fluent-chain → mark chain root
                        // Consumed via the `is_fn_body_trailing` variant.
                        consume_walk_block_inner(&mut ctx, b, errors, true);
                        // Plan 100.1 (D133): exit-point checks.
                        let exit_span = b.span;
                        ctx.check_obligations_at_exit(exit_span, errors);
                        // Field-exit check for methods.
                        if let Some(recv) = &f.receiver {
                            ctx.check_fields_at_exit(
                                &recv.type_name,
                                recv.consume,
                                &f.name,
                                exit_span,
                                errors,
                            );
                        }
                        // Plan 100.8 (D166): D162 coverage check — errdefer/okdefer
                        // for consume vars in failable functions.
                        check_d162_coverage(f, &ctx, b, errors, &lin_reg);
                    }
                    FnBody::Expr(e) => {
                        consume_walk_expr(&mut ctx, e, errors);
                        // Plan 100.2: FnBody::Expr trailing ident = implicit return.
                        // Plan 73.1 V3 [M-73.1-fluent-return-implicit-consume]: also
                        // covers fluent-return method-chains (parity with
                        // `consume_walk_block` trailing path).
                        if let Some(name) = implicit_return_consume_var(&ctx, e) {
                            ctx.mark_consumed(&name, e.span);
                        }
                        ctx.check_obligations_at_exit(e.span, errors);
                    }
                    FnBody::External => {}
                }
            }
            Item::Test(t) => {
                let mut ctx = ConsumeCtx::new(&reg, &lin_reg);
                consume_walk_block(&mut ctx, &t.body, errors);
                // Plan 100.1 (D133): exit-point checks for test scope.
                ctx.check_obligations_at_exit(t.body.span, errors);
            }
            _ => {}
        }
    }
}

// ── Plan 100.8 (D166): D162 coverage check helpers ───────────────────────────

/// Check if a function's effect list contains `Fail[...]` or bare `Fail`
/// (indicating the function can throw).
fn fn_is_failable(effects: &[TypeRef]) -> bool {
    effects.iter().any(|e| {
        if let TypeRef::Named { path, .. } = e {
            path.last().map(|n| n == "Fail").unwrap_or(false)
        } else {
            false
        }
    })
}

/// Recursively scan a block for `errdefer` / `okdefer` / `defer` stmts.
/// Returns (has_errdefer, has_okdefer) — both are coarse: presence of ANY
/// errdefer/okdefer in the direct stmts (non-nested) is sufficient for
/// the D162 simplified check.
///
/// Plan 100.7 (D165): plain `defer` runs on ALL exits (including error path),
/// so it counts as errdefer-coverage for D162-uncovered-error-path purposes.
fn scan_defer_coverage(b: &Block) -> (bool, bool) {
    let mut has_errdefer = false;
    let mut has_okdefer = false;
    for s in &b.stmts {
        match s {
            Stmt::ErrDefer { .. } | Stmt::DeferWithResult { .. } => {
                has_errdefer = true;
            }
            Stmt::OkDefer { .. } => {
                has_okdefer = true;
            }
            // Plain `defer` runs on ALL exits (success + error + cancel).
            // Counts as both errdefer and okdefer coverage for D162.
            Stmt::Defer { .. } => {
                has_errdefer = true;
                has_okdefer = true;
            }
            _ => {}
        }
    }
    (has_errdefer, has_okdefer)
}

/// Plan 100.8 (D166): Simplified D162 coverage check.
///
/// Emits `D162-uncovered-error-path` when a failable function (`Fail[E]`
/// in effects) has consume bindings but no `errdefer` covering the error path.
///
/// This is the tooling-layer implementation of D162 (the full static-flow
/// version lives in Plan 100.4.5; this version provides IDE-feedback via
/// the D166 LSP quick-fix infrastructure).
fn check_d162_coverage(
    f: &FnDecl,
    ctx: &ConsumeCtx,
    block: &Block,
    errors: &mut Vec<Diagnostic>,
    lin_reg: &LinearityRegistry,
) {
    use crate::diag::{Applicability, Suggestion};

    // Only check failable functions with consume bindings ever declared.
    // Use all_declared_consume (not consume_obligations which is cleared after
    // each block exit).  Plan 100.8 (D166) fix: check D162 even when the var
    // is properly consumed on success path.
    if ctx.all_declared_consume.is_empty() { return; }
    if !fn_is_failable(&f.effects) { return; }

    let (has_errdefer, has_okdefer) = scan_defer_coverage(block);

    // D162-uncovered-error-path: failable function + consume binding + no errdefer.
    // Plan 100.7 (D165): body_has_throw tells us whether there are explicit throw
    // statements in the function body. Used below to distinguish "consumed at exit
    // via explicit error-branch handling" from "consumed at exit with no error paths."
    let body_throws = block_has_throw(block);
    if !has_errdefer {
        for name in &ctx.all_declared_consume {
            let canon = ctx.canonical(name);
            // Plan 100.7 (D165): if the consume variable is Consumed at fn-exit
            // AND the body contains at least one explicit `throw` statement,
            // the coder has explicitly handled the error path (e.g. tx.rollback()
            // before throw in a diverging branch). Skip D162 in this case.
            // If there are NO explicit throws but the variable is Consumed at exit,
            // the function is still Fail-annotated — D162 fires as a lint (external
            // handler injections can interrupt the function at any Fail-effect site).
            let state = ctx.states.get(&canon).or_else(|| ctx.states.get(name.as_str()));
            if matches!(state, Some(VarState::Consumed(_))) && body_throws {
                continue;
            }
            let ty = ctx.var_types.get(name)
                .or_else(|| ctx.var_types.get(&canon))
                .cloned()
                .unwrap_or_default();
            let methods = lin_reg.consume_methods_for(&ty);
            let cleanup_method = if methods.len() > 1 {
                methods.last().cloned().unwrap_or_default()
            } else {
                methods.first().cloned().unwrap_or_else(|| "cleanup".to_string())
            };
            let suggestion = Suggestion {
                message: format!(
                    "add `errdefer {{ {name}.{method}() }}` to cover error-path \
                     (D162-uncovered-error-path quick fix)",
                    name = name, method = cleanup_method),
                span: block.span,
                replacement: format!(
                    "errdefer {{ {name}.{method}() }}",
                    name = name, method = cleanup_method),
                applicability: Applicability::MachineApplicable,
            };
            errors.push(Diagnostic::new(
                format!(
                    "[D162-uncovered-error-path] consume binding `{}` (тип `{}`) \
                     в failable function без `errdefer` покрытия error-path. \
                     При throw/panic `{}` не будет cleaned up. \
                     Добавьте `errdefer {{ {}.{}() }}`.",
                    name, ty, name, name, cleanup_method),
                block.span,
            ).with_suggestion(suggestion));
        }
    }

    // D162-uncovered-success-path: failable function + consume + has errdefer
    // but no okdefer or explicit commit call on success path.
    // This is a lighter warning — we just note it (MaybeIncorrect suggestion).
    if has_errdefer && !has_okdefer {
        // Only emit if there are consume obligations (errdefer exists but
        // success path might be uncovered).
        // Simplified: check if the trailing expression of the block is a
        // consume method call (if not, suggest okdefer).
        let success_covered = block.trailing.as_ref().map(|t| {
            matches!(&t.kind, ExprKind::Call { func, .. }
                if matches!(&func.kind, ExprKind::Member { .. }))
        }).unwrap_or(false);
        if !success_covered {
            for name in &ctx.all_declared_consume {
                let canon = ctx.canonical(name);
                let ty = ctx.var_types.get(name)
                    .or_else(|| ctx.var_types.get(&canon))
                    .cloned()
                    .unwrap_or_default();
                let methods = lin_reg.consume_methods_for(&ty);
                let primary_method = methods.first().cloned()
                    .unwrap_or_else(|| "commit".to_string());
                // Only emit if var is still Live at function end (errdefer present
                // but actual consume may be missing). This is conservative —
                // we only emit for the first uncovered var.
                let state = ctx.states.get(&canon).or_else(|| ctx.states.get(name));
                if !matches!(state, Some(VarState::Live)) { continue; }
                let suggestion = Suggestion {
                    message: format!(
                        "add `okdefer {{ {name}.{method}() }}` or explicit call \
                         (D162-uncovered-success-path quick fix)",
                        name = name, method = primary_method),
                    span: block.span,
                    replacement: format!(
                        "okdefer {{ {name}.{method}() }}",
                        name = name, method = primary_method),
                    applicability: Applicability::MaybeIncorrect,
                };
                errors.push(Diagnostic::new(
                    format!(
                        "[D162-uncovered-success-path] consume binding `{}` (тип `{}`) \
                         имеет errdefer для error-path, но success-path может быть \
                         не покрыт. Добавьте `okdefer {{ {}.{}() }}` или явный вызов.",
                        name, ty, name, primary_method),
                    block.span,
                ).with_suggestion(suggestion));
                break; // Only first uncovered var to avoid noise.
            }
        }
    }
}

/// Объединить два VarState на слиянии путей (branch join).
fn consume_join2(a: &VarState, b: &VarState) -> VarState {
    match (a, b) {
        (VarState::Live, VarState::Live) => VarState::Live,
        (VarState::Consumed(s), VarState::Consumed(_)) => VarState::Consumed(*s),
        (VarState::MaybeConsumed(s), _) | (_, VarState::MaybeConsumed(s)) =>
            VarState::MaybeConsumed(*s),
        (VarState::Consumed(s), VarState::Live)
        | (VarState::Live, VarState::Consumed(s)) => VarState::MaybeConsumed(*s),
    }
}

/// Слить состояния веток. Базис — `saved` (pre-branch); ветка-локальные
/// переменные отбрасываются.
fn consume_join(saved: &HashMap<String, VarState>,
                a: &HashMap<String, VarState>,
                b: &HashMap<String, VarState>) -> HashMap<String, VarState> {
    let mut out = HashMap::new();
    for (k, base) in saved {
        let sa = a.get(k).unwrap_or(base);
        let sb = b.get(k).unwrap_or(base);
        out.insert(k.clone(), consume_join2(sa, sb));
    }
    out
}

/// Plan 108.1 followup ([M-108.1-readonly-to-explicit-mut-coerce]):
/// Check args at mut-param positions for readonly-binding source.
/// Передача readonly-binding (через `readonly_locals`) в `mut`-param
/// → E_READONLY_COERCE с machine-applicable Suggestion.
/// **Plan 118.5 V2 [M-118.5-member-index-call-broader] (2026-06-04):**
/// recursively walk Member/Index chain down к the root Ident. Used by
/// UnsafeCtx walk_expr Member/Index arms to detect access through unsafe-T
/// bindings (e.g. `x.field.subfield` where x: unsafe T → root is `x`).
/// Conservative: returns None for non-Ident / non-Member / non-Index roots
/// (no false-positives on inferred types).
fn unsafe_t_root_ident(e: &Expr) -> Option<String> {
    use crate::ast::ExprKind;
    match &e.kind {
        ExprKind::Ident(n) => Some(n.clone()),
        ExprKind::Member { obj, .. } => unsafe_t_root_ident(obj),
        ExprKind::Index { obj, .. } => unsafe_t_root_ident(obj),
        _ => None,
    }
}

/// **Plan 118.5 V2 [M-118.5-arg-coerce-unsafe] (2026-06-04):** passing
/// `unsafe T` binding к non-unsafe param outside unsafe context →
/// E_UNSAFE_ARG_REQUIRES_WRAP.
///
/// Parallel structure к `check_readonly_coerce_args` (D176 / Plan 108.1).
/// `non_unsafe_param_idxs` — positions of params whose declared type is NOT
/// `unsafe T` (after strip_modifiers check). Args at these positions whose
/// expression is Ident в `ctx.unsafe_t_locals` violate the contract — the
/// callee may read uninitialized memory.
fn check_unsafe_coerce_args(
    ctx: &ConsumeCtx,
    args: &[CallArg],
    non_unsafe_param_idxs: &[usize],
    errors: &mut Vec<Diagnostic>,
) {
    for &idx in non_unsafe_param_idxs {
        if let Some(CallArg::Item(arg)) = args.get(idx) {
            if let ExprKind::Ident(name) = &arg.kind {
                if ctx.unsafe_t_locals.contains(name) {
                    errors.push(Diagnostic::new(
                        format!(
                            "[E_UNSAFE_ARG_REQUIRES_WRAP] argument `{}` имеет \
                             тип `unsafe T`, но передаётся в non-unsafe \
                             parameter — нарушение sound subtyping (Plan \
                             118.5 V2 / D216 V2 §V2.3). callee может прочитать \
                             uninitialized value. Решения: (a) wrap call site \
                             в `unsafe {{ ... }}` block с явным narrow cast \
                             argument: `unsafe {{ fn_name({} as T, ...) }}`; \
                             (b) declare callee param как `unsafe T` (если \
                             callee действительно handles uninit values).",
                            name, name),
                        arg.span,
                    ));
                }
            }
        }
    }
}

fn check_readonly_coerce_args(
    ctx: &ConsumeCtx,
    args: &[CallArg],
    mut_param_idxs: &[usize],
    errors: &mut Vec<Diagnostic>,
) {
    for &idx in mut_param_idxs {
        if let Some(CallArg::Item(arg)) = args.get(idx) {
            if let ExprKind::Ident(name) = &arg.kind {
                if ctx.readonly_locals.contains(name) {
                    errors.push(Diagnostic::new(
                        format!(
                            "[E_READONLY_COERCE] аргумент `{}` имеет тип `readonly T`, но \
                             передаётся в `mut`-параметр — нарушение sound subtyping (D176, \
                             Plan 108.1 followup).  readonly binding гарантирует immutability \
                             у caller'а; передача в mut позволила бы callee'у мутировать.",
                            name),
                        arg.span,
                    ).with_note(
                        "решения: (a) убрать `readonly` annotation у source binding'а \
                         (если значение действительно мутируемое); (b) сделать callee-param \
                         non-mut (default readonly) или `readonly`; (c) скопировать значение \
                         в новый mutable binding перед передачей."
                            .to_string(),
                    ));
                }
            }
        }
    }
}

/// Plan 73.1 V3 [M-73.1-fluent-return-implicit-consume]:
/// Determine whether a trailing/return expression evaluates to a consume-
/// obligation variable directly OR via a fluent (`-> @`) method-chain.
///
/// Example: `sb.append(c)` where `mut @append(c char) -> @` (fluent) and
/// `sb` is a consume-obligation → returns `Some("sb")` because the chain
/// value IS `sb`.  Recurses through arbitrarily long chains
/// (`sb.append(x).append(y).truncate(n)`).
///
/// Returns the binding name to mark Consumed; `None` when the expression
/// does not transitively return a consume-obligation var.
fn implicit_return_consume_var(ctx: &ConsumeCtx, e: &Expr) -> Option<String> {
    match &e.kind {
        ExprKind::Ident(name) => {
            if ctx.consume_obligations.contains(name.as_str()) {
                Some(name.to_string())
            } else {
                None
            }
        }
        ExprKind::Call { func, .. } => {
            let ExprKind::Member { obj, name: method } = &func.kind else {
                return None;
            };
            // Chain root must transitively reduce to a consume-obligation var.
            let root = implicit_return_consume_var(ctx, obj)?;
            // Fluent chain preserves receiver type — look up receiver type by
            // the chain root.  Match in `recv_returning` registry.
            let ty = ctx.var_types.get(&root)?.clone();
            if ctx.reg.recv_returning.contains(&(ty, method.clone())) {
                Some(root)
            } else {
                None
            }
        }
        _ => None,
    }
}

fn consume_walk_block(ctx: &mut ConsumeCtx, b: &Block, errors: &mut Vec<Diagnostic>) {
    consume_walk_block_inner(ctx, b, errors, false);
}

/// Plan 73.1 V3: variant taking `is_fn_body_trailing` flag.  When true,
/// the block's trailing expression is treated as the function's implicit
/// return value, so a fluent-chain trailing
/// (`sb.append(x).append(y)`) marks its consume-obligation root Consumed.
/// Nested blocks (if-then, loop-body, regular `{}`) call with `false`
/// because their trailing value is usually discarded by the outer
/// statement / if-without-else.
fn consume_walk_block_inner(
    ctx: &mut ConsumeCtx,
    b: &Block,
    errors: &mut Vec<Diagnostic>,
    is_fn_body_trailing: bool,
) {
    // Plan 100.1 (D133): track consume-obligations introduced in this block.
    // На exit'е блока проверяем только NEW obligations (не было до входа).
    let obligations_before = ctx.consume_obligations.clone();

    for s in &b.stmts {
        consume_walk_stmt(ctx, s, errors);
    }
    if let Some(t) = &b.trailing {
        consume_walk_expr(ctx, t, errors);
        // Plan 100.1 (D133 / D9): trailing expr = implicit return.
        // Ident-trailing always counts as implicit-return-of-value (existing
        // V1 semantics — preserved for compatibility).  Fluent-chain
        // trailing only counts when this block is the function body
        // (Plan 73.1 V3 [M-73.1-fluent-return-implicit-consume]).
        if is_fn_body_trailing {
            if let Some(name) = implicit_return_consume_var(ctx, t) {
                ctx.mark_consumed(&name, t.span);
            }
        } else if let ExprKind::Ident(name) = &t.kind {
            if ctx.consume_obligations.contains(name.as_str()) {
                ctx.mark_consumed(name, t.span);
            }
        }
    }

    // Plan 100.1 (D133): exit-check для obligations введённых в этом блоке
    // (не в outer scope — те проверяются при function-exit).
    let new_obligations: Vec<String> = ctx.consume_obligations.iter()
        .filter(|n| !obligations_before.contains(n.as_str()))
        .cloned()
        .collect();
    if !new_obligations.is_empty() {
        // Временно ограничить consume_obligations только новыми, чтобы
        // check_obligations_at_exit не дублировал outer-scope проверки.
        let full_obligations = std::mem::replace(
            &mut ctx.consume_obligations,
            new_obligations.iter().cloned().collect());
        ctx.check_obligations_at_exit(b.span, errors);
        ctx.consume_obligations = full_obligations;
        // Убрать проверённые обязательства (они выполнились или ошибка эмитирована).
        for n in &new_obligations {
            ctx.consume_obligations.remove(n);
        }
    }
}

fn consume_walk_stmt(ctx: &mut ConsumeCtx, s: &Stmt, errors: &mut Vec<Diagnostic>) {
    match s {
        Stmt::Let(decl) => {
            consume_walk_expr(ctx, &decl.value, errors);
            let mut names = Vec::new();
            consume_pattern_names(&decl.pattern, &mut names);
            // Plan 108.2 (D36 enforcement) + 108.3 (per-name mut):
            // `let mut x` → is_mut=true; `let x` → false;
            // `consume x` → implicit mut (ownership transfer).
            // `let (mut a, b) = ...` → per-name (a=true, b=false).
            let outer_effective_mut = decl.mutable || decl.consume;
            let mut name_mut_pairs = Vec::new();
            consume_pattern_names_with_mut(&decl.pattern, &mut name_mut_pairs);
            for (n, pat_mut) in &name_mut_pairs {
                if n != "_" {
                    // outer `let mut` || per-name `mut` || consume.
                    ctx.local_mut.insert(n.clone(), outer_effective_mut || *pat_mut);
                }
            }
            // Plan 108.1 followup: track readonly-annotated locals.
            // `let view readonly T = ...` → readonly_locals.contains("view").
            let is_readonly_annotated = matches!(&decl.ty, Some(TypeRef::Readonly(..)));
            if is_readonly_annotated {
                for n in &names {
                    if n != "_" {
                        ctx.readonly_locals.insert(n.clone());
                    }
                }
            }
            // Plan 118.5 V2 [M-118.5-arg-coerce-unsafe]: track unsafe-T
            // locals. Detect `let x unsafe T = ...` via the same
            // outer_unsafe_before_pointer() helper used by Stmt::Let
            // registration в UnsafeCtx.
            let is_unsafe_t_annotated = decl.ty.as_ref()
                .map_or(false, |t| t.outer_unsafe_before_pointer());
            if is_unsafe_t_annotated {
                for n in &names {
                    if n != "_" {
                        ctx.unsafe_t_locals.insert(n.clone());
                    }
                }
            }
            // alias-форма `let <name> = <rhs>` — `name` ссылается на тот
            // же объект:
            //   (a) Plan 73 followup: `let a = b` — RHS голый идентификатор.
            //   (b) Plan 77 (D132): `let x = recv.fluent()` — fluent-метод
            //       `-> @` гарантированно возвращает сам receiver.
            let alias_src: Option<String> = if names.len() == 1 {
                match &decl.value.kind {
                    ExprKind::Ident(src) => {
                        let canon = ctx.canonical(src);
                        if canon != names[0] && ctx.states.contains_key(&canon) {
                            Some(canon)
                        } else { None }
                    }
                    ExprKind::Call { func, .. } => {
                        if let ExprKind::Member { obj, name: method } = &func.kind {
                            if let ExprKind::Ident(recv) = &obj.kind {
                                let canon = ctx.canonical(recv);
                                let fluent = ctx.var_types.get(&canon)
                                    .map(|ty| ctx.reg.recv_returning
                                        .contains(&(ty.clone(), method.clone())))
                                    .unwrap_or(false);
                                if fluent && canon != names[0]
                                    && ctx.states.contains_key(&canon)
                                {
                                    Some(canon)
                                } else { None }
                            } else { None }
                        } else { None }
                    }
                    _ => None,
                }
            } else { None };
            // Plan 73.1 (D180): consume binding syntax enforcement.
            // Pre-compute: is RHS consume-obligated? Is alias source consume-obligated?
            let inferred_ty_d180 = ctx.infer_let_type(decl);
            let rhs_yields_consume_type = inferred_ty_d180.as_ref()
                .map(|ty| ctx.lin_reg.consume_types.contains(ty))
                .unwrap_or(false);
            let alias_obligated = if let Some(canon) = &alias_src {
                ctx.consume_obligations.contains(canon)
                    || ctx.var_types.get(canon)
                        .map(|ty| ctx.lin_reg.consume_types.contains(ty))
                        .unwrap_or(false)
            } else { false };

            // `let` keyword span — replace with `consume` (3 chars → 7 chars, but
            // span-based replacement just covers the keyword position).
            // decl.span.start points to `let` (3 chars) или `consume` (7 chars).
            let kw_span = crate::diag::Span {
                file_id: decl.span.file_id,
                start: decl.span.start,
                end: decl.span.start + 3, // "let" = 3 chars; if `consume` present, end overlaps but suggestion ignored
            };

            // Rule 2 (D180): `let X = consume_var` (alias) → E_VIEW_BINDING_FORBIDDEN.
            if !decl.consume && alias_obligated && names.len() == 1 {
                errors.push(crate::diag::Diagnostic::new(
                    format!(
                        "[E_VIEW_BINDING_FORBIDDEN] view-binding на consume-обязательную \
                         переменную `{}` запрещён в теле функции (D180). \
                         Used `let` без consume keyword.",
                        names[0]
                    ),
                    decl.span,
                ).with_note(
                    "views существуют ТОЛЬКО как function-параметры (D157). \
                     Для transfer ownership используй `consume X = …` (move); \
                     для view-borrow перенеси в function-параметр.".to_string(),
                ).with_suggestion(crate::diag::Suggestion {
                    message: format!("use `consume {} = …` для move ownership", names[0]),
                    span: kw_span,
                    replacement: "consume".to_string(),
                    applicability: crate::diag::Applicability::MachineApplicable,
                }));
            }
            // Rule 1 (D180): non-alias consume-obligated RHS без `consume` keyword.
            else if !decl.consume && rhs_yields_consume_type && names.len() == 1 {
                errors.push(crate::diag::Diagnostic::new(
                    format!(
                        "[E_CONSUME_KEYWORD_MISSING] binding `{}` держит \
                         consume-обязательную инстанс типа `{}` — требуется keyword \
                         `consume` (D180).",
                        names[0],
                        inferred_ty_d180.as_deref().unwrap_or("?")
                    ),
                    decl.span,
                ).with_note(
                    "consume-обязательные значения должны быть явно ownership-bound \
                     через `consume X = …`. Альтернатива: передать в function-параметр \
                     для view-borrow.".to_string(),
                ).with_suggestion(crate::diag::Suggestion {
                    message: format!("add `consume` keyword: `consume {} = …`", names[0]),
                    span: kw_span,
                    replacement: "consume".to_string(),
                    applicability: crate::diag::Applicability::MachineApplicable,
                }));
            }
            // W_CONSUME_KEYWORD_UNNECESSARY: `consume` keyword на binding с
            // не-consume RHS. Эмитится только когда тип ОБЪЯВЛЕН ЛОКАЛЬНО в
            // текущем модуле (local_type_names). Для внешних типов (stdlib,
            // ExternalRegistry) мы не можем надёжно определить consume-статус
            // из module.items → предупреждение не эмитится (false-negative,
            // но не false-positive). Это корректно: пользовательские типы из
            // stdlib могут быть consume без попадания в module.items.
            //
            // Conservative: emit только когда inferred_ty_d180.is_some() —
            // т.е. тип известен и НЕ consume. Если тип неизвестен (None),
            // skip (sound: false-negative permissive, не false-positive).
            else if decl.consume && !rhs_yields_consume_type && !alias_obligated
                && names.len() == 1
                && inferred_ty_d180.as_ref().map(|ty| {
                    ctx.lin_reg.local_type_names.contains(ty.as_str())
                }).unwrap_or(false)
            {
                let consume_kw_span = crate::diag::Span {
                    file_id: decl.span.file_id,
                    start: decl.span.start,
                    end: decl.span.start + 8, // "consume " = 8 chars
                };
                errors.push(crate::diag::Diagnostic::new(
                    format!(
                        "[W_CONSUME_KEYWORD_UNNECESSARY] keyword `consume` на binding \
                         `{}` избыточен — RHS типа `{}` не consume-обязателен (D180).",
                        names[0],
                        inferred_ty_d180.as_deref().unwrap_or("?")
                    ),
                    consume_kw_span,
                ).with_note(
                    "удали `consume ` для regular let-binding.".to_string(),
                ).with_suggestion(crate::diag::Suggestion {
                    message: "delete `consume ` keyword".to_string(),
                    span: consume_kw_span,
                    replacement: "let".to_string(),
                    applicability: crate::diag::Applicability::MachineApplicable,
                }));
            }

            // Rule 3 (D180): `consume X = consume_var` = move semantics
            // (mark source Consumed, transfer obligation to X).
            if let Some(ref canon) = alias_src {
                if decl.consume && alias_obligated && names.len() == 1 {
                    // Move: source becomes Consumed, X gets new obligation.
                    ctx.mark_consumed(canon, decl.span);
                    ctx.consume_obligations.remove(canon);
                    let ty = ctx.var_types.get(canon).cloned();
                    ctx.declare_consume_binding(&names[0], ty);
                    // Skip the existing alias/declare path below.
                    return;
                }
            }

            if let Some(canon) = alias_src {
                let ty = ctx.var_types.get(&canon).cloned();
                ctx.declare_alias(&names[0], &canon, ty);
            } else {
                let ty = ctx.infer_let_type(decl);
                // Plan 100.3 (D157): detect consume-closures.
                // If the RHS is a closure that calls consume-methods on outer
                // consume-obligation vars, it becomes a consume-closure (FnOnce).
                let closure_body_for_scan: Option<&Expr> = match &decl.value.kind {
                    ExprKind::ClosureLight { body: ClosureBody::Expr(ex), .. } => Some(ex),
                    ExprKind::Lambda { body, .. } => Some(body),
                    _ => None,
                };
                let consume_closure_captured: Option<Vec<String>> =
                    if names.len() == 1 && !decl.consume {
                        closure_body_for_scan.map(|body| {
                            d157_scan_closure_captures(body, &ctx.consume_obligations, ctx)
                        }).filter(|caps| !caps.is_empty())
                    } else { None };

                for n in &names {
                    // Тип привязываем только к одиночному ident-pattern'у.
                    let t = if names.len() == 1 { ty.clone() } else { None };
                    // Plan 100.1 (D133 / D9): `consume tx = ...` binding.
                    if decl.consume {
                        ctx.declare_consume_binding(n, t);
                    } else if let Some(ref captured) = consume_closure_captured {
                        // Plan 100.3 (D157): consume-closure — declares as consume-obligation.
                        ctx.declare_consume_closure(n, captured.clone());
                    } else {
                        ctx.declare(n, t);
                    }
                }
            }
        }
        // Plan 114.4 Ф.2: scope-local const — pass-through (no-op for now).
        Stmt::Const(_) => {}
        Stmt::Expr(e) => consume_walk_expr(ctx, e, errors),
        Stmt::Assign { target, op, value, .. } => {
            consume_walk_expr(ctx, value, errors);
            match &target.kind {
                ExprKind::Ident(name) => {
                    if matches!(op, AssignOp::Assign) {
                        // `x = v` — свежее значение. Развязываем alias-класс
                        // `x` (прочие члены сохраняют прежнее состояние), x
                        // получает новый объект → live и сам по себе.
                        ctx.dissolve_alias_class(name);
                        ctx.aliases.remove(name);
                        ctx.states.insert(name.clone(), VarState::Live);
                    } else {
                        // compound `+=` и т.п. читают старое значение.
                        ctx.use_var(name, target.span, errors);
                        let canon = ctx.canonical(name);
                        ctx.states.insert(canon, VarState::Live);
                    }
                }
                // Plan 100.1 (D5.1): `@<field> = v` — field rebind.
                // Если поле consume-типа и было Live → D133-assign-live-field.
                // После assign — поле Live снова (rebind).
                ExprKind::Member { obj, name: field_name }
                    if matches!(obj.kind, ExprKind::SelfAccess)
                        && matches!(op, AssignOp::Assign) =>
                {
                    // Plan 100.1 (D5.1): check: если поле было Live (полностью
                    // не consumed, без частичного consume sub-fields) →
                    // silent-overwrite error. MaybeConsumed = sub-field was
                    // consumed (D5.2 nested pattern) → assign is OK (rebind).
                    if let Some(VarState::Live) = ctx.field_states.get(field_name.as_str()) {
                        errors.push(Diagnostic::new(
                            format!(
                                "[D133-assign-live-field] присваивание в Live \
                                 consume-поле `@.{}` без предшествующего consume — \
                                 silent leak. Сначала consume: `@{}.<consume-method>()`, \
                                 затем присвойте новое значение.",
                                field_name, field_name),
                            target.span,
                        ));
                    }
                    // Rebind → поле Live снова (восстановлено независимо от предыдущего состояния).
                    ctx.mark_field_live(field_name);
                }
                _ => consume_walk_expr(ctx, target, errors),
            }
        }
        Stmt::Return { value, span } => {
            if let Some(v) = value {
                consume_walk_expr(ctx, v, errors);
                if let ExprKind::Ident(name) = &v.kind {
                    // Plan 100.3 (D157): view-param cannot escape via return.
                    if ctx.is_view_param(name) {
                        errors.push(Diagnostic::new(
                            format!(
                                "[D157-view-escape-return] `{}` — view-param (read-only borrow): \
                                 нельзя вернуть из функции. View-borrow не может outlive scope \
                                 source'а. Используйте `consume` qualifier на параметре для \
                                 transfer ownership.",
                                name),
                            *span,
                        ));
                    }
                    // Plan 100.1 (D133 / D9): `return tx` — обязательство
                    // передаётся caller'у. Пометить возвращённый consume-var как
                    // Consumed (obligation satisfied by transfer).
                    if ctx.consume_obligations.contains(name.as_str()) {
                        ctx.mark_consumed(name, *span);
                    }
                }
            }
        }
        Stmt::Throw { value, .. } => consume_walk_expr(ctx, value, errors),
        Stmt::Break(_) | Stmt::Continue(_) | Stmt::Reveal { .. } => {}
        // defer/errdefer/okdefer/defer-with-result исполняются на scope-exit.
        // Plan 100.4.5 (D162): тело walk'ается изолированно (use-after-consume
        // ловится, consume наружу не протекает), НО любой consume-call над
        // outer consume-var (`@var.consume_method()` или `consume_fn(@var)`)
        // mark'ает var как Consumed в outer ctx — D162 cover semantic.
        //
        // Side-effect: explicit `tx.commit()` AFTER `defer { tx.commit() }` →
        // use-after-consume error (D162-double-cover from check_d162_coverage
        // tooling layer also captures this).
        Stmt::Defer { body, .. } | Stmt::ErrDefer { body, .. }
        | Stmt::OkDefer { body, .. } | Stmt::DeferWithResult { body, .. } => {
            // Collect outer consume-vars consumed inside body (pre-walk snapshot).
            let pre_obligations: HashSet<String> = ctx.consume_obligations.clone();
            consume_walk_isolated_expr(ctx, &[], body, errors);
            // D162 cover: mark outer consume-vars referenced via consume-method
            // call inside body as Consumed.
            d162_mark_defer_cover(ctx, body, &pre_obligations);
        }
        // Plan 110 D188: consume scope-block. Init expression evaluated +
        // body block walked. Full consume-binding semantics (binding visible
        // только в body; on_exit dispatch как auto-consume) — Plan 110.1.2.
        // Здесь walk recursively, не вводим binding в obligations (110.1.2
        // обязанность).
        Stmt::ConsumeScope { init, body, .. } => {
            consume_walk_expr(ctx, init, errors);
            for stmt in &body.stmts {
                consume_walk_stmt(ctx, stmt, errors);
            }
            if let Some(t) = &body.trailing {
                consume_walk_expr(ctx, t, errors);
            }
        }
        Stmt::AssertStatic { expr, .. } | Stmt::Assume { expr, .. } => {
            consume_walk_expr(ctx, expr, errors);
        }
        Stmt::Apply { args, .. } => {
            for a in args { consume_walk_expr(ctx, a, errors); }
        }
        Stmt::Calc { steps, .. } => {
            for st in steps { consume_walk_expr(ctx, &st.expr, errors); }
        }
        // Plan 136 Ф.2: tuple destructuring assignment — semantic validation.
        Stmt::TupleAssign { lhs, rhs, span } => {
            // 1. Arity check.
            if lhs.len() != rhs.len() {
                errors.push(Diagnostic::new(
                    format!(
                        "[E_TUPLE_ASSIGN_ARITY_MISMATCH] tuple assign: {} lhs elements \
                         but {} rhs elements — counts must match (Plan 136 D236).",
                        lhs.len(), rhs.len()
                    ),
                    *span,
                ));
                // Still walk sub-expressions for further diagnostics.
                for e in lhs { consume_walk_expr(ctx, e, errors); }
                for e in rhs { consume_walk_expr(ctx, e, errors); }
                return;
            }
            // 2. Per-lhs-element checks: mutability + consume-type ban.
            for (i, lhs_expr) in lhs.iter().enumerate() {
                if let Some(root) = lvalue_root_ident(lhs_expr) {
                    let root = root.to_string();
                    // (a) Mutability check via param_mut / local_mut.
                    let is_param = ctx.param_mut.contains_key(&root);
                    let is_local = ctx.local_mut.contains_key(&root);
                    if is_param {
                        let is_mut = ctx.param_mut[&root];
                        if !is_mut {
                            errors.push(Diagnostic::new(
                                format!(
                                    "[E_TUPLE_ASSIGN_LHS_NOT_MUT] tuple assign: lhs element {} \
                                     (`{}`) is a param not marked `mut` — cannot assign \
                                     (Plan 136 D236; D176 amend default-readonly params).",
                                    i, root
                                ),
                                lhs_expr.span,
                            ));
                        }
                    } else if is_local {
                        let is_mut = ctx.local_mut[&root];
                        if !is_mut {
                            errors.push(Diagnostic::new(
                                format!(
                                    "[E_TUPLE_ASSIGN_LHS_NOT_MUT] tuple assign: lhs element {} \
                                     (`{}`) is a local binding not marked `mut` — cannot assign \
                                     (Plan 136 D236; D36 locals readonly by default).",
                                    i, root
                                ),
                                lhs_expr.span,
                            ));
                        }
                    }
                    // (b) Consume-type ban: type of lhs element must not be consume.
                    let ty_str = ctx.var_types.get(&ctx.canonical(&root))
                        .or_else(|| ctx.var_types.get(&root))
                        .cloned();
                    if let Some(ref ty) = ty_str {
                        if ctx.lin_reg.consume_types.contains(ty) {
                            errors.push(Diagnostic::new(
                                format!(
                                    "[E_TUPLE_ASSIGN_CONSUME_TYPE] tuple assign: lhs element {} \
                                     (`{}`) has consume type `{}` — tuple destructuring assignment \
                                     of consume types is not supported in V1 (Plan 136 D236). \
                                     Use explicit consume binding or consume-method.",
                                    i, root, ty
                                ),
                                lhs_expr.span,
                            ));
                        }
                    }
                }
            }
            // 3. Walk all sub-expressions (consume tracking, use-after-consume, etc).
            for e in lhs { consume_walk_expr(ctx, e, errors); }
            for e in rhs { consume_walk_expr(ctx, e, errors); }
        }
    }
}

/// Walk блока изолированно (closure / handler / trailing): состояние
/// `states` восстанавливается после — consume внутрь наружу не течёт.
fn consume_walk_isolated_block(ctx: &mut ConsumeCtx, params: &[String],
                               b: &Block, errors: &mut Vec<Diagnostic>) {
    let saved = ctx.states.clone();
    for p in params { ctx.declare(p, None); }
    consume_walk_block(ctx, b, errors);
    ctx.states = saved;
}

fn consume_walk_isolated_expr(ctx: &mut ConsumeCtx, params: &[String],
                              e: &Expr, errors: &mut Vec<Diagnostic>) {
    let saved = ctx.states.clone();
    for p in params { ctx.declare(p, None); }
    consume_walk_expr(ctx, e, errors);
    ctx.states = saved;
}

/// Plan 100.4.5 (D162): scan defer/errdefer/okdefer body для consume-method
/// calls над outer consume-vars. Mark такие vars как Consumed в outer ctx.
///
/// `pre_obligations` — snapshot consume_obligations ДО body walk; используется
/// для filtering (mark только outer vars, не inner-bindings из body).
///
/// Simplified bootstrap implementation:
/// - Recursively walk body expr.
/// - Detect `<ident>.<method>()` form where `<ident>` ∈ pre_obligations and
///   `<method>` ∈ consume-methods-for(var's type).
/// - mark_consumed for each matched var.
fn d162_mark_defer_cover(ctx: &mut ConsumeCtx, body: &Expr, pre_obligations: &HashSet<String>) {
    let mut covered: Vec<(String, Span)> = Vec::new();
    d162_collect_covers(body, pre_obligations, ctx, &mut covered);
    // D162 cover semantic: defer body выполняется на scope exit; obligation
    // satisfied НЕ означает что var consumed СЕЙЧАС. Var остаётся Live (для
    // post-defer use); просто remove from obligations так что check_consume
    // не emit'ит D133-not-consumed на exit.
    //
    // Double-cover semantics (D3): если defer body covers + explicit body
    // call consumes — explicit call mark'ает Consumed; повторный call
    // даёт use-after-consume (existing behavior). check_d162_coverage
    // (Plan 100.8 D166 tooling) emits also dedicated D162-double-cover.
    for (name, _span) in covered {
        ctx.consume_obligations.remove(name.as_str());
        // Также remove canonical alias-form.
        let canon = ctx.canonical(&name);
        ctx.consume_obligations.remove(canon.as_str());
    }
}

fn d162_collect_covers(e: &Expr, pre_obligations: &HashSet<String>,
                       ctx: &ConsumeCtx, out: &mut Vec<(String, Span)>) {
    match &e.kind {
        ExprKind::Call { func, .. } => {
            if let ExprKind::Member { obj, name: method } = &func.kind {
                if let ExprKind::Ident(recv) = &obj.kind {
                    let canon = ctx.canonical(recv);
                    if pre_obligations.contains(&canon) || pre_obligations.contains(recv) {
                        // var_types stores type names (String).
                        let type_name = ctx.var_types.get(&canon)
                            .or_else(|| ctx.var_types.get(recv))
                            .cloned();
                        if let Some(tn) = type_name {
                            if ctx.reg.methods.contains(&(tn, method.clone())) {
                                out.push((recv.clone(), e.span));
                            }
                        }
                    }
                }
            }
            d162_collect_covers(func, pre_obligations, ctx, out);
        }
        ExprKind::Block(b) => {
            for s in &b.stmts { d162_collect_covers_stmt(s, pre_obligations, ctx, out); }
            if let Some(t) = &b.trailing { d162_collect_covers(t, pre_obligations, ctx, out); }
        }
        ExprKind::If { cond, then, else_ } => {
            d162_collect_covers(cond, pre_obligations, ctx, out);
            for s in &then.stmts { d162_collect_covers_stmt(s, pre_obligations, ctx, out); }
            if let Some(t) = &then.trailing { d162_collect_covers(t, pre_obligations, ctx, out); }
            match else_ {
                Some(ElseBranch::Block(b)) => {
                    for s in &b.stmts { d162_collect_covers_stmt(s, pre_obligations, ctx, out); }
                    if let Some(t) = &b.trailing { d162_collect_covers(t, pre_obligations, ctx, out); }
                }
                Some(ElseBranch::If(e2)) => d162_collect_covers(e2, pre_obligations, ctx, out),
                None => {}
            }
        }
        _ => {}
    }
}

fn d162_collect_covers_stmt(s: &Stmt, pre_obligations: &HashSet<String>,
                            ctx: &ConsumeCtx, out: &mut Vec<(String, Span)>) {
    match s {
        Stmt::Expr(e) | Stmt::Throw { value: e, .. } => d162_collect_covers(e, pre_obligations, ctx, out),
        Stmt::Return { value: Some(v), .. } => d162_collect_covers(v, pre_obligations, ctx, out),
        Stmt::Let(decl) => d162_collect_covers(&decl.value, pre_obligations, ctx, out),
        Stmt::Const(_) => {}
        _ => {}
    }
}

/// Plan 100.3 (D157): Scan closure body for consume-method calls on outer
/// vars (consume-closure detection). Returns names of outer vars that
/// the closure body would consume when invoked.
///
/// Conservative (sound): only detects direct `recv.consume_method()` patterns
/// where `recv` is a known outer consume-obligation. Does NOT detect
/// indirect consumption through nested calls.
fn d157_scan_closure_captures(
    body: &Expr,
    outer_obligations: &HashSet<String>,
    ctx: &ConsumeCtx,
) -> Vec<String> {
    let mut captured = Vec::new();
    d157_scan_expr(body, outer_obligations, ctx, &mut captured);
    captured.sort();
    captured.dedup();
    captured
}

fn d157_scan_expr(e: &Expr, outer: &HashSet<String>, ctx: &ConsumeCtx, out: &mut Vec<String>) {
    match &e.kind {
        ExprKind::Call { func, args, trailing } => {
            if let ExprKind::Member { obj, name: method } = &func.kind {
                if let ExprKind::Ident(recv) = &obj.kind {
                    let canon = ctx.canonical(recv);
                    let in_outer = outer.contains(&canon) || outer.contains(recv.as_str());
                    if in_outer {
                        // Check if this is a consume-method call.
                        let type_name = ctx.var_types.get(&canon)
                            .or_else(|| ctx.var_types.get(recv.as_str()))
                            .cloned();
                        if let Some(tn) = type_name {
                            if ctx.reg.methods.contains(&(tn, method.clone())) {
                                out.push(recv.clone());
                            }
                        }
                    }
                }
            }
            d157_scan_expr(func, outer, ctx, out);
            for a in args { d157_scan_expr(a.expr(), outer, ctx, out); }
            if let Some(t) = trailing {
                match t {
                    Trailing::Block(b) => d157_scan_block(b, outer, ctx, out),
                    _ => {}
                }
            }
        }
        ExprKind::Block(b) => d157_scan_block(b, outer, ctx, out),
        ExprKind::If { cond, then, else_ } => {
            d157_scan_expr(cond, outer, ctx, out);
            d157_scan_block(then, outer, ctx, out);
            match else_ {
                Some(ElseBranch::Block(b)) => d157_scan_block(b, outer, ctx, out),
                Some(ElseBranch::If(e2)) => d157_scan_expr(e2, outer, ctx, out),
                None => {}
            }
        }
        ExprKind::Member { obj, .. } => d157_scan_expr(obj, outer, ctx, out),
        ExprKind::Binary { left, right, .. } => {
            d157_scan_expr(left, outer, ctx, out);
            d157_scan_expr(right, outer, ctx, out);
        }
        _ => {}
    }
}

fn d157_scan_block(b: &Block, outer: &HashSet<String>, ctx: &ConsumeCtx, out: &mut Vec<String>) {
    for s in &b.stmts {
        match s {
            Stmt::Expr(e) | Stmt::Throw { value: e, .. } => d157_scan_expr(e, outer, ctx, out),
            Stmt::Return { value: Some(v), .. } => d157_scan_expr(v, outer, ctx, out),
            Stmt::Let(decl) => d157_scan_expr(&decl.value, outer, ctx, out),
            Stmt::Const(_) => {}
            _ => {}
        }
    }
    if let Some(t) = &b.trailing { d157_scan_expr(t, outer, ctx, out); }
}

/// Walk тела цикла (for/while/loop) — пессимистично: переменная,
/// потреблённая в теле, становится maybe-consumed (consume на 2-й
/// итерации = use-after-consume).
fn consume_walk_loop(ctx: &mut ConsumeCtx, loop_vars: &[String],
                     body: &Block, errors: &mut Vec<Diagnostic>) {
    let pre = ctx.states.clone();
    // Pass 1 — обнаружить consume в теле (ошибки в throwaway sink).
    for v in loop_vars { ctx.declare(v, None); }
    let mut throwaway: Vec<Diagnostic> = Vec::new();
    consume_walk_block(ctx, body, &mut throwaway);
    let consumed: Vec<String> = pre.keys()
        .filter(|k| matches!(ctx.states.get(*k),
            Some(VarState::Consumed(_)) | Some(VarState::MaybeConsumed(_))))
        .cloned()
        .collect();
    // Reset к pre, pre-mark consumed-в-теле как maybe-consumed.
    ctx.states = pre.clone();
    for k in &consumed {
        ctx.states.insert(k.clone(), VarState::MaybeConsumed(body.span));
    }
    // Pass 2 — реальный walk (ошибки эмитятся).
    for v in loop_vars { ctx.declare(v, None); }
    consume_walk_block(ctx, body, errors);
    // Post-loop: цикл мог не выполниться ни разу → consumed-в-теле
    // переменные maybe-consumed; ветка-локальные сбрасываются.
    ctx.states = pre;
    for k in &consumed {
        ctx.states.insert(k.clone(), VarState::MaybeConsumed(body.span));
    }
}

/// Plan 100.2 (D156): `for consume x in iter { body }` semantics.
/// Each loop variable is a consume-obligation; iter is Consumed after loop.
/// Pass-2 architecture: detect outer-scope pessimism, then real walk + check.
fn consume_walk_consume_for(
    ctx: &mut ConsumeCtx,
    iter: &Expr,
    loop_var_names: &[String],
    body: &Block,
    errors: &mut Vec<Diagnostic>,
) {
    // Walk iter expression (use-after-consume check for the collection var).
    consume_walk_expr(ctx, iter, errors);

    let pre = ctx.states.clone();
    let pre_obligations = ctx.consume_obligations.clone();

    // ── Pass 1: discover which outer-scope vars get consumed in body ──
    // (pessimistic: if consumed in body, mark maybe-consumed post-loop)
    for n in loop_var_names {
        ctx.declare_consume_binding(n, None);
    }
    let mut throwaway: Vec<Diagnostic> = Vec::new();
    consume_walk_block(ctx, body, &mut throwaway);
    let outer_consumed: Vec<String> = pre.keys()
        .filter(|k| matches!(ctx.states.get(*k),
            Some(VarState::Consumed(_)) | Some(VarState::MaybeConsumed(_))))
        .cloned()
        .collect();

    // ── Reset for pass 2: restore + pessimistic outer-consumed ──
    ctx.states = pre.clone();
    for k in &outer_consumed {
        ctx.states.insert(k.clone(), VarState::MaybeConsumed(body.span));
    }
    ctx.consume_obligations = pre_obligations.clone();

    // ── Pass 2: real walk with error collection ──
    for n in loop_var_names {
        ctx.declare_consume_binding(n, None);
    }
    consume_walk_block(ctx, body, errors);

    // ── Check loop vars BEFORE resetting state ──
    let body_span = body.span;
    for n in loop_var_names {
        let canon = ctx.canonical(n);
        let state = ctx.states.get(&canon).or_else(|| ctx.states.get(n)).cloned();
        match state {
            None | Some(VarState::Live) => {
                errors.push(Diagnostic::new(
                    format!(
                        "[D156-iter-not-consumed] `for consume` loop variable `{}` is not \
                         consumed in loop body. Every iteration must consume the loop variable \
                         via a consume-method, `return`, or consume-param transfer.",
                        n),
                    body_span,
                ));
            }
            Some(VarState::MaybeConsumed(_)) => {
                errors.push(Diagnostic::new(
                    format!(
                        "[D156-iter-maybe-consumed] `for consume` loop variable `{}` is \
                         consumed on some execution paths but not all. Every iteration must \
                         consume the loop variable on ALL execution paths.",
                        n),
                    body_span,
                ));
            }
            Some(VarState::Consumed(_)) => {}
        }
        ctx.consume_obligations.remove(n);
    }

    // ── Post-loop: restore pre state with pessimistic outer-consumed ──
    ctx.states = pre;
    for k in &outer_consumed {
        ctx.states.insert(k.clone(), VarState::MaybeConsumed(body.span));
    }

    // Mark iter variable as Consumed after for-consume loop.
    // Pragmatic (D156): even early break → iter considered Consumed.
    if let ExprKind::Ident(name) = &iter.kind {
        ctx.mark_consumed(name, iter.span);
        // If the iter was a consume-obligation (e.g. `consume txs = get_vec()`),
        // the mark_consumed above satisfies it.
    }
}

/// Plan 128.2 Ф.1 — walk Member/Index/TurboFish chain до root binding.
///
/// Returns:
///  * `Some(name)` если корень chain'а — `Ident(name)` (включая псевдо-`"self"`
///    для `SelfAccess`, который не используется в текущем check'е — self
///    обрабатывается отдельным путём через ReceiverKind);
///  * `None` если корень — rvalue (`Call`, `IntLit`, etc) — для таких chain'ов
///    enforcement не применим (mutation в temp — no-op anyway).
///
/// Used by mut-method-on-chain check (`b.field.sub.mut_m()`) — root binding'а
/// `b` mutability gate'ит весь chain независимо от типов промежуточных полей.
/// Cross-ref: `is_through_ro_binding` (Plan 124.8) — symmetric для D175.
fn lvalue_root_ident(e: &Expr) -> Option<&str> {
    match &e.kind {
        ExprKind::Ident(name) => Some(name.as_str()),
        ExprKind::Member { obj, .. } => lvalue_root_ident(obj),
        ExprKind::Index { obj, .. } => lvalue_root_ident(obj),
        ExprKind::TurboFish { base, .. } => lvalue_root_ident(base),
        _ => None,
    }
}

/// Plan 128.2 Ф.1 — is method one of the receiver-mutating "builtin" methods
/// for arrays/maps/sets? Used by both Ident-receiver path (line ~13690) and
/// chain-receiver path (Member/Index chain → root binding check).
fn is_builtin_mut_method(method: &str) -> bool {
    matches!(
        method,
        "push" | "pop" | "append" | "append_zero" | "insert" | "remove"
        | "clear" | "truncate" | "reserve" | "swap"
        | "sort" | "sort_by" | "set" | "extend" | "extend_from"
        | "copy_from" | "copy_within" | "shrink_to_fit" | "fill"
        | "drain" | "dedup" | "reverse" | "shuffle"
        // Plan 118.2: as_mut_ptr exposes mutable internal pointer.
        | "as_mut_ptr"
    )
}

fn consume_walk_expr(ctx: &mut ConsumeCtx, e: &Expr, errors: &mut Vec<Diagnostic>) {
    match &e.kind {
        // ─── Листья ───
        ExprKind::IntLit(_) | ExprKind::FloatLit(_) | ExprKind::StrLit(_)
        | ExprKind::BoolLit(_) | ExprKind::UnitLit | ExprKind::CharLit(_)
        | ExprKind::NullPtrLit
        | ExprKind::Path(_) | ExprKind::SelfAccess => {}

        // ─── Использование переменной ───
        ExprKind::Ident(name) => ctx.use_var(name, e.span, errors),

        // ─── Интерполированная строка `"... ${expr} ..."` ───
        ExprKind::InterpolatedStr { parts } => {
            for p in parts {
                if let InterpStrPart::Expr { expr: ex, spec: _ } = p {
                    consume_walk_expr(ctx, ex, errors);
                }
            }
        }

        // ─── Вызовы — точки consume ───
        ExprKind::Call { func, args, trailing } => {
            match &func.kind {
                // Method call: obj.method(args).
                ExprKind::Member { obj, name: method } => {
                    // Plan 128.2 Ф.1 — chain-receiver mut enforcement.
                    // `b.field.sub.mut_m()` где `b` — `ro` binding: чистый Ident
                    // path ниже видит `obj.kind == Member`, не `Ident`, и пропускает
                    // check. Здесь — walk chain to root и применяем те же rules.
                    // Pure-Ident случай (`b.mut_m()`) обработается ниже existing
                    // path'ом; этот pre-pass отрабатывает ТОЛЬКО chain receivers.
                    if !matches!(obj.kind, ExprKind::Ident(_)) {
                        if let Some(root) = lvalue_root_ident(obj) {
                            let root = root.to_string();
                            let recv_ty = ctx.var_types.get(&ctx.canonical(&root))
                                .or_else(|| ctx.var_types.get(&root))
                                .cloned();
                            // Mut-method identification: ВНУТРИ chain'а тип
                            // receiver'а method-call'а (объект сразу под `.method`)
                            // — это `obj`, тип которого мы не знаем точно без
                            // полноценного inference. Используем conservative
                            // эвристику: если `method` зарегистрирован как mut на
                            // ЛЮБОМ типе ИЛИ builtin mut-method — считаем mut.
                            // Это может изредка дать over-rejection для chain'ов
                            // с omonимными pure-методами, но soundness важнее.
                            // (Plan 128.2 §1.3 — acceptable trade-off.)
                            // Plan 135: если recv-mut overload pair (и ro и mut),
                            // то ro-binding может вызывать через chain — не ошибка.
                            let is_registered_mut_any = ctx.reg.mut_methods.iter()
                                .any(|(_, m)| m == method.as_str());
                            // Plan 135: check if there's a ro-overload for ANY type
                            // with this method name (conservative mirror of mut check).
                            let has_any_ro_overload = ctx.reg.ro_methods.iter()
                                .any(|(_, m)| m == method.as_str());
                            let is_mut_method = (is_registered_mut_any && !has_any_ro_overload)
                                || is_builtin_mut_method(method.as_str());
                            if is_mut_method {
                                // (a) Param check — E_PARAM_NOT_MUT.
                                if let Some(&is_mut) = ctx.param_mut.get(&root) {
                                    if !is_mut {
                                        let ty_str = recv_ty.as_deref().unwrap_or("?");
                                        errors.push(Diagnostic::new(
                                            format!(
                                                "[E_PARAM_NOT_MUT] параметр `{}` не помечен `mut`, \
                                                 но mut-метод `{}` вызван через chain `{}…`. \
                                                 Root binding chain'а должен быть `mut` (Plan 128.2 / D33 \
                                                 lvalue chain enforcement; тип root — `{}`).",
                                                root, method, root, ty_str),
                                            e.span,
                                        ).with_note(
                                            "добавь `mut` к параметру: `fn ...(mut <name> T)` — \
                                             разрешит mut-method вызовы через field/index chain."
                                                .to_string(),
                                        ).with_suggestion(crate::diag::Suggestion {
                                            message: format!("add `mut` to param `{}`", root),
                                            span: e.span,
                                            replacement: format!("mut {}", root),
                                            applicability: crate::diag::Applicability::MaybeIncorrect,
                                        }));
                                    }
                                }
                                // (b) Local check — E_LOCAL_NOT_MUT.
                                if let Some(&is_mut) = ctx.local_mut.get(&root) {
                                    if !is_mut {
                                        let ty_str = recv_ty.as_deref().unwrap_or("?");
                                        errors.push(Diagnostic::new(
                                            format!(
                                                "[E_LOCAL_NOT_MUT] local-binding `{}` не помечен `mut`, \
                                                 но mut-метод `{}` вызван через chain `{}…`. \
                                                 Root binding chain'а должен быть `mut` (Plan 128.2 / D33 \
                                                 lvalue chain enforcement; тип root — `{}`).",
                                                root, method, root, ty_str),
                                            e.span,
                                        ).with_note(
                                            "добавь `mut` к binding'у: `mut <name> = ...` (Plan 114 D184) — \
                                             разрешит mut-method вызовы через field/index chain."
                                                .to_string(),
                                        ).with_suggestion(crate::diag::Suggestion {
                                            message: format!("change to `mut {}`", root),
                                            span: e.span,
                                            replacement: format!("mut {}", root),
                                            applicability: crate::diag::Applicability::MaybeIncorrect,
                                        }));
                                    }
                                }
                            }
                        }
                    }
                    if let ExprKind::Ident(recv) = &obj.kind {
                        // Любой вызов метода — использование receiver'а.
                        ctx.use_var(recv, obj.span, errors);
                        for a in args { consume_walk_expr(ctx, a.expr(), errors); }
                        if let Some(t) = trailing { consume_walk_trailing(ctx, t, errors); }
                        let recv = recv.clone();
                        // Plan 100.3 (D157): view-param cannot call consume-methods.
                        if ctx.is_view_param(&recv) && ctx.is_consume_method(&recv, method) {
                            errors.push(Diagnostic::new(
                                format!(
                                    "[D157-consume-via-view] `{}` — view-param (read-only borrow): \
                                     нельзя вызывать consume-метод `{}`. Используйте `consume` \
                                     qualifier на параметре функции для ownership transfer.",
                                    recv, method),
                                e.span,
                            ));
                        }
                        // Plan 108.1 (D176 amend): mut-method on non-mut param → E_PARAM_NOT_MUT.
                        // Двa источника mut-методов:
                        //  (a) registered (`ctx.reg.mut_methods` — StringBuilder, WriteBuffer,
                        //      user `fn T mut @method`).
                        //  (b) builtin collection (array `[]T`, map `[K:V]`, set `{T}`) —
                        //      `.push/.pop/.append/.insert/.remove/.clear/.truncate/.reserve/
                        //       .swap/.sort/.set/.extend/.copy_from`.
                        if let Some(&is_mut) = ctx.param_mut.get(&recv) {
                            if !is_mut {
                                let recv_ty = ctx.var_types.get(&ctx.canonical(&recv))
                                    .or_else(|| ctx.var_types.get(&recv))
                                    .cloned();
                                let registered = recv_ty.as_ref()
                                    .map(|rty| ctx.reg.mut_methods.contains(&(rty.clone(), method.clone())))
                                    .unwrap_or(false);
                                // Plan 135: ro-binding may call ro-overload of a
                                // recv-mut pair — not a param-not-mut error.
                                let has_ro_overload = recv_ty.as_ref()
                                    .map(|rty| ctx.reg.ro_methods.contains(&(rty.clone(), method.clone())))
                                    .unwrap_or(false);
                                let builtin_mut_method = matches!(
                                    method.as_str(),
                                    "push" | "pop" | "append" | "append_zero" | "insert" | "remove"
                                    | "clear" | "truncate" | "reserve" | "swap"
                                    | "sort" | "sort_by" | "set" | "extend" | "extend_from"
                                    | "copy_from" | "copy_within" | "shrink_to_fit" | "fill"
                                    | "drain" | "dedup" | "reverse" | "shuffle"
                                    // Plan 118.2: as_mut_ptr exposes mutable
                                    // internal pointer — requires mut binding.
                                    | "as_mut_ptr"
                                );
                                if (registered && !has_ro_overload) || builtin_mut_method {
                                    let ty_str = recv_ty.as_deref().unwrap_or("?");
                                    errors.push(Diagnostic::new(
                                        format!(
                                            "[E_PARAM_NOT_MUT] параметр `{}` не помечен `mut`, \
                                             но вызывается mut-метод `{}` (тип `{}`).  \
                                             Default для параметров — read-only (D176 amend, Plan 108.1).",
                                            recv, method, ty_str),
                                        e.span,
                                    ).with_note(
                                        "добавь `mut` к параметру: `fn ...(mut <name> T)` — \
                                         разрешит вызов mut-методов и index-assignment в callee."
                                            .to_string(),
                                    ).with_suggestion(crate::diag::Suggestion {
                                        message: format!("add `mut` to param `{}`", recv),
                                        span: e.span,
                                        replacement: format!("mut {}", recv),
                                        applicability: crate::diag::Applicability::MaybeIncorrect,
                                    }));
                                }
                            }
                        }
                        // Plan 108.2 (D36 enforcement): mut-method on non-mut local
                        // → E_LOCAL_NOT_MUT.  Parallel к param check выше.
                        if let Some(&is_mut) = ctx.local_mut.get(&recv) {
                            if !is_mut {
                                let recv_ty = ctx.var_types.get(&ctx.canonical(&recv))
                                    .or_else(|| ctx.var_types.get(&recv))
                                    .cloned();
                                let registered = recv_ty.as_ref()
                                    .map(|rty| ctx.reg.mut_methods.contains(&(rty.clone(), method.clone())))
                                    .unwrap_or(false);
                                // Plan 135: if there is also a ro-overload for this
                                // (type, method) pair, a ro-binding call dispatches
                                // to the ro-overload — NOT an error.
                                let has_ro_overload = recv_ty.as_ref()
                                    .map(|rty| ctx.reg.ro_methods.contains(&(rty.clone(), method.clone())))
                                    .unwrap_or(false);
                                let builtin_mut_method = matches!(
                                    method.as_str(),
                                    "push" | "pop" | "append" | "append_zero" | "insert" | "remove"
                                    | "clear" | "truncate" | "reserve" | "swap"
                                    | "sort" | "sort_by" | "set" | "extend" | "extend_from"
                                    | "copy_from" | "copy_within" | "shrink_to_fit" | "fill"
                                    | "drain" | "dedup" | "reverse" | "shuffle"
                                    // Plan 118.2: as_mut_ptr exposes mutable
                                    // internal pointer — requires mut binding.
                                    | "as_mut_ptr"
                                );
                                if (registered && !has_ro_overload) || builtin_mut_method {
                                    let ty_str = recv_ty.as_deref().unwrap_or("?");
                                    errors.push(Diagnostic::new(
                                        format!(
                                            "[E_LOCAL_NOT_MUT] local-binding `{}` не помечен `mut`, \
                                             но вызывается mut-метод `{}` (тип `{}`).  \
                                             Default для `let`-binding'ов — read-only (D36 enforcement, Plan 108.2).",
                                            recv, method, ty_str),
                                        e.span,
                                    ).with_note(
                                        "добавь `mut` к binding'у: `mut <name> = ...` (Plan 114 D184) — \
                                         разрешит вызов mut-методов и field/index-assignment."
                                            .to_string(),
                                    ).with_suggestion(crate::diag::Suggestion {
                                        message: format!("change `ro {}` to `mut {}`", recv, recv),
                                        span: e.span,
                                        replacement: format!("mut {}", recv),
                                        applicability: crate::diag::Applicability::MaybeIncorrect,
                                    }));
                                }
                            }
                        }
                        // consume-метод → receiver (весь alias-класс)
                        // потребляется.
                        if ctx.is_consume_method(&recv, method) {
                            ctx.mark_consumed(&recv, e.span);
                        } else {
                            // Plan 100.2 (D156): `for consume` loop var has
                            // None type (declared without type inference).
                            // If calling a method that IS a consume-method for
                            // ANY registered consume type AND recv is a
                            // consume-obligation → treat as consuming.
                            let canon = ctx.canonical(&recv);
                            let is_obligation = ctx.consume_obligations.contains(&recv)
                                || ctx.consume_obligations.contains(&canon);
                            if is_obligation
                                && ctx.var_types.get(&canon)
                                     .or_else(|| ctx.var_types.get(&recv)).is_none()
                            {
                                let is_any_consume_method = ctx.lin_reg.consume_methods
                                    .values()
                                    .any(|ms| ms.iter().any(|m| m == method.as_str()));
                                if is_any_consume_method {
                                    ctx.mark_consumed(&recv, e.span);
                                }
                            }
                        }
                        // consume-параметры метода.
                        if let Some(ty) = ctx.var_types.get(&ctx.canonical(&recv)).cloned() {
                            if let Some(idxs) = ctx.reg
                                .method_params.get(&(ty.clone(), method.clone())).cloned()
                            {
                                ctx.consume_args(args, &idxs, e.span);
                            }
                            // Plan 108.1 followup ([M-108.1-readonly-to-explicit-mut-coerce]):
                            // E_READONLY_COERCE — передача readonly-binding в mut-param метода.
                            if let Some(mut_idxs) = ctx.reg
                                .method_mut_params.get(&(ty.clone(), method.clone())).cloned()
                            {
                                check_readonly_coerce_args(ctx, args, &mut_idxs, errors);
                            }
                            // Plan 118.5 V2 [M-118.5-arg-coerce-unsafe]:
                            // E_UNSAFE_ARG_REQUIRES_WRAP — передача unsafe-T-
                            // binding в non-unsafe param метода.
                            if let Some(non_unsafe_idxs) = ctx.reg
                                .method_non_unsafe_params.get(&(ty, method.clone())).cloned()
                            {
                                check_unsafe_coerce_args(ctx, args, &non_unsafe_idxs, errors);
                            }
                        }
                    } else if let ExprKind::Member {
                        obj: inner_obj,
                        name: field_name,
                    } = &obj.kind {
                        // Plan 100.1 (D5): `@field.method()` — field-level
                        // consume tracking. SelfAccess = `@`.
                        if matches!(inner_obj.kind, ExprKind::SelfAccess) {
                            for a in args { consume_walk_expr(ctx, a.expr(), errors); }
                            if let Some(t) = trailing { consume_walk_trailing(ctx, t, errors); }
                            // Если метод — consume-метод типа поля → mark field Consumed.
                            let is_consume_method = ctx.lin_reg.consume_types.iter()
                                .any(|ty| ctx.lin_reg.consume_methods
                                    .get(ty.as_str())
                                    .map_or(false, |ms| ms.contains(method)));
                            if is_consume_method {
                                // Verify field indeed tracked (is a consume-field).
                                if ctx.field_states.contains_key(field_name.as_str()) {
                                    // check use-after-consume for field
                                    if let Some(VarState::Consumed(at)) =
                                        ctx.field_states.get(field_name.as_str())
                                    {
                                        let at = *at;
                                        errors.push(Diagnostic::new(
                                            format!(
                                                "использование потреблённого поля \
                                                 `@.{}` (D133): поле уже потреблено",
                                                field_name),
                                            obj.span,
                                        ).with_note_at(
                                            "поле потреблено здесь".to_string(), at));
                                    }
                                    ctx.mark_field_consumed(field_name, e.span);
                                }
                            }
                        } else if let ExprKind::Member {
                            obj: deep_obj,
                            name: parent_field,
                        } = &inner_obj.kind {
                            // Plan 100.1 (D5.2): `@parent.field.method()` —
                            // nested field consume. Mark parent field as
                            // MaybeConsumed (partially consumed sub-field).
                            if matches!(deep_obj.kind, ExprKind::SelfAccess) {
                                let is_consume_method = ctx.lin_reg.consume_types.iter()
                                    .any(|ty| ctx.lin_reg.consume_methods
                                        .get(ty.as_str())
                                        .map_or(false, |ms| ms.contains(method)));
                                if is_consume_method
                                    && ctx.field_states.contains_key(parent_field.as_str())
                                {
                                    // Mark parent as MaybeConsumed: sub-field was
                                    // consumed but parent was not directly consumed.
                                    // This prevents D5.1 false positive on rebind.
                                    ctx.field_states.insert(
                                        parent_field.clone(),
                                        VarState::MaybeConsumed(e.span));
                                }
                            }
                            consume_walk_expr(ctx, obj, errors);
                            for a in args { consume_walk_expr(ctx, a.expr(), errors); }
                            if let Some(t) = trailing { consume_walk_trailing(ctx, t, errors); }
                        } else {
                            consume_walk_expr(ctx, obj, errors);
                            for a in args { consume_walk_expr(ctx, a.expr(), errors); }
                            if let Some(t) = trailing { consume_walk_trailing(ctx, t, errors); }
                        }
                    } else {
                        consume_walk_expr(ctx, obj, errors);
                        for a in args { consume_walk_expr(ctx, a.expr(), errors); }
                        if let Some(t) = trailing { consume_walk_trailing(ctx, t, errors); }
                        // Plan 73.1 V3 [M-73.1-fluent-return-implicit-consume] extension:
                        // chain `var.fluent1(...).fluent2(...).consume_method(...)` —
                        // detect chain root, check that root + method matches a consume
                        // method on root's type, mark root Consumed.
                        if let Some(root) = implicit_return_consume_var(ctx, obj) {
                            if let Some(ty) = ctx.var_types.get(&root).cloned() {
                                if ctx.reg.methods.contains(&(ty.clone(), method.clone())) {
                                    ctx.mark_consumed(&root, e.span);
                                }
                                // Also: consume-param indexes for chain-receiver consume args.
                                if let Some(idxs) = ctx.reg.method_params
                                    .get(&(ty, method.clone())).cloned()
                                {
                                    ctx.consume_args(args, &idxs, e.span);
                                }
                            }
                        }
                    }
                }
                // Free-fn call: f(args).
                ExprKind::Ident(fname) => {
                    // Plan 100.3 (D157): view-borrow semantics for free-fn calls.
                    // consume_obligations var passed to NON-consume param = view-borrow → OK.
                    // Rvalue (call returning consume-type) passed to view-param → D133-consume-rvalue-in-view.
                    let consume_idxs = ctx.reg.fn_params.get(fname.as_str())
                        .cloned()
                        .unwrap_or_default();
                    let view_idxs = ctx.reg.fn_view_params.get(fname.as_str())
                        .cloned()
                        .unwrap_or_default();
                    // Plan 108.1 followup ([M-108.1-readonly-to-explicit-mut-coerce]):
                    // E_READONLY_COERCE — передача readonly-binding в mut-param.
                    if let Some(mut_idxs) = ctx.reg.fn_mut_params.get(fname.as_str()).cloned() {
                        check_readonly_coerce_args(ctx, args, &mut_idxs, errors);
                    }
                    // Plan 118.5 V2 [M-118.5-arg-coerce-unsafe]:
                    // E_UNSAFE_ARG_REQUIRES_WRAP — передача unsafe-T-binding
                    // в non-unsafe param свободной функции.
                    if let Some(non_unsafe_idxs) = ctx.reg
                        .fn_non_unsafe_params.get(fname.as_str()).cloned()
                    {
                        check_unsafe_coerce_args(ctx, args, &non_unsafe_idxs, errors);
                    }
                    for (i, a) in args.iter().enumerate() {
                        let is_consume_param = consume_idxs.contains(&i);
                        let is_view_param = view_idxs.contains(&i) || (!is_consume_param);
                        // D133-consume-rvalue-in-view: rvalue of consume-type → view-param.
                        // Rvalue = call returning consume-type (no binding → no tracking slot).
                        if is_view_param && !is_consume_param {
                            if let ExprKind::Call { func: inner_func, .. } = &a.expr().kind {
                                let ret_type: Option<String> = match &inner_func.kind {
                                    ExprKind::Ident(inner_fname) =>
                                        ctx.reg.fn_return_types.get(inner_fname.as_str()).cloned(),
                                    _ => None,
                                };
                                if let Some(rt) = ret_type {
                                    if ctx.lin_reg.consume_types.contains(&rt) {
                                        errors.push(Diagnostic::new(
                                            format!(
                                                "[D133-consume-rvalue-in-view] consume-rvalue (тип `{}`) \
                                                 передан в view-param функции `{}`. Привяжите через \
                                                 `consume name = …`, затем используйте `name`.",
                                                rt, fname),
                                            a.expr().span,
                                        ));
                                    }
                                }
                            }
                        }
                    }
                    // Plan 100.3 (D157): consume-closure invocation.
                    // If calling a consume-closure (FnOnce-like), first check
                    // use-after-consume, then mark captured vars + closure Consumed.
                    let is_consume_closure_call = ctx.is_consume_closure(fname);
                    if is_consume_closure_call {
                        // Check use-after-consume on closure (D157 FnOnce semantics).
                        let canon = ctx.canonical(fname);
                        if let Some(VarState::Consumed(at)) = ctx.states.get(&canon)
                            .or_else(|| ctx.states.get(fname.as_str()))
                        {
                            let at = *at;
                            errors.push(Diagnostic::new(
                                format!(
                                    "[D157-consume-closure-double-invoke] consume-closure `{}` \
                                     уже была вызвана (FnOnce-эквивалент): повторный вызов \
                                     невозможен. Consume-closure можно вызвать ровно один раз.",
                                    fname),
                                e.span,
                            ).with_note_at("closure вызвана (и потреблена) здесь".to_string(), at));
                        } else {
                            ctx.use_var(fname, e.span, errors);
                        }
                    }
                    for a in args { consume_walk_expr(ctx, a.expr(), errors); }
                    if let Some(t) = trailing { consume_walk_trailing(ctx, t, errors); }
                    if !consume_idxs.is_empty() {
                        ctx.consume_args(args, &consume_idxs, e.span);
                    }
                    if is_consume_closure_call {
                        // Invoke: mark captured outer vars + closure itself Consumed.
                        ctx.invoke_consume_closure(fname, e.span);
                    }
                    // Plan 100.1 (D133 / D3): `panic` = exit-point.
                    // Все Live consume-obligations на panic-call → D133.
                    if fname == "panic" || fname == "exit" || fname == "abort" {
                        ctx.check_obligations_at_exit(e.span, errors);
                    }
                }
                // Path call: Type.static(args) / module.fn(args).
                ExprKind::Path(parts) => {
                    for a in args { consume_walk_expr(ctx, a.expr(), errors); }
                    if let Some(t) = trailing { consume_walk_trailing(ctx, t, errors); }
                    if parts.len() == 2 {
                        if let Some(idxs) = ctx.reg.method_params
                            .get(&(parts[0].clone(), parts[1].clone())).cloned()
                        {
                            ctx.consume_args(args, &idxs, e.span);
                        }
                    }
                    if let Some(last) = parts.last() {
                        if let Some(idxs) = ctx.reg.fn_params.get(last).cloned() {
                            ctx.consume_args(args, &idxs, e.span);
                        }
                    }
                }
                _ => {
                    consume_walk_expr(ctx, func, errors);
                    for a in args { consume_walk_expr(ctx, a.expr(), errors); }
                    if let Some(t) = trailing { consume_walk_trailing(ctx, t, errors); }
                }
            }
        }

        // ─── Доступы / операторы ───
        ExprKind::Member { obj, .. } => consume_walk_expr(ctx, obj, errors),
        ExprKind::Index { obj, index } => {
            consume_walk_expr(ctx, obj, errors);
            consume_walk_expr(ctx, index, errors);
        }
        ExprKind::TurboFish { base, .. } => consume_walk_expr(ctx, base, errors),
        ExprKind::Try(inner) | ExprKind::Bang(inner) => consume_walk_expr(ctx, inner, errors),
        ExprKind::As(inner, _) | ExprKind::Is(inner, _) => consume_walk_expr(ctx, inner, errors),
        ExprKind::Unary { operand, .. } => consume_walk_expr(ctx, operand, errors),
        ExprKind::Binary { left, right, .. } => {
            consume_walk_expr(ctx, left, errors);
            consume_walk_expr(ctx, right, errors);
        }
        ExprKind::Throw(inner) => consume_walk_expr(ctx, inner, errors),
        ExprKind::Interrupt(opt) => {
            if let Some(v) = opt { consume_walk_expr(ctx, v, errors); }
        }
        ExprKind::Range { start, end, .. } => {
            if let Some(s) = start { consume_walk_expr(ctx, s, errors); }
            if let Some(e) = end { consume_walk_expr(ctx, e, errors); }
        }

        // ─── `a ?? b` — `b` исполняется условно ───
        ExprKind::Coalesce(a, b) => {
            consume_walk_expr(ctx, a, errors);
            let after_a = ctx.states.clone();
            consume_walk_expr(ctx, b, errors);
            let after_b = ctx.states.clone();
            ctx.states = consume_join(&after_a, &after_a, &after_b);
        }

        // ─── Ветвление if / if-let ───
        ExprKind::If { cond, then, else_ } => {
            consume_walk_expr(ctx, cond, errors);
            consume_walk_if(ctx, then, else_, errors);
        }
        ExprKind::IfLet { pattern, scrutinee, guard, then, else_ } => {
            consume_walk_expr(ctx, scrutinee, errors);
            let saved = ctx.states.clone();
            let mut names = Vec::new();
            consume_pattern_names(pattern, &mut names);
            for n in &names { ctx.declare(n, None); }
            // Plan 106: guard sees pattern bindings.
            if let Some(g) = guard { consume_walk_expr(ctx, g, errors); }
            consume_walk_block(ctx, then, errors);
            let then_states = ctx.states.clone();
            ctx.states = saved.clone();
            consume_walk_else(ctx, else_, errors);
            let else_states = ctx.states.clone();
            ctx.states = consume_join(&saved, &then_states, &else_states);
        }

        // ─── match ───
        ExprKind::Match { scrutinee, arms } => {
            consume_walk_expr(ctx, scrutinee, errors);
            let saved = ctx.states.clone();
            let mut joined: Option<HashMap<String, VarState>> = None;
            for arm in arms {
                ctx.states = saved.clone();
                let mut names = Vec::new();
                consume_pattern_names(&arm.pattern, &mut names);
                for n in &names { ctx.declare(n, None); }
                if let Some(g) = &arm.guard { consume_walk_expr(ctx, g, errors); }
                match &arm.body {
                    MatchArmBody::Expr(ex) => consume_walk_expr(ctx, ex, errors),
                    MatchArmBody::Block(b) => consume_walk_block(ctx, b, errors),
                }
                let arm_states = ctx.states.clone();
                joined = Some(match joined {
                    None => arm_states,
                    Some(j) => consume_join(&saved, &j, &arm_states),
                });
            }
            ctx.states = joined.unwrap_or(saved);
        }

        // ─── select ───
        ExprKind::Select { arms } => {
            let saved = ctx.states.clone();
            let mut joined: Option<HashMap<String, VarState>> = None;
            for arm in arms {
                ctx.states = saved.clone();
                match &arm.op {
                    SelectOp::Recv { binding, chan } => {
                        consume_walk_expr(ctx, chan, errors);
                        if let Some(b) = binding { ctx.declare(b, None); }
                    }
                    SelectOp::Send { chan, value } => {
                        consume_walk_expr(ctx, chan, errors);
                        consume_walk_expr(ctx, value, errors);
                    }
                    SelectOp::Default => {}
                }
                if let Some(g) = &arm.guard { consume_walk_expr(ctx, g, errors); }
                consume_walk_block(ctx, &arm.body, errors);
                let arm_states = ctx.states.clone();
                joined = Some(match joined {
                    None => arm_states,
                    Some(j) => consume_join(&saved, &j, &arm_states),
                });
            }
            ctx.states = joined.unwrap_or(saved);
        }

        // ─── Циклы — пессимистично ───
        ExprKind::For { pattern, iter, body, iter_consume, .. } => {
            let mut names = Vec::new();
            consume_pattern_names(pattern, &mut names);
            // Plan 108.3 (D36 amend): track loop-var mutability.
            // `for x in iter` → x immutable.  `for mut x in iter` → x mutable.
            // `for (mut a, b) in pairs` → per-name a mutable, b immutable.
            // `for consume x in iter` → implicit mut.
            let mut name_mut_pairs = Vec::new();
            consume_pattern_names_with_mut(pattern, &mut name_mut_pairs);
            for (n, pat_mut) in &name_mut_pairs {
                if n != "_" {
                    ctx.local_mut.insert(n.clone(), *iter_consume || *pat_mut);
                }
            }
            if *iter_consume {
                // Plan 100.2 (D156): consume-iteration — each loop var is an
                // obligation; iter marked Consumed after loop.
                consume_walk_consume_for(ctx, iter, &names, body, errors);
            } else {
                consume_walk_expr(ctx, iter, errors);
                consume_walk_loop(ctx, &names, body, errors);
            }
        }
        ExprKind::ParallelFor { pattern, iter, body, .. } => {
            consume_walk_expr(ctx, iter, errors);
            let mut names = Vec::new();
            consume_pattern_names(pattern, &mut names);
            consume_walk_loop(ctx, &names, body, errors);
        }
        ExprKind::While { cond, body, .. } => {
            consume_walk_expr(ctx, cond, errors);
            consume_walk_loop(ctx, &[], body, errors);
        }
        ExprKind::WhileLet { pattern, scrutinee, body, .. } => {
            consume_walk_expr(ctx, scrutinee, errors);
            let mut names = Vec::new();
            consume_pattern_names(pattern, &mut names);
            consume_walk_loop(ctx, &names, body, errors);
        }
        ExprKind::Loop { body, .. } => consume_walk_loop(ctx, &[], body, errors),

        // ─── Блоки / scope-конструкции ───
        ExprKind::Block(b) => consume_walk_block(ctx, b, errors),
        ExprKind::With { bindings, body } => {
            for wb in bindings { consume_walk_expr(ctx, &wb.handler, errors); }
            consume_walk_block(ctx, body, errors);
        }
        ExprKind::Supervised { body, cancel } => {
            if let Some(c) = cancel { consume_walk_expr(ctx, c, errors); }
            consume_walk_block(ctx, body, errors);
        }
        ExprKind::Forbid { body, .. } | ExprKind::Realtime { body, .. } => {
            consume_walk_block(ctx, body, errors);
        }
        ExprKind::Detach(b) | ExprKind::Blocking(b) => consume_walk_isolated_block(ctx, &[], b, errors),
        ExprKind::Spawn(inner) => consume_walk_isolated_expr(ctx, &[], inner, errors),

        // ─── Литералы-агрегаты ───
        ExprKind::TupleLit(elems) => {
            for el in elems { consume_walk_expr(ctx, el, errors); }
        }
        ExprKind::ArrayLit(elems) => {
            for el in elems {
                match el {
                    ArrayElem::Item(ex) | ArrayElem::Spread(ex) =>
                        consume_walk_expr(ctx, ex, errors),
                }
            }
        }
        ExprKind::MapLit { elems, .. } => {
            for el in elems {
                match el {
                    MapElem::Pair(k, v) => {
                        consume_walk_expr(ctx, k, errors);
                        consume_walk_expr(ctx, v, errors);
                    }
                    MapElem::Spread(ex) => consume_walk_expr(ctx, ex, errors),
                }
            }
        }
        ExprKind::RecordLit { fields, .. } => {
            for f in fields {
                if let Some(v) = &f.value { consume_walk_expr(ctx, v, errors); }
            }
        }
        ExprKind::TaggedTemplate { tag, args, .. } => {
            consume_walk_expr(ctx, tag, errors);
            for a in args { consume_walk_expr(ctx, a, errors); }
        }

        // ─── Closure / handler — изолированный walk ───
        ExprKind::Lambda { params, body, .. } => {
            let names: Vec<String> = params.iter().map(|p| p.name.clone()).collect();
            consume_walk_isolated_expr(ctx, &names, body, errors);
        }
        ExprKind::ClosureLight { params, body } => {
            let names: Vec<String> = params.iter().map(|p| p.name.clone()).collect();
            match body {
                ClosureBody::Expr(ex) => consume_walk_isolated_expr(ctx, &names, ex, errors),
                ClosureBody::Block(b) => consume_walk_isolated_block(ctx, &names, b, errors),
            }
        }
        ExprKind::ClosureFull(sig) => {
            let names: Vec<String> = sig.params.iter().map(|p| p.name.clone()).collect();
            consume_walk_fnbody_isolated(ctx, &names, &sig.body, errors);
        }
        // Plan 97 Ф.4 (D142): protocol-литерал — consume-walk идентичен.
        ExprKind::HandlerLit { methods, .. } | ExprKind::ProtocolLit { methods, .. } => {
            for m in methods {
                let names: Vec<String> = m.params.iter().map(|p| p.name.clone()).collect();
                match &m.body {
                    HandlerMethodBody::Expr(ex) =>
                        consume_walk_isolated_expr(ctx, &names, ex, errors),
                    HandlerMethodBody::Block(b) =>
                        consume_walk_isolated_block(ctx, &names, b, errors),
                }
            }
        }

        // ─── Контрактные кванторы — ghost, walk body для use-detection ───
        ExprKind::Forall { body, range, .. } | ExprKind::Exists { body, range, .. } => {
            consume_walk_expr(ctx, range, errors);
            consume_walk_expr(ctx, body, errors);
        }
    }
}

/// if-then-else branch join (общий для `If`).
///
/// Plan 100.7 (D165): divergence-aware join. Если ветка заканчивается
/// throw/return (diverges), она не достигает точки слияния — её состояние
/// исключается из join. Это устраняет ложные MaybeConsumed ошибки при паттерне
/// `if cond { x.consume(); throw err }` где x полностью consumed на diverging
/// пути и остаётся Live на non-diverging пути.
fn consume_walk_if(ctx: &mut ConsumeCtx, then: &Block,
                   else_: &Option<ElseBranch>, errors: &mut Vec<Diagnostic>) {
    let saved = ctx.states.clone();
    let then_diverges = block_diverges(then);
    consume_walk_block(ctx, then, errors);
    let then_states = ctx.states.clone();
    ctx.states = saved.clone();
    let else_diverges = else_branch_diverges(else_);
    consume_walk_else(ctx, else_, errors);
    let else_states = ctx.states.clone();
    // Divergence-aware merge: если ветка diverges — её финальные состояния
    // не вносятся в join (управление не достигает точки слияния).
    ctx.states = match (then_diverges, else_diverges) {
        (true, true) => saved,        // оба пути diverge → после if недостижимо
        (true, false) => else_states,  // then diverges → только else-состояние
        (false, true) => then_states,  // else diverges → только then-состояние
        (false, false) => consume_join(&saved, &then_states, &else_states),
    };
}

/// Diverges-check для ElseBranch.
fn else_branch_diverges(else_: &Option<ElseBranch>) -> bool {
    match else_ {
        Some(ElseBranch::Block(b)) => block_diverges(b),
        Some(ElseBranch::If(e)) => expr_diverges(e),
        None => false, // нет else → implicit () — не diverges
    }
}

fn consume_walk_else(ctx: &mut ConsumeCtx, else_: &Option<ElseBranch>,
                     errors: &mut Vec<Diagnostic>) {
    match else_ {
        Some(ElseBranch::Block(b)) => consume_walk_block(ctx, b, errors),
        Some(ElseBranch::If(e)) => consume_walk_expr(ctx, e, errors),
        None => {}
    }
}

fn consume_walk_trailing(ctx: &mut ConsumeCtx, t: &Trailing,
                         errors: &mut Vec<Diagnostic>) {
    match t {
        Trailing::Block(b) => consume_walk_isolated_block(ctx, &[], b, errors),
        Trailing::Fn(sig) => {
            let names: Vec<String> = sig.params.iter().map(|p| p.name.clone()).collect();
            consume_walk_fnbody_isolated(ctx, &names, &sig.body, errors);
        }
        Trailing::LegacyBlockWithParams(tb) => {
            let names: Vec<String> = tb.params.iter().map(|p| p.name.clone()).collect();
            consume_walk_isolated_block(ctx, &names, &tb.body, errors);
        }
    }
}

fn consume_walk_fnbody_isolated(ctx: &mut ConsumeCtx, params: &[String],
                                body: &FnBody, errors: &mut Vec<Diagnostic>) {
    match body {
        FnBody::Block(b) => consume_walk_isolated_block(ctx, params, b, errors),
        FnBody::Expr(e) => consume_walk_isolated_expr(ctx, params, e, errors),
        FnBody::External => {}
    }
}

fn check_defer_bodies(module: &Module, errors: &mut Vec<Diagnostic>) {
    // Lookup callee effects: fn_name -> effects (для suspend detection).
    let mut fn_effects: HashMap<String, Vec<TypeRef>> = HashMap::new();
    for item in &module.items {
        if let Item::Fn(f) = item {
            let key = match &f.receiver {
                Some(r) => format!("{}.{}", r.type_name, f.name),
                None => f.name.clone(),
            };
            fn_effects.entry(key).or_default().extend(f.effects.iter().cloned());
        }
    }

    // Walk bodies функций и тестов. Per-fn — передаём enclosing fn-sig
    // effects (D158): defer body Fail-effect разрешён если fn-sig объявляет
    // `Fail[E']`; иначе compile error D158-defer-fail-not-in-sig.
    for item in &module.items {
        match item {
            Item::Fn(f) => {
                if let FnBody::Block(b) = &f.body {
                    walk_block_for_defers(b, &fn_effects, &f.effects, errors);
                } else if let FnBody::Expr(e) = &f.body {
                    walk_expr_for_defers(e, &fn_effects, &f.effects, errors);
                }
            }
            Item::Test(t) => {
                // Test body — implicit Fail[any] (test failure framework).
                // Allow Fail в defer body как если test-fn declared Fail.
                let test_effects: Vec<TypeRef> = vec![TypeRef::Named {
                    path: vec!["Fail".to_string()],
                    generics: vec![],
                    span: t.body.span,
                }];
                walk_block_for_defers(&t.body, &fn_effects, &test_effects, errors);
            }
            _ => {}
        }
    }
}

/// Walk block: для каждого Stmt::Defer/ErrDefer — проверить body;
/// рекурсивно walk остальные stmts (там может быть вложенный block с
/// defer'ами).
///
/// `current_fn_effects` — effect-row enclosing fn-sig (D158): defer body
/// Fail-effect разрешён если sig объявляет `Fail[E']`. Pass-through
/// recursive walkers; per-defer body checker делает actual gate.
fn walk_block_for_defers(b: &Block, fn_effects: &HashMap<String, Vec<TypeRef>>, current_fn_effects: &[TypeRef], errors: &mut Vec<Diagnostic>) {
    for s in &b.stmts {
        match s {
            Stmt::Defer { body, .. } => {
                check_defer_body(body, "defer", fn_effects, current_fn_effects, errors);
            }
            Stmt::ErrDefer { body, .. } => {
                check_defer_body(body, "errdefer", fn_effects, current_fn_effects, errors);
            }
            // D160 Plan 100.4.3: OkDefer/DeferWithResult — same body constraints.
            Stmt::OkDefer { body, .. } => {
                check_defer_body(body, "okdefer", fn_effects, current_fn_effects, errors);
            }
            Stmt::DeferWithResult { body, .. } => {
                check_defer_body(body, "defer |result|", fn_effects, current_fn_effects, errors);
            }
            Stmt::Let(decl) => walk_expr_for_defers(&decl.value, fn_effects, current_fn_effects, errors),
            Stmt::Const(_) => {}
            Stmt::Expr(e) => walk_expr_for_defers(e, fn_effects, current_fn_effects, errors),
            Stmt::Assign { target, value, .. } => {
                walk_expr_for_defers(target, fn_effects, current_fn_effects, errors);
                walk_expr_for_defers(value, fn_effects, current_fn_effects, errors);
            }
            Stmt::Return { value, .. } => {
                if let Some(v) = value { walk_expr_for_defers(v, fn_effects, current_fn_effects, errors); }
            }
            Stmt::Throw { value, .. } => walk_expr_for_defers(value, fn_effects, current_fn_effects, errors),
            Stmt::AssertStatic { expr, .. } | Stmt::Assume { expr, .. } => walk_expr_for_defers(expr, fn_effects, current_fn_effects, errors),
            Stmt::Break(_) | Stmt::Continue(_) => {}
            Stmt::Apply { args, .. } => {
                for a in args { walk_expr_for_defers(a, fn_effects, current_fn_effects, errors); }
            }
            Stmt::Calc { steps, .. } => {
                for step in steps { walk_expr_for_defers(&step.expr, fn_effects, current_fn_effects, errors); }
            }
            // Plan 110 D188: walk init expr + body block recursively.
            Stmt::ConsumeScope { init, body, .. } => {
                walk_expr_for_defers(init, fn_effects, current_fn_effects, errors);
                walk_block_for_defers(body, fn_effects, current_fn_effects, errors);
            }
            Stmt::Reveal { .. } => {}
            // Plan 136: tuple destructuring assignment.
            Stmt::TupleAssign { lhs, rhs, .. } => {
                for e in lhs { walk_expr_for_defers(e, fn_effects, current_fn_effects, errors); }
                for e in rhs { walk_expr_for_defers(e, fn_effects, current_fn_effects, errors); }
            }
        }
    }
    if let Some(t) = &b.trailing {
        walk_expr_for_defers(t, fn_effects, current_fn_effects, errors);
    }
}

/// Walk expression: рекурсивно ищем вложенные блоки с defer'ами.
/// Сам по себе expression не проверяется — только nested blocks.
///
/// `current_fn_effects` (D158) — pass-through к check_defer_body для гейта
/// Fail-effect в defer body. Lambdas / closures **новые** scopes — у них
/// собственные effects; для simplicity bootstrap'а consume parent
/// fn_effects (overly-permissive: closure без Fail в свой effect-row,
/// но defer inside может бросать; runtime errors будут поймать через
/// type-check Outer-call-site). Production-уровневое уточнение —
/// Plan 100.4.5 closure-as-defer.
fn walk_expr_for_defers(e: &Expr, fn_effects: &HashMap<String, Vec<TypeRef>>, current_fn_effects: &[TypeRef], errors: &mut Vec<Diagnostic>) {
    match &e.kind {
        ExprKind::Block(b) => walk_block_for_defers(b, fn_effects, current_fn_effects, errors),
        ExprKind::If { cond, then, else_ } => {
            walk_expr_for_defers(cond, fn_effects, current_fn_effects, errors);
            walk_block_for_defers(then, fn_effects, current_fn_effects, errors);
            if let Some(ElseBranch::Block(b)) = else_ { walk_block_for_defers(b, fn_effects, current_fn_effects, errors); }
            if let Some(ElseBranch::If(e2)) = else_ { walk_expr_for_defers(e2, fn_effects, current_fn_effects, errors); }
        }
        ExprKind::IfLet { scrutinee, then, else_, .. } => {
            walk_expr_for_defers(scrutinee, fn_effects, current_fn_effects, errors);
            walk_block_for_defers(then, fn_effects, current_fn_effects, errors);
            if let Some(ElseBranch::Block(b)) = else_ { walk_block_for_defers(b, fn_effects, current_fn_effects, errors); }
            if let Some(ElseBranch::If(e2)) = else_ { walk_expr_for_defers(e2, fn_effects, current_fn_effects, errors); }
        }
        ExprKind::Match { scrutinee, arms } => {
            walk_expr_for_defers(scrutinee, fn_effects, current_fn_effects, errors);
            for a in arms {
                match &a.body {
                    MatchArmBody::Expr(e2) => walk_expr_for_defers(e2, fn_effects, current_fn_effects, errors),
                    MatchArmBody::Block(b) => walk_block_for_defers(b, fn_effects, current_fn_effects, errors),
                }
                if let Some(g) = &a.guard { walk_expr_for_defers(g, fn_effects, current_fn_effects, errors); }
            }
        }
        ExprKind::For { iter, body, .. } | ExprKind::ParallelFor { iter, body, .. } => {
            walk_expr_for_defers(iter, fn_effects, current_fn_effects, errors);
            walk_block_for_defers(body, fn_effects, current_fn_effects, errors);
        }
        ExprKind::While { cond, body, .. } => {
            walk_expr_for_defers(cond, fn_effects, current_fn_effects, errors);
            walk_block_for_defers(body, fn_effects, current_fn_effects, errors);
        }
        ExprKind::WhileLet { scrutinee, body, .. } => {
            walk_expr_for_defers(scrutinee, fn_effects, current_fn_effects, errors);
            walk_block_for_defers(body, fn_effects, current_fn_effects, errors);
        }
        ExprKind::Loop { body, .. } => walk_block_for_defers(body, fn_effects, current_fn_effects, errors),
        ExprKind::Select { arms } => {
            for arm in arms {
                match &arm.op {
                    SelectOp::Recv { chan, .. } => walk_expr_for_defers(chan, fn_effects, current_fn_effects, errors),
                    SelectOp::Send { chan, value } => {
                        walk_expr_for_defers(chan, fn_effects, current_fn_effects, errors);
                        walk_expr_for_defers(value, fn_effects, current_fn_effects, errors);
                    }
                    SelectOp::Default => {}
                }
                if let Some(g) = &arm.guard { walk_expr_for_defers(g, fn_effects, current_fn_effects, errors); }
                walk_block_for_defers(&arm.body, fn_effects, current_fn_effects, errors);
            }
        }
        ExprKind::With { body, .. } | ExprKind::Forbid { body, .. }
        | ExprKind::Realtime { body, .. }
        | ExprKind::Detach(body) | ExprKind::Blocking(body) => {
            walk_block_for_defers(body, fn_effects, current_fn_effects, errors);
        }
        ExprKind::Supervised { body, cancel } => {
            if let Some(c) = cancel { walk_expr_for_defers(c, fn_effects, current_fn_effects, errors); }
            walk_block_for_defers(body, fn_effects, current_fn_effects, errors);
        }
        ExprKind::Call { func, args, trailing } => {
            walk_expr_for_defers(func, fn_effects, current_fn_effects, errors);
            for a in args {
                walk_expr_for_defers(a.expr(), fn_effects, current_fn_effects, errors);
            }
            if let Some(tr) = trailing {
                match tr {
                    Trailing::Block(b) => walk_block_for_defers(b, fn_effects, current_fn_effects, errors),
                    Trailing::Fn(fsb) => {
                        if let FnBody::Block(b) = &fsb.body { walk_block_for_defers(b, fn_effects, current_fn_effects, errors); }
                        else if let FnBody::Expr(e2) = &fsb.body { walk_expr_for_defers(e2, fn_effects, current_fn_effects, errors); }
                    }
                    Trailing::LegacyBlockWithParams(tb) => {
                        walk_block_for_defers(&tb.body, fn_effects, current_fn_effects, errors);
                    }
                }
            }
        }
        ExprKind::Spawn(body) => walk_expr_for_defers(body, fn_effects, current_fn_effects, errors),
        ExprKind::Binary { left, right, .. } => {
            walk_expr_for_defers(left, fn_effects, current_fn_effects, errors);
            walk_expr_for_defers(right, fn_effects, current_fn_effects, errors);
        }
        ExprKind::Unary { operand, .. } => walk_expr_for_defers(operand, fn_effects, current_fn_effects, errors),
        ExprKind::Try(e2) | ExprKind::Bang(e2) | ExprKind::Throw(e2) => {
            walk_expr_for_defers(e2, fn_effects, current_fn_effects, errors);
        }
        ExprKind::Coalesce(a, b) => {
            walk_expr_for_defers(a, fn_effects, current_fn_effects, errors);
            walk_expr_for_defers(b, fn_effects, current_fn_effects, errors);
        }
        ExprKind::As(e2, _) | ExprKind::Is(e2, _) => walk_expr_for_defers(e2, fn_effects, current_fn_effects, errors),
        ExprKind::Member { obj, .. } | ExprKind::Index { obj, .. } => walk_expr_for_defers(obj, fn_effects, current_fn_effects, errors),
        ExprKind::TurboFish { base, .. } => walk_expr_for_defers(base, fn_effects, current_fn_effects, errors),
        ExprKind::Lambda { body, .. } | ExprKind::Interrupt(Some(body)) => walk_expr_for_defers(body, fn_effects, current_fn_effects, errors),
        ExprKind::Range { start, end, .. } => {
            if let Some(s) = start { walk_expr_for_defers(s, fn_effects, current_fn_effects, errors); }
            if let Some(e) = end { walk_expr_for_defers(e, fn_effects, current_fn_effects, errors); }
        }
        ExprKind::ArrayLit(elems) => {
            for el in elems {
                match el {
                    ArrayElem::Item(e2) | ArrayElem::Spread(e2) => walk_expr_for_defers(e2, fn_effects, current_fn_effects, errors),
                }
            }
        }
        ExprKind::TupleLit(elems) => {
            for el in elems { walk_expr_for_defers(el, fn_effects, current_fn_effects, errors); }
        }
        ExprKind::RecordLit { fields, .. } => {
            for f in fields {
                if let Some(v) = &f.value { walk_expr_for_defers(v, fn_effects, current_fn_effects, errors); }
            }
        }
        // Лямбды closure-full: body внутри FnSigBody.
        ExprKind::ClosureFull(fsb) => {
            if let FnBody::Block(b) = &fsb.body { walk_block_for_defers(b, fn_effects, current_fn_effects, errors); }
            else if let FnBody::Expr(e2) = &fsb.body { walk_expr_for_defers(e2, fn_effects, current_fn_effects, errors); }
        }
        ExprKind::ClosureLight { body, .. } => {
            match body {
                ClosureBody::Expr(e2) => walk_expr_for_defers(e2, fn_effects, current_fn_effects, errors),
                ClosureBody::Block(b) => walk_block_for_defers(b, fn_effects, current_fn_effects, errors),
            }
        }
        // Простые узлы без вложенных блоков.
        _ => {}
    }
}

/// Body constraint check: exit-control, Fail-effect, suspend.
///
/// D158 (Plan 100.4.1): Fail в defer body разрешён, если enclosing fn-sig
/// объявляет `Fail[E']` (passed in `current_fn_effects`) ИЛИ throw/?/!!
/// находятся внутри `with Fail = handler { ... }` (silent suppress
/// shorthand) — tracked через `DeferBodyCtx.inside_fail_handler_depth`.
fn check_defer_body(body: &Expr, kw: &str, fn_effects: &HashMap<String, Vec<TypeRef>>, current_fn_effects: &[TypeRef], errors: &mut Vec<Diagnostic>) {
    // D90 Plan 20 Ф.3 (revised): Вариант 3 — return/break/continue разрешены
    // только внутри nested loop/fn-literal в defer body (local control). На
    // top-level defer body они запрещены — нельзя hijack scope-exit
    // окружающей функции/цикла.
    //
    // Ctx tracks: loop-nesting depth (break/continue ok если >0), fn-literal
    // depth (return ok если >0), fail-handler-wrap depth (D158: внутри
    // `with Fail = ... { ... }` body Fail-throws silently suppressed).
    let ctx = DeferBodyCtx { loop_depth: 0, fn_depth: 0, inside_fail_handler_depth: 0 };
    check_defer_body_inner(body, kw, fn_effects, current_fn_effects, &ctx, errors);
}

#[derive(Clone, Copy)]
struct DeferBodyCtx {
    /// Текущая глубина loop'ов (for/while/loop) внутри defer body. Если >0,
    /// `break`/`continue` локальны — разрешены.
    loop_depth: usize,
    /// Текущая глубина fn-литералов (closure/lambda) внутри defer body. Если
    /// >0, `return` локален — разрешён (relates только к ближайшему fn).
    fn_depth: usize,
    /// D158 (Plan 100.4.1): depth of `with Fail = ... { ... }` wrappers
    /// внутри defer body. Если >0, Fail-throws (`throw`/`?`/`!!` + Fail-
    /// calls) — silently suppressed inner handler'ом, не propagate'ятся
    /// в outer defer scope. **Backward-compat shorthand** для pre-D158
    /// pattern: `defer { with Fail = handler { ... } { risky() } }`.
    inside_fail_handler_depth: usize,
}

fn check_defer_body_inner(e: &Expr, kw: &str, fn_effects: &HashMap<String, Vec<TypeRef>>, current_fn_effects: &[TypeRef], ctx: &DeferBodyCtx, errors: &mut Vec<Diagnostic>) {
    // D158 gate: Fail-throws разрешены если (a) внутри `with Fail = ...`
    // wrapper'а, ИЛИ (b) enclosing fn-sig объявляет `Fail[E']`.
    let fail_throw_allowed = ctx.inside_fail_handler_depth > 0
        || has_fail_effect(current_fn_effects);

    // Сначала проверяем узел сам по себе.
    match &e.kind {
        // Exit-control: throw expression-form (D85 redirected via Fail).
        // D158 (Plan 100.4.1): allow если fail_throw_allowed; иначе error D158-defer-fail-not-in-sig.
        ExprKind::Throw(_) => {
            if !fail_throw_allowed {
                errors.push(Diagnostic::new(
                    format!("`throw` inside `{}` body requires `Fail[E]` in enclosing fn signature (D158-defer-fail-not-in-sig). \
                             Either (1) add `Fail[E]` to fn signature — cleanup-fail composes с propagating error через MultiError, \
                             ИЛИ (2) wrap with `with Fail = handler {{ ... }}` for silent suppress.", kw),
                    e.span,
                ));
            }
        }
        // ? и !! desugar в throw → same D158 rule.
        ExprKind::Try(_) => {
            if !fail_throw_allowed {
                errors.push(Diagnostic::new(
                    format!("`?` operator inside `{}` body requires `Fail[E]` in enclosing fn signature (D158-defer-fail-not-in-sig). \
                             Either (1) add `Fail[E]` to fn signature; ИЛИ (2) wrap with `with Fail = handler {{ ... }}`.", kw),
                    e.span,
                ));
            }
        }
        ExprKind::Bang(_) => {
            if !fail_throw_allowed {
                errors.push(Diagnostic::new(
                    format!("`!!` operator inside `{}` body requires `Fail[E]` in enclosing fn signature (D158-defer-fail-not-in-sig). \
                             Either (1) add `Fail[E]` to fn signature; ИЛИ (2) wrap with `with Fail = handler {{ ... }}`.", kw),
                    e.span,
                ));
            }
        }
        // Interrupt — досрочный exit with-блока, hijack'ит scope exit-семантику.
        // D158 НЕ amend'аем: interrupt — это hijack scope-exit, не failable cleanup.
        ExprKind::Interrupt(_) => {
            errors.push(Diagnostic::new(
                format!("`interrupt` is not allowed inside `{}` body (D90 §6): defer body cannot hijack scope exit.", kw),
                e.span,
            ));
        }
        // D159 (Plan 100.4.2) keeps AST-level concurrency-construct ban:
        // spawn / supervised / detach / blocking / parallel for создают новые
        // fiber'ы которые переживут scope cleanup'а — leak supervised
        // hierarchy. Sync suspend (Time.sleep, Net.*, etc.) разрешён.
        ExprKind::Spawn(_) | ExprKind::Supervised { .. } | ExprKind::Detach(_)
        | ExprKind::Blocking(_)
        | ExprKind::ParallelFor { .. } => {
            errors.push(Diagnostic::new(
                format!("concurrency construct (`spawn`/`supervised`/`detach`/`blocking`/`parallel for`) \
                         is not allowed inside `{}` body (D159-spawn-in-defer): \
                         leaks supervised hierarchy. Use sync suspend operations or `Time.timeout` instead.", kw),
                e.span,
            ));
        }
        // D159 (Plan 100.4.2): Call с suspend-эффектами — СНЯТ запрет
        // (D90 §5 amended). Suspend operations (Time.sleep, Net.*, Fs.*, Db.*,
        // Channel.recv) теперь allowed в defer body для production graceful
        // cleanup. spawn / parallel for / supervised / detach / blocking
        // остаются запрещены через AST-level matches выше (D5 D159).
        ExprKind::Call { func, .. } => {
            if let Some(callee_name) = call_target_name(func) {
                if let Some(effs) = fn_effects.get(&callee_name) {
                    // D158 (Plan 100.4.1): Fail-call check — same fail_throw_allowed rule.
                    if has_fail_effect(effs) && !fail_throw_allowed {
                        errors.push(Diagnostic::new(
                            format!("call to `{}` has `Fail` effect, not allowed inside `{}` body — \
                                     enclosing fn-sig must declare `Fail[E]` (D158-defer-fail-not-in-sig). \
                                     Either (1) add `Fail[E]` to fn signature; ИЛИ (2) wrap with `with Fail = handler {{ ... }}`.",
                                    callee_name, kw),
                            e.span,
                        ));
                    }
                }
            }
            // D159 also lifted built-in effect ops ban (Time.sleep / Net.get / etc.) —
            // suspend allowed; spawn/parallel for ban сохраняется AST-level выше.
            let _ = func; // suppress unused-warning post-removal
        }
        _ => {}
    }

    // Рекурсивно вглубь — вложенные scope (block, if, etc.) подчиняются тем же
    // ограничениям, т.к. они часть defer body.
    walk_defer_subexprs(e, kw, fn_effects, current_fn_effects, ctx, errors);
}

fn walk_defer_subexprs(e: &Expr, kw: &str, fn_effects: &HashMap<String, Vec<TypeRef>>, current_fn_effects: &[TypeRef], ctx: &DeferBodyCtx, errors: &mut Vec<Diagnostic>) {
    match &e.kind {
        ExprKind::Block(b) => check_defer_body_block(b, kw, fn_effects, current_fn_effects, ctx, errors),
        ExprKind::If { cond, then, else_ } => {
            check_defer_body_inner(cond, kw, fn_effects, current_fn_effects, ctx, errors);
            check_defer_body_block(then, kw, fn_effects, current_fn_effects, ctx, errors);
            match else_ {
                Some(ElseBranch::Block(b)) => check_defer_body_block(b, kw, fn_effects, current_fn_effects, ctx, errors),
                Some(ElseBranch::If(e2)) => check_defer_body_inner(e2, kw, fn_effects, current_fn_effects, ctx, errors),
                None => {}
            }
        }
        ExprKind::IfLet { scrutinee, then, else_, .. } => {
            check_defer_body_inner(scrutinee, kw, fn_effects, current_fn_effects, ctx, errors);
            check_defer_body_block(then, kw, fn_effects, current_fn_effects, ctx, errors);
            match else_ {
                Some(ElseBranch::Block(b)) => check_defer_body_block(b, kw, fn_effects, current_fn_effects, ctx, errors),
                Some(ElseBranch::If(e2)) => check_defer_body_inner(e2, kw, fn_effects, current_fn_effects, ctx, errors),
                None => {}
            }
        }
        ExprKind::Match { scrutinee, arms } => {
            check_defer_body_inner(scrutinee, kw, fn_effects, current_fn_effects, ctx, errors);
            for a in arms {
                match &a.body {
                    MatchArmBody::Expr(e2) => check_defer_body_inner(e2, kw, fn_effects, current_fn_effects, ctx, errors),
                    MatchArmBody::Block(b) => check_defer_body_block(b, kw, fn_effects, current_fn_effects, ctx, errors),
                }
                if let Some(g) = &a.guard { check_defer_body_inner(g, kw, fn_effects, current_fn_effects, ctx, errors); }
            }
        }
        ExprKind::For { iter, body, .. } => {
            check_defer_body_inner(iter, kw, fn_effects, current_fn_effects, ctx, errors);
            let inner = DeferBodyCtx { loop_depth: ctx.loop_depth + 1, fn_depth: ctx.fn_depth, inside_fail_handler_depth: ctx.inside_fail_handler_depth };
            check_defer_body_block(body, kw, fn_effects, current_fn_effects, &inner, errors);
        }
        ExprKind::While { cond, body, .. } => {
            check_defer_body_inner(cond, kw, fn_effects, current_fn_effects, ctx, errors);
            let inner = DeferBodyCtx { loop_depth: ctx.loop_depth + 1, fn_depth: ctx.fn_depth, inside_fail_handler_depth: ctx.inside_fail_handler_depth };
            check_defer_body_block(body, kw, fn_effects, current_fn_effects, &inner, errors);
        }
        ExprKind::WhileLet { scrutinee, body, .. } => {
            check_defer_body_inner(scrutinee, kw, fn_effects, current_fn_effects, ctx, errors);
            let inner = DeferBodyCtx { loop_depth: ctx.loop_depth + 1, fn_depth: ctx.fn_depth, inside_fail_handler_depth: ctx.inside_fail_handler_depth };
            check_defer_body_block(body, kw, fn_effects, current_fn_effects, &inner, errors);
        }
        ExprKind::Loop { body, .. } => {
            let inner = DeferBodyCtx { loop_depth: ctx.loop_depth + 1, fn_depth: ctx.fn_depth, inside_fail_handler_depth: ctx.inside_fail_handler_depth };
            check_defer_body_block(body, kw, fn_effects, current_fn_effects, &inner, errors);
        }
        ExprKind::Select { arms } => {
            for arm in arms {
                match &arm.op {
                    SelectOp::Recv { chan, .. } => check_defer_body_inner(chan, kw, fn_effects, current_fn_effects, ctx, errors),
                    SelectOp::Send { chan, value } => {
                        check_defer_body_inner(chan, kw, fn_effects, current_fn_effects, ctx, errors);
                        check_defer_body_inner(value, kw, fn_effects, current_fn_effects, ctx, errors);
                    }
                    SelectOp::Default => {}
                }
                if let Some(g) = &arm.guard { check_defer_body_inner(g, kw, fn_effects, current_fn_effects, ctx, errors); }
                check_defer_body_block(&arm.body, kw, fn_effects, current_fn_effects, ctx, errors);
            }
        }
        // D158 (Plan 100.4.1): `with Fail = handler { ... } { body }` —
        // body inside silently suppress'ит Fail-throws (inner handler ловит
        // их). Increment ctx.inside_fail_handler_depth для recursive check.
        ExprKind::With { bindings, body } => {
            let any_fail = bindings.iter().any(|b| matches!(&b.effect, TypeRef::Named { path, .. } if path.len() == 1 && path[0] == "Fail"));
            let inner = if any_fail {
                DeferBodyCtx {
                    loop_depth: ctx.loop_depth,
                    fn_depth: ctx.fn_depth,
                    inside_fail_handler_depth: ctx.inside_fail_handler_depth + 1,
                }
            } else { *ctx };
            check_defer_body_block(body, kw, fn_effects, current_fn_effects, &inner, errors);
        }
        ExprKind::Forbid { body, .. } | ExprKind::Realtime { body, .. } => {
            check_defer_body_block(body, kw, fn_effects, current_fn_effects, ctx, errors);
        }
        ExprKind::Call { func, args, trailing } => {
            check_defer_body_inner(func, kw, fn_effects, current_fn_effects, ctx, errors);
            for a in args { check_defer_body_inner(a.expr(), kw, fn_effects, current_fn_effects, ctx, errors); }
            if let Some(tr) = trailing {
                match tr {
                    Trailing::Block(b) => check_defer_body_block(b, kw, fn_effects, current_fn_effects, ctx, errors),
                    Trailing::Fn(fsb) => {
                        // Trailing fn-literal `fn { ... }` — это лямбда; return
                        // внутри неё локален для лямбды, а не для defer body.
                        let inner = DeferBodyCtx { loop_depth: ctx.loop_depth, fn_depth: ctx.fn_depth + 1, inside_fail_handler_depth: ctx.inside_fail_handler_depth };
                        if let FnBody::Block(b) = &fsb.body { check_defer_body_block(b, kw, fn_effects, current_fn_effects, &inner, errors); }
                        else if let FnBody::Expr(e2) = &fsb.body { check_defer_body_inner(e2, kw, fn_effects, current_fn_effects, &inner, errors); }
                    }
                    Trailing::LegacyBlockWithParams(tb) => {
                        let inner = DeferBodyCtx { loop_depth: ctx.loop_depth, fn_depth: ctx.fn_depth + 1, inside_fail_handler_depth: ctx.inside_fail_handler_depth };
                        check_defer_body_block(&tb.body, kw, fn_effects, current_fn_effects, &inner, errors);
                    }
                }
            }
        }
        ExprKind::Binary { left, right, .. } => {
            check_defer_body_inner(left, kw, fn_effects, current_fn_effects, ctx, errors);
            check_defer_body_inner(right, kw, fn_effects, current_fn_effects, ctx, errors);
        }
        ExprKind::Unary { operand, .. } => check_defer_body_inner(operand, kw, fn_effects, current_fn_effects, ctx, errors),
        ExprKind::Coalesce(a, b) => {
            check_defer_body_inner(a, kw, fn_effects, current_fn_effects, ctx, errors);
            check_defer_body_inner(b, kw, fn_effects, current_fn_effects, ctx, errors);
        }
        ExprKind::As(e2, _) | ExprKind::Is(e2, _) => check_defer_body_inner(e2, kw, fn_effects, current_fn_effects, ctx, errors),
        ExprKind::Member { obj, .. } | ExprKind::Index { obj, .. } => check_defer_body_inner(obj, kw, fn_effects, current_fn_effects, ctx, errors),
        ExprKind::TurboFish { base, .. } => check_defer_body_inner(base, kw, fn_effects, current_fn_effects, ctx, errors),
        ExprKind::Range { start, end, .. } => {
            if let Some(s) = start { check_defer_body_inner(s, kw, fn_effects, current_fn_effects, ctx, errors); }
            if let Some(e) = end { check_defer_body_inner(e, kw, fn_effects, current_fn_effects, ctx, errors); }
        }
        ExprKind::ArrayLit(elems) => {
            for el in elems {
                match el {
                    ArrayElem::Item(e2) | ArrayElem::Spread(e2) => check_defer_body_inner(e2, kw, fn_effects, current_fn_effects, ctx, errors),
                }
            }
        }
        ExprKind::TupleLit(elems) => {
            for el in elems { check_defer_body_inner(el, kw, fn_effects, current_fn_effects, ctx, errors); }
        }
        ExprKind::RecordLit { fields, .. } => {
            for f in fields {
                if let Some(v) = &f.value { check_defer_body_inner(v, kw, fn_effects, current_fn_effects, ctx, errors); }
            }
        }
        // Lambda/closure bodies — это отдельный scope для defer'а
        // (defer внутри lambda относится к scope lambda, не parent).
        // Не проверяем — это уже не defer body, а его callees, которые
        // могут быть call'аны откуда угодно. Лямбда сама **может** быть
        // call'нута асинхронно — но это не defer issue, это её caller's
        // concern.
        ExprKind::Lambda { .. } | ExprKind::ClosureLight { .. } | ExprKind::ClosureFull(_) => {}
        // Suspend / Throw / Interrupt — уже flagged выше в check_defer_body_inner.
        _ => {}
    }
}

fn check_defer_body_block(b: &Block, kw: &str, fn_effects: &HashMap<String, Vec<TypeRef>>, current_fn_effects: &[TypeRef], ctx: &DeferBodyCtx, errors: &mut Vec<Diagnostic>) {
    for s in &b.stmts {
        match s {
            Stmt::Return { span, value } => {
                // Вариант 3 (D90): return локален только внутри nested fn-литерала.
                if ctx.fn_depth == 0 {
                    errors.push(Diagnostic::new(
                        format!("`return` is not allowed at the top level of `{}` body (D90): defer body cannot hijack scope exit of the enclosing function. \
                                 (Local `return` inside nested `fn`/closure внутри defer body разрешён.)", kw),
                        *span,
                    ));
                }
                if let Some(v) = value {
                    check_defer_body_inner(v, kw, fn_effects, current_fn_effects, ctx, errors);
                }
            }
            Stmt::Break(span) => {
                if ctx.loop_depth == 0 {
                    errors.push(Diagnostic::new(
                        format!("`break` is not allowed at the top level of `{}` body (D90): defer body cannot hijack the enclosing loop. \
                                 (Local `break` inside nested loop разрешён.)", kw),
                        *span,
                    ));
                }
            }
            Stmt::Continue(span) => {
                if ctx.loop_depth == 0 {
                    errors.push(Diagnostic::new(
                        format!("`continue` is not allowed at the top level of `{}` body (D90): defer body cannot hijack the enclosing loop. \
                                 (Local `continue` inside nested loop разрешён.)", kw),
                        *span,
                    ));
                }
            }
            Stmt::Throw { span, value } => {
                // D158 (Plan 100.4.1): Stmt-form `throw` (а не expr-form) — same rule
                // как expr-form Throw в check_defer_body_inner.
                let fail_throw_allowed = ctx.inside_fail_handler_depth > 0
                    || has_fail_effect(current_fn_effects);
                if !fail_throw_allowed {
                    errors.push(Diagnostic::new(
                        format!("`throw` inside `{}` body requires `Fail[E]` in enclosing fn signature (D158-defer-fail-not-in-sig). \
                                 Either (1) add `Fail[E]` to fn signature — cleanup-fail composes с propagating error через MultiError, \
                                 ИЛИ (2) wrap with `with Fail = effect Fail {{ ... }}` for silent suppress.", kw),
                        *span,
                    ));
                }
                check_defer_body_inner(value, kw, fn_effects, current_fn_effects, ctx, errors);
            }
            Stmt::Let(decl) => check_defer_body_inner(&decl.value, kw, fn_effects, current_fn_effects, ctx, errors),
            Stmt::Const(_) => {}
            Stmt::Expr(e) => check_defer_body_inner(e, kw, fn_effects, current_fn_effects, ctx, errors),
            Stmt::Assign { target, value, .. } => {
                check_defer_body_inner(target, kw, fn_effects, current_fn_effects, ctx, errors);
                check_defer_body_inner(value, kw, fn_effects, current_fn_effects, ctx, errors);
            }
            // Nested defer/errdefer — это OK. Это новый scope (block),
            // defer'ы внутри регистрируются для этого внутреннего scope'а,
            // не для родительского. Рх body тоже проверяется — но через
            // основной walk (check_defer_bodies проходит по всем bodies).
            Stmt::Defer { body, .. } => check_defer_body(body, "defer", fn_effects, current_fn_effects, errors),
            Stmt::ErrDefer { body, .. } => check_defer_body(body, "errdefer", fn_effects, current_fn_effects, errors),
            // D160 Plan 100.4.3: OkDefer / DeferWithResult body — same constraints as defer.
            Stmt::OkDefer { body, .. } => check_defer_body(body, "okdefer", fn_effects, current_fn_effects, errors),
            Stmt::DeferWithResult { body, .. } => check_defer_body(body, "defer |result|", fn_effects, current_fn_effects, errors),
            // Plan 33.2 Ф.8: assert_static в defer body — walk expr.
            Stmt::AssertStatic { expr, .. } | Stmt::Assume { expr, .. } => check_defer_body_inner(expr, kw, fn_effects, current_fn_effects, ctx, errors),
            // Ф.4.1: apply — ghost, args walk.
            Stmt::Apply { args, .. } => {
                for a in args { check_defer_body_inner(a, kw, fn_effects, current_fn_effects, ctx, errors); }
            }
            // Ф.4.2: calc — ghost, шаги walk.
            Stmt::Calc { steps, .. } => {
                for step in steps { check_defer_body_inner(&step.expr, kw, fn_effects, current_fn_effects, ctx, errors); }
            }
            // Plan 110 D188: nested consume{} inside defer body — init +
            // body block walk (D197 cleanup re-entrance — full rules в
            // Plan 110.1.8).
            Stmt::ConsumeScope { init, body, .. } => {
                check_defer_body_inner(init, kw, fn_effects, current_fn_effects, ctx, errors);
                check_defer_body_block(body, kw, fn_effects, current_fn_effects, ctx, errors);
            }
            Stmt::Reveal { .. } => {}
            // Plan 136: tuple destructuring assignment.
            Stmt::TupleAssign { lhs, rhs, .. } => {
                for e in lhs { check_defer_body_inner(e, kw, fn_effects, current_fn_effects, ctx, errors); }
                for e in rhs { check_defer_body_inner(e, kw, fn_effects, current_fn_effects, ctx, errors); }
            }
        }
    }
    if let Some(t) = &b.trailing {
        check_defer_body_inner(t, kw, fn_effects, current_fn_effects, ctx, errors);
    }
}

/// Рзвлечь имя callee если выражение — call target (Ident или Type.method).
fn call_target_name(e: &Expr) -> Option<String> {
    match &e.kind {
        ExprKind::Ident(n) => Some(n.clone()),
        ExprKind::Path(parts) if parts.len() >= 2 => Some(parts.join(".")),
        ExprKind::Member { obj, name } => {
            if let ExprKind::Ident(head) = &obj.kind {
                Some(format!("{}.{}", head, name))
            } else {
                None
            }
        }
        _ => None,
    }
}

// ──────────────────────────────────────────────────────────────────────────
// Plan 33.1 Ф.2 (D24): ContractCtx — проверка базовых правил контрактов.
//
// Минимальный pass для 33.1. Полная type-проверка (контракт должен быть
// bool, result.value под guard'ом, и т.д.) — в Ф.3 вместе с SMT-кодировкой.
//
// Базовые правила (33.1):
// 1. `result` запрещён в `requires` (значения ещё нет).
// 2. `old(...)` запрещён в `requires` (нет «до»).
// 3. composition: вызов другой fn в контракте — error в 33.1 (Plan 33.2
//    разрешит для @pure функций).
// ──────────────────────────────────────────────────────────────────────────

/// Контекст контракт-проверок.
///
/// Plan 33.2 Ф.7: разрешает composition — вызов `#pure` функций
/// в контрактах. Non-`#pure` функции в контрактах — compile error.
struct ContractCtx {
    /// Рмена всех top-level fn.
    fn_names: HashSet<String>,
    /// Рмена fn объявленных `#pure` (через атрибут).
    /// Рспользуются для разрешения composition в контрактах (33.2).
    pure_fn_names: HashSet<String>,
    /// Plan 33.3 Ф.9: pure_view-имя → (effect_name, arity).
    /// При вызове `balance(id)` в контракте определяем (а) что это
    /// pure_view, (б) к какому эффекту относится, (в) что эффект в
    /// сигнатуре enclosing fn.
    // Multimap: method_name → Vec<(effect_name, arity)>.
    // Multiple effects can share the same pure_view method name; we keep all of
    // them so that a function whose signature contains *any* matching effect is
    // accepted without a spurious "effect not in signature" error.
    pure_views: HashMap<String, Vec<(String, usize)>>,
}

impl ContractCtx {
    fn build(module: &Module) -> Self {
        let mut fn_names = HashSet::new();
        let mut pure_fn_names = HashSet::new();
        let mut pure_views: HashMap<String, Vec<(String, usize)>> = HashMap::new();
        for item in &module.items {
            match item {
                Item::Fn(fd) => {
                    fn_names.insert(fd.name.clone());
                    if matches!(fd.purity, Purity::Pure) {
                        pure_fn_names.insert(fd.name.clone());
                    }
                    // Ф.3 (Plan 33.5): SCC inference добавляется ниже.
                }
                Item::Type(td) => {
                    if let TypeDeclKind::Effect(methods) = &td.kind {
                        for m in methods {
                            if matches!(m.kind, EffectOpKind::PureView) {
                                pure_views
                                    .entry(m.name.clone())
                                    .or_default()
                                    .push((td.name.clone(), m.params.len()));
                            }
                        }
                    }
                }
                _ => {}
            }
        }
        // Ф.3 (Plan 33.5): SCC inference — авто-определяем pure fn'ы
        // через Tarjan SCC на call-graph (паритет с Dafny auto-pure).
        // Добавляем в pure_fn_names если не помечены явно Effectful.
        // Стек не проблема: main() запускается в потоке с 32 MiB стека.
        let inferred = crate::verify::pipeline::infer_pure_fns_scc(module);
        for name in inferred {
            pure_fn_names.insert(name);
        }
        Self { fn_names, pure_fn_names, pure_views }
    }

    fn check_module(&self, module: &Module, errors: &mut Vec<Diagnostic>) {
        for item in &module.items {
            if let Item::Fn(fd) = item {
                self.check_fn(fd, errors);
            }
        }
    }

    fn check_fn(&self, fd: &FnDecl, errors: &mut Vec<Diagnostic>) {
        // Plan 33.2 Ф.5: проверка modifies-frame.
        // Если объявлен `modifies`, все assignment'ы внутри body должны
        // быть покрыты frame-target'ами.
        if !fd.modifies.is_empty() {
            self.check_modifies_frame(fd, errors);
        }
        // Plan 33.1 Ф.4: контракты на Fail-функциях требуют ContractResult
        // + flow-аналитики для result.is_ok / result.value / result.error.
        // Это полная реализация — отложена до Ф.3 SMT integration вместе
        // с Z3-кодировкой ContractResult-datatype.
        // В 33.1 — explicit compile error чтобы избежать silent unsoundness.
        if !fd.contracts.is_empty() && Self::fn_has_fail(fd) {
            errors.push(Diagnostic::new(
                format!(
                    "contracts on `Fail`-returning functions not yet supported in Plan 33.1 \
                     (`{}` has `Fail` effect; ContractResult + flow-analysis for \
                     result.is_ok / result.value / result.error — Plan 33.1 Ф.3 / Ф.4 follow-up)",
                    fd.name
                ),
                fd.span,
            ));
            // Контракты не проверяем дальше — error уже выдан.
            return;
        }
        // Plan 33.3 Ф.9: множество имён эффектов из сигнатуры функции
        // (для разрешения pure_view-вызовов в контрактах).
        let fn_effects: HashSet<String> = fd.effects.iter()
            .filter_map(|tr| match tr {
                TypeRef::Named { path, .. } => path.last().cloned(),
                _ => None,
            })
            .collect();
        for contract in &fd.contracts {
            match contract.kind {
                ContractKind::Requires => {
                    self.check_requires_expr(&contract.expr, &fn_effects, &fd.name, errors);
                }
                ContractKind::Ensures => {
                    self.check_ensures_expr(&contract.expr, &fn_effects, &fd.name, errors);
                }
                ContractKind::EnsuresFail => {
                    // D.1.5: ensures_fail — проверяем как ensures (V1 bootstrap).
                    // V2: добавить проверку что `result` не используется.
                    self.check_ensures_expr(&contract.expr, &fn_effects, &fd.name, errors);
                }
            }
            // Plan 140.3 ([M-140.1-message-interpolation]): sub-выражения
            // интерполированного сообщения (`"got ${x}"`) проверяем под теми же
            // ghost-правилами, что и сам контракт (`result` допустим лишь в ensures).
            if let Some(msg_expr) = &contract.message_expr {
                match contract.kind {
                    ContractKind::Requires =>
                        self.check_requires_expr(msg_expr, &fn_effects, &fd.name, errors),
                    _ =>
                        self.check_ensures_expr(msg_expr, &fn_effects, &fd.name, errors),
                }
            }
        }
    }

    /// Plan 33.2 Ф.5: проверка `modifies`-frame.
    /// Walks body, для каждого Stmt::Assign к **non-local** target'у
    /// (параметр / self / поле) проверяет что target покрыт frame-target'ом.
    ///
    /// Локальные `let mut` НЕ требуют frame-cover'а — `modifies` относится
    /// к **API-visible** mutations (параметры, self.fields). Это паритет с
    /// Dafny: «modifies clause is about heap effect, not stack locals».
    fn check_modifies_frame(&self, fd: &FnDecl, errors: &mut Vec<Diagnostic>) {
        let block = match &fd.body {
            FnBody::Block(b) => b,
            FnBody::Expr(_) | FnBody::External => return, // no assigns possible
        };
        // Collect local-binding names (let / let mut в block).
        let mut locals: std::collections::HashSet<String> = std::collections::HashSet::new();
        for stmt in &block.stmts {
            if let Stmt::Let(LetDecl { pattern, .. }) = stmt {
                Self::collect_binding_names(pattern, &mut locals);
            }
        }
        for stmt in &block.stmts {
            if let Stmt::Assign { target, span, .. } = stmt {
                // Skip locals.
                if let Some(root_name) = Self::root_lvalue_name(target) {
                    if locals.contains(&root_name) { continue; }
                }
                if !Self::is_assign_covered(target, &fd.modifies) {
                    errors.push(Diagnostic::new(
                        format!(
                            "assignment to `{}` is not covered by `modifies` clause of `{}`",
                            Self::expr_display(target), fd.name
                        ),
                        *span,
                    ));
                }
            }
        }
    }

    fn collect_binding_names(p: &Pattern, out: &mut std::collections::HashSet<String>) {
        match p {
            Pattern::Ident { name, .. } => { out.insert(name.clone()); }
            Pattern::Binding { name, inner, .. } => {
                out.insert(name.clone());
                Self::collect_binding_names(inner, out);
            }
            Pattern::Tuple(ps, _) => for sub in ps { Self::collect_binding_names(sub, out); }
            Pattern::Record { fields, .. } => for f in fields {
                if let Some(sub) = &f.pattern { Self::collect_binding_names(sub, out); }
                else { out.insert(f.name.clone()); }
            },
            Pattern::Array { elems, .. } => for e in elems {
                match e {
                    ArrayPatternElem::Item(pp) => Self::collect_binding_names(pp, out),
                    ArrayPatternElem::RestBind(n) => { out.insert(n.clone()); }
                    ArrayPatternElem::Rest => {}
                }
            },
            _ => {}
        }
    }

    fn root_lvalue_name(e: &Expr) -> Option<String> {
        match &e.kind {
            ExprKind::Ident(n) => Some(n.clone()),
            ExprKind::Member { obj, .. } => Self::root_lvalue_name(obj),
            ExprKind::Index { obj, .. } => Self::root_lvalue_name(obj),
            _ => None,
        }
    }

    /// Проверка: один target покрыт `modifies`-list'ом.
    fn is_assign_covered(target: &Expr, frame: &[FrameTarget]) -> bool {
        for ft in frame {
            if Self::frame_covers(ft, target) {
                return true;
            }
        }
        false
    }

    fn frame_covers(ft: &FrameTarget, target: &Expr) -> bool {
        match ft {
            FrameTarget::Whole(e) => Self::same_lvalue(e, target),
            FrameTarget::Field { receiver, field, .. } => {
                if let ExprKind::Member { obj, name } = &target.kind {
                    name == field && Self::same_lvalue(receiver, obj)
                } else {
                    false
                }
            }
            FrameTarget::ArrayElem { array, index, .. } => {
                if let ExprKind::Index { obj, index: tidx } = &target.kind {
                    Self::same_lvalue(array, obj) && Self::same_lvalue(index, tidx)
                } else {
                    false
                }
            }
            FrameTarget::ArrayAll { array, .. } => {
                if let ExprKind::Index { obj, .. } = &target.kind {
                    Self::same_lvalue(array, obj)
                } else {
                    false
                }
            }
        }
    }

    /// Простой сравнитель l-value (без полного structural equality).
    fn same_lvalue(a: &Expr, b: &Expr) -> bool {
        match (&a.kind, &b.kind) {
            (ExprKind::Ident(n1), ExprKind::Ident(n2)) => n1 == n2,
            (ExprKind::SelfAccess, ExprKind::SelfAccess) => true,
            (ExprKind::Member { obj: o1, name: n1 }, ExprKind::Member { obj: o2, name: n2 }) => {
                n1 == n2 && Self::same_lvalue(o1, o2)
            }
            _ => false,
        }
    }

    fn expr_display(e: &Expr) -> String {
        match &e.kind {
            ExprKind::Ident(n) => n.clone(),
            ExprKind::SelfAccess => "self".into(),
            ExprKind::Member { obj, name } => format!("{}.{}", Self::expr_display(obj), name),
            ExprKind::Index { obj, .. } => format!("{}[..]", Self::expr_display(obj)),
            _ => "<expr>".into(),
        }
    }

    /// Проверка: функция объявляет `Fail` (любой вариант) в effects.
    fn fn_has_fail(fd: &FnDecl) -> bool {
        fd.effects.iter().any(|e| {
            matches!(e, TypeRef::Named { path, .. }
                if !path.is_empty() && path.last().map(|s| s.as_str()) == Some("Fail"))
        })
    }

    /// `requires`: запрещены `result` и `old(...)`.
    fn check_requires_expr(
        &self,
        e: &Expr,
        fn_effects: &HashSet<String>,
        fn_name: &str,
        errors: &mut Vec<Diagnostic>,
    ) {
        self.walk_expr(e, fn_effects, fn_name, errors, /*in_ensures*/ false);
    }

    /// `ensures`: `result`/`old(...)` разрешены; composition запрещён в 33.1.
    fn check_ensures_expr(
        &self,
        e: &Expr,
        fn_effects: &HashSet<String>,
        fn_name: &str,
        errors: &mut Vec<Diagnostic>,
    ) {
        self.walk_expr(e, fn_effects, fn_name, errors, /*in_ensures*/ true);
    }

    fn walk_expr(
        &self,
        e: &Expr,
        fn_effects: &HashSet<String>,
        fn_name: &str,
        errors: &mut Vec<Diagnostic>,
        in_ensures: bool,
    ) {
        match &e.kind {
            ExprKind::Ident(n) => {
                if n == "result" && !in_ensures {
                    errors.push(Diagnostic::new(
                        "`result` is not available in `requires` (only in `ensures`)",
                        e.span,
                    ));
                }
            }
            ExprKind::Call { func, args, .. } => {
                // Detect `old(...)` — special-cased call.
                if let ExprKind::Ident(name) = &func.kind {
                    if name == "old" {
                        if !in_ensures {
                            errors.push(Diagnostic::new(
                                "`old(...)` is not available in `requires` (only in `ensures`)",
                                e.span,
                            ));
                        }
                        // Walk old() arg ONCE; it's a snapshot of pre-state,
                        // not a composition.
                        for a in args {
                            self.walk_expr(a.expr(), fn_effects, fn_name, errors, in_ensures);
                        }
                        return;
                    }
                    // Plan 33.3 Ф.9.3 part 2: pure_view-вызов в контракте
                    // разрешён только если соответствующий эффект объявлен в
                    // сигнатуре enclosing fn (`(...) Eff -> ...`). pure_view
                    // — read-only observation, нужен effect-handler в scope.
                    // Multiple effects may share the same pure_view name;
                    // accept if fn_effects contains ANY of them.
                    if let Some(entries) = self.pure_views.get(name) {
                        let matching = entries.iter()
                            .find(|(eff, _)| fn_effects.contains(eff));
                        let (effect_name, expected_arity) = if let Some(entry) = matching {
                            entry
                        } else {
                            let (effect_name, expected_arity) = &entries[0];
                            let effects_hint: Vec<&str> = entries.iter()
                                .map(|(e, _)| e.as_str())
                                .collect();
                            errors.push(Diagnostic::new(
                                format!(
                                    "pure_view `{}.{}` referenced in contract of `{}`, \
                                     but effect `{}` is not in this function's signature \
                                     (add `{}` to effects)",
                                    effect_name, name, fn_name,
                                    effects_hint.join("` or `"),
                                    effects_hint.join("` or `"),
                                ),
                                e.span,
                            ));
                            &entries[0]
                        };
                        if args.len() != *expected_arity {
                            errors.push(Diagnostic::new(
                                format!(
                                    "pure_view `{}.{}` expects {} arg(s), got {}",
                                    effect_name, name, expected_arity, args.len(),
                                ),
                                e.span,
                            ));
                        }
                        // pure_view-вызов разрешён; walk args, не walk
                        // callee (это identifier-name pure_view, не fn).
                        for a in args {
                            self.walk_expr(a.expr(), fn_effects, fn_name, errors, in_ensures);
                        }
                        return;
                    }
                    // Plan 33.2 Ф.7 composition: вызов другой fn в контракте
                    // разрешён ТОЛЬКО если она `#pure`.
                    if self.fn_names.contains(name) && !self.pure_fn_names.contains(name) {
                        errors.push(Diagnostic::new(
                            format!(
                                "calling user function `{}` in contracts requires `#pure` attribute \
                                 (Plan 33.2 composition: only #pure functions allowed)",
                                name
                            ),
                            e.span,
                        ));
                    }
                }
                // Plan 140.2 Part A (D256): self-method call `@method()` в контракте.
                // SMT-encoder поддерживает только встроенные #pure-аксессоры
                // (`@len()`/`@cap()`/`@byte_len()`/`@is_empty()` → `_field_*_int(_self)`);
                // прочие `@method()` (в т.ч. non-pure / mut-receiver) НЕ кодируются —
                // даём внятную ошибку на checker-этапе вместо обобщённого E2401.
                if let ExprKind::Member { obj, name } = &func.kind {
                    if matches!(obj.kind, ExprKind::SelfAccess)
                        && !matches!(name.as_str(), "len" | "cap" | "byte_len" | "is_empty")
                    {
                        errors.push(Diagnostic::new(
                            format!(
                                "self-метод `@{}()` в контракте не поддерживается SMT-encoder'ом \
                                 (Plan 140.2: разрешены только #pure-аксессоры \
                                 `@len()`/`@cap()`/`@byte_len()`/`@is_empty()`); \
                                 ссылайтесь на поле напрямую (`@{}`) или вынесите логику в #pure fn",
                                name, name,
                            ),
                            e.span,
                        ));
                        return;
                    }
                }
                // Walk callee + args.
                self.walk_expr(func, fn_effects, fn_name, errors, in_ensures);
                for a in args {
                    self.walk_expr(a.expr(), fn_effects, fn_name, errors, in_ensures);
                }
            }
            ExprKind::Binary { left, right, .. } => {
                self.walk_expr(left, fn_effects, fn_name, errors, in_ensures);
                self.walk_expr(right, fn_effects, fn_name, errors, in_ensures);
            }
            ExprKind::Unary { operand, .. } => {
                self.walk_expr(operand, fn_effects, fn_name, errors, in_ensures);
            }
            ExprKind::Member { obj, .. } => {
                self.walk_expr(obj, fn_effects, fn_name, errors, in_ensures);
            }
            ExprKind::Index { obj, index } => {
                self.walk_expr(obj, fn_effects, fn_name, errors, in_ensures);
                self.walk_expr(index, fn_effects, fn_name, errors, in_ensures);
            }
            ExprKind::As(inner, _) | ExprKind::Is(inner, _) => {
                self.walk_expr(inner, fn_effects, fn_name, errors, in_ensures);
            }
            ExprKind::Try(inner) | ExprKind::Bang(inner) => {
                self.walk_expr(inner, fn_effects, fn_name, errors, in_ensures);
            }
            ExprKind::Coalesce(l, r) => {
                self.walk_expr(l, fn_effects, fn_name, errors, in_ensures);
                self.walk_expr(r, fn_effects, fn_name, errors, in_ensures);
            }
            // Литералы, paths, и прочее — не интересно для базовых правил.
            _ => {}
        }
    }
}

// ──────────────────────────────────────────────────────────────────────────
// Plan 33.3 Ф.9.7 (D24): ghost-var usage check.
//
// Verus/Dafny semantics: ghost binding (`ghost let x = ...`) — spec-only,
// не emit'ится в runtime. Non-ghost код не может читать ghost-var.
// До этого: catch'илось C-compiler'ом как «undeclared identifier» (ghost
// эрейзится в codegen). Теперь — proper compile-error на type-check этапе
// с понятным сообщением.
//
// Эвристика: walk каждый fn body, в каждом block:
// 1. Собираем `ghost let` имена в scope.
// 2. Walk остальные stmt'ы (non-ghost) и trailing — если ident ссылается
//    на ghost-name → error.
//
// Ограничения bootstrap:
// - Не учитываем `requires`/`ensures` (ghost OK там — но walk их не
//   делаем, и не должны catches as «non-ghost»).
// - Nested blocks: ghost из outer scope виден inner non-ghost — это
//   ошибка (по Verus); ловим через accumulating ghost-set.
// - Pattern bindings: только Ident-pattern (простой случай).
// ──────────────────────────────────────────────────────────────────────────

fn check_ghost_usage(module: &Module, errors: &mut Vec<Diagnostic>) {
    for item in &module.items {
        if let Item::Fn(fd) = item {
            if let FnBody::Block(b) = &fd.body {
                let ghosts: HashSet<String> = HashSet::new();
                check_ghost_in_block(b, &ghosts, errors);
            } else if let FnBody::Expr(e) = &fd.body {
                let ghosts: HashSet<String> = HashSet::new();
                check_ghost_in_expr(e, &ghosts, errors);
            }
        } else if let Item::Test(t) = item {
            let ghosts: HashSet<String> = HashSet::new();
            check_ghost_in_block(&t.body, &ghosts, errors);
        }
    }
}

fn check_ghost_in_block(b: &Block, parent_ghosts: &HashSet<String>, errors: &mut Vec<Diagnostic>) {
    // Local ghost-set начинаем с parent + добавляем ghost-let'ы из этого
    // block'а в порядке появления.
    let mut ghosts = parent_ghosts.clone();
    for stmt in &b.stmts {
        if let Stmt::Let(decl) = stmt {
            if decl.is_ghost {
                // Ghost let value-expr может читать другие ghost-vars
                // — это OK. Не проверяем walk_expr на value.
                if let Pattern::Ident { name, .. } = &decl.pattern {
                    ghosts.insert(name.clone());
                }
                continue;
            }
        }
        // Non-ghost stmt: walk expr и проверяем что не читает ghost.
        check_ghost_in_stmt(stmt, &ghosts, errors);
    }
    if let Some(t) = &b.trailing {
        check_ghost_in_expr(t, &ghosts, errors);
    }
}

fn check_ghost_in_stmt(s: &Stmt, ghosts: &HashSet<String>, errors: &mut Vec<Diagnostic>) {
    match s {
        Stmt::Let(decl) => {
            // Non-ghost let: value не должен использовать ghost-vars.
            check_ghost_in_expr(&decl.value, ghosts, errors);
        }
        // Plan 114.4 Ф.2: scope-local const — pass-through (no-op for now).
        Stmt::Const(_) => {}
        Stmt::Expr(e) => check_ghost_in_expr(e, ghosts, errors),
        Stmt::Assign { target, value, .. } => {
            check_ghost_in_expr(target, ghosts, errors);
            check_ghost_in_expr(value, ghosts, errors);
        }
        Stmt::Return { value: Some(v), .. } => check_ghost_in_expr(v, ghosts, errors),
        Stmt::Throw { value, .. } => check_ghost_in_expr(value, ghosts, errors),
        Stmt::Defer { body, .. } | Stmt::ErrDefer { body, .. }
        | Stmt::OkDefer { body, .. } | Stmt::DeferWithResult { body, .. } => check_ghost_in_expr(body, ghosts, errors),
        // assert_static/assume — это spec-уровень, ghost-vars там OK.
        // Skip walk через них чтобы не выдавать false-positives.
        Stmt::AssertStatic { .. } | Stmt::Assume { .. } => {}
        _ => {}
    }
}

fn check_ghost_in_expr(e: &Expr, ghosts: &HashSet<String>, errors: &mut Vec<Diagnostic>) {
    match &e.kind {
        ExprKind::Ident(n) => {
            if ghosts.contains(n) {
                errors.push(Diagnostic::new(
                    format!(
                        "ghost variable `{}` cannot be read in non-ghost code \
                         (Plan 33.3 Ф.9.1: ghost vars are spec-only, Verus/Dafny semantics). \
                         Move usage into a contract clause (`requires`/`ensures`/`invariant`) \
                         or another `ghost let` binding.",
                        n
                    ),
                    e.span,
                ));
            }
        }
        ExprKind::Binary { left, right, .. } => {
            check_ghost_in_expr(left, ghosts, errors);
            check_ghost_in_expr(right, ghosts, errors);
        }
        ExprKind::Unary { operand, .. } => check_ghost_in_expr(operand, ghosts, errors),
        ExprKind::Member { obj, .. } => check_ghost_in_expr(obj, ghosts, errors),
        ExprKind::Index { obj, index } => {
            check_ghost_in_expr(obj, ghosts, errors);
            check_ghost_in_expr(index, ghosts, errors);
        }
        ExprKind::Call { func, args, .. } => {
            check_ghost_in_expr(func, ghosts, errors);
            for a in args { check_ghost_in_expr(a.expr(), ghosts, errors); }
        }
        ExprKind::If { cond, then, else_ } => {
            check_ghost_in_expr(cond, ghosts, errors);
            check_ghost_in_block(then, ghosts, errors);
            if let Some(eb) = else_ {
                match eb {
                    ElseBranch::Block(b) => check_ghost_in_block(b, ghosts, errors),
                    ElseBranch::If(e) => check_ghost_in_expr(e, ghosts, errors),
                }
            }
        }
        ExprKind::Block(b) => check_ghost_in_block(b, ghosts, errors),
        ExprKind::As(inner, _) | ExprKind::Is(inner, _) | ExprKind::Try(inner) | ExprKind::Bang(inner) => {
            check_ghost_in_expr(inner, ghosts, errors);
        }
        ExprKind::Coalesce(l, r) => {
            check_ghost_in_expr(l, ghosts, errors);
            check_ghost_in_expr(r, ghosts, errors);
        }
        _ => {}
    }
}

// ============================================================================
// Plan 52 Ф.2 (D108): map-литерал `[k: v]` type-checking.
//
// Focused expected-type проход. Type-checker bootstrap'а синтаксический
// (нет полноценного bidirectional inference), поэтому MapLitCtx — это
// отдельный лёгкий walk, который НЕ заменяет существующие walk'и, а
// добавляет проверки литералов в позициях с известным ожидаемым типом:
//   - `let x HashMap[K,V] = [...]` — let-аннотация;
//   - `fn f() -> HashMap[K,V] => [...]` — return-выражение;
//   - `f([...])` где параметр имеет тип `HashMap[K,V]` — argument-позиция
//     (это и есть фундамент Ф.3a).
//
// На каждом `MapLit`:
//   - вывод `HashMap[K, V]` из ключей/значений ИЛИ из ожидаемого типа;
//   - enforce `K: Hashable` (примитивы — авто-OK; именованный тип —
//     нужны методы `hash` + `eq`; неизвестный/generic — permissive);
//   - унификация: все ключи в один `K`, все значения в один `V`.
// Пустой `[]` в позиции, ожидающей `HashMap` — валиден (пустая мапа).
// ============================================================================

/// Plan 52 Ф.2/Ф.3: контекст для map-литерал type-checking.
struct MapLitCtx {
    /// Для каждого concrete-типа — множество имён его методов. Нужно для
    /// Hashable-проверки именованных ключевых типов (требуются `hash` + `eq`).
    type_methods: HashMap<String, HashSet<String>>,
    /// Имена top-level типов модуля (record/sum/newtype/alias) — для
    /// различения «известный именованный тип» vs «generic-параметр».
    known_types: HashSet<String>,
    /// Plan 52 Ф.3: имена типов, помеченных `#from_fields` — str-keyed
    /// map-типы, в которые анонимный record-литерал `{field: v}` коэрсится
    /// через D55 map-coercion. Bootstrap honored только для
    /// `collections.hashmap.HashMap` (проверка canonical identity ниже).
    from_fields_types: HashSet<String>,
    /// Plan 52 Ф.3a: free-fn name → `(имя, тип)` параметров (только если у
    /// имени **один** кандидат — без overload; иначе резолв неоднозначен и
    /// пропускается). Для D55 argument-position coercion.
    fn_param_types: HashMap<String, Vec<(String, TypeRef)>>,
    /// Plan 52 Ф.3a: `Type.method` → `(имя, тип)` параметров (static +
    /// instance методы; только уникальные по имени, без overload).
    method_param_types: HashMap<String, Vec<(String, TypeRef)>>,
    /// Plan 52 Ф.3a: имя метода → `(имя, тип)` параметров, если метод с этим
    /// именем существует ровно на **одном** типе без overload (для резолва
    /// instance-call `obj.method(...)` без type-inference receiver'а).
    unique_method_param_types: HashMap<String, Vec<(String, TypeRef)>>,
    /// Имена generic-параметров, видимых в текущей функции. Заполняется
    /// per-fn в `check_fn`. Generic `K` — permissive (Hashable не enforce'ится
    /// статически: bound-проверка — отдельный механизм Plan 15).
    fn_generics: HashSet<String>,
    /// Plan 52 Ф.23: типы помеченные `#from_pairs` — target для desugar'а
    /// `[k: v]` (canonical-identity check, как для from_fields).
    from_pairs_types: HashSet<String>,
}

impl MapLitCtx {
    fn build(module: &Module) -> Self {
        let mut type_methods: HashMap<String, HashSet<String>> = HashMap::new();
        let mut known_types: HashSet<String> = HashSet::new();
        let mut from_fields_types: HashSet<String> = HashSet::new();
        // Plan 52 Ф.3a: сначала собираем все overload-группы, потом
        // оставляем только уникальные (single-candidate) для резолва
        // argument-позиций — overload без type-inference резолвить нельзя.
        let mut fn_overloads: HashMap<String, Vec<&FnDecl>> = HashMap::new();
        let mut method_overloads: HashMap<String, Vec<&FnDecl>> = HashMap::new();
        // имя метода → множество (type_name) на которых он определён.
        let mut method_owner_count: HashMap<String, Vec<&FnDecl>> = HashMap::new();
        // Plan 52 Ф.19: canonical identity для `#from_fields`. Через
        // peer_files определяем какой peer-файл объявил TypeDecl с
        // маркером — если path содержит сегмент `collections/hashmap` или
        // `std/collections/hashmap`, это canonical stdlib HashMap.
        // Иначе — user-локальный type с #from_fields → не trust'им.
        //
        // Bootstrap-policy: `#from_fields` honored ТОЛЬКО для типов в
        // canonical stdlib pаth. User-локальные типы с attribute получают
        // warning (через lints, не здесь) — bootstrap не дает им
        // map-coercion для безопасности. После Ф.23 (FromPairs protocol)
        // user-типы получают расширяемость через протоколы.
        let is_canonical_stdlib_from_fields = |type_name: &str, items: &[Item]| -> bool {
            items.iter().any(|it| matches!(it, Item::Type(t)
                if t.name == type_name && t.attrs.contains(&TypeAttr::FromFields)))
        };
        let mut canonical_from_fields_types: HashSet<String> = HashSet::new();
        let mut canonical_from_pairs_types: HashSet<String> = HashSet::new();
        for pf in &module.peer_files {
            let path_str = pf.path.to_string_lossy().replace('\\', "/").to_lowercase();
            // Canonical stdlib markers — собираем имена типов с
            // #from_fields / #from_pairs из peer-файлов в std/collections/.
            let is_stdlib = path_str.contains("/std/collections/")
                || path_str.contains("std\\collections\\");
            if is_stdlib {
                for it in &pf.items_here {
                    if let Item::Type(t) = it {
                        if t.attrs.contains(&TypeAttr::FromFields) {
                            canonical_from_fields_types.insert(t.name.clone());
                        }
                        if t.attrs.contains(&TypeAttr::FromPairs) {
                            canonical_from_pairs_types.insert(t.name.clone());
                        }
                    }
                }
            }
        }
        // Fallback для single-file/legacy (нет peer_files info): принимаем
        // attribute как раньше (bare-name). Это safety net для тестов где
        // peer_files пуст; в реальной компиляции stdlib HashMap всегда
        // приходит через folder-module → попадает в canonical set.
        let use_canonical = !canonical_from_fields_types.is_empty()
            || !canonical_from_pairs_types.is_empty();
        let _ = is_canonical_stdlib_from_fields; // подавить warning о неиспользовании
        let mut from_pairs_types: HashSet<String> = HashSet::new();

        // Plan 52.1 Ф.4: pre-pass для собирания всех methods (нужно для
        // method-validation user-типов с #from_pairs ниже). Без pre-pass
        // type'ы обрабатываются до своих fn-методов → method-check
        // упирается в пустой type_methods.
        let mut prepass_type_methods: HashMap<String, HashSet<String>> = HashMap::new();
        for item in &module.items {
            if let Item::Fn(f) = item {
                if let Some(recv) = &f.receiver {
                    prepass_type_methods
                        .entry(recv.type_name.clone())
                        .or_default()
                        .insert(f.name.clone());
                }
            }
        }

        for item in &module.items {
            match item {
                Item::Type(t) => {
                    known_types.insert(t.name.clone());
                    // Plan 52 Ф.19: canonical-identity check. Если у нас
                    // есть peer_files info — добавляем только canonical
                    // stdlib типы. User-локальный `type HashMap #from_fields`
                    // не попадёт в set → map-coercion для него не сработает.
                    if t.attrs.contains(&TypeAttr::FromFields) {
                        if !use_canonical || canonical_from_fields_types.contains(&t.name) {
                            from_fields_types.insert(t.name.clone());
                        }
                    }
                    // Plan 52.1 Ф.4: from_pairs canonical-check с
                    // method-validation. User-локальный `type #from_pairs`
                    // honored ЕСЛИ имеет требуемые методы
                    // (`with_capacity(int) -> Self` и `insert_new(K, V)`).
                    // Это безопасно: codegen эмитит вызовы этих методов,
                    // и они существуют.
                    //
                    // Без validation user мог бы получить codegen-fail
                    // ('no method with_capacity' / 'no method insert_new')
                    // — confusing. Validation даёт actionable error
                    // через type-check ('type X #from_pairs but missing
                    // with_capacity method').
                    if t.attrs.contains(&TypeAttr::FromPairs) {
                        let is_canonical = canonical_from_pairs_types.contains(&t.name);
                        let is_user = !is_canonical;
                        if is_canonical {
                            from_pairs_types.insert(t.name.clone());
                        } else if is_user {
                            // User-локальный тип — проверяем методы через
                            // prepass_type_methods (собран до этого цикла,
                            // т.к. types и fns могут идти в любом порядке).
                            let methods = prepass_type_methods.get(&t.name);
                            let has_with_capacity = methods
                                .map_or(false, |m| m.contains("with_capacity"));
                            let has_insert_new = methods
                                .map_or(false, |m| m.contains("insert_new"));
                            if has_with_capacity && has_insert_new {
                                from_pairs_types.insert(t.name.clone());
                            }
                            // Если методов нет — silently ignore. Better-error
                            // diagnostic — отдельная фаза (требует mutable
                            // errors vec в build, что нарушает текущую сигнатуру).
                            // Без validation user получит CC-error при использовании.
                        }
                    }
                }
                Item::Fn(f) => {
                    if let Some(recv) = &f.receiver {
                        type_methods
                            .entry(recv.type_name.clone())
                            .or_default()
                            .insert(f.name.clone());
                        let key = format!("{}.{}", recv.type_name, f.name);
                        method_overloads.entry(key).or_default().push(f);
                        method_owner_count.entry(f.name.clone()).or_default().push(f);
                    } else {
                        fn_overloads.entry(f.name.clone()).or_default().push(f);
                    }
                }
                _ => {}
            }
        }
        // Оставляем только single-candidate (без overload) — иначе резолв
        // по имени неоднозначен и argument-позиция не получает expected.
        let extract_params = |fns: &[&FnDecl]| -> Option<Vec<(String, TypeRef)>> {
            match fns {
                [single] => Some(
                    single
                        .params
                        .iter()
                        .map(|p| (p.name.clone(), p.ty.clone()))
                        .collect(),
                ),
                _ => None,
            }
        };
        let fn_param_types: HashMap<String, Vec<(String, TypeRef)>> = fn_overloads
            .iter()
            .filter_map(|(k, v)| extract_params(v).map(|p| (k.clone(), p)))
            .collect();
        let method_param_types: HashMap<String, Vec<(String, TypeRef)>> = method_overloads
            .iter()
            .filter_map(|(k, v)| extract_params(v).map(|p| (k.clone(), p)))
            .collect();
        let unique_method_param_types: HashMap<String, Vec<(String, TypeRef)>> =
            method_owner_count
                .iter()
                .filter_map(|(k, v)| extract_params(v).map(|p| (k.clone(), p)))
                .collect();
        MapLitCtx {
            type_methods,
            known_types,
            from_fields_types,
            fn_param_types,
            method_param_types,
            unique_method_param_types,
            fn_generics: HashSet::new(),
            from_pairs_types,
        }
    }

    fn check_module(&self, module: &Module, errors: &mut Vec<Diagnostic>) {
        for item in &module.items {
            match item {
                Item::Fn(f) => {
                    // Generic-параметры функции — permissive scope для Hashable.
                    let mut ctx = MapLitCtx {
                        type_methods: self.type_methods.clone(),
                        known_types: self.known_types.clone(),
                        from_fields_types: self.from_fields_types.clone(),
                        fn_param_types: self.fn_param_types.clone(),
                        method_param_types: self.method_param_types.clone(),
                        unique_method_param_types: self.unique_method_param_types.clone(),
                        fn_generics: f.generics.iter().map(|g| g.name.clone()).collect(),
                        from_pairs_types: self.from_pairs_types.clone(),
                    };
                    // Generic-параметры receiver-типа тоже видимы.
                    if let Some(recv) = &f.receiver {
                        for g in &recv.generics {
                            if let TypeRef::Named { path, .. } = g {
                                if path.len() == 1 {
                                    ctx.fn_generics.insert(path[0].clone());
                                }
                            }
                        }
                    }
                    match &f.body {
                        FnBody::Expr(e) => {
                            ctx.walk_expr(e, f.return_type.as_ref(), errors);
                        }
                        FnBody::Block(b) => ctx.walk_block(b, errors),
                        FnBody::External => {}
                    }
                }
                Item::Test(t) => {
                    self.walk_block(&t.body, errors);
                }
                // Plan 57: bench — map-литералы могут встречаться в любом из
                // трёх разделов; обходим setup/measure/teardown.
                Item::Bench(b) => {
                    for s in &b.setup {
                        self.walk_stmt(s, errors);
                    }
                    self.walk_block(&b.measure_body, errors);
                    for s in &b.teardown {
                        self.walk_stmt(s, errors);
                    }
                }
                Item::Const(c) => {
                    self.walk_expr(&c.value, c.ty.as_ref(), errors);
                }
                Item::Let(l) => {
                    self.walk_expr(&l.value, l.ty.as_ref(), errors);
                }
                Item::Type(_) => {}
                // Plan 33.3 Ф.13: lemma — spec-only, эрейзится в codegen.
                Item::Lemma(_) => {}
            }
        }
    }

    fn walk_block(&self, b: &Block, errors: &mut Vec<Diagnostic>) {
        for s in &b.stmts {
            self.walk_stmt(s, errors);
        }
        if let Some(t) = &b.trailing {
            // Trailing-выражение блока не имеет известного ожидаемого
            // типа без контекста — walk без expected.
            self.walk_expr(t, None, errors);
        }
    }

    fn walk_stmt(&self, s: &Stmt, errors: &mut Vec<Diagnostic>) {
        match s {
            Stmt::Expr(e) => self.walk_expr(e, None, errors),
            Stmt::Let(d) => {
                // let-аннотация — known-target-type position (D55).
                self.walk_expr(&d.value, d.ty.as_ref(), errors);
            }
            // Plan 114.4 Ф.2: scope-local const — pass-through (no-op for now).
            Stmt::Const(_) => {}
            Stmt::Assign { target, value, .. } => {
                self.walk_expr(target, None, errors);
                self.walk_expr(value, None, errors);
            }
            Stmt::Return { value, .. } => {
                // Return-выражение — known-target-type, но return_type здесь
                // недоступен (walk_block не несёт его). Walk без expected;
                // FnBody::Expr-возврат покрыт в check_module отдельно.
                if let Some(v) = value {
                    self.walk_expr(v, None, errors);
                }
            }
            Stmt::Throw { value, .. } => self.walk_expr(value, None, errors),
            Stmt::Break(_) | Stmt::Continue(_) => {}
            Stmt::Defer { body, .. } | Stmt::ErrDefer { body, .. }
            | Stmt::OkDefer { body, .. } | Stmt::DeferWithResult { body, .. } => {
                self.walk_expr(body, None, errors);
            }
            // Plan 110 D188: walk init + body block recursively.
            Stmt::ConsumeScope { init, body, .. } => {
                self.walk_expr(init, None, errors);
                for stmt in &body.stmts {
                    self.walk_stmt(stmt, errors);
                }
                if let Some(t) = &body.trailing {
                    self.walk_expr(t, None, errors);
                }
            }
            Stmt::AssertStatic { expr, .. } | Stmt::Assume { expr, .. } => {
                self.walk_expr(expr, None, errors);
            }
            // Plan 33.3 Ф.13: Apply/Calc — proof-statements, spec-only.
            Stmt::Apply { .. } | Stmt::Calc { .. } | Stmt::Reveal { .. } => {}
            // Plan 136: tuple destructuring assignment.
            Stmt::TupleAssign { lhs, rhs, .. } => {
                for e in lhs { self.walk_expr(e, None, errors); }
                for e in rhs { self.walk_expr(e, None, errors); }
            }
        }
    }

    /// Обход выражения с опциональным ожидаемым типом. На `MapLit` —
    /// запускает проверку; рекурсивно спускается во все под-выражения,
    /// протаскивая expected туда, где он известен (let / arg-позиции).
    fn walk_expr(&self, e: &Expr, expected: Option<&TypeRef>, errors: &mut Vec<Diagnostic>) {
        match &e.kind {
            ExprKind::MapLit { elems, .. } => {
                let pairs = crate::ast::MapElem::cloned_pairs(&elems);
                self.check_map_lit(e, &pairs, expected, errors);
                // Рекурсия в ключи/значения — без expected (key/value
                // expected-types выводятся внутри check_map_lit; для
                // вложенных литералов глубокий проход — будущее расширение).
                for (k, v) in pairs.iter() {
                    self.walk_expr(k, None, errors);
                    self.walk_expr(v, None, errors);
                }
                // Plan 55 followup: рекурсия в spread expressions.
                for me in elems.iter() {
                    if let crate::ast::MapElem::Spread(se) = me {
                        self.walk_expr(se, expected, errors);
                    }
                }
            }
            ExprKind::ArrayLit(elems) => {
                for el in elems {
                    match el {
                        ArrayElem::Item(x) | ArrayElem::Spread(x) => {
                            self.walk_expr(x, None, errors);
                        }
                    }
                }
            }
            ExprKind::Call { func, args, trailing } => {
                self.walk_expr(func, None, errors);
                // Plan 52 Ф.3a: D55 argument-position coercion. Если callee
                // резолвится в единственного кандидата — протаскиваем тип
                // соответствующего параметра как expected в каждый аргумент.
                // Positional args связываются по индексу, named (D102) — по
                // имени параметра. Это разблокирует `f({...})` / `f([k:v])`
                // / `f(opts: {...})`.
                let params = self.resolve_call_params(func);
                let mut positional_idx = 0usize;
                for a in args.iter() {
                    let arg_expected: Option<&TypeRef> = match (&params, a.arg_name()) {
                        (Some(ps), Some(name)) => {
                            // Named-arg: ищем параметр по имени.
                            ps.iter().find(|(pn, _)| pn == name).map(|(_, t)| t)
                        }
                        (Some(ps), None) => {
                            // Positional-arg: по текущему индексу.
                            let r = ps.get(positional_idx).map(|(_, t)| t);
                            positional_idx += 1;
                            r
                        }
                        (None, _) => None,
                    };
                    self.walk_expr(a.expr(), arg_expected, errors);
                }
                if let Some(t) = trailing {
                    match t {
                        crate::ast::Trailing::Block(b) => self.walk_block(b, errors),
                        crate::ast::Trailing::LegacyBlockWithParams(tb) => {
                            self.walk_block(&tb.body, errors)
                        }
                        crate::ast::Trailing::Fn(sb) => match &sb.body {
                            FnBody::Expr(x) => self.walk_expr(x, None, errors),
                            FnBody::Block(b) => self.walk_block(b, errors),
                            FnBody::External => {}
                        },
                    }
                }
            }
            ExprKind::TurboFish { base, .. } => self.walk_expr(base, expected, errors),
            ExprKind::Try(x) | ExprKind::Bang(x) => self.walk_expr(x, None, errors),
            ExprKind::Coalesce(a, b) => {
                self.walk_expr(a, None, errors);
                self.walk_expr(b, None, errors);
            }
            ExprKind::As(x, _) | ExprKind::Is(x, _) => self.walk_expr(x, None, errors),
            ExprKind::Binary { left, right, .. } => {
                self.walk_expr(left, None, errors);
                self.walk_expr(right, None, errors);
            }
            ExprKind::Unary { operand, .. } => self.walk_expr(operand, None, errors),
            ExprKind::Member { obj, .. } => self.walk_expr(obj, None, errors),
            ExprKind::Index { obj, index } => {
                self.walk_expr(obj, None, errors);
                self.walk_expr(index, None, errors);
            }
            ExprKind::TupleLit(elems) => {
                for x in elems { self.walk_expr(x, None, errors); }
            }
            ExprKind::RecordLit { type_name, fields, .. } => {
                // Plan 52 Ф.3: D55 map-coercion. Анонимный record-литерал
                // `{field: v}` в позиции, ожидающей тип с маркером
                // `#from_fields` (= HashMap) — это НЕ record-coercion (поля
                // литерала ≠ поля struct'а HashMap), а map-coercion: имена
                // полей становятся строковыми ключами.
                if type_name.is_none() {
                    if let Some(exp) = expected {
                        if self.expected_is_from_fields(exp) {
                            self.check_record_map_coercion(e, fields, exp, errors);
                            // Значения уже проверены внутри; рекурсия в них.
                            for f in fields {
                                if let Some(v) = &f.value {
                                    self.walk_expr(v, None, errors);
                                }
                            }
                            return;
                        }
                    }
                }
                for f in fields {
                    if let Some(v) = &f.value { self.walk_expr(v, None, errors); }
                }
            }
            ExprKind::If { cond, then, else_ } => {
                self.walk_expr(cond, None, errors);
                self.walk_block(then, errors);
                if let Some(eb) = else_ {
                    match eb {
                        ElseBranch::Block(b) => self.walk_block(b, errors),
                        ElseBranch::If(x) => self.walk_expr(x, None, errors),
                    }
                }
            }
            ExprKind::IfLet { scrutinee, then, else_, .. } => {
                self.walk_expr(scrutinee, None, errors);
                self.walk_block(then, errors);
                if let Some(eb) = else_ {
                    match eb {
                        ElseBranch::Block(b) => self.walk_block(b, errors),
                        ElseBranch::If(x) => self.walk_expr(x, None, errors),
                    }
                }
            }
            ExprKind::Match { scrutinee, arms } => {
                self.walk_expr(scrutinee, None, errors);
                for arm in arms {
                    if let Some(g) = &arm.guard { self.walk_expr(g, None, errors); }
                    match &arm.body {
                        MatchArmBody::Expr(x) => self.walk_expr(x, None, errors),
                        MatchArmBody::Block(b) => self.walk_block(b, errors),
                    }
                }
            }
            ExprKind::For { iter, body, .. } | ExprKind::ParallelFor { iter, body, .. } => {
                self.walk_expr(iter, None, errors);
                self.walk_block(body, errors);
            }
            ExprKind::While { cond, body, .. } => {
                self.walk_expr(cond, None, errors);
                self.walk_block(body, errors);
            }
            ExprKind::WhileLet { scrutinee, body, .. } => {
                self.walk_expr(scrutinee, None, errors);
                self.walk_block(body, errors);
            }
            ExprKind::Loop { body, .. } => self.walk_block(body, errors),
            ExprKind::Block(b) => self.walk_block(b, errors),
            ExprKind::Spawn(x) => self.walk_expr(x, None, errors),
            ExprKind::Detach(b) | ExprKind::Blocking(b) => self.walk_block(b, errors),
            ExprKind::Supervised { body, cancel } => {
                self.walk_block(body, errors);
                if let Some(c) = cancel { self.walk_expr(c, None, errors); }
            }
            ExprKind::Forbid { body, .. } | ExprKind::Realtime { body, .. } => {
                self.walk_block(body, errors);
            }
            ExprKind::Throw(x) => self.walk_expr(x, None, errors),
            ExprKind::Interrupt(opt) => {
                if let Some(x) = opt { self.walk_expr(x, None, errors); }
            }
            ExprKind::Range { start, end, .. } => {
                if let Some(s) = start { self.walk_expr(s, None, errors); }
                if let Some(e) = end { self.walk_expr(e, None, errors); }
            }
            ExprKind::InterpolatedStr { parts } => {
                for p in parts {
                    if let crate::ast::InterpStrPart::Expr { expr: x, spec: _ } = p {
                        self.walk_expr(x, None, errors);
                    }
                }
            }
            ExprKind::TaggedTemplate { args, .. } => {
                for x in args { self.walk_expr(x, None, errors); }
            }
            ExprKind::Lambda { body, .. } => self.walk_expr(body, None, errors),
            ExprKind::ClosureLight { body, .. } => match body {
                ClosureBody::Expr(x) => self.walk_expr(x, None, errors),
                ClosureBody::Block(b) => self.walk_block(b, errors),
            },
            ExprKind::ClosureFull(sb) => match &sb.body {
                FnBody::Expr(x) => self.walk_expr(x, None, errors),
                FnBody::Block(b) => self.walk_block(b, errors),
                FnBody::External => {}
            },
            ExprKind::With { bindings, body } => {
                for b in bindings { self.walk_expr(&b.handler, None, errors); }
                self.walk_block(body, errors);
            }
            // Plan 97 Ф.4 (D142): protocol-литерал — walk идентичен.
            ExprKind::HandlerLit { methods, .. } | ExprKind::ProtocolLit { methods, .. } => {
                for m in methods {
                    match &m.body {
                        HandlerMethodBody::Expr(x) => self.walk_expr(x, None, errors),
                        HandlerMethodBody::Block(b) => self.walk_block(b, errors),
                    }
                }
            }
            ExprKind::Select { arms } => {
                for arm in arms {
                    match &arm.op {
                        crate::ast::SelectOp::Recv { chan, .. } => {
                            self.walk_expr(chan, None, errors)
                        }
                        crate::ast::SelectOp::Send { chan, value } => {
                            self.walk_expr(chan, None, errors);
                            self.walk_expr(value, None, errors);
                        }
                        crate::ast::SelectOp::Default => {}
                    }
                    if let Some(g) = &arm.guard { self.walk_expr(g, None, errors); }
                    self.walk_block(&arm.body, errors);
                }
            }
            // Plan 33.3 Ф.13: Forall/Exists — spec quantifiers.
            ExprKind::Forall { body, .. } | ExprKind::Exists { body, .. } => {
                self.walk_expr(body, None, errors);
            }
            // Листовые.
            ExprKind::Ident(_) | ExprKind::Path(_) | ExprKind::SelfAccess
            | ExprKind::IntLit(_) | ExprKind::FloatLit(_) | ExprKind::BoolLit(_)
            | ExprKind::StrLit(_) | ExprKind::CharLit(_) | ExprKind::UnitLit
            | ExprKind::NullPtrLit => {}
        }
    }

    /// Plan 52 Ф.3a: резолвит callee `func`-выражение в список `(имя, тип)`
    /// параметров для D55 argument-position coercion.
    ///
    /// Поддерживает (bootstrap, только single-candidate без overload):
    ///   - `f(...)` — free-fn по имени;
    ///   - `Type.method(...)` — static-method / конструктор;
    ///   - `obj.method(...)` — instance-method, если имя метода уникально
    ///     (определено ровно на одном типе) — без type-inference receiver'а.
    ///
    /// Возвращает `None` если резолв неоднозначен (overload, неизвестное
    /// имя, сложный callee) — тогда argument-позиции не получают expected
    /// (graceful fallback: coercion-проверки просто не запускаются).
    fn resolve_call_params(&self, func: &Expr) -> Option<Vec<(String, TypeRef)>> {
        // Распаковываем turbofish до базового func-expr.
        let base: &Expr = match &func.kind {
            ExprKind::TurboFish { base, .. } => base,
            _ => func,
        };
        match &base.kind {
            ExprKind::Ident(name) => self.fn_param_types.get(name).cloned(),
            ExprKind::Path(parts) if parts.len() == 2 => {
                // `Type.method` — static-call / конструктор.
                let key = format!("{}.{}", parts[0], parts[1]);
                self.method_param_types.get(&key).cloned()
            }
            ExprKind::Member { name: method_name, .. } => {
                // `obj.method` — instance-call. Резолвим по уникальному
                // имени метода (определён ровно на одном типе без overload).
                self.unique_method_param_types.get(method_name).cloned()
            }
            _ => None,
        }
    }

    /// Plan 52 Ф.2: проверка map-литерала `[k: v]`.
    fn check_map_lit(
        &self,
        e: &Expr,
        pairs: &[(Expr, Expr)],
        expected: Option<&TypeRef>,
        errors: &mut Vec<Diagnostic>,
    ) {
        // Извлечь K, V из ожидаемого типа.
        // Plan 52.1 Ф.4: Принимаем `HashMap[K, V]` (legacy hardcode) ИЛИ
        // любой тип помеченный `#from_pairs` (Ф.23 + Ф.4 user-types
        // через method-validation в MapLitCtx::build).
        let (exp_k, exp_v) = match expected {
            Some(TypeRef::Named { path, generics, .. })
                if (path.last().map(|s| s.as_str()) == Some("HashMap")
                    || self.expected_is_from_pairs(expected.unwrap()))
                    && generics.len() == 2 =>
            {
                (Some(&generics[0]), Some(&generics[1]))
            }
            // Ожидаемый тип задан, но это не HashMap и не #from_pairs тип —
            // литерал `[k:v]` не может быть coerce'нут.
            Some(other) if !is_unknown_type(other) => {
                errors.push(Diagnostic::new(
                    format!(
                        "map literal `[k: v]` requires a `HashMap` or \
                         `#from_pairs`-marked type, but the expected type \
                         here is `{}`",
                        typeref_render(other)
                    ),
                    e.span,
                ));
                return;
            }
            _ => (None, None),
        };

        // Вывод типа ключей: унификация всех ключевых выражений.
        let key_ty = self.unify_exprs(
            pairs.iter().map(|(k, _)| k),
            exp_k,
            "key",
            e.span,
            errors,
        );
        // Вывод типа значений: унификация всех value-выражений.
        let _val_ty = self.unify_exprs(
            pairs.iter().map(|(_, v)| v),
            exp_v,
            "value",
            e.span,
            errors,
        );

        // Enforce `K: Hashable`.
        if let Some(k) = &key_ty {
            self.check_hashable(k, e.span, errors);
        }
    }

    /// Plan 52 Ф.3 / Ф.19: `true` если ожидаемый тип несёт маркер
    /// `#from_fields` (str-keyed map-тип для D55 map-coercion).
    ///
    /// `from_fields_types` собран в `MapLitCtx::build` через peer_files
    /// canonical-identity check (Ф.19) — туда попадают только типы из
    /// `std/collections/` peer-файлов. User-локальный `type HashMap
    /// #from_fields` НЕ попадает в set даже при совпадении имени со
    /// stdlib HashMap. Это закрывает M-52-from-fields-canonical.
    fn expected_is_from_fields(&self, expected: &TypeRef) -> bool {
        let TypeRef::Named { path, .. } = expected else { return false; };
        match path.last() {
            Some(name) => self.from_fields_types.contains(name),
            None => false,
        }
    }

    /// Plan 52 Ф.23: `true` если ожидаемый тип несёт маркер `#from_pairs`
    /// (target для desugar'а `[k: v]`). User-типы получают support
    /// литерала добавив attribute + with_capacity/insert_new методы.
    fn expected_is_from_pairs(&self, expected: &TypeRef) -> bool {
        let TypeRef::Named { path, .. } = expected else { return false; };
        match path.last() {
            Some(name) => self.from_pairs_types.contains(name),
            None => false,
        }
    }

    /// Plan 52 Ф.3: проверка D55 map-coercion анонимного record-литерала
    /// `{field: v}` в позиции, ожидающей `#from_fields`-тип (`HashMap[str, V]`).
    ///
    /// Имена полей литерала → строковые ключи (тип `str`, тривиально
    /// Hashable). Все значения полей унифицируются в `V`. Field-punning
    /// (`{debug, verbose}`) поддержан — значение это одноимённая переменная,
    /// тип которой здесь не проверяется (NameResCtx ловит undefined).
    fn check_record_map_coercion(
        &self,
        e: &Expr,
        fields: &[RecordLitField],
        expected: &TypeRef,
        errors: &mut Vec<Diagnostic>,
    ) {
        // Извлечь V из ожидаемого `HashMap[str, V]`.
        let exp_v = match expected {
            TypeRef::Named { path, generics, .. }
                if path.last().map(|s| s.as_str()) == Some("HashMap")
                    && generics.len() == 2 =>
            {
                // Ключ map-coercion всегда str — проверим, что ожидаемый
                // K-параметр это действительно str (или any/generic).
                if let TypeRef::Named { path: kpath, .. } = &generics[0] {
                    if kpath.len() == 1
                        && kpath[0] != "str"
                        && kpath[0] != "any"
                        && !self.fn_generics.contains(&kpath[0])
                    {
                        errors.push(Diagnostic::new(
                            format!(
                                "record-literal map-coercion `{{field: v}}` produces \
                                 string keys, but the expected map key type is `{}` \
                                 — use a map literal `[\"field\": v]` for non-string \
                                 keys, or annotate `HashMap[str, V]`",
                                typeref_render(&generics[0])
                            ),
                            e.span,
                        ));
                        return;
                    }
                }
                Some(&generics[1])
            }
            // `#from_fields`-тип без 2 generic-параметров — permissive
            // (bootstrap honored только HashMap[K,V]; иные формы — будущее).
            _ => None,
        };

        // Спред в map-coerced record-литерале — не поддержан в bootstrap
        // (D60-spread для мап — отдельная фича).
        for f in fields {
            if f.is_spread {
                errors.push(Diagnostic::new(
                    "spread `...` in a map-coercion record literal is not \
                     supported in bootstrap — insert entries explicitly",
                    f.span,
                ));
                return;
            }
        }

        // Унифицировать типы значений полей в `V`. Field-punning
        // (`value: None`) — значение это переменная `f.name`, тип не
        // выводим локально (None из simple_expr_type) → permissive.
        let value_exprs: Vec<&Expr> = fields
            .iter()
            .filter_map(|f| f.value.as_ref())
            .collect();
        let _ = self.unify_exprs(
            value_exprs.into_iter(),
            exp_v,
            "value",
            e.span,
            errors,
        );
        // Ключи — строковые имена полей, str тривиально Hashable: проверка
        // не нужна.
    }

    /// Унифицирует типы набора выражений. Если задан `expected` — все
    /// выражения сверяются с ним; иначе тип выводится best-effort из
    /// первого выражения с известным типом и остальные сверяются с ним.
    /// `role` — "key" / "value" для текста ошибки. Возвращает выведенный
    /// тип (или `expected`), если он определён.
    fn unify_exprs<'e>(
        &self,
        exprs: impl Iterator<Item = &'e Expr>,
        expected: Option<&TypeRef>,
        role: &str,
        lit_span: Span,
        errors: &mut Vec<Diagnostic>,
    ) -> Option<TypeRef> {
        let mut inferred: Option<TypeRef> = expected.cloned();
        for ex in exprs {
            let this_ty = simple_expr_type(ex);
            let Some(this) = this_ty else { continue };
            match &inferred {
                None => inferred = Some(this),
                Some(prev) => {
                    if !simple_types_compatible(prev, &this) {
                        let hint = if role == "value" {
                            " — возможно нужен общий тип, напр. `HashMap[K, JsonValue]`?"
                        } else {
                            ""
                        };
                        errors.push(Diagnostic::new(
                            format!(
                                "map literal {}s have incompatible types `{}` and `{}`{}",
                                role,
                                typeref_render(prev),
                                typeref_render(&this),
                                hint
                            ),
                            ex.span,
                        ));
                        // Один error на role — дальше не плодим.
                        return inferred;
                    }
                }
            }
        }
        let _ = lit_span;
        inferred
    }

    /// Enforce `K: Hashable` для ключевого типа map-литерала.
    ///
    /// Bootstrap-семантика (best-effort, консистентно с `check_satisfaction`):
    ///   - примитивы (`str`/`int`/`bool`/`char`/числовые) — авто-Hashable;
    ///   - generic-параметр текущей функции — permissive (статический
    ///     bound-check — отдельный механизм Plan 15, здесь не дублируем);
    ///   - известный именованный тип — требует методы `hash` и `eq`;
    ///   - неизвестный тип / составной — permissive (не ругаемся).
    fn check_hashable(&self, k: &TypeRef, span: Span, errors: &mut Vec<Diagnostic>) {
        let TypeRef::Named { path, .. } = k else {
            // Array / Tuple / Func как ключ — permissive в bootstrap.
            return;
        };
        if path.len() != 1 {
            return; // module-qualified — permissive
        }
        let name = &path[0];
        // Примитивы — авто-Hashable.
        if matches!(
            name.as_str(),
            "int" | "i8" | "i16" | "i32" | "i64"
                | "u8" | "u16" | "u32" | "u64"
                | "f32" | "f64" | "bool" | "char" | "str"
                // Plan 76: `never` — bottom-тип (uninhabited), vacuously primitive.
                | "never"
        ) {
            return;
        }
        // Generic-параметр функции — permissive (bound-check — Plan 15).
        if self.fn_generics.contains(name) {
            return;
        }
        // Известный именованный тип — требует `hash` + `equal` (D237 Equal protocol).
        if self.known_types.contains(name) {
            let methods = self.type_methods.get(name);
            let has_hash = methods.map(|m| m.contains("hash")).unwrap_or(false);
            // Plan 91.8b: @eq removed; Equal protocol uses @equal.
            let has_eq = methods.map(|m| m.contains("equal")).unwrap_or(false);
            if !has_hash || !has_eq {
                let mut missing = Vec::new();
                if !has_hash { missing.push("`hash() -> u64`"); }
                if !has_eq { missing.push("`equal(other Self) -> bool`"); }
                errors.push(Diagnostic::new(
                    format!(
                        "key type `{}` does not implement `Hashable` — a map key \
                         type must provide {}. Add the missing method(s) to `{}` \
                         or use a primitive key type.",
                        name,
                        missing.join(" and "),
                        name
                    ),
                    span,
                ));
            }
            return;
        }
        // Неизвестное имя — permissive (не наша забота: NameResCtx поймает
        // действительно undefined типы).
    }
}

/// Plan 52 Ф.2: `true` если тип — `any` или иной «неизвестный» маркер,
/// для которого coercion-проверки пропускаются (permissive).
fn is_unknown_type(t: &TypeRef) -> bool {
    matches!(t, TypeRef::Named { path, .. } if path.len() == 1 && path[0] == "any")
}

/// Plan 52 Ф.2: рендер TypeRef в человекочитаемую строку для диагностик.
fn typeref_render(t: &TypeRef) -> String {
    match t {
        TypeRef::Named { path, generics, .. } => {
            let base = path.join(".");
            if generics.is_empty() {
                base
            } else {
                let inner: Vec<String> = generics.iter().map(typeref_render).collect();
                format!("{}[{}]", base, inner.join(", "))
            }
        }
        TypeRef::Array(inner, _) => format!("[]{}", typeref_render(inner)),
        TypeRef::FixedArray(n, inner, _) => format!("[{}]{}", n, typeref_render(inner)),
        TypeRef::Tuple(elems, _) => {
            let inner: Vec<String> = elems.iter().map(typeref_render).collect();
            format!("({})", inner.join(", "))
        }
        TypeRef::Unit(_) => "()".to_string(),
        TypeRef::Func { .. } => "fn(...)".to_string(),
        // Plan 97 Ф.2 (D142): анонимный protocol-тип. В Plan 52
        // coercion-диагностиках достаточно компактного маркера;
        // полный pretty-print — в `typeref_display`.
        TypeRef::Protocol { methods, .. } => format!("protocol {{...{} sigs}}", methods.len()),
        // D176 (Plan 108): readonly T — display as "readonly T"
        TypeRef::Readonly(inner, _) => format!("ro {}", typeref_render(inner)),
        // Plan 118 D216 §1 / Plan 118.5 V2 (2026-06-04): typed pointer
        // `*T` family — split into three AST wrapper arms after V2 amend.
        //   - Pointer(T, _)    → `* T` (canonical readonly)
        //   - Mut(inner, _)    → `mut <inner>` (right-binding wrapper)
        //   - Unsafe(inner, _) → `unsafe <inner>` (right-binding wrapper)
        TypeRef::Pointer(inner, _) => format!("* {}", typeref_render(inner)),
        TypeRef::Mut(inner, _) => format!("mut {}", typeref_render(inner)),
        TypeRef::Unsafe(inner, _) => format!("unsafe {}", typeref_render(inner)),
    }
}

/// Plan 52 Ф.2: best-effort тип выражения по синтаксической форме.
/// Возвращает `None` если тип не выводится локально (Ident без scope,
/// произвольный вызов и т.п.) — такие выражения не участвуют в
/// унификации (permissive: «не знаем — не ругаемся»).
fn simple_expr_type(e: &Expr) -> Option<TypeRef> {
    let prim = |name: &str| {
        Some(TypeRef::Named {
            path: vec![name.to_string()],
            generics: Vec::new(),
            span: e.span,
        })
    };
    match &e.kind {
        ExprKind::IntLit(_) => prim("int"),
        ExprKind::FloatLit(_) => prim("f64"),
        ExprKind::BoolLit(_) => prim("bool"),
        ExprKind::StrLit(_) | ExprKind::InterpolatedStr { .. } => prim("str"),
        ExprKind::CharLit(_) => prim("char"),
        ExprKind::RecordLit { type_name: Some(name), .. } => Some(TypeRef::Named {
            path: name.clone(),
            generics: Vec::new(),
            span: e.span,
        }),
        // f64.NAN / int.MAX и т.п. — Path(["f64", "NAN"]).
        ExprKind::Path(parts) if parts.len() == 2 => {
            match parts[0].as_str() {
                "f64" => prim("f64"),
                "f32" => prim("f32"),
                "int" => prim("int"),
                "i8" | "i16" | "i32" | "i64" | "u8" | "u16" | "u32" | "u64" => prim(&parts[0]),
                _ => None,
            }
        }
        // Унарный минус не меняет числовой тип операнда.
        ExprKind::Unary { op: crate::ast::UnOp::Neg, operand } => simple_expr_type(operand),
        _ => None,
    }
}

/// Plan 52 Ф.2: совместимость двух простых типов для унификации
/// ключей/значений map-литерала. Bootstrap: точное равенство имён +
/// числовая лёгкость (int-литерал совместим с любым целочисленным
/// ожидаемым типом — coercion на codegen-уровне).
fn simple_types_compatible(a: &TypeRef, b: &TypeRef) -> bool {
    if is_unknown_type(a) || is_unknown_type(b) {
        return true;
    }
    match (a, b) {
        (
            TypeRef::Named { path: pa, generics: ga, .. },
            TypeRef::Named { path: pb, generics: gb, .. },
        ) => {
            if pa == pb && ga.len() == gb.len() {
                return ga.iter().zip(gb).all(|(x, y)| simple_types_compatible(x, y));
            }
            // Числовая лёгкость: int-литерал унифицируется с любым
            // целочисленным типом (codegen разрешит).
            let is_int = |p: &[String]| {
                p.len() == 1
                    && matches!(
                        p[0].as_str(),
                        "int" | "i8" | "i16" | "i32" | "i64"
                            | "u8" | "u16" | "u32" | "u64"
                    )
            };
            if is_int(pa) && is_int(pb) {
                return true;
            }
            false
        }
        (TypeRef::Array(ia, _), TypeRef::Array(ib, _)) => simple_types_compatible(ia, ib),
        (TypeRef::Tuple(ea, _), TypeRef::Tuple(eb, _)) => {
            ea.len() == eb.len()
                && ea.iter().zip(eb).all(|(x, y)| simple_types_compatible(x, y))
        }
        _ => false,
    }
}

// ============================================================================
// Plan 52 Ф.7 production-fix: annotate_map_literals — mutable pass.
//
// После `check_module` (immutable: проверки/errors), но ДО `desugar_module`:
// проходим по AST mutable, выводим K/V для каждого `MapLit` и записываем
// в узел через поля `inferred_key`/`inferred_value`. Десугаринг затем
// эмитит `HashMap[K, V].with_capacity(n)` с turbofish — иначе
// мономорфизация инстанциирует `HashMap[void*, void*]` → segfault.
//
// Стратегия:
//   - Build immutable `MapLitCtx` для type-таблиц (известные типы,
//     #from_fields, param-types для arg-position resolve).
//   - Mutable AST walker с expected-type propagation в let / FnBody::Expr-
//     return / argument-position. Те же позиции что MapLitCtx::walk_expr.
//   - На каждом `MapLit`: вычислить (K, V) через `simple_expr_type` +
//     unify_inferred helper; записать в узел. Не emit errors (это сделал
//     check_module).
// ============================================================================

/// Plan 52 Ф.7: пройти по AST mutable, записать inferred K/V для каждого
/// `MapLit`. Вызывается ПОСЛЕ `check_module` (errors уже emitted), ДО
/// `desugar_module` (читает inferred K/V для turbofish).
pub fn annotate_map_literals(module: &mut Module) {
    let ctx = MapLitCtx::build(module);
    let mut ann = MapLitAnnotator {
        ctx,
        fn_generics: HashSet::new(),
        var_types: HashMap::new(),
    };
    ann.walk_module(module);
    // Plan 42.4 / Plan 52 Ф.7: peer_files несут per-peer копии items для
    // name resolution. Десугаринг обходит и peer_files.items_here, поэтому
    // аннотировать нужно тоже их — иначе peer-копия MapLit'а останется без
    // inferred K/V → fallback bare Path → segfault.
    for pf in &mut module.peer_files {
        ann.walk_items(&mut pf.items_here);
    }
}

/// Mutable AST walker для аннотации MapLit-узлов inferred K/V.
struct MapLitAnnotator {
    /// Immutable type-таблицы (#from_fields, param-types).
    ctx: MapLitCtx,
    /// Generic-параметры текущей функции — для permissive Hashable.
    fn_generics: HashSet<String>,
    /// Plan 52.x: типы let-биндингов и параметров текущего item'а.
    /// Нужны для классификации all-spread литералов `[...a, ...b]` без
    /// аннотации: чтобы отличить map-spread от array-spread, нужен тип
    /// spread-источника. Сбрасывается на границе каждого item'а.
    var_types: HashMap<String, TypeRef>,
}

impl MapLitAnnotator {
    fn walk_module(&mut self, module: &mut Module) {
        self.walk_items(&mut module.items);
    }

    fn walk_items(&mut self, items: &mut [Item]) {
        for item in items.iter_mut() {
            match item {
                Item::Fn(f) => {
                    self.fn_generics =
                        f.generics.iter().map(|g| g.name.clone()).collect();
                    if let Some(recv) = &f.receiver {
                        for g in &recv.generics {
                            if let TypeRef::Named { path, .. } = g {
                                if path.len() == 1 {
                                    self.fn_generics.insert(path[0].clone());
                                }
                            }
                        }
                    }
                    // Plan 52.x: свежий var-scope на функцию + параметры.
                    self.var_types.clear();
                    for p in &f.params {
                        self.var_types.insert(p.name.clone(), p.ty.clone());
                    }
                    let return_ty = f.return_type.clone();
                    match &mut f.body {
                        FnBody::Expr(e) => self.walk_expr(e, return_ty.as_ref()),
                        FnBody::Block(b) => self.walk_block(b),
                        FnBody::External => {}
                    }
                }
                Item::Test(t) => {
                    self.fn_generics.clear();
                    self.var_types.clear();
                    self.walk_block(&mut t.body);
                }
                // Plan 57: bench body — аннотируем все три раздела.
                Item::Bench(b) => {
                    self.fn_generics.clear();
                    self.var_types.clear();
                    for s in &mut b.setup {
                        self.walk_stmt(s);
                    }
                    self.walk_block(&mut b.measure_body);
                    for s in &mut b.teardown {
                        self.walk_stmt(s);
                    }
                }
                Item::Const(c) => {
                    self.fn_generics.clear();
                    self.var_types.clear();
                    let ty = c.ty.clone();
                    self.walk_expr(&mut c.value, ty.as_ref());
                }
                Item::Let(l) => {
                    self.fn_generics.clear();
                    self.var_types.clear();
                    let ty = l.ty.clone();
                    self.walk_expr(&mut l.value, ty.as_ref());
                }
                Item::Type(_) | Item::Lemma(_) => {}
            }
        }
    }

    fn walk_block(&mut self, b: &mut Block) {
        for s in &mut b.stmts {
            self.walk_stmt(s);
        }
        if let Some(t) = &mut b.trailing {
            self.walk_expr(t, None);
        }
    }

    fn walk_stmt(&mut self, s: &mut Stmt) {
        match s {
            Stmt::Expr(e) => self.walk_expr(e, None),
            Stmt::Let(d) => {
                let ty = d.ty.clone();
                self.walk_expr(&mut d.value, ty.as_ref());
                // Plan 52.x: запоминаем тип биндинга для классификации
                // all-spread литералов `[...a, ...b]` без аннотации.
                if let Pattern::Ident { name, .. } = &d.pattern {
                    if let Some(bt) = &d.ty {
                        self.var_types.insert(name.clone(), bt.clone());
                    } else if let ExprKind::MapLit {
                        inferred_key: Some(k),
                        inferred_value: Some(v),
                        inferred_target_type,
                        ..
                    } = &d.value.kind
                    {
                        // Без аннотации, но значение — выведенный map-литерал.
                        let path = inferred_target_type
                            .clone()
                            .unwrap_or_else(|| vec!["HashMap".to_string()]);
                        self.var_types.insert(
                            name.clone(),
                            TypeRef::Named {
                                path,
                                generics: vec![k.clone(), v.clone()],
                                span: d.value.span,
                            },
                        );
                    } else {
                        // Неизвестный тип — снять устаревший entry (shadowing).
                        self.var_types.remove(name);
                    }
                }
            }
            // Plan 114.4 Ф.2: scope-local const — pass-through (no-op for now).
            Stmt::Const(_) => {}
            Stmt::Assign { target, value, .. } => {
                self.walk_expr(target, None);
                self.walk_expr(value, None);
            }
            Stmt::Return { value, .. } => {
                if let Some(v) = value { self.walk_expr(v, None); }
            }
            Stmt::Throw { value, .. } => self.walk_expr(value, None),
            Stmt::Break(_) | Stmt::Continue(_) => {}
            Stmt::Defer { body, .. } | Stmt::ErrDefer { body, .. }
            | Stmt::OkDefer { body, .. } | Stmt::DeferWithResult { body, .. } => {
                self.walk_expr(body, None);
            }
            // Plan 110 D188: walk init + body block recursively.
            Stmt::ConsumeScope { init, body, .. } => {
                self.walk_expr(init, None);
                for stmt in &mut body.stmts {
                    self.walk_stmt(stmt);
                }
                if let Some(t) = &mut body.trailing {
                    self.walk_expr(t, None);
                }
            }
            Stmt::AssertStatic { expr, .. } | Stmt::Assume { expr, .. } => {
                self.walk_expr(expr, None);
            }
            Stmt::Apply { .. } | Stmt::Calc { .. } | Stmt::Reveal { .. } => {}
            // Plan 136: tuple destructuring assignment.
            Stmt::TupleAssign { lhs, rhs, .. } => {
                for e in lhs { self.walk_expr(e, None); }
                for e in rhs { self.walk_expr(e, None); }
            }
        }
    }

    /// Plan 52.x: для all-spread `ArrayLit` (`[...a, ...b]`) без expected-
    /// типа выводит map-тип из типов spread-источников. Возвращает
    /// `Some(HashMap-тип)` только если ВСЕ источники — `Ident`-ы
    /// #from_pairs-типа; иначе это array-spread `[...arr1, ...arr2]` —
    /// возвращаем `None`, классификация остаётся прежней (массив).
    fn infer_map_type_from_spreads(&self, kind: &ExprKind) -> Option<TypeRef> {
        let ExprKind::ArrayLit(elems) = kind else {
            return None;
        };
        if elems.is_empty() {
            return None;
        }
        let mut first: Option<TypeRef> = None;
        for el in elems {
            let ArrayElem::Spread(s) = el else {
                return None;
            };
            let ExprKind::Ident(name) = &s.kind else {
                return None;
            };
            let ty = self.var_types.get(name)?;
            if !self.ctx.expected_is_from_pairs(ty) {
                return None;
            }
            if first.is_none() {
                first = Some(ty.clone());
            }
        }
        first
    }

    fn walk_expr(&mut self, e: &mut Expr, expected: Option<&TypeRef>) {
        // Plan 52.x: all-spread `[...a, ...b]` без expected-типа —
        // синтезируем map-тип из spread-источников, чтобы конверсия
        // ArrayLit→MapLit ниже и inference K/V сработали (без этого
        // spread двух map'ов без аннотации мис-классифицируется как
        // массив → `b->len` на HashMap → CC-FAIL).
        let synth_expected: Option<TypeRef> = if expected.is_none() {
            self.infer_map_type_from_spreads(&e.kind)
        } else {
            None
        };
        let expected = expected.or(synth_expected.as_ref());

        // Plan 52.3 Ф.1: empty `[]` в позиции #from_pairs-типа конвертим
        // в empty MapLit. Codegen ArrayLit пустой → array (CC-FAIL для
        // HashMap-target). MapLit пустой → with_capacity(0) — пустая мапа.
        // Plan 55 followup (spread): `[...spread]` (только spreads, без
        // pairs) тоже может быть **либо** array **либо** map — disambiguate
        // через expected type. Если expected is #from_pairs → conv в MapLit.
        if let ExprKind::ArrayLit(elems) = &e.kind {
            let all_spread = !elems.is_empty()
                && elems.iter().all(|el| matches!(el, ArrayElem::Spread(_)));
            let is_empty = elems.is_empty();
            if is_empty || all_spread {
                if let Some(exp) = expected {
                    if self.ctx.expected_is_from_pairs(exp) {
                        // Конвертим: spreads (если есть) move'аются в MapElem.
                        // annotate ниже заполнит inferred_key/value/target_type.
                        let new_elems: Vec<MapElem> = if is_empty {
                            Vec::new()
                        } else {
                            elems.iter().map(|el| match el {
                                ArrayElem::Spread(s) => MapElem::Spread(s.clone()),
                                ArrayElem::Item(_) => unreachable!("all_spread guard"),
                            }).collect()
                        };
                        e.kind = ExprKind::MapLit {
                            elems: new_elems,
                            inferred_key: None,
                            inferred_value: None,
                            inferred_target_type: None,
                        };
                    }
                }
            }
        }

        // 1. На MapLit — заполнить inferred_key/value/target_type (до спуска).
        if let ExprKind::MapLit {
            elems,
            inferred_key,
            inferred_value,
            inferred_target_type,
        } = &mut e.kind {
            let pairs = crate::ast::MapElem::cloned_pairs(elems);
            let (exp_k, exp_v) = extract_hashmap_kv(expected);
            *inferred_key = infer_unified_type(
                pairs.iter().map(|(k, _)| k),
                exp_k,
            );
            *inferred_value = infer_unified_type(
                pairs.iter().map(|(_, v)| v),
                exp_v,
            );
            // Plan 52 Ф.23: если expected помечен #from_pairs — записываем
            // имя target-типа для desugar. Иначе fallback на HashMap.
            if let Some(TypeRef::Named { path, .. }) = expected {
                if self.ctx.expected_is_from_pairs(expected.unwrap()) {
                    *inferred_target_type = Some(path.clone());
                }
            }
        }
        // Plan 52 Ф.10: D55 map-coercion для `{field: v}` в позиции
        // `#from_fields`-типа (= HashMap[str, V]). Если expected —
        // HashMap-with-#from_fields-маркер И литерал анонимный,
        // записываем V в `inferred_map_v`. Codegen `emit_record_as_map`
        // эмитит как `HashMap[str,V].with_capacity + insert("field", v)`.
        if let ExprKind::RecordLit { type_name: None, inferred_map_v, .. } = &mut e.kind {
            if let Some(exp) = expected {
                if self.ctx.expected_is_from_fields(exp) {
                    let (_, exp_v) = extract_hashmap_kv(Some(exp));
                    if let Some(v) = exp_v {
                        *inferred_map_v = Some(v.clone());
                    }
                }
            }
        }
        // 2. Спуск в под-выражения с propagation expected-type где известен.
        match &mut e.kind {
            ExprKind::MapLit { elems, .. } => {
                for me in elems.iter_mut() {
                    match me {
                        crate::ast::MapElem::Pair(k, v) => {
                            self.walk_expr(k, None);
                            self.walk_expr(v, None);
                        }
                        crate::ast::MapElem::Spread(e) => self.walk_expr(e, None),
                    }
                }
            }
            ExprKind::ArrayLit(elems) => {
                for el in elems.iter_mut() {
                    match el {
                        ArrayElem::Item(x) | ArrayElem::Spread(x) => {
                            self.walk_expr(x, None);
                        }
                    }
                }
            }
            ExprKind::Call { func, args, trailing } => {
                self.walk_expr(func, None);
                // Argument-позиция — propagation expected типа параметра
                // (фундамент Ф.3a).
                let params = self.ctx.resolve_call_params(func);
                let mut positional_idx = 0usize;
                for a in args.iter_mut() {
                    let arg_expected: Option<TypeRef> = match (&params, a.arg_name()) {
                        (Some(ps), Some(name)) => ps
                            .iter()
                            .find(|(pn, _)| pn == name)
                            .map(|(_, t)| t.clone()),
                        (Some(ps), None) => {
                            let r = ps.get(positional_idx).map(|(_, t)| t.clone());
                            positional_idx += 1;
                            r
                        }
                        (None, _) => None,
                    };
                    let expr_mut = match a {
                        CallArg::Item(x) | CallArg::Spread(x) => x,
                        CallArg::Named { value, .. } => value,
                    };
                    self.walk_expr(expr_mut, arg_expected.as_ref());
                }
                if let Some(t) = trailing {
                    match t {
                        crate::ast::Trailing::Block(b) => self.walk_block(b),
                        crate::ast::Trailing::LegacyBlockWithParams(tb) => {
                            self.walk_block(&mut tb.body)
                        }
                        crate::ast::Trailing::Fn(sb) => match &mut sb.body {
                            FnBody::Expr(x) => self.walk_expr(x, None),
                            FnBody::Block(b) => self.walk_block(b),
                            FnBody::External => {}
                        },
                    }
                }
            }
            ExprKind::TurboFish { base, .. } => self.walk_expr(base, expected),
            ExprKind::Try(x) | ExprKind::Bang(x) => self.walk_expr(x, None),
            ExprKind::Coalesce(a, b) => {
                self.walk_expr(a, None);
                self.walk_expr(b, None);
            }
            ExprKind::As(x, _) | ExprKind::Is(x, _) => self.walk_expr(x, None),
            ExprKind::Binary { left, right, .. } => {
                self.walk_expr(left, None);
                self.walk_expr(right, None);
            }
            ExprKind::Unary { operand, .. } => self.walk_expr(operand, None),
            ExprKind::Member { obj, .. } => self.walk_expr(obj, None),
            ExprKind::Index { obj, index } => {
                self.walk_expr(obj, None);
                self.walk_expr(index, None);
            }
            ExprKind::TupleLit(elems) => {
                for x in elems.iter_mut() { self.walk_expr(x, None); }
            }
            ExprKind::RecordLit { fields, .. } => {
                for f in fields.iter_mut() {
                    if let Some(v) = &mut f.value { self.walk_expr(v, None); }
                }
            }
            ExprKind::If { cond, then, else_ } => {
                self.walk_expr(cond, None);
                self.walk_block(then);
                if let Some(eb) = else_ {
                    match eb {
                        ElseBranch::Block(b) => self.walk_block(b),
                        ElseBranch::If(x) => self.walk_expr(x, None),
                    }
                }
            }
            ExprKind::IfLet { scrutinee, then, else_, .. } => {
                self.walk_expr(scrutinee, None);
                self.walk_block(then);
                if let Some(eb) = else_ {
                    match eb {
                        ElseBranch::Block(b) => self.walk_block(b),
                        ElseBranch::If(x) => self.walk_expr(x, None),
                    }
                }
            }
            ExprKind::Match { scrutinee, arms } => {
                self.walk_expr(scrutinee, None);
                for arm in arms.iter_mut() {
                    if let Some(g) = &mut arm.guard { self.walk_expr(g, None); }
                    match &mut arm.body {
                        MatchArmBody::Expr(x) => self.walk_expr(x, None),
                        MatchArmBody::Block(b) => self.walk_block(b),
                    }
                }
            }
            ExprKind::For { iter, body, .. } | ExprKind::ParallelFor { iter, body, .. } => {
                self.walk_expr(iter, None);
                self.walk_block(body);
            }
            ExprKind::While { cond, body, .. } => {
                self.walk_expr(cond, None);
                self.walk_block(body);
            }
            ExprKind::WhileLet { scrutinee, body, .. } => {
                self.walk_expr(scrutinee, None);
                self.walk_block(body);
            }
            ExprKind::Loop { body, .. } => self.walk_block(body),
            ExprKind::Block(b) => self.walk_block(b),
            ExprKind::Spawn(x) => self.walk_expr(x, None),
            ExprKind::Detach(b) | ExprKind::Blocking(b) => self.walk_block(b),
            ExprKind::Supervised { body, cancel } => {
                self.walk_block(body);
                if let Some(c) = cancel { self.walk_expr(c, None); }
            }
            ExprKind::Forbid { body, .. } | ExprKind::Realtime { body, .. } => {
                self.walk_block(body);
            }
            ExprKind::Throw(x) => self.walk_expr(x, None),
            ExprKind::Interrupt(opt) => {
                if let Some(x) = opt { self.walk_expr(x, None); }
            }
            ExprKind::Range { start, end, .. } => {
                if let Some(s) = start { self.walk_expr(s, None); }
                if let Some(e) = end { self.walk_expr(e, None); }
            }
            ExprKind::InterpolatedStr { parts } => {
                for p in parts.iter_mut() {
                    if let crate::ast::InterpStrPart::Expr { expr: x, spec: _ } = p {
                        self.walk_expr(x, None);
                    }
                }
            }
            ExprKind::TaggedTemplate { args, .. } => {
                for x in args.iter_mut() { self.walk_expr(x, None); }
            }
            ExprKind::Lambda { body, .. } => self.walk_expr(body, None),
            ExprKind::ClosureLight { body, .. } => match body {
                ClosureBody::Expr(x) => self.walk_expr(x, None),
                ClosureBody::Block(b) => self.walk_block(b),
            },
            ExprKind::ClosureFull(sb) => match &mut sb.body {
                FnBody::Expr(x) => self.walk_expr(x, None),
                FnBody::Block(b) => self.walk_block(b),
                FnBody::External => {}
            },
            ExprKind::With { bindings, body } => {
                for b in bindings.iter_mut() { self.walk_expr(&mut b.handler, None); }
                self.walk_block(body);
            }
            // Plan 97 Ф.4 (D142): protocol-литерал — walk-mut идентичен.
            ExprKind::HandlerLit { methods, .. } | ExprKind::ProtocolLit { methods, .. } => {
                for m in methods.iter_mut() {
                    match &mut m.body {
                        HandlerMethodBody::Expr(x) => self.walk_expr(x, None),
                        HandlerMethodBody::Block(b) => self.walk_block(b),
                    }
                }
            }
            ExprKind::Select { arms } => {
                for arm in arms.iter_mut() {
                    match &mut arm.op {
                        crate::ast::SelectOp::Recv { chan, .. } => {
                            self.walk_expr(chan, None)
                        }
                        crate::ast::SelectOp::Send { chan, value } => {
                            self.walk_expr(chan, None);
                            self.walk_expr(value, None);
                        }
                        crate::ast::SelectOp::Default => {}
                    }
                    if let Some(g) = &mut arm.guard { self.walk_expr(g, None); }
                    self.walk_block(&mut arm.body);
                }
            }
            ExprKind::Forall { body, .. } | ExprKind::Exists { body, .. } => {
                self.walk_expr(body, None);
            }
            ExprKind::Ident(_) | ExprKind::Path(_) | ExprKind::SelfAccess
            | ExprKind::IntLit(_) | ExprKind::FloatLit(_) | ExprKind::BoolLit(_)
            | ExprKind::StrLit(_) | ExprKind::CharLit(_) | ExprKind::UnitLit
            | ExprKind::NullPtrLit => {}
        }
        // Подавляем unused warnings.
        let _ = &self.fn_generics;
    }
}

/// Plan 52 Ф.7: извлечь (K, V) из ожидаемого типа `HashMap[K, V]`.
/// Возвращает (None, None) если expected не HashMap[_, _].
fn extract_hashmap_kv(expected: Option<&TypeRef>) -> (Option<&TypeRef>, Option<&TypeRef>) {
    match expected {
        Some(TypeRef::Named { path, generics, .. })
            if path.last().map(|s| s.as_str()) == Some("HashMap")
                && generics.len() == 2 =>
        {
            (Some(&generics[0]), Some(&generics[1]))
        }
        _ => (None, None),
    }
}

/// Plan 52 Ф.7: вывести унифицированный тип набора выражений. Если задан
/// `expected` — берём его (приоритет контекста). Иначе — best-effort
/// первое выражение с известным simple_expr_type. Несовместимости не
/// репортим (это работа check_map_lit, эта функция silent).
fn infer_unified_type<'e>(
    exprs: impl Iterator<Item = &'e Expr>,
    expected: Option<&TypeRef>,
) -> Option<TypeRef> {
    if let Some(t) = expected {
        return Some(t.clone());
    }
    for ex in exprs {
        if let Some(t) = simple_expr_type(ex) {
            return Some(t);
        }
    }
    None
}

// ─── Plan 103.1 Ф.4: Ordering validation helpers ─────────────────────────
//
// Compile-time validation of MemOrdering arguments on atomic load/store ops.
// Called from Plan 103.2+ method-call type-check pipeline for AtomicX.load()
// and AtomicX.store() overloads that accept a MemOrdering parameter.
//
// Error codes (no central registry exists; embedded in Diagnostic message):
//   E_INVALID_ORDERING_LOAD  — Release/AcqRel on load (only Relaxed/Acquire/SeqCst valid)
//   E_INVALID_ORDERING_STORE — Acquire/AcqRel on store (only Relaxed/Release/SeqCst valid)
//
// See D167 (spec/decisions/06-concurrency.md) for semantics rationale.

/// Error code for forbidden ordering on atomic load operation.
/// Release and AcqRel are invalid for load (they provide no acquire synchronization).
pub const E_INVALID_ORDERING_LOAD: &str = "E_INVALID_ORDERING_LOAD";

/// Error code for forbidden ordering on atomic store operation.
/// Acquire and AcqRel are invalid for store (they provide no release synchronization).
pub const E_INVALID_ORDERING_STORE: &str = "E_INVALID_ORDERING_STORE";

/// Plan 103.1 Ф.4: Extract the variant name from a MemOrdering path expression.
/// Returns Some("Acquire") for `MemOrdering.Acquire`, None for runtime values.
fn mem_ordering_variant(ord_expr: &Expr) -> Option<&str> {
    use crate::ast::ExprKind;
    if let ExprKind::Path(parts) = &ord_expr.kind {
        if parts.len() == 2 && parts[0] == "MemOrdering" {
            return Some(&parts[1]);
        }
    }
    None
}

/// Plan 103.1 Ф.4: Validate MemOrdering argument for an atomic **load** operation.
///
/// Valid orderings for load: Relaxed, Acquire, SeqCst.
/// Invalid: Release, AcqRel (these orderings make no semantic sense on a load).
///
/// Validation is compile-time only when the ordering is a literal constant.
/// Runtime-value orderings are skipped (handled via runtime panic in codegen).
///
/// # Plan 103.2 integration
/// Call from the method-call type-check path for `AtomicX.load(ord MemOrdering)`.
/// Pass `ord_arg` = the MemOrdering expression argument, `span` = call-site span.
#[allow(dead_code)]  // Called from Plan 103.2
pub fn check_atomic_load_ordering(
    ord_arg: &Expr,
    span: crate::diag::Span,
) -> Result<(), crate::diag::Diagnostic> {
    let Some(variant) = mem_ordering_variant(ord_arg) else {
        return Ok(()); // Runtime value — skip compile-time check
    };
    match variant {
        "Release" | "AcqRel" => Err(
            crate::diag::Diagnostic::new(
                format!(
                    "[{}] `MemOrdering.{}` запрещён для load; \
                     используйте Relaxed, Acquire, или SeqCst. \
                     Release/AcqRel не имеют семантики для load-операций.",
                    E_INVALID_ORDERING_LOAD, variant
                ),
                span,
            )
            .with_suggestion(crate::diag::Suggestion {
                message: "замените на Acquire (или SeqCst для simplicity)".to_string(),
                span,
                replacement: "MemOrdering.Acquire".to_string(),
                applicability: crate::diag::Applicability::MaybeIncorrect,
            })
        ),
        _ => Ok(()),
    }
}

/// Plan 103.1 Ф.4: Validate MemOrdering argument for an atomic **store** operation.
///
/// Valid orderings for store: Relaxed, Release, SeqCst.
/// Invalid: Acquire, AcqRel (these orderings make no semantic sense on a store).
///
/// # Plan 103.2 integration
/// Call from the method-call type-check path for `AtomicX.store(v, ord MemOrdering)`.
/// Pass `ord_arg` = the MemOrdering expression argument, `span` = call-site span.
#[allow(dead_code)]  // Called from Plan 103.2
pub fn check_atomic_store_ordering(
    ord_arg: &Expr,
    span: crate::diag::Span,
) -> Result<(), crate::diag::Diagnostic> {
    let Some(variant) = mem_ordering_variant(ord_arg) else {
        return Ok(()); // Runtime value — skip compile-time check
    };
    match variant {
        "Acquire" | "AcqRel" => Err(
            crate::diag::Diagnostic::new(
                format!(
                    "[{}] `MemOrdering.{}` запрещён для store; \
                     используйте Relaxed, Release, или SeqCst. \
                     Acquire/AcqRel не имеют семантики для store-операций.",
                    E_INVALID_ORDERING_STORE, variant
                ),
                span,
            )
            .with_suggestion(crate::diag::Suggestion {
                message: "замените на Release (или SeqCst для simplicity)".to_string(),
                span,
                replacement: "MemOrdering.Release".to_string(),
                applicability: crate::diag::Applicability::MaybeIncorrect,
            })
        ),
        _ => Ok(()),
    }
}

// =============================================================================
// Plan 118 Ф.3.5 — E_UNSAFE_REQUIRED enforcement
// =============================================================================

/// Plan 118 D216 §8 (D2 amend): Walk fn bodies, emit E_UNSAFE_REQUIRED
/// для AddrOf (`&value`) / Deref (`*expr`) used вне `unsafe { ... }` block
/// или `#unsafe fn` body context.
///
/// Маркер unsafe context'а — Block.is_unsafe field (set parser в KwUnsafe
/// arm of parse_primary) OR fn.unsafe_attr (Plan 118 Ф.3.2 #unsafe attr).
///
/// Depth counter incremented при entry в unsafe block / fn; pointer ops
/// allowed iff depth > 0.
pub(crate) fn check_unsafe_context_in_module(
    module: &crate::ast::Module,
    errors: &mut Vec<Diagnostic>,
) {
    use crate::ast::{Item, FnBody};
    // Pre-collect names of #unsafe fns для A11 enforcement
    // (E_UNSAFE_CALL_REQUIRES_WRAP — calling #unsafe fn без `unsafe { }` wrap).
    // Plan 118 A25: pre-collect fn names that have Fail effect — cast к
    // *fn → E_CALLBACK_THROWS_OVER_C_ABI (Nova exceptions cannot cross C ABI).
    let mut unsafe_fns: HashSet<String> = HashSet::new();
    // Plan 138.2 [M-138-vec-bulk-parity] sharper A11 precision (the Ф.3.5
    // receiver-aware-lookup followup noted at the match site below): unsafe
    // STATIC methods (`fn Type.m()` — e.g. `RawMem.fill` / `RawMem.compare`)
    // are keyed by `(type_name, method)` rather than bare method name. Without
    // this, a same-named *instance* method on another type (e.g. `Vec[T] @fill`
    // / `Vec[T] @compare`) would falsely require an `unsafe { }` wrap at its
    // call site whenever `RawMem` is in scope (it is transitively, via
    // `vec_owned.nv`). Static-method calls write the receiver type literally
    // (`RawMem.fill(...)`), so receiver-name matching is exact and introduces
    // no false negatives.
    let mut unsafe_static_methods: HashSet<(String, String)> = HashSet::new();
    let mut fail_fns: HashSet<String> = HashSet::new();
    let collect_from = |item: &Item,
                        unsafe_fns: &mut HashSet<String>,
                        unsafe_static_methods: &mut HashSet<(String, String)>,
                        fail_fns: &mut HashSet<String>| {
        if let Item::Fn(fd) = item {
            if fd.unsafe_attr {
                match &fd.receiver {
                    Some(r) if r.kind == crate::ast::ReceiverKind::Static => {
                        unsafe_static_methods
                            .insert((r.type_name.clone(), fd.name.clone()));
                    }
                    _ => {
                        unsafe_fns.insert(fd.name.clone());
                    }
                }
            }
            // Plan 118 A25: detect Fail effect через TypeRef::Named { path }
            // где last segment == "Fail". Fn с Fail effect = throwable —
            // cast к *fn forbidden.
            for eff in &fd.effects {
                if let crate::ast::TypeRef::Named { path, .. } = eff {
                    if path.last().map_or(false, |n| n == "Fail") {
                        fail_fns.insert(fd.name.clone());
                        break;
                    }
                }
            }
        }
    };
    for item in &module.items {
        collect_from(item, &mut unsafe_fns, &mut unsafe_static_methods, &mut fail_fns);
    }
    for pf in &module.peer_files {
        for item in &pf.items_here {
            collect_from(item, &mut unsafe_fns, &mut unsafe_static_methods, &mut fail_fns);
        }
    }
    let mut state = UnsafeCtx {
        depth: 0,
        unsafe_fns,
        unsafe_static_methods,
        fail_fns,
        in_realtime: false,
        ptr_vars: vec![HashSet::new()],
        unsafe_t_vars: vec![HashSet::new()],
        // Plan 118.1.6 (2026-06-08): track locals/params bound к
        // *unsafe fn(...) pointer type. Used by E_UNSAFE_CALL_REQUIRES_WRAP
        // to fire on indirect call `ufp()` outside `unsafe { }` block.
        unsafe_fn_ptr_vars: vec![HashSet::new()],
        in_call_arg: false,
    };
    // peer_files mode: walk only entry peers items_here (Plan 62.A pattern)
    let entry_items: Vec<&Item> = if module.peer_files.is_empty() {
        module.items.iter().collect()
    } else {
        module.peer_files.iter()
            .filter(|pf| pf.is_entry_module)
            .flat_map(|pf| pf.items_here.iter())
            .collect()
    };
    for item in entry_items {
        if let Item::Fn(fd) = item {
            // #unsafe fn body — implicit unsafe context per D216 §9.
            let entered_unsafe_fn = fd.unsafe_attr;
            if entered_unsafe_fn { state.depth += 1; }
            // Plan 118 A33: #realtime fn body — pointer ops banned.
            let entered_realtime = matches!(
                fd.realtime_attr,
                crate::ast::RealtimeAttr::Realtime | crate::ast::RealtimeAttr::RealtimeNogc
            ) || matches!(fd.sync_class, Some(crate::ast::SyncClass::Realtime));
            let prev_realtime = state.in_realtime;
            if entered_realtime { state.in_realtime = true; }
            // Plan 118.5 Ф.4 / D216 V2 §V2.3: register fn params типа unsafe T.
            // Push fresh fn-scope unsafe_t frame BEFORE walking body so that
            // params bound к unsafe T types fire E_UNSAFE_T_READ_REQUIRES_WRAP
            // on safe-context reads inside body.
            state.unsafe_t_vars.push(HashSet::new());
            // Plan 118.1.6: push fresh fn-scope unsafe-fn-ptr frame parallel
            // к unsafe_t_vars. Register fn params типа `*unsafe fn(...)` so
            // calling those params без `unsafe { }` wrap → E_UNSAFE_CALL_REQUIRES_WRAP.
            state.unsafe_fn_ptr_vars.push(HashSet::new());
            for p in &fd.params {
                if p.ty.outer_unsafe_before_pointer() {
                    state.register_unsafe_t_var(&p.name);
                }
                if p.ty.is_unsafe_fn_pointer() {
                    state.register_unsafe_fn_ptr_var(&p.name);
                }
            }
            if let FnBody::Block(b) = &fd.body {
                state.walk_block(b, errors);
            } else if let FnBody::Expr(e) = &fd.body {
                state.walk_expr(e, errors);
            }
            state.unsafe_fn_ptr_vars.pop();
            state.unsafe_t_vars.pop();
            state.in_realtime = prev_realtime;
            if entered_unsafe_fn { state.depth -= 1; }
        }
        if let Item::Test(t) = item {
            state.walk_block(&t.body, errors);
        }
    }
}

struct UnsafeCtx {
    depth: usize,
    /// Plan 118 A11 enforcement: names of #unsafe free-fns + #unsafe instance
    /// methods в текущем module. Call с этим именем outside unsafe context →
    /// E_UNSAFE_CALL_REQUIRES_WRAP.
    unsafe_fns: HashSet<String>,
    /// Plan 138.2 [M-138-vec-bulk-parity]: #unsafe STATIC methods keyed by
    /// `(receiver_type_name, method_name)` — e.g. `(RawMem, fill)`. Matched
    /// only when the call's receiver is literally that type (`RawMem.fill(...)`),
    /// so a same-named instance method on another type (`v.fill(...)` on Vec)
    /// is NOT falsely gated. Closes the "receiver-type-aware lookup" V1 gap
    /// noted at the A11 match site.
    unsafe_static_methods: HashSet<(String, String)>,
    /// Plan 118 A25 enforcement: names of fns с Fail effect — cast к *fn
    /// → E_CALLBACK_THROWS_OVER_C_ABI (Nova exceptions cannot cross C ABI).
    fail_fns: HashSet<String>,
    /// Plan 118 A33 enforcement: currently walking body #realtime fn.
    /// Pointer ops (AddrOf, Deref) inside #realtime fn → E_REALTIME_POINTER_OP
    /// — deref может GC trigger (allocation), violates realtime guarantee
    /// (Plan 113 D172 cross-ref).
    in_realtime: bool,
    /// Plan 118 A28 enforcement: locals bound к typed-pointer expression
    /// (let x = &v, let x = *p, let x = expr as *T). Stack of scope-frames
    /// (push на block entry, pop при exit) — позволяет shadowing-safe lookup.
    /// `"${x}"` interpolation на ptr var → E_PTR_NO_DISPLAY_USE_DEBUG_STR.
    ptr_vars: Vec<HashSet<String>>,
    /// **Plan 118.5 Ф.4 / D216 V2 §V2.3 (2026-06-04):** locals/params bound к
    /// `unsafe T` type. Reading these в safe context →
    /// `E_UNSAFE_T_READ_REQUIRES_WRAP`. Write safe (transitions к valid).
    /// Stack of scope-frames mirrors ptr_vars structure.
    unsafe_t_vars: Vec<HashSet<String>>,
    /// **Plan 118.1.6 (2026-06-08):** locals/params bound к `*unsafe fn(...)`
    /// type. Calling such a binding outside `unsafe { }` block at depth==0 →
    /// `E_UNSAFE_CALL_REQUIRES_WRAP` (the C ABI fn body может invoke pointer
    /// ops без gating; callsite должен explicitly opt-in к unsafe context).
    /// Stack of scope-frames mirrors `ptr_vars` structure для shadowing.
    ///
    /// Registration sources:
    ///   - `let x: *unsafe fn(...) = ...` (type annotation has unsafe-fn-ptr shape);
    ///   - `let x = &unsafe_fn_name` (UnOp::AddrOf shape);
    ///   - fn params типа `*unsafe fn(...)` (params binding registration).
    unsafe_fn_ptr_vars: Vec<HashSet<String>>,
    /// **Plan 118.5 V2 [M-118.5-arg-coerce-unsafe] (2026-06-04):** when true,
    /// the Ident read check для unsafe_t_vars is suppressed — defer к the
    /// precise `check_unsafe_coerce_args` pass which knows callee param
    /// types. Set when walking Call args; cleared при return.
    in_call_arg: bool,
}

impl UnsafeCtx {
    fn walk_block(&mut self, b: &crate::ast::Block, errors: &mut Vec<Diagnostic>) {
        // Plan 118 D216 §8: track unsafe context entry/exit.
        if b.is_unsafe { self.depth += 1; }
        // Plan 118 A28: push fresh ptr-var scope frame.
        self.ptr_vars.push(HashSet::new());
        // Plan 118.5 Ф.4: push fresh unsafe-T scope frame (parallel к ptr_vars).
        self.unsafe_t_vars.push(HashSet::new());
        // Plan 118.1.6: push fresh unsafe-fn-ptr scope frame.
        self.unsafe_fn_ptr_vars.push(HashSet::new());
        for stmt in &b.stmts {
            self.walk_stmt(stmt, errors);
        }
        if let Some(t) = &b.trailing {
            self.walk_expr(t, errors);
        }
        self.unsafe_fn_ptr_vars.pop();
        self.unsafe_t_vars.pop();
        self.ptr_vars.pop();
        if b.is_unsafe { self.depth -= 1; }
    }

    /// **Plan 118.5 Ф.4 (2026-06-04):** check if `name` ∈ any unsafe-T scope
    /// frame. Used by walk_expr Ident arm to detect read of unsafe binding.
    fn is_unsafe_t_var(&self, name: &str) -> bool {
        self.unsafe_t_vars.iter().rev().any(|f| f.contains(name))
    }

    /// **Plan 118.5 Ф.4 (2026-06-04):** register `name` as bound к unsafe-T
    /// type в innermost scope. Shadowing automatic — Ident lookup walks
    /// outer-most-last, latest binding wins.
    fn register_unsafe_t_var(&mut self, name: &str) {
        if let Some(frame) = self.unsafe_t_vars.last_mut() {
            frame.insert(name.to_string());
        }
    }

    /// **Plan 118.1.6 (2026-06-08):** check if `name` resolves к local/param
    /// bound к `*unsafe fn(...)` type. Walks scope frames outer-most-last
    /// (latest binding wins — handles shadowing).
    fn is_unsafe_fn_ptr_var(&self, name: &str) -> bool {
        self.unsafe_fn_ptr_vars.iter().rev().any(|f| f.contains(name))
    }

    /// **Plan 118.1.6 (2026-06-08):** register `name` as bound к
    /// `*unsafe fn(...)` type в innermost scope.
    fn register_unsafe_fn_ptr_var(&mut self, name: &str) {
        if let Some(frame) = self.unsafe_fn_ptr_vars.last_mut() {
            frame.insert(name.to_string());
        }
    }

    /// **Plan 118.1.6 (2026-06-08):** detect whether the RHS expression of
    /// a `let` binding evaluates к `*unsafe fn(...)` value. Conservative —
    /// fires when syntactic shape is one of:
    ///   - `&IDENT` где IDENT ∈ self.unsafe_fns (UnOp::AddrOf form);
    ///   - bare Ident name ∈ self.unsafe_fn_ptr_vars (forwarding through
    ///     another let-binding или fn param).
    /// Block trailing-expression inherits (handles `unsafe { &uf }`).
    fn expr_produces_unsafe_fn_ptr(&self, e: &Expr) -> bool {
        use crate::ast::{ExprKind, UnOp};
        match &e.kind {
            ExprKind::Unary { op: UnOp::AddrOf, operand } => {
                matches!(&operand.kind, ExprKind::Ident(n) if self.unsafe_fns.contains(n))
            }
            ExprKind::Ident(name) => self.is_unsafe_fn_ptr_var(name),
            ExprKind::Block(b) => b.trailing.as_ref()
                .map_or(false, |t| self.expr_produces_unsafe_fn_ptr(t)),
            _ => false,
        }
    }

    /// Plan 118 A28/A17: syntactic check для "expression value is a typed pointer".
    /// Conservative — fires only when can be detected without full type-inference:
    ///   - `&value` / `*expr` unary
    ///   - `expr as *T` (cast к pointer type)
    ///   - Block expression — peek в trailing (handles `unsafe { &x }` form)
    ///   - Ident binding к локалу, RHS которого был один из above
    /// Полная type-aware enforcement — Session 4+ через infer_expr_type.
    fn expr_is_typed_pointer(&self, e: &Expr) -> bool {
        use crate::ast::{ExprKind, UnOp};
        match &e.kind {
            ExprKind::Unary { op: UnOp::AddrOf, .. } => true,
            ExprKind::Unary { op: UnOp::RawAddrOf, .. } => true,
            ExprKind::Unary { op: UnOp::Deref, .. } => true,
            // Plan 118.5 V2 (2026-06-04): expanded to detect all pointer-
            // family AST wrappers — Pointer (canonical), Mut (mut * T),
            // Unsafe (unsafe * T). Each represents a typed-pointer cast
            // target at the syntactic level.
            ExprKind::As(_, ty) => matches!(
                ty,
                crate::ast::TypeRef::Pointer(_, _)
                    | crate::ast::TypeRef::Mut(_, _)
                    | crate::ast::TypeRef::Unsafe(_, _)
            ),
            ExprKind::Ident(name) => self.ptr_vars.iter().rev().any(|f| f.contains(name)),
            // Block-trailing inheritance: `unsafe { &x }` / nested block.
            // Empty trailing => not a pointer (unit-typed).
            ExprKind::Block(b) => b.trailing.as_ref()
                .map_or(false, |t| self.expr_is_typed_pointer(t)),
            _ => false,
        }
    }

    /// Plan 118 A28: register `name` as typed-pointer local в current frame
    /// (innermost scope). Shadowing automatic — Ident lookup walks frames
    /// outer-most-last, so latest binding wins.
    fn register_ptr_var(&mut self, name: &str) {
        if let Some(frame) = self.ptr_vars.last_mut() {
            frame.insert(name.to_string());
        }
    }

    fn walk_stmt(&mut self, s: &crate::ast::Stmt, errors: &mut Vec<Diagnostic>) {
        use crate::ast::Stmt;
        match s {
            Stmt::Expr(e) => self.walk_expr(e, errors),
            Stmt::Let(d) => {
                self.walk_expr(&d.value, errors);
                // Plan 118 A28: track typed-pointer locals для interpolation
                // diagnostic. Match только simple-ident pattern (no destructure).
                // Two registration sources:
                //   (a) RHS expression is syntactically a typed pointer
                //       (&v, *p, e as *T, Ident in ptr_vars, block
                //       trailing к pointer shape).
                //   (b) Type annotation is a pointer type (TypeRef::Pointer /
                //       Mut / Unsafe чей strip_modifiers → Pointer). Covers the
                //       common `mut buf: *mut u8 = expr_returning_ptr` pattern
                //       where RHS is a fn Call (e.g. RawMem.alloc) — syntactically
                //       opaque, but annotation makes pointer-ness explicit.
                //       [M-118-ptr-index-unsafe] fix.
                let is_ptr_rhs = self.expr_is_typed_pointer(&d.value);
                let is_ptr_ann = d.ty.as_ref().map_or(false, |ty| ty.is_pointer());
                if is_ptr_rhs || is_ptr_ann {
                    if let crate::ast::Pattern::Ident { name, .. } = &d.pattern {
                        self.register_ptr_var(name);
                    }
                }
                // Plan 118.5 Ф.4 / D216 V2 §V2.3: track unsafe-T bindings.
                // When type annotation explicitly has `unsafe T` shape (outer
                // wrapper is Unsafe before any Pointer), register binding name —
                // subsequent Ident reads outside unsafe { } context emit
                // E_UNSAFE_T_READ_REQUIRES_WRAP.
                if let Some(ty) = &d.ty {
                    if ty.outer_unsafe_before_pointer() {
                        if let crate::ast::Pattern::Ident { name, .. } = &d.pattern {
                            self.register_unsafe_t_var(name);
                        }
                    }
                }
                // Plan 118.1.6 (2026-06-08): track *unsafe fn(...) bindings +
                // E_UNSAFE_FN_PTR_COERCION enforcement.
                //
                // Three cases by combining (RHS-shape, type-annotation):
                //   (a) RHS produces *unsafe fn(...), ann ∈ {None, *unsafe fn(...)}:
                //       binding inherits unsafe-fn-ptr — register.
                //   (b) RHS produces *unsafe fn(...), ann = *fn(...) (safe):
                //       COVARIANCE VIOLATION — emit E_UNSAFE_FN_PTR_COERCION.
                //       Annotation overrides — do NOT register as unsafe-fn-ptr
                //       (let user proceed with broken assumption surfacing as
                //       call-site error).
                //   (c) RHS is non-unsafe-fn-ptr, ann = *unsafe fn(...):
                //       safe→unsafe widening — register (covariant; valid).
                //
                // Pattern restricted к simple Ident — destructure NOT supported
                // (fn pointers don't destructure meaningfully).
                let rhs_is_unsafe_fn_ptr = self.expr_produces_unsafe_fn_ptr(&d.value);
                let ann_is_unsafe_fn_ptr =
                    d.ty.as_ref().map_or(false, |t| t.is_unsafe_fn_pointer());
                let ann_is_safe_fn_ptr =
                    d.ty.as_ref().map_or(false, |t| t.is_safe_fn_pointer());
                if rhs_is_unsafe_fn_ptr && ann_is_safe_fn_ptr {
                    errors.push(Diagnostic::new(
                        "[E_UNSAFE_FN_PTR_COERCION] cannot coerce \
                         `*unsafe fn(...)` value into `*fn(...)` binding — \
                         safety attribute would be silently dropped (Plan 118.1.6 \
                         D216 amend). `#unsafe fn` body contains pointer ops \
                         без gating: callsite needs to know it must wrap call \
                         в `unsafe {{ ... }}`. Allowed direction: `*fn(...)` \
                         → `*unsafe fn(...)` (covariant widening — safe fn is \
                         always usable where unsafe fn expected). Fix: change \
                         binding annotation к `*unsafe fn(...)`, или extract \
                         non-#unsafe wrapper fn and take its address.".to_string(),
                        d.value.span,
                    ));
                }
                if let crate::ast::Pattern::Ident { name, .. } = &d.pattern {
                    // Annotation-driven registration: explicit `*unsafe fn(...)`
                    // (case (a) + (c)). Skip when annotation is safe-fn-ptr
                    // (case (b)) — error already emitted; downgrade RHS effect.
                    if ann_is_unsafe_fn_ptr {
                        self.register_unsafe_fn_ptr_var(name);
                    } else if rhs_is_unsafe_fn_ptr && !ann_is_safe_fn_ptr {
                        // Inference: RHS shape leaks unsafe-fn-ptr — register.
                        self.register_unsafe_fn_ptr_var(name);
                    }
                }
            }
            Stmt::Const(c) => {
                self.walk_expr(&c.value, errors);
            }
            Stmt::Assign { target, value, .. } => {
                // **Plan 118.5 V2 [M-118.5-write-safe-tracking] (2026-06-04):**
                // Write к unsafe T binding is SAFE (transitions value к valid
                // initialized state per D216 V2 §V2.3). Skip the Ident read
                // check for simple-Ident assign targets — `x = 42` doesn't
                // READ x. Non-Ident targets (`x.field = 42`, `arr[i] = 42`)
                // DO read x (to find field/element), so walk normally.
                use crate::ast::ExprKind;
                if !matches!(target.kind, ExprKind::Ident(_)) {
                    self.walk_expr(target, errors);
                }
                self.walk_expr(value, errors);
            }
            Stmt::Return { value: Some(e), .. } => self.walk_expr(e, errors),
            // Plan 118 Ф.3.5: остальные stmt-варианты не имеют sub-expressions
            // или covered downstream walks (`for`/`while`/`loop` body — Expr).
            _ => {}
        }
    }

    fn walk_expr(&mut self, e: &Expr, errors: &mut Vec<Diagnostic>) {
        use crate::ast::{ExprKind, UnOp};
        match &e.kind {
            // Plan 118 D216 §8 ENFORCEMENT POINT: AddrOf / Deref require
            // unsafe context (block с is_unsafe = true OR enclosing #unsafe fn).
            ExprKind::Unary { op: UnOp::AddrOf, operand } => {
                // Plan 118.6: &x is safe — no E_UNSAFE_REQUIRED for AddrOf.
                // Plan 118.7: unsafe { &x } no longer suppresses promote —
                // &x always uses escape analysis regardless of unsafe context.
                // Plan 118 A33: pointer ops banned в #realtime fn body
                // (D216 §20, D172 cross-ref) — & may allocate via auto-promote.
                if self.in_realtime {
                    errors.push(Diagnostic::new(
                        "[E_REALTIME_POINTER_OP] `&value` pointer creation \
                         forbidden в `#realtime fn` body (Plan 118 D216 §20 \
                         + Plan 113 D172). `&` может trigger heap allocation \
                         via escape-analysis auto-promote — violates \
                         realtime no-GC-pause guarantee.".to_string(),
                        e.span,
                    ));
                }
                self.walk_expr(operand, errors);
            }
            // Plan 118.7 D216 §4 amend: `raw &x` — сырой стек-адрес без
            // escape analysis. Требует unsafe {} (E_UNSAFE_REQUIRED вне него).
            ExprKind::Unary { op: UnOp::RawAddrOf, operand } => {
                if self.depth == 0 {
                    errors.push(Diagnostic::new(
                        "[E_UNSAFE_REQUIRED] `raw &x` requires unsafe context \
                         (Plan 118.7 D216 §4). `raw &x` produces a raw stack \
                         pointer without escape analysis or auto-promote — may \
                         be dangling after scope exit. Wrap в `unsafe { raw &x }` \
                         или mark enclosing fn `#unsafe`.".to_string(),
                        e.span,
                    ));
                }
                if self.in_realtime {
                    errors.push(Diagnostic::new(
                        "[E_REALTIME_POINTER_OP] `raw &x` forbidden в `#realtime fn` \
                         body (Plan 118 D216 §20 + Plan 113 D172).".to_string(),
                        e.span,
                    ));
                }
                self.walk_expr(operand, errors);
            }
            ExprKind::Unary { op: UnOp::Deref, operand } => {
                if self.depth == 0 {
                    errors.push(Diagnostic::new(
                        "[E_UNSAFE_REQUIRED] `*expr` pointer dereference \
                         requires unsafe context (Plan 118 D216 §8). Wrap \
                         expression в `unsafe { ... }` block, или mark \
                         enclosing fn `#unsafe`.".to_string(),
                        e.span,
                    ));
                }
                if self.in_realtime {
                    errors.push(Diagnostic::new(
                        "[E_REALTIME_POINTER_OP] `*expr` pointer dereference \
                         forbidden в `#realtime fn` body (Plan 118 D216 §20 \
                         + Plan 113 D172). Deref может GC trigger (если \
                         pointee references GC-tracked memory).".to_string(),
                        e.span,
                    ));
                }
                self.walk_expr(operand, errors);
            }
            ExprKind::Unary { operand, .. } => self.walk_expr(operand, errors),
            // Recurse в children.
            ExprKind::Block(b) => self.walk_block(b, errors),
            ExprKind::Binary { left, right, op } => {
                // Plan 118 A17 enforcement (D216 §6 cast/compare table):
                // pointer-pointer order comparison (`<`, `<=`, `>`, `>=`)
                // requires unsafe context. Pointer addresses are not stable
                // ordinals across allocations (GC-relocation invariance broken;
                // OS ASLR randomizes layout). Equality (`==`/`!=`) — safe.
                // V1 syntactic detection: both operands match expr_is_typed_pointer
                // (Unary AddrOf/Deref / As(*T) / Ident in ptr_vars). Full
                // type-aware enforcement — Session 4+ via infer_expr_type.
                let is_order_cmp = matches!(
                    op,
                    crate::ast::BinOp::Lt | crate::ast::BinOp::Le
                    | crate::ast::BinOp::Gt | crate::ast::BinOp::Ge
                );
                if is_order_cmp
                    && self.depth == 0
                    && self.expr_is_typed_pointer(left)
                    && self.expr_is_typed_pointer(right)
                {
                    errors.push(Diagnostic::new(
                        "[E_PTR_ORDER_COMPARE_REQUIRES_UNSAFE] pointer-pointer \
                         order comparison (`<`, `<=`, `>`, `>=`) requires unsafe \
                         context (Plan 118 D216 §6). Pointer addresses не stable \
                         ordinals: (1) GC-relocation invalidates ordering invariant; \
                         (2) OS ASLR randomizes address layout per process — \
                         comparison results не deterministic across runs. \
                         Equality `==`/`!=` — safe (identity check). \
                         Fix: wrap в `unsafe {{ ... }}` block если действительно \
                         нужно order-compare; rethink если это normal control flow.".to_string(),
                        e.span,
                    ));
                }
                self.walk_expr(left, errors);
                self.walk_expr(right, errors);
            }
            ExprKind::Call { func, args, .. } => {
                // Plan 118 A11 enforcement: detect call к #unsafe fn outside
                // unsafe context. Callee identification:
                //   - Ident (free fn) — lookup в unsafe_fns
                //   - Member receiver (method call) — Plan 118.1.5 closeout
                //     (2026-06-06): lookup method name в unsafe_fns. Note:
                //     unsafe_fns HashSet stores #unsafe free-fns + instance
                //     method names. Plan 138.2 [M-138-vec-bulk-parity]: #unsafe
                //     STATIC methods are now keyed `(type, method)` and matched
                //     only when the receiver is literally that type — closing
                //     the V1 bare-name collision (a `Vec[T] @fill`/`@compare`
                //     instance method no longer collides with `RawMem.fill`/
                //     `RawMem.compare` static externs).
                if self.depth == 0 {
                    let unsafe_callee_name: Option<String> = match &func.kind {
                        ExprKind::Ident(fname) if self.unsafe_fns.contains(fname) => {
                            Some(fname.clone())
                        }
                        // Static unsafe-method call `Type.m(...)`: receiver is
                        // the literal type identifier. Match the (type, method)
                        // pair exactly.
                        ExprKind::Member { obj, name: mname, .. }
                            if matches!(&obj.kind, ExprKind::Ident(tn)
                                if self.unsafe_static_methods
                                    .contains(&(tn.clone(), mname.clone()))) =>
                        {
                            Some(mname.clone())
                        }
                        // Instance unsafe-method call (or free-fn used as
                        // method): bare-name lookup in unsafe_fns. Static
                        // methods are intentionally excluded here (handled
                        // above by exact receiver match).
                        ExprKind::Member { name: mname, .. } if self.unsafe_fns.contains(mname) => {
                            Some(mname.clone())
                        }
                        // Plan 118.1.6 (2026-06-08): indirect call через
                        // *unsafe fn(...) binding — same gating as direct call.
                        // Callee shape `Ident(local)` where local ∈
                        // unsafe_fn_ptr_vars. Indirection adds no safety —
                        // pointee fn body still has unguarded pointer ops.
                        ExprKind::Ident(fname) if self.is_unsafe_fn_ptr_var(fname) => {
                            Some(fname.clone())
                        }
                        _ => None,
                    };
                    if let Some(fname) = unsafe_callee_name {
                        errors.push(Diagnostic::new(
                            format!(
                                "[E_UNSAFE_CALL_REQUIRES_WRAP] calling \
                                 `#unsafe fn {}` requires `unsafe {{ ... }}` \
                                 block wrap (Plan 118 D216 §9). #unsafe fn \
                                 body содержит pointer ops без unsafe-block \
                                 gating; callers must explicitly opt-in \
                                 к unsafe context (Rust pattern — no \
                                 effect propagation up the call stack).",
                                fname,
                            ),
                            func.span,
                        ));
                    }
                }
                self.walk_expr(func, errors);
                // Plan 118.5 V2 [M-118.5-arg-coerce-unsafe]: walk args в
                // in_call_arg mode — defers unsafe-T Ident read check к
                // precise check_unsafe_coerce_args (ConsumeCtx pass), which
                // knows callee param types and only errors on TRUE mismatches
                // (unsafe-T arg → non-unsafe param).
                let prev_in_call_arg = self.in_call_arg;
                self.in_call_arg = true;
                for a in args {
                    self.walk_expr(a.expr(), errors);
                }
                self.in_call_arg = prev_in_call_arg;
            }
            ExprKind::Member { obj, .. } => {
                // Plan 118.5 V2 [M-118.5-member-index-call-broader] (2026-06-04):
                // accessing a field on an unsafe-T binding reads the binding
                // value (to evaluate the .field/.method) — this counts as
                // unsafe read. Conservative scope: only fire if root Ident
                // is unambiguously в unsafe_t_vars.
                if self.depth == 0 && !self.in_call_arg {
                    if let Some(root) = unsafe_t_root_ident(obj) {
                        if self.is_unsafe_t_var(&root) {
                            errors.push(Diagnostic::new(
                                format!(
                                    "[E_UNSAFE_T_READ_REQUIRES_WRAP] member \
                                     access reads `unsafe T` binding `{}` — \
                                     requires unsafe context (Plan 118.5 V2 / \
                                     D216 V2 §V2.3). Field access evaluates \
                                     the binding value (possibly uninitialized). \
                                     Wrap access site в `unsafe {{ ... }}` block.",
                                    root,
                                ),
                                e.span,
                            ));
                        }
                    }
                }
                self.walk_expr(obj, errors)
            }
            ExprKind::Index { obj, index } => {
                // Plan 118 [M-118-ptr-index-unsafe] D216 §8: `ptr[i]` on a
                // typed pointer (`*T` / `*mut T` / `*unsafe T`) requires
                // `unsafe { }` context — identical semantics к `*ptr` deref
                // (unsafe { *(ptr + i) } → unsafe { ptr[i] }).
                //
                // Detection: syntactic `expr_is_typed_pointer(obj)` (covers
                // `&x`, `*p`, `e as *T`, Ident ∈ ptr_vars). `in_call_arg`
                // suppressed for the same reason as the Ident arm — precise
                // coerce pass handles ptr args to typed-ptr params without
                // false-positive gating.
                if self.expr_is_typed_pointer(obj) {
                    if self.depth == 0 {
                        errors.push(Diagnostic::new(
                            "[E_UNSAFE_REQUIRED] `ptr[i]` pointer index requires \
                             unsafe context (Plan 118 D216 §8, [M-118-ptr-index-unsafe]). \
                             Pointer index `ptr[i]` ≡ `*(ptr + i)` — derefs the \
                             pointer without bounds guarantee; semantically identical \
                             к explicit `*ptr` deref. Wrap в `unsafe {{ ... }}` block, \
                             или mark enclosing fn `#unsafe`. \
                             Example: `unsafe {{ @data[i] }}` instead of \
                             `*(@data + i)`.".to_string(),
                            e.span,
                        ));
                    }
                    if self.in_realtime {
                        errors.push(Diagnostic::new(
                            "[E_REALTIME_POINTER_OP] `ptr[i]` pointer index \
                             forbidden в `#realtime fn` body (Plan 118 D216 §20 \
                             + Plan 113 D172). Pointer index ≡ `*(ptr + i)` — \
                             deref может GC trigger, violates realtime \
                             no-GC-pause guarantee.".to_string(),
                            e.span,
                        ));
                    }
                }
                // Plan 118.5 V2 [M-118.5-member-index-call-broader]: index
                // access on unsafe-T binding reads the slot — needs unsafe.
                if self.depth == 0 && !self.in_call_arg {
                    if let Some(root) = unsafe_t_root_ident(obj) {
                        if self.is_unsafe_t_var(&root) {
                            errors.push(Diagnostic::new(
                                format!(
                                    "[E_UNSAFE_T_READ_REQUIRES_WRAP] index \
                                     access reads `unsafe T` binding `{}` — \
                                     requires unsafe context (Plan 118.5 V2 / \
                                     D216 V2 §V2.3). Indexing evaluates the \
                                     binding value (possibly uninitialized). \
                                     Wrap в `unsafe {{ ... }}` block.",
                                    root,
                                ),
                                e.span,
                            ));
                        }
                    }
                }
                self.walk_expr(obj, errors);
                self.walk_expr(index, errors);
            }
            ExprKind::If { cond, then, else_ } => {
                self.walk_expr(cond, errors);
                self.walk_block(then, errors);
                if let Some(eb) = else_ {
                    // ElseBranch has either block или another If — handle both
                    match eb {
                        crate::ast::ElseBranch::Block(b) => self.walk_block(b, errors),
                        crate::ast::ElseBranch::If(e) => self.walk_expr(e, errors),
                    }
                }
            }
            ExprKind::While { cond, body, .. } => {
                self.walk_expr(cond, errors);
                self.walk_block(body, errors);
            }
            ExprKind::Loop { body, .. } => self.walk_block(body, errors),
            ExprKind::For { iter, body, .. } => {
                self.walk_expr(iter, errors);
                self.walk_block(body, errors);
            }
            ExprKind::Match { scrutinee, arms, .. } => {
                self.walk_expr(scrutinee, errors);
                for arm in arms {
                    match &arm.body {
                        crate::ast::MatchArmBody::Expr(e) => self.walk_expr(e, errors),
                        crate::ast::MatchArmBody::Block(b) => self.walk_block(b, errors),
                    }
                }
            }
            ExprKind::As(inner, ty) => {
                // Plan 118 A24+A25: cast `expr as *fn(...)` checks:
                //   A24 — closure-with-env cast banned (E_CLOSURE_HAS_ENV)
                //   A25 — fn-with-Fail cast banned (E_CALLBACK_THROWS_OVER_C_ABI)
                //
                // Plan 118.5 V2 (2026-06-04): strip Mut/Unsafe/Readonly
                // modifier wrappers via strip_modifiers() to detect the
                // underlying Pointer regardless of right-binding wrappers
                // (e.g. `expr as mut * fn(...)` also matches).
                if let crate::ast::TypeRef::Pointer(inner_ty, _) = ty.strip_modifiers() {
                    if matches!(inner_ty.as_ref(), crate::ast::TypeRef::Func { .. }) {
                        // A24: closure literal с env captures — banned.
                        // V1 conservative: any ClosureLight/ClosureFull → reject.
                        // Free fn identifiers (Ident) — permissive (no env at
                        // top-level fns). Method values (Member с @ prefix) —
                        // also rejected (bound self captures receiver).
                        match &inner.kind {
                            ExprKind::ClosureLight { .. } | ExprKind::ClosureFull(_) => {
                                errors.push(Diagnostic::new(
                                    "[E_CLOSURE_HAS_ENV] cast `<closure> as \
                                     *fn(...)` forbidden — closure literals \
                                     может capture environment (Plan 118 \
                                     D216 §10). C ABI requires captureless \
                                     fn pointer. Workaround: extract closure \
                                     к top-level free fn, тогда cast \
                                     `free_fn as *fn(...)` valid.".to_string(),
                                    e.span,
                                ));
                            }
                            // Method value `obj.@method` — bound self capture
                            // (D11 Ф.4). For V1 conservative reject; bare
                            // type-level `Type.@method` (unbound method) — OK
                            // когда detected through parent expr context.
                            ExprKind::Member { name, .. } if name.starts_with('@') => {
                                errors.push(Diagnostic::new(
                                    format!(
                                        "[E_CLOSURE_HAS_ENV] cast method value \
                                         `{}` as *fn(...) forbidden — bound \
                                         method captures receiver (self) \
                                         (Plan 118 D216 §10). Use static \
                                         fn (free function) для FFI callback \
                                         registration.",
                                        name,
                                    ),
                                    e.span,
                                ));
                            }
                            _ => {}
                        }
                        // A25: source fn has Fail effect — banned.
                        if let ExprKind::Ident(fname) = &inner.kind {
                            if self.fail_fns.contains(fname) {
                                errors.push(Diagnostic::new(
                                    format!(
                                        "[E_CALLBACK_THROWS_OVER_C_ABI] cast \
                                         `{} as *fn(...)` forbidden — source \
                                         fn declares Fail effect (Plan 118 \
                                         D216 §10, §20). C ABI не propagates \
                                         Nova exception machinery; callback \
                                         throwing across boundary = UB. \
                                         Workaround: wrap fn body в `catch` \
                                         expression, return sentinel value.",
                                        fname,
                                    ),
                                    e.span,
                                ));
                            }
                        }
                    }
                }
                // **Plan 118.5 V2 [M-118.5-narrow-cast] (2026-06-04):** narrow
                // cast `unsafe T → T` (strip Unsafe wrapper from value type) is
                // a value-level assertion of validity. Requires `unsafe { }`
                // context per D216 V2 §V2.3 — caller asserts the value is
                // actually initialized.
                //
                // Detection: inner is `Ident` registered в `unsafe_t_vars` AND
                // target ty (after strip_modifiers) is NOT an Unsafe wrapper
                // (so cast narrows OUT of unsafe). If depth==0, emit specific
                // narrow-cast error AND skip the inner walk (else generic
                // E_UNSAFE_T_READ_REQUIRES_WRAP would also fire — double error).
                let mut narrow_handled = false;
                if self.depth == 0 {
                    if let ExprKind::Ident(name) = &inner.kind {
                        if self.is_unsafe_t_var(name)
                            && !matches!(ty.strip_modifiers(),
                                crate::ast::TypeRef::Unsafe(_, _))
                        {
                            errors.push(Diagnostic::new(
                                format!(
                                    "[E_UNSAFE_T_NARROW_REQUIRES_UNSAFE] narrow \
                                     cast from `unsafe T` binding `{}` к non-\
                                     unsafe type requires `unsafe {{ ... }}` \
                                     context (Plan 118.5 V2 / D216 V2 §V2.3). \
                                     Caller must assert the value is actually \
                                     initialized before narrowing. Wrap entire \
                                     cast expression: `unsafe {{ {} as T }}`. \
                                     Write к unsafe T binding is safe \
                                     (transitions к valid); only the explicit \
                                     drop of the `unsafe` wrapper requires \
                                     unsafe context assertion.",
                                    name, name,
                                ),
                                e.span,
                            ));
                            narrow_handled = true;
                        }
                    }
                }
                if !narrow_handled {
                    self.walk_expr(inner, errors);
                }
            }
            ExprKind::Is(inner, _) | ExprKind::Try(inner) | ExprKind::Bang(inner) => {
                self.walk_expr(inner, errors);
            }
            // Plan 83 fiber-runtime constructs — body is Block.
            ExprKind::Detach(body) | ExprKind::Blocking(body) => self.walk_block(body, errors),
            // Plan 118 A28: `"... ${expr} ..."` interpolation. Если выражение
            // часть — typed pointer (`&v` / `*p` / `e as *T` / locale-ptr-var),
            // emit E_PTR_NO_DISPLAY_USE_DEBUG_STR. D216 §15 motivation: address
            // disclosure (security leak vector) + GC mover invalidates raw
            // address in str (stale value). Pointer Debug fmt — opt-in только
            // через `.to_debug_str()` (unsafe context — A27).
            ExprKind::InterpolatedStr { parts } => {
                for p in parts {
                    if let crate::ast::InterpStrPart::Expr { expr: ex, spec } = p {
                        // **Plan 91.14 Ф.5 (D229) + Plan 152.7-B (D258):** ban
                        // display-formatted pointers. Explicit ${ptr:?} (Debug)
                        // is the intended opt-in path — caller acknowledges
                        // address disclosure через Debug invocation. A rich spec
                        // (`Spec`) is display-class unless its kind is Debug, so
                        // it's banned too. Still requires unsafe context
                        // (enforced by `*T` impl).
                        let spec_is_display = match spec {
                            crate::ast::FormatSpec::None => true,
                            crate::ast::FormatSpec::Debug => false,
                            crate::ast::FormatSpec::Spec(s) => {
                                !matches!(s.kind, crate::ast::format_spec::Kind::Debug)
                            }
                        };
                        if spec_is_display && self.expr_is_typed_pointer(ex) {
                            errors.push(Diagnostic::new(
                                "[E_PTR_NO_DISPLAY_USE_DEBUG_STR] typed pointer \
                                 value cannot be interpolated в str через bare \
                                 `\"${...}\"` (Plan 118 D216 §15). Pointer \
                                 Display не auto-emitted: (1) address disclosure \
                                 leaks security-sensitive info; (2) GC mover \
                                 invalidates raw address — interpolated value \
                                 становится stale. Fix: use `${p:?}` syntax \
                                 (Plan 91.14 D229 Ф.5) внутри unsafe { } block \
                                 — explicit opt-in для debug-formatted ptr.".to_string(),
                                ex.span,
                            ));
                        }
                        self.walk_expr(ex, errors);
                    }
                }
            }
            // **Plan 118.5 Ф.4 / D216 V2 §V2.3 (2026-06-04):** detect read
            // of `unsafe T` binding outside unsafe { } context. Write safe
            // (transitions к valid); read requires unsafe wrap because value
            // may be uninitialized (MaybeUninit-style semantic).
            //
            // Detection: Ident expression resolving к binding registered в
            // unsafe_t_vars. Member/Index/Call access on unsafe-T binding
            // catches naturally via the Member/Index/Call arms recursing into
            // the Ident base (the access ITSELF is the read).
            ExprKind::Ident(name) => {
                // Plan 118.5 V2 [M-118.5-arg-coerce-unsafe]: when walking
                // Call args, defer unsafe-T read check к the precise
                // ConsumeCtx check_unsafe_coerce_args (which knows callee
                // param types — matched-param pass should NOT error).
                if self.depth == 0 && !self.in_call_arg && self.is_unsafe_t_var(name) {
                    errors.push(Diagnostic::new(
                        format!(
                            "[E_UNSAFE_T_READ_REQUIRES_WRAP] reading `unsafe T` \
                             binding `{}` requires unsafe context (Plan 118.5 \
                             Ф.4 / D216 V2 §V2.3). `unsafe T` values may be \
                             uninitialized — read без prior write is UB. Fix: \
                             wrap read site в `unsafe {{ ... }}` block, или \
                             use explicit narrow `unsafe {{ {} as T }}` after \
                             initialization. Write to `unsafe T` slot — safe \
                             (transitions к valid initialized state).",
                            name, name,
                        ),
                        e.span,
                    ));
                }
            }
            // Plan 118 Ф.3.5 leaf nodes (literals, idents, paths) — no children.
            // Other variants covered through their child expressions (handler
            // bodies, closure lits etc.) — V1 scaffold не deep-walks все edge
            // cases. Closures + handler bodies — Ф.3.5 follow-on extension.
            _ => {}
        }
    }
}

#[cfg(test)]
mod primitive_mut_method_tests {
    //! Plan 128 Ф.3: `E_PRIMITIVE_MUT_METHOD` rejects `fn <primitive> mut
    //! @method(...)` declarations. Parser permits the form; codegen would
    //! silently no-op the mutation (primitive receiver passed by value).
    //! Type-checker pass turns the silent footgun into a hard error.
    //!
    //! Coverage:
    //!   1. `fn str  mut @hack`  → E_PRIMITIVE_MUT_METHOD (str).
    //!   2. `fn int  mut @inc`   → E_PRIMITIVE_MUT_METHOD (int).
    //!   3. `fn bool mut @flip`  → E_PRIMITIVE_MUT_METHOD (bool).
    //!   4. `fn f64  mut @scale` → E_PRIMITIVE_MUT_METHOD (f64).
    //!   5. `fn str      @len`        — accepted (ro method on primitive).
    //!   6. `fn UserType mut @method` — accepted (non-primitive receiver).
    //!
    //! Tests work directly on the AST level via `is_primitive_leaf` +
    //! `check_primitive_mut_method` to stay independent of parser/lexer
    //! evolution. Receiver/FnDecl/Module are built by hand using
    //! `Default` impls (`FnDecl: Default`, `FnBody: Default = External`),
    //! mirroring the helper-construction pattern used by `name_res_tests`
    //! and other in-mod test bundles.
    use super::*;
    use crate::ast::{FnBody, FnDecl, Item, Module, Receiver, ReceiverKind};
    use crate::diag::Span;

    fn dummy_span() -> Span {
        Span { start: 0, end: 0, file_id: MAIN_FILE_ID }
    }

    fn make_recv(type_name: &str, mutable: bool, kind: ReceiverKind) -> Receiver {
        Receiver {
            type_name: type_name.to_string(),
            generics: Vec::new(),
            carrier_bounds: Vec::new(),
            receiver_ty: None,
            kind,
            mutable,
            consume: false,
            span: dummy_span(),
        }
    }

    fn make_method(name: &str, recv: Receiver) -> FnDecl {
        FnDecl {
            name: name.to_string(),
            receiver: Some(recv),
            body: FnBody::External,
            span: dummy_span(),
            ..Default::default()
        }
    }

    fn make_module(fns: Vec<FnDecl>) -> Module {
        Module {
            name: vec!["test".to_string()],
            imports: Vec::new(),
            items: fns.into_iter().map(Item::Fn).collect(),
            attrs: Vec::new(),
            contract_opt_out: Default::default(),
            doc_attrs: Vec::new(),
            span: dummy_span(),
            peer_files: Vec::new(),
            doc: None,
        }
    }

    fn run_check(module: &Module) -> Vec<Diagnostic> {
        let mut errors = Vec::new();
        check_primitive_mut_method(module, &mut errors);
        errors
    }

    fn assert_rejected(diags: &[Diagnostic], ty: &str, method: &str) {
        assert_eq!(diags.len(), 1,
            "expected exactly one E_PRIMITIVE_MUT_METHOD for `fn {} mut @{}`, \
             got {} diags: {:#?}", ty, method, diags.len(), diags);
        let msg = &diags[0].message;
        assert!(msg.contains("E_PRIMITIVE_MUT_METHOD"),
            "diag must carry E_PRIMITIVE_MUT_METHOD tag; got: {}", msg);
        assert!(msg.contains(ty),
            "diag must mention primitive name `{}`; got: {}", ty, msg);
        assert!(msg.contains(method),
            "diag must mention method name `{}`; got: {}", method, msg);
        // Suggestion must point users to the pure-function alternative
        // (`fn name(x T) -> T`), not silently leave them stuck.
        assert!(msg.contains("pure function") || msg.contains("returning a new value"),
            "diag must include the pure-function suggestion; got: {}", msg);
    }

    // ─── Negative cases: primitives reject mut-methods ────────────────────

    #[test]
    fn rejects_str_mut_method() {
        let m = make_module(vec![make_method(
            "hack",
            make_recv("str", true, ReceiverKind::Instance),
        )]);
        let diags = run_check(&m);
        assert_rejected(&diags, "str", "hack");
    }

    #[test]
    fn rejects_int_mut_method() {
        let m = make_module(vec![make_method(
            "inc",
            make_recv("int", true, ReceiverKind::Instance),
        )]);
        let diags = run_check(&m);
        assert_rejected(&diags, "int", "inc");
    }

    #[test]
    fn rejects_bool_mut_method() {
        let m = make_module(vec![make_method(
            "flip",
            make_recv("bool", true, ReceiverKind::Instance),
        )]);
        let diags = run_check(&m);
        assert_rejected(&diags, "bool", "flip");
    }

    #[test]
    fn rejects_f64_mut_method() {
        let m = make_module(vec![make_method(
            "scale",
            make_recv("f64", true, ReceiverKind::Instance),
        )]);
        let diags = run_check(&m);
        assert_rejected(&diags, "f64", "scale");
    }

    // ─── Positive cases: legal method declarations pass through ───────────

    #[test]
    fn accepts_str_ro_method() {
        // `fn str @len() -> int` — no `mut` on receiver, just an instance
        // method on a primitive. Plan 91 explicitly permits this shape
        // (see nova_tests/syntax/methods_on_primitives.nv).
        let m = make_module(vec![make_method(
            "len",
            make_recv("str", false, ReceiverKind::Instance),
        )]);
        let diags = run_check(&m);
        assert!(diags.is_empty(),
            "ro instance method on primitive must NOT trigger \
             E_PRIMITIVE_MUT_METHOD; got: {:#?}", diags);
    }

    #[test]
    fn accepts_user_type_mut_method() {
        // `fn UserType mut @method()` — non-primitive receiver. D215/D226
        // path is responsible for the pointer-ABI plumbing; this pass
        // must stay out of its way.
        let m = make_module(vec![make_method(
            "method",
            make_recv("UserType", true, ReceiverKind::Instance),
        )]);
        let diags = run_check(&m);
        assert!(diags.is_empty(),
            "mut-receiver method on user-defined type must NOT trigger \
             E_PRIMITIVE_MUT_METHOD; got: {:#?}", diags);
    }

    // ─── is_primitive_leaf classifier — coverage of the full primitive set ─

    #[test]
    fn is_primitive_leaf_covers_full_primitive_set() {
        // Sweep the entire primitive family — any gap here = silent escape
        // hatch for the mut-method footgun.
        // Plan 133: usize/isize removed from primitives.
        // Plan 134: "ptr" and "nova_ptr" removed from primitive leaf set.
        for ty in &[
            "int", "uint",
            "i8", "i16", "i32", "i64",
            "u8", "u16", "u32", "u64",
            "f32", "f64",
            "bool", "char", "str",
            "Unit",
        ] {
            assert!(is_primitive_leaf(ty),
                "expected `{}` to be classified as primitive leaf", ty);
        }
    }

    #[test]
    fn is_primitive_leaf_rejects_user_and_generic_names() {
        for ty in &["UserType", "T", "Option", "Result", "List", "Map",
                    "INT", "Str", "Bool", ""] {
            assert!(!is_primitive_leaf(ty),
                "expected `{}` to NOT be classified as primitive leaf", ty);
        }
    }

    // ─── Edge cases ───────────────────────────────────────────────────────

    #[test]
    fn ignores_static_method_even_if_mutable_flag_set() {
        // Static methods (`fn T.foo()`) can't legitimately carry `mut` on
        // the receiver — there's no receiver value. Guard against accidental
        // future parser changes that might leak the flag onto Static; the
        // check should simply not fire (other passes handle the structural
        // error).
        let m = make_module(vec![make_method(
            "ctor",
            make_recv("str", true, ReceiverKind::Static),
        )]);
        let diags = run_check(&m);
        assert!(diags.is_empty(),
            "static-kind receiver must be skipped even if `mutable` is set; \
             got: {:#?}", diags);
    }

    #[test]
    fn reports_each_offending_method_independently() {
        // Two illegal methods in the same module must each get their own
        // diagnostic — no dedup/coalesce.
        let m = make_module(vec![
            make_method("hack",  make_recv("str", true, ReceiverKind::Instance)),
            make_method("inc",   make_recv("int", true, ReceiverKind::Instance)),
            make_method("len",   make_recv("str", false, ReceiverKind::Instance)),
        ]);
        let diags = run_check(&m);
        assert_eq!(diags.len(), 2,
            "expected 2 diagnostics (str-hack + int-inc), str-len accepted; \
             got: {:#?}", diags);
        let joined = diags.iter().map(|d| d.message.as_str())
            .collect::<Vec<_>>().join("\n");
        assert!(joined.contains("hack"), "missing hack diag: {}", joined);
        assert!(joined.contains("inc"),  "missing inc diag: {}", joined);
        assert!(!joined.contains("len"), "len must NOT be flagged: {}", joined);
    }
}

#[cfg(test)]
mod named_tuple_ctor_infer_tests {
    //! Plan 128.1 Ф.2 — D215 NamedTuple constructor type-producing path.
    //!
    //! Bug: `infer_expr_type(Call { func: Ident("Vec3"), .. })` returned
    //! `None` для NamedTuple types because the `matches!` arm only listed
    //! `TypeDeclKind::Newtype | TypeDeclKind::Alias`. Without inferred
    //! type, `let v Vec3 = Vec3(1,2,3)` binding stored `Unknown` в scope,
    //! cascading в default-int fallback при array-literal element infer.
    //!
    //! Coverage:
    //!   1. NamedTuple ctor → Named(Vec3) — Бug fix.
    //!   2. Newtype ctor — regression preserved (existing behaviour).
    //!   3. Sum variant ctor (`Red(int)` from `type Color | Red(int) | ...`)
    //!      — must STAY Unknown (variant names aren't top-level types).
    //!      Сritical regression guard: без этого fix теоретически мог бы
    //!      случайно отнести variant ctor к производному типу через
    //!      `self.types.get(...)`.
    use super::*;
    use crate::ast::{
        Expr, ExprKind, NamedTupleField, SumVariant, SumVariantKind, TypeDecl,
        TypeDeclKind, TypeRef,
    };
    use crate::diag::Span;

    fn dummy_span() -> Span {
        Span { start: 0, end: 0, file_id: MAIN_FILE_ID }
    }

    fn make_named_tuple(name: &str, fields: Vec<(&str, &str)>) -> TypeDecl {
        let nt_fields = fields.into_iter().map(|(fname, fty)| NamedTupleField {
            name: fname.to_string(),
            ty: TypeRef::Named {
                path: vec![fty.to_string()],
                generics: Vec::new(),
                span: dummy_span(),
            },
            span: dummy_span(),
            priv_field: false,
            priv_module_field: false,
            visible_to: Vec::new(),
            default: None,
        }).collect();
        TypeDecl {
            name: name.to_string(),
            kind: TypeDeclKind::NamedTuple(nt_fields),
            span: dummy_span(),
            ..Default::default()
        }
    }

    fn make_newtype(name: &str, inner: &str) -> TypeDecl {
        let inner_tr = TypeRef::Named {
            path: vec![inner.to_string()],
            generics: Vec::new(),
            span: dummy_span(),
        };
        TypeDecl {
            name: name.to_string(),
            kind: TypeDeclKind::Newtype(inner_tr),
            span: dummy_span(),
            ..Default::default()
        }
    }

    fn make_sum_with_tuple_variant(
        sum_name: &str,
        variant_name: &str,
        payload_type: &str,
    ) -> TypeDecl {
        let payload = TypeRef::Named {
            path: vec![payload_type.to_string()],
            generics: Vec::new(),
            span: dummy_span(),
        };
        let variant = SumVariant {
            name: variant_name.to_string(),
            kind: SumVariantKind::Tuple(vec![payload]),
            discriminant: None,
            span: dummy_span(),
        };
        TypeDecl {
            name: sum_name.to_string(),
            kind: TypeDeclKind::Sum(vec![variant]),
            span: dummy_span(),
            ..Default::default()
        }
    }

    fn make_module_with_types(types: Vec<TypeDecl>) -> Module {
        Module {
            name: vec!["test".to_string()],
            imports: Vec::new(),
            items: types.into_iter().map(Item::Type).collect(),
            attrs: Vec::new(),
            contract_opt_out: Default::default(),
            doc_attrs: Vec::new(),
            span: dummy_span(),
            peer_files: Vec::new(),
            doc: None,
        }
    }

    fn make_ctor_call(ctor_name: &str) -> Expr {
        // `Vec3(1, 2, 3)` shape — args contents don't matter для type infer
        // (Call arm только смотрит на func identity).
        Expr {
            kind: ExprKind::Call {
                func: Box::new(Expr {
                    kind: ExprKind::Ident(ctor_name.to_string()),
                    span: dummy_span(), id: crate::ast::ExprId::UNSET,
                }),
                args: Vec::new(),
                trailing: None,
            },
            span: dummy_span(), id: crate::ast::ExprId::UNSET,
        }
    }

    fn infer_ctor(ctx: &TypeCheckCtx<'_>, ctor_name: &str) -> Option<TypeRef> {
        let call = make_ctor_call(ctor_name);
        let scope = HashMap::new();
        ctx.infer_expr_type(&call, &scope)
    }

    #[test]
    fn infer_call_named_tuple_returns_type() {
        // Plan 128.1 Ф.2 — PRIMARY FIX. `Vec3(1,2,3)` где Vec3 = NamedTuple
        // должен возвращать Named(Vec3), не None.
        let m = make_module_with_types(vec![
            make_named_tuple("Vec3", vec![("x", "f64"), ("y", "f64"), ("z", "f64")]),
        ]);
        let arena = FnDeclArena::new();
        let sig = crate::sig_registry::SigRegistry::build_base(&m);
        let ctx = TypeCheckCtx::build(&m, &arena, &sig);
        let inferred = infer_ctor(&ctx, "Vec3");
        match inferred {
            Some(TypeRef::Named { path, .. }) => {
                assert_eq!(path, vec!["Vec3".to_string()],
                    "NamedTuple ctor must infer as its own Named type; got path {:?}",
                    path);
            }
            other => panic!(
                "Plan 128.1 Ф.2: expected Some(Named(Vec3)) для NamedTuple ctor; \
                 got {:?}. Без fix'а type-производство NamedTuple ctor падало \
                 в default-int.",
                other,
            ),
        }
    }

    #[test]
    fn infer_call_newtype_regression_preserved() {
        // Regression guard: existing Plan 115 D214 [M-115-newtype-constructor]
        // path не должен сломаться от добавления NamedTuple-arm'а.
        let m = make_module_with_types(vec![
            make_newtype("SqHandle", "ptr"),
        ]);
        let arena = FnDeclArena::new();
        let sig = crate::sig_registry::SigRegistry::build_base(&m);
        let ctx = TypeCheckCtx::build(&m, &arena, &sig);
        let inferred = infer_ctor(&ctx, "SqHandle");
        match inferred {
            Some(TypeRef::Named { path, .. }) => {
                assert_eq!(path, vec!["SqHandle".to_string()],
                    "Newtype ctor infer must remain Named(SqHandle)");
            }
            other => panic!("Newtype ctor regression: expected Named(SqHandle), got {:?}", other),
        }
    }

    #[test]
    fn infer_call_sum_variant_stays_unknown() {
        // CRITICAL REGRESSION GUARD: sum variants хранятся ВНУТРИ
        // TypeDeclKind::Sum(...), не как top-level types. `self.types.get("Red")`
        // должен вернуть None — variant ctor НЕ попадает в matches!-arm,
        // даже если он был extended NamedTuple-кейсом.
        //
        // Если этот тест ломается → variant ctor неверно отнесён к
        // top-level type, инфер вернёт `Named(Red)` вместо None, и
        // assignable() начнёт сравнивать `Red` (несуществующий тип) с
        // expected `Color` → ложный E_TYPE_MISMATCH.
        let m = make_module_with_types(vec![
            make_sum_with_tuple_variant("Color", "Red", "int"),
        ]);
        let arena = FnDeclArena::new();
        let sig = crate::sig_registry::SigRegistry::build_base(&m);
        let ctx = TypeCheckCtx::build(&m, &arena, &sig);
        // `Red(1)` — variant ctor; `Red` НЕ в `ctx.types`.
        let inferred = infer_ctor(&ctx, "Red");
        assert!(inferred.is_none(),
            "Sum variant ctor `Red(int)` MUST infer as None (variant name \
             не top-level type); got Some({:?}). Plan 128.1 Ф.2 NamedTuple \
             arm не должен случайно захватить variant ctor.",
            inferred);
        // Sum type itself тоже не должен инфериться через ctor-call —
        // у sum нет positional ctor с тем же именем (Color(...) — invalid).
        // Но `self.types.get("Color")` существует с kind = Sum;
        // matches! arm НЕ списка Sum → fallthrough к None. Подтверждаем.
        let color_inferred = infer_ctor(&ctx, "Color");
        assert!(color_inferred.is_none(),
            "Sum type name used as ctor must NOT type-produce \
             (Color = Sum, не Newtype/Alias/NamedTuple); got {:?}",
            color_inferred);
    }

    // ────────────────────────────────────────────────────────────────────
    // Plan 126.2 Ф.1: synthesized auto-derive methods registered in
    // method_table.
    // ────────────────────────────────────────────────────────────────────

    /// NamedTuple of primitive fields with `#impl(<protocols>)`.
    fn make_named_tuple_impl(
        name: &str,
        fields: Vec<(&str, &str)>,
        protocols: &[&str],
    ) -> TypeDecl {
        let mut td = make_named_tuple(name, fields);
        td.impl_protocols = protocols.iter().map(|p| p.to_string()).collect();
        td
    }

    /// Helper: true если у типа есть метод с данным именем (base ∪ synth).
    /// U.2.3.3: was `ctx.method_table` (= base+synth); now via synth-aware helper.
    fn mt_has(ctx: &TypeCheckCtx<'_>, ty: &str, method: &str) -> bool {
        ctx.t_provides_method(ty, method)
    }

    /// Helper: первый FnDecl метода типа по имени (base ∪ synth).
    fn mt_fn<'c>(ctx: &'c TypeCheckCtx<'_>, ty: &str, method: &str) -> Option<&'c FnDecl> {
        ctx.find_method_decl(ty, method)
    }

    #[test]
    fn synth_equal_registered_in_method_table() {
        let m = make_module_with_types(vec![
            make_named_tuple_impl("P", vec![("x", "int"), ("y", "int")], &["Equal"]),
        ]);
        let arena = FnDeclArena::new();
        let sig = crate::sig_registry::SigRegistry::build_base(&m);
        let ctx = TypeCheckCtx::build(&m, &arena, &sig);
        assert!(mt_has(&ctx, "P", "equal"),
            "synthesized Equal.equal must be registered in method_table[P]");
    }

    #[test]
    fn synth_hash_registered_in_method_table() {
        let m = make_module_with_types(vec![
            make_named_tuple_impl("P", vec![("x", "int")], &["Hash"]),
        ]);
        let arena = FnDeclArena::new();
        let sig = crate::sig_registry::SigRegistry::build_base(&m);
        let ctx = TypeCheckCtx::build(&m, &arena, &sig);
        assert!(mt_has(&ctx, "P", "hash"),
            "synthesized Hash.hash must be registered in method_table[P]");
    }

    #[test]
    fn synth_clone_registered_in_method_table() {
        let m = make_module_with_types(vec![
            make_named_tuple_impl("P", vec![("x", "int")], &["Clone"]),
        ]);
        let arena = FnDeclArena::new();
        let sig = crate::sig_registry::SigRegistry::build_base(&m);
        let ctx = TypeCheckCtx::build(&m, &arena, &sig);
        assert!(mt_has(&ctx, "P", "clone"),
            "synthesized Clone.clone must be registered in method_table[P]");
    }

    #[test]
    fn synth_compare_registered_in_method_table() {
        let m = make_module_with_types(vec![
            make_named_tuple_impl("P", vec![("x", "int")], &["Compare"]),
        ]);
        let arena = FnDeclArena::new();
        let sig = crate::sig_registry::SigRegistry::build_base(&m);
        let ctx = TypeCheckCtx::build(&m, &arena, &sig);
        assert!(mt_has(&ctx, "P", "compare"),
            "synthesized Compare.compare must be registered in method_table[P]");
    }

    #[test]
    fn synth_display_registered_in_method_table() {
        let m = make_module_with_types(vec![
            make_named_tuple_impl("P", vec![("x", "int")], &["Display"]),
        ]);
        let arena = FnDeclArena::new();
        let sig = crate::sig_registry::SigRegistry::build_base(&m);
        let ctx = TypeCheckCtx::build(&m, &arena, &sig);
        assert!(mt_has(&ctx, "P", "display"),
            "synthesized Display.display must be registered in method_table[P]");
    }

    #[test]
    fn synth_all_six_protocols_registered_together() {
        let m = make_module_with_types(vec![
            make_named_tuple_impl(
                "P",
                vec![("x", "int"), ("y", "int")],
                &["Equal", "Hash", "Clone", "Compare", "Display", "Debug"],
            ),
        ]);
        let arena = FnDeclArena::new();
        let sig = crate::sig_registry::SigRegistry::build_base(&m);
        let ctx = TypeCheckCtx::build(&m, &arena, &sig);
        for method in ["equal", "hash", "clone", "compare", "display", "debug"] {
            assert!(mt_has(&ctx, "P", method),
                "synthesized method `{}` must be registered in method_table[P]",
                method);
        }
    }

    #[test]
    fn synth_methods_marked_compiler_generated() {
        let m = make_module_with_types(vec![
            make_named_tuple_impl("P", vec![("x", "int")], &["Equal", "Hash"]),
        ]);
        let arena = FnDeclArena::new();
        let sig = crate::sig_registry::SigRegistry::build_base(&m);
        let ctx = TypeCheckCtx::build(&m, &arena, &sig);
        for method in ["equal", "hash"] {
            let fd = mt_fn(&ctx, "P", method)
                .unwrap_or_else(|| panic!("method `{}` not registered", method));
            assert!(fd.compiler_generated,
                "synthesized method `{}` must carry compiler_generated = true",
                method);
            assert_eq!(fd.name, method);
            assert!(fd.receiver.as_ref().map_or(false, |r| r.type_name == "P"),
                "synthesized method receiver must target type P");
        }
    }

    #[test]
    fn no_synth_without_impl_annotation() {
        // Type без `#impl(...)` — никаких synthesized методов.
        let m = make_module_with_types(vec![
            make_named_tuple("P", vec![("x", "int")]),
        ]);
        let arena = FnDeclArena::new();
        let sig = crate::sig_registry::SigRegistry::build_base(&m);
        let ctx = TypeCheckCtx::build(&m, &arena, &sig);
        assert!(!mt_has(&ctx, "P", "equal"),
            "no `#impl` annotation → no synthesized methods in method_table");
        assert!(ctx.synth_methods.get("P").map_or(true, |m| m.is_empty()),
            "synth_methods[P] must be empty/absent without #impl");
    }

    #[test]
    fn no_synth_when_user_provides_explicit_method() {
        // User wins: explicit `fn P @equal(...)` → synthesis skipped, no
        // duplicate. We register the user fn manually via an Item::Fn.
        let p = make_named_tuple_impl("P", vec![("x", "int")], &["Equal"]);
        let user_equal = FnDecl {
            name: "equal".to_string(),
            receiver: Some(Receiver {
                type_name: "P".to_string(),
                generics: vec![],
                carrier_bounds: vec![],
                receiver_ty: None,
                kind: ReceiverKind::Instance,
                mutable: false,
                consume: false,
                span: dummy_span(),
            }),
            params: vec![],
            body: FnBody::External,
            span: dummy_span(),
            compiler_generated: false,
            ..FnDecl::default()
        };
        let m = Module {
            name: vec!["test".to_string()],
            imports: Vec::new(),
            items: vec![Item::Type(p), Item::Fn(user_equal)],
            attrs: Vec::new(),
            contract_opt_out: Default::default(),
            doc_attrs: Vec::new(),
            span: dummy_span(),
            peer_files: Vec::new(),
            doc: None,
        };
        let arena = FnDeclArena::new();
        let sig = crate::sig_registry::SigRegistry::build_base(&m);
        let ctx = TypeCheckCtx::build(&m, &arena, &sig);
        let fns = ctx.method_overloads("P", "equal")
            .expect("equal must be registered (user-provided)");
        assert_eq!(fns.len(), 1,
            "user-provided equal must not be duplicated by synthesis");
        assert!(!fns[0].compiler_generated,
            "registered equal must be the USER fn (compiler_generated = false), \
             synthesis must be skipped when user provides explicit method");
    }
}

#[cfg(test)]
mod chain_root_mut_check_tests {
    //! Plan 128.2 Ф.1 — `lvalue_root_ident` + chain-receiver mut enforcement.
    //!
    //! Coverage matrix:
    //!   1. `lvalue_root_ident` pure helper:
    //!      - Ident root → Some(name).
    //!      - Member chain → walks к корневому Ident.
    //!      - Index chain → walks к корневому Ident.
    //!      - Mixed chain (Member + Index) → walks к корневому Ident.
    //!      - rvalue base (Call/Lit) → None.
    //!      - SelfAccess → None (НЕ binding, обрабатывается отдельным path'ом).
    //!   2. `is_builtin_mut_method`: builtin-list membership check.
    //!   3. End-to-end через `check_module` (parser → check) — chain-aware
    //!      receiver mut check для `ro` binding, `mut` binding, ro param,
    //!      mut param, mixed Member+Index chain, и rvalue-chain (no enforcement).
    //!
    //! Pure-helper tests работают напрямую с AST (synthetic Expr). E2e
    //! тесты используют parser + check_module — это позволяет проверять
    //! `param_mut` / `local_mut` integration без ручной набивки ConsumeCtx.
    use super::*;
    use crate::ast::{Expr, ExprKind, TypeRef};
    use crate::diag::Span;

    fn dummy_span() -> Span {
        Span { start: 0, end: 0, file_id: MAIN_FILE_ID }
    }

    fn ident(name: &str) -> Expr {
        Expr { kind: ExprKind::Ident(name.to_string()), span: dummy_span(), id: crate::ast::ExprId::UNSET }
    }

    fn member(obj: Expr, field: &str) -> Expr {
        Expr {
            kind: ExprKind::Member {
                obj: Box::new(obj),
                name: field.to_string(),
            },
            span: dummy_span(), id: crate::ast::ExprId::UNSET,
        }
    }

    fn index(obj: Expr, idx: Expr) -> Expr {
        Expr {
            kind: ExprKind::Index {
                obj: Box::new(obj),
                index: Box::new(idx),
            },
            span: dummy_span(), id: crate::ast::ExprId::UNSET,
        }
    }

    fn int_lit(n: i64) -> Expr {
        Expr { kind: ExprKind::IntLit(n), span: dummy_span(), id: crate::ast::ExprId::UNSET }
    }

    fn turbofish(base: Expr, args: Vec<TypeRef>) -> Expr {
        Expr {
            kind: ExprKind::TurboFish {
                base: Box::new(base),
                type_args: args,
            },
            span: dummy_span(), id: crate::ast::ExprId::UNSET,
        }
    }

    fn self_access() -> Expr {
        Expr { kind: ExprKind::SelfAccess, span: dummy_span(), id: crate::ast::ExprId::UNSET }
    }

    fn call(func: Expr) -> Expr {
        Expr {
            kind: ExprKind::Call {
                func: Box::new(func),
                args: vec![],
                trailing: None,
            },
            span: dummy_span(), id: crate::ast::ExprId::UNSET,
        }
    }

    // ─── Pure-helper: lvalue_root_ident ────────────────────────────────

    #[test]
    fn pure_predicate_root_is_ident_itself() {
        let e = ident("b");
        assert_eq!(lvalue_root_ident(&e), Some("b"));
    }

    #[test]
    fn pure_predicate_member_chain_walks_to_root_ident() {
        // b.field.sub_field
        let e = member(member(ident("b"), "field"), "sub_field");
        assert_eq!(lvalue_root_ident(&e), Some("b"));
    }

    #[test]
    fn pure_predicate_index_chain_walks_to_root_ident() {
        // arr[0][1]
        let e = index(index(ident("arr"), int_lit(0)), int_lit(1));
        assert_eq!(lvalue_root_ident(&e), Some("arr"));
    }

    #[test]
    fn pure_predicate_mixed_member_index_walks_to_root() {
        // b.parts[i].v.x — Member(Member(Index(Member(Ident(b), "parts"), i), "v"), "x")
        let e = member(
            member(
                index(member(ident("b"), "parts"), ident("i")),
                "v",
            ),
            "x",
        );
        assert_eq!(lvalue_root_ident(&e), Some("b"));
    }

    #[test]
    fn pure_predicate_turbofish_chain_walks_through() {
        // x[T].field
        let e = member(turbofish(ident("x"), vec![]), "field");
        assert_eq!(lvalue_root_ident(&e), Some("x"));
    }

    #[test]
    fn pure_predicate_rvalue_root_returns_none() {
        // foo().field — Call root → None.
        let e = member(call(ident("foo")), "field");
        assert_eq!(lvalue_root_ident(&e), None);
    }

    #[test]
    fn pure_predicate_literal_root_returns_none() {
        // 42.something — synthetic but covers leaf rvalue case.
        let e = member(int_lit(42), "something");
        assert_eq!(lvalue_root_ident(&e), None);
    }

    #[test]
    fn pure_predicate_self_access_returns_none() {
        // @field — SelfAccess root → None (`@` обрабатывается отдельно
        // через ReceiverKind в impl-методе; helper НЕ маппит self → "self").
        let e = member(self_access(), "field");
        assert_eq!(lvalue_root_ident(&e), None);
    }

    // ─── Pure-helper: is_builtin_mut_method ────────────────────────────

    #[test]
    fn builtin_mut_method_recognises_common_array_ops() {
        for m in ["push", "pop", "clear", "insert", "remove", "sort",
                  "extend", "copy_from", "as_mut_ptr"] {
            assert!(is_builtin_mut_method(m),
                "`{}` должен быть builtin mut-method", m);
        }
    }

    #[test]
    fn builtin_mut_method_rejects_pure_methods() {
        for m in ["len", "is_empty", "get", "iter", "abs", "to_string"] {
            assert!(!is_builtin_mut_method(m),
                "`{}` НЕ должен быть builtin mut-method (pure-read)", m);
        }
    }

    // ─── End-to-end через parser + check_module ────────────────────────

    /// Helper: parse source + run check_module, return all diagnostics
    /// (Err'ом возвращается список ошибок; Ok даёт пустой vec).
    fn check_src(src: &str) -> Vec<Diagnostic> {
        let module = match crate::parser::parse(src) {
            Ok(m) => m,
            Err(diag) => return vec![diag],
        };
        match check_module(&module) {
            Ok(_) => Vec::new(),
            Err(diags) => diags,
        }
    }

    fn has_diag_tag(diags: &[Diagnostic], tag: &str) -> bool {
        diags.iter().any(|d| d.message.contains(tag))
    }

    /// Stable test-only type registration trick: define a type with a
    /// declared `mut`-method, then exercise chain receiver against it.
    const HELPER_TYPES: &str = r#"
module test_helpers

type Vec3 {
    mut x f64
    mut y f64
    mut z f64
}

fn Vec3 mut @set_x(v f64) {
    @x = v
}

fn Vec3 @len() -> f64 {
    return @x
}

type Body {
    mut v Vec3
}
"#;

    #[test]
    fn e2e_ro_member_chain_mut_method_rejected() {
        // `ro b = Body(...); b.v.set_x(99.0)` — должен ловиться как
        // E_LOCAL_NOT_MUT (chain root `b` — ro local).
        let src = format!(r#"
{HELPER_TYPES}

fn run() {{
    ro b = Body{{ v: Vec3{{ x: 1.0, y: 2.0, z: 3.0 }} }}
    b.v.set_x(99.0)
}}
"#);
        let diags = check_src(&src);
        assert!(has_diag_tag(&diags, "E_LOCAL_NOT_MUT"),
            "ro b → b.v.set_x() — должен fire E_LOCAL_NOT_MUT; \
             diagnostics: {:#?}",
            diags.iter().map(|d| &d.message).collect::<Vec<_>>());
    }

    #[test]
    fn e2e_mut_member_chain_mut_method_allowed() {
        // `mut b = Body(...); b.v.set_x(99.0)` — НЕ должен fire
        // E_LOCAL_NOT_MUT (chain root `b` — mut local).
        let src = format!(r#"
{HELPER_TYPES}

fn run() {{
    mut b = Body{{ v: Vec3{{ x: 1.0, y: 2.0, z: 3.0 }} }}
    b.v.set_x(99.0)
}}
"#);
        let diags = check_src(&src);
        assert!(!has_diag_tag(&diags, "E_LOCAL_NOT_MUT"),
            "mut b → b.v.set_x() — НЕ должен fire E_LOCAL_NOT_MUT; \
             diagnostics: {:#?}",
            diags.iter().map(|d| &d.message).collect::<Vec<_>>());
    }

    #[test]
    fn e2e_ro_member_chain_pure_method_allowed() {
        // `ro b; b.v.len()` — pure-method, НЕ должен fire E_LOCAL_NOT_MUT.
        let src = format!(r#"
{HELPER_TYPES}

fn run() {{
    ro b = Body{{ v: Vec3{{ x: 1.0, y: 2.0, z: 3.0 }} }}
    let _ = b.v.len()
}}
"#);
        let diags = check_src(&src);
        assert!(!has_diag_tag(&diags, "E_LOCAL_NOT_MUT"),
            "ro b → b.v.len() (pure-method) — НЕ должен fire E_LOCAL_NOT_MUT; \
             diagnostics: {:#?}",
            diags.iter().map(|d| &d.message).collect::<Vec<_>>());
    }

    #[test]
    fn e2e_ro_param_member_chain_mut_method_rejected() {
        // `fn f(b Body) { b.v.set_x(99.0) }` — param без `mut`, chain
        // receiver — должен fire E_PARAM_NOT_MUT.
        let src = format!(r#"
{HELPER_TYPES}

fn run(b Body) {{
    b.v.set_x(99.0)
}}
"#);
        let diags = check_src(&src);
        assert!(has_diag_tag(&diags, "E_PARAM_NOT_MUT"),
            "fn(b Body) → b.v.set_x() — должен fire E_PARAM_NOT_MUT; \
             diagnostics: {:#?}",
            diags.iter().map(|d| &d.message).collect::<Vec<_>>());
    }

    #[test]
    fn e2e_mut_param_member_chain_mut_method_allowed() {
        // `fn f(mut b Body) { b.v.set_x(99.0) }` — `mut b` param,
        // chain receiver — НЕ должен fire.
        let src = format!(r#"
{HELPER_TYPES}

fn run(mut b Body) {{
    b.v.set_x(99.0)
}}
"#);
        let diags = check_src(&src);
        assert!(!has_diag_tag(&diags, "E_PARAM_NOT_MUT"),
            "fn(mut b Body) → b.v.set_x() — НЕ должен fire E_PARAM_NOT_MUT; \
             diagnostics: {:#?}",
            diags.iter().map(|d| &d.message).collect::<Vec<_>>());
    }

    #[test]
    fn e2e_ro_ident_mut_method_still_rejected() {
        // Regression: existing Ident-receiver path должен продолжать работать
        // (мы добавили chain pre-pass, не сломали Ident path).
        // `ro arr: []int; arr.push(1)` — builtin mut-method на ro local.
        let src = r#"
fn run() {
    ro arr = [1, 2, 3]
    arr.push(4)
}
"#;
        let diags = check_src(src);
        assert!(has_diag_tag(&diags, "E_LOCAL_NOT_MUT"),
            "ro arr → arr.push(4) — должен fire E_LOCAL_NOT_MUT (Ident path); \
             diagnostics: {:#?}",
            diags.iter().map(|d| &d.message).collect::<Vec<_>>());
    }

    #[test]
    fn e2e_ro_index_chain_builtin_mut_rejected() {
        // `ro arr2d: [][]int; arr2d[0].push(1)` — Index chain → root arr2d
        // ro, builtin push на []int. Должен fire E_LOCAL_NOT_MUT через
        // chain pre-pass.
        let src = r#"
fn run() {
    ro arr2d = [[1, 2], [3, 4]]
    arr2d[0].push(99)
}
"#;
        let diags = check_src(src);
        assert!(has_diag_tag(&diags, "E_LOCAL_NOT_MUT"),
            "ro arr2d → arr2d[0].push() — должен fire E_LOCAL_NOT_MUT \
             (Index chain root); diagnostics: {:#?}",
            diags.iter().map(|d| &d.message).collect::<Vec<_>>());
    }
}

